INSERT OR IGNORE INTO "recommendations" VALUES(1,6114,'tt0103874',NULL,'Bram Stoker''s Dracula','Bram Stoker''s Dracula','movie',1992,'https://image.tmdb.org/t/p/w500/4ZbUxjY5DZ7RCxGwvzSEr4rThd1.jpg','https://image.tmdb.org/t/p/original/88S6EYQBVyQktDfSqsB33I169jN.jpg','Count Dracula, a 15th-century prince, is condemned to live off the blood of the living for eternity. Young lawyer Jonathan Harker is sent to Dracula''s castle to finalise a land deal, but when the Count sees a photo of Harker''s fiancée, Mina, the spitting image of his dead wife, he imprisons him and sets off for London to track her down.',NULL,NULL,11.2091,7.45,0,2.16166666666666671e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2,15999,'tt0216651',NULL,'Vampire Hunter D: Bloodlust','吸血鬼ハンターD ブラッドラスト','movie',2001,'https://image.tmdb.org/t/p/w500/9ipbQRgOq6Ilxpwagfa98ikgR9v.jpg','https://image.tmdb.org/t/p/original/lwkwVTNdNeG0a1FT06wr1Ylm1OV.jpg','Legendary dhampir D competes with a motley family of bounty hunters to track down Charlotte Elbourne, a young woman seemingly abducted by undead nobleman Meier Link.',NULL,NULL,4.1843,7.7,0,13.6625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(3,591538,'tt10095582',NULL,'The Tragedy of Macbeth','The Tragedy of Macbeth','movie',2021,'https://image.tmdb.org/t/p/w500/tDNJEhcLbX3jIk3BMCur9pCdaVD.jpg','https://image.tmdb.org/t/p/original/lMjY6kMBOHhloz2Ul16fLJn8xuw.jpg','Macbeth, the Thane of Glamis, receives a prophecy from a trio of witches that one day he will become King of Scotland. Consumed by ambition and spurred to action by his wife, Macbeth murders his king and takes the throne for himself.',NULL,NULL,5.5881,6.9,0,1.25166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(4,201085,'tt2554274',NULL,'Crimson Peak','Crimson Peak','movie',2015,'https://image.tmdb.org/t/p/w500/f9TOb5anVwZeSbYjU1qNxPk3KUk.jpg','https://image.tmdb.org/t/p/original/nQQIUwEEqa6sjPvnqcGbjJxbdit.jpg','In the aftermath of a family tragedy, an aspiring author is torn between love for her childhood friend and the temptation of a mysterious outsider. Trying to escape the ghosts of her past, she is swept away to a house that breathes, bleeds… and remembers.',NULL,NULL,4.3631,6.661,0,2.45553333333333299e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(5,120,'tt0120737',NULL,'The Lord of the Rings: The Fellowship of the Ring','The Lord of the Rings: The Fellowship of the Ring','movie',2001,'https://image.tmdb.org/t/p/w500/6oom5QYQ2yQTMJIbnvbkBL9cHo6.jpg','https://image.tmdb.org/t/p/original/mWDdRXTivGE7aaY2vo1Ie0PfCX5.jpg','Young hobbit Frodo Baggins, after inheriting a mysterious ring from his uncle Bilbo, must leave his home in order to keep it from falling into the hands of its evil creator. Along the way, a fellowship is formed to protect the ringbearer and make sure that the ring arrives at its final destination: Mt. Doom, the only place where it can be destroyed.',NULL,NULL,39.5377,8.4,0,24.989375,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(6,374052,'tt3908142',NULL,'The Love Witch','The Love Witch','movie',2016,'https://image.tmdb.org/t/p/w500/q6mZjCwGn9KCTrStTRM88pui0is.jpg','https://image.tmdb.org/t/p/original/zPzJ3DAUjpJoiBm4jODt50QEEr3.jpg','A modern-day witch uses spells and magic to get men to fall in love with her, with deadly consequences.',NULL,NULL,2.5385,6.419,0,1.53185714285714276e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(7,487083,'tt6127004',NULL,'Paradise Hills','Paradise Hills','movie',2019,'https://image.tmdb.org/t/p/w500/7V1N8vMPNDw6be3MDiA4DC0s4Bv.jpg','https://image.tmdb.org/t/p/original/1m8kFUHZA04CrtwPLMJoe7sW9mP.jpg','A young woman is sent to Paradise Hills to be reformed, only to learn that the high-class facility''s beautiful facade hides a sinister secret.',NULL,NULL,1.5391,5.919,0,10.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(8,361292,'tt1034415',NULL,'Suspiria','Suspiria','movie',2018,'https://image.tmdb.org/t/p/w500/bRpKFPb8CWKRQxVo9NzOuPPlO3Q.jpg','https://image.tmdb.org/t/p/original/k4renoGJzagylgBYWbpjQLYGAfB.jpg','A darkness swirls at the center of a world-renowned dance company, one that will engulf the artistic director, an ambitious young dancer, and a grieving psychotherapist. Some will succumb to the nightmare. Others will finally wake up.',NULL,NULL,4.8135,6.896,0,16.99375,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(9,16395,'tt0080923',NULL,'Inferno','Inferno','movie',1980,'https://image.tmdb.org/t/p/w500/A92SmwJ4w2GSF6Mp2m8xE9GbG39.jpg','https://image.tmdb.org/t/p/original/eJGbf7RB8YNE9s3YLCt6lgqAOB9.jpg','A young man returns from Rome to his sister''s satanic New York apartment house.',NULL,NULL,2.0072,6.6,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(10,993784,'tt21188080',NULL,'Lisa Frankenstein','Lisa Frankenstein','movie',2024,'https://image.tmdb.org/t/p/w500/jAW7ZdIm4HLKB3g15uMOWYNdU8r.jpg','https://image.tmdb.org/t/p/original/tsDoiLwZyAbYewoIUDJKk1SJzTF.jpg','In 1989, a misunderstood teenager has a high school crush — who just happens to be a handsome corpse! After a set of playfully horrific circumstances bring him back to life, the two embark on a murderous journey to find love, happiness…and a few missing body parts along the way.',NULL,NULL,2.8166,6.37,0,10.614,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(11,9016,'tt0133240',NULL,'Treasure Planet','Treasure Planet','movie',2002,'https://image.tmdb.org/t/p/w500/kNhZkR3UNbXfvESQo7mJpOi4tGd.jpg','https://image.tmdb.org/t/p/original/f2opsSUSiMdEp6AiY2sbC8QPd8S.jpg','When space galleon cabin boy Jim Hawkins discovers a map to an intergalactic "loot of a thousand worlds," a cyborg cook named John Silver teaches him to battle supernovas and space storms on their journey to find treasure.',NULL,NULL,7.4196,7.575,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(12,10865,'tt0230011',NULL,'Atlantis: The Lost Empire','Atlantis: The Lost Empire','movie',2001,'https://image.tmdb.org/t/p/w500/oK8yR6xSQreWf1ouP1VpXKwoop5.jpg','https://image.tmdb.org/t/p/original/4eTiLRTYwAVQyQAjuFuf3BXAony.jpg','A young linguist named Milo Thatch joins an intrepid group of explorers to find the mysterious lost continent of Atlantis.',NULL,NULL,5.0734,7.0,0,11.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(13,402431,'tt1262426',NULL,'Wicked','Wicked','movie',2024,'https://image.tmdb.org/t/p/w500/xDGbZ0JJ3mYaGKy4Nzd9Kph6M9L.jpg','https://image.tmdb.org/t/p/original/fyZ6SDUS4o9jp2EHxfZa3qS9ean.jpg','In the land of Oz, ostracized and misunderstood green-skinned Elphaba is forced to share a room with the popular aristocrat Glinda at Shiz University, and the two''s unlikely friendship is tested as they begin to fulfill their respective destinies as Glinda the Good and the Wicked Witch of the West.',NULL,NULL,15.1966,6.909,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(14,117488,'tt11041332',NULL,'Yellowjackets','Yellowjackets','tv',2021,'https://image.tmdb.org/t/p/w500/xRnGrn7Z7SC0KIBodocoU1QgDZF.jpg','https://image.tmdb.org/t/p/original/ibFWJDWS8cTO6s2vZVd2uKDm8p.jpg','This equal parts survival epic, psychological horror story and coming-of-age drama tells the saga of a team of wildly talented high school girls soccer players who become the (un)lucky survivors of a plane crash deep in the remote northern wilderness. The series chronicles their descent from a complicated but thriving team to savage clans, while also tracking the lives they’ve attempted to piece back together nearly 25 years later.',NULL,NULL,17.9801,7.449,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(15,433808,'tt5638642',NULL,'The Ritual','The Ritual','movie',2017,'https://image.tmdb.org/t/p/w500/9022CYEGqYETCeXN1oE3uwYJWub.jpg','https://image.tmdb.org/t/p/original/vaArQHq1lHFNppoJlMlv30Gs2fQ.jpg','A group of college friends reunite for a trip to the forest, but encounter a menacing presence in the woods that''s stalking them.',NULL,NULL,6.0293,6.29,0,17.83625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(16,424121,'tt6217306',NULL,'Apostle','Apostle','movie',2018,'https://image.tmdb.org/t/p/w500/rd269f2Yftxxam3EOJPYVwrvjIJ.jpg','https://image.tmdb.org/t/p/original/tvGTSdLjKJgFHTcF4x9HSxoTIgW.jpg','In 1905, a man travels to a remote island in search of his missing sister who has been kidnapped by a mysterious religious cult.',NULL,NULL,5.0697,6.138,0,15.022,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(17,11020,'tt0073540',NULL,'Picnic at Hanging Rock','Picnic at Hanging Rock','movie',1975,'https://image.tmdb.org/t/p/w500/7BAXwmFN4pZDNb9N6kzmAAwdssi.jpg','https://image.tmdb.org/t/p/original/41Mlaj6wfjlF4wQaVH0tjfDXvMi.jpg','In the early 1900s, Miranda attends a girls boarding school in Australia. One Valentine''s Day, the school''s typically strict headmistress treats the girls to a picnic field trip to an unusual but scenic volcanic formation called Hanging Rock. Despite rules against it, Miranda and several other girls venture off. It''s not until the end of the day that the faculty realizes the girls and one of the teachers have disappeared mysteriously.',NULL,NULL,1.8705,7.237,0,1.55233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(18,16307,'tt0070917',NULL,'The Wicker Man','The Wicker Man','movie',1973,'https://image.tmdb.org/t/p/w500/wwtrXRL8SiOWxhwLEvw7iBgYh0g.jpg','https://image.tmdb.org/t/p/original/fK5OHX7OIl57UqAbPiM4F3hc9wr.jpg','Police sergeant Neil Howie is called to an island village in search of a missing girl whom the locals claim never existed. The investigation is further complicated as Howie’s religious views clash with those of the island’s residents.',NULL,NULL,5.0977,7.337,0,1.75837500000000019e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(19,26774,'tt0066849',NULL,'The Blood on Satan''s Claw','The Blood on Satan''s Claw','movie',1971,'https://image.tmdb.org/t/p/w500/shUG4L8iKu9g4bhZVI3SNsIOvD3.jpg','https://image.tmdb.org/t/p/original/lVgJzjtd97Aznpbp4KkSM0Oxj7J.jpg','After a landsman in 18th century England discovers a corpse covered in fur buried in a field, the town becomes infected by "the devil''s skin," leading the local children to engage in demonic rituals and criminal behavior.',NULL,NULL,1.9314,6.2,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(20,11905,'tt0087075',NULL,'The Company of Wolves','The Company of Wolves','movie',1984,'https://image.tmdb.org/t/p/w500/2g2YPws1MiEWTodUE8u3qOf78XS.jpg','https://image.tmdb.org/t/p/original/8LMKwSUdHxU8AGPVY7BV4wS5TeQ.jpg','An adaptation of Angela Carter''s fairy tales. Young Rosaleen dreams of a village in the dark woods, where Granny tells her cautionary tales in which innocent maidens are tempted by wolves who are hairy on the inside. As Rosaleen grows into womanhood, will the wolves come for her too?',NULL,NULL,2.4288,6.3,0,13.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(21,179111,'tt2375574',NULL,'A Field in England','A Field in England','movie',2013,'https://image.tmdb.org/t/p/w500/dKhMJr8yoHVyvxyUiAeIn2hKVdL.jpg','https://image.tmdb.org/t/p/original/euBvKWkvYD38O7dMMvw3GvrkZoa.jpg','During the Civil War in 17th-Century England, a small group of deserters flee from a raging battle through an overgrown field. They are captured by an alchemist, who forces the group to aid him in his search to find a hidden treasure that he believes is buried in the field. Crossing a vast mushroom circle, which provides their first meal, the group quickly descend into a chaos of arguments, fighting and paranoia, and, as it becomes clear that the treasure might be something other than gold, they slowly become victim to the terrifying energies trapped inside the field.',NULL,NULL,1.1399,6.212,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(22,10957,'tt0088814',NULL,'The Black Cauldron','The Black Cauldron','movie',1985,'https://image.tmdb.org/t/p/w500/h64i9e6oJs2jrDZ4QzspXMqZhPF.jpg','https://image.tmdb.org/t/p/original/4idEU92m0oR1BWa1iwb5pZ9bWCu.jpg','Taran is an assistant pigkeeper with boyish dreams of becoming a great warrior. However, he has to put the daydreaming aside when his charge, an oracular pig named Hen Wen, is kidnapped by an evil lord known as the Horned King. The villain hopes Hen will show him the way to The Black Cauldron, which has the power to create a giant army of unstoppable soldiers.',NULL,NULL,3.9539,6.441,0,11.79,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(23,13597,'tt0091369',NULL,'Labyrinth','Labyrinth','movie',1986,'https://image.tmdb.org/t/p/w500/pejayhTVBEL4w8YKSfrhOjjWVlH.jpg','https://image.tmdb.org/t/p/original/mGkleIuPO2flRyvP8yBcUykSQsp.jpg','Frustrated with babysitting on yet another weekend night, Sarah, a teenager with an active imagination, summons the Goblins to take her baby stepbrother away. When little Toby actually disappears, Sarah must follow him into a fantastical world to rescue him from the Goblin King. Guarding his castle is the labyrinth itself, a twisted maze of deception, populated with outrageous characters and unknown dangers.',NULL,NULL,5.7776,7.289,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(24,2637,'tt0265349',NULL,'The Mothman Prophecies','The Mothman Prophecies','movie',2002,'https://image.tmdb.org/t/p/w500/z2PiOTyjbCOnMHY2QJdq3I4jU44.jpg','https://image.tmdb.org/t/p/original/zQM01PhOwJY9ePnWPQ8L0YeKf8c.jpg','Reporter John Klein is plunged into a world of impossible terror when fate draws him to the sleepy West Virginia town of Point Pleasant, whose residents are being visited by a great winged shape that sows hideous nightmares and fevered visions.',NULL,NULL,4.7287,6.2,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(25,546554,'tt8946378',NULL,'Knives Out','Knives Out','movie',2019,'https://image.tmdb.org/t/p/w500/pThyQovXQrw2m0s9x82twj48Jq4.jpg','https://image.tmdb.org/t/p/original/4HWAQu28e2yaWrtupFPGFkdNU7V.jpg','When renowned crime novelist Harlan Thrombey is found dead at his estate just after his 85th birthday, the inquisitive and debonair Detective Benoit Blanc is mysteriously enlisted to investigate. From Harlan''s dysfunctional family to his devoted staff, Blanc sifts through a web of red herrings and self-serving lies to uncover the truth behind Harlan''s untimely death.',NULL,NULL,14.3029,7.841,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(26,12246,'tt0416044',NULL,'Mongol: The Rise of Genghis Khan','Монгол','movie',2007,'https://image.tmdb.org/t/p/w500/8hlyJVMKFJNJb8QRtdfjage2tGF.jpg','https://image.tmdb.org/t/p/original/m50btvvexrrDUpJjSey1C4IU1OD.jpg','The story recounts the early life of Genghis Khan, a slave who went on to conquer half the world in the 11th century.',NULL,NULL,3.1693,6.783,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(27,530385,'tt8772262',NULL,'Midsommar','Midsommar','movie',2019,'https://image.tmdb.org/t/p/w500/7LEI8ulZzO5gy9Ww2NVCrKmHeDZ.jpg','https://image.tmdb.org/t/p/original/pYgj8e2Y6RufnSyOA6OnzmxFXxZ.jpg','Several friends travel to Sweden to study as anthropologists a summer festival that is held every ninety years in the remote hometown of one of them. What begins as a dream vacation in a place where the sun never sets, gradually turns into a dark nightmare as the mysterious inhabitants invite them to participate in their disturbing festive activities.',NULL,NULL,14.6112,7.148,0,1.55300000000000011e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(28,766507,'tt11866324',NULL,'Prey','Prey','movie',2022,'https://image.tmdb.org/t/p/w500/ujr5pztc1oitbe7ViMUOilFaJ7s.jpg','https://image.tmdb.org/t/p/original/7ZO9yoEU2fAHKhmJWfAc2QIPWJg.jpg','When danger threatens her camp, the fierce and highly skilled Comanche warrior Naru sets out to protect her people. But the prey she stalks turns out to be a highly evolved alien predator with a technically advanced arsenal.',NULL,NULL,10.8905,7.66,0,11.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(29,329865,'tt2543164',NULL,'Arrival','Arrival','movie',2016,'https://image.tmdb.org/t/p/w500/x2FJsf1ElAgr63Y3PNPtJrcmpoe.jpg','https://image.tmdb.org/t/p/original/8MUZz7oPXQftFTslZpRP3CVMOoq.jpg','Taking place after alien crafts land around the world, an expert linguist is recruited by the military to determine whether they come in peace or are a threat.',NULL,NULL,17.4039,7.63,0,14.216,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(30,438631,'tt1160419',NULL,'Dune','Dune','movie',2021,'https://image.tmdb.org/t/p/w500/gDzOcq0pfeCeqMBwKIJlSmQpjkZ.jpg','https://image.tmdb.org/t/p/original/qVgZu5BTx6pu4owCvVOm4zjTfOi.jpg','Paul Atreides, a brilliant and gifted young man born into a great destiny beyond his understanding, must travel to the most dangerous planet in the universe to ensure the future of his family and his people. As malevolent forces explode into conflict over the planet''s exclusive supply of the most precious resource in existence - a commodity capable of unlocking humanity''s greatest potential - only those who can conquer their fear will survive.',NULL,NULL,43.2609,7.782,0,1.51033333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(31,157336,'tt0816692',NULL,'Interstellar','Interstellar','movie',2014,'https://image.tmdb.org/t/p/w500/yQvGrMoipbRoddT0ZR8tPoR7NfX.jpg','https://image.tmdb.org/t/p/original/2ssWTSVklAEc98frZUQhgtGHx7s.jpg','The adventures of a group of explorers who make use of a newly discovered wormhole to surpass the limitations on human space travel and conquer the vast distances involved in an interstellar voyage.',NULL,NULL,53.275,8.481,0,10.64,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(32,62,'tt0062622',NULL,'2001: A Space Odyssey','2001: A Space Odyssey','movie',1968,'https://image.tmdb.org/t/p/w500/ve72VxNqjGM69Uky4WTo2bK6rfq.jpg','https://image.tmdb.org/t/p/original/w5IDXtifKntw0ajv2co7jFlTQDM.jpg','Humanity finds a mysterious object buried beneath the lunar surface and sets off to find its origins with the help of HAL 9000, the world''s most advanced super computer.',NULL,NULL,16.1982,8.049,0,1.75837500000000019e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(33,686,'tt0118884',NULL,'Contact','Contact','movie',1997,'https://image.tmdb.org/t/p/w500/bCpMIywuNZeWt3i5UMLEIc0VSwM.jpg','https://image.tmdb.org/t/p/original/yFkUPqBuUnbhYbQL8VFpTrAT9za.jpg','A radio astronomer receives the first extraterrestrial radio signal ever picked up on Earth. As the world powers scramble to decipher the message and decide upon a course of action, she must make some difficult decisions between her beliefs, the truth, and reality.',NULL,NULL,9.2004,7.448,0,1.51816666666666648e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(34,8967,'tt0478304',NULL,'The Tree of Life','The Tree of Life','movie',2011,'https://image.tmdb.org/t/p/w500/l8cwuB5WJSoj4uMAsnzuHBOMaSJ.jpg','https://image.tmdb.org/t/p/original/xq1HIwZq9VbuvMQELAua1nqEkH.jpg','The impressionistic story of a Texas family in the 1950s. The film follows the life journey of the eldest son, Jack, through the innocence of childhood to his disillusioned adult years as he tries to reconcile a complicated relationship with his father. Jack finds himself a lost soul in the modern world, seeking answers to the origins and meaning of life while questioning the existence of faith.',NULL,NULL,4.2616,6.724,0,15.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(35,75612,'tt1483013',NULL,'Oblivion','Oblivion','movie',2013,'https://image.tmdb.org/t/p/w500/bYLM3GpNUZnoFElPXp1zlhDPdtv.jpg','https://image.tmdb.org/t/p/original/2kVt8oj1cSz4GAP0Hi8SESOiH0T.jpg','Jack Harper is one of the last few drone repairmen stationed on Earth. Part of a massive operation to extract vital resources after decades of war with a terrifying threat known as the Scavs, Jack’s mission is nearly complete. His existence is brought crashing down when he rescues a beautiful  stranger from a downed spacecraft. Her arrival triggers a chain of events that  forces him to question everything he knows and puts the fate of humanity in his hands.',NULL,NULL,7.51,6.684,0,8.75333333333333207e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(36,34636,'tt0100240',NULL,'The NeverEnding Story II: The Next Chapter','Die unendliche Geschichte II - Auf der Suche nach Phantásien','movie',1990,'https://image.tmdb.org/t/p/w500/bRSLCuO2B6owYBtUwGYGqWZCVo6.jpg','https://image.tmdb.org/t/p/original/22328gc644F4pZn30nWPPUo4I93.jpg','Once again, Bastian is transported to the world of Fantasia which he recently managed to save from destruction. However, the land is now being destroyed by an evil sorceress, Xayide, so he must join up with Atreyu and face the Emptiness once more.',NULL,NULL,2.5683,5.782,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(37,9833,'tt0293508',NULL,'The Phantom of the Opera','The Phantom of the Opera','movie',2004,'https://image.tmdb.org/t/p/w500/aTsp2VTaCBiGs8w05OTXfD97FRZ.jpg','https://image.tmdb.org/t/p/original/p3P0eTh8AnqauhRZg0wgoBFvcjF.jpg','A young soprano becomes the obsession of a disfigured and murderous musical genius who lives beneath the Paris Opera House.',NULL,NULL,6.2253,7.267,0,12.37,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(38,7131,'tt0338526',NULL,'Van Helsing','Van Helsing','movie',2004,'https://image.tmdb.org/t/p/w500/gsFun8nATm52aGHeT8ueAel98nE.jpg','https://image.tmdb.org/t/p/original/d72ROyJqXQtw2OupW0l15eicRAF.jpg','Famed monster slayer Gabriel Van Helsing is dispatched to Transylvania to assist the last of the Valerious bloodline in defeating Count Dracula. Anna Valerious reveals that Dracula has formed an unholy alliance with Dr. Frankenstein''s monster and is hell-bent on exacting a centuries-old curse on her family.',NULL,NULL,10.1298,6.423,0,1.74587500000000019e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(39,274854,'tt1618442',NULL,'The Last Witch Hunter','The Last Witch Hunter','movie',2015,'https://image.tmdb.org/t/p/w500/dS9YdnJkxtKE2PKCSsxTaO7Jpf5.jpg','https://image.tmdb.org/t/p/original/mXmvN6drkdU1PWFF92AGklEVIa3.jpg','The modern world holds many secrets, but by far the most astounding is that witches still live among us; vicious supernatural creatures intent on unleashing the Black Death upon the world and putting an end to the human race once and for all. Armies of witch hunters have battled this unnatural enemy for centuries, including Kaulder, a valiant warrior who many years ago slayed the all-powerful Witch Queen, decimating her followers in the process. In the moments right before her death, the Queen cursed Kaulder with immortality, forever separating him from his beloved wife and daughter. Today, Kaulder is the last living hunter who has spent his immortal life tracking down rogue witches, all the while yearning for his long-lost family.',NULL,NULL,6.2653,6.015,0,2.27684615384615369e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(40,426063,'tt5040012',NULL,'Nosferatu','Nosferatu','movie',2024,'https://image.tmdb.org/t/p/w500/5qGIxdEO841C0tdY8vOdLoRVrr0.jpg','https://image.tmdb.org/t/p/original/2gAStVyyv9C3BSEKhP0a1aM3Qy9.jpg','A gothic tale of obsession between a haunted young woman and the terrifying vampire infatuated with her, causing untold horror in its wake.',NULL,NULL,12.6813,6.715,0,1.92239999999999966e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(41,588226,'tt9185816',NULL,'Woodstock: Three Days That Defined a Generation','Woodstock','movie',2019,'https://image.tmdb.org/t/p/w500/ejPrzjG17UrYHjUn8xE3EAYnoDl.jpg','https://image.tmdb.org/t/p/original/aXLcNxJI2JDdASNL6ZaNI0jWl2s.jpg','50 years after the legendary fest, Barak Goodman’s electric retelling of Woodstock, from the point of view of those who were on the ground, evokes the freedom, passion, community, and joy the three-day music festival created.',NULL,NULL,0.6741,7.304,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(42,786,'tt0181875',NULL,'Almost Famous','Almost Famous','movie',2000,'https://image.tmdb.org/t/p/w500/3rrkyLYbgLj84AYvjhdcJot4JPx.jpg','https://image.tmdb.org/t/p/original/AqLtFRKVX2G0ghMnMnQoSGan4pY.jpg','In 1973, a precocious 15-year-old aspiring rock journalist lands a dream assignment from Rolling Stone to tour with a rising rock band, embarking on a coming-of-age journey as he discovers the exhilarating and heartbreaking realities behind rock stardom.',NULL,NULL,5.5385,7.5,0,15.4025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(43,290250,'tt3799694',NULL,'The Nice Guys','The Nice Guys','movie',2016,'https://image.tmdb.org/t/p/w500/clq4So9spa9cXk3MZy2iMdqkxP2.jpg','https://image.tmdb.org/t/p/original/yxYUN3fBPJdTNdXC1l8L24XFPhX.jpg','A private eye investigates the apparent suicide of a fading porn star in 1970s Los Angeles and uncovers a conspiracy.',NULL,NULL,8.8242,7.132,0,1.25233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(44,5722,'tt0065466',NULL,'Beyond the Valley of the Dolls','Beyond the Valley of the Dolls','movie',1970,'https://image.tmdb.org/t/p/w500/eslylQSssnNIV4f06fHtfxPTH3I.jpg','https://image.tmdb.org/t/p/original/4ms1JNHHpW4rwEXnjyhLN7IP0PZ.jpg','An all-girl rock band moves to Hollywood in the hope of achieving success, only to fall into a whirlpool of wickedness and decadence.',NULL,NULL,2.4268,6.1,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(45,46919,'tt0060959',NULL,'Daisies','Sedmikrásky','movie',1966,'https://image.tmdb.org/t/p/w500/8sxMhdn3i1Pn8OlGCBBjr9rjP1y.jpg','https://image.tmdb.org/t/p/original/A1Ajyl9qdUvK94ABteqEelk6M1Q.jpg','Two teenage girls embark on a series of destructive pranks in which they consume and destroy the world around them.',NULL,NULL,2.2866,7.3,0,8.73,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(46,9571,'tt0106677',NULL,'Dazed and Confused','Dazed and Confused','movie',1993,'https://image.tmdb.org/t/p/w500/msG9awbLhVZwv1Eh9Ge7SofMexW.jpg','https://image.tmdb.org/t/p/original/mhYQOazZVBAPtKDw3TXybDtMJgK.jpg','The adventures of a group of Texas teens on their last day of school in 1976, centering on student Randall Floyd, who moves easily among stoners, jocks and geeks. Floyd is a star athlete, but he also likes smoking weed, which presents a conundrum when his football coach demands he sign a "no drugs" pledge.',NULL,NULL,6.5179,7.3,0,1.75887499999999974e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(47,466272,'tt7131622',NULL,'Once Upon a Time... in Hollywood','Once Upon a Time... in Hollywood','movie',2019,'https://image.tmdb.org/t/p/w500/8j58iEBw9pOXFD2L0nt0ZXeHviB.jpg','https://image.tmdb.org/t/p/original/xwgBHC2FgoIrQitl8jZwXXdsR9u.jpg','Los Angeles, 1969. TV star Rick Dalton, a struggling actor specializing in westerns, and stuntman Cliff Booth, his best friend, try to survive in a constantly changing movie industry. Dalton is the neighbor of the young and promising actress and model Sharon Tate, who has just married the prestigious Polish director Roman Polanski…',NULL,NULL,13.4911,7.422,0,13.5225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(48,30497,'tt0072271',NULL,'The Texas Chain Saw Massacre','The Texas Chain Saw Massacre','movie',1974,'https://image.tmdb.org/t/p/w500/mpgkRPH1GNkMCgdPk2OMyHzAks7.jpg','https://image.tmdb.org/t/p/original/wvBx1Q1FcQE1BPLfBbgA3y9aaS1.jpg','Five friends head out to rural Texas to visit the grave of a grandfather. On the way, they stumble across what appears to be a deserted house, only to discover something sinister within. Something armed with a chainsaw.',NULL,NULL,7.7155,7.29,0,13.6975,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(49,719256,'tt10098448',NULL,'Jesus Revolution','Jesus Revolution','movie',2023,'https://image.tmdb.org/t/p/w500/A3qqrl8lJvlpRCwkbUEADXzVaDC.jpg','https://image.tmdb.org/t/p/original/m42PtAhEtEqbNV8Cs8TsXcTN4ha.jpg','In the 1970s, aimless teenager Greg Laurie searches for all the right things in all the wrong places until he meets Lonnie Frisbee, a charismatic hippie/street preacher. Together with local pastor Chuck Smith, they open the doors of a languishing church to an unexpected revival.',NULL,NULL,2.1008,6.857,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(50,14517,'tt0366780',NULL,'MirrorMask','MirrorMask','movie',2005,'https://image.tmdb.org/t/p/w500/itIJU3NKbdgScA1WPIxXzOlm0Uj.jpg','https://image.tmdb.org/t/p/original/zDkLBWZmt8jZrEhdKoUKoaEwETC.jpg','In a fantasy world of opposing kingdoms, a 15-year old girl must find the fabled MirrorMask in order to save the kingdom and get home.',NULL,NULL,2.5879,6.419,0,1.21866666666666656e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(51,14506,'tt0096764',NULL,'The Adventures of Baron Munchausen','The Adventures of Baron Munchausen','movie',1988,'https://image.tmdb.org/t/p/w500/oiOwGRqwrKpg1EMUlPgRjVC49bn.jpg','https://image.tmdb.org/t/p/original/mBh3NXCkSCasZGovzAuc9UlFCru.jpg','An account of Baron Munchausen''s supposed travels and fantastical experiences with his band of misfits.',NULL,NULL,2.5078,6.985,0,1.62042857142857137e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(52,41213,'tt0054665',NULL,'The Fabulous Baron Munchausen','Baron Prášil','movie',1962,'https://image.tmdb.org/t/p/w500/azAhyBd8netxD18VdYo7C4oUvbR.jpg','https://image.tmdb.org/t/p/original/elfVwrfn5goenMteFuYboz5q2BN.jpg','A 20th century man lands on the Moon and discovers that Baron Munchausen has beaten him to it, accompanied by Cyrano de Bergerac and the characters from Jules Verne''s novels about the conquest of the satellite.',NULL,NULL,1.4684,7.4,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(53,22611,'tt0104740',NULL,'Little Nemo: Adventures in Slumberland','NEMO/ニモ','movie',1989,'https://image.tmdb.org/t/p/w500/uVyqRtRaIGrHJvfxImrHHFaQNxM.jpg','https://image.tmdb.org/t/p/original/8hwjzxg1XgLTWK3LENj7RVyGBkb.jpg','A little boy whose dreams transcend reality is sucked into his own fantasy, which is everything he has dreamed of, until he unleashes an old secret that may not only destroy this perfect dream world but reality itself.',NULL,NULL,3.3913,6.9,0,1.18466666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(54,13155,'tt0089908',NULL,'Return to Oz','Return to Oz','movie',1985,'https://image.tmdb.org/t/p/w500/dyMwaXA9nVhPiA5wYHsvfUAnbaB.jpg','https://image.tmdb.org/t/p/original/p6zh3jTuuhNfsUhUCEajEizDC9K.jpg','Dorothy, saved from a psychiatric experiment by a mysterious girl, finds herself back in the land of her dreams, and makes delightful new friends, and dangerous new enemies.',NULL,NULL,3.0558,6.714,0,1.23466666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(55,818,'tt0295178',NULL,'Austin Powers in Goldmember','Austin Powers in Goldmember','movie',2002,'https://image.tmdb.org/t/p/w500/n8V61f1v7idya4WJzGEJNoIp9iL.jpg','https://image.tmdb.org/t/p/original/kuPpElzfYnzsCye0hF8EbJSrvwo.jpg','The world''s most shagadelic spy continues his fight against Dr. Evil. This time, the diabolical doctor and his clone, Mini-Me, team up with a new foe—''70s kingpin Goldmember. While pursuing the team of villains to stop them from world domination, Austin gets help from his dad and an old girlfriend.',NULL,NULL,4.9159,6.023,0,11.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(56,1052,'tt0060176',NULL,'Blow-Up','Blow-Up','movie',1966,'https://image.tmdb.org/t/p/w500/jVDVpydUw8Z50naUDAG4NbRCrSa.jpg','https://image.tmdb.org/t/p/original/rWtRkNGkg05rET8taCA96c7heLb.jpg','A successful mod photographer in London whose world is bounded by fashion, pop music, marijuana, and easy sex, feels his life is boring and despairing. But in the course of a single day he unknowingly captures a death on film.',NULL,NULL,2.4943,7.3,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(57,15598,'tt0060086',NULL,'Alfie','Alfie','movie',1966,'https://image.tmdb.org/t/p/w500/tPUqgfGMkZazRZ1UO41j2Fiib5C.jpg','https://image.tmdb.org/t/p/original/ksSpcJxiYaqDlgAgEFtbGieXQMM.jpg','A young man leads a promiscuous lifestyle until several life reversals make him rethink his purposes and goals in life.',NULL,NULL,1.6642,6.534,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(58,576845,'tt9639470',NULL,'Last Night in Soho','Last Night in Soho','movie',2021,'https://image.tmdb.org/t/p/w500/n1ZRmjlk1BJTY7aASqACfPAaLn2.jpg','https://image.tmdb.org/t/p/original/nPWy5KISy7BbUOQcg588dflKzTL.jpg','A young girl, passionate about fashion design, is mysteriously able to enter the 1960s where she encounters her idol, a dazzling wannabe singer. But 1960s London is not what it seems, and time seems to be falling apart with shady consequences.',NULL,NULL,5.6549,7.271,0,1.21766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(59,1398,'tt0079944',NULL,'Stalker','Сталкер','movie',1979,'https://image.tmdb.org/t/p/w500/1qhOyf5C4s9ZdvY8d5JDx9DFMeT.jpg','https://image.tmdb.org/t/p/original/6yrbWzzrPp7pwz6zHdifspJk8t3.jpg','Near a gray and unnamed city is the Zone, a place guarded by barbed wire and soldiers, and where the normal laws of physics are victim to frequent anomalies. A stalker guides two men into the Zone, specifically to an area in which deep-seated desires are granted.',NULL,NULL,5.7691,8.088,0,1.72355555555555568e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(60,73920,'tt0091759',NULL,'Dead Man''s Letters','Письма мертвого человека','movie',1986,'https://image.tmdb.org/t/p/w500/uPfG3ZnXCdRdxZ88DqMe0UuIwBS.jpg','https://image.tmdb.org/t/p/original/lLvIoN4fHSrmOuK0CvVgkqA6Sa4.jpg','In a desolate world following the nuclear apocalypse, a scholar helps a small group of adults and children survive in the basement of a former museum of history. In his mind, he writes letters to his only son that will never be read and tries to find shreds of hope in his new reality.',NULL,NULL,2.1738,6.9,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(61,27072,'tt0093593',NULL,'On the Silver Globe','Na Srebrnym Globie','movie',1989,'https://image.tmdb.org/t/p/w500/4zzam82e6rCY2Ktm0fyRoseHhkh.jpg','https://image.tmdb.org/t/p/original/5nZ0ax5n5k9MogcGX3IxVjlCMRt.jpg','A small group of cosmic explorers, including a woman, leaves Earth to start a new civilization. They do not realize that within themselves they carry the end of their own dream. They die one by one, while their children revert to a primitive native culture, creating new myths and a new god.',NULL,NULL,3.551,7.7,0,8.92,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(62,NULL,NULL,11208,'NieR: Automata','NieR: Automata','game',2017,'https://images.igdb.com/igdb/image/upload/t_cover_big/co5pcj.jpg',NULL,'NieR: Automata tells the story of androids 2B, 9S and A2 and their battle to reclaim the machine-driven dystopia overrun by powerful machines.','https://www.igdb.com/games/nier-automata','["PlayStation 4", "PC (Microsoft Windows)", "Xbox One"]',NULL,NULL,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(63,8966,'tt1099212',NULL,'Twilight','Twilight','movie',2008,'https://image.tmdb.org/t/p/w500/3Gkb6jm6962ADUPaCBqzz9CTbn9.jpg','https://image.tmdb.org/t/p/original/weAYfu6FfrNxEDJ3xH1XpgQcqUv.jpg','When Bella Swan moves to a small town in the Pacific Northwest, she falls in love with Edward Cullen, a mysterious classmate who reveals himself to be a 108-year-old vampire. Despite Edward''s repeated cautions, Bella can''t stay away from him, a fatal move that endangers her own life.',NULL,NULL,16.067,6.3,0,1.23966666666666647e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(64,1368,'tt0083944',NULL,'First Blood','First Blood','movie',1982,'https://image.tmdb.org/t/p/w500/a9sa6ERZCpplbPEO7OMWE763CLD.jpg','https://image.tmdb.org/t/p/original/teCZlGivejMw4rVzyxBSYQNr6XI.jpg','When former Green Beret John Rambo is harassed by local law enforcement and arrested for vagrancy, he is forced to flee into the mountains and wage an escalating one-man war against his pursuers.',NULL,NULL,11.3456,7.51,0,11.395,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(65,76726,'tt1706593',NULL,'Chronicle','Chronicle','movie',2012,'https://image.tmdb.org/t/p/w500/kdyrdFIt29FUmLIKvedAc2j4rpo.jpg','https://image.tmdb.org/t/p/original/rgNzvSagnlc32TuMEBa529QFIig.jpg','Three high school students make an incredible discovery, leading to their developing uncanny powers beyond their understanding. As they learn to control their abilities and use them to their advantage, their lives start to spin out of control, and their darker sides begin to take over.',NULL,NULL,7.8997,6.854,0,11.27,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(66,12783,'tt0864761',NULL,'The Duchess','The Duchess','movie',2008,'https://image.tmdb.org/t/p/w500/77ckyYrWmR12kl3qToqmDySnuwv.jpg','https://image.tmdb.org/t/p/original/qY6jnp4cNUYMz6FBG7ATtVmWttM.jpg','A chronicle of the life of 18th century aristocrat Georgiana, Duchess of Devonshire, who was reviled for her extravagant political and personal life.',NULL,NULL,4.8078,6.98,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(67,457136,'tt2328900',NULL,'Mary Queen of Scots','Mary Queen of Scots','movie',2018,'https://image.tmdb.org/t/p/w500/b5RMzLAyq5QW6GtN9sIeAEMLlBI.jpg','https://image.tmdb.org/t/p/original/iv5N169nQIzrS0pZ8MBEiemTtVt.jpg','In 1561, Mary Stuart, widow of the King of France, returns to Scotland, reclaims her rightful throne and menaces the future of Queen Elizabeth I as ruler of England, because she has a legitimate claim to the English throne. Betrayals, rebellions, conspiracies and their own life choices imperil both Queens. They experience the bitter cost of power, until their tragic fate is finally fulfilled.',NULL,NULL,3.0476,6.557,0,11.28,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(68,531428,'tt8613070',NULL,'Portrait of a Lady on Fire','Portrait de la jeune fille en feu','movie',2019,'https://image.tmdb.org/t/p/w500/rUDuOKpkKBHxx41BScqKej72iT3.jpg','https://image.tmdb.org/t/p/original/ivJ5UzT6IzucLVfbZwCCwiJJoBz.jpg','On an isolated island in Brittany at the end of the eighteenth century, a female painter is obliged to paint a wedding portrait of a young woman.',NULL,NULL,11.9654,8.095,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(69,11347,'tt0095488',NULL,'The Lair of the White Worm','The Lair of the White Worm','movie',1988,'https://image.tmdb.org/t/p/w500/bhL5Z8srwSXJuosfBqei9Dxv41C.jpg','https://image.tmdb.org/t/p/original/eeBXjRQikfiIlagI0EWTAE1ymLr.jpg','When an archaeologist uncovers a strange skull in a foreign land, the residents of a nearby town begin to disappear, leading to further inexplicable occurrences.',NULL,NULL,3.3706,5.944,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(70,8327,'tt0071615',NULL,'The Holy Mountain','La montaña sagrada','movie',1973,'https://image.tmdb.org/t/p/w500/mP5FGQbNjFkrjcZ6AVHrvokPRe5.jpg','https://image.tmdb.org/t/p/original/oUceCsSe255ZKXCMsHhqXM1xuUp.jpg','The Alchemist assembles together a group of people from all walks of life to represent the planets in the solar system. The occult adept''s intention is to put his recruits through strange mystical rites and divest them of their worldly baggage before embarking on a trip to Lotus Island. There they ascend the Holy Mountain to displace the immortal gods who secretly rule the universe.',NULL,NULL,4.9556,7.526,0,1.64657142857142844e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(71,16184,'tt0304262',NULL,'The Happiness of the Katakuris','カタクリ家の幸福','movie',2002,'https://image.tmdb.org/t/p/w500/8iIei17w5DVEz4P9OjxIM10f7Jh.jpg','https://image.tmdb.org/t/p/original/8kFu3NmbwMmi8iRXWy09awhMFLC.jpg','The Katakuri family has just opened their guest house in the mountains. Unfortunately their first guest commits suicide and in order to avoid trouble they decide to bury him in the backyard. Things get way more complicated when their second guest, a famous sumo wrestler, dies while having sex with his underage girlfriend and the grave behind the house starts to fill up more and more.',NULL,NULL,0.8345,6.9,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(72,985,'tt0074486',NULL,'Eraserhead','Eraserhead','movie',1977,'https://image.tmdb.org/t/p/w500/mxveW3mGVc0DzLdOmtkZsgd7c3B.jpg','https://image.tmdb.org/t/p/original/ApB0mF2d5Oqioi3yxjuogiotSLI.jpg','First-time father Henry Spencer tries to survive his industrial environment, his angry girlfriend, and the unbearable screams of his newly born mutant child.',NULL,NULL,7.194,7.337,0,25.814375,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(73,16642,'tt0077405',NULL,'Days of Heaven','Days of Heaven','movie',1978,'https://image.tmdb.org/t/p/w500/rwxTYjOZmX2rGhz7avLe1qsjNqe.jpg','https://image.tmdb.org/t/p/original/zUqIL6H6d44se9ZOsfvvCuOsbap.jpg','In 1916, a Chicago steel worker accidentally kills his supervisor and flees to the Texas panhandle with his girlfriend and little sister to work harvesting wheat in the fields of a stoic farmer.',NULL,NULL,3.0842,7.476,0,10.514,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(74,21168,'tt0100469',NULL,'The Reflecting Skin','The Reflecting Skin','movie',1990,'https://image.tmdb.org/t/p/w500/ehUosbTVyCQtf6nAfpmQ8Q3XSd7.jpg','https://image.tmdb.org/t/p/original/y5xRzPzLk1gEnatnAfI6YKcHkCr.jpg','In 1950s rural Idaho, a young boy watches helplessly as his friends and brother fall under the spell of a mysterious widow living up the road and becomes convinced that she is a vampire.',NULL,NULL,1.6566,6.7,0,14.718,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(75,4512,'tt0443680',NULL,'The Assassination of Jesse James by the Coward Robert Ford','The Assassination of Jesse James by the Coward Robert Ford','movie',2007,'https://image.tmdb.org/t/p/w500/xMKn6EQS7eR5ubhPJbw5pQSBZMw.jpg','https://image.tmdb.org/t/p/original/3HvQ5PaxwQJEiRSZD5AyVuqEiNn.jpg','Outlaw Jesse James is rumored to be the ''fastest gun in the West''. An eager recruit into James'' notorious gang, Robert Ford eventually grows jealous of the famed outlaw and, when Robert and his brother sense an opportunity to kill James, their murderous action elevates their target to near mythical status.',NULL,NULL,4.0769,7.058,0,13.895,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(76,770,'tt0031381',NULL,'Gone with the Wind','Gone with the Wind','movie',1939,'https://image.tmdb.org/t/p/w500/lNz2Ow0wGCAvzckW7EOjE03KcYv.jpg','https://image.tmdb.org/t/p/original/4FHcxMtVruMr7ltU2cItWssLjTP.jpg','The spoiled daughter of a Georgia plantation owner conducts a tumultuous romance with a cynical profiteer during the American Civil War and Reconstruction Era.',NULL,NULL,10.7203,7.909,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(77,655,'tt0087884',NULL,'Paris, Texas','Paris, Texas','movie',1984,'https://image.tmdb.org/t/p/w500/sP27Qm4THyRZyHjHYMfIDtJP6YE.jpg','https://image.tmdb.org/t/p/original/fWrq3u16gaBJ6nYNWcR3XaOhQPq.jpg','A man wanders out of the desert not knowing who he is. His brother finds him, and helps to pull his memory back of the life he led before he walked out on his family and disappeared four years earlier.',NULL,NULL,6.9378,8.08,0,2.08841666666666654e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(78,150342,'tt0348060',NULL,'The Snow Queen','The Snow Queen','movie',1995,'https://image.tmdb.org/t/p/w500/fF5mUf8i4h4nxL6aWOzcbwcnvvc.jpg','https://image.tmdb.org/t/p/original/zMC3c29eMk4rvAlHSpagxE0wjN8.jpg','Far away, in her vast ice palace, the Snow Queen plots to rule the world by deflecting all the sun''s warmth away from Earth so that it freezes over. But her mirror breaks, and on her mission to find all the missing pieces, she kidnaps Tom, who has part of the mirror in his body. Can his sister Ellie save Tom, and stop the evil Queen from achieving global dominance?',NULL,NULL,0.7925,6.479,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(79,9837,'tt0120794',NULL,'The Prince of Egypt','The Prince of Egypt','movie',1998,'https://image.tmdb.org/t/p/w500/2xUjYwL6Ol7TLJPPKs7sYW5PWLX.jpg','https://image.tmdb.org/t/p/original/565DYYXgdRYMiETLi2EDx4p7s92.jpg','The strong bond between two Royal Egyptian brothers is challenged when their chosen responsibilities set them at odds, with extraordinary consequences.',NULL,NULL,9.3468,7.314,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(80,205584,'tt2404233',NULL,'Gods of Egypt','Gods of Egypt','movie',2016,'https://image.tmdb.org/t/p/w500/hzH7fwaTyQNITLo40Hu3R7cVMqv.jpg','https://image.tmdb.org/t/p/original/pl2zr5efo9Dz1fi2gpsslGwEQm.jpg','A common thief joins a mythical god on a quest through Egypt.',NULL,NULL,6.0902,5.698,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(81,583551,'tt3530728',NULL,'The Never Ending Love Story','無盡的慾','movie',1994,'https://image.tmdb.org/t/p/w500/8Rts0WO8CpaNi4hy2YOpdSdifCK.jpg','https://image.tmdb.org/t/p/original/wpqzvB7Ep9HBNQNdhPmsuLC0i07.jpg','Follows the changing love lives of college buddies KK and Ronnie, with their girlfriends/wives May and Candy. Workaholic adman KK and his girlfriend May are going through a tough time. They attend Ronnie’s wedding, where KK meets Ronnie’s cousin Candy. KK hires Candy as a secretary on Ronnie’s urging, and the two drift together. Meanwhile, Ronnie’s marriage fails, and he gets together with May….',NULL,NULL,0.6614,0.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(82,268893,'tt0500177',NULL,'VeggieTales: Where''s God When I''m S-Scared?','VeggieTales: Where''s God When I''m S-Scared?','movie',1993,'https://image.tmdb.org/t/p/w500/5UiJ6zPXEm5kb6X3Z1UXXt0NS8d.jpg','https://image.tmdb.org/t/p/original/3OpKiYVWMnkWAv8fhoP7I2xOVLS.jpg','Whether it''s a giant Frankencelery from a scary movie or a hungry den of lions from Ancient Babylon, Junior Asparagus learns we can trust God with all of our fears and that He really is "bigger than the boogey-man!"',NULL,NULL,0.4771,6.7,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(83,8785,'tt0059643',NULL,'The Saragossa Manuscript','Rękopis znaleziony w Saragossie','movie',1966,'https://image.tmdb.org/t/p/w500/aFqDycFgEt1ko80mcj3wFWGQS1O.jpg','https://image.tmdb.org/t/p/original/amOWoHk6wwkwphimSqc3WIzIQ3l.jpg','During the Napoleonic wars, a Spanish officer and an opposing officer find a book written by the former''s grandfather.',NULL,NULL,1.2794,7.763,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(84,947,'tt0056172',NULL,'Lawrence of Arabia','Lawrence of Arabia','movie',1962,'https://image.tmdb.org/t/p/w500/AiAm0EtDvyGqNpVoieRw4u65vD1.jpg','https://image.tmdb.org/t/p/original/z30x999Uku15xcFbe5s3hLvQPDl.jpg','During World War I, English officer Thomas Edward ''T.E.'' Lawrence sets out to unite and lead the diverse, often warring, Arab tribes to fight the Turks.',NULL,NULL,7.4102,7.997,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(85,16672,'tt0058625',NULL,'Woman in the Dunes','砂の女','movie',1964,'https://image.tmdb.org/t/p/w500/xiBr3bIT2xpbuIKo5bLK7ebP4O1.jpg','https://image.tmdb.org/t/p/original/dxfFh9pTKDaYH2B6PwcR6ohCM1L.jpg','A vacationing entomologist suffers extreme physical and psychological trauma after being taken captive by the residents of a poor seaside village and made to live with a woman whose life task is shoveling sand for them.',NULL,NULL,2.8912,8.2,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(86,13041,'tt0067866',NULL,'El Topo','El Topo','movie',1970,'https://image.tmdb.org/t/p/w500/fKoNBTATc94rUYLq8VyypS24LUw.jpg','https://image.tmdb.org/t/p/original/xkfXO0Zswvvlbs0FlxH3TA4qji3.jpg','El Topo decides to confront warrior Masters on a trans-formative desert journey he begins with his 6 year old son, who must bury his childhood totems to become a man.',NULL,NULL,1.9016,7.1,0,1.23466666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(87,89,'tt0097576',NULL,'Indiana Jones and the Last Crusade','Indiana Jones and the Last Crusade','movie',1989,'https://image.tmdb.org/t/p/w500/sizg1AU8f8JDZX4QIgE4pjUMBvx.jpg','https://image.tmdb.org/t/p/original/12fvZHskx57kQfNEUXJ3v0flWYQ.jpg','In 1938, an art collector appeals to eminent archaeologist Dr. Indiana Jones to embark on a search for the Holy Grail. Indy learns that a medieval historian has vanished while searching for it, and the missing man is his own father, Dr. Henry Jones Sr.. He sets out to rescue his father by following clues in the old man''s notebook, which his father had mailed to him before he went missing. Indy arrives in Venice, where he enlists the help of a beautiful academic, Dr. Elsa Schneider, along with Marcus Brody and Sallah. Together they must stop the Nazis from recovering the power of eternal life and taking over the world!',NULL,NULL,9.9162,7.853,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(88,564,'tt0120616',NULL,'The Mummy','The Mummy','movie',1999,'https://image.tmdb.org/t/p/w500/yhIsVvcUm7QxzLfT6HW2wLf5ajY.jpg','https://image.tmdb.org/t/p/original/8zLS8p1tRyWFLRFfmgQq0j5WE6z.jpg','Dashing legionnaire Rick O''Connell stumbles upon the hidden ruins of Hamunaptra while in the midst of a battle to claim the area in 1920s Egypt. It has been over three thousand years since former High Priest Imhotep suffered a fate worse than death as a punishment for a forbidden love—along with a curse that guarantees eternal doom upon the world if he is ever awoken.',NULL,NULL,17.5987,6.984,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(89,14784,'tt0460791',NULL,'The Fall','The Fall','movie',2006,'https://image.tmdb.org/t/p/w500/ez7xavvDr5yDz4sSvI55xDp0BoU.jpg','https://image.tmdb.org/t/p/original/vNrXoT45xscHY6AN4IGf44vHxVJ.jpg','In a hospital on the outskirts of 1920s Los Angeles, an injured stuntman begins to tell a fellow patient, a little girl with a broken arm, a fantastic story about 5 mythical heroes. Thanks to his fractured state of mind and her vivid imagination, the line between fiction and reality starts to blur as the tale advances.',NULL,NULL,5.2155,7.6,0,2.33492857142857133e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(90,169881,'tt2101473',NULL,'The Physician','The Physician','movie',2013,'https://image.tmdb.org/t/p/w500/18eJr4Fc4HKymLgKLgGQbD37SPK.jpg','https://image.tmdb.org/t/p/original/5VuOmxGfqu7yf05q8Q6SUKOh7oe.jpg','England, 1021: Born in a miserable mining town, Robert Cole swears to become a physician and vanquish disease and death. His harsh path of many years, a quest for knowledge besieged by countless challenges and sacrifices, leads him to the remote Isfahan, in Persia, where he meets Ibn Sina, the greatest healer of his time.',NULL,NULL,3.415,7.337,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(91,1734,'tt0209163',NULL,'The Mummy Returns','The Mummy Returns','movie',2001,'https://image.tmdb.org/t/p/w500/kdJsW7hcy1lrj7tdMPycTAQPAiR.jpg','https://image.tmdb.org/t/p/original/7s7WkAFPBsMTprYMbqbgKoppQsR.jpg','Rick and Evelyn O’Connell, along with their 8-year-old son Alex, discover the key to the legendary Scorpion King’s might: the fabled Bracelet of Anubis. Unfortunately, a newly resurrected Imhotep has designs on the bracelet as well, and isn’t above kidnapping its new bearer, Alex, to gain control of Anubis’s otherworldly army.',NULL,NULL,11.9204,6.41,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(92,9334,'tt0277296',NULL,'The Scorpion King','The Scorpion King','movie',2002,'https://image.tmdb.org/t/p/w500/aITIsX20tACn6jgtyDcCYpRT216.jpg','https://image.tmdb.org/t/p/original/nZSUgauXlVUrJGdGUGWMXCtnZx4.jpg','In ancient Egypt, peasant Mathayus is hired to exact revenge on the powerful Memnon and the sorceress Cassandra, who are ready to overtake Balthazar''s village. Amid betrayals, thieves, abductions and more, Mathayus strives to bring justice to his complicated world.',NULL,NULL,4.5299,5.591,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(93,458576,'tt6475714',NULL,'Monster Hunter','Monster Hunter','movie',2020,'https://image.tmdb.org/t/p/w500/1UCOF11QCw8kcqvce8LKOO6pimh.jpg','https://image.tmdb.org/t/p/original/8tNX8s3j1O0eqilOQkuroRLyOZA.jpg','A portal transports Cpt. Artemis and an elite unit of soldiers to a strange world where powerful monsters rule with deadly ferocity. Faced with relentless danger, the team encounters a mysterious hunter who may be their only hope to find a way home.',NULL,NULL,4.315,6.512,0,10.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(94,9028,'tt0063032',NULL,'The Great Silence','Il grande silenzio','movie',1968,'https://image.tmdb.org/t/p/w500/3kpxS7SZMyYSXvhDnmxQXOOxiTM.jpg','https://image.tmdb.org/t/p/original/ksGuopH0XgXLNHJMvoqZMl3lHTT.jpg','A mute gunslinger fights in the defense of a group of outlaws and a vengeful young widow, against a group of ruthless bounty hunters.',NULL,NULL,1.9427,7.5,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(95,248933,'tt2650978',NULL,'The Dark Valley','Das finstere Tal','movie',2014,'https://image.tmdb.org/t/p/w500/8s59L4YCmDNyQAkSrlkvc3Vc3fp.jpg','https://image.tmdb.org/t/p/original/fXHT6tTLVCchwrsFkpTyqtUcsCy.jpg','The Alps, late 19th century. Greider, a mysterious lone rider who claims to be a photographer, arrives at an isolated lumber village, despotically ruled by a family clan, asking for winter accommodation.',NULL,NULL,1.3116,7.042,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(96,10212,'tt0129332',NULL,'Ravenous','Ravenous','movie',1999,'https://image.tmdb.org/t/p/w500/6tJc9vIVYctNCajC1dU1oVcmIsD.jpg','https://image.tmdb.org/t/p/original/mBw7GMmRycQHFXRUjn70KrzCJCq.jpg','After arriving at his new, remote Army outpost, Capt. John Boyd and his regiment aid a wounded frontiersman who recounts a horrifying tale of a wagon train murdered by its supposed guide – a vicious U.S. Army colonel gone rogue. Fearing the worst, the regiment heads out into the wilderness to verify the gruesome claims.',NULL,NULL,2.7756,6.846,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(97,29496,'tt0066939',NULL,'Cut-Throats Nine','Condenados a vivir','movie',1971,'https://image.tmdb.org/t/p/w500/o2YJpPfcmliO36dtjsBOroN9tgs.jpg','https://image.tmdb.org/t/p/original/eIH1NgJx5btpvcamE5IFumZTGZM.jpg','A group of ruthless convicts is led to prison through an inhospitable mountain range by a small cavalry detachment commanded by Sergeant Brown, who is accompanied by his young and beautiful daughter.',NULL,NULL,1.8154,6.5,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(98,281957,'tt1663202',NULL,'The Revenant','The Revenant','movie',2015,'https://image.tmdb.org/t/p/w500/ji3ecJphATlVgWNY0B0RVXZizdf.jpg','https://image.tmdb.org/t/p/original/hEQYZq2CDB2LSJVxxlazdBOKeyW.jpg','In the 1820s, a frontiersman, Hugh Glass, sets out on a path of vengeance against those who left him for dead after a bear mauling.',NULL,NULL,12.2186,7.541,0,6.81000000000000049e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(99,294963,'tt2494362',NULL,'Bone Tomahawk','Bone Tomahawk','movie',2015,'https://image.tmdb.org/t/p/w500/4MmTHpn2Y8emqvBgvOjufImUmKZ.jpg','https://image.tmdb.org/t/p/original/orXMq2jZy8wFmePv7zXS2Kor7Ug.jpg','During a shootout in a saloon, Sheriff Hunt injures a suspicious stranger. The doctor''s assistant, wife of the local foreman, tends to him in prison. That night, the town is attacked and they both disappear—only the arrow of a cannibal tribe is found. Hunt and a few of his men go in search of the prisoner and the foreman''s wife.',NULL,NULL,3.3584,6.9,0,8.52799999999999869e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(100,2362,'tt0070909',NULL,'Westworld','Westworld','movie',1973,'https://image.tmdb.org/t/p/w500/qNt29HzxwZ4jGTgSRxdA34ino9Q.jpg','https://image.tmdb.org/t/p/original/m9K8LWrIuujCvYW9c7SgIOSOOj1.jpg','Delos is a futuristic amusement park that features themed worlds populated by human-like androids. After two patrons have a run-in with a menacing gunslinger in West World, the androids at Delos all begin to malfunction, causing havoc throughout the park.',NULL,NULL,5.3175,6.8,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(101,273248,'tt3460252',NULL,'The Hateful Eight','The Hateful Eight','movie',2015,'https://image.tmdb.org/t/p/w500/jIywvdPjia2t3eKYbjVTcwBQlG8.jpg','https://image.tmdb.org/t/p/original/7g1zO5t0bd27Iqn5ZUDJmksOGPJ.jpg','Bounty hunters seek shelter from a raging blizzard and get caught up in a plot of betrayal and deception.',NULL,NULL,9.7193,7.757,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(102,18,'tt0119116',NULL,'The Fifth Element','Le Cinquième Élément','movie',1997,'https://image.tmdb.org/t/p/w500/fPtlCO1yQtnoLHOwKtWz7db6RGU.jpg','https://image.tmdb.org/t/p/original/jW21PoKwqs79wk6bfiYezox63mK.jpg','In 2257, a taxi driver is unintentionally given the task of saving a young girl who is part of the key that will ensure the survival of humanity.',NULL,NULL,13.9533,7.585,0,2.0673636363636362e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(103,28422,'tt1128075',NULL,'Love Exposure','愛のむきだし','movie',2008,'https://image.tmdb.org/t/p/w500/p4DFAaYsMt15W7YZWMSvsUFDTew.jpg','https://image.tmdb.org/t/p/original/ywVxppdRe8KN53P937p94mcXEoJ.jpg','The story of a teenage boy called Yu, who falls for Yoko, a girl he runs into while operating for the sake of sin as an upskirt photographer in an offshoot of the porn industry. His attempts to woo her are complicated by a spot of cross-dressing - which convinces Yoko that she is lesbian - dalliances with kung-fu and crime, and a constant struggle with the guilt that''s a legacy of his Catholic upbringing.',NULL,NULL,3.4751,7.922,0,14.816,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(104,NULL,NULL,193776,'Portal Maze 2','Portal Maze 2','game',2021,'https://images.igdb.com/igdb/image/upload/t_cover_big/coaanx.jpg',NULL,NULL,'https://www.igdb.com/games/portal-maze-2','["Android"]',NULL,NULL,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(105,264660,'tt0470752',NULL,'Ex Machina','Ex Machina','movie',2015,'https://image.tmdb.org/t/p/w500/dmJW8IAKHKxFNiUnoDR7JfsK7Rp.jpg','https://image.tmdb.org/t/p/original/uqOuJ50EtTj7kkDIXP8LCg7G45D.jpg','Caleb, a coder at the world''s largest internet company, wins a competition to spend a week at a private mountain retreat belonging to Nathan, the reclusive CEO of the company. But when Caleb arrives at the remote location he finds that he will have to participate in a strange and fascinating experiment in which he must interact with the world''s first true artificial intelligence, housed in the body of a beautiful robot girl.',NULL,NULL,11.0192,7.572,0,1.2716666666666665e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(106,NULL,NULL,139615,'Control: Override','Control: Override','game',2021,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2j0h.jpg',NULL,'Control: Override is a puzzle game where control itself is a powerup. Solve puzzles, Break through a rogue AI''s security layers and confront the truth about why it went rogue.','https://www.igdb.com/games/control-override','["PC (Microsoft Windows)", "Xbox One"]',NULL,NULL,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(107,341006,'tt1082807',NULL,'The Belko Experiment','The Belko Experiment','movie',2017,'https://image.tmdb.org/t/p/w500/faJK0dP3S92kQoKtO4LZMjy41kf.jpg','https://image.tmdb.org/t/p/original/10OzC1HoKp2AwkaPktH3HsQM2u5.jpg','A group of eighty American workers are locked in their office and ordered by an unknown voice to participate in a twisted game.',NULL,NULL,2.7345,6.168,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(108,73499,'tt1646980',NULL,'The Double','The Double','movie',2011,'https://image.tmdb.org/t/p/w500/t4W10sjJSDAWRUDn2Kb8DQKxiZv.jpg','https://image.tmdb.org/t/p/original/tY1z1IqNBTiH4bUXt4LLiYXLYpq.jpg','The mysterious murder of a US senator bearing the distinctive trademark of the legendary Soviet assassin ''Cassius'', forces retired CIA operative, Paul Shepherson to team with rookie FBI agent, Ben Geary  to solve the crime. Having spent his career chasing Cassius, Shepherdson is convinced his nemesis is long dead, but is pushed to take on the case by his former supervisor, Tom Highland. Geary, who wrote his Master''s thesis on Shepherdson''s pursuit of the Soviet killer, is certain that Cassius has resurfaced.',NULL,NULL,2.7617,5.826,0,1.20166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(109,14337,'tt0390384',NULL,'Primer','Primer','movie',2004,'https://image.tmdb.org/t/p/w500/xEoq2WmDzpzxhkHEsmOYOg6BPg6.jpg','https://image.tmdb.org/t/p/original/blSQbKAreIqcu2AWGDNjR8k3fAy.jpg','A group of fledgling inventors discover a complex method to manipulate reality. At first, they successfully game the stock market with it, but the consequences of the invention start to catch up with them.',NULL,NULL,3.3361,6.749,0,1.16650000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(110,492,'tt0120601',NULL,'Being John Malkovich','Being John Malkovich','movie',1999,'https://image.tmdb.org/t/p/w500/31FGQu3OnwdmS4COquENe0vMZc0.jpg','https://image.tmdb.org/t/p/original/1Nyjb7aeRKynWgmOl8he5ZcvWLm.jpg','One day at work, unsuccessful puppeteer Craig finds a portal into the head of actor John Malkovich. The portal soon becomes a passion for anybody who enters its mad and controlling world of overtaking another human body.',NULL,NULL,4.3248,7.421,0,14.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(111,421471,'tt2582784',NULL,'Flower','Flower','movie',2017,'https://image.tmdb.org/t/p/w500/xYTI11qFnmx39LRhDOsGEabfqtp.jpg','https://image.tmdb.org/t/p/original/lcgaDmokrKltbgwQu9Wf6X0qPTE.jpg','Rebellious, quick-witted Erica Vandross is a 17-year-old firecracker living with her single mom, Laurie, and her mom''s new boyfriend, Bob, in L.A.''s San Fernando Valley. When Bob''s mentally unbalanced son, Luke, arrives from rehab to live with the family, Erica finds her domestic and personal life overwhelmed. With Luke and her sidekicks Kala and Claudine in tow, Erica acts out by exposing a high school teacher''s dark secret.',NULL,NULL,1.0194,6.313,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(112,73567,'tt1726669',NULL,'Killer Joe','Killer Joe','movie',2012,'https://image.tmdb.org/t/p/w500/6Tt1TQeOI4TpXu1cBUgNGNGeznW.jpg','https://image.tmdb.org/t/p/original/20LDgpq7CzqRDEBa4WBlbon2J8.jpg','A cop who moonlights as a hit man agrees to kill the hated mother of a desperate drug dealer in exchange for a tumble with the young man''s virginal sister.',NULL,NULL,3.045,6.53,0,13.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(113,146233,'tt1392214',NULL,'Prisoners','Prisoners','movie',2013,'https://image.tmdb.org/t/p/w500/uhviyknTT5cEQXbn6vWIqfM4vGm.jpg','https://image.tmdb.org/t/p/original/yKsMvfVx8vrvAM6NQSTEX0rBmMK.jpg','After his six-year-old daughter is abducted, a desperate father takes justice into his own hands when he loses faith in the detective leading the investigation, setting both men on a collision course as the search descends into obsession and moral compromise.',NULL,NULL,14.2496,8.106,0,1.44140000000000014e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(114,1288341,'tt36926359',NULL,'Seven Snipers','Seven Snipers','movie',2026,'https://image.tmdb.org/t/p/w500/pK6tGCG6UAgUT5FTq3ylGErHxQQ.jpg','https://image.tmdb.org/t/p/original/g2aOpyCO1vEyUZURh3V5uaHu187.jpg','When a former elite sniper is hunted down by the ruthless warlord who once held her captive, she must fight to the death to protect the daughter she has raised in hiding, on a remote Australian farm.',NULL,NULL,53.6448,5.821,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(115,39013,'tt1399683',NULL,'Winter''s Bone','Winter''s Bone','movie',2010,'https://image.tmdb.org/t/p/w500/a0qhPkNlxLfsf5B2jFyI1Pp04XV.jpg','https://image.tmdb.org/t/p/original/wW4dZWEfUIXWVKhKsPFBokndJbI.jpg','After discovering her father put their house up for his bail bond and then disappeared, 17-year-old Ree Dolly must confront the local criminal underworld and the harsh Ozark wilderness in order to to track down her father and save her family.',NULL,NULL,2.7812,6.781,0,1.31266666666666669e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(116,46648,'tt2356777',NULL,'True Detective','True Detective','tv',2014,'https://image.tmdb.org/t/p/w500/dC7jkj2g1aU8sxKqM6D4g44xA6w.jpg','https://image.tmdb.org/t/p/original/v8YFr8BbU9qsO8PYIulzTeM6Qk.jpg','An American anthology police detective series utilizing multiple timelines in which investigations seem to unearth personal and professional secrets of those involved, both within or outside the law.',NULL,NULL,39.3356,8.292,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(117,38545,'tt0100842',NULL,'The Unbelievable Truth','The Unbelievable Truth','movie',1990,'https://image.tmdb.org/t/p/w500/36Gqgyh1nOguvnIH8RBfhj7EpjH.jpg','https://image.tmdb.org/t/p/original/sKE6dfuO56T0xq88xuiHahuDDNA.jpg','After serving time for murder, Josh Hutton returns to his home town where he meets Audry Hugo. No one can remember exactly what Josh did...',NULL,NULL,1.2969,6.9,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(118,13132,'tt0299458',NULL,'All the Real Girls','All the Real Girls','movie',2003,'https://image.tmdb.org/t/p/w500/sQ6dMkwPIFucYSmFQcr38WBYzs.jpg','https://image.tmdb.org/t/p/original/dRtyK88tpvxWyBPVRLx4b64W036.jpg','In a sleepy little mill town in North Carolina, Paul is the town Romeo. But when his best friend''s sister returns home from boarding school, he finds himself falling for her innocent charm. In spite of her lack of experience and the violent protests of her brother, the two find themselves in a sweet, dreamy and all-consuming love.',NULL,NULL,1.2407,6.0,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(119,12656,'tt0116289',NULL,'Feeling Minnesota','Feeling Minnesota','movie',1996,'https://image.tmdb.org/t/p/w500/fCJ5eUZw6mGS53spQxGUu7rzFm1.jpg','https://image.tmdb.org/t/p/original/pWQccERGRrNRJTEK9cOLV8M4Efx.jpg','Sam Clayton''s marriage to ex-stripper Freddie comes about when she''s strong-armed into the match by Red, a club proprietor who once did her a favor. But Freddie falls in love with Jjaks, Sam''s brother, and the pair tries to escape the situation together. It isn''t long before both Sam and Red catch up with them, resulting in threats against the two of them -- although tension also starts to build between Sam and Red.',NULL,NULL,1.7108,5.428,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(120,1920,'tt0098936',NULL,'Twin Peaks','Twin Peaks','tv',1990,'https://image.tmdb.org/t/p/w500/lA9CNSdo50iQPZ8A2fyVpMvJZAf.jpg','https://image.tmdb.org/t/p/original/j5w04XEuFv85N3RIovXBJIHxjSb.jpg','The body of Laura Palmer is washed up on a beach near the small Washington state town of Twin Peaks. FBI Special Agent Dale Cooper is called in to investigate her strange demise only to uncover a web of mystery that ultimately leads him deep into the heart of the surrounding woodland and his very own soul.',NULL,NULL,41.9831,8.34,0,3.15609090909090923e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(121,1923,'tt0105665',NULL,'Twin Peaks: Fire Walk with Me','Twin Peaks: Fire Walk with Me','movie',1992,'https://image.tmdb.org/t/p/w500/mxsGXqetGnirf99qapYd5MMY1VL.jpg','https://image.tmdb.org/t/p/original/amGU1FpELmenVvNmPShW58Orepy.jpg','In the questionable town of Deer Meadow, Washington, FBI Agent Desmond inexplicably disappears while hunting for the man who murdered a teen girl. The killer is never apprehended, and, after experiencing dark visions and supernatural encounters, Agent Dale Cooper chillingly predicts that the culprit will claim another life. Meanwhile, in the more cozy town of Twin Peaks, hedonistic beauty Laura Palmer hangs with lowlifes and seems destined for a grisly fate.',NULL,NULL,5.3051,7.4,0,16.58,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(122,1402,'tt1520211',NULL,'The Walking Dead','The Walking Dead','tv',2010,'https://image.tmdb.org/t/p/w500/aN29llVoCFtBTwDZFtqdD9d8dHb.jpg','https://image.tmdb.org/t/p/original/rAOjnEFTuNysY7bot8zonhImGMh.jpg','Sheriff''s deputy Rick Grimes awakens from a coma to find a post-apocalyptic world dominated by flesh-eating zombies. He sets out to find his family and encounters many other survivors along the way.',NULL,NULL,97.4201,8.085,0,12.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(123,11778,'tt0077416',NULL,'The Deer Hunter','The Deer Hunter','movie',1978,'https://image.tmdb.org/t/p/w500/bbGtogDZOg09bm42KIpCXUXICkh.jpg','https://image.tmdb.org/t/p/original/a5zBQfXmLk3qqRYF7AioWpiAxk2.jpg','Three steelworkers enlist in the army and are sent to Vietnam, one leaving behind a rushed marriage, the others a shared love. What they encounter during the war changes their lives forever.',NULL,NULL,6.6686,7.969,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(124,2039,'tt0093565',NULL,'Moonstruck','Moonstruck','movie',1987,'https://image.tmdb.org/t/p/w500/2mnVWpvsHEHHnfvLn1NXYVvBGl5.jpg','https://image.tmdb.org/t/p/original/5RQ5SIcrtKeUYeYeJLRTljR8LcN.jpg','37-year-old Italian-American widow Loretta Castorini believes she is unlucky in love, and so accepts a marriage proposal from her boyfriend Johnny, even though she doesn''t love him. When she meets his estranged younger brother Ronny, an emotional and passionate man, she finds herself drawn to him. She tries to resist, but Ronny, who blames his brother for the loss of his hand, has no scruples about aggressively pursuing her while Johnny is out of the country. As Loretta falls for Ronny, she learns that she''s not the only one in her family with a secret romance.',NULL,NULL,3.5299,6.8,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(125,11009,'tt0076666',NULL,'Saturday Night Fever','Saturday Night Fever','movie',1977,'https://image.tmdb.org/t/p/w500/ylA7E5Md21aqgzxbwa2dFxX8LKV.jpg','https://image.tmdb.org/t/p/original/iihMna17sTxP3zwlWBsKZbvDiGZ.jpg','Tony spends his Saturdays at a disco where his stylish moves raise his popularity among the patrons. But his life outside the disco is not easy and things change when he gets attracted to Stephanie.',NULL,NULL,4.6698,6.733,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(126,4032,'tt0102492',NULL,'My Girl','My Girl','movie',1991,'https://image.tmdb.org/t/p/w500/qyJJNHteA7BUwQSey05t7qP4vRV.jpg','https://image.tmdb.org/t/p/original/vSd89kiENYeFa6mPHzsM5BgliPm.jpg','Vada Sultenfuss is obsessed with death. Her mother is dead, and her father runs a funeral parlor. She is also in love with her English teacher, and joins a poetry class over the summer just to impress him. Thomas J., her best friend, is "allergic to everything", and sticks with Vada despite her hangups. When Vada''s father hires Shelly, and begins to fall for her, things take a turn to the worse...',NULL,NULL,4.8729,7.418,0,1.4067499999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(127,13,'tt0109830',NULL,'Forrest Gump','Forrest Gump','movie',1994,'https://image.tmdb.org/t/p/w500/Cw4hIUIAmSYfK9QfaUW5igp9La.jpg','https://image.tmdb.org/t/p/original/66Kn4XWhkuPkJxOJyPEx4U2CUfN.jpg','A man with a low IQ has accomplished great things in his life and been present during significant historic events—in each case, far exceeding what anyone imagined he could do. But despite all he has achieved, his one true love eludes him.',NULL,NULL,35.9374,8.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(128,18415,'tt0119237',NULL,'Gummo','Gummo','movie',1997,'https://image.tmdb.org/t/p/w500/tMdoCRx0XIPR5uYBwxbxR7WCNBb.jpg','https://image.tmdb.org/t/p/original/mLdMnoIE4SjMkTkgxayaHH9DS4.jpg','Teenagers Solomon and Tummler kill time in Xenia, Ohio, a small town that has never recovered from the tornado that ravaged the community in the 1970s.',NULL,NULL,1.8903,6.616,0,2.13141666666666651e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(129,340487,'tt4468634',NULL,'Certain Women','Certain Women','movie',2016,'https://image.tmdb.org/t/p/w500/jIfW4p27B30zSfGCohB2S4cTRz4.jpg','https://image.tmdb.org/t/p/original/rq63u5290HJ6k42J5Mfi8KNu8Rl.jpg','Three strong-willed women strive to forge their own paths amidst the wide-open plains of the American Northwest: a lawyer forced to subdue a troubled client; a wife and mother whose plans to construct her dream home reveal fissures in her marriage; and a lonely ranch hand who forms an ambiguous bond with a young law student.',NULL,NULL,1.6021,6.0,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(130,98514,'tt0110998',NULL,'River of Grass','River of Grass','movie',1995,'https://image.tmdb.org/t/p/w500/i2s1L8AavAfKIcKf3ONhF3no405.jpg','https://image.tmdb.org/t/p/original/tErSuaPqo3XU5CWPSmORKwxRtwY.jpg','Cozy, a dissatisfied housewife, meets Lee at a bar. A drink turns into a home break-in, and a gunshot sends them on the run together, thinking they''ve committed murder.',NULL,NULL,1.0157,6.196,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(131,9464,'tt0118789',NULL,'Buffalo ''66','Buffalo ''66','movie',1998,'https://image.tmdb.org/t/p/w500/fxzXFzbSGNA52NHQCMqQiwzMIQw.jpg','https://image.tmdb.org/t/p/original/oCcRRoalUWy83x3gqhCIl6pPUAi.jpg','Billy is released after five years in prison. In the next moment, he kidnaps teenage student Layla and visits his parents with her, pretending she is his girlfriend and they will soon marry.',NULL,NULL,3.6073,7.1,0,1.43483333333333327e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(132,948549,'tt19637052',NULL,'Love Lies Bleeding','Love Lies Bleeding','movie',2024,'https://image.tmdb.org/t/p/w500/xImj8RLe39YK0lyVu9kXv7ApN8p.jpg','https://image.tmdb.org/t/p/original/oMiKHO3H5RixfLsiU5Vumhlp5sj.jpg','Reclusive gym manager Lou falls hard for Jackie, an ambitious bodybuilder headed through town to Las Vegas in pursuit of her dream. But their love ignites violence, pulling them deep into the web of Lou’s criminal family.',NULL,NULL,4.6306,6.547,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(133,590223,'tt2222042',NULL,'Love and Monsters','Love and Monsters','movie',2020,'https://image.tmdb.org/t/p/w500/718NnyxyQuBQcGWt9sdelA1Zc3h.jpg','https://image.tmdb.org/t/p/original/lA5fOBqTOQBQ1s9lEYYPmNXoYLi.jpg','Seven years since the Monsterpocalypse began, Joel Dawson has been living underground in order to survive. But after reconnecting over radio with his high school girlfriend Aimee, Joel decides to venture out to reunite with her, despite all the dangerous monsters that stand in his way.',NULL,NULL,4.6329,7.268,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(134,82654,'tt1588173',NULL,'Warm Bodies','Warm Bodies','movie',2013,'https://image.tmdb.org/t/p/w500/i8vCO3uszvlfBJVEyuIZVUDlt60.jpg','https://image.tmdb.org/t/p/original/iNl1i8OJAaCf3ElkOPI9ud6CuXB.jpg','After a zombie becomes involved with the girlfriend of one of his victims, their romance sets in motion a sequence of events that might transform the entire lifeless world.',NULL,NULL,4.7713,6.474,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(135,50456,'tt0993842',NULL,'Hanna','Hanna','movie',2011,'https://image.tmdb.org/t/p/w500/6QDeHwBXDHbCbuzStgUpuUAqnap.jpg','https://image.tmdb.org/t/p/original/qq39KWLKBBJmOtj54grO58XyoXG.jpg','Raised by her father, an ex-CIA agent, in the wilds of Finland, Hanna''s upbringing has been geared to making her the perfect assassin. Sent into the world by her father on a mission, Hanna journeys across Europe, eluding agents dispatched after her by a ruthless intelligence operative. As she nears her ultimate target, Hanna faces startling revelations about her existence.',NULL,NULL,3.3035,6.586,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(136,49020,'tt1440292',NULL,'Submarine','Submarine','movie',2011,'https://image.tmdb.org/t/p/w500/nbzXX3CYtKUBrPeMcG7PVoLQHXB.jpg','https://image.tmdb.org/t/p/original/zaa2noUk2Dm6IgdTWWEe4WpL08o.jpg','15-year-old deep-thinking Welsh schoolboy Oliver Tate struggles to initiate and maintain a relationship with Jordana, his devilish, dark-haired classmate at their Swansea high school. As his parents'' marriage begins to fall apart, similar problems arise in his relationship with Jordana.',NULL,NULL,5.5534,7.361,0,14.664,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(137,42188,'tt1334260',NULL,'Never Let Me Go','Never Let Me Go','movie',2010,'https://image.tmdb.org/t/p/w500/8F0r5ng9Fp60OhzQfR5v33fppq.jpg','https://image.tmdb.org/t/p/original/ppf18IfACeWmkObqyjrhmNiL6G4.jpg','As children, Kathy, Ruth, and Tommy spend their childhood at an idyllic and secluded English boarding school. As they grow into adults, they must come to terms with the complexity and strength of their love for one another while also preparing for the haunting reality awaiting them.',NULL,NULL,3.8668,6.851,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(138,99896,'tt8098956',NULL,'Noughts + Crosses','Noughts + Crosses','tv',2020,'https://image.tmdb.org/t/p/w500/xKo7Zog27jcGvPKGkpHkqbLqLR8.jpg','https://image.tmdb.org/t/p/original/tRHML16irVmFXqKDoIwP8Sk8rQU.jpg','In an alternate history where black “Cross” people rule over white “Noughts”, young couple Sephy and Callum are divided by their colour but united by love.',NULL,NULL,3.0237,5.9,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(139,430354,'tt4720702',NULL,'Bushwick','Bushwick','movie',2017,'https://image.tmdb.org/t/p/w500/9fGjmzxdiKWsrlY3syrm2aXeTq7.jpg','https://image.tmdb.org/t/p/original/3UcoX8gVusWaQI1jKQj2MOdf9zV.jpg','When an unknown military force invades Bushwick, a Brooklyn neighborhood, young student Lucy and war veteran Stupe must rely on each other to escape and survive.',NULL,NULL,2.4262,5.209,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(140,399366,'tt5886440',NULL,'Marrowbone','El secreto de Marrowbone','movie',2017,'https://image.tmdb.org/t/p/w500/iX77zMSqUv2Qt7ToEnN2mmEudEf.jpg','https://image.tmdb.org/t/p/original/mc7w3y83wQU9YAIAmP1hoxqQped.jpg','A young man and his three younger siblings are plagued by a sinister presence in the sprawling manor in which they live.',NULL,NULL,5.4173,7.28,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(141,17835,'tt0090163',NULL,'Threads','Threads','movie',1985,'https://image.tmdb.org/t/p/w500/1LZXTlcgDIdVFtPUvF7Q2XV6D2r.jpg','https://image.tmdb.org/t/p/original/k2flNjj017S5QkDmWC7i8IsRbyF.jpg','Documentary style account of a nuclear holocaust and its effect on the working class city of Sheffield, England; and the eventual long run effects of nuclear war on civilization.',NULL,NULL,2.0531,7.624,0,1.28433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(142,95202,'tt9151230',NULL,'To the Lake','Эпидемия','tv',2019,'https://image.tmdb.org/t/p/w500/miwLlQleUq3br4ozZl3p3hCLrkv.jpg','https://image.tmdb.org/t/p/original/hagv8VLYecqZkD97GRiGzTyzwWq.jpg','A grim drama that unfolds against the backdrop of a global catastrophe. An unknown new virus turns Moscow into a city of the dead. Money loses its value and those not yet infected struggle desperately for food and survival.',NULL,NULL,4.5471,7.338,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(143,8843,'tt0209958',NULL,'The Cell','The Cell','movie',2000,'https://image.tmdb.org/t/p/w500/1LX8AOUGDSrBDzgC4KLtRvyJFgY.jpg','https://image.tmdb.org/t/p/original/iFJ7GEIjIysbEJ36TohH28x6Nyu.jpg','A psychotherapist journeys inside a comatose serial killer in the hopes of saving his latest victim.',NULL,NULL,5.9064,6.273,0,2.33485714285714287e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(144,145623,'tt0058246',NULL,'The Games of Angels','Les jeux des anges','movie',1967,'https://image.tmdb.org/t/p/w500/rArDYpo0hBwID0J1e4p8g6Rn4fT.jpg','https://image.tmdb.org/t/p/original/5RUnoFZq9wfmCcRXKDIvsOrjfpE.jpg','Animated short. Abstract forms in a setting evocative of a concentration camp created by the universe. Based on a series of paintings by the Polish artists and filmmaker Walerian Borowczyk, Les Jeux des Anges takes the viewer into a nightmarish and sinister labyrinth world. With images reminiscent of Bosch and Ernst and an abstract soundtrack the film evoke unspeakable horrors lurking at the heart Borowczyk''s masterpiece. Borowczyk described the film himself as "A report on the city of angels."',NULL,NULL,1.1,5.5,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(145,1352874,'tt32059878',NULL,'The Crucifix: Blood of the Exorcist','The Crucifix: Blood of the Exorcist','movie',2025,'https://image.tmdb.org/t/p/w500/u3qOxvlykoTpurg1G8VOcawoePI.jpg','https://image.tmdb.org/t/p/original/be5T7oHxmDG4ytEimwPdmDHZD9N.jpg','A gruesome discovery in the grounds of their new home plunges a young couple into a maelstrom of spiritual possession, pagan rituals, Viking battles, and violent revenge.',NULL,NULL,15.5371,5.484,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(146,846867,'tt15090124',NULL,'Mad God','Mad God','movie',2021,'https://image.tmdb.org/t/p/w500/105stT9GkiENXiYqvWYKoAuHKQL.jpg','https://image.tmdb.org/t/p/original/eMDQdKeoWTrCm2wEs7I7OD3bTQl.jpg','A silent figure known as The Assassin travels through a nightmare underworld of tortured souls, ruined cities and wretched monstrosities forged from the primordial horrors of the unconscious mind of Phil Tippett, the world''s preeminent stop-motion animator.',NULL,NULL,2.1368,6.803,0,24.81,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(147,342737,'tt4385888',NULL,'20th Century Women','20th Century Women','movie',2016,'https://image.tmdb.org/t/p/w500/mso2rEr9i0MilRIOao5HaWFipS9.jpg','https://image.tmdb.org/t/p/original/5eZ8kRSlD8P8a42y9GEGl1yAqOb.jpg','In 1979 Santa Barbara, California, Dorothea Fields is a determined single mother in her mid-50s who is raising her adolescent son, Jamie, at a moment brimming with cultural change and rebellion. Dorothea enlists the help of two younger women – Abbie, a free-spirited punk artist living as a boarder in the Fields'' home and Julie, a savvy and provocative teenage neighbour – to help with Jamie''s upbringing.',NULL,NULL,3.3792,7.3,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(148,581734,'tt9770150',NULL,'Nomadland','Nomadland','movie',2021,'https://image.tmdb.org/t/p/w500/8Vc5EOUEIF1EUXuX9eLFf7BvN3P.jpg','https://image.tmdb.org/t/p/original/563sRDK3rZS31TXCdTY4lfcwrNK.jpg','A woman in her sixties embarks on a journey through the western United States after losing everything in the Great Recession, living as a van-dwelling modern-day nomad.',NULL,NULL,3.6104,7.163,0,11.27,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(149,334533,'tt3553976',NULL,'Captain Fantastic','Captain Fantastic','movie',2016,'https://image.tmdb.org/t/p/w500/2sFME73GaD8UsUxPUKe60cPdLif.jpg','https://image.tmdb.org/t/p/original/d84M69u6Q202dm6EvhVxbiqrK9f.jpg','Deep in the forests of the Pacific Northwest, a father devoted to raising his six kids with a rigorous physical and intellectual education is forced to leave his paradise and enter the world, beginning a journey that challenges his idea of what it means to be a parent.',NULL,NULL,4.8426,7.889,0,13.14,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(150,4688,'tt0445922',NULL,'Across the Universe','Across the Universe','movie',2007,'https://image.tmdb.org/t/p/w500/447c8Te3DXC46rQvDEixKGO4dS6.jpg','https://image.tmdb.org/t/p/original/s2mJnlqvRwVo1XpnmuPGvWso7pJ.jpg','When young dockworker Jude leaves Liverpool to find his estranged father in the United States, he is swept up by the waves of change that are re-shaping the nation. Jude falls in love with Lucy, who joins the growing anti-war movement. As the body count in Vietnam rises, political tensions at home spiral out of control and the star-crossed lovers find themselves in a psychedelic world gone mad.',NULL,NULL,2.731,7.1,0,11.275,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(151,624,'tt0064276',NULL,'Easy Rider','Easy Rider','movie',1969,'https://image.tmdb.org/t/p/w500/3H3vwPGX6EbBRffIVHp3eHHcjka.jpg','https://image.tmdb.org/t/p/original/qvTmYyYsv71qTq5syAq24k1kGk.jpg','Wyatt and Billy, two Harley-riding hippies, complete a drug deal in Southern California and decide to travel cross-country in search of spiritual truth.',NULL,NULL,3.1686,7.052,0,1.28566666666666673e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(152,934433,'tt17663992',NULL,'Scream VI','Scream VI','movie',2023,'https://image.tmdb.org/t/p/w500/wDWwtvkRRlgTiUr6TyLSMX8FCuZ.jpg','https://image.tmdb.org/t/p/original/k6ANeyxAfMRi5xhxIXv1Scn9vc2.jpg','Following the latest Ghostface killings, the four survivors leave Woodsboro behind and start a fresh chapter.',NULL,NULL,9.5918,6.94,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(153,11645,'tt0089881',NULL,'Ran','乱','movie',1985,'https://image.tmdb.org/t/p/w500/dGgiXMWDcS5aJTBEFu7bmaQPNox.jpg','https://image.tmdb.org/t/p/original/3ssNAWypRl47iriwBFNx7RUEUub.jpg','Shakespeare''s King Lear is reimagined as a singular historical epic set in sixteenth-century Japan where an aging warlord divides his kingdom between his three sons.',NULL,NULL,5.7747,8.011,0,15.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(154,33408,'tt0106627',NULL,'The Crush','The Crush','movie',1993,'https://image.tmdb.org/t/p/w500/4B0eHFjUYYZlkE1fthC29KVC4CS.jpg','https://image.tmdb.org/t/p/original/h8RQ5X0SzCLtICqIEgw2Xqcb7oY.jpg','A precocious and obsessive teenager develops a crush on a naive writer with harrowing consequences.',NULL,NULL,2.9724,6.666,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(155,660120,'tt10370710',NULL,'The Worst Person in the World','Verdens verste menneske','movie',2021,'https://image.tmdb.org/t/p/w500/1NxGNQchGBTHXJ6RShLY1IlZqWn.jpg','https://image.tmdb.org/t/p/original/woYGBHERSMhIHqmkkRCbCXp81l4.jpg','The chronicles of four years in the life of Julie, a young woman who navigates the troubled waters of her love life and struggles to find her career path, leading her to take a realistic look at who she really is.',NULL,NULL,5.5664,7.4,0,12.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(156,718032,'tt11271038',NULL,'Licorice Pizza','Licorice Pizza','movie',2021,'https://image.tmdb.org/t/p/w500/ivXtvzfliGvoJ1DhSHIGyYBToWe.jpg','https://image.tmdb.org/t/p/original/fkn5KBUUKxbG7MjOs9poAOAik40.jpg','The story of Gary Valentine and Alana Kane growing up, running around and going through the treacherous navigation of first love in the San Fernando Valley, 1973.',NULL,NULL,3.4477,6.953,0,1.4209999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(157,11976,'tt0089469',NULL,'Legend','Legend','movie',1985,'https://image.tmdb.org/t/p/w500/6n3PQSYpZRK5YPk2w8JEwED7AZk.jpg','https://image.tmdb.org/t/p/original/3g8rLMw0SbA0h2GHiOCBoqFTXVq.jpg','Set in a timeless mythical forest inhabited by fairies, goblins, unicorns and mortals, this fantastic story follows a mystical forest dweller, chosen by fate, to undertake a heroic quest. He must save the beautiful Princess  Lili and defeat the demonic Lord of Darkness, or the world will be plunged into a never-ending ice age.',NULL,NULL,4.5184,6.25,0,1.9573999999999998e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(158,13225,'tt0104254',NULL,'FernGully: The Last Rainforest','FernGully: The Last Rainforest','movie',1992,'https://image.tmdb.org/t/p/w500/xkJxdeaibcrcsi1XHvT0IuOjdzB.jpg','https://image.tmdb.org/t/p/original/2GBUz0Z4YyKi2ojHylPIT6yBBl1.jpg','When a sprite named Crysta shrinks a human boy, Zak, down to her size, he vows to help the magical fairy folk stop a greedy logging company from destroying their home: the pristine rainforest known as FernGully. Zak and his new friends fight to defend FernGully from lumberjacks — and the vengeful spirit they accidentally unleash after chopping down a magic tree.',NULL,NULL,2.6242,6.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(159,10150,'tt0084237',NULL,'The Last Unicorn','The Last Unicorn','movie',1982,'https://image.tmdb.org/t/p/w500/MRHFtXTjxC74MGCzHACcuqvHiw.jpg','https://image.tmdb.org/t/p/original/fwxOQkzYtRVKs3kzcyukdbsyIuh.jpg','A unicorn learns from a riddle-speaking butterfly that she is supposedly the last of her kind, all the others having been herded away by the monstrous Red Bull. The unicorn sets out to discover the truth behind the butterfly''s words. She is eventually joined on her quest by Schmendrick, a second-rate magician, and Molly Grue, a middle-aged woman who dreamed all her life of seeing a unicorn. Their journey leads them far from home, all the way to the castle of King Haggard.',NULL,NULL,2.8437,7.3,0,12.37,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(160,10601,'tt0316396',NULL,'Peter Pan','Peter Pan','movie',2003,'https://image.tmdb.org/t/p/w500/6QdU3TZZrIvXFzoHOwafZAynFjB.jpg','https://image.tmdb.org/t/p/original/zyWbOvKCdA9V9P5xuUG2eiPYsUo.jpg','In stifling Edwardian London, Wendy Darling mesmerizes her brothers every night with bedtime tales of swordplay, swashbuckling and the fearsome Captain Hook. But the children become the heroes of an even greater story, when Peter Pan flies into their nursery one night and leads them over moonlit rooftops through a galaxy of stars and to the lush jungles of Neverland.',NULL,NULL,5.5219,7.131,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(161,40074,'tt0075666',NULL,'Alucarda','Alucarda, la hija de las tinieblas','movie',1977,'https://image.tmdb.org/t/p/w500/auZZ7zqm7qbLWBTmq4S2fO6L64m.jpg','https://image.tmdb.org/t/p/original/xOuFz7t8zFEMLmzCHxnSLLkvNST.jpg','A young girl''s arrival at a convent after the death of her parents marks the beginning of a series of events that unleash an evil presence on the girl and her mysterious new friend, an enigmatic figure known as Alucarda. Demonic possession, Satan worship, and vampirism follows.',NULL,NULL,1.5103,6.422,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(162,576560,'tt5807330',NULL,'Tread','Tread','movie',2020,'https://image.tmdb.org/t/p/w500/sXh2U3Pj2iMjzzW993kUvHE10RK.jpg','https://image.tmdb.org/t/p/original/do2FxGgBYKO1hsF8sA1NmIBvs3m.jpg','Pushed to his breaking point, a master welder in a small town at the foot of the Rocky Mountains quietly fortifies a bulldozer with 30 tons of concrete and steel and seeks to destroy those he believes have wronged him.',NULL,NULL,0.5517,6.615,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(163,45649,'tt1612774',NULL,'Rubber','Rubber','movie',2010,'https://image.tmdb.org/t/p/w500/mWgCORI5IC5vOvB2cDVQe0YNtXZ.jpg','https://image.tmdb.org/t/p/original/cqfaq9uczoHBBug74eORBH4Jcpe.jpg','In the California desert, the adventures of a telepathic killer-tire, mysteriously attracted by a very pretty girl, as witnessed by incredulous onlookers.',NULL,NULL,4.2813,5.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(164,65294,'tt4834206',NULL,'A Series of Unfortunate Events','A Series of Unfortunate Events','tv',2017,'https://image.tmdb.org/t/p/w500/qg7WXAatXyQq6zO3SnWnRJEayeZ.jpg','https://image.tmdb.org/t/p/original/scQYe3wMt98baZAPhuBcewEqns7.jpg','The orphaned Baudelaire children face trials, tribulations and the evil Count Olaf, all in their quest to uncover the secret of their parents'' death.',NULL,NULL,11.5267,7.409,0,12.7675,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(165,70785,'tt5421602',NULL,'Anne with an E','Anne with an E','tv',2017,'https://image.tmdb.org/t/p/w500/6P6tXhjT5tK3qOXzxF9OMLlG7iz.jpg','https://image.tmdb.org/t/p/original/ywQtHG17LZhAFZyZtBflhtFMtJ7.jpg','A coming-of-age story about an outsider who, against all odds and numerous challenges, fights for love and acceptance and for her place in the world. The series centers on a young orphaned girl in the late 1890s, who, after an abusive childhood spent in orphanages and the homes of strangers, is mistakenly sent to live with an elderly woman and her aging brother. Over time, 13-year-old Anne will transform their lives and eventually the small town in which they live with her unique spirit, fierce intellect and brilliant imagination.',NULL,NULL,18.5878,8.652,0,11.775,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(166,11236,'tt0108071',NULL,'The Secret Garden','The Secret Garden','movie',1993,'https://image.tmdb.org/t/p/w500/zf6h5dJ7wVG7LqMO9dhHGHVejzj.jpg','https://image.tmdb.org/t/p/original/8s7FJ9dHXgeFZdvxfjPmrrJh6EC.jpg','A young British girl born and reared in India loses her neglectful parents in an earthquake. She is returned to England to live at her uncle''s castle. Her uncle is very distant due to the loss of his wife ten years before. Neglected once again, she begins exploring the estate and discovers a garden that has been locked and forgotten. Aided by one of the servants'' boys, she begins restoring the garden, and eventually discovers some other secrets of the manor.',NULL,NULL,5.5667,7.423,0,13.422,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(167,1111873,'tt27489557',NULL,'Abigail','Abigail','movie',2024,'https://image.tmdb.org/t/p/w500/5gKKSoD3iezjoL7YqZONjmyAiRA.jpg','https://image.tmdb.org/t/p/original/2TPoqmatGDfBOiRxqNoL11ncCJe.jpg','A group of criminals kidnap a teenage ballet dancer, the daughter of a notorious gang leader, in order to obtain a ransom of $50 million, but over time, they discover that she is not just an ordinary girl. After the kidnappers begin to diminish, one by one, they discover, to their increasing horror, that they are locked inside with no normal little girl.',NULL,NULL,5.6254,6.663,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(168,67058,'tt0093891',NULL,'Rumpelstiltskin','Rumpelstiltskin','movie',1987,'https://image.tmdb.org/t/p/w500/sTmY51bKxYdp4YyJYaZF3nzOQ5R.jpg','https://image.tmdb.org/t/p/original/esBWpY7eyM0smpqe2RoDTFWQrBQ.jpg','A musical version of the classic story about a miller''s daughter who recieves help from a mischievous dwarf, then ends up over her head. Now, she and a mute servant girl may be the only hope for her baby son, John.',NULL,NULL,1.8205,4.3,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(169,91239,'tt8740790',NULL,'Bridgerton','Bridgerton','tv',2020,'https://image.tmdb.org/t/p/w500/uXTg565ahu9RwonCX1V2Hex1NU6.jpg','https://image.tmdb.org/t/p/original/6umsRLI7t0ydFwCl0JNEIO0q2LH.jpg','Wealth, lust, and betrayal set in the backdrop of Regency era England, seen through the eyes of the powerful Bridgerton family.',NULL,NULL,51.2141,8.063,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(170,348,'tt0078748',NULL,'Alien','Alien','movie',1979,'https://image.tmdb.org/t/p/w500/vfrQk5IPloGg1v9Rzbh2Eg3VGyM.jpg','https://image.tmdb.org/t/p/original/AmR3JG1VQVxU8TfAvljUhfSFUOx.jpg','During its return to the earth, commercial spaceship Nostromo intercepts a distress signal from a distant planet. When a three-member team of the crew discovers a chamber containing thousands of eggs on the planet, a creature inside one of the eggs attacks an explorer. The entire crew is unaware of the impending nightmare set to descend upon them when the alien parasite planted inside its unfortunate host is birthed.',NULL,NULL,21.8022,8.2,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(171,1535290,'tt38624355',NULL,'Host','แม่ซื้อ','movie',2025,'https://image.tmdb.org/t/p/w500/3AalQRe1NQkHmvHXrDePnB8JBtt.jpg','https://image.tmdb.org/t/p/original/2LzXxNrirJmUymYA9JRkbDomPcI.jpg','Ing is sent to Pinijkhun Reform School, an all-girls facility on a remote island. The only rule here is that everyone must obey orders.',NULL,NULL,7.8238,6.2,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(172,315011,'tt4262980',NULL,'Shin Godzilla','シン・ゴジラ','movie',2016,'https://image.tmdb.org/t/p/w500/jPNShaWZMpVF0iQ7j1dvTuZLD20.jpg','https://image.tmdb.org/t/p/original/tb0uo01w2kDHiQwTszsLlSusAm4.jpg','When a massive, gilled monster emerges from the deep and tears through the city, the government scrambles to save its citizens.  A rag-tag team of volunteers cuts through a web of red tape to uncover the monster''s weakness and its mysterious ties to a foreign superpower.  But time is not on their side - the greatest catastrophe to ever befall the world is about to evolve right before their very eyes.',NULL,NULL,5.8047,7.238,0,1.2509999999999998e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(173,254375,'tt1626146',NULL,'Hector and the Search for Happiness','Hector and the Search for Happiness','movie',2014,'https://image.tmdb.org/t/p/w500/lymRg46xAt6s9ApWa9MBcgnzXAS.jpg','https://image.tmdb.org/t/p/original/vujKrqkydYxLuFvdGjA5bDicupV.jpg','Hector is a quirky psychiatrist who has become increasingly tired of his humdrum life. As he tells his girlfriend, Clara, he feels like a fraud: he hasn’t really tasted life, and yet he’s offering advice to patients who are just not getting any happier. So Hector decides to break out of his deluded and routine driven life. Armed with buckets of courage and child-like curiosity, he embarks on a global quest in hopes of uncovering the elusive secret formula for true happiness. And so begins a larger than life adventure with riotously funny results.',NULL,NULL,1.6609,6.687,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(174,78,'tt0083658',NULL,'Blade Runner','Blade Runner','movie',1982,'https://image.tmdb.org/t/p/w500/63N9uy8nd9j7Eog2axPQ8lbr3Wj.jpg','https://image.tmdb.org/t/p/original/hJ5R9d6QuH3tzr8L8neZZTuzNXm.jpg','In the smog-choked dystopian Los Angeles of 2019, blade runner Rick Deckard is called out of retirement to terminate a quartet of replicants who have escaped to Earth seeking their creator for a way to extend their short life spans.',NULL,NULL,14.5843,7.9,0,2.63729411764705901e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(175,149,'tt0094625',NULL,'Akira','AKIRA','movie',1988,'https://image.tmdb.org/t/p/w500/neZ0ykEsPqxamsX6o5QNUFILQrz.jpg','https://image.tmdb.org/t/p/original/fK40VGYIm7hmKrLJ26fgPQU0qRG.jpg','A secret military project endangers Neo-Tokyo when it turns a biker gang member into a rampaging psychic psychopath that only two teenagers and a group of psychics can stop.',NULL,NULL,11.8061,7.9,0,2.21423076923076926e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(176,861,'tt0100802',NULL,'Total Recall','Total Recall','movie',1990,'https://image.tmdb.org/t/p/w500/wVbeL6fkbTKSmNfalj4VoAUUqJv.jpg','https://image.tmdb.org/t/p/original/x2wOlXuK4NzPDQ0OBZiJjNNOp6Y.jpg','Construction worker Douglas Quaid''s obsession with the planet Mars leads him to visit Rekall, a virtual vacation company that manufactures memories. When something goes wrong during Quaid''s memory implant procedure, his life turns upside down, leading him to question what is reality and what isn''t.',NULL,NULL,7.9215,7.323,0,1.03466666666666675e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(177,68724,'tt1535108',NULL,'Elysium','Elysium','movie',2013,'https://image.tmdb.org/t/p/w500/aRjuJuPXHtVs6YegfeeQWXGRs1E.jpg','https://image.tmdb.org/t/p/original/oo9GyiNKvR4CU1etuYl081UJ1LE.jpg','In the year 2159, two classes of people exist: the very wealthy who live on a pristine man-made space station called Elysium, and the rest, who live on an overpopulated, ruined Earth. Secretary Rhodes, a hard line government official, will stop at nothing to enforce anti-immigration laws and preserve the luxurious lifestyle of the citizens of Elysium. That doesn’t stop the people of Earth from trying to get in, by any means they can. When unlucky Max is backed into a corner, he agrees to take on a daunting mission that, if successful, will not only save his life, but could bring equality to these polarized worlds.',NULL,NULL,6.5109,6.524,0,1.15166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(178,581389,'tt12838766',NULL,'Space Sweepers','승리호','movie',2021,'https://image.tmdb.org/t/p/w500/bmemsraCG1kIthY74NjDnnLRT2Q.jpg','https://image.tmdb.org/t/p/original/drulhSX7P5TQlEMQZ3JoXKSDEfz.jpg','When the crew of a space junk collector ship called The Victory discovers a humanoid robot named Dorothy that''s known to be a weapon of mass destruction, they get involved in a risky business deal which puts their lives at stake.',NULL,NULL,2.0503,7.038,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(179,10540,'tt0082869',NULL,'Outland','Outland','movie',1981,'https://image.tmdb.org/t/p/w500/qmjlDkV8CfCboa8WV06ytZaThqx.jpg','https://image.tmdb.org/t/p/original/6m1ol0YFN35kXQ2KNz5LDWwaD56.jpg','On the sunless moon Io, Marshall William T. O’Niel goes toe-to-toe with the corrupt manager of a mining colony and his gang of roughnecks while investigating a rash of worker suicides.',NULL,NULL,2.6944,6.424,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(180,2927,'tt0097910',NULL,'Moon 44','Moon 44','movie',1990,'https://image.tmdb.org/t/p/w500/ia7Ew8QXiN1Urh63xYFYZ7ZfF2t.jpg','https://image.tmdb.org/t/p/original/sWExgcLS5zqCsVeGpuhVqK8Q4YO.jpg','Year 2038: The mineral resources of the earth are drained, in space there are fights for the last deposits on other planets and satellites. This is the situation when one of the bigger mining corporations has lost all but one mineral moons and many of their fully automatic mining robots are disappearing on their flight home. Since nobody else wants the job, they send prisoners to defend the mining station. Among them undercover agent Stone, who shall clear the whereabouts of the expensive robots. In an atmosphere of corruption, fear and hatred he gets between the fronts of rivaling groups.',NULL,NULL,1.6196,5.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(181,30991,'tt0213338',NULL,'Cowboy Bebop','カウボーイビバップ','tv',1998,'https://image.tmdb.org/t/p/w500/xDiXDfZwC6XYC6fxHI1jl3A3Ill.jpg','https://image.tmdb.org/t/p/original/A4PHx94G7mvM3b8vsDJ5HEaQ6uv.jpg','In 2071, roughly fifty years after an accident with a hyperspace gateway made the Earth almost uninhabitable, humanity has colonized most of the rocky planets and moons of the Solar System. Amid a rising crime rate, the Inter Solar System Police (ISSP) set up a legalized contract system, in which registered bounty hunters, also referred to as "Cowboys", chase criminals and bring them in alive in return for a reward.',NULL,NULL,20.9076,8.497,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(182,68421,'tt2261227',NULL,'Altered Carbon','Altered Carbon','tv',2018,'https://image.tmdb.org/t/p/w500/AisK4uFsnwwmMkSynFpNl0VeGR.jpg','https://image.tmdb.org/t/p/original/A6I3M4MIA2Pi2gS6vGdg2eVlVXT.jpg','After 250 years on ice, a prisoner returns to life in a new body with one chance to win his freedom: by solving a mind-bending murder.',NULL,NULL,15.8252,7.637,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(183,83867,'tt9253284',NULL,'Andor','Andor','tv',2022,'https://image.tmdb.org/t/p/w500/khZqmwHQicTYoS7Flreb9EddFZC.jpg','https://image.tmdb.org/t/p/original/quCeAmVQHfsdcYkicbxZWVauCVb.jpg','In an era filled with danger, deception and intrigue, Cassian Andor will discover the difference he can make in the struggle against the tyrannical Galactic Empire. He embarks on a path that is destined to turn him into a rebel hero.',NULL,NULL,29.7164,8.295,0,9.18333333333333357e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(184,63639,'tt3230854',NULL,'The Expanse','The Expanse','tv',2015,'https://image.tmdb.org/t/p/w500/5vQlVWkIMPhZ88OWchJsgwGEK9.jpg','https://image.tmdb.org/t/p/original/uUwnClwdMA12bpHgeKgkQrbu5Oe.jpg','A thriller set two hundred years in the future following the case of a missing young woman who brings a hardened detective and a rogue ship''s captain together in a race across the solar system to expose the greatest conspiracy in human history.',NULL,NULL,61.4166,8.066,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(185,399579,'tt0437086',NULL,'Alita: Battle Angel','Alita: Battle Angel','movie',2019,'https://image.tmdb.org/t/p/w500/xRWht48C2V8XNfzvPehyClOvDni.jpg','https://image.tmdb.org/t/p/original/jXDselREPq8TOVGM4dzBBUM7xVk.jpg','When Alita awakens with no memory of who she is in a future world she does not recognize, she is taken in by Ido, a compassionate doctor who realizes that somewhere in this abandoned cyborg shell is the heart and soul of a young woman with an extraordinary past.',NULL,NULL,15.8826,7.3,0,1.23866666666666649e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(186,13600,'tt0970411',NULL,'City of Ember','City of Ember','movie',2008,'https://image.tmdb.org/t/p/w500/xHYxFNsl8KuT4tHai8d1Y5gJI0F.jpg','https://image.tmdb.org/t/p/original/n8KxhAnfoAFoOrYLQcHi7nhp1zB.jpg','For generations, the people of the City of Ember have flourished in an amazing world of glittering lights. But Ember''s once powerful generator is failing and the great lamps that illuminate the city are starting to flicker. Now, two teenagers, in a race against time, must search Ember for clues that will unlock the ancient mystery of the city''s existence, before the the lights go out forever.',NULL,NULL,4.435,6.366,0,1.13633333333333332e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(187,44826,'tt0970179',NULL,'Hugo','Hugo','movie',2011,'https://image.tmdb.org/t/p/w500/1dxRq3o3l3bVWNRvvSb7rRf68qp.jpg','https://image.tmdb.org/t/p/original/Aj81Gu3u1a64qXFOLDuF5gdxyy0.jpg','Orphaned and alone except for an uncle, Hugo Cabret lives in the walls of a train station in 1930s Paris. Hugo''s job is to oil and maintain the station''s clocks, but to him, his more important task is to protect a broken automaton and notebook left to him by his late father. Accompanied by the goddaughter of an embittered toy merchant, Hugo embarks on a quest to solve the mystery of the automaton and find a place he can call home.',NULL,NULL,5.2512,7.175,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(188,8698,'tt0311429',NULL,'The League of Extraordinary Gentlemen','The League of Extraordinary Gentlemen','movie',2003,'https://image.tmdb.org/t/p/w500/kdAuVFP63XXxnb983ry2pLCKd9S.jpg','https://image.tmdb.org/t/p/original/n3VpgjdOB1DkHSUe1DbFzV8ncpJ.jpg','To prevent a world war from breaking out, famous characters from Victorian literature band together to do battle against a cunning villain.',NULL,NULL,5.4689,6.015,0,1.13533333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(189,5137,'tt0346156',NULL,'Sky Captain and the World of Tomorrow','Sky Captain and the World of Tomorrow','movie',2004,'https://image.tmdb.org/t/p/w500/cO73CS7XKRPfGYh6G36StnhswQc.jpg','https://image.tmdb.org/t/p/original/mTWwWXuqF65CthgoA4j2Pd0bWwz.jpg','When gigantic robots attack New York City, "Sky Captain" uses his private air force to fight them off. His ex-girlfriend, reporter Polly Perkins, has been investigating the recent disappearance of prominent scientists. Suspecting a link between the global robot attacks and missing men, Sky Captain and Polly decide to work together. They fly to the Himalayas in pursuit of the mysterious Dr. Totenkopf, the mastermind behind the robots.',NULL,NULL,2.858,5.896,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(190,8953,'tt0348121',NULL,'Steamboy','スチームボーイ','movie',2004,'https://image.tmdb.org/t/p/w500/he3fyAy1OUruuwhiv2xvup8H3pc.jpg','https://image.tmdb.org/t/p/original/c31SAQjVMeVGv7mZsrw5BKGXj2P.jpg','In 1860s Britain, a boy inventor finds himself caught in the middle of a deadly conflict over a revolutionary advance in steam power.',NULL,NULL,2.3113,6.902,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(191,340357,'tt3422078',NULL,'April and the Extraordinary World','Avril et le monde truqué','movie',2015,'https://image.tmdb.org/t/p/w500/cenqAhHFJRGf08L8rgvHTlFrLuL.jpg','https://image.tmdb.org/t/p/original/bALW6bJuN1VW2xRsx49Hy7JIejG.jpg','It''s 1941, but France is trapped in the 19th Century, governed by steam and Napoleon V. Avril, a teenage girl, goes in search of her missing scientist parents.',NULL,NULL,1.5158,7.071,0,1.23433333333333319e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(192,2666,'tt0118929',NULL,'Dark City','Dark City','movie',1998,'https://image.tmdb.org/t/p/w500/tNPEGju4DpTdbhBphNmZoEi9Bd3.jpg','https://image.tmdb.org/t/p/original/sWi4SSeVPii4NU365Df9vzX1yOX.jpg','A man struggles with memories of his past, including a wife he cannot remember, in a nightmarish world with no sun and run by beings with telekinetic powers who seek the souls of humans.',NULL,NULL,7.6456,7.327,0,17.32375,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(193,1164,'tt0449467',NULL,'Babel','Babel','movie',2006,'https://image.tmdb.org/t/p/w500/bZByZbvU7u14WjoUJERqCRW9saN.jpg','https://image.tmdb.org/t/p/original/9YoLdWeBSxAdR6BqQ5uS88d3FWO.jpg','Tragedy strikes a married couple vacationing in the Moroccan desert, which jumpstarts an interlocking story involving four different families.',NULL,NULL,7.8572,7.172,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(194,334541,'tt4034228',NULL,'Manchester by the Sea','Manchester by the Sea','movie',2016,'https://image.tmdb.org/t/p/w500/o9VXYOuaJxCEKOxbA86xqtwmqYn.jpg','https://image.tmdb.org/t/p/original/fjk4eE8Ypke4YLv5A3ArDH4GzYH.jpg','After his older brother passes away, Lee Chandler is forced to return home to care for his 16-year-old nephew. There he is compelled to deal with a tragic past that separated him from his family and the community where he was born and raised.',NULL,NULL,7.5062,7.553,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(195,587,'tt0319061',NULL,'Big Fish','Big Fish','movie',2003,'https://image.tmdb.org/t/p/w500/tjK063yCgaBAluVU72rZ6PKPH2l.jpg','https://image.tmdb.org/t/p/original/bLqUd0tBvKezDr9MEla7k34i3rp.jpg','Throughout his life Edward Bloom has always been a man of big appetites, enormous passions and tall tales. In his later years, he remains a huge mystery to his son, William. Now, to get to know the real man, Will begins piecing together a true picture of his father from flashbacks of his amazing adventures.',NULL,NULL,7.3973,7.755,0,1.53549999999999986e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(196,334,'tt0175880',NULL,'Magnolia','Magnolia','movie',1999,'https://image.tmdb.org/t/p/w500/tpfC325Jk6S38VTe5dDWjWtoyxr.jpg','https://image.tmdb.org/t/p/original/mFfyE5DPFDqoes4HIcElHc2a15y.jpg','On one random day in the San Fernando Valley, a dying father, a young wife, a male caretaker, a famous lost son, a police officer in love, a boy genius, an ex-boy genius, a game show host and an estranged daughter will each become part of a dazzling multiplicity of plots, but one story.',NULL,NULL,5.6931,7.724,0,13.8875,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(197,1381,'tt0414993',NULL,'The Fountain','The Fountain','movie',2006,'https://image.tmdb.org/t/p/w500/4XTf8GuCVLWolubANaKkpk62YPq.jpg','https://image.tmdb.org/t/p/original/9RNJ0pKYA8EQiMa0lFZ68gzeElH.jpg','Spanning over one thousand years, and three parallel stories, The Fountain is a story of love, death, spirituality, and the fragility of our existence in this world.',NULL,NULL,3.7846,6.905,0,13.532,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(198,644,'tt0212720',NULL,'A.I. Artificial Intelligence','A.I. Artificial Intelligence','movie',2001,'https://image.tmdb.org/t/p/w500/8MZSGX5JORoO72EfuAEcejH5yHn.jpg','https://image.tmdb.org/t/p/original/n7p6UTAZtkeoHkwCO42BEQaMFJY.jpg','David, a robotic boy—the first of his kind programmed to love—is adopted as a test case by a Cybertronics employee and his wife. Though he gradually becomes their child, a series of unexpected circumstances make this life impossible for David.',NULL,NULL,7.3592,7.1,0,1.0004999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(199,313369,'tt3783958',NULL,'La La Land','La La Land','movie',2016,'https://image.tmdb.org/t/p/w500/uDO8zWDhfWwoFdKS4fzkUJt0Rf0.jpg','https://image.tmdb.org/t/p/original/nlPCdZlHtRNcF6C9hzUH4ebmV1w.jpg','Mia, an aspiring actress, serves lattes to movie stars in between auditions and Sebastian, a jazz musician, scrapes by playing cocktail party gigs in dingy bars, but as success mounts they are faced with decisions that begin to fray the fragile fabric of their love affair, and the dreams they worked so hard to maintain in each other threaten to rip them apart.',NULL,NULL,16.7201,7.898,0,1.54366666666666674e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(200,545611,'tt6710474',NULL,'Everything Everywhere All at Once','Everything Everywhere All at Once','movie',2022,'https://image.tmdb.org/t/p/w500/u68AjlvlutfEIcpmbYpKcdi09ut.jpg','https://image.tmdb.org/t/p/original/ss0Os3uWJfQAENILHZUdX8Tt1OC.jpg','An aging Chinese immigrant is swept up in an insane adventure, where she alone can save what''s important to her by connecting with the lives she could have led in other universes.',NULL,NULL,18.7985,7.716,0,1.46119999999999983e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(201,15804,'tt0101985',NULL,'A Brighter Summer Day','牯嶺街少年殺人事件','movie',1991,'https://image.tmdb.org/t/p/w500/3l8fOAwiN3N5n3hHnZ51eog7Zu2.jpg','https://image.tmdb.org/t/p/original/hypv7bDxzqdhJfEpjRKf1aQbdc.jpg','A boy experiences first love, friendships and injustices growing up in 1960s Taiwan.',NULL,NULL,4.5608,8.2,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(202,153,'tt0335266',NULL,'Lost in Translation','Lost in Translation','movie',2003,'https://image.tmdb.org/t/p/w500/3jCLmYDIIiSMPujbwygNpqdpM8N.jpg','https://image.tmdb.org/t/p/original/6ITVHoipvxAS8luzKtHTbPaHLtT.jpg','Two lost souls visiting Tokyo -- the young, neglected wife of a photographer and a washed-up movie star shooting a TV commercial -- find an odd solace and pensive freedom to be real in each other''s company, away from their lives in America.',NULL,NULL,9.9499,7.38,0,2.34207142857142827e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(203,76,'tt0112471',NULL,'Before Sunrise','Before Sunrise','movie',1995,'https://image.tmdb.org/t/p/w500/kf1Jb1c2JAOqjuzA3H4oDM263uB.jpg','https://image.tmdb.org/t/p/original/qA2TyqPldTtoTVY3LKrNIG5g6bH.jpg','An unexpected meeting on a train leads two travelers to spend an evening wandering through Vienna. As the night unfolds, they share stories and conversations about life and love, exploring new ideas while a quiet intimacy grows between them, knowing it may be their only night together.',NULL,NULL,14.6712,7.969,0,22.29,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(204,38,'tt0338013',NULL,'Eternal Sunshine of the Spotless Mind','Eternal Sunshine of the Spotless Mind','movie',2004,'https://image.tmdb.org/t/p/w500/5MwkWH9tYHv3mV9OdYTMR5qreIz.jpg','https://image.tmdb.org/t/p/original/W1ffLQGHoxfAOq0ZYdPtJlvAdb.jpg','Joel Barish, heartbroken that his girlfriend underwent a procedure to erase him from her memory, decides to do the same. However, as he watches his memories of her fade away, he realises that he still loves her, and may be too late to correct his mistake.',NULL,NULL,19.1552,8.09,0,1.86533333333333324e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(205,84892,'tt1659337',NULL,'The Perks of Being a Wallflower','The Perks of Being a Wallflower','movie',2012,'https://image.tmdb.org/t/p/w500/aKCvdFFF5n80P2VdS7d8YBwbCjh.jpg','https://image.tmdb.org/t/p/original/aM6E4DBP6588q3tEr9hz41ls80q.jpg','Pittsburgh, Pennsylvania, 1991. High school freshman Charlie is a wallflower, always watching life from the sidelines, until two senior students, Sam and her stepbrother Patrick, become his mentors, helping him discover the joys of friendship, music and love.',NULL,NULL,9.7575,7.806,0,1.94709090909090924e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(206,226857,'tt2318092',NULL,'Endless Love','Endless Love','movie',2014,'https://image.tmdb.org/t/p/w500/7WDqvNmy4p6IJx8JjvzOtaV2IRr.jpg','https://image.tmdb.org/t/p/original/g27PNNr3GNo72hf86KIHjzx66H4.jpg','A privileged girl and a charismatic boy''s instant desire sparks a love affair made only more reckless by parents trying to keep them apart.',NULL,NULL,3.7557,6.929,0,6.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(207,46705,'tt1120985',NULL,'Blue Valentine','Blue Valentine','movie',2010,'https://image.tmdb.org/t/p/w500/dc8BdKnDY5Iy28KzUGtHIXuqqFK.jpg','https://image.tmdb.org/t/p/original/fAqpfILTPsaKpAzoAvkXf5glgSo.jpg','Dean and Cindy live a quiet life in a modest neighborhood. They appear to have the world at their feet at the outset of the relationship. However, his lack of ambition and her retreat into self-absorption cause potentially irreversible cracks in their marriage.',NULL,NULL,4.4981,6.966,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(208,158907,'tt1999987',NULL,'Breathe In','Breathe In','movie',2013,'https://image.tmdb.org/t/p/w500/dqXrIoaPTYIB9GWdD0DF1LArl6d.jpg','https://image.tmdb.org/t/p/original/nypN2Pm1IPNMlXv3vQPOK6T7wy7.jpg','When a foreign exchange student arrives in a small upstate New York town, she challenges the dynamics of her host family''s relationships and alters their lives forever.',NULL,NULL,1.3898,5.895,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(209,1440,'tt0404203',NULL,'Little Children','Little Children','movie',2006,'https://image.tmdb.org/t/p/w500/l2wTSP0Ifo9vY03nJEfkFBbT2S9.jpg','https://image.tmdb.org/t/p/original/uDDgaNppSCJm6kWDLl7vMeu8xcl.jpg','The lives of two lovelorn spouses from separate marriages, a registered sex offender, and a disgraced ex-police officer intersect as they struggle to resist their vulnerabilities and temptations.',NULL,NULL,4.2304,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(210,12116,'tt0068205',NULL,'Love in the Afternoon','L''Amour l''après-midi','movie',1972,'https://image.tmdb.org/t/p/w500/5fItTSqhGG2T9WkUNu2nSruSKsP.jpg','https://image.tmdb.org/t/p/original/AiidLUGpb8lVvH3s4olLjAuwcCz.jpg','Frederic leads a bourgeois life; he is a partner in a small Paris office and is happily married to Helene, a teacher expecting her second child. In the afternoons, Frederic daydreams about other women, but has no intention of taking any action. One day, Chloe, who had been a mistress of an old friend, begins dropping by his office. They meet as friends, irregularly in the afternoons, till eventually Chloe decides to seduce Frederic, causing him a moral dilemma.',NULL,NULL,1.9191,7.292,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(211,2251,'tt0250797',NULL,'Unfaithful','Unfaithful','movie',2002,'https://image.tmdb.org/t/p/w500/bjiHEhuiwhIygzjczbTPAA07cGc.jpg','https://image.tmdb.org/t/p/original/egVj5Y9f79xPnyAQJmeDR0Uwow3.jpg','A New York suburban couple''s marriage goes dangerously awry when the wife indulges in an adulterous fling.',NULL,NULL,19.3969,6.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(212,2288,'tt0376541',NULL,'Closer','Closer','movie',2004,'https://image.tmdb.org/t/p/w500/fGGaokx4k00S0J603VG53Qlr9jz.jpg','https://image.tmdb.org/t/p/original/s7oDV92ltdecJ7BTfGSOgsDi900.jpg','The relationships of two couples become complicated and deceitful when the man from one couple meets the woman of the other.',NULL,NULL,4.1025,6.835,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(213,11220,'tt0112913',NULL,'Fallen Angels','墮落天使','movie',1995,'https://image.tmdb.org/t/p/w500/yyM9BPdwttK5LKZSLvHae7QPKo1.jpg','https://image.tmdb.org/t/p/original/lInQVVbPjKFGX7GDcxNMXALy2Y4.jpg','An indifferent hitman, his infatuated business partner and an ex-convict search for love and meaning as their lives cross paths in Hong Kong.',NULL,NULL,6.0669,7.694,0,2.00218181818181832e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(214,440298,'tt6543652',NULL,'Cold War','Zimna wojna','movie',2018,'https://image.tmdb.org/t/p/w500/6rbS8oPIgUMhQgIX8oGVTtlNgLR.jpg','https://image.tmdb.org/t/p/original/ed0qbGNeA8XMU85T9QS30UWJQNw.jpg','A man and a woman meet in the ruins of post-war Poland. With vastly different backgrounds and temperaments, they are fatally mismatched and yet drawn to each other.',NULL,NULL,1.8994,7.43,0,1.26833333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(215,251232,'tt2459156',NULL,'Copenhagen','Copenhagen','movie',2014,'https://image.tmdb.org/t/p/w500/1MSFfjvgf9auNANWcaGTvzf1TcW.jpg','https://image.tmdb.org/t/p/original/j5jPqb3h9wMGaXZtWwGfIMH5ykg.jpg','After weeks of traveling through Europe, the immature William finds himself in Copenhagen, the place of his father’s birth. He befriends the youthful Effy, who works in William’s hotel as part of an internship program, and they set off to find William’s last living relative. Effy’s mix of youthful exuberance and wisdom challenges William unlike any  woman ever has. As the attraction builds, he must come to grips with destabilizing elements of his family’s sordid past.',NULL,NULL,0.6343,6.6,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(216,370755,'tt5247022',NULL,'Paterson','Paterson','movie',2016,'https://image.tmdb.org/t/p/w500/AuJ1ZlfqwuAr9H5Qr1U9KILylse.jpg','https://image.tmdb.org/t/p/original/5Bk7kYSKAuNrxI5BXpDqlsln2P0.jpg','A week in the life of Paterson, a poet bus driver, and his wife Laura, a very creative artist, who live in Paterson, New Jersey, hometown of many famous poets and artists.',NULL,NULL,2.8951,7.115,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(217,60994,'tt0160338',NULL,'Guinevere','Guinevere','movie',1999,'https://image.tmdb.org/t/p/w500/1isgjzl3mwVoxlRd7sqJ7COzwZw.jpg','https://image.tmdb.org/t/p/original/4PqIL1UJfvowW67hANZqgdA9uC3.jpg','A young girl from an affluent family rebels and becomes involved with a much older photographer.',NULL,NULL,1.3845,5.731,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(218,194,'tt0211915',NULL,'Amélie','Le Fabuleux Destin d''Amélie Poulain','movie',2001,'https://image.tmdb.org/t/p/w500/nSxDa3M9aMvGVLoItzWTepQ5h5d.jpg','https://image.tmdb.org/t/p/original/6n53UI4mX9QMfe2S0Pgt8mGebY1.jpg','At a tiny Parisian café, the adorable yet painfully shy Amélie accidentally discovers a gift for helping others. Soon Amelie is spending her days as a matchmaker, guardian angel, and all-around do-gooder. But when she bumps into a handsome stranger, will she find the courage to become the star of her very own love story?',NULL,NULL,13.5619,7.9,0,1.61166666666666671e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(219,2788,'tt0110950',NULL,'Reality Bites','Reality Bites','movie',1994,'https://image.tmdb.org/t/p/w500/qGDhodtpkpxkrFqokenGNJlzt6w.jpg','https://image.tmdb.org/t/p/original/wPW1cMe2XyeLnm2DNDudoDXVSwt.jpg','A small circle of friends suffering from post-collegiate blues must confront the hard truth about life, love and the pursuit of gainful employment. As they struggle to map out survival guides for the future, the Gen-X quartet soon begins to realize that reality isn''t all it''s cracked up to be.',NULL,NULL,3.391,6.541,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(220,401,'tt0333766',NULL,'Garden State','Garden State','movie',2004,'https://image.tmdb.org/t/p/w500/h3iqYiGS6F3y7GxaS4AT8nFxZ2i.jpg','https://image.tmdb.org/t/p/original/2mu6XkJE0B6nK5jeOvXOyWPVmhw.jpg','Andrew returns to his hometown for his mother’s funeral, a journey that reconnects him with old friends. The trip coincides with his decision to stop taking his powerful antidepressants. A chance meeting with Sam—a girl also struggling with various maladies—opens up the possibility of rekindling emotional connections, confronting his psychologist father, and perhaps beginning a new life.',NULL,NULL,2.7774,7.073,0,13.5125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(221,52512,'tt0412596',NULL,'Café Lumière','珈琲時光','movie',2004,'https://image.tmdb.org/t/p/w500/mvXQlk3mZnfJkzZg13Mt7qPstMF.jpg','https://image.tmdb.org/t/p/original/9CvEknBybOKB69rnoPVo16DSqtf.jpg','In a distinctly contemporary Tokyo that looks backwards to the city’s disappearing past, Yoko is a writer investigating the life of a modernist composer of the 1930s. She is pregnant by a man she does not want to marry and has found a kindred spirit in a used bookstore owner who aids her research.',NULL,NULL,1.0954,6.733,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(222,121986,'tt2347569',NULL,'Frances Ha','Frances Ha','movie',2013,'https://image.tmdb.org/t/p/w500/jrq1NoKvsxWCcffVOjegiYwloFN.jpg','https://image.tmdb.org/t/p/original/oUVd42KgJWW6YnZLfzI7SDTdcPL.jpg','An aspiring dancer moves to New York City and becomes caught up in a whirlwind of flighty fair-weather friends, diminishing fortunes and career setbacks.',NULL,NULL,2.3338,7.331,0,13.5225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(223,4935,'tt0347149',NULL,'Howl''s Moving Castle','ハウルの動く城','movie',2004,'https://image.tmdb.org/t/p/w500/13kOl2v0nD2OLbVSHnHk8GUFEhO.jpg','https://image.tmdb.org/t/p/original/nv5wwZou159v5OC61i4ElR7OqyY.jpg','Sophie, a young milliner, is turned into an elderly woman by a witch who enters her shop and curses her. She encounters a wizard named Howl and gets caught up in his resistance to fighting for the king.',NULL,NULL,21.158,8.4,0,1.46783333333333345e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(224,5590,'tt0066207',NULL,'Donkey Skin','Peau d''âne','movie',1970,'https://image.tmdb.org/t/p/w500/kSODEFNpTBCOJNHhsbwrwvH0Uvd.jpg','https://image.tmdb.org/t/p/original/3yZva3ONs7C1kKJ6IVvrZQJCUIj.jpg','A fairy godmother helps a princess disguise herself so she won''t have to marry her father.',NULL,NULL,2.4257,7.2,0,15.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(225,37533,'tt0097995',NULL,'White Wedding','Noce blanche','movie',1989,'https://image.tmdb.org/t/p/w500/AoR69wN0JDzq7DWW9a5rhiMSNZq.jpg','https://image.tmdb.org/t/p/original/h8jhI6FiMcCCKpSxl1ehCkhtPaX.jpg','A philosophy professor has an illicit affair with one of his students, a bright yet troubled girl who lives alone.',NULL,NULL,3.027,6.548,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(226,9044,'tt0375154',NULL,'Tristan & Isolde','Tristan & Isolde','movie',2006,'https://image.tmdb.org/t/p/w500/r7TpY5hJ4jQGH7c8yzJgBnTwPH6.jpg','https://image.tmdb.org/t/p/original/cmmOLD0UOrw8rJ2WBb3rvEUhkE1.jpg','An affair between the second in line to Britain''s throne and the princess of the feuding Irish spells doom for the young lovers.',NULL,NULL,2.8451,6.7,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(227,6003,'tt0063518',NULL,'Romeo and Juliet','Romeo and Juliet','movie',1968,'https://image.tmdb.org/t/p/w500/vaBQKLbSWkXGTOlsz9ARdJP4lvg.jpg','https://image.tmdb.org/t/p/original/zQyNGzYD144sbFKrfBP8mFwqDxn.jpg','Romeo Montague and Juliet Capulet fall in love against the wishes of their feuding families. Driven by their passion, the young lovers defy their destiny and elope, only to suffer the ultimate tragedy.',NULL,NULL,5.2651,7.4,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(228,321612,'tt2771200',NULL,'Beauty and the Beast','Beauty and the Beast','movie',2017,'https://image.tmdb.org/t/p/w500/hKegSKIDep2ewJWPUQD7u0KqFIp.jpg','https://image.tmdb.org/t/p/original/uU1Mt4JWhDvl4vKb3AfxNsorkoM.jpg','A live-action adaptation of Disney''s version of the classic tale of a cursed prince and a beautiful young woman who helps him break the spell.',NULL,NULL,17.7191,6.967,0,12.0125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(229,314405,'tt3278330',NULL,'Tale of Tales','Il racconto dei racconti','movie',2015,'https://image.tmdb.org/t/p/w500/ryZsoaYmcEJsye6P5uo5thEjpqB.jpg','https://image.tmdb.org/t/p/original/ntz8lrQbN5f92HoRSVS0CxPVzvB.jpg','The Queen of Selvascura risks everything to be a mother; the King of Roccaforte falls in love with the voice of a mysterious girl; the King of Altomonte becomes obsessed with a flea and neglects his daughter.',NULL,NULL,2.5428,6.429,0,1.42139999999999986e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(230,2270,'tt0486655',NULL,'Stardust','Stardust','movie',2007,'https://image.tmdb.org/t/p/w500/7zbFmxy3DqKYL2M8Hop6uylp2Uy.jpg','https://image.tmdb.org/t/p/original/8i68M9wkPc5hilvGCoatQmGHV9h.jpg','In a countryside town bordering on a magical land, a young man makes a promise to his beloved that he''ll retrieve a fallen star by venturing into the magical realm. His journey takes him into a world beyond his wildest dreams and reveals his true identity.',NULL,NULL,6.2731,7.293,0,1.25133333333333318e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(231,5048,'tt0102722',NULL,'Prospero''s Books','Prospero''s Books','movie',1991,'https://image.tmdb.org/t/p/w500/lF9uNTBDtpQOGHrKGWc6rqDDwbM.jpg','https://image.tmdb.org/t/p/original/cRC3YsfboAmLnVwlYNaHIQquJUJ.jpg','An exiled magician finds an opportunity for revenge against his enemies muted when his daughter and the son of his chief enemy fall in love in this uniquely structured retelling of the ''The Tempest''.',NULL,NULL,1.1613,6.808,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(232,744276,'tt13070038',NULL,'After Ever Happy','After Ever Happy','movie',2022,'https://image.tmdb.org/t/p/w500/moogpu8rNkEjTgFyLXwhPghft5w.jpg','https://image.tmdb.org/t/p/original/rwgmDkIEv8VjAsWx25ottJrFvpO.jpg','As a shocking truth about a couple''s families emerges, the two lovers discover they are not so different from each other. Tessa is no longer the sweet, simple, good girl she was when she met Hardin — any more than he is the cruel, moody boy she fell so hard for.',NULL,NULL,5.7511,6.779,0,1.53516666666666665e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(233,14442,'tt0327679',NULL,'Ella Enchanted','Ella Enchanted','movie',2004,'https://image.tmdb.org/t/p/w500/7AyNzwSEpJEG1gBdgwRfXi1cjs8.jpg','https://image.tmdb.org/t/p/original/r4Q7GKzTiAzr1MGU1b13s9L12YZ.jpg','Ella lives in a magical world in which each child, at the moment of their birth, is given a virtuous "gift" from a fairy godmother. Ella''s so-called gift, however, is obedience. This birthright proves itself to be quite the curse once Ella finds herself in the hands of several unscrupulous characters whom she quite literally cannot disobey. Determined to gain control of her life and decisions, Ella sets off on a journey to find her fairy godmother who she hopes will lift the curse. The path, however, isn''t easy -- Ella must outwit a slew of unpleasant obstacles including ogres, giants, wicked stepsisters, elves and Prince Charmont''s evil uncle, who wants to take over the crown and rule the kingdom.',NULL,NULL,5.2392,6.5,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(234,62764,'tt1667353',NULL,'Mirror Mirror','Mirror Mirror','movie',2012,'https://image.tmdb.org/t/p/w500/pys6zIJN8Sxlk2Ss2GZuYuXPbtw.jpg','https://image.tmdb.org/t/p/original/iFSO0glqR8wydqaRl9KxQI63xEd.jpg','After she spends all her money, an evil enchantress queen schemes to marry a handsome, wealthy prince. There''s just one problem - he''s in love with a beautiful princess, Snow White. Now, joined by seven rebellious dwarves, Snow White launches an epic battle of good vs. evil...',NULL,NULL,3.626,5.92,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(235,16176,'tt0075232',NULL,'The Slipper and the Rose','The Slipper and the Rose','movie',1976,'https://image.tmdb.org/t/p/w500/o7tQ79sqZwt5dQskCW5ymjtd13r.jpg','https://image.tmdb.org/t/p/original/zgqC7Gig2Q4fSyE5agLA5uKcXBT.jpg','Prince Edward wants to marry for love, but the King and court of the Kingdom of Euphrania are anxious for the Prince to wed no matter what. When the Prince meets Cinderella at a ball, he''s sure she''s the one, and when she loses her slipper upon exiting the dance, the Prince is determined to find and marry her.',NULL,NULL,1.3472,6.9,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(236,8703,'tt0070832',NULL,'Three Wishes for Cinderella','Tři oříšky pro Popelku','movie',1973,'https://image.tmdb.org/t/p/w500/2WlY1JSRoDJkbPg53kxyKlHJu0b.jpg','https://image.tmdb.org/t/p/original/r3tn3xGjHdLnjSdQOC3WEkTloPC.jpg','Popelka, a resourceful and independent young girl, is a servant in her stepmother''s house and confides in her closest friend the owl. When she comes across three magical acorns, she''s granted a single wish for each one of them.',NULL,NULL,1.502,7.46,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(237,32593,'tt0255605',NULL,'Snow White','Snow White','movie',2001,'https://image.tmdb.org/t/p/w500/xIjplbyfFDbHsN7ZK40klO5nnUw.jpg','https://image.tmdb.org/t/p/original/7eoIQCeAMCw1pevX4Dhqs0MJzYN.jpg','Snow White''s mother dies during childbirth, leaving baby Snow and father John for dead on an icy field, who then receives a visit from one of Satan''s representatives, granting him three wishes.',NULL,NULL,1.6034,5.896,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(238,10452,'tt0110963',NULL,'Queen Margot','La Reine Margot','movie',1994,'https://image.tmdb.org/t/p/w500/8uGkhBLiJMIkwohGPo3iB9AuwDg.jpg','https://image.tmdb.org/t/p/original/h0lGYUOxXKCM1W7cgvHN1UW1TC4.jpg','Paris, Kingdom of France, August 18, 1572. To avoid the outbreak of a religious war, the Catholic princess Marguerite de Valois, sister of the feeble King Charles IX, marries the Huguenot King Henry III of Navarre.',NULL,NULL,2.2522,7.194,0,13.5225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(239,12184,'tt0467200',NULL,'The Other Boleyn Girl','The Other Boleyn Girl','movie',2008,'https://image.tmdb.org/t/p/w500/q2lgC8mmAltWTkbqPM8n5EYF4XL.jpg','https://image.tmdb.org/t/p/original/jovVe4UGpmQEAE6ZEmV5xa6Kk1f.jpg','A sumptuous and sensual tale of intrigue, romance and betrayal set against the backdrop of a defining moment in European history: two beautiful sisters, Anne and Mary Boleyn, driven by their family''s blind ambition, compete for the love of the handsome and passionate King Henry VIII.',NULL,NULL,4.8324,6.704,0,1.23533333333333317e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(240,4518,'tt0127536',NULL,'Elizabeth','Elizabeth','movie',1998,'https://image.tmdb.org/t/p/w500/qEk48VLOdibXFVIEzE9ETZUBcCs.jpg','https://image.tmdb.org/t/p/original/LTjGvAf92YLudl5zqJP9tHLuSo.jpg','The story of the ascension to the throne and the early reign of Queen Elizabeth the First, the endless attempts by her council to marry her off, the Catholic hatred of her and her romance with Lord Robert Dudley.',NULL,NULL,3.4144,7.162,0,1.23433333333333319e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(241,10831,'tt0083851',NULL,'The Draughtsman''s Contract','The Draughtsman''s Contract','movie',1982,'https://image.tmdb.org/t/p/w500/ljeTWR2kowGXijMc8LMuy72ULM3.jpg','https://image.tmdb.org/t/p/original/4cExyNONv6JNlOuBH1qcUvIyd8O.jpg','R. Neville, a brash young draftsman, is hired to make a dozen landscape illustrations at the estate of Mr Herbert and his wife Virginia. Aside from monetary compensation, the arrangement includes a sexual liaison offered to Neville by Virginia while her estranged husband is away. But when the murdered body of Mr Herbert is discovered at the estate, mysterious clues found in Neville''s drawings point to the identity of the killer.',NULL,NULL,1.212,7.062,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(242,335984,'tt1856101',NULL,'Blade Runner 2049','Blade Runner 2049','movie',2017,'https://image.tmdb.org/t/p/w500/gajva2L0rPYkEWjzgFlBXCAVBE5.jpg','https://image.tmdb.org/t/p/original/gNdLJU9TxrpGx4dkZidjys3fyy0.jpg','Thirty years after the events of the first film, a new blade runner, LAPD Officer K, unearths a long-buried secret that has the potential to plunge what''s left of society into chaos. K''s discovery leads him on a quest to find Rick Deckard, a former LAPD blade runner who has been missing for 30 years.',NULL,NULL,28.273,7.596,0,19.026,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(243,458737,'tt6053438',NULL,'First Reformed','First Reformed','movie',2018,'https://image.tmdb.org/t/p/w500/8HKA3Hwf8jQWy8TCYWr7C8Wft23.jpg','https://image.tmdb.org/t/p/original/mLwIDLa1FMkbKLteZRTatyvWLHX.jpg','A pastor of a small church in upstate New York starts to spiral out of control after a soul-shaking encounter with an unstable environmental activist and his pregnant wife.',NULL,NULL,2.2061,6.966,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(244,8051,'tt0272338',NULL,'Punch-Drunk Love','Punch-Drunk Love','movie',2002,'https://image.tmdb.org/t/p/w500/htYp4yqFu4rzBEIa6j9jP8miDm3.jpg','https://image.tmdb.org/t/p/original/q8GwhIAttJwqmjDtbLW8JvEMMdw.jpg','A socially awkward and volatile small business owner meets the love of his life after being threatened by a gang of scammers.',NULL,NULL,3.8009,7.108,0,1.28466666666666675e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(245,4960,'tt0383028',NULL,'Synecdoche, New York','Synecdoche, New York','movie',2008,'https://image.tmdb.org/t/p/w500/5UwdhrjXhUgsiDhe1dpS9z4yj7q.jpg','https://image.tmdb.org/t/p/original/insPcjOIWFf6Uc9DR0ORgXATqSM.jpg','A theater director struggles with his work, and the women in his life, as he attempts to create a life-size replica of New York inside a warehouse as part of his new play.',NULL,NULL,4.6458,7.532,0,14.116,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(246,37247,'tt0061722',NULL,'The Graduate','The Graduate','movie',1967,'https://image.tmdb.org/t/p/w500/8XaDpF0COV1MLsDirJMnxmYc1Wp.jpg','https://image.tmdb.org/t/p/original/lIY8ZTp6OJTAMfiorDGsPsJ5LT.jpg','A disillusioned college graduate finds himself torn between his older lover and her daughter.',NULL,NULL,6.6464,7.6,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(247,937278,'tt7405458',NULL,'A Man Called Otto','A Man Called Otto','movie',2022,'https://image.tmdb.org/t/p/w500/130H1gap9lFfiTF9iDrqNIkFvC9.jpg','https://image.tmdb.org/t/p/original/9ZznETDyfPWVugRiv0jfGrkRftw.jpg','When a lively young family moves in next door, grumpy widower Otto Anderson meets his match in a quick-witted, pregnant woman named Marisol, leading to an unlikely friendship that turns his world upside down.',NULL,NULL,8.4169,7.747,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(248,692,'tt0069089',NULL,'Pink Flamingos','Pink Flamingos','movie',1972,'https://image.tmdb.org/t/p/w500/10N8SvTQwUqyWgocPam1P18Jgr.jpg','https://image.tmdb.org/t/p/original/uh1zf6Q0UcHaqWQXZXu1qOOSCRg.jpg','Notorious Baltimore criminal and underground figure Divine goes up against Connie & Raymond Marble, a sleazy married couple who make a passionate attempt to humiliate her and seize her tabloid-given title as "The Filthiest Person Alive".',NULL,NULL,4.1337,6.138,0,13.6525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(249,791177,'tt10168670',NULL,'Bones and All','Bones and All','movie',2022,'https://image.tmdb.org/t/p/w500/dBQuk2LkHjrDsSjueirPQg96GCc.jpg','https://image.tmdb.org/t/p/original/8sPxa4sdRvjgRG3GgkO8RQxUR9P.jpg','Abandoned by her father, a young woman embarks on a thousand-mile odyssey through the backroads of America where she meets a disenfranchised drifter. But despite their best efforts, all roads lead back to their terrifying pasts and to a final stand that will determine whether their love can survive their otherness.',NULL,NULL,5.6528,7.001,0,14.316,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(250,13310,'tt1139797',NULL,'Let the Right One In','Låt den rätte komma in','movie',2008,'https://image.tmdb.org/t/p/w500/7IG4WjaAOVDlLvLUkh513HSwhW8.jpg','https://image.tmdb.org/t/p/original/gH3lvKcY6EDMXrUtqZEiHPVV91n.jpg','When Oskar, a sensitive, bullied 12-year-old boy, meets his new neighbor, the mysterious and moody Eli, they strike up a friendship. Initially reserved with each other, Oskar and Eli slowly form a close bond, but it soon becomes apparent that she is no ordinary young girl.',NULL,NULL,4.9438,7.544,0,1.65714285714285693e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(251,4513,'tt0389722',NULL,'30 Days of Night','30 Days of Night','movie',2007,'https://image.tmdb.org/t/p/w500/7LwSrvFA0gz1KAlcrGcinoQPene.jpg','https://image.tmdb.org/t/p/original/w8VDpCcKezdBbXJEWMHwttI35mU.jpg','This is the story of an isolated Alaskan town that is plunged into darkness for a month each year when the sun sinks below the horizon. As the last rays of light fade, the town is attacked by a bloodthirsty gang of vampires bent on an uninterrupted orgy of destruction. Only the small town''s husband-and-wife Sheriff team stand between the survivors and certain destruction.',NULL,NULL,5.3883,6.437,0,12.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(252,1226578,'tt23468450',NULL,'Longlegs','Longlegs','movie',2024,'https://image.tmdb.org/t/p/w500/1EwNyiiNFd863H4e8nWEzutnZD7.jpg','https://image.tmdb.org/t/p/original/6ToGkmqn0KG0UGGGUAC1Ww0e5CM.jpg','FBI Agent Lee Harker is a gifted new recruit assigned to the unsolved case of an elusive serial killer. As the case takes complex turns, unearthing evidence of the occult, Harker discovers a personal connection to the merciless killer and must race against time to stop him before he claims the lives of another innocent family.',NULL,NULL,6.8232,6.525,0,17.3875,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(253,500840,'tt7939766',NULL,'I''m Thinking of Ending Things','I''m Thinking of Ending Things','movie',2020,'https://image.tmdb.org/t/p/w500/5ynWWapdl45hJXUh0KIevxSG9JQ.jpg','https://image.tmdb.org/t/p/original/bMKGU5HFHPvg67ybbNXnBvpFEp0.jpg','Nothing is as it seems when a woman experiencing misgivings about her new boyfriend joins him on a road trip to meet his parents at their remote farm.',NULL,NULL,2.6706,6.541,0,14.526,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(254,110402,'tt2328813',NULL,'Hard to Be a God','Трудно быть богом','movie',2014,'https://image.tmdb.org/t/p/w500/ivdmKR9K56nxfhWwA5k2UQnyeFK.jpg','https://image.tmdb.org/t/p/original/iNhaEPAgAinPuA4fkimowUrWniy.jpg','A group of scientists is sent to the planet Arkanar to help the local civilization, which is in the Medieval phase of its own history, to find the right path to progress. Their task is a difficult one: they cannot interfere violently and in no case can they kill. The scientist Rumata tries to save the local intellectuals from their punishment and cannot avoid taking a position.',NULL,NULL,0.7672,6.557,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(255,1314481,'tt33612209',NULL,'The Devil Wears Prada 2','The Devil Wears Prada 2','movie',2026,'https://image.tmdb.org/t/p/w500/fCAURTUx3YfsJ8k9I0UamjSILiR.jpg','https://image.tmdb.org/t/p/original/Af907x5h9W1wVis8XrSd7ynTWuy.jpg','Andy Sachs returns to Runway as Miranda Priestly navigates a new media landscape and Runway''s position within. The duo reconnect with former assistant Emily Charlton, now the head of a luxury brand that possesses funding which could ensure Runway''s survival.',NULL,NULL,299.8408,7.091,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(256,31767,'tt0066993',NULL,'The Devils','The Devils','movie',1971,'https://image.tmdb.org/t/p/w500/y1k7eiOFc6fzm8XeTa1kNGx6JIs.jpg','https://image.tmdb.org/t/p/original/8ApwSMdd9QehKjvW3fOmKVrnZXv.jpg','A charismatic 17th-century French priest becomes the target of a sexually obsessed nun’s witchcraft accusations, which corrupt church and state officials are all too happy to exploit.​​​​​​​​​​​​​​​​',NULL,NULL,3.3601,7.442,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(257,766,'tt0106308',NULL,'Army of Darkness','Army of Darkness','movie',1992,'https://image.tmdb.org/t/p/w500/xsgTuAtR2zSH8Umg3jWZcZjlDpe.jpg','https://image.tmdb.org/t/p/original/5RPXs9g0sZ9Woo4pNLxdXdge7tc.jpg','Ash, a handsome, shotgun-toting, chainsaw-armed department store clerk, is time warped backwards into England''s Dark Ages, where he romances a beauty and faces legions of the undead.',NULL,NULL,15.8385,7.3,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(258,1265,'tt0398808',NULL,'Bridge to Terabithia','Bridge to Terabithia','movie',2007,'https://image.tmdb.org/t/p/w500/3xFxGodKPMFLheS8rujFSmLfcq4.jpg','https://image.tmdb.org/t/p/original/tH2SoOS2HqOJCOImbeGkmKSdCMz.jpg','Jesse Aarons trained all summer to become the fastest runner in school. So he''s very upset when newcomer Leslie Burke outruns him and everyone else. Despite this and other differences including that she''s rich, he''s poor, she''s a city girl, and he''s a country boy the two become fast friends. Together they create Terabithia, a land of monsters, trolls, ogres, and giants where they rule as king and queen.',NULL,NULL,12.3894,7.345,0,1.66671428571428563e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(259,12519,'tt0111201',NULL,'Sirens','Sirens','movie',1994,'https://image.tmdb.org/t/p/w500/bOUDHgOlxANs1KsYZEsLSjZBTkd.jpg','https://image.tmdb.org/t/p/original/A0YCPfLrxv2xX0Hno9eFBEemYPL.jpg','In 1930s Australia, Anglican clergyman Anthony Campion and his prim wife, Estella, are asked to visit noted painter Norman Lindsay, whose planned contribution to an international art exhibit is considered blasphemous. While Campion and Lindsay debate, Estella finds herself drawn to the three beautiful models sitting for the painter''s current work, freethinking Sheela, sensual Pru and virginal Giddy.',NULL,NULL,3.9987,5.614,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(260,13768,'tt0283084',NULL,'Tuck Everlasting','Tuck Everlasting','movie',2002,'https://image.tmdb.org/t/p/w500/9BXAC4uTHuD37hpiGOmhetqNgnO.jpg','https://image.tmdb.org/t/p/original/2mNUbRzy8QqFMxP6B9dxqlt998n.jpg','Teenager Winnie Foster is growing up in a small rural town in 1914 with her loving but overprotective parents, but Winnie longs for a life of greater freedom and adventure.',NULL,NULL,2.1912,6.696,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(261,6435,'tt0120791',NULL,'Practical Magic','Practical Magic','movie',1998,'https://image.tmdb.org/t/p/w500/AwmToSgf2IL3aHv0QRVsR5KvChv.jpg','https://image.tmdb.org/t/p/original/mGznDQ8opBuRd004ChVWhDqjAyW.jpg','Sally and Gillian Owens, born into a magical family, have mostly avoided witchcraft themselves. But when Gillian''s vicious boyfriend, Jimmy Angelov, dies unexpectedly, the Owens sisters give themselves a crash course in hard magic. With policeman Gary Hallet growing suspicious, the girls struggle to resurrect Angelov -- and unwittingly inject his corpse with an evil spirit that threatens to end their family line.',NULL,NULL,6.8727,6.784,0,1.63142857142857167e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(262,2759,'tt0109045',NULL,'The Adventures of Priscilla, Queen of the Desert','The Adventures of Priscilla, Queen of the Desert','movie',1994,'https://image.tmdb.org/t/p/w500/kJ7syYXEJgSBmBfSnF3Can9cK1J.jpg','https://image.tmdb.org/t/p/original/q1PuySDtRiKSgxAZjpIbFvvLOus.jpg','Two drag performers and a transgender woman travel across the desert to perform their unique style of cabaret.',NULL,NULL,3.252,7.3,0,11.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(263,108322,'tt0075345',NULL,'Tracks','Tracks','movie',1976,'https://image.tmdb.org/t/p/w500/1hzdbJS5WNMzCY7sV6qSmOaOT10.jpg','https://image.tmdb.org/t/p/original/zQ1LInLSdYFnpQJYqNSU02MVgBw.jpg','A soldier returns from Vietnam on special assignment, accompanying the body of his friend by train to California for burial. During the trip, he falls in love with a gentle college student. But their relationship is shattered by his flashbacks to combat.',NULL,NULL,1.1562,5.6,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(264,9067,'tt0114614',NULL,'Tank Girl','Tank Girl','movie',1995,'https://image.tmdb.org/t/p/w500/dpX63vJd6k5fMTudLaEOw9ffX8h.jpg','https://image.tmdb.org/t/p/original/rmG0rboJMA9sE6vttQCM2eXXJ2Q.jpg','After a comet disrupts the rain cycle of Earth, the planet has become a desolate, barren desert by the year 2033. With resources scarce, Kesslee, head of the powerful and evil Water & Power Corporation, the de facto government, has taken control of the water supply. Unwilling to cower under Kesslee''s tyrannical rule, a pair of outlaws known as Tank Girl and Jet Girl rise up, joining the mysterious rebel Rippers to destroy the corrupt system.',NULL,NULL,2.4936,5.5,0,1.25133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(265,431,'tt0123755',NULL,'Cube','Cube','movie',1998,'https://image.tmdb.org/t/p/w500/x4BTjxdrOKC27FcSkBh8KPEgnum.jpg','https://image.tmdb.org/t/p/original/3TimUBrXMVblpnTsyg4HssGVbBv.jpg','A group of strangers find themselves trapped in a maze-like prison. It soon becomes clear that each of them possesses the peculiar skills necessary to escape, if they don''t wind up dead first.',NULL,NULL,4.7484,6.825,0,1.29433333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(266,NULL,NULL,18689,'Yume Nikki','Yume Nikki','game',2004,'https://images.igdb.com/igdb/image/upload/t_cover_big/co81f2.jpg',NULL,'Yume Nikki is a 32-Bit freeware game created by Kikiyama, a Japanese solo game designer. The game was made using RPGMaker 2003. The game is regarded as one of the most original applications of RPGMaker 2003, and the start of a possible new genre of games.

"Yume Nikki" means "Dream Diary" in Japanese, and the game follows a young girl named Madotsuki as she dreams. The goal is to seek out and acquire all 24 ''Effects''.

The game otherwise has no plot, and nearly the entire game is left up to speculation.','https://www.igdb.com/games/yume-nikki','["Web browser", "PC (Microsoft Windows)"]',NULL,NULL,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(267,NULL,NULL,9235,'LSD: Dream Emulator','LSD: Dream Emulator','game',1998,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2hhs.jpg',NULL,'In LSD the player navigates through a psychedelic dream world. The idea is simply to walk around and explore things in a dream environment. There are many strange environments in this world, and one way to travel through them is by foot. However, if the player bumps into walls or other objects in the game, they will be transported to another environment instantaneously through a system called "linking". Bumping into people, animals, or special objects usually results in a stranger dream.

Each dream can last up to 10 minutes, after which the player will ''wake up'', when the screen fades away and the player is sent back to the game''s initial menu. However, if the player falls off a cliff or into a hole in the dream, then the player will wake up immediately. There is a graph that appears at the end of each dream that keeps track of the player''s state of mind; the states are Upper, Downer, Static and Dynamic, as referring to the environments and the general feel of the dream the player just went through. Past states may have effects on later dreams.','https://www.igdb.com/games/lsd-dream-emulator','["PlayStation 3", "PlayStation", "PlayStation Portable"]',NULL,NULL,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(268,458305,'tt8368406',NULL,'Vivarium','Vivarium','movie',2019,'https://image.tmdb.org/t/p/w500/myf3qzpeN0JbuFRPwSpJcz7rmAT.jpg','https://image.tmdb.org/t/p/original/zLa8fA7boGtNoNH7n6iYi9UqoaH.jpg','A young woman and her fiancé are in search of the perfect starter home. After following a mysterious real estate agent to a new housing development, the couple finds themselves trapped in a maze of identical houses and forced to raise an otherworldly child.',NULL,NULL,6.4492,6.066,0,1.54316666666666684e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(269,6795,'tt0406375',NULL,'Zathura: A Space Adventure','Zathura: A Space Adventure','movie',2005,'https://image.tmdb.org/t/p/w500/gDb5BW2NLqZ9cvg9nyzkZVvmgze.jpg','https://image.tmdb.org/t/p/original/s9Bn7Mx4U9cWOR1WdFZjU1DTAkh.jpg','After their father is called into work, two young boys, Walter and Danny, are left in the care of their teenage sister, Lisa, and told they must stay inside. Walter and Danny, who anticipate a boring day, are shocked when they begin playing Zathura, a space-themed board game, which they realize has mystical powers when their house is shot into space. With the help of an astronaut, the boys attempt to return home.',NULL,NULL,5.1341,6.449,0,10.78,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(270,424781,'tt5688932',NULL,'Sorry to Bother You','Sorry to Bother You','movie',2018,'https://image.tmdb.org/t/p/w500/peTl1V04E9ppvhgvNmSX0r2ALqO.jpg','https://image.tmdb.org/t/p/original/x832ykgj3fx0Q0MFKEno77XM47e.jpg','In an alternate present-day version of Oakland, black telemarketer Cassius Green discovers a magical key to professional success – which propels him into a macabre universe.',NULL,NULL,3.3436,6.778,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(271,2617,'tt0095253',NULL,'The Great Outdoors','The Great Outdoors','movie',1988,'https://image.tmdb.org/t/p/w500/zxIoPZiqKOxrWvieumpxA6bOgkt.jpg','https://image.tmdb.org/t/p/original/lLvTqn3P1MFiCSAWEjSoR3MxRsX.jpg','It''s vacation time for outdoorsy Chicago man Chet Ripley, along with his wife, Connie, and their two kids, Buck and Ben. But a serene weekend of fishing at a Wisconsin lakeside cabin gets crashed by Connie''s obnoxious brother-in-law, Roman Craig, his wife, Kate, and the couple''s two daughters. As the excursion wears on, the Ripleys find themselves at odds with the stuffy Craig family.',NULL,NULL,2.8207,6.447,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(272,695458,NULL,NULL,'Jonas Mekas, Friday 13th October','Friday The 13 Okt, Jonas Mekas','movie',1996,'https://image.tmdb.org/t/p/w500/z0QDtsO4BRfWL3XY5tGaH3xrzB7.jpg','https://image.tmdb.org/t/p/original/1jXR3HBPCosslsrrFoU0mjjJYu.jpg','Jonas, Birgit and Anja are leaving for the Brooklyn Bridge. By taxi, buying beer, drinking in the street, joking, running, dancing on the bridge. It was a very funny afternoon.',NULL,NULL,0.3932,0.0,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(273,296099,'tt1524930',NULL,'Vacation','Vacation','movie',2015,'https://image.tmdb.org/t/p/w500/fYDALvoCt3DBlSWN6pSAnGQ9ld7.jpg','https://image.tmdb.org/t/p/original/6y5ALiAai1JbLRb7ZlydNwEPu5a.jpg','Hoping to bring his family closer together and to recreate his childhood vacation for his own kids, a grown up Rusty Griswold takes his wife and their two sons on a cross-country road trip to the coolest theme park in America, Walley World. Needless to say, things don''t go quite as planned.',NULL,NULL,5.2077,6.304,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(274,869291,'tt12349832',NULL,'Cuckoo','Cuckoo','movie',2024,'https://image.tmdb.org/t/p/w500/4bGP5cnSZbfBJfIidZNSEIKnav7.jpg','https://image.tmdb.org/t/p/original/1eoCL8fPUZKlho03XVeNzZ3nlds.jpg','After reluctantly moving to the German Alps with her father and his new family, Gretchen discovers that their new town hides sinister secrets, as she''s plagued by strange noises and frightening visions of a woman pursuing her.',NULL,NULL,2.7462,5.726,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(275,83666,'tt1748122',NULL,'Moonrise Kingdom','Moonrise Kingdom','movie',2012,'https://image.tmdb.org/t/p/w500/y4SXcbNl6CEF2t36icuzuBioj7K.jpg','https://image.tmdb.org/t/p/original/bsYv9IFIGfpAV0oUbe7YTiyxhox.jpg','Set on an island off the coast of New England in the summer of 1965, Moonrise Kingdom tells the story of two twelve-year-olds who fall in love, make a secret pact, and run away together into the wilderness. As various authorities try to hunt them down, a violent storm is brewing off-shore – and the peaceful island community is turned upside down in more ways than anyone can handle.',NULL,NULL,4.7162,7.678,0,16.73,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(276,965150,'tt19770238',NULL,'Aftersun','Aftersun','movie',2022,'https://image.tmdb.org/t/p/w500/evKz85EKouVbIr51zy5fOtpNRPg.jpg','https://image.tmdb.org/t/p/original/4jdduww9j5RyzO4ITRcuBFhqNN1.jpg','Sophie reflects on the shared joy and private melancholy of a holiday she took with her father twenty years earlier. Memories fill the gaps between camcorder footages as she tries to reconcile the father she knew with the troubled man she didn''t.',NULL,NULL,6.6729,7.649,0,1.48120000000000011e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(277,760104,'tt13560574',NULL,'X','X','movie',2022,'https://image.tmdb.org/t/p/w500/lopZSVtXzhFY603E9OqF7O1YKsh.jpg','https://image.tmdb.org/t/p/original/70Rm9ItxKuEKN8iu6rNjfwAYUCJ.jpg','In 1979, a group of young filmmakers set out to make an adult film in rural Texas, but when their reclusive, elderly hosts catch them in the act, the cast find themselves fighting for their lives.',NULL,NULL,11.1389,6.714,0,13.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(278,9769,'tt0119558',NULL,'Lolita','Lolita','movie',1997,'https://image.tmdb.org/t/p/w500/9INcC14WZjCMKGE360VXmklCLdZ.jpg','https://image.tmdb.org/t/p/original/b9diKSmofRcgjbUxDrSPms82yAN.jpg','Humbert Humbert is a middle-aged British novelist who is both appalled by and attracted to the vulgarity of American culture. When he comes to stay at the boarding house run by Charlotte Haze, he soon becomes obsessed with Lolita, the woman''s teenaged daughter.',NULL,NULL,11.6345,7.1,0,1.17233333333333344e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(279,56743,'tt1575539',NULL,'Elena Undone','Elena Undone','movie',2010,'https://image.tmdb.org/t/p/w500/m4SDHYqLbYHnq5Lb6XPZPHgBbID.jpg','https://image.tmdb.org/t/p/original/fQExn029sEcpXvpKJQIQdEwKv5d.jpg','The wife of a pastor who preaches against homosexuality embarks on an affair with a female writer.',NULL,NULL,1.7523,6.882,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(280,726209,'tt12747748',NULL,'Leave the World Behind','Leave the World Behind','movie',2023,'https://image.tmdb.org/t/p/w500/29rhl1xopxA7JlGVVsf1UHfYPvN.jpg','https://image.tmdb.org/t/p/original/5cRw2QHQz5bp7W2KLdSpZoFoTTw.jpg','A family''s getaway to a luxurious rental home takes an ominous turn when a cyberattack knocks out their devices—and two strangers appear at their door.',NULL,NULL,5.3797,6.379,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(281,394117,'tt5649144',NULL,'The Florida Project','The Florida Project','movie',2017,'https://image.tmdb.org/t/p/w500/5QnDxdJg1fi6uMSkSi4x8tHsltm.jpg','https://image.tmdb.org/t/p/original/GOwNU7Z9G3ORjNxdZnURfuIGS6.jpg','The story of a precocious six year-old and her ragtag group of friends whose summer break is filled with childhood wonder, possibility and a sense of adventure while the adults around them struggle with hard times.',NULL,NULL,4.8331,7.4,0,1.79477777777777802e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(282,12232,'tt0033152',NULL,'The Thief of Bagdad','The Thief of Bagdad','movie',1940,'https://image.tmdb.org/t/p/w500/8Fs29JYTOkDluTXgbvLRIaps6PO.jpg','https://image.tmdb.org/t/p/original/kIGfEkETCQUU94ougWCYwem4CV2.jpg','When Prince Ahmad is blinded and cast out of Bagdad by the nefarious Jaffar, he joins forces with the scrappy thief Abu to win back his royal place, as well as the heart of a beautiful princess.',NULL,NULL,2.6093,7.134,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(283,1495,'tt0320661',NULL,'Kingdom of Heaven','Kingdom of Heaven','movie',2005,'https://image.tmdb.org/t/p/w500/rNaBe4TwbMef71sgscqabpGKsxh.jpg','https://image.tmdb.org/t/p/original/8itHQecANtOevcCdr3AhVxFCYkw.jpg','After his wife dies, a blacksmith named Balian is thrust into royalty, political intrigue and bloody holy wars during the Crusades.',NULL,NULL,14.5388,7.1,0,1.45599999999999987e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(284,8392,'tt0096283',NULL,'My Neighbor Totoro','となりのトトロ','movie',1988,'https://image.tmdb.org/t/p/w500/rtGDOeG9LzoerkDGZF9dnVeLppL.jpg','https://image.tmdb.org/t/p/original/zkThiZAaAie8Lw7RAc5yPTOewBV.jpg','Two sisters move to the country with their father in order to be closer to their hospitalized mother, and discover the surrounding trees are inhabited by Totoros, magical spirits of the forest. When the youngest runs away from home, the older sister seeks help from the spirits to find her.',NULL,NULL,15.8843,8.1,0,1.63357142857142889e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(285,947891,'tt18559464',NULL,'My Old Ass','My Old Ass','movie',2024,'https://image.tmdb.org/t/p/w500/yUs4Sw9AyTg2sA1qWBkNpD2mGSj.jpg','https://image.tmdb.org/t/p/original/iPHsjvbFyGbeCEDC7u8Ib8U1zS6.jpg','An 18th birthday mushroom trip brings free-spirited Elliott face-to-face with her wisecracking 39-year-old self. But when Elliott’s "old ass" starts handing out warnings about what her younger self should and shouldn''t do, Elliott realizes she has to rethink everything about family, love, and what''s becoming a transformative summer.',NULL,NULL,3.0962,6.8,0,1.26866666666666656e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(286,11816,'tt0082846',NULL,'On Golden Pond','On Golden Pond','movie',1981,'https://image.tmdb.org/t/p/w500/ic4f03J6pnf9cpQmVDABFhUpbCU.jpg','https://image.tmdb.org/t/p/original/ydGY4z0hN8XebemBOJgnTD4ceiJ.jpg','For Norman and Ethel Thayer, this summer on golden pond is filled with conflict and resolution. When their daughter Chelsea arrives, the family is forced to renew the bonds of love and overcome the generational friction that has existed for years.',NULL,NULL,2.0078,7.267,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(287,1633,'tt0101921',NULL,'Fried Green Tomatoes','Fried Green Tomatoes','movie',1991,'https://image.tmdb.org/t/p/w500/g71l1vbJwyAAYk8zKCkIQQ58qcb.jpg','https://image.tmdb.org/t/p/original/ApnB7gY4MrWoPqIw17lEMp1mXJD.jpg','Amidst her own personality crisis, a southern housewife meets an outgoing old woman who tells her the story of Idgie Threadgoode and Ruth Jamison, two young women who experienced hardships and love in 1920s Whistle Stop, Alabama.',NULL,NULL,4.816,7.664,0,1.26766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(288,682507,'tt9411972',NULL,'Where the Crawdads Sing','Where the Crawdads Sing','movie',2022,'https://image.tmdb.org/t/p/w500/n1el846gLDXfhOvrRCsyvaAOQWv.jpg','https://image.tmdb.org/t/p/original/fsHxHpREPdE299Bl7RvKb1HKk9U.jpg','Abandoned by her family, Kya raises herself all alone in the marshes outside of her small town. When her former boyfriend is found dead, Kya is instantly branded by the local townspeople and law enforcement as the prime suspect for his murder.',NULL,NULL,6.1695,7.524,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(289,863873,'tt15552142',NULL,'Caddo Lake','Caddo Lake','movie',2024,'https://image.tmdb.org/t/p/w500/r1h1YltM7bwzlWE330izIgQSwkj.jpg','https://image.tmdb.org/t/p/original/jcpUCn3oFKitAnbwosoPqaMFccj.jpg','When an 8-year-old girl mysteriously vanishes on Caddo Lake, a series of past deaths and disappearances begin to link together, forever altering a broken family’s history.',NULL,NULL,3.5347,7.235,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(290,300668,'tt2798920',NULL,'Annihilation','Annihilation','movie',2018,'https://image.tmdb.org/t/p/w500/4YRplSk6BhH6PRuE9gfyw9byUJ6.jpg','https://image.tmdb.org/t/p/original/9trZvBr44UGedUOiGo3jgSUw13e.jpg','A biologist signs up for a dangerous, secret expedition into a mysterious zone where the laws of nature don''t apply.',NULL,NULL,7.0832,6.444,0,13.965,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(291,858017,'tt15574270',NULL,'I Saw the TV Glow','I Saw the TV Glow','movie',2024,'https://image.tmdb.org/t/p/w500/hS4GYkYpN1rfl4GIxyc02sCyfAj.jpg','https://image.tmdb.org/t/p/original/jKulL2hdp5S7dVbpoItAtdCyzXI.jpg','In late-90s suburbia, a lonely teenager meets a girl at school who introduces him to a mysterious late-night T.V. show — a vision of a supernatural world pulsing beneath their own. As time goes on, however, questions begin to arise about why the show sometimes seems more real than their own lives. In the pale glow of the television, their view of reality begins to crack.',NULL,NULL,6.5975,6.128,0,21.315,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(292,14,'tt0169547',NULL,'American Beauty','American Beauty','movie',1999,'https://image.tmdb.org/t/p/w500/wby9315QzVKdW9BonAefg8jGTTb.jpg','https://image.tmdb.org/t/p/original/2ndw55F40IkALzWyjCCza3M6nqM.jpg','Lester Burnham, a depressed suburban father in a mid-life crisis, decides to turn his hectic life around after developing an infatuation with his daughter''s attractive friend.',NULL,NULL,9.756,7.999,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(293,7345,'tt0469494',NULL,'There Will Be Blood','There Will Be Blood','movie',2007,'https://image.tmdb.org/t/p/w500/fa0RDkAlCec0STeMNAhPaF89q6U.jpg','https://image.tmdb.org/t/p/original/9UAKA6ceZi6TgQwTAAMt7DWwYPI.jpg','Ruthless silver miner, turned oil prospector, Daniel Plainview, moves to oil-rich California. Using his son to project a trustworthy, family-man image, Plainview cons local landowners into selling him their valuable properties for a pittance. However, local preacher Eli Sunday suspects Plainview''s motives and intentions, starting a slow-burning feud that threatens both their lives.',NULL,NULL,10.7024,8.07,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(294,19908,'tt1156398',NULL,'Zombieland','Zombieland','movie',2009,'https://image.tmdb.org/t/p/w500/dUkAmAyPVqubSBNRjRqCgHggZcK.jpg','https://image.tmdb.org/t/p/original/oihWVx3imvRKujnGmSDYhfG1gI5.jpg','Columbus has made a habit of running from what scares him. Tallahassee doesn''t have fears. If he did, he''d kick their ever-living ass. In a world overrun by zombies, these two are perfectly evolved survivors. But now, they''re about to stare down the most terrifying prospect of all: each other.',NULL,NULL,7.7881,7.26,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(295,747,'tt0365748',NULL,'Shaun of the Dead','Shaun of the Dead','movie',2004,'https://image.tmdb.org/t/p/w500/dgXPhzNJH8HFTBjXPB177yNx6RI.jpg','https://image.tmdb.org/t/p/original/wb34q3VgzHgL8frVMywrN3wXmqx.jpg','Shaun lives a supremely uneventful life, which revolves around his girlfriend, his mother, and, above all, his local pub. This gentle routine is threatened when the dead return to life and make strenuous attempts to snack on ordinary Londoners.',NULL,NULL,9.0087,7.544,0,11.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(296,1542,'tt0151804',NULL,'Office Space','Office Space','movie',1999,'https://image.tmdb.org/t/p/w500/iEmTwOkUaLziMQCUZii5wPQBIAO.jpg','https://image.tmdb.org/t/p/original/g7o5O6xRWkMiwHXiYMPC690YEL4.jpg','A depressed white-collar worker tries hypnotherapy, only to find himself in a perpetual state of devil-may-care bliss that prompts him to start living by his own rules, and hatch a hapless attempt to embezzle money from his soul-killing employers.',NULL,NULL,4.6978,7.379,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(297,639,'tt0098635',NULL,'When Harry Met Sally...','When Harry Met Sally...','movie',1989,'https://image.tmdb.org/t/p/w500/rFOiFUhTMtDetqCGClC9PIgnC1P.jpg','https://image.tmdb.org/t/p/original/i8aIbji5vcPoHwcLBZYQSniGkAI.jpg','Sex always gets in the way of friendships between men and women. At least, that''s what Harry Burns believes. So when Harry meets Sally Albright and a deep friendship blossoms between them, Harry''s determined not to let his attraction to Sally destroy it. But when a night of weakness ends in a morning of panic, can the pair avoid succumbing to Harry''s fears by remaining friends and admitting they just might be the perfect match for each other?',NULL,NULL,6.2344,7.405,0,11.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(298,703,'tt0075686',NULL,'Annie Hall','Annie Hall','movie',1977,'https://image.tmdb.org/t/p/w500/dEtjPywhDbAXYjoFfhBC4U9unU7.jpg','https://image.tmdb.org/t/p/original/8n9dYsTbXTykzm2Nuy7R2ftapXQ.jpg','New York comedian Alvy Singer falls in love with the ditsy Annie Hall.',NULL,NULL,3.8195,7.7,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(299,1262,'tt0420223',NULL,'Stranger Than Fiction','Stranger Than Fiction','movie',2006,'https://image.tmdb.org/t/p/w500/nCzcepubwShvZ4vbCsygQNgF2Z1.jpg','https://image.tmdb.org/t/p/original/d9eONXYtCmQnPWw61w9pNMGlSzK.jpg','Harold Crick is a lonely IRS agent whose mundane existence is transformed when he hears a mysterious voice narrating his life.',NULL,NULL,3.7804,7.291,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(300,10201,'tt1068680',NULL,'Yes Man','Yes Man','movie',2008,'https://image.tmdb.org/t/p/w500/8Vk2nQF1kY34x53YnWd5zDaTht.jpg','https://image.tmdb.org/t/p/original/l9kUuYVqiZV1r6d4nKUKcQvtLR3.jpg','Carl Allen, a guy whose life is going nowhere, signs up for a self-help program based on one simple covenant: say yes to everything…and anything.',NULL,NULL,8.7822,6.691,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(301,9576,'tt0084805',NULL,'Tootsie','Tootsie','movie',1982,'https://image.tmdb.org/t/p/w500/ngyCzZwb9y5sMUCig5JQT4Y33Q.jpg','https://image.tmdb.org/t/p/original/dGRGes6Yw0vK1IymLatHBXGvvpS.jpg','When struggling, out of work actor Michael Dorsey secretly adopts a female alter ego—Dorothy Michaels—in order to land a part in a daytime drama, he unwittingly becomes a feminist icon and ends up in a romantic pickle.',NULL,NULL,3.3657,7.207,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(302,3414,'tt0085088',NULL,'Scarecrow and Mrs. King','Scarecrow and Mrs. King','tv',1983,'https://image.tmdb.org/t/p/w500/36oUFRNJQORpL9fmnrSXdFqEGty.jpg','https://image.tmdb.org/t/p/original/A3AEKSTwNGsnYOHnBmI8ZAe3TWR.jpg','Scarecrow and Mrs. King is an American television series that aired from October 3, 1983, to May 28, 1987 on CBS. The show stars Kate Jackson and Bruce Boxleitner as divorced housewife Amanda King and top-level "Agency" operative Lee Stetson who begin a strange association, and eventual romance, after encountering one another in a train station.',NULL,NULL,11.9068,6.591,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(303,3525,'tt0096463',NULL,'Working Girl','Working Girl','movie',1988,'https://image.tmdb.org/t/p/w500/q2jfFzZvAzjTaArQR0tjilIZ5aJ.jpg','https://image.tmdb.org/t/p/original/lRWIiRSOMH7qQT6UGcmx8Uykix3.jpg','When a secretary''s idea is stolen by her boss, she takes a risky chance to reclaim it by impersonating him and running the project from his position.',NULL,NULL,3.9598,6.605,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(304,27205,'tt1375666',NULL,'Inception','Inception','movie',2010,'https://image.tmdb.org/t/p/w500/xlaY2zyzMfkhk0HSC5VUwzoZPU1.jpg','https://image.tmdb.org/t/p/original/8ZTVqvKDQ8emSGUEMjsS4yHAwrp.jpg','Cobb, a skilled thief who commits corporate espionage by infiltrating the subconscious of his targets is offered a chance to regain his old life as payment for a task considered to be impossible: "inception", the implantation of another person''s idea into a target''s subconscious.',NULL,NULL,54.3632,8.372,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(305,1903,'tt0259711',NULL,'Vanilla Sky','Vanilla Sky','movie',2001,'https://image.tmdb.org/t/p/w500/cAh2pCiNPftsY3aSqJuIOde7uWr.jpg','https://image.tmdb.org/t/p/original/wwLufumafJojc59hgIamHyJSTO9.jpg','David Aames has it all: wealth, good looks and gorgeous women on his arm. But just as he begins falling for the warmhearted Sofia, his face is horribly disfigured in a car accident. That''s just the beginning of his troubles as the lines between illusion and reality, between life and death, are blurred.',NULL,NULL,6.4189,6.827,0,1.56883333333333325e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(306,795,'tt0120632',NULL,'City of Angels','City of Angels','movie',1998,'https://image.tmdb.org/t/p/w500/iuzxpUjHsbQJXV3kB9ZAdCimM60.jpg','https://image.tmdb.org/t/p/original/pYl4YpepgRbr504D7ep58C5gMyF.jpg','When a guardian angel – who invisibly watches over the citizens of Los Angeles – becomes captivated by a strong-willed heart surgeon, he ponders trading in his pure, otherworldly existence for a mortal life with his beloved. The couple embarks on a tender but forbidden romance spanning heaven and Earth.',NULL,NULL,5.809,6.814,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(307,10021,'tt0093936',NULL,'The Secret of My Success','The Secret of My Success','movie',1987,'https://image.tmdb.org/t/p/w500/7UizUgCGt2Vx48m3v2bOUEt51b2.jpg','https://image.tmdb.org/t/p/original/tqm00kwclq6nibl7u9De8u3cq0X.jpg','Brantley Foster, a well-educated kid from Kansas, has always dreamed of making it big in New York City, but once there, he learns that jobs - and girls - are hard to get. When he visits his uncle, Howard Prescott, who runs a multi-million-dollar company, he is given a job in the mail room.',NULL,NULL,3.2495,6.486,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(308,10603,'tt0119190',NULL,'George of the Jungle','George of the Jungle','movie',1997,'https://image.tmdb.org/t/p/w500/lWp8hUqE4oLPxsYgilXoYoVThfU.jpg','https://image.tmdb.org/t/p/original/zqkfvhbBf3IftOr1g7qjtwpFy6d.jpg','Deep in the African jungle, a baby named George, the sole survivor of a plane crash, is raised by gorillas. George grows up to be a buff and lovable klutz who has a rainforest full of animal friends: Tookie, his big-beaked toucan messenger; Ape, a witty talking gorilla; and Shep, a peanut-loving pooch of an elephant. But when poachers mess with George''s pals, the King of Swing swings into action.',NULL,NULL,5.5693,5.668,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(309,51876,'tt1219289',NULL,'Limitless','Limitless','movie',2011,'https://image.tmdb.org/t/p/w500/kCokPP4WCQRrrAuZ7FcpIyHr8b2.jpg','https://image.tmdb.org/t/p/original/vQGo5VjJcHxpzIa8lMBFzpAth1w.jpg','The life of an unsuccessful writer is transformed by a top-secret ''smart drug'' that allows him to use 100% of his brain and become a perfect version of himself. His enhanced abilities soon attract shadowy forces that threaten his new life.',NULL,NULL,7.7098,7.201,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(310,9880,'tt0247638',NULL,'The Princess Diaries','The Princess Diaries','movie',2001,'https://image.tmdb.org/t/p/w500/7axhsbEzFan6HQQ1aMOy7w3CFRx.jpg','https://image.tmdb.org/t/p/original/d44RH1S9h1iQfhwsX9IX4zxhzjQ.jpg','A socially awkward but very bright 15-year-old girl being raised by a single mom discovers that she is the princess of a small European country because of the recent death of her long-absent father, who, unknown to her, was the crown prince of Genovia. She must make a choice between continuing the life of a San Francisco teen or stepping up to the throne.',NULL,NULL,9.6173,6.961,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(311,2322,'tt0105435',NULL,'Sneakers','Sneakers','movie',1992,'https://image.tmdb.org/t/p/w500/l2pIGwCvpZEpBuMb55YBl6A04Jv.jpg','https://image.tmdb.org/t/p/original/smK3ud9IKSLVuRXdKauJ9p0DwNB.jpg','When shadowy U.S. intelligence agents blackmail a reformed computer hacker and his eccentric team of security experts into stealing a code-breaking ''black box'' from a Soviet-funded genius, they uncover a bigger conspiracy. Now, he and his ''sneakers'' must save themselves and the world economy by retrieving the box from their blackmailers.',NULL,NULL,5.7579,6.906,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(312,6479,'tt0480249',NULL,'I Am Legend','I Am Legend','movie',2007,'https://image.tmdb.org/t/p/w500/iPDkaSdKk2jRLTM65UOEoKtsIZ8.jpg','https://image.tmdb.org/t/p/original/ePgD1cwmklyrFBjl6z96IuixuSY.jpg','Robert Neville is a scientist who was unable to stop the spread of the terrible virus that was incurable and man-made. Immune, Neville is now the last human survivor in what is left of New York City and perhaps the world. For three years, Neville has faithfully sent out daily radio messages, desperate to find any other survivors who might be out there. But he is not alone.',NULL,NULL,13.6314,7.218,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(313,2028,'tt0098258',NULL,'Say Anything...','Say Anything...','movie',1989,'https://image.tmdb.org/t/p/w500/nkucKciFGSRalw6dJtsglWqOXMC.jpg','https://image.tmdb.org/t/p/original/bAdIO0Jt886Ad1eY9bDXXeCpXsV.jpg','Average student and eternal optimist Lloyd Dobler seeks to capture the heart of Diane Court, a beautiful but unattainable valedictorian classmate. He surprises just about everyone - including himself - when she returns the sentiment. However, Diane''s divorced, over-protective father soon begins to disapprove of the match, and Lloyd realises that it''s going to take more than just the power of love to conquer all.',NULL,NULL,3.6268,7.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(314,157386,'tt1714206',NULL,'The Spectacular Now','The Spectacular Now','movie',2013,'https://image.tmdb.org/t/p/w500/obDS8pTWVWZiNAaTyfIFWYZbRsZ.jpg','https://image.tmdb.org/t/p/original/xy5YazEiPb3Nij6TUEP9Dq3LDhp.jpg','Sutter, a popular party animal, unexpectedly meets the introverted Aimee after waking up on a stranger''s lawn. As Sutter deals with the problems in his life and Aimee plans for her future beyond school, an unexpected romance blossoms between them.',NULL,NULL,6.2897,6.681,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(315,399055,'tt5580390',NULL,'The Shape of Water','The Shape of Water','movie',2017,'https://image.tmdb.org/t/p/w500/9zfwPffUXpBrEP26yp0q1ckXDcj.jpg','https://image.tmdb.org/t/p/original/abirSHwWgKajV3hXhaIR5lcCIXe.jpg','An other-worldly story, set against the backdrop of Cold War era America circa 1962, where a mute janitor working at a lab falls in love with an amphibious man being held captive there and devises a plan to help him escape.',NULL,NULL,8.8239,7.236,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(316,22500,'tt0095525',NULL,'Gandahar','Gandahar','movie',1987,'https://image.tmdb.org/t/p/w500/lDM8fxNsu8oYRmM66kZrLQnPNyw.jpg','https://image.tmdb.org/t/p/original/omysgecSqildPjk4LL8To0L3tgm.jpg','On the planet Gandahar where peace reigns and poverty is unknown, this utopian lifestyle is upset by reports of people at the outlying frontiers being turned to stone. Sylvain is sent to investigate this mysterious threat.',NULL,NULL,2.6711,6.9,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(317,16859,'tt0097814',NULL,'Kiki''s Delivery Service','魔女の宅急便','movie',1989,'https://image.tmdb.org/t/p/w500/Aufa4YdZIv4AXpR9rznwVA5SEfd.jpg','https://image.tmdb.org/t/p/original/h5pAEVma835u8xoE60kmLVopLct.jpg','A young witch, on her mandatory year of independent life, finds fitting into a new community difficult while she supports herself by running an air courier service.',NULL,NULL,11.1848,7.839,0,1.34050000000000011e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(318,9726,'tt0401445',NULL,'A Good Year','A Good Year','movie',2006,'https://image.tmdb.org/t/p/w500/10ErazhJxfL68rWg2KLfwiRuIou.jpg','https://image.tmdb.org/t/p/original/dV5AKLfihrUTfAqh7dj9MG3OUWl.jpg','Failed London banker Max Skinner inherits his uncle''s vineyard in Provence, where he spent many childhood holidays. Upon his arrival, he meets a woman from California who tells Max she is his long-lost cousin and that the property is hers.',NULL,NULL,3.0537,6.689,0,11.56,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(319,22660,'tt0050798',NULL,'Old Yeller','Old Yeller','movie',1957,'https://image.tmdb.org/t/p/w500/Xe7AB0ffhGPSdBZ4qJ9AKJfllL.jpg','https://image.tmdb.org/t/p/original/bFj82z1rOIEmsin3jbdGzkeBDpv.jpg','Young Travis Coates is left to take care of the family ranch with his mother and younger brother while his father goes off on a cattle drive in the 1860s. When a yellow mongrel comes for an uninvited stay with the family, Travis reluctantly adopts the dog.',NULL,NULL,2.592,6.9,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(320,10934,'tt0328589',NULL,'Under the Tuscan Sun','Under the Tuscan Sun','movie',2003,'https://image.tmdb.org/t/p/w500/3vQUQwdtfPt1Sl2GZrIECWWA0dk.jpg','https://image.tmdb.org/t/p/original/dy516GsG7lvszB47FiotNjLARDY.jpg','Frances Mayes, a 35-year-old professor and writer from San Francisco, decides to take a tour of Tuscany following a difficult divorce. After impulsively buying a run-down villa in the Italian countryside, she begins to piece her life back together in unexpected ways.',NULL,NULL,4.1932,6.889,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(321,10315,'tt0432283',NULL,'Fantastic Mr. Fox','Fantastic Mr. Fox','movie',2009,'https://image.tmdb.org/t/p/w500/euZyZb6iGreujYKrGyZHRddhUYh.jpg','https://image.tmdb.org/t/p/original/xRxSLhhjPG2D8l0BXi0KdN4IvPt.jpg','The Fantastic Mr. Fox, bored with his current life, plans a heist against the three local farmers. The farmers, tired of sharing their chickens with the sly fox, seek revenge against him and his family.',NULL,NULL,9.6848,7.8,0,1.55283333333333324e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(322,61617,'tt3718778',NULL,'Over the Garden Wall','Over the Garden Wall','tv',2014,'https://image.tmdb.org/t/p/w500/m3lU8n7WxzMecxKZcqhq5y5ESy.jpg','https://image.tmdb.org/t/p/original/hozufHEzqIRpqJrlyGDqnsyFrAQ.jpg','Two brothers, Wirt and Greg, find themselves lost in the Unknown; a strange forest adrift in time. With the help of a wise old Woodsman and a foul-tempered bluebird named Beatrice, Wirt and Greg must travel across this strange land, in hope of finding their way home. Join them as they encounter surprises and obstacles on their journey through the wood.',NULL,NULL,8.7474,8.575,0,1.54416666666666664e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(323,352490,'tt4560008',NULL,'This Beautiful Fantastic','This Beautiful Fantastic','movie',2016,'https://image.tmdb.org/t/p/w500/22b9jLGJ8OVzlEnWzqF0yRy5Na3.jpg','https://image.tmdb.org/t/p/original/eKGjQNJ6sbSB1LoIeNoGXG0HozV.jpg','Set against the backdrop of a beautiful garden in the heart of London, this contemporary fairy tale revolves around the unlikely friendship between a reclusive young woman and a cantankerous old widower. Bella Brown is a beautifully quirky young woman who dreams of writing and illustrating a successful children’s book. After she is forced by her landlord to deal with her neglected garden or face eviction, she meets her match, nemesis, and unlikely mentor in Alfie Stephenson, a grumpy, loveless, old man who lives next door who happens to be an amazing horticulturalist.',NULL,NULL,1.2948,7.1,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(324,13967,'tt0482546',NULL,'Miss Potter','Miss Potter','movie',2006,'https://image.tmdb.org/t/p/w500/fecGKwGABfZdMbiH1WQN9zMcOkS.jpg','https://image.tmdb.org/t/p/original/heXvhrTFCF8j84iFQtpXEKCFwGL.jpg','Beatrix Potter, the author of the beloved children''s book "The Tale of Peter Rabbit", struggles for love, happiness and success.',NULL,NULL,4.2677,6.638,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(325,7406,'tt0075472',NULL,'All Creatures Great and Small','All Creatures Great and Small','tv',1978,'https://image.tmdb.org/t/p/w500/inl6wqdRPoLEDXttC33x9PBoMbN.jpg','https://image.tmdb.org/t/p/original/kqpOg91jYda1G3RU7MpjdHllAGy.jpg','The trials and misadventures of the staff at a country veterinary office in Yorkshire. James Herriot, a young animal surgeon, moves to a small Yorkshire town to begin his first job.',NULL,NULL,12.0184,7.796,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(326,2493,'tt0093779',NULL,'The Princess Bride','The Princess Bride','movie',1987,'https://image.tmdb.org/t/p/w500/2FC9L9MrjBoGHYjYZjdWQdopVYb.jpg','https://image.tmdb.org/t/p/original/2CisgvF2HcIVnbMZbSjASCtSgEb.jpg','In this enchantingly cracked fairy tale, the beautiful Princess Buttercup and the dashing Westley must overcome staggering odds to find happiness amid six-fingered swordsmen, murderous princes, Sicilians and rodents of unusual size. But even death can''t stop these true lovebirds from triumphing.',NULL,NULL,10.3919,7.703,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(327,156700,'tt2179116',NULL,'The Kings of Summer','The Kings of Summer','movie',2013,'https://image.tmdb.org/t/p/w500/6dcIbwJuxlEnzLe0EaGFvsh4ZdS.jpg','https://image.tmdb.org/t/p/original/1IL2nLny4P2njzO1MNZMrJV9EmD.jpg','Three restless teenagers run away to the woods for the summer, determined to escape their parents and live by their own rules. In a hidden clearing, they build a makeshift house and attempt to create an independent life, testing their friendship, freedom, and the challenges of living off the land.',NULL,NULL,2.712,6.967,0,2.38149999999999977e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(328,1396,'tt0072443',NULL,'Mirror','Зеркало','movie',1975,'https://image.tmdb.org/t/p/w500/AttDP5OEsMxtHPPN7Z92p2Ntnmd.jpg','https://image.tmdb.org/t/p/original/9UAcMhSCDJ2OCo5QdPpSERjhMA1.jpg','A dying man in his forties recalls his childhood, his mother, the war and personal moments that tell of and juxtapose pivotal moments in Soviet history with daily life.',NULL,NULL,6.4906,7.953,0,13.1425,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(329,1242898,'tt31227572',NULL,'Predator: Badlands','Predator: Badlands','movie',2025,'https://image.tmdb.org/t/p/w500/pHpq9yNUIo6aDoCXEBzjSolywgz.jpg','https://image.tmdb.org/t/p/original/82lM4GJ9uuNvNDOEpxFy77uv4Ak.jpg','Cast out from his clan, a young Predator finds an unlikely ally in a damaged android and embarks on a treacherous journey in search of the ultimate adversary.',NULL,NULL,52.3507,7.821,0,13.64,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(330,338766,'tt2582782',NULL,'Hell or High Water','Hell or High Water','movie',2016,'https://image.tmdb.org/t/p/w500/ljRRxqy2aXIkIBXLmOVifcOR021.jpg','https://image.tmdb.org/t/p/original/kQVdpIPCqfpa24I8SQRiwOAbkLG.jpg','A divorced dad and his ex-con brother resort to a desperate scheme in order to save their family''s farm in West Texas.',NULL,NULL,5.4802,7.303,0,6.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(331,1587,'tt0108550',NULL,'What''s Eating Gilbert Grape','What''s Eating Gilbert Grape','movie',1993,'https://image.tmdb.org/t/p/w500/8FxWgsfDNosewo7H65oE4QkOb7g.jpg','https://image.tmdb.org/t/p/original/m05zMH2I7aEOP4zc0JYOdqR4JUD.jpg','Gilbert Grape is a small-town young man with a lot of responsibility. Chief among his concerns are his mother, who is so overweight that she can''t leave the house, and his mentally impaired younger brother, Arnie, who has a knack for finding trouble. Settled into a job at a grocery store and an ongoing affair with local woman Betty Carver, Gilbert finally has his life shaken up by the free-spirited Becky.',NULL,NULL,5.9988,7.661,0,14.918,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(332,10935,'tt0080855',NULL,'Heaven''s Gate','Heaven''s Gate','movie',1980,'https://image.tmdb.org/t/p/w500/kW4Vk31nhtKPKGuYMaVATq3wcHC.jpg','https://image.tmdb.org/t/p/original/v0DsJiF7LAeJtqFObQfq3eU6rag.jpg','Harvard graduate James Averill serves as the sheriff of prosperous Jackson County, Wyoming, standing at the center of a conflict between impoverished immigrants and affluent cattle farmers. Politically connected ranchers enlist mercenary Nathan Champion—who is also vying for the affections of local madam Ella Watson—to combat the immigrant uprising. As tensions escalate, both Averill and Champion start to question their decisions.',NULL,NULL,4.7564,6.745,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(333,24266,'tt0084296',NULL,'The Man from Snowy River','The Man from Snowy River','movie',1982,'https://image.tmdb.org/t/p/w500/1alAfoJf7Pjn0QuwzO9wY7SLQCt.jpg','https://image.tmdb.org/t/p/original/vlMzSehjjVmOsJzeMz4ef9y29sF.jpg','Jim Craig has lived his first 18 years in the mountains of Australia on his father''s farm. The death of his father forces him to go to the lowlands to earn enough money to get the farm back on its feet.',NULL,NULL,1.6632,7.012,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(334,35796,'tt0119506',NULL,'Lawn Dogs','Lawn Dogs','movie',1997,'https://image.tmdb.org/t/p/w500/hNi2M5Z7GUEaSCPjt66yavLlsqV.jpg','https://image.tmdb.org/t/p/original/rKOzBCXwtRtkLpDQOyCcNvDS0qo.jpg','In the affluent, gated community of Camelot Gardens, bored wives indiscriminately sleep around while their unwitting husbands try desperately to climb the social ladder. Trent, a 21-year-old outsider who mows the neighborhood lawns, quietly observes the infidelities and hypocrisies of this overly privileged society. When Devon, a 10-year-old daughter from one family, forges a friendship with Trent, things suddenly get very complicated.',NULL,NULL,1.1818,7.1,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(335,615643,'tt10633456',NULL,'Minari','Minari','movie',2021,'https://image.tmdb.org/t/p/w500/6mPNdmjdbVKPITv3LLCmQoKs9Zw.jpg','https://image.tmdb.org/t/p/original/bKCpRjjTKcr3KAITmwjVMobbBYg.jpg','A Korean American family moves to an Arkansas farm in search of its own American dream. Amidst the challenges of this new life in the strange and rugged Ozarks, they discover the undeniable resilience of family and what really makes a home.',NULL,NULL,2.604,7.326,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(336,103731,'tt1935179',NULL,'Mud','Mud','movie',2013,'https://image.tmdb.org/t/p/w500/o2jT5jQdKh1HAF0fMKuGwBOwOYB.jpg','https://image.tmdb.org/t/p/original/otmqSaptLwYutON1oZEgBLZeBEQ.jpg','Two teenage boys find a fugitive hiding out on an island in the Mississippi River and help him reunite with his lover and escape an avenging family and their armed posse.',NULL,NULL,4.7576,7.057,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(337,837,'tt0086541',NULL,'Videodrome','Videodrome','movie',1983,'https://image.tmdb.org/t/p/w500/qqqkiZSU9EBGZ1KiDmfn07S7qvv.jpg','https://image.tmdb.org/t/p/original/eBS1nvaQ7BMdsSlkoLyKapf0FEY.jpg','As the president of a trashy TV channel, Max Renn is desperate for new programming to attract viewers. When he happens upon "Videodrome," a TV show dedicated to gratuitous torture and punishment, Max sees a potential hit and broadcasts the show on his channel. However, after his girlfriend auditions for the show and never returns, Max investigates the truth behind Videodrome and discovers that the graphic violence may not be as fake as he thought.',NULL,NULL,4.7609,7.246,0,13.7875,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(338,23963,'tt1226681',NULL,'Pontypool','Pontypool','movie',2009,'https://image.tmdb.org/t/p/w500/uh4n9FSYYaeOWchP8gBPNtg7kD7.jpg','https://image.tmdb.org/t/p/original/yxBmRVQ2Sa6P5Acqu3Ts32QudZC.jpg','When disc jockey Grant Mazzy reports to his basement radio station in the Canadian town of Pontypool, he thinks it''s just another day at work. But when he hears reports of a virus that turns people into zombies, Mazzy barricades himself in the radio booth and tries to figure out a way to warn his listeners about the virus and its unlikely mode of transmission.',NULL,NULL,1.6876,6.459,0,11.28,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(339,565743,'tt6803046',NULL,'The Vast of Night','The Vast of Night','movie',2019,'https://image.tmdb.org/t/p/w500/q2P9lYkctl5Ory71HEBMaFxbVlD.jpg','https://image.tmdb.org/t/p/original/lVSMgZUBE4XTVaPBEBAczre4f1W.jpg','At the dawn of the space-race, two radio-obsessed teens discover a strange frequency over the airwaves in what becomes the most important night of their lives and in the history of their small town.',NULL,NULL,2.0905,6.554,0,1.23899999999999987e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(340,16337,'tt0092076',NULL,'The Texas Chainsaw Massacre 2','The Texas Chainsaw Massacre 2','movie',1986,'https://image.tmdb.org/t/p/w500/cO1Dvg7k87lHSPOdumn3ddJEKdX.jpg','https://image.tmdb.org/t/p/original/5MMnUP4mzay6tVNZ8DF3HBeEUMX.jpg','A radio host is victimised by the notorious cannibal family while a former Texas Marshal hunts them.',NULL,NULL,3.3702,5.7,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(341,192132,'tt2479800',NULL,'Palo Alto','Palo Alto','movie',2014,'https://image.tmdb.org/t/p/w500/yjcwwYP3eSigxLKKVBoVVz85ZWv.jpg','https://image.tmdb.org/t/p/original/1CbxtdiBSBnihJh5F4nG4sH868L.jpg','A lack of parental guidance encourages teens in an affluent California town to rebel with substance abuse and casual sex.',NULL,NULL,1.6183,6.1,0,11.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(342,396461,'tt5691670',NULL,'Under the Silver Lake','Under the Silver Lake','movie',2018,'https://image.tmdb.org/t/p/w500/6sq6fOb02zjhguNpi5VOklq6Nj.jpg','https://image.tmdb.org/t/p/original/44dgugY6wBUFfJdaVOhNfr6E5g3.jpg','Young and disenchanted Sam meets a mysterious and beautiful woman who''s swimming in his building''s pool one night. When she suddenly vanishes the next morning, Sam embarks on a surreal quest across Los Angeles to decode the secret behind her disappearance, leading him into the murkiest depths of mystery, scandal and conspiracy.',NULL,NULL,3.2994,6.3,0,13.7625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(343,171274,'tt1791528',NULL,'Inherent Vice','Inherent Vice','movie',2014,'https://image.tmdb.org/t/p/w500/pfVua7TzzttOh3RTOuBqT7xN0oY.jpg','https://image.tmdb.org/t/p/original/cwytQHRHSrMnsSEowcY4Z6jIEeb.jpg','In Los Angeles at the turn of the 1970s, drug-fueled detective Larry "Doc" Sportello investigates the disappearance of an ex-girlfriend.',NULL,NULL,3.6891,6.54,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(344,16614,'tt1091722',NULL,'Adventureland','Adventureland','movie',2009,'https://image.tmdb.org/t/p/w500/eeSJNAR1aWcgANq26KWIHm3cbyB.jpg','https://image.tmdb.org/t/p/original/4dm60JrE7rCWQvqio1KdzQvfCvS.jpg','It''s the summer of 1987, and recent college grad James Brennan can''t wait to begin his long-anticipated dream trip to Europe. Unfortunately, James'' plans come to a screeching halt when his parents announce that they are unable to subsidize his trip. Forced to take a job at the local amusement park, James prepares for the worst summer ever, until he finds love with a captivating co-worker named Em.',NULL,NULL,2.2252,6.4,0,1.28500000000000014e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(345,4723,'tt0405336',NULL,'Southland Tales','Southland Tales','movie',2007,'https://image.tmdb.org/t/p/w500/7dbIDQ80z4bxiDlAvxRwc5TI44C.jpg','https://image.tmdb.org/t/p/original/oaT5yMG61XetddVmymGrDVeoCg4.jpg','Set in the futuristic landscape of Los Angeles on July 4, 2008, as it stands on the brink of social, economic and environmental disaster. Boxer Santaros is an action star who''s stricken with amnesia. His life intertwines with Krysta Now, an adult film star developing her own reality television project, and Ronald Taverner, a Hermosa Beach police officer who holds the key to a vast conspiracy.',NULL,NULL,2.6927,5.2,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(346,3597,'tt0119345',NULL,'I Know What You Did Last Summer','I Know What You Did Last Summer','movie',1997,'https://image.tmdb.org/t/p/w500/dQyaJx0SptDqvQcAewAr8FAtLB2.jpg','https://image.tmdb.org/t/p/original/6wpIPoE1H7N5yCuFsfcYoGBhFlP.jpg','After an accident on a winding road, four teens make the fatal mistake of dumping their victim''s body into the sea. Exactly one year later, the deadly secret resurfaces as they''re stalked by a hook-handed figure.',NULL,NULL,5.0864,6.0,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(347,1548,'tt0162346',NULL,'Ghost World','Ghost World','movie',2001,'https://image.tmdb.org/t/p/w500/uwKqnUPE4dSM0kKuMW0vXpURh2T.jpg','https://image.tmdb.org/t/p/original/6zIOO1NrTehQkDaNfvga4luSRQc.jpg','Two quirky, cynical teenaged girls try to figure out what to do with their lives after high school graduation. After they play a prank on an eccentric, middle aged record collector, one of them befriends him, which causes a rift in the girls’ friendship.',NULL,NULL,1.8736,7.092,0,13.032,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(348,85350,'tt1065073',NULL,'Boyhood','Boyhood','movie',2014,'https://image.tmdb.org/t/p/w500/2BvtvDUyxiMJ4dmKfiQf4qdOHQN.jpg','https://image.tmdb.org/t/p/original/Ac2s9RJEi1ZeaQopoLsqlsmWQmx.jpg','The film tells a story of a divorced couple trying to raise their young son. The story follows the boy for twelve years, from first grade at age 6 through 12th grade at age 17-18, and examines his relationship with his parents as he grows.',NULL,NULL,4.4007,7.5,0,1.51766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(349,97367,'tt1817273',NULL,'The Place Beyond the Pines','The Place Beyond the Pines','movie',2013,'https://image.tmdb.org/t/p/w500/vY5j2xQzMGWmxBuhQo0HfA4Lxqb.jpg','https://image.tmdb.org/t/p/original/qCsaZ2GoaCn5vmOUD9kCsyabr9o.jpg','A motorcycle stunt rider considers committing a crime in order to provide for his wife and child, an act that puts him on a collision course with a cop-turned-politician.',NULL,NULL,4.4209,6.979,0,13.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(350,838,'tt0069704',NULL,'American Graffiti','American Graffiti','movie',1973,'https://image.tmdb.org/t/p/w500/1tjLivPad2PX8FAzWko7FPIb8d2.jpg','https://image.tmdb.org/t/p/original/xdofxnT2FADbSFOJflOTLnCoZe9.jpg','A couple of high school graduates spend one final night cruising the strip with their buddies before they go off to college.',NULL,NULL,3.7985,7.043,0,13.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(351,19008,'tt0115040',NULL,'The Garden','Záhrada','movie',1995,'https://image.tmdb.org/t/p/w500/u9rrUaFUUePbPdem4ZnsyE7rbtF.jpg','https://image.tmdb.org/t/p/original/3XXGGrULW7WJQ16B3EBSgGKb88T.jpg','Jakub''s life arrived at a dead-end. He leaves his job, and gets into conflict with his father. The trouble just grows by his relation with a married woman. Breaking out, Jakub realizes the pleasures of the countryside in the old garden of his grandfather. He finds true love with an angel, and encounters various exciting moments of his new free life. Strange visitors arrive, and he wont get back to town anymore.',NULL,NULL,0.73,7.28,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(352,451480,'tt1289403',NULL,'The Guernsey Literary & Potato Peel Pie Society','The Guernsey Literary & Potato Peel Pie Society','movie',2018,'https://image.tmdb.org/t/p/w500/55oz5d6NdH7ohbM1I1Euh1Tt6PN.jpg','https://image.tmdb.org/t/p/original/mGDUIbcrdULI7N0eg1Ip7oY0aUS.jpg','Free-spirited writer Juliet Ashton forms a life-changing bond with the delightful and eccentric Guernsey Literary and Potato Peel Pie Society, when she decides to write about the book club they formed during the occupation of Guernsey in WWII.',NULL,NULL,1.8687,7.4,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(353,543084,'tt8969332',NULL,'The Biggest Little Farm','The Biggest Little Farm','movie',2019,'https://image.tmdb.org/t/p/w500/xpR9OdRibETfuWNrdxStAJDRU7A.jpg','https://image.tmdb.org/t/p/original/dvWrNGm9c4cPOg43jEF4blAZX3V.jpg','The successes and failures of a couple determined to live in harmony with nature on a farm outside of Los Angeles are lovingly chronicled by filmmaking farmer John Chester, in this inspiring documentary.',NULL,NULL,1.1173,7.601,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(354,8282,'tt0836700',NULL,'Summer Hours','L''Heure d''été','movie',2008,'https://image.tmdb.org/t/p/w500/dUBEHjL1qa5y0uKQauwPdWoMVUM.jpg','https://image.tmdb.org/t/p/original/dQoQYlnbbI08gotToAO5ZyS1v63.jpg','After the death of a septuagenarian woman, her three children deliberate over what to do with her estate.',NULL,NULL,1.2685,6.407,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(355,11235,'tt0085859',NULL,'Local Hero','Local Hero','movie',1983,'https://image.tmdb.org/t/p/w500/jqxD0H9a1rg5bXftsm6gsNOjt4n.jpg','https://image.tmdb.org/t/p/original/tfiFC0pw1ccJFBkYkhP9uWeQ1S1.jpg','An American oil company sends a man to Scotland to buy up an entire village where they want to build a refinery. But things don''t go as expected.',NULL,NULL,1.9111,6.8,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(356,25518,'tt0115650',NULL,'La Belle Verte','La Belle Verte','movie',1996,'https://image.tmdb.org/t/p/w500/8KE4MGBu9BNr2dawI17n1We64nF.jpg','https://image.tmdb.org/t/p/original/a1ng6McskX9Qg8SJNE98zywG4ki.jpg','As part of an intergalactic coalition, a well-meaning space alien volunteers to bring a message of self-actualization and harmony with nature to the one planet rejected by all her peers as incorrigible: Earth.',NULL,NULL,3.7063,7.154,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(357,336222,'tt3296658',NULL,'Rams','Hrútar','movie',2015,'https://image.tmdb.org/t/p/w500/pk75njhxcxTJAl0FJ1V2ROGIEy1.jpg','https://image.tmdb.org/t/p/original/eAgKvahrg6EY521kEA11GwGvjY2.jpg','In a secluded valley in Iceland, Gummi and Kiddi live side by side, tending to their sheep. Their ancestral sheep-stock is considered one of the country’s best and the two brothers are repeatedly awarded for their prized rams who carry an ancient lineage. Although they share the land and a way of life, Gummi and Kiddi have not spoken to each other in four decades. When a lethal disease suddenly infects Kiddi’s sheep, the entire valley comes under threat. The authorities decide to cull all the animals in the area to contain the outbreak. But Gummi and Kiddi don’t give up so easily – and each brother tries to stave off the disaster in his own fashion: Kiddi by using his rifle and Gummi by using his wits.',NULL,NULL,0.8019,6.969,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(358,106765,'tt0049150',NULL,'Valley of Peace','Dolina miru','movie',1956,'https://image.tmdb.org/t/p/w500/de1q7qX3jtRVHNZI8hvVZPHLCf2.jpg','https://image.tmdb.org/t/p/original/siNF05xZZzMwlc46iSmEBVUkIce.jpg','When the planes bombed a Slovene town, a Slovene boy and a German girl set on a journey towards the valley, in which there is no war. On their way a black American pilot, who jumped of a shoot-down plane, joins them. Although American planes have killed the boy''s parents, he accepts the pilot with enthusiasm. The children communicate with him in German and the valley of peace seems like the last paradise place of refuge. The Slovene boy, the German girl, and the American pilot represent a symbolic triangle of peace in this adventure happening in the middle of the War of Liberation.',NULL,NULL,0.3961,6.6,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(359,293,'tt0105265',NULL,'A River Runs Through It','A River Runs Through It','movie',1992,'https://image.tmdb.org/t/p/w500/aVP45oS2cBL4WtZ1kB7r8uarruB.jpg','https://image.tmdb.org/t/p/original/85dLdBCBbuZYde0T6L1CKXd707u.jpg','The Maclean brothers, Paul and Norman, live a relatively idyllic life in rural Montana, spending much of their time fly fishing. The sons of a minister, the boys eventually part company when Norman moves east to attend college, leaving his rebellious brother to find trouble back home. When Norman finally returns, the siblings resume their fishing outings, and assess where they''ve been and where they''re going.',NULL,NULL,4.3548,7.0,0,12.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(360,228194,'tt2980648',NULL,'The Hundred-Foot Journey','The Hundred-Foot Journey','movie',2014,'https://image.tmdb.org/t/p/w500/1vFhSr7INoulu18smHqicft05i8.jpg','https://image.tmdb.org/t/p/original/jUaZAbdpNl33VHprUl4qEohXn8q.jpg','A story centered around an Indian family who moves to France and opens a restaurant across the street from a Michelin-starred French restaurant.',NULL,NULL,2.1302,7.3,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(361,123778,'tt0102993',NULL,'The Company of Strangers','The Company of Strangers','movie',1990,'https://image.tmdb.org/t/p/w500/hlXFhekstIC0hsVjbhLjjC5EWBy.jpg','https://image.tmdb.org/t/p/original/h8ruAR69EEpXnMtGMEGGIPzaYsg.jpg','A busload of women become stranded in an isolated part of the Canadian countryside. As they await rescue, they reflect on their lives through a mostly ad-libbed script.',NULL,NULL,0.3247,7.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(362,398818,'tt5726616',NULL,'Call Me by Your Name','Call Me by Your Name','movie',2017,'https://image.tmdb.org/t/p/w500/mZ4gBdfkhP9tvLH1DO4m4HYtiyi.jpg','https://image.tmdb.org/t/p/original/4Xh2a1WeTp6b8Ksvug0pAMbX3dT.jpg','In the summer of 1983, a 17-year-old Elio spends his days in his family''s villa in Italy. One day Oliver, a graduate student, arrives to assist Elio''s father, a professor of Greco-Roman culture. Soon, Elio and Oliver discover a summer that will alter their lives forever.',NULL,NULL,17.0985,8.1,0,1.63214285714285729e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(363,11191,'tt0095690',NULL,'Mystic Pizza','Mystic Pizza','movie',1988,'https://image.tmdb.org/t/p/w500/2wqMKLJEMjenT7U8UqnuI070cUC.jpg','https://image.tmdb.org/t/p/original/czGSXzONlaJNntsWR4t1elodavq.jpg','Three teenage girls come of age while working at a pizza parlor in Mystic, Connecticut.',NULL,NULL,2.5626,6.294,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(364,94028,'tt11016042',NULL,'RIPLEY','RIPLEY','tv',2024,'https://image.tmdb.org/t/p/w500/rpSo8z9alultGVTqQ3dkLEyU8xx.jpg','https://image.tmdb.org/t/p/original/erpjqVdJLpDQJjsbxaSJmMwvcqd.jpg','A grifter in 1960s New York is hired to convince a wealthy man''s son to return home from Italy and begins a life of deceit, fraud and murder.',NULL,NULL,11.5115,7.923,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(365,5165,'tt0053619',NULL,'L''Avventura','L''avventura','movie',1960,'https://image.tmdb.org/t/p/w500/7kUXAS8K7Ihw1T1mhARjnLuMVk3.jpg','https://image.tmdb.org/t/p/original/kF5AeKG5XIZkAXY0kRgm57qEbJI.jpg','Claudia and Anna join Anna''s lover, Sandro, on a boat trip to a remote volcanic island. When Anna goes missing, a search is launched. In the meantime, Sandro and Claudia become involved in a romance despite Anna''s disappearance, though the relationship suffers from guilt and tension.',NULL,NULL,2.8565,7.5,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(366,2786,'tt0059592',NULL,'Pierrot le Fou','Pierrot le fou','movie',1965,'https://image.tmdb.org/t/p/w500/i124H6iQB4CawrgFW9aZaZs7OBO.jpg','https://image.tmdb.org/t/p/original/4zJ9w3lZcZI3mBXcNiq6s8bqpDO.jpg','Pierrot escapes his boring society and travels from Paris to the Mediterranean Sea with Marianne, a girl chased by hit-men from Algeria. They lead an unorthodox life, always on the run.',NULL,NULL,2.9395,7.3,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(367,241855,'tt3395184',NULL,'Spring','Spring','movie',2014,'https://image.tmdb.org/t/p/w500/aBObn1dKdJpMA1EYFDTYPWdccwr.jpg','https://image.tmdb.org/t/p/original/62PJAfCHczgD6sTdnnLXQIuKRlN.jpg','A young man in a personal tailspin flees the US to Italy, where he sparks up a romance with a woman harboring a dark, primordial secret.',NULL,NULL,2.2663,6.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(368,945729,'tt22687790',NULL,'A Haunting in Venice','A Haunting in Venice','movie',2023,'https://image.tmdb.org/t/p/w500/l6iwxT0NbVw6QiF08YTIuTnXS82.jpg','https://image.tmdb.org/t/p/original/qB9wshRySHgN2MibLOlsW6YalqD.jpg','Celebrated sleuth Hercule Poirot, now retired and living in self-imposed exile in Venice, reluctantly attends a Halloween séance at a decaying, haunted palazzo. When one of the guests is murdered, the detective is thrust into a sinister world of shadows and secrets.',NULL,NULL,5.0567,6.566,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(369,18872,'tt0113725',NULL,'Maborosi','幻の光','movie',1995,'https://image.tmdb.org/t/p/w500/ri9sequtTo9K8I6AQoRbbBzU8F2.jpg','https://image.tmdb.org/t/p/original/bk8RQN88Hh5jusTKydxCJfDlDNg.jpg','A tragedy strikes a young woman''s life without warning or reason. She continues living while searching for meaning in a lonely world.',NULL,NULL,1.5538,7.5,0,1.21933333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(370,1913,'tt0369702',NULL,'The Sea Inside','Mar adentro','movie',2004,'https://image.tmdb.org/t/p/w500/mQW1JJKCUg02cmWBzr9JFu9vM1V.jpg','https://image.tmdb.org/t/p/original/7XmDhCTkce5GH8KCdbMoTZdxn1p.jpg','Ramón Sampedro is a ship mechanic and part-time poet left a quadriplegic following a diving accident. Ramón fought for 30 years for the legal right to end his own life. He develops close relationships with his long-term lawyer Julia and his friend Rosa, who tries to convince him that his life is worth living. Despite his situation, Ramón manages to inspire those around him to live life to the fullest.',NULL,NULL,3.3226,7.56,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(371,713,'tt0107822',NULL,'The Piano','The Piano','movie',1993,'https://image.tmdb.org/t/p/w500/rx8RKXn8OtuS6lqloYsjyrGOUp4.jpg','https://image.tmdb.org/t/p/original/c2O99arhWcuLexMHiuRfSuDMpYm.jpg','When an arranged marriage brings Ada and her spirited daughter to the wilderness of nineteenth-century New Zealand, she finds herself locked in a battle of wills with both her controlling husband and a rugged frontiersman to whom she develops a forbidden attraction.',NULL,NULL,9.6367,7.374,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(372,586451,'tt8299768',NULL,'Blow the Man Down','Blow the Man Down','movie',2019,'https://image.tmdb.org/t/p/w500/AgxDU9Vp0R6RIV6jpmQ4JrTcZzv.jpg','https://image.tmdb.org/t/p/original/fsM6AB85cptuiG142s6ZQS17mjr.jpg','While grieving for the loss of their mother, the Connolly sisters suddenly find they have a crime to cover up, leading them deep into the underbelly of their salty Maine fishing village.',NULL,NULL,1.5427,6.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(373,22292,'tt0039420',NULL,'The Ghost and Mrs. Muir','The Ghost and Mrs. Muir','movie',1947,'https://image.tmdb.org/t/p/w500/idoD3cwfwj86BPvVoWVgWhnT2xq.jpg','https://image.tmdb.org/t/p/original/m1QTfbKD90j63Gh9bOJt0g67LvA.jpg','In 1900, young widow Lucy Muir learns that her seaside cottage is haunted and forms a unique relationship with the ghost.',NULL,NULL,1.9459,7.539,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(374,3021,'tt0450385',NULL,'1408','1408','movie',2007,'https://image.tmdb.org/t/p/w500/yE9MCW7ZNxSw5SC1TMqm51pMBIV.jpg','https://image.tmdb.org/t/p/original/a4ZupLMg23auAw8e1j1K39PCO6z.jpg','A man who specializes in debunking paranormal occurrences checks into the fabled room 1408 in the Dolphin Hotel. Soon after settling in, he confronts genuine terror.',NULL,NULL,6.2208,6.698,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(375,83473,'tt2072029',NULL,'7 Nights Of Darkness','7 Nights Of Darkness','movie',2011,'https://image.tmdb.org/t/p/w500/waC7zI1fqjmZo9C0NvUQTUnYo4I.jpg','https://image.tmdb.org/t/p/original/4gqr9cHhQaDsZsN7DQL9CLFzmZt.jpg','In 2010 six reality television show contestants spent seven nights in an abandoned and haunted asylum. The show never aired but an editor for the network was able to piece together some footage. The prize for staying all seven nights was a share of one million dollars that was to be split amongst any contestants that didn''t leave. No prize money was ever awarded.',NULL,NULL,0.9822,4.032,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(376,447332,'tt6644200',NULL,'A Quiet Place','A Quiet Place','movie',2018,'https://image.tmdb.org/t/p/w500/nAU74GmpUk7t5iklEp3bufwDq4n.jpg','https://image.tmdb.org/t/p/original/nHRUtBwFNnNN70vcQ7lAsjc2T6S.jpg','A family is forced to live in silence while hiding from creatures that hunt by sound.',NULL,NULL,9.9172,7.395,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(377,1598,'tt0101540',NULL,'Cape Fear','Cape Fear','movie',1991,'https://image.tmdb.org/t/p/w500/meJZAAuVcjic2ipvbOPz5UlE4P9.jpg','https://image.tmdb.org/t/p/original/ntgpger7OwFNlEldxuvvFHDKzjW.jpg','Sam Bowden is a small-town corporate attorney. Max Cady is a tattooed, cigar-smoking, Bible-quoting, psychotic rapist. What do they have in common? 14 years ago, Sam was a public defender assigned to Max Cady''s rape trial, and he made a serious error: he hid a document from his illiterate client that could have gotten him acquitted. Now, the cagey Cady has been released, and he intends to teach Sam Bowden and his family a thing or two about loss.',NULL,NULL,9.0027,7.264,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(378,10823,'tt0087050',NULL,'Children of the Corn','Children of the Corn','movie',1984,'https://image.tmdb.org/t/p/w500/jJTrFHu3rjAgP1lryKGEsC9hqyM.jpg','https://image.tmdb.org/t/p/original/1IKOtiErR3I4JMgK4LjCFc2DQ0d.jpg','A traveling couple end up in an abandoned Nebraska town inhabited by a cult of murderous children who worship a demon that lives in the local cornfields.',NULL,NULL,4.7607,5.7,0,1.4709999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(379,797134,'tt11967404',NULL,'C.O.R.N.','C.O.R.N.','movie',2021,'https://image.tmdb.org/t/p/w500/gwOOUmpPi74AcemVCiYc6C8xuFG.jpg','https://image.tmdb.org/t/p/original/q1o2aJ1n6P2VuqcITNqnokPJwzu.jpg','Stranded in a rural area, 2 teens make friends with locals on Halloween but soon run into a cult called C.O.R.N. (Collective Order of Recreational Necrophilanthropists) that have chosen this area to perform human taxidermy.',NULL,NULL,0.4112,6.3,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(380,19592,'tt0377749',NULL,'Dead Birds','Dead Birds','movie',2005,'https://image.tmdb.org/t/p/w500/xB1qpndocvnS23qIv0F7OqYZLpj.jpg','https://image.tmdb.org/t/p/original/WyCraJdklEeet3hTJiAjzhmhWx.jpg','Towards the end of the Civil War, a group of Confederate soldiers hole up on an abandoned plantation after robbing a bank, and find themselves at the mercy of supernatural forces.',NULL,NULL,1.3378,5.691,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(381,743022,'tt9191844',NULL,'Fear PHarm','Fear PHarm','movie',2020,'https://image.tmdb.org/t/p/w500/mSlmVGukZquWwiw3Bv2sArX5UmE.jpg','https://image.tmdb.org/t/p/original/78ycoJaCgjtB0YbDIHaObFwJkvG.jpg','Four people enter a corn maze for Halloween and are picked off one by one by the twisted family who own the scare attraction.',NULL,NULL,0.5534,5.337,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(382,18274,'tt0068615',NULL,'Frogs','Frogs','movie',1972,'https://image.tmdb.org/t/p/w500/dF2OlQBMJiggzkjhfaNfx7HzBOU.jpg','https://image.tmdb.org/t/p/original/rVjkmGfhU8q4d9hXsq3612bEtwI.jpg','Jason Crockett is an aging, grumpy, physically disabled millionaire who invites his family to his island estate for his birthday celebration. Pickett Smith is a free-lance photographer who is doing a pollution layout for an ecology magazine. Jason Crockett hates nature, poisoning anything that crawls on his property. On the night of his birthday the frogs and other members of nature begin to pay Crockett back.',NULL,NULL,1.023,4.758,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(383,418078,'tt4695012',NULL,'It Comes at Night','It Comes at Night','movie',2017,'https://image.tmdb.org/t/p/w500/rNKJpFMlOZn5zkzBPZxEJrQn5Km.jpg','https://image.tmdb.org/t/p/original/6h9pjTsWzaUWuUszHHbeI1JWE1.jpg','Secure within a desolate home as an unnatural threat terrorizes the world, a man has established a tenuous domestic order with his wife and son, but this will soon be put to test when a desperate young family arrives seeking refuge.',NULL,NULL,2.8528,5.871,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(384,27374,'tt0816556',NULL,'Lake Mungo','Lake Mungo','movie',2009,'https://image.tmdb.org/t/p/w500/g0zCELYfBfSv8TOGC13buABVN53.jpg','https://image.tmdb.org/t/p/original/5eaS62YjA5Z7WPcf4quyZa5VpeO.jpg','After 16-year-old Alice Palmer drowns at a local dam, her family experiences a series of strange, inexplicable events centered in and around their home. Unsettled, the Palmers seek the help of a psychic and parapsychologist, who discovers that Alice led a secret, double life. At Lake Mungo, Alice''s secret past emerges.',NULL,NULL,3.1714,6.17,0,19.846,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(385,27324,'tt0286751',NULL,'Pulse','回路','movie',2001,'https://image.tmdb.org/t/p/w500/c3zEimDraIyMSasPMGDaNOrhnzn.jpg','https://image.tmdb.org/t/p/original/7Zkp2AL7Nc4IWfZefgyvbEeSI7m.jpg','In the immense city of Tokyo, the darkness of the afterlife lures some of its inhabitants desperately trying to escape the sadness and isolation of the modern world.',NULL,NULL,3.8228,6.707,0,1.66771428571428579e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(386,2675,'tt0286106',NULL,'Signs','Signs','movie',2002,'https://image.tmdb.org/t/p/w500/YtrIdrTxpRhvCnlw43dwOjfLqx.jpg','https://image.tmdb.org/t/p/original/rsPjEr7o02mo8ex6wD2PbRwasUe.jpg','A family living on a farm finds mysterious crop circles in their fields which suggests something more frightening to come.',NULL,NULL,8.43,6.725,0,13.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(387,994143,'tt21307994',NULL,'Skinamarink','Skinamarink','movie',2023,'https://image.tmdb.org/t/p/w500/o942912KFh89SGhqWuKXuT0SXzN.jpg','https://image.tmdb.org/t/p/original/8Y0RxH5cXiKV8C9Wyj6JkW9VYaG.jpg','Two children wake up in the middle of the night to find their father is missing, and all the windows and doors in their home have vanished.',NULL,NULL,3.1289,5.339,0,25.76625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
