INSERT OR IGNORE INTO "recommendations" VALUES(389,2667,'tt0185937',NULL,'The Blair Witch Project','The Blair Witch Project','movie',1999,'https://image.tmdb.org/t/p/w500/9050VGrYjYrEjpOvDZVAngLbg1f.jpg','https://image.tmdb.org/t/p/original/1JnemtgRmn3vcVE4GEzUkJVuL8B.jpg','In October of 1994 three student filmmakers disappeared in the woods near Burkittsville, Maryland, while shooting a documentary. A year later their footage was found.',NULL,NULL,6.0446,6.367,0,14.316,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(390,694,'tt0081505',NULL,'The Shining','The Shining','movie',1980,'https://image.tmdb.org/t/p/w500/uAR0AWqhQL1hQa69UDEbb2rE5Wx.jpg','https://image.tmdb.org/t/p/original/mmd1HnuvAzFc4iuVJcnBrhDNEKr.jpg','Jack Torrance accepts a caretaker job at the Overlook Hotel, where he, along with his wife Wendy and their son Danny, must live isolated from the rest of the world for the winter. But they aren''t prepared for the madness that lurks within.',NULL,NULL,28.9345,8.2,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(391,184352,'tt2427892',NULL,'Tom at the Farm','Tom à la ferme','movie',2014,'https://image.tmdb.org/t/p/w500/df7pp0jSs4wRxfWHtdgCaDPelmm.jpg','https://image.tmdb.org/t/p/original/jv247hW6iebdNHwtt8fZdXjZwdV.jpg','A young man travels to an isolated farm for his lover''s funeral where he''s quickly drawn into a twisted, sexually charged game by his lover''s aggressive brother.',NULL,NULL,1.2766,6.774,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(392,1078605,'tt26581740',NULL,'Weapons','Weapons','movie',2025,'https://image.tmdb.org/t/p/w500/cpf7vsRZ0MYRQcnLWteD5jK9ymT.jpg','https://image.tmdb.org/t/p/original/8VyTWJrNEyV2MTWvniDVp0MpOAe.jpg','When all but one child from the same class mysteriously vanish on the same night at exactly the same time, a community is left questioning who or what is behind their disappearance.',NULL,NULL,17.0307,7.259,0,1.41900000000000012e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(393,258480,'tt2402927',NULL,'Carol','Carol','movie',2015,'https://image.tmdb.org/t/p/w500/cJeled7EyPdur6TnCA5GYg0UVna.jpg','https://image.tmdb.org/t/p/original/o0ghC4XMIMdbRBXIqSvnPrxwj3W.jpg','In 1950s New York, a department-store clerk who dreams of a better life falls for an older, married woman.',NULL,NULL,3.7219,7.493,0,1.2993333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(394,64690,'tt0780504',NULL,'Drive','Drive','movie',2011,'https://image.tmdb.org/t/p/w500/602vevIURmpDfzbnv5Ubi6wIkQm.jpg','https://image.tmdb.org/t/p/original/iymDDg4upZWgpbSeiE1JCjsSPBs.jpg','Driver is a skilled Hollywood stuntman who moonlights as a getaway driver for criminals. Though he projects an icy exterior, lately he''s been warming up to a pretty neighbor named Irene and her young son, Benicio. When Irene''s husband gets out of jail, he enlists Driver''s help in a million-dollar heist. The job goes horribly wrong, and Driver must risk his life to protect Irene and Benicio from the vengeful masterminds behind the robbery.',NULL,NULL,10.6508,7.583,0,1.18499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(395,1018,'tt0166924',NULL,'Mulholland Drive','Mulholland Drive','movie',2001,'https://image.tmdb.org/t/p/w500/x7A59t6ySylr1L7aubOQEA480vM.jpg','https://image.tmdb.org/t/p/original/g9ClaS5EqU0Hk8WIbMNhld0Bk6f.jpg','Blonde Betty Elms has only just arrived in Hollywood to become a movie star when she meets an enigmatic brunette with amnesia. Meanwhile, as the two set off to solve the second woman''s identity, filmmaker Adam Kesher runs into ominous trouble while casting his latest project.',NULL,NULL,12.7636,7.8,0,2.04736363636363662e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(396,12573,'tt1019452',NULL,'A Serious Man','A Serious Man','movie',2009,'https://image.tmdb.org/t/p/w500/5gGxDS8WmrebPlMHexVS8EVehiP.jpg','https://image.tmdb.org/t/p/original/6j3YrwkG4TZo8oNR4U4SDpql4pP.jpg','It is 1967, and Larry Gopnik, a physics professor at a quiet Midwestern university, has just been informed by his wife Judith that she is leaving him. She has fallen in love with one of his more pompous acquaintances Sy Ableman.',NULL,NULL,2.7602,6.697,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(397,86838,'tt1931533',NULL,'Seven Psychopaths','Seven Psychopaths','movie',2012,'https://image.tmdb.org/t/p/w500/4ukEYAxlSivFcDG6vLxJB6PjTjg.jpg','https://image.tmdb.org/t/p/original/6KrodMTWn9hNZBhrwOYd8snqtVp.jpg','A struggling screenwriter inadvertently becomes entangled in the Los Angeles criminal underworld after his oddball friends kidnap a gangster''s beloved Shih Tzu.',NULL,NULL,3.4131,6.82,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(398,242582,'tt2872718',NULL,'Nightcrawler','Nightcrawler','movie',2014,'https://image.tmdb.org/t/p/w500/j9HrX8f7GbZQm1BrBiR40uFQZSb.jpg','https://image.tmdb.org/t/p/original/bdI6U1mT0kCdTJ6TWtiFxQ42GSn.jpg','When Lou Bloom, desperate for work, muscles into the world of L.A. crime journalism, he blurs the line between observer and participant to become the star of his own story. Aiding him in his effort is Nina, a TV-news veteran.',NULL,NULL,9.7534,7.709,0,13.135,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(399,340666,'tt4550098',NULL,'Nocturnal Animals','Nocturnal Animals','movie',2016,'https://image.tmdb.org/t/p/w500/mdLDgQBD0va09npSQX5Zgo2evXM.jpg','https://image.tmdb.org/t/p/original/5d6m8CIBQcHeiwr6R5ou4wxO9Vn.jpg','Susan Morrow receives a book manuscript from her ex-husband – a man she left 20 years earlier – asking for her opinion of his writing. As she reads, she is drawn into the fictional life of Tony Hastings, a mathematics professor whose family vacation turns violent.',NULL,NULL,4.4559,7.41,0,1.25266666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(400,429200,'tt4846232',NULL,'Good Time','Good Time','movie',2017,'https://image.tmdb.org/t/p/w500/yE1c9hj5Hf8a9KplAdRdhADqUro.jpg','https://image.tmdb.org/t/p/original/5AhkjcqqRxBdpYZ0TeOuTCuOUYq.jpg','After a botched bank robbery lands his younger brother in prison, Connie Nikas embarks on a twisted odyssey through New York City''s underworld to get his brother Nick out of jail.',NULL,NULL,4.7809,7.21,0,1.41119999999999983e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(401,619730,'tt10731256',NULL,'Don''t Worry Darling','Don''t Worry Darling','movie',2022,'https://image.tmdb.org/t/p/w500/jOqxKIOC92BVyinYO1Fm73XY7Tc.jpg','https://image.tmdb.org/t/p/original/tfCNMP37jRX3TOetuce7FLkxNKa.jpg','Alice and Jack are lucky to be living in the idealized community of Victory, the experimental company town housing the men who work for the top-secret Victory Project and their families. But when cracks in their idyllic life begin to appear, exposing flashes of something much more sinister lurking beneath the attractive façade, Alice can’t help questioning exactly what they’re doing in Victory, and why.',NULL,NULL,6.2484,6.763,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(402,10218,'tt0117802',NULL,'Swingers','Swingers','movie',1996,'https://image.tmdb.org/t/p/w500/rRjWk68kU3a2so4lgr3TKB7Y5vA.jpg','https://image.tmdb.org/t/p/original/urQRrvRzsBztqjOt7yuxX9gpqw1.jpg','After 6 years together, Mike''s girlfriend leaves him, so he travels to LA to be a star. Six months on, he''s still not doing very well— so a few of his friends try to reconnect him to the social scene and hopefully help him forget his failed relationship.',NULL,NULL,3.8774,6.849,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(403,87739,'tt10048342',NULL,'The Queen''s Gambit','The Queen''s Gambit','tv',2020,'https://image.tmdb.org/t/p/w500/zU0htwkhNvBQdVSIKB9s6hgVeFK.jpg','https://image.tmdb.org/t/p/original/34OGjFEbHj0E3lE2w0iTUVq0CBz.jpg','In a 1950s orphanage, a young girl reveals an astonishing talent for chess and begins an unlikely journey to stardom while grappling with addiction.',NULL,NULL,13.9395,8.432,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(404,11459,'tt0405325',NULL,'Sky High','Sky High','movie',2005,'https://image.tmdb.org/t/p/w500/nBB0XNMwvYvWpo67EcxQqKMoMKf.jpg','https://image.tmdb.org/t/p/original/jdPlX87pp3s7BplR2m7ldVJyP3z.jpg','Set in a world where superheroes are commonly known and accepted, young Will Stronghold, the son of the Commander and Jetstream, tries to find a balance between being a normal teenager and an extraordinary being.',NULL,NULL,4.95,6.261,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
