INSERT OR IGNORE INTO "recommendations" VALUES(406,213,'tt0053125',NULL,'North by Northwest','North by Northwest','movie',1959,'https://image.tmdb.org/t/p/w500/kNOFPQrel9YFCVzI0DF8FnCEpCw.jpg','https://image.tmdb.org/t/p/original/OR8oloCZ3klJtB7Y0i8pSqWw5a.jpg','Advertising man Roger Thornhill is mistaken for a spy, triggering a deadly cross-country chase.',NULL,NULL,5.4977,7.963,0,13.9025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(407,309242,'tt2349144',NULL,'Mississippi Grind','Mississippi Grind','movie',2015,'https://image.tmdb.org/t/p/w500/vS3Bc6BiuZtAbSQpKhhRzPa7c2d.jpg','https://image.tmdb.org/t/p/original/fXyhfO8wUzrP5FWihTta3JhwZ2L.jpg','Gerry is a talented but down-on-his-luck gambler whose fortunes begin to change when he meets Curtis, a younger, highly charismatic poker player.  The two strike up an immediate friendship and Gerry quickly persuades his new friend to accompany him on a road trip to a legendary high stakes poker game in New Orleans. As they make their way down the Mississippi River, Gerry and Curtis manage to find themselves in just about every bar, racetrack, casino, and pool hall they can find, experiencing both incredible highs and dispiriting lows, but ultimately forging a deep and genuine bond that will stay with them long after their adventure is over.',NULL,NULL,1.4963,6.0,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(408,141,'tt0246578',NULL,'Donnie Darko','Donnie Darko','movie',2001,'https://image.tmdb.org/t/p/w500/j2AtZFsflxiluaNtajMTI0Avm8C.jpg','https://image.tmdb.org/t/p/original/msCHK5Kh1YbdZ0zPJ2nzPUhhSN9.jpg','After narrowly escaping a bizarre accident, a troubled teenager is plagued by visions of a large bunny rabbit that manipulates him to commit a series of crimes.',NULL,NULL,10.4157,7.8,0,1.44140000000000014e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(409,396940,'tt5112578',NULL,'Super Dark Times','Super Dark Times','movie',2017,'https://image.tmdb.org/t/p/w500/7sJoNicLJ9EZwetp5ucjS8qQ9g1.jpg','https://image.tmdb.org/t/p/original/EaGrw1TSRdYxZADDGjJKB40YKV.jpg','Teenagers Zach and Josh have been best friends their whole lives, but when a gruesome accident leads to a cover-up, the secret drives a wedge between them and propels them down a rabbit hole of escalating paranoia and violence.',NULL,NULL,1.6085,6.49,0,17.2775,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(410,776501,'tt13648224',NULL,'We''re All Going to the World''s Fair','We''re All Going to the World''s Fair','movie',2022,'https://image.tmdb.org/t/p/w500/fXn4Nz1WCTEmzAFvwgEZoPHvptR.jpg','https://image.tmdb.org/t/p/original/8ruxjzQ8Zl0QDbWXvSzViXTZIX.jpg','Reality and fantasy begin to blur when a teenager, alone in her attic bedroom, immerses herself in a role-playing horror game online.',NULL,NULL,1.3585,5.468,0,1.84622222222222234e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(411,113988,'',NULL,'DAHMER - Monster: The Jeffrey Dahmer Story','DAHMER - Monster: The Jeffrey Dahmer Story','tv',2022,'https://image.tmdb.org/t/p/w500/f2PVrphK0u81ES256lw3oAZuF3x.jpg','https://image.tmdb.org/t/p/original/5vUux2vNUTqwCzb7tVcH18XnsF.jpg','This series examines the gruesome and horrific true crimes of Jeffrey Dahmer and the systemic failures that enabled one of America’s most notorious serial killers to continue his murderous spree in plain sight for over a decade.',NULL,NULL,15.191,7.963,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(412,162,'tt0099487',NULL,'Edward Scissorhands','Edward Scissorhands','movie',1990,'https://image.tmdb.org/t/p/w500/e0FqKFvGPdQNWG8tF9cZBtev9Em.jpg','https://image.tmdb.org/t/p/original/uNLIMPxknsV4n3IAEDpS1iqF5dm.jpg','A small suburban town receives a visit from a castaway unfinished science experiment named Edward.',NULL,NULL,10.6243,7.719,0,13.885,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(413,13919,'tt0406650',NULL,'The Chumscrubber','The Chumscrubber','movie',2005,'https://image.tmdb.org/t/p/w500/uMb26IjDgdq8p4H3XNO1CAsjT4m.jpg','https://image.tmdb.org/t/p/original/t5dM0pTUTZ8X3ubmUp3hOuOpdcO.jpg','The Chumscrubber is a dark comedy about the lives of people who live in upper-class suburbia. It all begins when Dean Stiffle finds the body of his friend, Troy. He doesn''t bother telling any of the adults because he knows they won''t care. Everyone in town is too self consumed to worry about anything else than themselves. And everybody is on some form of drug just to get through their days.',NULL,NULL,1.5296,6.493,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(414,11446,'tt0114906',NULL,'Welcome to the Dollhouse','Welcome to the Dollhouse','movie',1996,'https://image.tmdb.org/t/p/w500/fsMMOVto87pvUQyozOF9CaT9aMR.jpg','https://image.tmdb.org/t/p/original/cmD7smdQnflmpthFDjSArI2jKZF.jpg','An unattractive 7th grader struggles to cope with suburban life as the middle child with inattentive parents and bullies at school.',NULL,NULL,4.2981,7.1,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(415,32646,'tt0114323',NULL,'Safe','Safe','movie',1995,'https://image.tmdb.org/t/p/w500/2O71QsBkbqdLqQdx2yuNpJ4pFPq.jpg','https://image.tmdb.org/t/p/original/p8O3WhMWumLrLp21BRW80kBND4d.jpg','Carol White, a Los Angeles housewife in the late 1980s, comes down with a debilitating illness with no clear diagnosis.',NULL,NULL,1.3471,7.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(416,270303,'tt3235888',NULL,'It Follows','It Follows','movie',2015,'https://image.tmdb.org/t/p/w500/iwnQ1JH1wdWrGYkgWySptJ5284A.jpg','https://image.tmdb.org/t/p/original/ikaRI4yMxKOje5SmOlAhOBUnicL.jpg','A young woman is followed by an unknown supernatural force after a sexual encounter.',NULL,NULL,22.3691,6.585,0,2.66050000000000039e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(417,331482,'tt3281548',NULL,'Little Women','Little Women','movie',2019,'https://image.tmdb.org/t/p/w500/yn5ihODtZ7ofn8pDYfxCmxh8AXI.jpg','https://image.tmdb.org/t/p/original/lqxxwTRk0l7CubY6JkJdhnwJEkn.jpg','Four sisters come of age in America in the aftermath of the Civil War.',NULL,NULL,9.2317,7.9,0,11.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(418,346364,'tt1396484',NULL,'It','It','movie',2017,'https://image.tmdb.org/t/p/w500/9E2y5Q7WlCVNEhP5GiVTjhEhx1o.jpg','https://image.tmdb.org/t/p/original/qVGpxnjrGlHaSTCqTQI6viBDSfp.jpg','In a small town in Maine, seven children known as The Losers Club come face to face with life problems, bullies and a monster that takes the shape of a clown called Pennywise.',NULL,NULL,9.9417,7.2,0,14.032,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(419,88640,'tt3829868',NULL,'Looking for Alaska','Looking for Alaska','tv',2019,'https://image.tmdb.org/t/p/w500/9Sf2xUDLU0gyJfwDvmXhIqIzgrj.jpg','https://image.tmdb.org/t/p/original/Ah7762FWHdQYHUnbCwAzPFHsgOs.jpg','Miles enrolls in a new boarding school seeking adventure. There, he befriends a group of quirky students led by the captivating and troubled Alaska. As they pull pranks and explore dark secrets, a night of celebration takes a tragic turn, forcing the group to grapple with loss and the complexities of growing up.',NULL,NULL,4.2578,7.9,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(420,235,'tt0092005',NULL,'Stand by Me','Stand by Me','movie',1986,'https://image.tmdb.org/t/p/w500/vz0w9BSehcqjDcJOjRaCk7fgJe7.jpg','https://image.tmdb.org/t/p/original/yjGllQUm28R4X9xD9T5xMszirgw.jpg','After learning that a boy their age has been accidentally killed near their rural homes, four boys decide to go see the body. Gordie, Vern, Chris, and Teddy encounter a mean junk man and a marsh full of leeches, but they also learn more about one another and their very different home lives. Just a lark at first, the boys'' adventure evolves into a defining event in their lives.',NULL,NULL,8.8564,7.8,0,1.7666249999999998e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(421,162215,'tt1894476',NULL,'How I Live Now','How I Live Now','movie',2013,'https://image.tmdb.org/t/p/w500/4drLEdRSIzKZOKLsM79kBvsuq18.jpg','https://image.tmdb.org/t/p/original/tCdypgid7Meg3qpmvquUA9qqLNH.jpg','An American girl, sent to the English countryside to stay with relatives, finds love and purpose while fighting for her survival as war envelops the world around her.',NULL,NULL,1.7018,6.617,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(422,5915,'tt0758758',NULL,'Into the Wild','Into the Wild','movie',2007,'https://image.tmdb.org/t/p/w500/jnLnLYP5pGDfri04gxtAqAvkHMw.jpg','https://image.tmdb.org/t/p/original/87tmTU1NSR5EUGTKsF5rhLwZtZc.jpg','After graduating from Emory University in 1992, top student and athlete Christopher McCandless abandons his possessions, gives his entire $24,000 savings account to charity, and hitchhikes to Alaska to live in the wilderness.',NULL,NULL,7.1482,7.795,0,9.40666666666666628e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(423,98631,'tt1900893',NULL,'Himizu','ヒミズ','movie',2012,'https://image.tmdb.org/t/p/w500/s6T399aAmPNQEK8Uf4MImlQdiil.jpg','https://image.tmdb.org/t/p/original/e0F2dA9PlyfH1i0paPZIKOb5Pjg.jpg','Two 14-year-olds from troubled, abusive homes come together sharing misery and pain. In the aftermath of an earthquake, the classmates learn how to survive while relying on one another for emotional and physical support.',NULL,NULL,1.5172,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(424,1443,'tt0159097',NULL,'The Virgin Suicides','The Virgin Suicides','movie',2000,'https://image.tmdb.org/t/p/w500/1NCQtXPQnaHRjOZVmktA9BSM35F.jpg','https://image.tmdb.org/t/p/original/6b6UpsOXmjO8mJKYsGTG9HW49CN.jpg','A group of male friends become obsessed with five mysterious sisters who are sheltered by their strict, religious parents.',NULL,NULL,5.3516,7.131,0,2.38293333333333343e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(425,1122618,'tt30319516',NULL,'Good One','Good One','movie',2024,'https://image.tmdb.org/t/p/w500/yesxQtWrG5vCrNsnG3TrXiOfpOZ.jpg','https://image.tmdb.org/t/p/original/13H7aiwQsiEDok54b1OFDTz7u1X.jpg','On a weekend backpacking trip in the Catskills, 17-year-old Sam contends with the competing egos of her father and his oldest friend.',NULL,NULL,1.4164,6.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(426,2268,'tt0385752',NULL,'The Golden Compass','The Golden Compass','movie',2007,'https://image.tmdb.org/t/p/w500/6DTH9poR8RAw859L6OuokT7z993.jpg','https://image.tmdb.org/t/p/original/qifYc5jT4CZxmLH9DfOlipioSPp.jpg','In a parallel universe, after overhearing a shocking secret, precocious orphan Lyra Belacqua trades her carefree existence roaming the halls of Jordan College for an otherworldly adventure in the far North, unaware that it''s part of her destiny.',NULL,NULL,5.1941,6.087,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(427,428078,'tt1571234',NULL,'Mortal Engines','Mortal Engines','movie',2018,'https://image.tmdb.org/t/p/w500/gLhYg9NIvIPKVRTtvzCWnp1qJWG.jpg','https://image.tmdb.org/t/p/original/rm2oMykm5nX6SzXFr7TGHkO6r8Z.jpg','Many thousands of years in the future, Earth’s cities roam the globe on huge wheels, devouring each other in a struggle for ever diminishing resources. On one of these massive traction cities, the old London, Tom Natsworthy has an unexpected encounter with a mysterious young woman from the wastelands who will change the course of his life forever.',NULL,NULL,6.6767,6.239,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(428,16577,'tt0375568',NULL,'Astro Boy','Astro Boy','movie',2009,'https://image.tmdb.org/t/p/w500/6AK3uOHaIbl6EDaytHYe4FinZMu.jpg','https://image.tmdb.org/t/p/original/t39jaNSYMVNecNPQSVVlW6I4opm.jpg','Set in the futuristic Metro City, Astro Boy (Atom) is a young robot with incredible powers created by a brilliant scientist in the image of the son he had lost. Unable to fulfill his creator''s expectations, Astro embarks on a journey in search of acceptance, experiencing betrayal and a netherworld of robot gladiators, before returning to save Metro City and reconcile with the father who rejected him.',NULL,NULL,3.5665,6.343,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(429,94605,'tt11126994',NULL,'Arcane','Arcane','tv',2021,'https://image.tmdb.org/t/p/w500/abf8tHznhSvl9BAElD2cQeRr7do.jpg','https://image.tmdb.org/t/p/original/q8eejQcg1bAqImEV8jh8RtBD4uH.jpg','Amid the stark discord of twin cities Piltover and Zaun, two sisters fight on rival sides of a war between magic technologies and clashing convictions.',NULL,NULL,29.4553,8.8,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(430,792307,'tt14230458',NULL,'Poor Things','Poor Things','movie',2023,'https://image.tmdb.org/t/p/w500/kCGlIMHnOm8JPXq3rXM6c5wMxcT.jpg','https://image.tmdb.org/t/p/original/zh6IdheEYinU4TPtorWsjx6qPQE.jpg','Brought back to life by an unorthodox scientist, a young woman runs off with a lawyer on a whirlwind adventure across the continents. Free from the prejudices of her times, she grows steadfast in her purpose to stand for equality and liberation.',NULL,NULL,8.6524,7.639,0,1.68828571428571443e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(431,68507,'tt5607976',NULL,'His Dark Materials','His Dark Materials','tv',2019,'https://image.tmdb.org/t/p/w500/g6tIKGc3f1H5QMz1dcgCwADKpZ7.jpg','https://image.tmdb.org/t/p/original/t8KjRqfOqNx14cHLwARjR08bjeb.jpg','Lyra is an orphan who lives in a parallel universe in which science, theology and magic are entwined. Her search for a kidnapped friend uncovers a sinister plot involving stolen children and turns into a quest to understand a mysterious phenomenon called Dust. She is later joined on her journey by Will, a boy who possesses a knife that can cut windows between worlds. As she learns the truth about her parents and her prophesied destiny, the two young people are caught up in a war against celestial powers that ranges across many worlds.',NULL,NULL,14.0554,7.818,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(432,83542,'tt1371111',NULL,'Cloud Atlas','Cloud Atlas','movie',2012,'https://image.tmdb.org/t/p/w500/8naVv2Xu3rWI5JKHz0vCujx6GaJ.jpg','https://image.tmdb.org/t/p/original/cHm1lWAok12vwnTHqzprbPTk49q.jpg','A set of six nested stories spanning time between the 19th century and a distant post-apocalyptic future. Cloud Atlas explores how the actions and consequences of individual lives impact one another throughout the past, the present and the future. Action, mystery and romance weave through the story as one soul is shaped from a killer into a hero and a single act of kindness ripples across centuries to inspire a revolution in the distant future.  Based on the award winning novel by David Mitchell. Directed by Tom Tykwer and the Wachowskis.',NULL,NULL,8.038,6.897,0,13.3925,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(433,19,'tt0017136',NULL,'Metropolis','Metropolis','movie',1927,'https://image.tmdb.org/t/p/w500/kr9wXRN23zLuWJIelahas1mtnYj.jpg','https://image.tmdb.org/t/p/original/eeMoFKxjjiCi6iep2GEZtSAMYIr.jpg','In a futuristic city sharply divided between the rich and the poor, the son of the city''s mastermind meets a prophet who predicts the coming of a savior to mediate their differences.',NULL,NULL,4.9931,8.1,0,1.16833333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(434,8884,'tt0893402',NULL,'Franklyn','Franklyn','movie',2008,'https://image.tmdb.org/t/p/w500/5yns10om8I19j4OHy1zoVRilAnw.jpg','https://image.tmdb.org/t/p/original/6hQgTpZVNHrLafE6IeSAoThQwkH.jpg','Set between the parallel worlds of contemporary London and the futuristic faith dominated metropolis of Meanwhile City, Franklyn weaves a tale of four souls, whose lives are intertwined by fate, romance and tragedy. As these worlds collide, a single bullet determines the destiny of these four characters.',NULL,NULL,1.6554,6.018,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(435,902,'tt0112682',NULL,'The City of Lost Children','La Cité des enfants perdus','movie',1995,'https://image.tmdb.org/t/p/w500/whwT3Q9JxbAYzEc3t7uYYcCbTMf.jpg','https://image.tmdb.org/t/p/original/f5ynCAQ1MuDgwoVyjouTw6UgK1l.jpg','A scientist in a surrealist society kidnaps children to steal their dreams, hoping that they slow his aging process.',NULL,NULL,2.585,7.248,0,17.60625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(436,89905,'tt9059760',NULL,'Normal People','Normal People','tv',2020,'https://image.tmdb.org/t/p/w500/c4mk4EQVIM11yd3W43DDdqDazDU.jpg','https://image.tmdb.org/t/p/original/w8rTBScgj2MON7eGN7raoU5qChJ.jpg','Marianne and Connell weave in and out of each other''s lives in this exploration of sex, power and the desire to love and be loved.',NULL,NULL,11.0261,8.122,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(437,67070,'tt5687612',NULL,'Fleabag','Fleabag','tv',2016,'https://image.tmdb.org/t/p/w500/27vEYsRKa3eAniwmoccOoluEXQ1.jpg','https://image.tmdb.org/t/p/original/hXdQ4MWsEOX6qg6VydKrLb3YJ4g.jpg','A portrait into the mind of a dry-witted, sexual, angry, porn-watching, grief-riddled woman, trying to make sense of the world. As she hurls herself headlong at modern living, Fleabag is thrown roughly up against the walls of contemporary London, with all its frenetic energy, late nights, and bright lights.',NULL,NULL,10.2982,8.3,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(438,240667,'tt16283804',NULL,'One Day','One Day','tv',2024,'https://image.tmdb.org/t/p/w500/smBWt8rHCCavV88C5gQVjh0NUFa.jpg','https://image.tmdb.org/t/p/original/4zP0CfrUBQFWMlWoB4p8aS4D4IA.jpg','After spending graduation night together, Emma and Dexter go their separate ways — but their lives remain intertwined.',NULL,NULL,6.3709,7.671,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(439,416477,'tt5462602',NULL,'The Big Sick','The Big Sick','movie',2017,'https://image.tmdb.org/t/p/w500/9fJTT8pBxxQsFILJHTtHhdYFr77.jpg','https://image.tmdb.org/t/p/original/fYI8WX2DquAHMqwh5mOMxc6RU5j.jpg','Pakistan-born comedian Kumail Nanjiani and grad student Emily Gardner fall in love but struggle as their cultures clash. When Emily contracts a mysterious illness, Kumail finds himself forced to face her feisty parents, his family''s expectations, and his true feelings.',NULL,NULL,2.5178,7.323,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(440,152601,'tt1798709',NULL,'Her','Her','movie',2013,'https://image.tmdb.org/t/p/w500/eCOtqtfvn7mxGl6nfmq4b1exJRc.jpg','https://image.tmdb.org/t/p/original/sPPsR9f4K0movWVQ99u4uMqFzEL.jpg','In the not so distant future, Theodore, a lonely writer, purchases a newly developed operating system designed to meet the user''s every need. To Theodore''s surprise, a romantic relationship develops between him and his operating system. This unconventional love story blends science fiction and romance in a sweet tale that explores the nature of love and the ways that technology isolates and connects us all.',NULL,NULL,8.3384,7.838,0,14.224,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(441,637053,'tt11618536',NULL,'Shithouse','Shithouse','movie',2020,'https://image.tmdb.org/t/p/w500/lyOajZgP8Iy3JdVgvaiBv9K5OMH.jpg','https://image.tmdb.org/t/p/original/4KajfHWJ190Qm6J1NR2qxFNntPb.jpg','Lonely college freshman Alex has closed himself off from his peers, who all appear to have this whole "college thing" figured out. But everything changes one night when Alex takes a leap and attends a party at Shithouse - a legendary party fraternity - where he forges a strong connection with Maggie.',NULL,NULL,0.8684,6.913,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(442,11036,'tt0332280',NULL,'The Notebook','The Notebook','movie',2004,'https://image.tmdb.org/t/p/w500/rNzQyW4f8B8cQeg7Dgj3n6eT5k9.jpg','https://image.tmdb.org/t/p/original/zdXnJqBaGFVtLoPNuMeKfEYUViZ.jpg','An epic love story centered around an older man who reads aloud to a woman with Alzheimer''s. From a faded notebook, the old man''s words bring to life the story about a couple who is separated by World War II, and is then passionately reunited, seven years later, after they have taken different paths.',NULL,NULL,22.1929,7.9,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(443,319,'tt0108399',NULL,'True Romance','True Romance','movie',1993,'https://image.tmdb.org/t/p/w500/39lXk6ud6KiJgGbbWI2PUKS7y2.jpg','https://image.tmdb.org/t/p/original/1Uh8yuXlFcMDpVHWZJidjanT06e.jpg','Clarence marries hooker Alabama, steals cocaine from her pimp, and tries to sell it in Hollywood, while the owners of the coke try to reclaim it.',NULL,NULL,6.0174,7.5,0,6.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(444,6977,'tt0477348',NULL,'No Country for Old Men','No Country for Old Men','movie',2007,'https://image.tmdb.org/t/p/w500/uB7RDZby43Wvu8SKGHHTwGyTDBX.jpg','https://image.tmdb.org/t/p/original/gddUsvfyySrM5k8B8wwJy2VRlBx.jpg','Llewelyn Moss stumbles upon dead bodies, $2 million and a hoard of heroin in a Texas desert, but methodical killer Anton Chigurh comes looking for it, with local sheriff Ed Tom Bell hot on his trail. The roles of prey and predator blur as the violent pursuit of money and justice collide.',NULL,NULL,18.0159,8.0,0,6.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(445,446021,'tt6628394',NULL,'Bad Times at the El Royale','Bad Times at the El Royale','movie',2018,'https://image.tmdb.org/t/p/w500/qExufIc4Rw0e4xdVZlhMdmEDGES.jpg','https://image.tmdb.org/t/p/original/gb3TVVZNNxVGNfS1NxGaiWZfwnW.jpg','Lake Tahoe, 1969. Seven strangers, each one with a secret to bury, meet at El Royale, a decadent motel with a dark past. In the course of a fateful night, everyone will have one last shot at redemption.',NULL,NULL,3.1108,6.844,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(446,680,'tt0110912',NULL,'Pulp Fiction','Pulp Fiction','movie',1994,'https://image.tmdb.org/t/p/w500/vQWk5YBFWF4bZaofAbv0tShwBvQ.jpg','https://image.tmdb.org/t/p/original/suaEOtk1N1sgg2MTM7oZd2cfVp3.jpg','A burger-loving hit man, his philosophical partner, a drug-addled gangster''s moll and a washed-up boxer converge in this sprawling, comedic crime caper. Their adventures unfurl in three stories that ingeniously trip back and forth in time.',NULL,NULL,38.4218,8.481,0,11.0175,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(447,2317,'tt0460091',NULL,'My Name Is Earl','My Name Is Earl','tv',2005,'https://image.tmdb.org/t/p/w500/57shLTTkHvhLUhyP1t0lNZPoAxD.jpg','https://image.tmdb.org/t/p/original/9dTbuwQy6WoVNy9hqBAuwR1MoUU.jpg','When petty criminal Earl Hickey wins the lottery, he sets off on a quest to repair his questionable karma.',NULL,NULL,24.4999,7.649,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(448,1541,'tt0103074',NULL,'Thelma & Louise','Thelma & Louise','movie',1991,'https://image.tmdb.org/t/p/w500/vbRAGLzbC75QfiKD1lKjmnQGuph.jpg','https://image.tmdb.org/t/p/original/eA15zhxnhQSg4k5MUbbTERIU23Z.jpg','Taking a break from their dreary lives, close friends Thelma and Louise embark on a short weekend trip that ends in unforeseen incriminating circumstances. As fugitives, both women rediscover the strength of their bond and their newfound resilience.',NULL,NULL,8.839,7.605,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(449,1700,'tt0100157',NULL,'Misery','Misery','movie',1990,'https://image.tmdb.org/t/p/w500/klPO5oh1LOxiPpdDXZo1ADgpKcw.jpg','https://image.tmdb.org/t/p/original/rUAn3Ul1tL7JXMjZ951UOI3F0UA.jpg','After an accident, acclaimed novelist Paul Sheldon is rescued by a nurse who claims to be his biggest fan.  Her obsession takes a dark turn when she holds him captive in her remote Colorado home and forces him to write back to life the popular literary character he killed off.',NULL,NULL,6.5386,7.754,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(450,2832,'tt0309698',NULL,'Identity','Identity','movie',2003,'https://image.tmdb.org/t/p/w500/sYgimsiBywqVwJI8H4sETke8m7v.jpg','https://image.tmdb.org/t/p/original/iiPBXynI88EgnpunHoUlBCnLpSE.jpg','Complete strangers stranded at a remote desert motel during a raging storm soon find themselves the target of a deranged murderer. As their numbers thin out, the travelers begin to turn on each other, as each tries to figure out who the killer is.',NULL,NULL,11.2626,7.187,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(451,451,'tt0113627',NULL,'Leaving Las Vegas','Leaving Las Vegas','movie',1995,'https://image.tmdb.org/t/p/w500/wTrFpGe3U65kXTldIUxuM2hmOAK.jpg','https://image.tmdb.org/t/p/original/uqYjy4MwB4vZScpUPGdINVaSeTd.jpg','Ben Sanderson, an alcoholic Hollywood screenwriter who lost everything because of his drinking, arrives in Las Vegas to drink himself to death. There, he meets and forms an uneasy friendship and non-interference pact with prostitute Sera.',NULL,NULL,3.5892,7.257,0,10.8925,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(452,539,'tt0054215',NULL,'Psycho','Psycho','movie',1960,'https://image.tmdb.org/t/p/w500/yz4QVqPx3h1hD1DfqqQkCq3rmxW.jpg','https://image.tmdb.org/t/p/original/mufF1aYvwdpKerhq5R1YrVcbJLY.jpg','When larcenous real estate clerk Marion Crane goes on the lam with a wad of cash and hopes of starting a new life, she ends up at the notorious Bates Motel, where manager Norman Bates cares for his housebound mother.',NULL,NULL,16.3227,8.412,0,6.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(453,41662,'tt0075612',NULL,'3 Women','3 Women','movie',1977,'https://image.tmdb.org/t/p/w500/uL5Yg8MEgHGXymTaJBYXn9g0xsH.jpg','https://image.tmdb.org/t/p/original/pTmMEIW2cyOkcSRkWTCDEbd5if0.jpg','Two co-workers, one a vain woman and the other an awkward teenager, share an increasingly bizarre relationship after becoming roommates.',NULL,NULL,3.133,7.1,0,11.5125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(454,395834,'tt5362988',NULL,'Wind River','Wind River','movie',2017,'https://image.tmdb.org/t/p/w500/pySivdR845Hom4u4T2WNkJxe6Ad.jpg','https://image.tmdb.org/t/p/original/zcbb4XArMpGSNUQUZTdemp2WOTs.jpg','An FBI agent teams with the town''s veteran game tracker to investigate a murder that occurred on a Native American reservation.',NULL,NULL,7.5625,7.438,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(455,1933,'tt0230600',NULL,'The Others','The Others','movie',2001,'https://image.tmdb.org/t/p/w500/p8g1vlTvpM6nr2hMMiZ1fUlKF0D.jpg','https://image.tmdb.org/t/p/original/rbBe9WQ1OqCxzgwskOTnaY6JdUA.jpg','Grace is a woman who lives in an old house kept dark because her two children, Anne and Nicholas, have a rare sensitivity to light. When the family begins to suspect the house is haunted, Grace fights to protect her children at any cost in the face of strange events and disturbing visions.',NULL,NULL,10.9508,7.618,0,1.82311111111111117e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(456,503919,'tt7984734',NULL,'The Lighthouse','The Lighthouse','movie',2019,'https://image.tmdb.org/t/p/w500/yAKNmpcUweGH6WMCEWenwU9PsbE.jpg','https://image.tmdb.org/t/p/original/sYLzRuEcwSz0L1Z92wQNrETHU9O.jpg','Two lighthouse keepers try to maintain their sanity while living on a remote and mysterious New England island in the 1890s.',NULL,NULL,7.5387,7.468,0,1.48300000000000018e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(457,9428,'tt0265666',NULL,'The Royal Tenenbaums','The Royal Tenenbaums','movie',2001,'https://image.tmdb.org/t/p/w500/nG7hZJn7wQTSDCQT39Gy3s3tbrp.jpg','https://image.tmdb.org/t/p/original/cbuX448RKetr5Y5cZkmJEfu3xji.jpg','Royal Tenenbaum and his wife Etheline had three children and then they separated. All three children are extraordinary --- all geniuses. Virtually all memory of the brilliance of the young Tenenbaums was subsequently erased by two decades of betrayal, failure, and disaster. Most of this was generally considered to be their father''s fault. "The Royal Tenenbaums" is the story of the family''s sudden, unexpected reunion one recent winter.',NULL,NULL,4.7873,7.458,0,14.526,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(458,1581,'tt0457939',NULL,'The Holiday','The Holiday','movie',2006,'https://image.tmdb.org/t/p/w500/h1ITOpvJN3Tw4Sy60w2QTfYMvdd.jpg','https://image.tmdb.org/t/p/original/9Ebn8atCcGk5OZrx4xmoTobAxoh.jpg','Two women, one American and one British, swap homes at Christmastime following bad breakups. Each woman finds romance with a local man but realizes that the imminent return home may end the relationship.',NULL,NULL,7.334,7.102,0,12.19,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(459,1180428,'tt31968800',NULL,'Skuld','Skuld – For the Love of Cod','movie',2023,'https://image.tmdb.org/t/p/w500/6BUQHHE6228Sm5jlF6HgyLkcF6C.jpg','https://image.tmdb.org/t/p/original/5Kx4SXBgGnzwd5LPdLNqp6arOGY.jpg','A young couple risks their financial situation and relationship, when they follow in the footsteps of their ancestors and start working as independent fishermen on their small fishing boat, Skuld. Does Iceland''s oldest industry have a future or will it disappear with the coming generation?',NULL,NULL,0.1058,0.0,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(460,9397,'tt0251075',NULL,'Evolution','Evolution','movie',2001,'https://image.tmdb.org/t/p/w500/dwIrP544LxJtXToLpzkEa08pIMm.jpg','https://image.tmdb.org/t/p/original/uQVXQ7VI0jbLDo5QwGGyLQUd1so.jpg','A comedy that follows the chaos that ensues when a meteor hits the Earth carrying alien life forms that give new meaning to the term "survival of the fittest." David Duchovny, Orlando Jones, Seann William Scott, and Julianne Moore are the only people standing between the aliens and world domination... which could be bad news for the Earth.',NULL,NULL,5.9983,6.117,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(461,21119,NULL,NULL,'Most Haunted: Midsummer Murders','Most Haunted: Midsummer Murders','tv',2007,NULL,NULL,'Most Haunted: Midsummer Murders is a spin-off series of the paranormal television series, Most Haunted. It ran on Living TV between 19 June 2007 and 7 August 2007.',NULL,NULL,0.3706,0.0,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(462,300,'tt0354899',NULL,'The Science of Sleep','La Science des rêves','movie',2006,'https://image.tmdb.org/t/p/w500/8bummqwU6MV65ZJvNtKx8Y3NIEk.jpg','https://image.tmdb.org/t/p/original/bHePzkyRcMhnab2qZbhj1bCElnf.jpg','A man entranced by his dreams and imagination is lovestruck with a French woman and feels he can show her his world.',NULL,NULL,2.473,6.979,0,13.7625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(463,776561,'tt11398346',NULL,'Strawberry Mansion','Strawberry Mansion','movie',2021,'https://image.tmdb.org/t/p/w500/xJtBlQIJaioDugwl5ZQbgrMRSi5.jpg','https://image.tmdb.org/t/p/original/c872xfad1PmqdGOJOiOwUIw0Bln.jpg','In the not-too-distant future, an all-seeing surveillance state conducts “dream audits” to collect taxes on the unconscious lives of the populace. Mild-mannered government agent James Preble travels to a remote farmhouse to audit the dreams of Arabella “Bella” Isadora, an eccentric, aging artist. Entering Bella’s vast VHS archive, which contains a lifetime of dreams, Preble stumbles upon a secret that offers him a chance at love—and hope for escape.',NULL,NULL,1.1825,6.761,0,14.416,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(464,61174,'tt4163486',NULL,'Bee and PuppyCat','Bee and PuppyCat','tv',2014,'https://image.tmdb.org/t/p/w500/2qwIq9Dqceine5TPwf50iQdqL3G.jpg','https://image.tmdb.org/t/p/original/6832R2aNwWv2PofPjMxFTTHXU3z.jpg','On a charming magical island, the impulsive Bee and her furry pal get up to all sorts of adventures while working for an intergalactic temp agency.',NULL,NULL,4.4499,8.223,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(465,309809,'tt1754656',NULL,'The Little Prince','The Little Prince','movie',2015,'https://image.tmdb.org/t/p/w500/je5Z7gbFTzrs3FPHINo9yGiHoVo.jpg','https://image.tmdb.org/t/p/original/ackk6QMSECnqWC2H73lKXs8J5iY.jpg','Based on the best-seller book ''The Little Prince'', the movie tells the story of a little girl that lives with resignation in a world where efficiency and work are the only dogmas. Everything will change when accidentally she discovers her neighbor that will tell her about the story of the Little Prince that he once met.',NULL,NULL,4.7484,7.615,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(466,483,'tt0100935',NULL,'Wild at Heart','Wild at Heart','movie',1990,'https://image.tmdb.org/t/p/w500/uLUFI5sJIfWrBUWB2Y1dEuyvvVy.jpg','https://image.tmdb.org/t/p/original/6xJ2odkMFmO2LptVUBR8t8wBldQ.jpg','Young lovers Sailor and Lula hit the road to start a new life together away from the wrath of Lula’s deranged, disapproving mother, who has hired a team of hitmen to cut the lovers’ surreal honeymoon short.',NULL,NULL,4.8832,7.038,0,14.0125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(467,432606,'tt6381052',NULL,'Sleep Has Her House','Sleep Has Her House','movie',2017,'https://image.tmdb.org/t/p/w500/xIFdTSIe3KVb2rxgBwfaWNdrFwx.jpg','https://image.tmdb.org/t/p/original/1ZnVWcwNScrznz9GPHiVMdckyGC.jpg','The shadows of screams climb beyond the hills.  It has happened before. But this will be the last time.  The last few sense it, withdrawing deep into the forest.  They cry out into the black, as the shadows pass away, into the ground.',NULL,NULL,0.8421,6.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(468,638,'tt0116922',NULL,'Lost Highway','Lost Highway','movie',1997,'https://image.tmdb.org/t/p/w500/5POhfNeFPIi4VUNwCTaK85sh98r.jpg','https://image.tmdb.org/t/p/original/hGnJhGSeyWlerHcLNnD06sbX5wU.jpg','A tormented jazz musician finds himself lost in an enigmatic story involving murder, surveillance, gangsters, doppelgängers, and an impossible transformation inside a prison cell.',NULL,NULL,6.2502,7.5,0,13.66,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(469,1730,'tt0460829',NULL,'Inland Empire','Inland Empire','movie',2006,'https://image.tmdb.org/t/p/w500/s5f0FbVAABEnJYKaApWORTxhiFC.jpg','https://image.tmdb.org/t/p/original/qyePa65qZVnuYWivTBXkHV9aI3A.jpg','When actress Nikki Grace gets the lead role in a cursed film, her world becomes more and more surreal, blending realities and ideas of infidelity, reincarnation, and supernatural forces.',NULL,NULL,3.4803,6.996,0,2.09966666666666696e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(470,493922,'tt7784604',NULL,'Hereditary','Hereditary','movie',2018,'https://image.tmdb.org/t/p/w500/4GFPuL14eXi66V96xBWY73Y9PfR.jpg','https://image.tmdb.org/t/p/original/gJbTXKNTL6O7r7PzF6ZRkJGBlPp.jpg','Following the death of the Leigh family matriarch, Annie and her children uncover disturbing secrets about their heritage. Their daily lives are not only impacted, but they also become entangled in a chilling fate from which they cannot escape, driving them to the brink of madness.',NULL,NULL,13.283,7.297,0,1.43433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(471,744746,'tt7917178',NULL,'Caveat','Caveat','movie',2021,'https://image.tmdb.org/t/p/w500/nbug05AceVU8PMXIONDFxMRtq54.jpg','https://image.tmdb.org/t/p/original/6RVsEZGdDpwZhZkaptSgF7AznHF.jpg','A lone drifter suffering from partial memory loss accepts a job to look after a psychologically troubled woman in an abandoned house on an isolated island.',NULL,NULL,4.1905,6.343,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(472,242224,'tt2321549',NULL,'The Babadook','The Babadook','movie',2014,'https://image.tmdb.org/t/p/w500/qt3fqapeo94TfvMyld8P7gkpXLz.jpg','https://image.tmdb.org/t/p/original/t18ocAG0cpgC1AP288SseqmXqB5.jpg','A grieving single mother and her child fall into a deep well of paranoia when an eerie children''s book manifests in their home.',NULL,NULL,5.2313,6.538,0,1.67428571428571402e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(473,9392,'tt0435625',NULL,'The Descent','The Descent','movie',2005,'https://image.tmdb.org/t/p/w500/mxFPI4KYBk5ri9cPteIS8jiDFgj.jpg','https://image.tmdb.org/t/p/original/9T5D5RGuCsC6CeqYZJTv4rT4RPy.jpg','After a personal tragedy, Sarah joins her friends on a caving expedition in the Appalachian Mountains. But when a rockfall traps them deep underground, their adventure turns into a nightmare. As they search for a way out, the group discovers they are not alone—lurking in the darkness are savage, cave-dwelling creatures. With rising tension and dwindling trust, the women must fight to survive against both the predators and each other.',NULL,NULL,9.424,6.985,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(474,1591126,'tt39086931',NULL,'Portrait of God','Portrait of God','movie',NULL,'https://image.tmdb.org/t/p/w500/8KFZwwIoh5zoMl1WxEXWhYlp53Y.jpg','https://image.tmdb.org/t/p/original/wg4KFiTdGSwdCVU6EaThmO7d7XX.jpg','A religious girl must come to terms with her faith when she analyzes a provocative painting of God.',NULL,NULL,1.2378,0.0,0,1.2509999999999998e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(475,533842,'tt12616338',NULL,'Kairo','Kairo','movie',2018,'https://image.tmdb.org/t/p/w500/m6vvYfHSwIQlo7y20gkdWPJHlwW.jpg',NULL,'In a school on the outskirts of São Paulo, social worker Sônia needs to remove nine-year-old Kairo from the classroom to have a difficult conversation.',NULL,NULL,0.8725,0.0,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(476,1173559,'tt26349732',NULL,'Insidious Inferno','Insidious Inferno','movie',2024,'https://image.tmdb.org/t/p/w500/8kljUAovBatZRYp2ye2RZr239hU.jpg','https://image.tmdb.org/t/p/original/8HbNKB2pMiD3mfLgbxe7DgAKjdS.jpg','A secluded cottage is plagued by gruesome murders and unbeknownst to the inhabitants something other worldly lurks within the halls. Can the couple solve the mystery of the cursed grounds in time or will they open the door to the inferno?',NULL,NULL,8.9662,5.333,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(477,326446,'tt3899154',NULL,'Savageland','Savageland','movie',2015,'https://image.tmdb.org/t/p/w500/4PqEA3ECcNgvH1l3LllE9TIaACy.jpg','https://image.tmdb.org/t/p/original/FtrwfLziRMeZMMyUEquHs81JMV.jpg','When a small town near the Arizona-Mexico border is wiped out overnight, suspicion falls on the lone survivor. But a roll of photos the survivor took that night tells a different story.',NULL,NULL,0.7822,6.615,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(478,748230,'tt10245072',NULL,'Salem''s Lot','Salem''s Lot','movie',2024,'https://image.tmdb.org/t/p/w500/wkx5cdXVo6G8UEeNibthKIZEY3Y.jpg','https://image.tmdb.org/t/p/original/jf1V00dZdNkVfEq7VPk8frrlELk.jpg','Author Ben Mears returns to his childhood home of Jerusalem''s Lot only to discover his hometown is being preyed upon by a bloodthirsty vampire.',NULL,NULL,2.531,5.996,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(479,516632,'tt5867314',NULL,'The Empty Man','The Empty Man','movie',2020,'https://image.tmdb.org/t/p/w500/8apzu9JFTUMtOpYkHk6LNPOs3pY.jpg','https://image.tmdb.org/t/p/original/hwpbTeZEaKKUfiUjc2FJZpv7uAI.jpg','On the trail of a missing girl, an ex-cop comes across a secretive group attempting to summon a terrifying supernatural entity.',NULL,NULL,4.5927,6.16,0,1.59457142857142848e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(480,354251,'tt4935334',NULL,'Southbound','Southbound','movie',2015,'https://image.tmdb.org/t/p/w500/ehXtB1jlMx8FBlsX9JLhSQkvlZp.jpg','https://image.tmdb.org/t/p/original/4lYkJp44zjCCQFSOL99tff6zoA3.jpg','The film contains five stories set on desolate stretches of a desert highway. Two men on the run from their past, a band on its way to a gig, a man struggling to get home, a brother in search of his long-lost sister and a family on vacation are forced to confront their worst fears and darkest secrets in these interwoven tales.',NULL,NULL,4.496,5.927,0,10.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(481,753453,'tt14867006',NULL,'V/H/S/94','V/H/S/94','movie',2021,'https://image.tmdb.org/t/p/w500/9fSogEkqDfJQTuGHsTFloQz3Tw8.jpg','https://image.tmdb.org/t/p/original/uWbP41poWgP0f7sgAQTf6UeRtwg.jpg','After the discovery of a mysterious VHS tape, a brutish police SWAT team launches a high-intensity raid on a remote warehouse, only to discover a sinister cult compound whose collection of pre-recorded material uncovers a nightmarish conspiracy.',NULL,NULL,3.7493,6.12,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(482,882598,'tt15474916',NULL,'Smile','Smile','movie',2022,'https://image.tmdb.org/t/p/w500/aPqcQwu4VGEewPhagWNncDbJ9Xp.jpg','https://image.tmdb.org/t/p/original/kMZIMqEXO5MFd5Y1Ha2jZZF4pvF.jpg','After witnessing a bizarre, traumatic incident involving a patient, Dr. Rose Cotter starts experiencing frightening occurrences that she can''t explain.',NULL,NULL,8.6587,6.672,0,10.775,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(483,1022787,'tt4900148',NULL,'Elio','Elio','movie',2025,'https://image.tmdb.org/t/p/w500/7z8jDiTZZco9moIKpTUImFtTy7o.jpg','https://image.tmdb.org/t/p/original/ukPu5xYOBAnh5H46uK4aQOirW2b.jpg','Elio, a space fanatic with an active imagination, finds himself on a cosmic misadventure where he must form new bonds with eccentric alien lifeforms, navigate a crisis of intergalactic proportions and somehow discover who he is truly meant to be.',NULL,NULL,14.9951,6.906,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(484,5876,'tt0884328',NULL,'The Mist','The Mist','movie',2007,'https://image.tmdb.org/t/p/w500/1CvJ6diBACKPVGOpcWuY4XPQdqX.jpg','https://image.tmdb.org/t/p/original/76J14zgwVWyOciri7X7F3DGP3TA.jpg','After a violent storm, a dense cloud of mist envelops a small Maine town, trapping David Drayton and his five-year-old son in a local grocery store with other local residents. They soon discover that the mist conceals deadly horrors that threaten their lives, and worse, their sanity.',NULL,NULL,9.9476,6.948,0,1.69037500000000022e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(485,1454234,NULL,NULL,'The Color Out Of Space','The Color Out Of Space','movie',2024,NULL,NULL,'A surreal stop-motion adaptation of H. P. Lovecraft''s story of an impossible alien color infecting a farm in rural Massachusetts, edited in a rough and psychedelic style reflecting the decay from a radioactive and addictive force.',NULL,NULL,0.0439,0.0,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(486,339964,'tt2239822',NULL,'Valerian and the City of a Thousand Planets','Valerian and the City of a Thousand Planets','movie',2017,'https://image.tmdb.org/t/p/w500/vlc95gl3PtrjxSEuM8RhTtSm2xU.jpg','https://image.tmdb.org/t/p/original/5rYnygKCkmqWuMv1O5yAnzGF8gV.jpg','In the 28th century, Valerian and Laureline are special operatives charged with keeping order throughout the human territories. On assignment from the Minister of Defense, the two undertake a mission to Alpha, an ever-expanding metropolis where species from across the universe have converged over centuries to share knowledge, intelligence, and cultures. At the center of Alpha is a mysterious dark force which threatens the peaceful existence of the City of a Thousand Planets, and Valerian and Laureline must race to identify the menace and safeguard not just Alpha, but the future of the universe.',NULL,NULL,7.9285,6.65,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(487,19995,'tt0499549',NULL,'Avatar','Avatar','movie',2009,'https://image.tmdb.org/t/p/w500/gKY6q7SjCkAU6FqvqWybDYgUKIF.jpg','https://image.tmdb.org/t/p/original/vL5LR6WdxWPjLPFRLe133jXWsh5.jpg','In the 22nd century, a paraplegic Marine is dispatched to the moon Pandora on a unique mission, but becomes torn between following orders and protecting an alien civilization.',NULL,NULL,36.0047,7.609,0,1.13466666666666675e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(488,12,'tt0266543',NULL,'Finding Nemo','Finding Nemo','movie',2003,'https://image.tmdb.org/t/p/w500/5lc6nQc0VhWFYFbNv016xze8Jvy.jpg','https://image.tmdb.org/t/p/original/eCynaAOgYYiw5yN5lBwz3IxqvaW.jpg','Nemo, an adventurous young clownfish, is unexpectedly taken from his Great Barrier Reef home to a dentist''s office aquarium. It''s up to his worrisome father Marlin and a friendly but forgetful fish Dory to bring Nemo home -- meeting vegetarian sharks, surfer dude turtles, hypnotic jellyfish, hungry seagulls, and more along the way.',NULL,NULL,24.2263,7.82,0,1.23433333333333319e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(489,223485,'tt3205376',NULL,'Slow West','Slow West','movie',2015,'https://image.tmdb.org/t/p/w500/j3PmbRZvf5KpNbapSjn8b0CpD6a.jpg','https://image.tmdb.org/t/p/original/HQES024QzKwPBO8YcKPCrgbF3Z.jpg','In the Old West, a 17-year-old Scottish boy teams up with a mysterious gunman to find the woman with whom he is infatuated.',NULL,NULL,1.5938,6.69,0,6.4075,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(490,44264,'tt1403865',NULL,'True Grit','True Grit','movie',2010,'https://image.tmdb.org/t/p/w500/tCrB8pcjadZjsDk7rleGJaIv78k.jpg','https://image.tmdb.org/t/p/original/5dwlH8Krm2bsuc2Pubw2cBb03g5.jpg','Following the murder of her father by a hired hand, a 14-year-old farm girl sets out to capture the killer. To aid her, she hires the toughest U.S. Marshal she can find—a man with ''true grit''—Reuben J. ''Rooster'' Cogburn.',NULL,NULL,5.435,7.307,0,2.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(491,3114,'tt0049730',NULL,'The Searchers','The Searchers','movie',1956,'https://image.tmdb.org/t/p/w500/jLBmgW0epNzJ1N9uzaVCjbyT94v.jpg','https://image.tmdb.org/t/p/original/fik1HN9kxpD4CtEOXA4WUruwsg1.jpg','As a Civil War veteran spends years searching for a young niece captured by Indians, his motivation becomes increasingly questionable.',NULL,NULL,6.603,7.69,0,5.036,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(492,3089,'tt0040724',NULL,'Red River','Red River','movie',1948,'https://image.tmdb.org/t/p/w500/jyNTsAzrIWB441OtvfbgKtx1kFS.jpg','https://image.tmdb.org/t/p/original/agUD7Wp6LAwpaB3phx6yiRmFoSY.jpg','Following the Civil War, headstrong rancher Thomas Dunson decides to lead a perilous cattle drive from Texas to Missouri. During the exhausting journey, his persistence becomes tyrannical in the eyes of Matthew Garth, his adopted son and protégé.',NULL,NULL,2.7099,7.347,0,1.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(493,142,'tt0388795',NULL,'Brokeback Mountain','Brokeback Mountain','movie',2005,'https://image.tmdb.org/t/p/w500/aByfQOQBNa4CMFwIgq3QrqY2ZHh.jpg','https://image.tmdb.org/t/p/original/vXzqV2RtJlT9WhNEM4NYWCEC6ZI.jpg','In 1960s Wyoming, two men develop a strong emotional and sexual relationship that endures as a lifelong connection complicating their lives as they get married and start families of their own.',NULL,NULL,10.1414,7.785,0,6.37666666666666692e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(494,21355,'tt0149624',NULL,'All the Pretty Horses','All the Pretty Horses','movie',2000,'https://image.tmdb.org/t/p/w500/6E4E7wYXw1DE2321F2hVNryLSk7.jpg','https://image.tmdb.org/t/p/original/7U6WJ0qri2sACtcGa0wEpM9eAM1.jpg','The year is 1949. A young Texan named John Grady finds himself without a home after his mother sells the ranch where he has spent his entire life. Lured south of the border by the romance of cowboy life and the promise of a fresh start, Cole and his pal embark on an adventure that will test their resilience, define their maturity, and change their lives forever.',NULL,NULL,2.1517,5.723,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(495,33,'tt0105695',NULL,'Unforgiven','Unforgiven','movie',1992,'https://image.tmdb.org/t/p/w500/54roTwbX9fltg85zjsmrooXAs12.jpg','https://image.tmdb.org/t/p/original/rvRGFevvZK48onX0PYI1eQLbuJd.jpg','William Munny is a retired, once-ruthless killer turned gentle widower and hog farmer. To help support his two motherless children, he accepts one last bounty-hunter mission to find the men who brutalized a prostitute. Joined by his former partner and a cocky greenhorn, he takes on a corrupt sheriff.',NULL,NULL,9.2619,7.9,0,4.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(496,2055,'tt0316356',NULL,'Open Range','Open Range','movie',2003,'https://image.tmdb.org/t/p/w500/1mrNc88NrUEGtMtat4FD7sfpFrW.jpg','https://image.tmdb.org/t/p/original/e65E7jH5bKMSgHJnWLw4ex02Dyu.jpg','A former gunslinger is forced to take up arms again when he and his cattle crew are threatened by a corrupt lawman.',NULL,NULL,3.3431,7.222,0,4.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(497,3175,'tt0072684',NULL,'Barry Lyndon','Barry Lyndon','movie',1975,'https://image.tmdb.org/t/p/w500/znfLskGQnXYB2xcOGM9eInRHPAV.jpg','https://image.tmdb.org/t/p/original/ef6SvWbSfCFlKodJZqpIaTvsRRP.jpg','An Irish rogue uses his cunning and wit to work his way up the social classes of 18th century England, transforming himself from the humble Redmond Barry into the noble Barry Lyndon.',NULL,NULL,5.9192,7.994,0,6.52999999999999936e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(498,581,'tt0099348',NULL,'Dances with Wolves','Dances with Wolves','movie',1990,'https://image.tmdb.org/t/p/w500/hw0ZEHAaTqTxSXGVwUFX7uvanSA.jpg','https://image.tmdb.org/t/p/original/ywWva4trKw7f3wtbz81Fe3FnrtC.jpg','Wounded Civil War soldier John Dunbar tries to commit suicide—and becomes a hero instead. As a reward, he''s assigned to his dream post, a remote junction on the Western frontier, and soon makes unlikely friends with the local Sioux tribe.',NULL,NULL,7.8046,7.847,0,6.17666666666666586e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(499,642,'tt0064115',NULL,'Butch Cassidy and the Sundance Kid','Butch Cassidy and the Sundance Kid','movie',1969,'https://image.tmdb.org/t/p/w500/gFmmykF1Ym3OGzENo50nZQaD1dx.jpg','https://image.tmdb.org/t/p/original/C6jcUqld8M6hZQmzBxgwHuQ4qT.jpg','As the west rapidly becomes civilized, a pair of outlaws in 1890s Wyoming find themselves pursued by a posse and decide to flee to South America in hopes of evading the law.',NULL,NULL,4.5677,7.6,0,2.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(500,384680,'tt5478478',NULL,'Hostiles','Hostiles','movie',2017,'https://image.tmdb.org/t/p/w500/rqoezyB51GfhiloOB5ZErg5HXas.jpg','https://image.tmdb.org/t/p/original/vBSsIyWExRpe3Robi8SAnayrMq1.jpg','A legendary Native American-hating Army captain nearing retirement in 1892 is given one last assignment: to escort a Cheyenne chief and his family through dangerous territory back to his Montana reservation.',NULL,NULL,3.6392,6.943,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(501,1406,'tt0101587',NULL,'City Slickers','City Slickers','movie',1991,'https://image.tmdb.org/t/p/w500/9DVZpm9pQNB3M17cRo752zqUYhL.jpg','https://image.tmdb.org/t/p/original/6aavXoygR0nZP4kIKQLdaXLO3z0.jpg','Three New York businessmen decide to take a "Wild West" vacation that turns out not to be the relaxing vacation they had envisioned.',NULL,NULL,4.8165,6.469,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(502,16331,'tt0171410',NULL,'The Jack Bull','The Jack Bull','movie',1999,'https://image.tmdb.org/t/p/w500/yPbvb9cHQxcg9GzXG8DCb0yMSJI.jpg','https://image.tmdb.org/t/p/original/yn1XpVtDpENvJ2qWD7E2istIgjM.jpg','When the law fails to punish a fellow rancher that has abused his horses, a Wyoming horse trader sacrifices it all in a quest for justice.',NULL,NULL,1.6888,6.432,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(503,11897,'tt0056085',NULL,'How the West Was Won','How the West Was Won','movie',1962,'https://image.tmdb.org/t/p/w500/rmwc89VMQR4rUSDfakd0Z6GyF6q.jpg','https://image.tmdb.org/t/p/original/4hK1fDFO2u4MmvMK2isOAzyweTL.jpg','The epic tale of the development of the American West from the 1830s through the Civil War to the end of the century, as seen through the eyes of one pioneer family.',NULL,NULL,3.544,6.991,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(504,14729,'tt0081071',NULL,'The Long Riders','The Long Riders','movie',1980,'https://image.tmdb.org/t/p/w500/1Dk9dieSkZeiEVarZFsPJdF9Qel.jpg','https://image.tmdb.org/t/p/original/hFidONuvMRoWdpgsysBRknXU74J.jpg','The origins, exploits and the ultimate fate of the James gang is told in a sympathetic portrayal of the bank robbers made up of brothers who begin their legendary bank raids because of revenge.',NULL,NULL,2.286,6.656,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(505,4476,'tt0110322',NULL,'Legends of the Fall','Legends of the Fall','movie',1994,'https://image.tmdb.org/t/p/w500/t1KPGlW0UGd0m515LPQmk2F4nu1.jpg','https://image.tmdb.org/t/p/original/eVIuBKpeLB8rkozkj8bVmxDuAsp.jpg','In early 20th-century Montana, Col. William Ludlow lives on a ranch in the wilderness with his sons, Alfred, Tristan, and Samuel. Eventually, the unconventional but close-knit family are bound by loyalty, tested by war, and torn apart by love, as told over the course of several decades in this epic saga.',NULL,NULL,7.0571,7.396,0,6.18666666666666653e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(506,537996,'tt6412452',NULL,'The Ballad of Buster Scruggs','The Ballad of Buster Scruggs','movie',2018,'https://image.tmdb.org/t/p/w500/voxl654m7p36y8FLu8oQD7dfwwK.jpg','https://image.tmdb.org/t/p/original/12RXkIWUXwOHXgAmlxJNIWRGrri.jpg','Vignettes weaving together the stories of six individuals in the old West at the end of the Civil War. Following the tales of a sharp-shooting songster, a wannabe bank robber, two weary traveling performers, a lone gold prospector, a woman traveling the West to an uncertain future, and a motley crew of strangers undertaking a carriage ride.',NULL,NULL,4.4786,7.134,0,6.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(507,468,'tt0102494',NULL,'My Own Private Idaho','My Own Private Idaho','movie',1991,'https://image.tmdb.org/t/p/w500/p9TF90Pb5yg2MNb2UztzyXktMm4.jpg','https://image.tmdb.org/t/p/original/stSaFz5CtMXwIj3r4MDjqxqWRot.jpg','In this loose adaptation of Shakespeare''s "Henry IV," Mike Waters is a hustler afflicted with narcolepsy. Scott Favor is the rebellious son of a mayor. Together, the two travel from Portland, Oregon to Idaho and finally to the coast of Italy in a quest to find Mike''s estranged mother. Along the way they turn tricks for money and drugs, eventually attracting the attention of a wealthy benefactor and sexual deviant.',NULL,NULL,3.6294,7.0,0,10.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(508,41692,'tt0096639',NULL,'Lonesome Dove','Lonesome Dove','tv',1989,'https://image.tmdb.org/t/p/w500/qK4iseZGf0YhYx53ecawSGhL0sl.jpg','https://image.tmdb.org/t/p/original/grThKpUYZ5nHppqAEvmF0pTSJa0.jpg','A pair of longtime friends and former Texas Rangers crave one last adventure before hanging-up their spurs. After stealing over a thousand head of cattle from rustlers south of the border, they recruit an unlikely crew of hands to drive the herd 3,000 miles north to the grasslands of Montana.',NULL,NULL,6.799,7.9,0,1.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(509,440161,'tt4971344',NULL,'The Sisters Brothers','The Sisters Brothers','movie',2018,'https://image.tmdb.org/t/p/w500/wTgomqYRTXT3BXQScnIo8uHDyWC.jpg','https://image.tmdb.org/t/p/original/2cI0rmMgoZOqP78iQDZwQASkKT3.jpg','Oregon, 1851. Hermann Kermit Warm, a chemist and aspiring gold prospector, keeps a profitable secret that the Commodore wants to know, so he sends the Sisters brothers, two notorious assassins, to capture him on his way to California.',NULL,NULL,2.1444,6.832,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(510,453278,'tt6217608',NULL,'The Rider','The Rider','movie',2018,'https://image.tmdb.org/t/p/w500/cFsrA0Is5xode2INrPj1VJcQ18n.jpg','https://image.tmdb.org/t/p/original/oaAyNmnqbB8Ad3O2t9iymZ2gEJa.jpg','Once a rising star of the rodeo circuit, and a gifted horse trainer, young cowboy Brady is warned that his riding days are over after a horse crushed his skull at a rodeo. In an attempt to regain control of his own fate, Brady undertakes a search for a new identity and what it means to be a man in the heartland of the United States.',NULL,NULL,1.237,7.26,0,2.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(511,9359,'tt0110478',NULL,'Maverick','Maverick','movie',1994,'https://image.tmdb.org/t/p/w500/mTVbGGi5PIexmxVzeyFd2RYKwfM.jpg','https://image.tmdb.org/t/p/original/ctzKCslTsMRsOJNvAm1Mw8ytiHY.jpg','Bret Maverick is a gambler who would rather con someone than fight them, and needs an additional $3k in order to enter a winner-takes-all poker game beginning in a few days. He joins forces with a woman with a marvelous Southern accent, and the two try and enter the game.',NULL,NULL,4.0365,6.902,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(512,9023,'tt0166813',NULL,'Spirit: Stallion of the Cimarron','Spirit: Stallion of the Cimarron','movie',2002,'https://image.tmdb.org/t/p/w500/cUgYrz4twiJ3QgVGpRfey984NIB.jpg','https://image.tmdb.org/t/p/original/b8hPBW0NJmiIVzvQjT3CwIpAdzl.jpg','A captured mustang remains determined to return to his herd no matter what.',NULL,NULL,8.141,7.704,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(513,600583,'tt10293406',NULL,'The Power of the Dog','The Power of the Dog','movie',2021,'https://image.tmdb.org/t/p/w500/kEy48iCzGnp0ao1cZbNeWR6yIhC.jpg','https://image.tmdb.org/t/p/original/gAsHuCQMN7mv4uFIvM4ACQ09hPr.jpg','A domineering but charismatic rancher wages a war of intimidation on his brother''s new wife and her teen son, until long-hidden secrets come to light.',NULL,NULL,3.8417,6.736,0,4.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(514,188161,'tt2557490',NULL,'A Million Ways to Die in the West','A Million Ways to Die in the West','movie',2014,'https://image.tmdb.org/t/p/w500/n9SicwnoNGWBwE75le27sUhCLMm.jpg','https://image.tmdb.org/t/p/original/5ZDM988DfYLFPBqy4CNvQ9AXnp4.jpg','As a cowardly farmer begins to fall for the mysterious new woman in town, he must put his new-found courage to the test when her husband, a notorious gun-slinger, announces his arrival.',NULL,NULL,4.6696,6.051,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(515,68718,'tt1853728',NULL,'Django Unchained','Django Unchained','movie',2012,'https://image.tmdb.org/t/p/w500/7oWY8VDWW7thTzWh3OKYRkWUlD5.jpg','https://image.tmdb.org/t/p/original/2oZklIzUbvZXXzIFzv7Hi68d6xf.jpg','With the help of a German bounty hunter, a freed slave sets out to rescue his wife from a brutal Mississippi plantation owner.',NULL,NULL,17.1302,8.2,0,2.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(516,734002,'tt10651230',NULL,'The Peasants','Chłopi','movie',2023,'https://image.tmdb.org/t/p/w500/8ATsQJx6SnG1EQgmbm3NNeUzwmw.jpg','https://image.tmdb.org/t/p/original/6U6F2OnHTLs1Pxk8ZVDCRbd3a76.jpg','Peasant girl Jagna is forced to marry the much older, wealthy farmer Boryna, despite her love for his son Antek. With time, Jagna becomes the object of envy and disdain with the villagers and she must fight to preserve her independence.',NULL,NULL,3.9149,7.512,0,7.7333333333333325e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(517,339877,'tt3262342',NULL,'Loving Vincent','Loving Vincent','movie',2017,'https://image.tmdb.org/t/p/w500/56sq57kDm7XgyXBYrgJLumo0Jac.jpg','https://image.tmdb.org/t/p/original/KKrsUGDXZfpeL3ddXTeGibmUHS.jpg','A young man arrives at the last hometown of painter Vincent van Gogh to deliver the troubled artist''s final letter and ends up investigating his final days there.',NULL,NULL,3.1565,7.985,0,10.616,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(518,832713,NULL,NULL,'Tales of the Bizarre: 2006 Fall Special','世にも奇妙な物語 ～2006秋の特別編～','movie',2006,'https://image.tmdb.org/t/p/w500/1rIVy1Xs71bHlT3GG1ZP2yQGD3a.jpg',NULL,'***Kyouko-san (Miss Kyouko) A young therapist at a hospital investigates when a spirit appears and kills people who say "Kyouko-san, Kyouko-san, please make me pretty" to the bathroom mirror.  ***Buchou OL (Manager-OL) [office lady] An OL and her boss switch bodies.  ***Kinou Kouen (Yesterday at the park) Domoto Koichi plays a man who loses his friend due to a freak accident. He then finds that through a time slip, he can return to the previous day and save his friend.  ***Neko ga Ongaeshi (Cat Repays a Favor) Kashiwagi Emi (Uchiyama Rina) is unable to get over her grandmother''s death. Her cat Kuro decides he will cure her loneliness.  ***Kazoku Kaigi (Family Meeting) A family of three meet with a car accident, but strangely wake up in their home the next morning. They are then told that they have to sacrifice one of them so two may live.',NULL,NULL,0.3846,0.0,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(519,5176,'tt0381849',NULL,'3:10 to Yuma','3:10 to Yuma','movie',2007,'https://image.tmdb.org/t/p/w500/voMB69AsLnPNmtfbrBl0lbeFKDH.jpg','https://image.tmdb.org/t/p/original/2eznGndOi8s9CGReAvcQ8PEULwm.jpg','In Arizona in the late 1800s, infamous outlaw Ben Wade and his vicious gang of thieves and murderers have plagued the Southern Railroad. When Wade is captured, Civil War veteran Dan Evans, struggling to survive on his drought-plagued ranch, volunteers to deliver him alive to the "3:10 to Yuma", a train that will take the killer to trial.',NULL,NULL,5.7001,7.23,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(520,73586,'tt4236770',NULL,'Yellowstone','Yellowstone','tv',2018,'https://image.tmdb.org/t/p/w500/vOYfRZ0NpUK5hG2CB2dJFnYJlGe.jpg','https://image.tmdb.org/t/p/original/ynSOcgDLZfdLCZfRSYZGiTgYJVo.jpg','Follow the violent world of the Dutton family, who controls the largest contiguous ranch in the United States. Led by their patriarch John Dutton, the family defends their property against constant attack by land developers, an Indian reservation, and America’s first National Park.',NULL,NULL,119.3545,8.266,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(521,9081,'tt0243017',NULL,'Waking Life','Waking Life','movie',2001,'https://image.tmdb.org/t/p/w500/2MRM4PL6H7yraAkwyUEe2EqoQH3.jpg','https://image.tmdb.org/t/p/original/56MLZww2dMVAaTt5LDKCBu1do2X.jpg','Waking Life is about a young man in a persistent lucid dream-like state. The film follows its protagonist as he initially observes and later participates in philosophical discussions that weave together issues like reality, free will, our relationships with others, and the meaning of life.',NULL,NULL,2.5028,7.472,0,9.02333333333333342e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(522,3509,'tt0405296',NULL,'A Scanner Darkly','A Scanner Darkly','movie',2006,'https://image.tmdb.org/t/p/w500/lUKudOpHICDj6A6SO7DdaZM4W48.jpg','https://image.tmdb.org/t/p/original/do8idarfaUTxxwaarefTNA724Qj.jpg','An undercover cop in a not-too-distant future becomes involved with a dangerous new drug and begins to lose his own identity as a result.',NULL,NULL,3.1971,6.805,0,13.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(523,99346,'tt11771270',NULL,'The English','The English','tv',2022,'https://image.tmdb.org/t/p/w500/aAFAwxj0VzBRyX5biAHUJM73qYG.jpg','https://image.tmdb.org/t/p/original/eenxjEAPwPbkjN6W5ZzTbfLA4GM.jpg','An aristocratic Englishwoman, Lady Cornelia Locke, arrives into the new and wild landscape of the American West to wreak revenge on the man she sees as responsible for the death of her son.',NULL,NULL,5.3679,7.252,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(524,NULL,NULL,25076,'Red Dead Redemption 2','Red Dead Redemption 2','game',2018,'https://images.igdb.com/igdb/image/upload/t_cover_big/co1q1f.jpg',NULL,'Red Dead Redemption 2 is the epic tale of outlaw Arthur Morgan and the infamous Van der Linde gang, on the run across America at the dawn of the modern age.','https://www.igdb.com/games/red-dead-redemption-2','["Google Stadia", "PlayStation 4", "PC (Microsoft Windows)", "Xbox One"]',NULL,NULL,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(525,301,'tt0053221',NULL,'Rio Bravo','Rio Bravo','movie',1959,'https://image.tmdb.org/t/p/w500/4gI4KKmoi0d3yfsF71YU3S0I5t8.jpg','https://image.tmdb.org/t/p/original/38uM6QuI06znUCELfOSiVQy05CX.jpg','A small-town sheriff in the American West enlists the help of a disabled man, a drunk, and a young gunfighter in his efforts to hold in jail the brother of the local bad guy.',NULL,NULL,3.9617,7.807,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(526,11509,'tt0090022',NULL,'Silverado','Silverado','movie',1985,'https://image.tmdb.org/t/p/w500/k6zurzegRKsNGMICXZ57VJDUzXO.jpg','https://image.tmdb.org/t/p/original/rPDcuFniW2yZrSRbLjeNdQy7P45.jpg','Four unwitting heroes cross paths on their journey to the sleepy town of Silverado. Little do they know the town where their family and friends reside has been taken over by a corrupt sheriff and a murderous posse. It''s up to the sharp-shooting foursome to save the day, but first they have to break each other out of jail, and learn who their real friends are.',NULL,NULL,2.7985,6.949,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(527,335,'tt0064116',NULL,'Once Upon a Time in the West','C''era una volta il West','movie',1968,'https://image.tmdb.org/t/p/w500/qbYgqOczabWNn2XKwgMtVrntD6P.jpg','https://image.tmdb.org/t/p/original/h31SOVlekuHXsMWVGxI8nPPfY82.jpg','As the railroad builders advance unstoppably through the Arizona desert on their way to the sea, Jill arrives in the small town of Flagstone with the intention of starting a new life.',NULL,NULL,14.4107,8.3,0,2.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(528,2289,'tt0159365',NULL,'Cold Mountain','Cold Mountain','movie',2003,'https://image.tmdb.org/t/p/w500/j0AJeeR5CQPDFh0otyWyCWREHO8.jpg','https://image.tmdb.org/t/p/original/xjJz025MAPrSeNj18LPjcyu4xFM.jpg','In this classic story of love and devotion set against the backdrop of the American Civil War, a wounded Confederate soldier named W.P. Inman deserts his unit and travels across the South, aiming to return to his young wife, Ada, who he left behind to tend their farm. As Inman makes his perilous journey home, Ada struggles to keep their home intact with the assistance of Ruby, a mysterious drifter sent to help her by a kindly neighbor.',NULL,NULL,4.4013,6.943,0,9.7333333333333325e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(529,42522,'tt0067204',NULL,'The Hired Hand','The Hired Hand','movie',1971,'https://image.tmdb.org/t/p/w500/qE1fgjbtQinQXvSA2ADnOj5SRdl.jpg','https://image.tmdb.org/t/p/original/wBdcrn5iBVpvZdpzkTfOBBbbuJc.jpg','Harry Collings returns home to his farm after drifting with his friend, Arch. His wife, who had given up on him, reluctantly allows him to stay, and soon believes that all will be well again. But then Harry has to make a difficult decision regarding his loyalties and priorities.',NULL,NULL,0.716,6.075,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(530,1936,'tt0047422',NULL,'River of No Return','River of No Return','movie',1954,'https://image.tmdb.org/t/p/w500/jXYjgPad6IIfZfCtzLuWTnJdijo.jpg','https://image.tmdb.org/t/p/original/mhvGp9LGViHQviOu86HW0Boo0kI.jpg','An itinerant farmer and his young son help a heart-of-gold saloon singer search for her estranged husband.',NULL,NULL,2.47,6.701,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(531,11536,'tt0055184',NULL,'The Misfits','The Misfits','movie',1961,'https://image.tmdb.org/t/p/w500/rkIkyPhT5oetT463HxpdIuct30l.jpg','https://image.tmdb.org/t/p/original/uCH6NY9qstOLbBTGv0rWxB1oJJH.jpg','While filing for a divorce, beautiful ex-stripper Roslyn Taber ends up meeting aging cowboy-turned-gambler Gay Langland and former World War II aviator Guido Racanelli. The two men instantly become infatuated with Roslyn and, on a whim, the three decide to move into Guido''s half-finished desert home together. When grizzled ex-rodeo rider Perce Howland arrives, the unlikely foursome strike up a business capturing wild horses.',NULL,NULL,3.3069,6.975,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(532,8413,'tt0119081',NULL,'Event Horizon','Event Horizon','movie',1997,'https://image.tmdb.org/t/p/w500/qfluaDXv0cIdLwgQWzNB2piHL2q.jpg','https://image.tmdb.org/t/p/original/nByMcYBhChTs2TF9fEFcTSsjme5.jpg','In 2047, a group of astronauts are sent to investigate and salvage the starship Event Horizon which disappeared mysteriously seven years before on its maiden voyage. However, it soon becomes evident that something sinister resides in its corridors.',NULL,NULL,11.8925,6.588,0,9.34333333333333371e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(533,333339,'tt1677720',NULL,'Ready Player One','Ready Player One','movie',2018,'https://image.tmdb.org/t/p/w500/pU1ULUq8D3iRxl1fdX2lZIzdHuI.jpg','https://image.tmdb.org/t/p/original/5a7lMDn3nAj2ByO0X1fg6BhUphR.jpg','When the creator of a popular video game system dies, a virtual contest is created to compete for his fortune.',NULL,NULL,15.5032,7.589,0,13.4025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(534,49049,'tt1343727',NULL,'Dredd','Dredd','movie',2012,'https://image.tmdb.org/t/p/w500/wLx65gtGVnUFCxceHWGszcruCZj.jpg','https://image.tmdb.org/t/p/original/jUqDBi02CDjqrroC3Zl8hroBbSr.jpg','In the future, America is a dystopian wasteland. The latest scourge is Ma-Ma, a prostitute-turned-drug pusher with a dangerous new drug and aims to take over the city. The only possibility of stopping her is an elite group of urban police called Judges, who combine the duties of judge, jury and executioner to deliver a brutal brand of swift justice. But even the top-ranking Judge, Dredd, discovers that taking down Ma-Ma isn’t as easy as it seems in this explosive adaptation of the hugely popular comic series.',NULL,NULL,6.4929,6.864,0,1.26933333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(535,68,'tt0088846',NULL,'Brazil','Brazil','movie',1985,'https://image.tmdb.org/t/p/w500/aewan59WcFThBimkTVVoNf2o5Vb.jpg','https://image.tmdb.org/t/p/original/9IYyCLf5NNAQFK9pNtqzEU9HWzM.jpg','Low-level bureaucrat Sam Lowry escapes the monotony of his day-to-day life through a recurring daydream of himself as a virtuous hero saving a beautiful damsel. Investigating a case that led to the wrongful arrest and eventual death of an innocent man instead of wanted terrorist Harry Tuttle, he meets the woman from his daydream, and in trying to help her gets caught in a web of mistaken identities, mindless bureaucracy and lies.',NULL,NULL,4.7882,7.7,0,19.725,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(536,945961,'tt18412256',NULL,'Alien: Romulus','Alien: Romulus','movie',2024,'https://image.tmdb.org/t/p/w500/b33nnKl1GSFbao4l3fZDDqsMx0F.jpg','https://image.tmdb.org/t/p/original/iYqSQaWDttQIQzsxg9xHyg0bttG.jpg','While scavenging the deep ends of a derelict space station, a group of young space colonizers come face to face with the most terrifying life form in the universe.',NULL,NULL,17.3561,7.2,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(537,696506,'tt12299608',NULL,'Mickey 17','Mickey 17','movie',2025,'https://image.tmdb.org/t/p/w500/edKpE9B5qN3e559OuMCLZdW1iBZ.jpg','https://image.tmdb.org/t/p/original/9PRKAdrDvAdCfg3EcApLTfzGsEt.jpg','Unlikely hero Mickey Barnes finds himself in the extraordinary circumstance of working for an employer who demands the ultimate commitment to the job… to die, for a living.',NULL,NULL,10.7694,6.839,0,13.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(538,9323,'tt0113568',NULL,'Ghost in the Shell','GHOST IN THE SHELL','movie',1995,'https://image.tmdb.org/t/p/w500/9gC88zYUBARRSThcG93MvW14sqx.jpg','https://image.tmdb.org/t/p/original/gTRXgigmgKpeJjW07iq686HZyBD.jpg','In the year 2029, the barriers of our world have been broken down by the net and by cybernetics, but this brings new vulnerability to humans in the form of brain-hacking. When a highly-wanted hacker known as ''The Puppetmaster'' begins involving them in politics, Section 9, a group of cybernetically enhanced cops, are called in to investigate and stop the Puppetmaster.',NULL,NULL,12.9358,7.926,0,1.49266666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(539,11299,'tt0275277',NULL,'Cowboy Bebop: The Movie','カウボーイビバップ 天国の扉','movie',2001,'https://image.tmdb.org/t/p/w500/34H5bsNc0EPILVr49TfOYXj50qV.jpg','https://image.tmdb.org/t/p/original/19EKawKy1Z7nUJMhQE28XBL6Guc.jpg','The year is 2071. Following a terrorist bombing, a deadly virus is released on the populace of Mars and the government has issued the largest bounty in history, for the capture of whoever is behind it. The bounty hunter crew of the spaceship Bebop; Spike, Faye, Jet and Ed, take the case with hopes of cashing in the bounty. However, the mystery surrounding the man responsible, Vincent, goes deeper than they ever imagined, and they aren''t the only ones hunting him.',NULL,NULL,3.123,7.727,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(540,1437,'tt0303461',NULL,'Firefly','Firefly','tv',2002,'https://image.tmdb.org/t/p/w500/vZcKsy4sGAvWMVqLluwYuoi11Kj.jpg','https://image.tmdb.org/t/p/original/te4VJNMipsFQofCkiytuyswGDlV.jpg','In the year 2517, the universe is a vast frontier where lawlessness reigns and adventure awaits! Join Captain Malcolm Reynolds and his ragtag crew aboard the spaceship Serenity as they navigate the fringes of society, battling the oppressive Alliance and facing off against ruthless bounty hunters.',NULL,NULL,12.9287,8.341,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(541,16320,'tt0379786',NULL,'Serenity','Serenity','movie',2005,'https://image.tmdb.org/t/p/w500/4sqUOaPFoP2W81mq1UYqZqf5WzA.jpg','https://image.tmdb.org/t/p/original/3aGsZdB5ud6LmU9lppwTLh2fqH1.jpg','A group of rebels travel the outskirts of space evading the sinister Alliance regime. Their lives of smuggling and cargo-running are interrupted by a psychic passenger who harbours a dangerous secret. Soon, the crew find themselves being pursued by an Alliance agent who will stop at nothing to find them.',NULL,NULL,5.3091,7.362,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(542,NULL,NULL,1877,'Cyberpunk 2077','Cyberpunk 2077','game',2020,'https://images.igdb.com/igdb/image/upload/t_cover_big/coaih8.jpg',NULL,'Cyberpunk 2077 is an open-world action-adventure game set in Night City, a sprawling metropolis driven by power, glamour, and body modification. Players assume the role of V, a mercenary outlaw in pursuit of a unique implant that holds the key to immortality. The game allows extensive customization of cyberware, skills, and playstyle. Choices made throughout the journey influence both the narrative and the world.','https://www.igdb.com/games/cyberpunk-2077','["Google Stadia", "Xbox Series X|S", "PlayStation 4", "Nintendo Switch 2", "PC (Microsoft Windows)", "PlayStation 5", "Mac", "Xbox One"]',NULL,NULL,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(543,198184,'tt1823672',NULL,'Chappie','Chappie','movie',2015,'https://image.tmdb.org/t/p/w500/uuDUpzlMFomdSfNWlpEPS9nVZWV.jpg','https://image.tmdb.org/t/p/original/3pKIcv6KhUE35jsKnv3MylQ3OT2.jpg','Every child comes into the world full of promise, and none more so than Chappie: he is gifted, special, a prodigy. Like any child, Chappie will come under the influence of his surroundings—some good, some bad—and he will rely on his heart and soul to find his way in the world and become his own man. But there''s one thing that makes Chappie different from any one else: he is a robot.',NULL,NULL,9.1613,6.791,0,12.2,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(544,1894,'tt0121765',NULL,'Star Wars: Episode II - Attack of the Clones','Star Wars: Episode II - Attack of the Clones','movie',2002,'https://image.tmdb.org/t/p/w500/oZNPzxqM2s5DyVWab09NTQScDQt.jpg','https://image.tmdb.org/t/p/original/abwxHfymXGAbbH3lo9PDEJEfvtW.jpg','Following an assassination attempt on Senator Padmé Amidala, Jedi Knights Anakin Skywalker and Obi-Wan Kenobi investigate a mysterious plot into the heart of the Separatist movement and the beginning of the Clone Wars.',NULL,NULL,8.6695,6.596,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(545,60554,'tt2930604',NULL,'Star Wars Rebels','Star Wars Rebels','tv',2014,'https://image.tmdb.org/t/p/w500/eLrScs6Bs26JMcS8hiZhf7YRROr.jpg','https://image.tmdb.org/t/p/original/8BNjxMJMFp0BgqMh4PyuwZMXxh1.jpg','Set between the events of Star Wars: Episodes III and IV, the story unfolds during a dark time when the evil Galactic Empire is tightening its grip of power on the galaxy. Imperial forces have occupied a remote planet and are ruining the lives of its people. The motley but clever crew of the starship Ghost — cowboy Jedi Kanan, ace pilot Hera, street-smart teenager Ezra, the “muscle” Zeb, warrior firebrand Sabine, and cantankerous old astromech droid Chopper — is among a select few who are brave enough to stand against the Empire. Together, they will face threatening new villains, encounter colorful adversaries, embark on thrilling adventures, and become heroes with the power to ignite a rebellion.',NULL,NULL,20.6557,7.725,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(546,17431,'tt1182345',NULL,'Moon','Moon','movie',2009,'https://image.tmdb.org/t/p/w500/35IU0Mq0zFsN1mYwDGts5mKc77n.jpg','https://image.tmdb.org/t/p/original/mvUAo9ACgmLpS4Ofc2IwD4n7WCt.jpg','With only three weeks left in his three-year contract, Sam Bell is eager to return to Earth. Stationed alone at a Moon-based facility with his computer assistant GERTY, an unexpected accident sets off a series of unsettling events that shake his isolation.',NULL,NULL,5.5923,7.563,0,1.52085714285714281e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(547,274870,'tt1355644',NULL,'Passengers','Passengers','movie',2016,'https://image.tmdb.org/t/p/w500/jK9S6HANSf2no64v1x1HxfcpmcA.jpg','https://image.tmdb.org/t/p/original/gHz4ZQytRs8YGrqFMwB3Vrr8pig.jpg','A spacecraft traveling to a distant colony planet and transporting thousands of people has a malfunction in its sleep chambers. As a result, two passengers are awakened 90 years early.',NULL,NULL,5.3624,6.956,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(548,6404,'tt0079641',NULL,'Nosferatu the Vampyre','Nosferatu - Phantom der Nacht','movie',1979,'https://image.tmdb.org/t/p/w500/jHKzGYwf7P34vz8MhJBTN6cnaYD.jpg','https://image.tmdb.org/t/p/original/uHudMff1vp2GDXqHD8QOA78QpNW.jpg','A real estate agent leaves behind his beautiful wife to go to Transylvania to visit the mysterious Count Dracula and formalize the purchase of a property in Wismar.',NULL,NULL,3.0844,7.284,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(549,310131,'tt4263482',NULL,'The Witch','The Witch','movie',2016,'https://image.tmdb.org/t/p/w500/zap5hpFCWSvdWSuPGAQyjUv2wAC.jpg','https://image.tmdb.org/t/p/original/zi2oYYNSSv7t44iSt5YrxHX9PYs.jpg','In 1630, a farmer relocates his family to a remote plot of land on the edge of a forest where strange, unsettling things happen. With suspicion and paranoia mounting, each family member''s faith, loyalty and love are tested in shocking ways.',NULL,NULL,8.5423,7.0,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(550,628,'tt0110148',NULL,'Interview with the Vampire','Interview with the Vampire','movie',1994,'https://image.tmdb.org/t/p/w500/2162lAT2MP36MyJd2sttmj5du5T.jpg','https://image.tmdb.org/t/p/original/3fChciF2G1wXHsyTfJD9y7uN6Il.jpg','A vampire relates his epic life story of love, betrayal, loneliness, and dark hunger to an over-curious reporter.',NULL,NULL,8.8272,7.389,0,1.07333333333333325e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(551,11979,'tt0238546',NULL,'Queen of the Damned','Queen of the Damned','movie',2002,'https://image.tmdb.org/t/p/w500/4MMpvQYgOz8K6lzlIVMXWjLzUPC.jpg','https://image.tmdb.org/t/p/original/dHkKPuiPSw9BbfAt1zdEZCuAzTX.jpg','Vampire Lestat awakens from his slumber and becomes a rock star. But chaos strikes when his music awakens Akasha, the vampire queen, who may not rest until she makes Lestat her new king.',NULL,NULL,5.1,6.11,0,13.5225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(552,7978,'tt0780653',NULL,'The Wolfman','The Wolfman','movie',2010,'https://image.tmdb.org/t/p/w500/fQqPoAHvHicie1ttuiV2q0yv9V7.jpg','https://image.tmdb.org/t/p/original/kTDunJrHYsH6o1wmD6iT4wXkuHo.jpg','Lawrence Talbot, an American man on a visit to Victorian London to make amends with his estranged father, gets bitten by a werewolf and, after a moonlight transformation, leaves him with a savage hunger for flesh.',NULL,NULL,4.4779,5.891,0,9.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(553,23220,'tt0053677',NULL,'The Brides of Dracula','The Brides of Dracula','movie',1960,'https://image.tmdb.org/t/p/w500/yJYJmxZZIAkrn0BaMcYnvEB8wVk.jpg','https://image.tmdb.org/t/p/original/9hdHLj5aJ0kQpPnCC2lFHsu9K7K.jpg','A young teacher on her way to a position in Transylvania helps a young man escape the shackles his mother has put on him. In so doing she innocently unleashes the horrors of the undead once again on the populace, including those at her school for ladies. Luckily for some, Dr. Van Helsing is already on his way.',NULL,NULL,1.7083,6.705,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(554,3053,'tt0061655',NULL,'The Fearless Vampire Killers','The Fearless Vampire Killers','movie',1967,'https://image.tmdb.org/t/p/w500/oexVZ419LUVBiZnBYgDfnUS1Ufv.jpg','https://image.tmdb.org/t/p/original/pmO4NERkXjJiCfpEuLT1raZS5fA.jpg','A noted professor and his dim-witted apprentice fall prey to their inquiring vampires, while on the trail of the ominous damsel in distress.',NULL,NULL,2.7516,7.0,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(555,46315,'tt0066516',NULL,'Valerie and Her Week of Wonders','Valerie a týden divů','movie',1970,'https://image.tmdb.org/t/p/w500/lY0IkdouazLBpPYot8dsPAsJqHK.jpg','https://image.tmdb.org/t/p/original/cygF3MFce4MDpvyqDQXNvZiytc4.jpg','Valerie, a Czechoslovakian teenager living with her grandmother, is blossoming into womanhood, but that transformation proves secondary to the effects she experiences when she puts on a pair of magic earrings. Now seeing the world around her in a different light, Valerie must endure her sexual awakening while attempting to discern reality from fantasy as she encounters lecherous priest Gracian, a vampire-like stranger and otherworldly carnival folk.',NULL,NULL,2.6335,6.959,0,1.23566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(556,622,'tt0142688',NULL,'The Ninth Gate','The Ninth Gate','movie',1999,'https://image.tmdb.org/t/p/w500/rxw9l9YNL14ODdmAavUwHLBjiDo.jpg','https://image.tmdb.org/t/p/original/qVyN9czTgRJ2SAA2BLXESzQEVgz.jpg','A rare book dealer finds himself at the heart of a string of paranormal events when he is hired to find the last two copies of a text, The Nine Gates of the Kingdom of Shadows, capable of summoning the Devil.',NULL,NULL,5.0408,6.495,0,14.422,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(557,9871,'tt0210070',NULL,'Ginger Snaps','Ginger Snaps','movie',2000,'https://image.tmdb.org/t/p/w500/ozohDiJd7Oi65NEf8B0ya7lR9Fr.jpg','https://image.tmdb.org/t/p/original/7GAgYVK29A4NADWhPbqC9c44X7P.jpg','The story of two outcast sisters, Ginger and Brigitte, in the mindless suburban town of Bailey Downs. On the night of Ginger''s first period, she is savagely attacked by a wild creature. Ginger''s wounds miraculously heal but something is not quite right. Now Brigitte must save her sister and save herself.',NULL,NULL,3.6792,6.945,0,1.23566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(558,12583,'tt0365265',NULL,'Ginger Snaps Back: The Beginning','Ginger Snaps Back: The Beginning','movie',2004,'https://image.tmdb.org/t/p/w500/tQ17krYhctcHnnslqq90zzGkhg7.jpg','https://image.tmdb.org/t/p/original/6WiX5YHelMF0ci2S1xXsiAQ9Jsu.jpg','Set in 19th Century Canada, Brigitte and her sister Ginger take refuge in a Traders'' Fort which later becomes under siege by some savage werewolves. But when one of the girls is bitten, they have no one to turn to but themselves.',NULL,NULL,1.3276,6.113,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(559,2668,'tt0162661',NULL,'Sleepy Hollow','Sleepy Hollow','movie',1999,'https://image.tmdb.org/t/p/w500/1GuK965FLJxqUw9fd1pmvjbFAlv.jpg','https://image.tmdb.org/t/p/original/m8t7K3LcAY7bpyQ7iQ5kGsrcjnh.jpg','Skeptical young detective Ichabod Crane gets transferred to the hamlet of Sleepy Hollow, New York, where he is tasked with investigating the decapitations of three people – murders the townsfolk attribute to a legendary specter, The Headless Horseman.',NULL,NULL,8.3615,7.193,0,19.43,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(560,4442,'tt0355295',NULL,'The Brothers Grimm','The Brothers Grimm','movie',2005,'https://image.tmdb.org/t/p/w500/iPrey2UYrA5Fqa8L3KnxqMqfmSq.jpg','https://image.tmdb.org/t/p/original/aDfGKWdtNHzDmnHkdDyXz7zoDuy.jpg','Folklore collectors and con artists, Jake and Will Grimm, travel from village to village pretending to protect townsfolk from enchanted creatures and performing exorcisms. However, they are put to the test when they encounter a real magical curse in a haunted forest with real magical beings, requiring genuine courage.',NULL,NULL,5.6442,5.864,0,1.42199999999999988e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(561,49730,'tt1486185',NULL,'Red Riding Hood','Red Riding Hood','movie',2011,'https://image.tmdb.org/t/p/w500/ixQYkLeLlTTnAoT32dukndyObB6.jpg','https://image.tmdb.org/t/p/original/r4A5SQSGTfleodMm45w7MJgE2WF.jpg','Valerie is in love with a brooding outsider, Peter, but her parents have arranged for her to marry another man. Unwilling to lose each other, Valerie and Peter plan to run away together when Valerie''s older sister is killed by a werewolf that prowls the dark forest surrounding their village. Panic grips the town as Valerie discovers that she has a unique connection to the beast--one that inexorably draws them together, making her both suspect ... and bait.',NULL,NULL,6.0294,5.977,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(562,277,'tt0320691',NULL,'Underworld','Underworld','movie',2003,'https://image.tmdb.org/t/p/w500/zsnQ41UZ3jo1wEeemF0eA9cAIU0.jpg','https://image.tmdb.org/t/p/original/zsgdVbuEwqZbnUN9qLGEMBYf2Zo.jpg','Vampires and werewolves have waged a nocturnal war against each other for centuries. But all bets are off when a female vampire warrior named Selene, who''s famous for her strength and werewolf-hunting prowess, becomes smitten with a peace-loving male werewolf, Michael, who wants to end the war.',NULL,NULL,7.5533,6.855,0,17.91,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(563,16559,'tt0037988',NULL,'The Picture of Dorian Gray','The Picture of Dorian Gray','movie',1945,'https://image.tmdb.org/t/p/w500/mfvcsmAzdie8YuWI0JpO2u1uzfF.jpg','https://image.tmdb.org/t/p/original/6LF0NpAu1Ea8ZlWTjwm4lWaBsyp.jpg','A corrupt young man somehow keeps his youthful beauty, but a special painting gradually reveals his inner ugliness to all.',NULL,NULL,3.0354,7.144,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(564,768,'tt0120681',NULL,'From Hell','From Hell','movie',2001,'https://image.tmdb.org/t/p/w500/t2WpWM8nBO4sULXr2bDfNEt4qgr.jpg','https://image.tmdb.org/t/p/original/bHKj3m3eLlU2wJQBlAs7wv6ZMBv.jpg','Frederick Abberline is an opium-huffing inspector from Scotland Yard who falls for one of Jack the Ripper''s prostitute targets in this Hughes brothers adaption of a graphic novel that posits the Ripper''s true identity.',NULL,NULL,2.5834,6.692,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(565,30959,'tt0058279',NULL,'Kwaidan','怪談','movie',1965,'https://image.tmdb.org/t/p/w500/t9UMfViYl47SdZZatKQ1JKjjCgs.jpg','https://image.tmdb.org/t/p/original/9GAU0z2wVA8M2D2w36CaloWYYgv.jpg','Taking its title from an archaic Japanese word meaning "ghost story," this anthology adapts four folk tales. A penniless samurai marries for money with tragic results. A man stranded in a blizzard is saved by Yuki the Snow Maiden, but his rescue comes at a cost. Blind musician Hoichi is forced to perform for an audience of ghosts. An author relates the story of a samurai who sees another warrior''s reflection in his teacup.',NULL,NULL,2.0695,7.7,0,1.61642857142857145e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(566,104251,'tt0071406',NULL,'Pastoral: To Die in the Country','田園に死す','movie',1974,'https://image.tmdb.org/t/p/w500/bnCaJFugZUZI0iACm9O2vbU24Af.jpg','https://image.tmdb.org/t/p/original/cRm7qbkTMcW9r0vQOiaz3pQZvNS.jpg','A director faces creative block while working on his latest film – a reimagination of his adolescence growing up in a mountain village in rural Japan.',NULL,NULL,1.5036,7.5,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(567,635199,'tt10919074',NULL,'Howling Village','犬鳴村','movie',2020,'https://image.tmdb.org/t/p/w500/doM8q4gqgLSFDbajjvJTlng4ZkN.jpg','https://image.tmdb.org/t/p/original/oMo1C8KgkHpFKReNdRW5oZIHDuq.jpg','After her brother goes missing, a young psychologist visits an infamous haunted and cursed location known as ‘Howling Village’ to investigate his disappearance and uncover her family’s dark history.',NULL,NULL,1.5131,5.824,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(568,2291,'tt0099871',NULL,'Jacob''s Ladder','Jacob''s Ladder','movie',1990,'https://image.tmdb.org/t/p/w500/ufLcHIi1aXjjH8MediAMvnwDsVI.jpg','https://image.tmdb.org/t/p/original/oubk1SEFtg3Q8eOncFvGQVa6OoP.jpg','After returning home from the Vietnam War, veteran Jacob Singer struggles to maintain his sanity. Plagued by hallucinations and flashbacks, Singer rapidly falls apart as the world and people around him morph and twist into disturbing images. His girlfriend, Jezzie, and ex-wife, Sarah, try to help, but to little avail. Even Singer''s chiropractor friend, Louis, fails to reach him as he descends into madness.',NULL,NULL,5.4439,7.367,0,1.87988888888888894e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(569,614017,'tt10805432',NULL,'Detention','返校','movie',2019,'https://image.tmdb.org/t/p/w500/8cKs4cPTAhAjjRAOjjXFbVnYc1l.jpg','https://image.tmdb.org/t/p/original/4NikiRtIvSAy2cAXYfX8fhFwnV6.jpg','In the 1960s, two classmates go looking for their missing friends and teachers, all of whom took part in an illegal book club, only to come face to face with ghosts and deformed monsters that have taken over their school.',NULL,NULL,1.3951,6.75,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(570,54111,'tt0266075',NULL,'Memento Mori','여고괴담 두번째 이야기','movie',1999,'https://image.tmdb.org/t/p/w500/6HDeHTbMQCWNmPD9Uqybtigt5sf.jpg','https://image.tmdb.org/t/p/original/npfTHcJkcXgrWHbeLLGkvbA0yFl.jpg','The ghost of a lesbian high-school girl takes revenge on the people who used to bully her. And another young girl finds her old diary detailing her love and rejection when she was alive.',NULL,NULL,1.42,6.325,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(571,32242,'tt0323630',NULL,'Phone','폰','movie',2002,'https://image.tmdb.org/t/p/w500/gXsnmaK7iSl8wiBCNDG2JP4lOiT.jpg','https://image.tmdb.org/t/p/original/2YxtGkkKsdB3kXNPnyGqOVhxe5a.jpg','Soon after getting a new phone, a woman notices strange things starting to happen. When she investigates, she discovers that everyone who has had her phone number before her has died suddenly and mysteriously.',NULL,NULL,0.9175,6.1,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(572,9539,'tt1029234',NULL,'Martyrs','Martyrs','movie',2008,'https://image.tmdb.org/t/p/w500/sT5ITTlTcnPOeFzHEu5j0hTZUvD.jpg','https://image.tmdb.org/t/p/original/fO1hwjlUqDe1ixO7eMfxTby62Ut.jpg','A young woman’s quest for revenge against the people who kidnapped and tortured her as a child leads her and her best friend, also a victim of child abuse, on a terrifying journey into a living hell of depravity.',NULL,NULL,6.6196,7.3,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(573,588,'tt0384537',NULL,'Silent Hill','Silent Hill','movie',2006,'https://image.tmdb.org/t/p/w500/r0bEDWO2w4a43K2xTNSF284qOsc.jpg','https://image.tmdb.org/t/p/original/48TM0HjZSRjIr4QMuDTsMWcz7gX.jpg','Rose, a desperate mother, takes her adopted daughter, Sharon, to the town of Silent Hill in an attempt to cure her of her ailment. After a violent car crash, Sharon disappears, and Rose embarks on a horrific journey to get her back and begins to uncover the truth behind the apocalyptic disaster that burned the town 30 years earlier.',NULL,NULL,6.8129,6.641,0,1.50933333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(574,565,'tt0298130',NULL,'The Ring','The Ring','movie',2002,'https://image.tmdb.org/t/p/w500/AeRpUynJKDpJveklBJipOYrVxCS.jpg','https://image.tmdb.org/t/p/original/6tuNQ16hC4Qp7wjTweKzUnnLBkI.jpg','Journalist Rachel Keller investigates a strange videotape that may be behind the untimely deaths of four teenagers. There is an urban legend about this tape: the viewer will die seven days after watching it. Rachel tracks down the video... and watches it. Now she has just seven days to unravel the mystery of the Ring in order to save herself and her son.',NULL,NULL,9.5855,6.706,0,14.378,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(575,3763,'tt0058430',NULL,'Onibaba','鬼婆','movie',1964,'https://image.tmdb.org/t/p/w500/xyPLG53OodhJtvfQEfcmC43l16O.jpg','https://image.tmdb.org/t/p/original/AcAMkNfQ21cL7EJzs5eVx24k3H4.jpg','While her son, Kichi, is away at war, a woman and her daughter-in-law survive by killing samurai who stray into their swamp, then selling whatever valuables they find. Both are devastated when they learn that Kichi has died, but his wife soon begins an affair with a neighbor who survived the war, Hachi. The mother disapproves and, when she can''t steal Hachi for herself, tries to scare her daughter-in-law with a mysterious mask from a dead samurai.',NULL,NULL,1.799,7.7,0,11.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(576,40149,'tt0122136',NULL,'Kuroneko','藪の中の黒猫','movie',1968,'https://image.tmdb.org/t/p/w500/43LZYSBRMZoi9QdYntkGXhLSMeI.jpg','https://image.tmdb.org/t/p/original/oLui5hnc8HnkVDXruisqu3LZb6H.jpg','In the Sengoku period, a woman and her daughter are raped and murdered by soldiers during a time of civil war. Afterwards, a series of samurai returning from the war through that area are found mysteriously dead with their throats torn out. The governor calls in a wild and fierce young hero to quell what is evidently an Onryō ghost.',NULL,NULL,1.3323,7.393,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(577,50173,'tt0154683',NULL,'Jigoku','地獄','movie',1960,'https://image.tmdb.org/t/p/w500/ehiMOuKE7i9WHgvs7dSIZelsHwA.jpg','https://image.tmdb.org/t/p/original/4ZVAAGCGDYncbZhjEgnfU1v2iQD.jpg','A group of sinners involved in interconnected tales of murder, revenge, deceit and adultery all meet at the Gates of Hell.',NULL,NULL,1.7585,6.359,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(578,21506,'tt0930083',NULL,'Noroi: The Curse','ノロイ','movie',2005,'https://image.tmdb.org/t/p/w500/vA7uZSMx8VL6LIuNFPnymwkRPBV.jpg','https://image.tmdb.org/t/p/original/9f29yseBYdoBUp5sFPElpeHVlck.jpg','A documentary filmmaker explores seemingly unrelated paranormal incidents connected by the legend of an ancient demon.',NULL,NULL,3.0574,6.875,0,14.416,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(579,4552,'tt0365376',NULL,'A Tale of Two Sisters','장화, 홍련','movie',2003,'https://image.tmdb.org/t/p/w500/l3exwhwyGE0NnHJ3lFQ7eXoBSkH.jpg','https://image.tmdb.org/t/p/original/syKbZiHVdXw0NcH6NdXWEKZaECv.jpg','Two sisters return home after a stay in a mental institution, only to face disturbing events and a strained relationship with their stepmother. As eerie occurrences unfold, dark family secrets begin to surface, blurring the line between reality and nightmare.',NULL,NULL,5.6354,7.098,0,1.35300000000000011e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(580,13402,'tt0498311',NULL,'Re-cycle','鬼域','movie',2006,'https://image.tmdb.org/t/p/w500/8zZQ0UBeA3UbdhgqCURHK0VymIY.jpg','https://image.tmdb.org/t/p/original/wccAWc8R4lwsREwL02oVHcsKT9w.jpg','Ting-yin, a young novelist, is struggling to come up with a followup to her best-selling trilogy of romance novels. After drafting her first chapter, she stops and deletes the file from her computer. She then starts seeing strange, unexplainable things and finds that she is experiencing the supernatural events that she described in her novel-to-be.',NULL,NULL,0.7869,6.459,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(581,36095,'tt0123948',NULL,'Cure','キュア','movie',1997,'https://image.tmdb.org/t/p/w500/xNVJr9q6AtSbjosS6Ed9YirOkSo.jpg','https://image.tmdb.org/t/p/original/xxIRKSd9LmHojUD5grvMuGypwVC.jpg','A frustrated detective deals with the case of several gruesome murders committed by people who have no recollection of what they''ve done.',NULL,NULL,4.9038,7.549,0,1.60271428571428558e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(582,1970,'tt0391198',NULL,'The Grudge','The Grudge','movie',2004,'https://image.tmdb.org/t/p/w500/7vPAVPKYexQVmvC578wPLn2CGCL.jpg','https://image.tmdb.org/t/p/original/yefSD6lp3jOBYkBeY5QxRRKTJME.jpg','An American nurse living and working in Tokyo is exposed to a mysterious supernatural curse, one that locks a person in a powerful rage before claiming their life and spreading to another victim.',NULL,NULL,4.9524,5.933,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(583,1975,'tt0433386',NULL,'The Grudge 2','The Grudge 2','movie',2006,'https://image.tmdb.org/t/p/w500/oHLeYXqA8P0jVIY2C8kQFyQTzkr.jpg','https://image.tmdb.org/t/p/original/lAp8haqJnLEVrYnSv7FZpwEJ7o4.jpg','A young woman encounters a malevolent supernatural force while searching for her missing sister in Tokyo, a mean high school prank goes horribly wrong, and strange things begin happening in a Chicago apartment building.',NULL,NULL,2.8814,5.568,0,7.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(584,10972,'tt0261983',NULL,'Session 9','Session 9','movie',2001,'https://image.tmdb.org/t/p/w500/A3Au37c3KJX29BDvldzGiYtaU5B.jpg','https://image.tmdb.org/t/p/original/q00YpCIaO4ke4qstYnds9PtAz3t.jpg','Tensions rise within an asbestos cleaning crew as they work in an abandoned mental hospital with a horrific past that seems to be coming back.',NULL,NULL,2.6673,6.141,0,1.28533333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(585,2750,'tt0274309',NULL,'24 Hour Party People','24 Hour Party People','movie',2002,'https://image.tmdb.org/t/p/w500/8f50NQ1wz6hdxfCISCPV8XQ6DII.jpg','https://image.tmdb.org/t/p/original/ucRD8UUr5tllltg3ZTWoXOyPXyJ.jpg','Manchester, 1976. Tony Wilson is an ambitious but frustrated local TV news reporter looking for a way to make his mark. After witnessing a life-changing concert by a band known as the Sex Pistols, he persuades his station to televise one of their performances, and soon Manchester''s punk groups are clamoring for him to manage them. Riding the wave of a musical revolution, Wilson and his friends create the legendary Factory Records label and The Hacienda club.',NULL,NULL,3.2501,6.964,0,1.23433333333333319e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(586,50162,'tt0225009',NULL,'964 Pinocchio','ピノキオ√964','movie',1991,'https://image.tmdb.org/t/p/w500/99iOoaDyFElUA5ihgBYKmGRhPJs.jpg','https://image.tmdb.org/t/p/original/afDTi2MQuqwvx0UQlNtS3EhgrNP.jpg','A memory-wiped and defective cyborg sex slave is tossed onto the streets and taken in by a homeless woman while his corporate creators hunt him down.',NULL,NULL,2.4128,6.0,0,1.2043333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(587,341013,'tt2406566',NULL,'Atomic Blonde','Atomic Blonde','movie',2017,'https://image.tmdb.org/t/p/w500/kV9R5h0Yct1kR8Hf8sJ1nX0Vz4x.jpg','https://image.tmdb.org/t/p/original/g3hni0i9iAQ13jDGOFWavJFlojc.jpg','An undercover MI6 agent is sent to Berlin during the Cold War to investigate the murder of a fellow agent and recover a missing list of double agents.',NULL,NULL,7.4638,6.436,0,14.248,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(588,40110,'tt0083609',NULL,'Burst City','爆裂都市','movie',1982,'https://image.tmdb.org/t/p/w500/bZ21OljXwIo0IjXXtObeK1F7856.jpg','https://image.tmdb.org/t/p/original/aJkIVcl8XO2zuP5dsM5X5x6REGI.jpg','Set in a barren, futuristic Tokyo of highways and wastelands, a rowdy group of punk bands and their fans gather to protest slow, boring, Japanese living.',NULL,NULL,0.8222,6.328,0,11.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(589,4441,'tt0424880',NULL,'Candy','Candy','movie',2006,'https://image.tmdb.org/t/p/w500/9DvrEg2p3Hrdr1uGe0t7kRraWjl.jpg','https://image.tmdb.org/t/p/original/r8J1GUYKfNFQhpg3dMhXwtmr6PL.jpg','A poet falls in love with an art student, who gravitates to his bohemian lifestyle — and his love of heroin. Hooked as much on one another as they are on the drug, their relationship alternates between states of oblivion, self-destruction, and despair.',NULL,NULL,4.1568,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(590,1245993,'tt1493274',NULL,'Caught Stealing','Caught Stealing','movie',2025,'https://image.tmdb.org/t/p/w500/cvda8s5J8YaHjTyEyXQpvD6f3iV.jpg','https://image.tmdb.org/t/p/original/41043LV7mfluH8iXEUPVseCDAv5.jpg','Burned-out ex-baseball player Hank Thompson unexpectedly finds himself embroiled in a dangerous struggle for survival amidst the criminal underbelly of late 1990s New York City, forced to navigate a treacherous underworld he never imagined.',NULL,NULL,7.3642,6.852,0,1.51671428571428563e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(591,598,'tt0317248',NULL,'City of God','Cidade de Deus','movie',2002,'https://image.tmdb.org/t/p/w500/k7eYdWvhYQyRQoU2TB2A2Xu2TfD.jpg','https://image.tmdb.org/t/p/original/uvitbjFU4JqvMwIkMWHp69bmUzG.jpg','In the poverty-stricken favelas of Rio de Janeiro in the 1970s, two young men choose different paths. Rocket is a budding photographer who documents the increasing drug-related violence of his neighborhood, while José “Zé” Pequeno is an ambitious drug dealer diving into a dangerous life of crime.',NULL,NULL,13.616,8.428,0,13.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(592,11564,'tt0083739',NULL,'Class of 1984','Class of 1984','movie',1982,'https://image.tmdb.org/t/p/w500/qIu9UGDLeACl7YGuAAgTFfQ0j8I.jpg','https://image.tmdb.org/t/p/original/ke6cDBFg4IPb8MWjPOBlIhtosQ0.jpg','Andy is a new teacher at an inner city high school that is unlike any he has seen before. There are metal detectors at the front door and the place is basically run by a tough kid named Peter Stegman. Soon, Andy and Stegman become enemies and Stegman will stop at nothing to protect his turf and drug dealing business.',NULL,NULL,2.2674,6.415,0,1.34074999999999988e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(593,26554,'tt0090849',NULL,'Class of Nuke ''Em High','Class of Nuke ''Em High','movie',1986,'https://image.tmdb.org/t/p/w500/2AljZDgKhzFaKO6i9tgmcytEA2b.jpg','https://image.tmdb.org/t/p/original/zXGyIySqNPWSG2jrMRyD8js7wtB.jpg','The pupils at a high school next to a nuclear power plant start acting and looking strange after buying contaminated drugs from a plant worker.',NULL,NULL,0.9427,5.6,0,14.432,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(594,303991,'tt1172049',NULL,'Demolition','Demolition','movie',2016,'https://image.tmdb.org/t/p/w500/4t56LZ1KbOOxgKfqMKN6truBDVc.jpg','https://image.tmdb.org/t/p/original/dapUorbOMzlaB12dACCtaiuaTQz.jpg','An emotionally desperate investment banker finds hope through a woman he meets.',NULL,NULL,4.1324,6.848,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(595,14029,'tt0089013',NULL,'Demons','Dèmoni','movie',1985,'https://image.tmdb.org/t/p/w500/ym0mtcSt6i45NIcAoSBQhop0wSP.jpg','https://image.tmdb.org/t/p/original/4anqXDsl5iZ26qeTRX3yZWylMgY.jpg','A group of people are trapped in a West Berlin movie theater infested with ravenous demons who proceed to kill and possess the humans one-by-one, thereby multiplying their numbers.',NULL,NULL,2.0301,6.6,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(596,653664,'tt9058654',NULL,'Dinner in America','Dinner in America','movie',2020,'https://image.tmdb.org/t/p/w500/t63UhnHaWQGcuE3pViuW3LSjBJj.jpg','https://image.tmdb.org/t/p/original/cOPonfWB5T2jE8eo10OSHQNSRXr.jpg','An on-the-lam punk rocker and a young woman obsessed with a local band go on an unexpected and epic journey together through the decaying suburbs of the American Midwest.',NULL,NULL,2.5485,7.665,0,6.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(597,192134,'tt2402105',NULL,'Dom Hemingway','Dom Hemingway','movie',2013,'https://image.tmdb.org/t/p/w500/hvrUPdZUDlSn1S4KCW5IdIMGS5D.jpg','https://image.tmdb.org/t/p/original/kBenhxySFb2NhRJjCVLRCiTqYPr.jpg','After spending 12 years in prison for keeping his mouth shut, notorious safe-cracker Dom Hemingway is back on the streets of London looking to collect what he''s owed.',NULL,NULL,1.0482,5.835,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(598,26574,'tt0092933',NULL,'Dudes','Dudes','movie',1987,'https://image.tmdb.org/t/p/w500/2NThzQWYfuVbhq6qq2TxWnbVOZy.jpg','https://image.tmdb.org/t/p/original/6uWtSE0NxODIgHNqAYUdtQjLV5G.jpg','Two punks from the big city, traveling across the country in a Volkswagen bug, embrace the western ethos when they must take revenge against a group of rednecks for killing their friend in this lighthearted road movie. Along the way, they enlist the help of a young woman who runs a wrecking service.',NULL,NULL,2.4165,5.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(599,2252,'tt0765443',NULL,'Eastern Promises','Eastern Promises','movie',2007,'https://image.tmdb.org/t/p/w500/nLwv1pxRCRZucQaqs6oPkq7HH3K.jpg','https://image.tmdb.org/t/p/original/1ckHUJ6ztq5XJRKM2nIAW0UjJNH.jpg','A Russian teenager living in London dies during childbirth but leaves clues in her diary that could tie her child to a rape involving a violent Russian mob family.',NULL,NULL,4.9071,7.348,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(600,1878,'tt0120669',NULL,'Fear and Loathing in Las Vegas','Fear and Loathing in Las Vegas','movie',1998,'https://image.tmdb.org/t/p/w500/tisNLcMkxryU2zxhi0PiyDFqhm0.jpg','https://image.tmdb.org/t/p/original/qJaR9AZx2Qq2oJ3krnSO0Z5ne5I.jpg','Raoul Duke and his attorney Dr. Gonzo drive a red convertible across the Mojave desert to Las Vegas with a suitcase full of drugs to cover a motorcycle race. As their consumption of drugs increases at an alarming rate, the stoned duo trash their hotel room and fear legal repercussions. Duke begins to drive back to L.A., but after an odd run-in with a cop, he returns to Sin City and continues his wild drug binge.',NULL,NULL,5.5434,7.202,0,1.59166666666666678e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(601,85889,'tt1450321',NULL,'Filth','Filth','movie',2013,'https://image.tmdb.org/t/p/w500/tzTKDgF6GcGaxKvRHR5J4MeWJ7b.jpg','https://image.tmdb.org/t/p/original/6g0MFaqYpUX9W7CXEq44ZcoxNz.jpg','A bigoted junkie cop suffering from borderline personality disorder and drug addiction manipulates and hallucinates his way in a bid to secure promotion.',NULL,NULL,3.7912,6.835,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(602,979660,'tt21942598',NULL,'Freaky Tales','Freaky Tales','movie',2025,'https://image.tmdb.org/t/p/w500/lo5mfglsGeMYmAkSRXs9DATNJxk.jpg','https://image.tmdb.org/t/p/original/elZZLzhDzjRIIkGcIK0FGmZSUaq.jpg','In 1987 Oakland, a mysterious force guides The Town''s underdogs in four interconnected tales: teen punks defend their turf against Nazi skinheads, a rap duo battles for hip-hop immortality, a weary henchman gets a shot at redemption, and an NBA All-Star settles the score.',NULL,NULL,2.2915,6.3,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(603,1380,'tt0097438',NULL,'Gleaming the Cube','Gleaming the Cube','movie',1989,'https://image.tmdb.org/t/p/w500/dpwbqnG2vmkwBBIpfQmFUf5l120.jpg','https://image.tmdb.org/t/p/original/lBTk2RgneFZqSQyKBGHfpknT1RK.jpg','An Orange County teenager''s carefree life of ditching class and skateboarding abandoned pools comes to a screeching halt when someone close to him dies. The cops rule the death a suicide, but the bereaved skater believes he was murdered. It''s up to him to solve the case, with a skateboard.',NULL,NULL,1.6321,6.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(604,8070,'tt0077315',NULL,'The Green Room','La Chambre verte','movie',1978,'https://image.tmdb.org/t/p/w500/8D2Oty3FpihcNoNowuYbzOaXKsv.jpg','https://image.tmdb.org/t/p/original/vTG5rpUcNGl28iKsf6Pd3G312pp.jpg','A widower maintains a memorial room filled with his late wife''s belongings. When fire destroys it, he transforms a chapel into a new shrine to preserve her memory.',NULL,NULL,1.3859,6.6,0,2.44993333333333325e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(605,11688,'tt0120917',NULL,'The Emperor''s New Groove','The Emperor''s New Groove','movie',2000,'https://image.tmdb.org/t/p/w500/isA0acj3ONKBLp1pKadUNzxEPFv.jpg','https://image.tmdb.org/t/p/original/mZj8EUr6F1x2PWZjKPxaeYd5WRw.jpg','When the self‑absorbed Emperor Kuzco is accidentally transformed into a llama, he must rely on a humble villager to survive the jungle and reclaim his throne.',NULL,NULL,13.682,7.564,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(606,10428,'tt0113243',NULL,'Hackers','Hackers','movie',1995,'https://image.tmdb.org/t/p/w500/w8H2KpRtpzwlxz5KrvINCVihok1.jpg','https://image.tmdb.org/t/p/original/r7fk4I68wiGrhaExjtvnGtCAI1l.jpg','Along with his new friends, a teenager who was arrested by the US Secret Service and banned from using a computer for writing a computer virus discovers a plot by a nefarious hacker, but they must use their computer skills to find the evidence while being pursued by the Secret Service and the evil computer genius behind the virus.',NULL,NULL,7.5848,6.379,0,1.51816666666666648e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(607,879,'tt0102057',NULL,'Hook','Hook','movie',1991,'https://image.tmdb.org/t/p/w500/a6rB1lGXoGms7gWxRfJneQmAjNV.jpg','https://image.tmdb.org/t/p/original/39OxcFZjX4uc6vYzexUh5qXghxE.jpg','The boy who wasn''t supposed to grow up—Peter Pan—does just that, becoming a soulless corporate lawyer whose workaholism could cost him his wife and kids. During his trip to see Granny Wendy in London, the vengeful Capt. Hook kidnaps Peter''s kids and forces Peter to return to Neverland.',NULL,NULL,7.8315,6.844,0,19.546,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(608,582927,'tt4323594',NULL,'I''m No Longer Here','Ya no estoy aquí','movie',2019,'https://image.tmdb.org/t/p/w500/AtfK71xkVaaHTZwU5mgfDgBqg9Y.jpg','https://image.tmdb.org/t/p/original/wFSXN4CaDfmUURbEbghhK6m7WPI.jpg','In Monterrey, Mexico, a young street gang spends their days dancing to slowed-down cumbia and attending parties. After a mix-up with a local cartel, their leader is forced to migrate to the U.S. but quickly longs to return home.',NULL,NULL,1.1395,7.87,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(609,41426,'tt0076240',NULL,'Jubilee','Jubilee','movie',1978,'https://image.tmdb.org/t/p/w500/8HtAaaDZDCCx2F73n41xMDWDhwU.jpg','https://image.tmdb.org/t/p/original/841V3wMNiwzOVdGo8G1cgaoaWHF.jpg','Queen Elizabeth I visits late 1970s England to find a depressing landscape where life has changed since her time.',NULL,NULL,1.2987,5.931,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(610,4836,'tt0375912',NULL,'Layer Cake','Layer Cake','movie',2004,'https://image.tmdb.org/t/p/w500/rDOxXteqxALBaSa3V3zTjGJuyWB.jpg','https://image.tmdb.org/t/p/original/tUjgRaqoTPgQKfqDx8PjVbpPWrG.jpg','When a seemingly straight-forward drug deal goes awry, XXXX has to break his die-hard rules and turn up the heat, not only to outwit the old regime and come out on top, but to save his own skin...',NULL,NULL,4.1268,6.914,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(611,11475,'tt0097728',NULL,'Leningrad Cowboys Go America','Leningrad Cowboys Go America','movie',1989,'https://image.tmdb.org/t/p/w500/rYI5IAKwqOl6nPcAYL58VzI0EXN.jpg','https://image.tmdb.org/t/p/original/kevyDBlyEJvQOPGd0b3BbtPKqrK.jpg','The Leningrad Cowboys, a group of Siberian musicians, and their manager, travel to America seeking fame and fortune. As they cross the country, trying to get to a wedding in Mexico, they are followed by the village idiot, who wishes to join the band.',NULL,NULL,0.8373,6.949,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(612,9787,'tt0355702',NULL,'Lords of Dogtown','Lords of Dogtown','movie',2005,'https://image.tmdb.org/t/p/w500/k2NiPfydLSwmk28C6qpvpJPuqtq.jpg','https://image.tmdb.org/t/p/original/r19wkx0JESCD74GVyREFLzZN2VA.jpg','The radical true story behind three teenage surfers from Venice Beach, California, who took skateboarding to the extreme and changed the world of sports forever. Stacy Peralta, Tony Alva and Jay Adams are the Z-Boys, a bunch of nobodies until they create a new style of skateboarding that becomes a worldwide phenomenon. But when their hobby becomes a business, the success shreds their friendship.',NULL,NULL,3.1154,7.092,0,17.17375,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(613,76341,'tt1392190',NULL,'Mad Max: Fury Road','Mad Max: Fury Road','movie',2015,'https://image.tmdb.org/t/p/w500/hA2ple9q4qnwxp3hKVNhroipsir.jpg','https://image.tmdb.org/t/p/original/uT895WNwm0aIJRtGizcQhrejWUo.jpg','An apocalyptic story set in the furthest reaches of our planet, in a stark desert landscape where humanity is broken, and most everyone is crazed fighting for the necessities of life. Within this world exist two rebels on the run who just might be able to restore order.',NULL,NULL,20.1414,7.636,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(614,169655,'tt0097826',NULL,'Manifesto','Manifesto','movie',1988,'https://image.tmdb.org/t/p/w500/draJxZvs6ABVTmtRfsR2hNAzXnY.jpg','https://image.tmdb.org/t/p/original/ucdh5fdSldYcPfeWQz0HkiTktqc.jpg','In a small European country, the king is scheduled to visit a small, quiet and "safe" village. It turns out that while the village may indeed be small, it''s neither as quiet nor as safe as it''s expected to be.',NULL,NULL,0.5729,4.0,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(615,250586,'tt0107587',NULL,'Mod Fuck Explosion','Mod Fuck Explosion','movie',1994,'https://image.tmdb.org/t/p/w500/vjLzdJmuOl5sXSAEcVKMW6XNKIw.jpg','https://image.tmdb.org/t/p/original/mUPWb6gjcJqTUGRGdNcBy6Hq76N.jpg','Teenage London is trying to find meaning in the world, or a leather jacket of her own. Unaccepted by neither the Mods or the Asian biker gang, she tries to find her own path. Meanwhile, the two gangs maintain a mutual vendetta sure to erupt in a smorgasbord of violence.',NULL,NULL,0.4213,5.5,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(616,1054867,'tt30144839',NULL,'One Battle After Another','One Battle After Another','movie',2025,'https://image.tmdb.org/t/p/w500/lbBWwxBht4JFP5PsuJ5onpMqugW.jpg','https://image.tmdb.org/t/p/original/zpEWFNqoN8Qg1SzMMHmaGyOBTdW.jpg','Washed-up revolutionary Bob exists in a state of stoned paranoia, surviving off-grid with his spirited, self-reliant daughter, Willa. When his evil nemesis resurfaces after 16 years and she goes missing, the former radical scrambles to find her, father and daughter both battling the consequences of his past.',NULL,NULL,17.862,7.344,0,1.13433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(617,132159,'tt13823494',NULL,'Pistol','Pistol','tv',2022,'https://image.tmdb.org/t/p/w500/qHswJ2FXpN9jJIqNlxgc5ZooFb4.jpg','https://image.tmdb.org/t/p/original/nyeeTs57UBtvhV3ZZVnwn7uk2t7.jpg','The story of a band of spotty, noisy, working-class kids with “no future,” who shook the boring, corrupt Establishment to its core, threatened to bring down the government and changed music and culture forever.',NULL,NULL,4.3315,7.551,0,6.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(618,13820,'tt0087995',NULL,'Repo Man','Repo Man','movie',1984,'https://image.tmdb.org/t/p/w500/bjuu5UceuVUNUjnOC2fBzL3hZKC.jpg','https://image.tmdb.org/t/p/original/5K5oPo1NJrAVUeaPzcXFH13Xplo.jpg','A down and out young punk gets a job working with a seasoned repo man, but what awaits him in his new career is a series of outlandish adventures revolving around aliens, the CIA, and a most wanted ''64 Chevy.',NULL,NULL,2.5792,6.656,0,2.4552666666666667e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(619,10925,'tt0089907',NULL,'The Return of the Living Dead','The Return of the Living Dead','movie',1985,'https://image.tmdb.org/t/p/w500/oNsV9BychAe4Sk6xFKp558Rlpyz.jpg','https://image.tmdb.org/t/p/original/h4uQC5IJAGSV83Ophuy87vJI42E.jpg','Two employees at a medical supply warehouse accidentally release a toxic gas from a misplaced top-secret U.S. Army shipment, causing the dead to rise from a nearby cemetery with an insatiable hunger for human brains.',NULL,NULL,5.544,7.196,0,1.52433333333333322e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(620,454,'tt0117509',NULL,'Romeo + Juliet','Romeo + Juliet','movie',1996,'https://image.tmdb.org/t/p/w500/eLf4jclPijOqfEp6bDAmezRFxk5.jpg','https://image.tmdb.org/t/p/original/m0miV65ZZIp13TNHJSRUF6vmCos.jpg','In this contemporary take on William Shakespeare''s classic tragedy, the Montagues and Capulets have moved their ongoing feud to the sweltering suburb of Verona Beach, where Romeo and Juliet fall in love and secretly wed. Though the film is visually modern, the bard''s dialogue remains.',NULL,NULL,5.5297,6.78,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(621,11468,'tt0235737',NULL,'The Salton Sea','The Salton Sea','movie',2002,'https://image.tmdb.org/t/p/w500/i3InMSlLUNBEdQTKazMdyVP1ryX.jpg','https://image.tmdb.org/t/p/original/mGhz7vE2EvWm6MfFqPJXDidNgAY.jpg','After the murder of his beloved wife, a man in search of redemption is set adrift in a world where nothing is as it seems. On his journey, he befriends slacker Jimmy "The Finn", becomes involved in rescuing his neighbor Colette from her own demons, and gets entangled in a web of deceit full of unexpected twists and turns.',NULL,NULL,1.5952,6.583,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(622,11966,'tt0096101',NULL,'Short Circuit 2','Short Circuit 2','movie',1988,'https://image.tmdb.org/t/p/w500/vXzkNsPEA59EON5PMVXsURe8o67.jpg','https://image.tmdb.org/t/p/original/hyI49UsyxEeljfjyjjXIXHQkw6V.jpg','Robot Johnny 5 moves to the city to help his friend Ben Jahrvi with his toy manufacturing enterprise, only to be manipulated by criminals who want to use him for their own nefarious purposes.',NULL,NULL,2.6677,6.226,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(623,14924,'tt0091954',NULL,'Sid and Nancy','Sid and Nancy','movie',1986,'https://image.tmdb.org/t/p/w500/wHzCbMCfipDJ38GW5IyBTWDflMz.jpg','https://image.tmdb.org/t/p/original/pLdutWHlPIHf7ldH31akiVLUHQQ.jpg','January 1978. After their success in England, the punk rock band Sex Pistols venture out on their tour of the southern United States. Temperamental bassist Sid Vicious is forced by his band mates to travel without his troubled girlfriend, Nancy Spungen, who will meet him in New York. When the band breaks up and Sid begins his solo career in a hostile city, the turbulent couple definitely falls into the depths of drug addiction.',NULL,NULL,3.0754,6.735,0,6.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(624,6396,'tt0133189',NULL,'SLC Punk','SLC Punk','movie',1998,'https://image.tmdb.org/t/p/w500/gdbj2uvElEfEvTDGUY40vvuJU3R.jpg','https://image.tmdb.org/t/p/original/nmrxw4INylwepfDRbIa4kYGAs6b.jpg','Two former geeks become 1980s punks, then party and go to concerts while deciding what to do with their lives.',NULL,NULL,1.4179,7.1,0,1.56033333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(625,94066,'tt0084698',NULL,'Smithereens','Smithereens','movie',1982,'https://image.tmdb.org/t/p/w500/jp29gfdiP7AxtjqzlzyaztFORMF.jpg','https://image.tmdb.org/t/p/original/1PyJzcHGC6irRaBRmjP0pUli7UT.jpg','A narcissistic runaway engages in a number of parasitic relationships amongst members of New York''s waning punk scene.',NULL,NULL,0.936,6.479,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(626,273059,'tt3257692',NULL,'Starving in Suburbia','Starving in Suburbia','movie',2014,'https://image.tmdb.org/t/p/w500/kSTqlLJ0gNEIQVNwVe9YhvAcdZo.jpg','https://image.tmdb.org/t/p/original/iSKHeZ2QumBwIuJnIBXzjaczbPP.jpg','When seventeen-year-old Hannah stumbles upon a website about Thinspiration--an online community devoted to anorexia as a life choice--she becomes an obsessive follower of the site founder, ButterflyAna. By the time Hannah''s family realizes what is happening and get Hannah the help she needs, the disease has fully taken hold and Hannah is refusing to eat. Will this family be able to exorcise the demon of anorexia from their lives?',NULL,NULL,2.2537,6.543,0,8.85000000000000142e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(627,10279,'tt0162677',NULL,'Summer of Sam','Summer of Sam','movie',1999,'https://image.tmdb.org/t/p/w500/yvGGA2CbT6xyFVTZUA9f2ok0q5V.jpg','https://image.tmdb.org/t/p/original/pXXhErx4sn30BuOnhNeGJX8mQ7r.jpg','Spike Lee''s take on the "Son of Sam" murders in New York City during the summer of 1977 centering on the residents of an Italian-American Northeast Bronx neighborhood who live in fear and distrust of one another.',NULL,NULL,3.4789,6.503,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(628,9607,'tt0108255',NULL,'Super Mario Bros.','Super Mario Bros.','movie',1993,'https://image.tmdb.org/t/p/w500/yt5bbMfKpg1nRr4k5edxs7tPK2m.jpg','https://image.tmdb.org/t/p/original/1GGfWFp9hp4RUHRHxd505z9rVFa.jpg','Mario and Luigi, plumbers from Brooklyn, find themselves in an alternate universe where evolved dinosaurs live in hi-tech squalor. They''re the only hope to save our universe from invasion by the dino dictator, Koopa.',NULL,NULL,3.8718,4.498,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(629,1061474,'tt5950044',NULL,'Superman','Superman','movie',2025,'https://image.tmdb.org/t/p/w500/ldyfo0BKmz5rWtJJKCvwaNS4cJT.jpg','https://image.tmdb.org/t/p/original/eGX66zonvc4bXg3rM08RUxdYSDx.jpg','Superman, a journalist in Metropolis, embarks on a journey to reconcile his Kryptonian heritage with his human upbringing as Clark Kent.',NULL,NULL,31.9309,7.332,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(630,11824,'tt0090142',NULL,'Teen Wolf','Teen Wolf','movie',1985,'https://image.tmdb.org/t/p/w500/bv9rY9eoue2Hat6tcvrKVQ0ow8v.jpg','https://image.tmdb.org/t/p/original/d1RYJQcljAlSOwTizaGS3oWnPEk.jpg','When a shy teenager''s new-found powers help him score at basketball - and with the popular girls - he has some pretty hairy decisions to make.',NULL,NULL,3.2622,6.206,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(631,1498,'tt0100758',NULL,'Teenage Mutant Ninja Turtles','Teenage Mutant Ninja Turtles','movie',1990,'https://image.tmdb.org/t/p/w500/shfAU6xIIEAEtsloIT3n9Fscz2E.jpg','https://image.tmdb.org/t/p/original/qXM08jXRwlT9rm10iAC2uoq0Kn.jpg','A quartet of humanoid turtles, trained by their mentor in Ninjutsu, must learn to work together to face the menace of Shredder and the Foot Clan.',NULL,NULL,5.3222,6.7,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(632,1497,'tt0103060',NULL,'Teenage Mutant Ninja Turtles II: The Secret of the Ooze','Teenage Mutant Ninja Turtles II: The Secret of the Ooze','movie',1991,'https://image.tmdb.org/t/p/w500/Hyvvz9Z3le1is8a0EeFJQm0aSC.jpg','https://image.tmdb.org/t/p/original/iIdmQwDP3rOS1XMZKMPFCPkA1Do.jpg','The Turtles and the Shredder battle once again, this time for the last cannister of the ooze that created the Turtles, which Shredder wants to create an army of new mutants. Meanwhile Splinter is coming... to a decision.',NULL,NULL,3.5167,6.234,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(633,21137,'tt0082252',NULL,'The Decline of Western Civilization','The Decline of Western Civilization','movie',1981,'https://image.tmdb.org/t/p/w500/36YfDJQKZfoCn5NLJ7mcrekE511.jpg','https://image.tmdb.org/t/p/original/f8xL5NhRuZNyai9Sijb9aykU1z5.jpg','The Los Angeles punk music scene circa 1980 is the focus of this film. With Alice Bag Band, Black Flag, Catholic Discipline, Circle Jerks, Fear, Germs, and X.',NULL,NULL,0.812,7.2,0,10.7675,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(634,27016,'tt0082639',NULL,'Ladies and Gentlemen, the Fabulous Stains','Ladies and Gentlemen, the Fabulous Stains','movie',1982,'https://image.tmdb.org/t/p/w500/tEFBKyD22O1rq9a7mTZCJjrzc9u.jpg','https://image.tmdb.org/t/p/original/mV6gplI7dCkZnSJbKvsaKMBDxMb.jpg','Corrine Burns retreats far into plans for her band, The Fabulous Stains, after her mother''s death.',NULL,NULL,0.9216,6.311,0,6.51500000000000056e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(635,45317,'tt0964517',NULL,'The Fighter','The Fighter','movie',2010,'https://image.tmdb.org/t/p/w500/xfsFerGhO1h6rLk8vwLgMyQ8WVJ.jpg','https://image.tmdb.org/t/p/original/2kqmEQZqime0G3ULgrKtAq3WVdH.jpg','Boxer "Irish" Micky Ward''s unlikely road to the world light welterweight title. His Rocky-like rise was shepherded by half-brother Dicky, a boxer-turned-trainer who rebounded in life after nearly being KO''d by drugs and crime.',NULL,NULL,4.4348,7.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(636,65754,'tt1568346',NULL,'The Girl with the Dragon Tattoo','The Girl with the Dragon Tattoo','movie',2011,'https://image.tmdb.org/t/p/w500/8bokS83zGdhaXgN9tjidUKmAftW.jpg','https://image.tmdb.org/t/p/original/dNFbrnF0mIBm0rClbfEFWTtsgMP.jpg','Disgraced journalist Mikael Blomkvist investigates the disappearance of a weary patriarch''s niece from 40 years ago. He is aided by the pierced, tattooed, punk computer hacker named Lisbeth Salander. As they work together in the investigation, Blomkvist and Salander uncover immense corruption beyond anything they have ever imagined.',NULL,NULL,8.1359,7.387,0,1.25324999999999988e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(637,11836,'tt0345950',NULL,'The SpongeBob SquarePants Movie','The SpongeBob SquarePants Movie','movie',2004,'https://image.tmdb.org/t/p/w500/1rvzKV1d18EbDVaEd4VDzK3cgnY.jpg','https://image.tmdb.org/t/p/original/i2fZIltljrhFPsUK9PN6O6ZE7M4.jpg','There''s trouble brewing in Bikini Bottom. Someone has stolen King Neptune''s crown, and it looks like Mr. Krab, SpongeBob''s boss, is the culprit. Though he''s just been passed over for the promotion of his dreams, SpongeBob stands by his boss, and along with his best pal Patrick, sets out on a treacherous mission to Shell City to reclaim the crown and save Mr. Krab''s life.',NULL,NULL,10.838,7.088,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(638,18502,'tt0090094',NULL,'The Stuff','The Stuff','movie',1985,'https://image.tmdb.org/t/p/w500/bT0PxmeePfzX8YrZHGaAXau9RLN.jpg','https://image.tmdb.org/t/p/original/tbYg8aKDTLia2ZjT3b4ykAAHyel.jpg','Amalgamated Dairies hires David Rutherford, an FBI man turned industrial saboteur, to investigate a popular new product called “the Stuff,” a new dessert product that is blowing ice cream sales out of the water. Nobody knows how it’s made or what’s in it, but people are lining up to buy it. It''s got a delicious flavor to die for!',NULL,NULL,2.1632,5.971,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(639,11474,'tt0080120',NULL,'The Warriors','The Warriors','movie',1979,'https://image.tmdb.org/t/p/w500/d6YZpBq4BhQr1K985J3CuL1cA8J.jpg','https://image.tmdb.org/t/p/original/i4Fp0AJsqAzbeVQyCoG0adRRfdh.jpg','Prominent gang leader Cyrus calls a meeting of New York''s gangs to set aside their turf wars and take over the city. At the meeting, a rival leader kills Cyrus, but a Coney Island gang called the Warriors is wrongly blamed for Cyrus'' death. Before you know it, the cops and every gangbanger in town is hot on the Warriors'' trail.',NULL,NULL,5.1186,7.677,0,1.49383333333333325e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(640,8337,'tt0096256',NULL,'They Live','They Live','movie',1988,'https://image.tmdb.org/t/p/w500/ngnybFTuopfbfmmEeX9jjBQQmF6.jpg','https://image.tmdb.org/t/p/original/3k2DQBryXzaL7DoAtu6veWWluwt.jpg','A lone drifter stumbles upon a unique pair of sunglasses that reveal aliens are systematically gaining control of the Earth by masquerading as humans and lulling the public into submission.',NULL,NULL,5.9608,7.3,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(641,823147,'tt8129806',NULL,'To Leslie','To Leslie','movie',2022,'https://image.tmdb.org/t/p/w500/bFTgfsw4cnNjIZZ2r6P363X2Uk3.jpg','https://image.tmdb.org/t/p/original/7SGsNmrdb6hLQujKpvuBUrkKmcv.jpg','A West Texas single mother wins the lottery and squanders it just as fast, leaving behind a world of heartbreak. Years later, with her charm running out and nowhere to go, she fights to rebuild her life and find redemption.',NULL,NULL,3.5055,7.004,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(642,9615,'tt0463985',NULL,'The Fast and the Furious: Tokyo Drift','The Fast and the Furious: Tokyo Drift','movie',2006,'https://image.tmdb.org/t/p/w500/46xqGOwHbh2TH2avWSw3SMXph4E.jpg','https://image.tmdb.org/t/p/original/dMARcKLrv0T7kVJ4iQR3vqTTdtT.jpg','In order to avoid a jail sentence, Sean Boswell heads to Tokyo to live with his military father. In a low-rent section of the city, Sean gets caught up in the underground world of drift racing',NULL,NULL,2.8207,6.549,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(643,33560,'tt0108366',NULL,'Totally F***ed Up','Totally F***ed Up','movie',1994,'https://image.tmdb.org/t/p/w500/qZBtSTEhlXy0aNTZ40umWLpJr2T.jpg','https://image.tmdb.org/t/p/original/mNaZmb5bCZXdbKL0mh57J5v7pdt.jpg','Gay, alienated Los Angeles teens have a hard time as their parents kick them out of their homes, they don’t have money, their lovers cheat, and they are harassed by gay-bashers.',NULL,NULL,1.2379,6.6,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(644,627,'tt0117951',NULL,'Trainspotting','Trainspotting','movie',1996,'https://image.tmdb.org/t/p/w500/1jUC02qsqS2NxBMFarbIhcQtazV.jpg','https://image.tmdb.org/t/p/original/dkfBKDUIWP1peEszdqK10MkMZCP.jpg','Heroin addict Mark Renton stumbles through bad ideas and sobriety attempts with his unreliable friends --Sick Boy, Begbie, Spud and Tommy. He also has an underage girlfriend, Diane, along for the ride. After cleaning up and moving from Edinburgh to London, Mark finds he can''t escape the life he left behind as Begbie and Sick Boy come knocking.',NULL,NULL,8.6998,7.958,0,1.48757142857142845e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(645,2034,'tt0139654',NULL,'Training Day','Training Day','movie',2001,'https://image.tmdb.org/t/p/w500/bUeiwBQdupBLQthMCHKV7zv56uv.jpg','https://image.tmdb.org/t/p/original/nuO8o9ltxhI7AZQxePavEZ4TyHa.jpg','On his first day on the job as a narcotics officer, a rookie cop works with a rogue detective who isn''t what he appears.',NULL,NULL,7.836,7.525,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(646,19053,'tt0086525',NULL,'Valley Girl','Valley Girl','movie',1983,'https://image.tmdb.org/t/p/w500/mQSrU9jerYSIOWeLBqFA1gcUU59.jpg','https://image.tmdb.org/t/p/original/stTmJizMu8LklEIIkSu7NqHchdH.jpg','Julie, a girl from the valley, meets Randy, a punk from the city. They are from different worlds and find love. Somehow they need to stay together in spite of her trendy, shallow friends.',NULL,NULL,2.1667,5.976,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(647,429202,'tt5960374',NULL,'Vox Lux','Vox Lux','movie',2018,'https://image.tmdb.org/t/p/w500/xmFOjB5bGvFqNzsX5TbIWzdvpGd.jpg','https://image.tmdb.org/t/p/original/qXzqEcHs9YcEgkjoNdWvxM2kIqZ.jpg','In 1999, teenage sisters Celeste and Eleanor survive a seismic, violent tragedy. The sisters compose and perform a song about their experience, making something lovely and cathartic out of catastrophe — while also catapulting Celeste to stardom. By 2017, the now 31-year-old Celeste is mother to a teenage daughter of her own and struggling to navigate a career fraught with scandals when another act of terrifying violence demands her attention.',NULL,NULL,1.4424,5.778,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(648,8909,'tt0493464',NULL,'Wanted','Wanted','movie',2008,'https://image.tmdb.org/t/p/w500/njy7Pz7ZHZceO7lNfGIHKphY8Hd.jpg','https://image.tmdb.org/t/p/original/vjwuT8EzWY96W6nrJKZNI2WJU87.jpg','Doormat Wesley Gibson is an office worker whose life is going nowhere. He meets an attractive woman named Fox and discovers that his recently murdered father - whom Wesley never knew - belonged to the Fraternity, a secret society of assassins which takes its orders from Fate itself. Fox and Sloan, the Fraternity''s leader, teach Wesley, through intense training, to tap into dormant powers and hone his innate killing skills. Though he enjoys his newfound abilities, he begins to suspect that there is more to the Fraternity than meets the eye.',NULL,NULL,7.7731,6.531,0,12.73,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(649,18484,'tt0413466',NULL,'Wassup Rockers','Wassup Rockers','movie',2005,'https://image.tmdb.org/t/p/w500/mABP5REdreZ4ZMhP0jUgyQlQBqB.jpg','https://image.tmdb.org/t/p/original/gcgAOPm2Gp0sHbYiixxnhyRt4oc.jpg','Instead of adhering to the norms of their South Central neighborhood, a group of skater boys opt to bus into Hollywood and Beverly Hills, where they attract local rich girls - and plenty of trouble with the police, jealous boyfriends, and nervous parents.',NULL,NULL,0.8893,5.63,0,1.42139999999999986e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(650,191294,'tt2364975',NULL,'We Are the Best!','Vi är bäst!','movie',2013,'https://image.tmdb.org/t/p/w500/8KzhURCHxpVtpMk4oMerB4vn48b.jpg','https://image.tmdb.org/t/p/original/81sWsKobcYTm5sMLB287r4oHYf4.jpg','Three girls in 1980s Stockholm decide to form a punk band—despite not having any instruments, and being told by everyone that punk is dead.',NULL,NULL,1.1753,7.007,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(651,16231,'tt0267116',NULL,'Wild Zero','WiLD ZERO','movie',1999,'https://image.tmdb.org/t/p/w500/9HOpvIaFJSwFyDXoULC9hWVdVsS.jpg','https://image.tmdb.org/t/p/original/d84kHdmlZd46xFiQqyPId8ouVgd.jpg','Only legendary Japanese garage rock band Guitar Wolf can stand between a race of aliens from destroying earth with an army of zombies.',NULL,NULL,0.7539,5.641,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(652,332562,'tt1517451',NULL,'A Star Is Born','A Star Is Born','movie',2018,'https://image.tmdb.org/t/p/w500/wrFpXMNBRj2PBiN4Z5kix51XaIZ.jpg','https://image.tmdb.org/t/p/original/dDYpjrwh1wNVQk0rEpc9P81wQt4.jpg','Seasoned musician Jackson Maine discovers — and falls in love with — struggling artist Ally. She has just about given up on her dream to make it big as a singer — until Jack coaxes her into the spotlight. But even as Ally''s career takes off, the personal side of their relationship is breaking down, as Jack fights an ongoing battle with his own internal demons.',NULL,NULL,5.6165,7.492,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(653,11931,'tt0388125',NULL,'In Her Shoes','In Her Shoes','movie',2005,'https://image.tmdb.org/t/p/w500/gmd2n3TuXewrbINp8Jfhwd5Jw6S.jpg','https://image.tmdb.org/t/p/original/yNhmsmCqK6bTl4xUT28fJ1r6f61.jpg','Irresponsible party girl Maggie is kicked out of her father''s and stepmother''s home—where she lives for free—and is taken in by her hard-working sister, Philadelphia lawyer Rose. After Maggie''s disruptive ways ruin her sister''s love life, Rose turns her out as well. But when their grandmother, who they never knew existed, comes into their lives, the sisters face some complicated truths about themselves and their family.',NULL,NULL,3.5964,6.221,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(654,37735,'tt1282140',NULL,'Easy A','Easy A','movie',2010,'https://image.tmdb.org/t/p/w500/v5f1qO6NJnxWgONgkYg21TW39DT.jpg','https://image.tmdb.org/t/p/original/30rvmoEBqovm723agDJ3QddWXcY.jpg','Olive, an average high school student, sees her below-the-radar existence turn around overnight once she decides to use the school''s gossip grapevine to advance her social standing. Now her classmates are turning against her and the school board is becoming concerned, including her favorite teacher and the distracted guidance counselor. With the support of her hilariously idiosyncratic parents and a little help from a long-time crush, Olive attempts to take on her notorious new identity and crush the rumor mill once and for all.',NULL,NULL,6.6659,6.804,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(655,200012,'tt0431645',NULL,'Downtown Girls','بنات وسط البلد','movie',2005,'https://image.tmdb.org/t/p/w500/1wHgzmKpSbHGKW8yIEJkpkzO1Rz.jpg','https://image.tmdb.org/t/p/original/2hHPCpi4LwMSXxEvMi9URluPfXk.jpg','The film takes place inside the world of Downtown that is full of stories and many social relations,through two girls,one is a hairdresser and the other is a saleswoman in a clothing store.',NULL,NULL,0.4015,6.0,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(656,391713,'tt4925292',NULL,'Lady Bird','Lady Bird','movie',2017,'https://image.tmdb.org/t/p/w500/gl66K7zRdtNYGrxyS2YDUP5ASZd.jpg','https://image.tmdb.org/t/p/original/jwBiY1kE5089i2WpfS1MHDYp3VO.jpg','Lady Bird McPherson, a strong willed, deeply opinionated, artistic 17 year old comes of age in Sacramento. Her relationship with her mother and her upbringing are questioned and tested as she plans to head off to college.',NULL,NULL,8.6724,7.251,0,14.436,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(657,290762,'tt2245003',NULL,'Miss You Already','Miss You Already','movie',2015,'https://image.tmdb.org/t/p/w500/cvA686C7O8MwXhFIaql4ui6eR0p.jpg','https://image.tmdb.org/t/p/original/ygiO8LyMEcHa8dwg0aLCpybPlP0.jpg','The friendship between two life-long girlfriends is put to the test when one starts a family and the other falls ill.',NULL,NULL,1.8795,7.389,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(658,11172,'tt0758766',NULL,'Music and Lyrics','Music and Lyrics','movie',2007,'https://image.tmdb.org/t/p/w500/1WXVpnovC0EETbqcjVhy3hwIITK.jpg','https://image.tmdb.org/t/p/original/cLZsdMMC3hoVQy9xwn3YJ4CR9Pd.jpg','A washed-up ''80s pop star gets a chance at a comeback when reigning pop diva Cora Corman invites him to write & record a duet with her, but there''s a problem--Alex hasn''t written a song in years; he''s never written lyrics and he has to come up with a hit in a matter of days.',NULL,NULL,4.377,6.453,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(659,21349,'tt0149691',NULL,'Anywhere but Here','Anywhere but Here','movie',1999,'https://image.tmdb.org/t/p/w500/2DNtxmXkotuaJexU57geTLIPnQf.jpg','https://image.tmdb.org/t/p/original/n03FL1Ia88Jq2nV7fz4AJE9utw0.jpg','Single mother Adele August is bad with money, and even worse when it comes to making decisions. Her straight-laced daughter, Ann, is a successful high school student with Ivy League aspirations. When Adele decides to pack up and move the two of them from the Midwest to Beverly Hills, Calif., to pursue her dreams of Hollywood success, Ann grows frustrated with her mother''s irresponsible and impulsive ways.',NULL,NULL,2.378,6.067,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(660,800787,'tt14153080',NULL,'A Good Person','A Good Person','movie',2023,'https://image.tmdb.org/t/p/w500/dhejMQdsqPtTTCKIkyoJ5FLfC3F.jpg','https://image.tmdb.org/t/p/original/bLZ1WGb59JXFRYRFgknOwwiPJ0l.jpg','Allison''s life falls apart following her involvement in a fatal accident. The unlikely relationship she forms with her would-be father-in-law helps her live a life worth living.',NULL,NULL,2.4069,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(661,198277,'tt1980929',NULL,'Begin Again','Begin Again','movie',2014,'https://image.tmdb.org/t/p/w500/qx4HXHXt528hS4rwePZbZo20xqZ.jpg','https://image.tmdb.org/t/p/original/xrSRmL6pXnRfu9vKwayILkNgLP.jpg','Gretta, a budding songwriter, finds herself alone after her boyfriend Dave ditches her. Her life gains purpose when Dan, a record label executive, notices her talent.',NULL,NULL,3.2322,7.234,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(662,73108,'tt1845866',NULL,'Teen Spirit','Teen Spirit','movie',2011,'https://image.tmdb.org/t/p/w500/8mmxoEBzTMX4ziYgveeEx35ltNY.jpg','https://image.tmdb.org/t/p/original/s75xYQOo4Hy2fy229CEfj5jgC2B.jpg','Amber, a mean popular girl who gets electrocuted and dies, is not allowed to enter into heaven unless she helps the least popular girl in school become Prom Queen within a week, but things do not go as planned.',NULL,NULL,4.0573,5.937,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(663,38167,'tt0879870',NULL,'Eat Pray Love','Eat Pray Love','movie',2010,'https://image.tmdb.org/t/p/w500/gjR5zUeMGV6UNqtI0OuzqrLQcjU.jpg','https://image.tmdb.org/t/p/original/elzrIY3nfzWz4AXh0lxxBsXLCGI.jpg','A married woman realizes how unhappy her marriage really is, and that her life needs to go in a different direction. After a painful divorce, she takes off on a round-the-world journey to "find herself".',NULL,NULL,5.5527,6.249,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(664,7303,'tt0252076',NULL,'Maid in Manhattan','Maid in Manhattan','movie',2002,'https://image.tmdb.org/t/p/w500/gnEuTYH3jhHxl80QyoPfZjEYd0J.jpg','https://image.tmdb.org/t/p/original/l5sD0AK286fBpXyDHRCbtaFMArN.jpg','Marisa Ventura is a struggling single mom who works at a posh Manhattan hotel and dreams of a better life for her and her young son. One fateful day, hotel guest and senatorial candidate Christopher Marshall meets Marisa and mistakes her for a wealthy socialite. After an enchanting evening together, the two fall madly in love. But when Marisa''s true identity is revealed, issues of class and social status threaten to separate them. Can two people from very different worlds overcome their differences and live happily ever after?',NULL,NULL,3.277,6.142,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(665,10802,'tt0114436',NULL,'Showgirls','Showgirls','movie',1995,'https://image.tmdb.org/t/p/w500/o4HT3Ap5c99W4FYpdXUtTvxGgPc.jpg','https://image.tmdb.org/t/p/original/jL3G2f8uNCFejJRlIqCzRp8Y7eV.jpg','Fresh to Las Vegas with no connections, Nomi Malone takes a job as an exotic dancer. Her talents are quickly noticed by Cristal, a headlining dancer who senses an opportunity to bolster her own act. But Nomi won’t play second fiddle and soon begins her venomous path to the top, ruthlessly backstabbing anyone who gets in her way.',NULL,NULL,7.2099,5.6,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(666,55721,'tt1478338',NULL,'Bridesmaids','Bridesmaids','movie',2011,'https://image.tmdb.org/t/p/w500/gJtA7hYsBMQ7EM3sPBMUdBfU7a0.jpg','https://image.tmdb.org/t/p/original/1pkpV7a02phSfAPeGVmpHaQd99J.jpg','Annie''s life is a mess. But when she finds out her lifetime best friend is engaged, she simply must serve as Lillian''s maid of honor. Though lovelorn and broke, Annie bluffs her way through the expensive and bizarre rituals. With one chance to get it perfect, she’ll show Lillian and her bridesmaids just how far you’ll go for someone you love.',NULL,NULL,5.1939,6.511,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(667,10096,'tt0337563',NULL,'13 Going on 30','13 Going on 30','movie',2004,'https://image.tmdb.org/t/p/w500/iNZdSIfhSCMtRILDNyhLn8UKeSG.jpg','https://image.tmdb.org/t/p/original/ld7UTOGzZSxIMbuYsb6eQ6QdN4h.jpg','After total humiliation at her thirteenth birthday party, Jenna Rink wants to just hide until she''s thirty. Thanks to some magic wishing dust, Jenna''s prayer has been answered. With a knockout body, a fabulous wardrobe, an athlete boyfriend, a dream job, and superstar friends, this can''t be a better life. But soon Jenna realizes that adult life isn’t as easy as she hoped for.',NULL,NULL,7.1769,6.777,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(668,9603,'tt0112697',NULL,'Clueless','Clueless','movie',1995,'https://image.tmdb.org/t/p/w500/8AwVTcgpTnmeOs4TdTWqcFDXEsA.jpg','https://image.tmdb.org/t/p/original/65d0MccsiRSPTVicregKQL8owoo.jpg','Shallow, rich and socially successful Cher is at the top of her Beverly Hills high school''s pecking scale. Seeing herself as a matchmaker, Cher first coaxes two teachers into dating each other. Emboldened by her success, she decides to give hopelessly klutzy new student Tai a makeover. When Tai becomes more popular than she is, Cher realizes that her disapproving ex-stepbrother was right about how misguided she was -- and falls for him.',NULL,NULL,5.6737,7.251,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(669,4599,'tt0350028',NULL,'Raising Helen','Raising Helen','movie',2004,'https://image.tmdb.org/t/p/w500/ubZin4oGXYp6hCn3WU6nrBre62y.jpg','https://image.tmdb.org/t/p/original/lw5YfNEZaxWo7Q7sn76bLUlyAhi.jpg','Helen Harris has a glamorous, big-city life working for one of New York''s hottest modeling agencies. But suddenly her free-spirited life gets turned upside down when she must chose between the life she''s always loved, and the new loves of her life!',NULL,NULL,2.116,6.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(670,18555,'tt0116353',NULL,'Foxfire','Foxfire','movie',1996,'https://image.tmdb.org/t/p/w500/ywrSScJT43HerqWPlMu8nigLFzg.jpg','https://image.tmdb.org/t/p/original/i2WrfAiK3o5NjqdM7XZKTrwil6m.jpg','The story of five teenage girls who form an unlikely bond after beating up a teacher who has sexually harassed them. They build a solid friendship but their wild ways begin to get out of control.',NULL,NULL,2.1268,6.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(671,11091,'tt0200027',NULL,'Riding in Cars with Boys','Riding in Cars with Boys','movie',2001,'https://image.tmdb.org/t/p/w500/1xzvRrpA9V1TxXP7kIf8d0AgJ1R.jpg','https://image.tmdb.org/t/p/original/wXax3nRWlZDfRqgrmBIKfE2OnaJ.jpg','In 1965, a young woman with dreams of becoming a writer has a son at the age of 15 and struggles to make things work with the drug-addicted father.',NULL,NULL,2.3993,6.743,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(672,8835,'tt0250494',NULL,'Legally Blonde','Legally Blonde','movie',2001,'https://image.tmdb.org/t/p/w500/9ohlMrJHQqKhfUKh7Zr3JQqHNLZ.jpg','https://image.tmdb.org/t/p/original/viU23X3BIycUFf6TOlm9c7TxLgM.jpg','Fashionable sorority queen Elle Woods has it all, but, she wants nothing more than to be Mrs. Warner Huntington III. But he dumps her before heading to Harvard Law School. Elle rallies all of her resources and gets into Harvard, determined to win him back. While there, she figures out that there is more to herself than just good looks.',NULL,NULL,15.6516,6.817,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(673,634,'tt0243155',NULL,'Bridget Jones''s Diary','Bridget Jones''s Diary','movie',2001,'https://image.tmdb.org/t/p/w500/olMTi7uCaec9Yr3Ar07D2SIja1G.jpg','https://image.tmdb.org/t/p/original/9rSpxsMhG1FnFtUDdvSAXdtLtb3.jpg','Bridget Jones is an average woman struggling against expectations. As a New Year''s resolution, Bridget decides to take control of her life, starting by keeping a diary in which she will always tell the complete truth. Her charming boss takes an interest in her, and she cannot stop running into a rather disagreeable acquaintance whom Bridget cannot help finding quietly attractive.',NULL,NULL,5.4739,6.743,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(674,4327,'tt0160127',NULL,'Charlie''s Angels','Charlie''s Angels','movie',2000,'https://image.tmdb.org/t/p/w500/iHTmZs0BmkwMCYi8rhvMWC5G4EM.jpg','https://image.tmdb.org/t/p/original/oq3IOr7QvEmei0eXsXacqaMPqlV.jpg','The captivating crime-fighting trio who are masters of disguise, espionage and martial arts are back! When a devious mastermind embroils them in a plot to destroy individual privacy, the Angels, aided by their loyal sidekick Bosley, set out to bring down the bad guys. But when a terrible secret is revealed, it makes the Angels targets for assassination.',NULL,NULL,9.4935,5.854,0,12.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(675,10564,'tt0198021',NULL,'Where the Heart Is','Where the Heart Is','movie',2000,'https://image.tmdb.org/t/p/w500/3iyT5W3PjDKMKVS1vfAnDLeSXh2.jpg','https://image.tmdb.org/t/p/original/ahGSlXunI3Aa0MV4IXlpjYVSVWI.jpg','Novalee Nation is a 17-year-old Tennessee transient who has to grow up in a hurry when she''s left pregnant and abandoned by her boyfriend on a roadside, and takes refuge in the friendly aisles of Wal-Mart. Eventually, some eccentric but kindly strangers ''adopt'' Novalee and her infant daughter, helping them buck the odds and build a new life.',NULL,NULL,3.5917,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(676,11355,'tt0151738',NULL,'Never Been Kissed','Never Been Kissed','movie',1999,'https://image.tmdb.org/t/p/w500/6BngDhDNfbBjhVFWDT2yMve32vi.jpg','https://image.tmdb.org/t/p/original/vNdulTZXaL11xFs7FWCnxEE7wqR.jpg','Josie Geller, a baby-faced junior copywriter at the Chicago Sun-Times, must pose as a student at her former high school to research contemporary teenage culture. With the help of her brother, Rob, Josie infiltrates the inner circle of the most popular clique on campus. But she hits a major snag in her investigation -- not to mention her own failed love life -- when she falls for her dreamy English teacher, Sam Coulson.',NULL,NULL,3.3768,6.169,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(677,2018,'tt0209475',NULL,'The Wedding Planner','The Wedding Planner','movie',2001,'https://image.tmdb.org/t/p/w500/meq4bLUPcBlOG3Z5YdiWuBMlpO.jpg','https://image.tmdb.org/t/p/original/h6D695KwxdjFWteDwZ6LHOfICr6.jpg','San Francisco''s premiere wedding planner, Mary Fiore is rescued from an accident by the man of her dreams, pediatrician Steve Edison, only to find he is the fiancé of her latest client. As Mary continues making their wedding arrangements, she and Steve are put into a string of uncomfortable situations that force them to face their mutual attraction.',NULL,NULL,3.5945,5.935,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(678,35690,'tt1294226',NULL,'The Last Song','The Last Song','movie',2010,'https://image.tmdb.org/t/p/w500/76twEOHXAM2oKnvZYBI5bP6GeDu.jpg','https://image.tmdb.org/t/p/original/7TUNSWElqh6bG2OZ9aEkTKeORtC.jpg','A drama centered on a rebellious girl who is sent to a Southern beach town for the summer to stay with her father. Through their mutual love of music, the estranged duo learn to reconnect.',NULL,NULL,3.0823,7.23,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(679,11631,'tt0795421',NULL,'Mamma Mia!','Mamma Mia!','movie',2008,'https://image.tmdb.org/t/p/w500/zdUA4FNHbXPadzVOJiU0Rgn6cHR.jpg','https://image.tmdb.org/t/p/original/90sDsHugeRU5dtTG3zEVIOXXl4L.jpg','A spirited young bride-to-be living with her single mother on a small Greek island secretly invites three of her mother''s ex-boyfriends in hope of finding her biological father to walk her down the aisle.',NULL,NULL,8.4667,6.964,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(680,455,'tt0286499',NULL,'Bend It Like Beckham','Bend It Like Beckham','movie',2002,'https://image.tmdb.org/t/p/w500/2dzSBmFWWqt8NbnubJKIWU21Y86.jpg','https://image.tmdb.org/t/p/original/vUe5v3l6ul7coxMv2oLwINeVgFi.jpg','Jess Bhamra, the daughter of a strict Indian couple in London, is not permitted to play organized soccer, even though she is 18. When Jess is playing for fun one day, her impressive skills are seen by Jules Paxton, who then convinces Jess to play for her semi-pro team. Jess uses elaborate excuses to hide her matches from her family while also dealing with her romantic feelings for her coach, Joe.',NULL,NULL,3.9733,6.329,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(681,288045,'tt0113353',NULL,'Happy Hour','歡樂時光','movie',1995,'https://image.tmdb.org/t/p/w500/7gv83KRB9GMASf693EMS5yfvqcu.jpg',NULL,'Three friends get drunk and hook up with a girl they meet in a bar. After a night of debauchery, the girl accuses them of rape, then falls into a coma after a suicide attempt.',NULL,NULL,0.5877,7.0,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(682,12229,'tt0122515',NULL,'The Acid House','The Acid House','movie',1998,'https://image.tmdb.org/t/p/w500/o0KvKCgxMFccx3SzDI3p2218921.jpg','https://image.tmdb.org/t/p/original/lh57j971CIzI3FruTbFeWpYHjej.jpg','A surreal triptych adapted by "Trainspotting" author Irvine Welsh from his acclaimed collection of short stories. Combining a vicious sense of humor with hard-talking drama, the film reaches into the hearts and minds of the chemical generation, casting a dark and unholy light into the hidden corners of the human psyche.',NULL,NULL,1.1384,6.25,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(683,19366,'tt0236348',NULL,'Josie and the Pussycats','Josie and the Pussycats','movie',2001,'https://image.tmdb.org/t/p/w500/dYwbqjnSFsvCGok8gsqRcY8ewTU.jpg','https://image.tmdb.org/t/p/original/wkQAYth62cJXsvqkYbDH8b1cqES.jpg','Josie, Melody and Val are three small-town girl musicians determined to take their rock band out of their garage and straight to the top, while remaining true to their look, style and sound. They get a record deal which brings fame and fortune but soon realize they are pawns of two people who want to control the youth of America. They must clear their names, even if it means losing fame and fortune.',NULL,NULL,1.9012,5.814,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(684,281,'tt0114558',NULL,'Strange Days','Strange Days','movie',1995,'https://image.tmdb.org/t/p/w500/rY5BrDRcYAKE0BYmmT66YG6Uy5Q.jpg','https://image.tmdb.org/t/p/original/zSFuvi6fIPT8CHpH1KMG25T2Iub.jpg','In the last days of 1999, ex-cop turned street hustler Lenny Nero receives a disc which contains the memories of the murder of a prostitute. With the help of bodyguard Mace, he starts to investigate and is pulled deeper and deeper in a whirl of murder, blackmail and intrigue.',NULL,NULL,3.2799,7.018,0,14.628,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(685,9705,'tt0244244',NULL,'Swordfish','Swordfish','movie',2001,'https://image.tmdb.org/t/p/w500/mM6h4jMqC4q5IaFgBIGKQDLnRU.jpg','https://image.tmdb.org/t/p/original/eSxvC0Qw0A9AfI355MF9dSItrfR.jpg','Rogue agent Gabriel Shear is determined to get his mitts on $9 billion stashed in a secret Drug Enforcement Administration account. He wants the cash to fight terrorism, but lacks the computer skills necessary to hack into the government mainframe. Enter Stanley Jobson, a n''er-do-well encryption expert who can log into anything.',NULL,NULL,4.5191,6.268,0,1.23533333333333317e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(686,96936,'tt2132285',NULL,'The Bling Ring','The Bling Ring','movie',2013,'https://image.tmdb.org/t/p/w500/6yh55qCcdgPRJweDWM2CiEubJCL.jpg','https://image.tmdb.org/t/p/original/ouN0GyE7mtIT6wyJeilaggyvgNj.jpg','Lured by stardom, a crew of aimless teens breaks into celebrity homes for a string of high-profile robberies and fame by appropriation.',NULL,NULL,3.859,5.43,0,12.826,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(687,11129,'tt0188674',NULL,'Human Traffic','Human Traffic','movie',1999,'https://image.tmdb.org/t/p/w500/cHwnYGZh1fVuVWqT28GpCN0usYF.jpg','https://image.tmdb.org/t/p/original/kRC0aqvYYDIrgeq83yUdq7qFTn4.jpg','For Jip, Lulu, Koop, Nina and Moff, the dead-end jobs they endure during the week just kill the time until Friday night. That''s when they cut very loose and get on the rollercoaster ride that takes them right through to Monday morning.',NULL,NULL,2.2507,6.806,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(688,24469,'tt1232776',NULL,'Fish Tank','Fish Tank','movie',2009,'https://image.tmdb.org/t/p/w500/rI3MKBDsWzQHi9PWDAMKkgmYcff.jpg','https://image.tmdb.org/t/p/original/4VgiVdd2I3AktHkOpCeSjtP4t8b.jpg','Fifteen-year-old Mia is in a constant state of war with her family and the world around her. When she meets her party-girl mother’s charming new boyfriend Connor, she is amazed to find he returns her attention, and believes he might help her start to make sense of her life.',NULL,NULL,1.7779,6.945,0,13.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(689,104,'tt0130827',NULL,'Run Lola Run','Lola rennt','movie',1998,'https://image.tmdb.org/t/p/w500/v0giIi4bTILVhNhJajet3WWY3FA.jpg','https://image.tmdb.org/t/p/original/wRcm3iwi4BeMN59U4fjO7u3dOVI.jpg','Lola receives a phone call from her boyfriend Manni. He lost 100,000 DM in a subway train that belongs to a very bad guy. She has 20 minutes to raise this amount and meet Manni. Otherwise, he will rob a store to get the money. Three different alternatives may happen depending on some minor event along Lola''s run.',NULL,NULL,4.3081,7.302,0,1.23566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(690,9398,'tt0196229',NULL,'Zoolander','Zoolander','movie',2001,'https://image.tmdb.org/t/p/w500/qdrbSneHZjJG2Dj0hhBxzzAo4HB.jpg','https://image.tmdb.org/t/p/original/lIyyiBOuyokL82rPEDcZaMKleA3.jpg','Clear the runway for Derek Zoolander, VH1''s three-time male model of the year. His face falls when hippie-chic Hansel scooters in to steal this year''s award. The evil fashion guru Mugatu seizes the opportunity to turn Derek into a killing machine. It''s a well-designed conspiracy and only with the help of Hansel and a few well-chosen accessories like Matilda can Derek make the world safe for male models everywhere.',NULL,NULL,4.6534,6.2,0,1.26766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(691,1946,'tt0120907',NULL,'eXistenZ','eXistenZ','movie',1999,'https://image.tmdb.org/t/p/w500/kETKF0JhdTPn1knci8CAdYL0d79.jpg','https://image.tmdb.org/t/p/original/epmwIWdQLouFJ8yx55quVvgnTKu.jpg','A game designer on the run from assassins must play her latest virtual reality creation with a marketing trainee to determine if the game has been damaged.',NULL,NULL,4.7895,6.788,0,1.1504999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(692,1550,'tt0311648',NULL,'Pieces of April','Pieces of April','movie',2003,'https://image.tmdb.org/t/p/w500/qm3jGZwz2UkwwEFEFzSot8T0pz1.jpg','https://image.tmdb.org/t/p/original/jcue2THX5mjQFV7EXqoQyXyLlbR.jpg','Quirky and rebellious April Burns lives with her boyfriend in a low-rent New York City apartment miles away from her emotionally distant family. But when she discovers that her mother has a fatal form of breast cancer, she invites the clan to her place for Thanksgiving. While her father struggles to drive her family into the city, April -- an inexperienced cook -- runs into kitchen trouble and must ask a neighbor for help.',NULL,NULL,1.7901,6.52,0,11.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(693,11132,'tt0361467',NULL,'Confessions of a Teenage Drama Queen','Confessions of a Teenage Drama Queen','movie',2004,'https://image.tmdb.org/t/p/w500/nQA9Ozh9ftLQyJvuKy6sl5zSlH2.jpg','https://image.tmdb.org/t/p/original/z5r8XnWFWTD0shvIlR9yCn85Lna.jpg','After moving to New Jersey, Lola bags a coveted role in a school play, which earns her the wrath of Carla, the most popular girl in school, who will do anything to ruin Lola''s life.',NULL,NULL,2.504,5.728,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(694,6116,'tt0120185',NULL,'Spice World','Spice World','movie',1997,'https://image.tmdb.org/t/p/w500/vKiAnV1QAGIJP38vatwCZp4dCrH.jpg','https://image.tmdb.org/t/p/original/zZEJu3db4Ld4urK5klPvQxkWzaX.jpg','World famous pop group the Spice Girls zip around London in their luxurious double decker tour bus having various adventures and performing for their fans.',NULL,NULL,2.9792,4.918,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(695,36592,'tt0435434',NULL,'Swing Girls','スウィングガールズ','movie',2004,'https://image.tmdb.org/t/p/w500/5pAfMXqcaUjr0dBuOhLpTRbtZqa.jpg','https://image.tmdb.org/t/p/original/dsiuxsSbQcasRpQT08nQSI2sc4Q.jpg','A group of delinquent high school girls form a band when they accidentally poison their school''s brass band and have to replace them.',NULL,NULL,3.3598,7.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(696,343611,'tt3393786',NULL,'Jack Reacher: Never Go Back','Jack Reacher: Never Go Back','movie',2016,'https://image.tmdb.org/t/p/w500/cOg3UT2NYWHZxp41vpxAnVCOC4M.jpg','https://image.tmdb.org/t/p/original/ww1eIoywghjoMzRLRIcbJLuKnJH.jpg','Years after resigning command of an elite military police unit, the nomadic, righter-of-wrongs Reacher is drawn back into the life he left behind when his friend and successor, Major Susan Turner is framed for espionage. Reacher will stop at nothing to prove her innocence and to expose the real perpetrators behind the killings of his former soldiers.',NULL,NULL,6.7829,6.026,0,13.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(697,34549,'tt0273799',NULL,'Max Keeble''s Big Move','Max Keeble''s Big Move','movie',2001,'https://image.tmdb.org/t/p/w500/eJ4olY0dZMC1MfMhRkLOWisWYtu.jpg','https://image.tmdb.org/t/p/original/ziINAUKAi1W74PffqDdBPk9E62l.jpg','Max Keeble, the victim of his 7th grade class, plots revenge when he learns he''s moving; it backfires when he doesn''t move after all.',NULL,NULL,1.9571,5.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(698,70193,'tt0798722',NULL,'Hazard','HAZARD','movie',2005,'https://image.tmdb.org/t/p/w500/37UiCE8LyyRLlg9p50LL2QvBmzz.jpg','https://image.tmdb.org/t/p/original/hS0IOeV0ghqiv1WcsjdKgYop9JT.jpg','Shin is a Japanese university student living a boring and meaningless life. One day, he spots a book titled Dangerous Ways to Walk the World, in which he finds a page written about hazards in New-York. Eager to get out, he jets off to New-York to find this inspiration.',NULL,NULL,0.5258,6.558,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(699,17609,'tt0870984',NULL,'Antichrist','Antichrist','movie',2009,'https://image.tmdb.org/t/p/w500/ge7zbYvpfsDP3luKi0iSpzOgncM.jpg','https://image.tmdb.org/t/p/original/utABPVjXBlM8NUOBecCyLLuzQSe.jpg','A grieving couple retreats to their cabin ''Eden'' in the woods, hoping to repair their broken hearts and troubled marriage. But nature takes its course and things go from bad to worse.',NULL,NULL,3.2555,6.6,0,11.78,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(700,26275,'tt0416220',NULL,'Kamikaze Girls','下妻物語','movie',2004,'https://image.tmdb.org/t/p/w500/fpmFgBElC7bDSHJwtmfJnYFyMqw.jpg','https://image.tmdb.org/t/p/original/4QCs7akSCJPOs2IYnLOTDvHFdVh.jpg','Momoko, a strange and seemingly emotionless girl obsessed with 18th century France, befriends a Yanki biker and the two experience the ups and downs of their unusual lives in a rural Japanese town.',NULL,NULL,2.7011,7.118,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(701,499537,'tt8173728',NULL,'The Wolf House','La casa lobo','movie',2018,'https://image.tmdb.org/t/p/w500/kvgch2e25cd6dWhRJ6G8BCJ1Wcq.jpg','https://image.tmdb.org/t/p/original/u4CVC9VVpbfxxFqf8fcaPVegUmZ.jpg','After escaping from a religious colony in Chile, Maria seeks shelter in a mansion where she’s taken in by two pigs, its only inhabitants. Like in a stop-motion dream, the universe of the house reacts to her feelings. The animals slowly morph into humans and the house into a dark, menacing world.',NULL,NULL,0.9159,7.568,0,1.60142857142857124e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(702,13101,'tt0042627',NULL,'Heart of Stone','Das kalte Herz','movie',1950,'https://image.tmdb.org/t/p/w500/wlkYm9ekfjqqxxSXx0JSvpflt1l.jpg','https://image.tmdb.org/t/p/original/9tC23FrKT8yJdCMKUTGUc2gbRY3.jpg','Lavish adaptation of Wilhelm Hauff′s fairy tale: Young charburner Peter Munk dreams of joining the upper class. He makes a deal with the sinister Holländer-Michel, who offers to trade Peter′s human heart for one made of stone. Once he has the "cold heart" in his body, Peter eventually strikes a fortune and enjoys great wealth, but at the same time, he becomes a bitter and emotionless man – and, having lost all traces of humanity, even murders his wife Lisbeth. Only then does Peter Munk finally realize what has become of him, and he decides to regain his real heart from Holländer-Michel.',NULL,NULL,1.8722,6.2,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(703,16523,'tt0386117',NULL,'Where the Wild Things Are','Where the Wild Things Are','movie',2009,'https://image.tmdb.org/t/p/w500/pzVqDpSzOg32IpXghHGSGAAArl6.jpg','https://image.tmdb.org/t/p/original/e0MwhnT6ydLrgQbq4IIABhJdsmo.jpg','Max imagines running away from his mom and sailing to a far-off land where large talking beasts—Ira, Carol, Douglas, the Bull, Judith and Alexander—crown him as their king, play rumpus, build forts and discover secret hideaways.',NULL,NULL,2.6656,6.5,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(704,NULL,NULL,114110,'Fear & Hunger','Fear & Hunger','game',2018,'https://images.igdb.com/igdb/image/upload/t_cover_big/co5wgw.jpg',NULL,'A dark fantasy survival horror RPG in which players must uncover the secrets of the dungeon of Fear & Hunger.','https://www.igdb.com/games/fear-and-hunger','["PC (Microsoft Windows)", "Mac"]',NULL,NULL,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(705,8922,'tt0263488',NULL,'Jeepers Creepers','Jeepers Creepers','movie',2001,'https://image.tmdb.org/t/p/w500/g410Y1U1ELbmJG14Zru3UAimm1G.jpg','https://image.tmdb.org/t/p/original/m0yTFeh8vrsMP0fQDdYGSh4xthX.jpg','On a desolate country highway, two homeward-bound teens are nearly run off the road by a maniac in a beat-up truck, and later spot him shoving what appears to be a body down a sewer pipe.',NULL,NULL,7.1055,6.5,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(706,11837,'tt0078480',NULL,'Watership Down','Watership Down','movie',1978,'https://image.tmdb.org/t/p/w500/q9ZcNxfquJbMTd6UfhAlJbmLBts.jpg','https://image.tmdb.org/t/p/original/sDaTPRwukICb6r9lwB1UiYFa2pW.jpg','When the warren belonging to a community of rabbits is threatened, a brave group led by Fiver, Bigwig, Blackberry and Hazel leave their homeland in a search of a safe new haven.',NULL,NULL,3.2059,7.2,0,1.40240000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(707,977000,'tt18561446',NULL,'Moon Garden','Moon Garden','movie',2023,'https://image.tmdb.org/t/p/w500/jEwxATA59b3StO8WiNdX9YfRwwg.jpg','https://image.tmdb.org/t/p/original/8DJefIN5uIiJ4k9xr6kGPfa68l3.jpg','A comatose five-year-old girl journeys through a dark industrial dreamscape, following her mother''s voice on a transistor radio to find her way back to consciousness.',NULL,NULL,0.4494,6.303,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(708,62215,'tt1527186',NULL,'Melancholia','Melancholia','movie',2011,'https://image.tmdb.org/t/p/w500/fMneszMiQuTKY8JUXrGGB5vwqJf.jpg','https://image.tmdb.org/t/p/original/qzrS5ShZZPsPdhM5ZbcQKG7fwFo.jpg','Two sisters find their already strained relationship challenged as a mysterious new planet threatens to collide with Earth.',NULL,NULL,3.6315,7.154,0,1.54283333333333345e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(709,614637,'tt13938338',NULL,'Woodlands Dark and Days Bewitched: A History of Folk Horror','Woodlands Dark and Days Bewitched: A History of Folk Horror','movie',2021,'https://image.tmdb.org/t/p/w500/hW1TFe8Q6W4p6hxFbWOTWvwoySg.jpg','https://image.tmdb.org/t/p/original/tEyWHYvNh60MsQbPIuZf46rsWo5.jpg','An exploration of the cinematic history of the folk horror, from its beginnings in the UK in the late sixties; through its proliferation on British television in the seventies and its many manifestations, culturally specific, in other countries; to its resurgence in the last decade.',NULL,NULL,0.5863,7.6,0,9.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(710,430231,'tt3986820',NULL,'The Endless','The Endless','movie',2017,'https://image.tmdb.org/t/p/w500/uVHPBTLb6Sj1Eso9HzyBAOMRheM.jpg','https://image.tmdb.org/t/p/original/nvCMi8ZhH1Z8i9ZFHYrXBl8uBw0.jpg','Two brothers return to the cult they fled from years ago to discover that the group''s beliefs may be more sane than they once thought.',NULL,NULL,2.1819,6.323,0,1.21766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(711,45974,'tt0191173',NULL,'The Halloween Tree','The Halloween Tree','movie',1993,'https://image.tmdb.org/t/p/w500/phcM1B7neu6g7ysw9CmIo35Qida.jpg','https://image.tmdb.org/t/p/original/bbDbM6ucn7TSpARZhWGvmMr1lto.jpg','Four children learn the origins of Halloween customs while trying to save the life of their friend.',NULL,NULL,0.8773,6.696,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(712,23202,'tt0862856',NULL,'Trick ''r Treat','Trick ''r Treat','movie',2007,'https://image.tmdb.org/t/p/w500/w0nmol4g7n6MFfhfphV7GzHHYjB.jpg','https://image.tmdb.org/t/p/original/wYI3r4DGKhwjPoDpfPfGdLMrPLt.jpg','Four interwoven stories that occur on Halloween: an everyday high school principal has a secret life as a serial killer; a college virgin might have just met the one guy for her; a group of teenagers pull a mean prank, and a bitter old recluse receives an uninvited guest.',NULL,NULL,3.441,6.983,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(713,6947,'tt0368447',NULL,'The Village','The Village','movie',2004,'https://image.tmdb.org/t/p/w500/v7UvYtKfIVaHLaHwVgfalyrK7Ho.jpg','https://image.tmdb.org/t/p/original/lxwCRTWWfCisuarrFFUhW43eBnW.jpg','When a willful young man tries to venture beyond his sequestered Pennsylvania hamlet, his actions set off a chain of chilling incidents that will alter the community forever.',NULL,NULL,4.7915,6.49,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(714,798286,'tt13521006',NULL,'Beau Is Afraid','Beau Is Afraid','movie',2023,'https://image.tmdb.org/t/p/w500/wgVkkjigF31r1nZV80uV0xNIoun.jpg','https://image.tmdb.org/t/p/original/atvEgnjjXN5QvFDThXVz4nyU9yi.jpg','Following the sudden death of his mother, a mild-mannered but anxiety-ridden man confronts his darkest fears as he embarks on an epic odyssey back home.',NULL,NULL,3.6762,6.721,0,14.334,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(715,26914,'tt0105643',NULL,'Troll 2','Troll 2','movie',1990,'https://image.tmdb.org/t/p/w500/eFth6zw4PEInzr2Y64mYVN1zbBi.jpg','https://image.tmdb.org/t/p/original/iGSkacZfUs3eJyg78XxKjT99Hfw.jpg','When young Joshua learns that he will be going on vacation with his family to a small town called Nilbog, he protests adamantly. He is warned by the spirit of his deceased grandfather that goblins populate the town. His parents, Michael and Diana, dismiss his apprehensions, but soon learn to appreciate their son''s warnings. Guided by his grandfather''s ghost, will Joshua and his family stand a chance in fighting off these evil beings?',NULL,NULL,1.3449,3.928,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(716,9005,'tt0400525',NULL,'The Ice Harvest','The Ice Harvest','movie',2005,'https://image.tmdb.org/t/p/w500/8N2X2u6nPoPEwRLIZbKacJw1xrC.jpg','https://image.tmdb.org/t/p/original/qDEU8UwN07cz689uErkWtMlok0m.jpg','A shady lawyer attempts a Christmas Eve crime, hoping to swindle the local mob out of some money. But his partner, a strip club owner, might have different plans for the cash.',NULL,NULL,2.0383,5.936,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(717,713364,'tt23060698',NULL,'Clown in a Cornfield','Clown in a Cornfield','movie',2025,'https://image.tmdb.org/t/p/w500/6ep6gw90TJ8bYvJC6hEDo8SxjoJ.jpg','https://image.tmdb.org/t/p/original/zrIE7qg61W2KEwDRCW83VtkhSeo.jpg','Quinn and her father have just moved to the quiet town of Kettle Springs hoping for a fresh start. Instead, she discovers a fractured community that has fallen on hard times after the treasured Baypen Corn Syrup Factory burned down. As the locals bicker amongst themselves and tensions boil over, a sinister, grinning figure emerges from the cornfields to cleanse the town of its burdens, one bloody victim at a time.',NULL,NULL,4.5164,6.111,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(718,1362514,'tt33425631',NULL,'House on Eden','House on Eden','movie',2025,'https://image.tmdb.org/t/p/w500/2xVyCvnuVVRpYohPxrvwxZiH49r.jpg','https://image.tmdb.org/t/p/original/qMV1paVi1WiHkmKH5uzIBDDh4Gf.jpg','Paranormal investigators Kris, Celina and their videographer Jay are rerouted to an abandoned house deep in the woods, where they find themselves facing a force unlike anything they''ve encountered before. As the night spirals into chaos, missing crew members and eerie phenomena hint at an ancient, malevolent presence watching their every move.',NULL,NULL,2.0251,4.76,0,1.03433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(719,559907,'tt9243804',NULL,'The Green Knight','The Green Knight','movie',2021,'https://image.tmdb.org/t/p/w500/if4hw3Ou5Sav9Em7WWHj66mnywp.jpg','https://image.tmdb.org/t/p/original/kIQc0kkqIYTo65x5XjlKgqdDQ6a.jpg','An epic fantasy adventure based on the timeless Arthurian legend, The Green Knight tells the story of Sir Gawain, King Arthur''s reckless and headstrong nephew, who embarks on a daring quest to confront the eponymous Green Knight, a gigantic emerald-skinned stranger and tester of men.',NULL,NULL,4.8378,6.6,0,18.73,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(720,39758,'tt1212452',NULL,'Bag of Bones','Bag of Bones','tv',2011,'https://image.tmdb.org/t/p/w500/jDaGB39D8bIk8Jja8QYbv8nGaGj.jpg','https://image.tmdb.org/t/p/original/y8NChH7plo7wUrkhMhEmqoHg5WC.jpg','Bestselling novelist Mike Noonan, unable to cope after his wife''s sudden death, returns to the couple''s lakeside retreat in Maine, where he becomes involved in a custody battle between a young widow and her child''s enormously wealthy grandfather. Mike inexplicably receives mysterious ghostly visitations, escalating nightmares and the realization that his late wife still has something to tell him.',NULL,NULL,1.9581,5.906,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(721,16118,'tt0079844',NULL,'Salem''s Lot','Salem''s Lot','tv',1979,'https://image.tmdb.org/t/p/w500/yaztNZUErjSmrVsuXEZiuIVyVj2.jpg','https://image.tmdb.org/t/p/original/gtpcM2uLLo99mL4Z7OntpCoWqEi.jpg','Ben Mears has returned to his hometown to write a book about the supposedly haunted Marsten House. When people around the Marsten House start dying mysteriously, Mears discovers that the owner of the mansion is actually a vampire who is turning them into an army of undead slaves.',NULL,NULL,3.4813,6.8,0,10.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(722,25748,'tt0106557',NULL,'Children of the Corn II: The Final Sacrifice','Children of the Corn II: The Final Sacrifice','movie',1992,'https://image.tmdb.org/t/p/w500/5UaH4zhfKT1taJGHUwPxm29ZENf.jpg','https://image.tmdb.org/t/p/original/ejSBZuLfTFzGftPhcOQRo576FcC.jpg','When a tabloid reporter and his son travel to a quiet Midwestern town to investigate a gruesome massacre, they fall victim to a possessed orphan named Micah.',NULL,NULL,1.4577,4.786,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(723,1598211,'tt8836798',NULL,'Local 58','Local 58','movie',2017,'https://image.tmdb.org/t/p/w500/aGWVYapXcPXH49lgacN3s5KfpjH.jpg','https://image.tmdb.org/t/p/original/wpPINkwEkJT0XQN68SIUSeIDXCz.jpg','Local 58, a public access television channel based in Mason County, West Virginia, is continuously hijacked over a period of decades with a series of ominous and surreal broadcasts.',NULL,NULL,0.3239,0.0,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(724,14836,'tt0327597',NULL,'Coraline','Coraline','movie',2009,'https://image.tmdb.org/t/p/w500/4jeFXQYytChdZYE9JYO7Un87IlW.jpg','https://image.tmdb.org/t/p/original/hofnlIyF6bePkgQOpcuRWLvzf15.jpg','Wandering her rambling old house in her boring new town, 11-year-old Coraline discovers a hidden door to a strangely idealized version of her life. In order to stay in the fantasy, she must make a frighteningly real sacrifice.',NULL,NULL,35.4483,7.92,0,14.796,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(725,420818,'tt6105098',NULL,'The Lion King','The Lion King','movie',2019,'https://image.tmdb.org/t/p/w500/dzBtMocZuJbjLOXvrl4zGYigDzh.jpg','https://image.tmdb.org/t/p/original/1TUg5pO1VZ4B0Q1amk3OlXvlpXV.jpg','Simba idolizes his father, King Mufasa, and takes to heart his own royal destiny. But not everyone in the kingdom celebrates the new cub''s arrival. Scar, Mufasa''s brother—and former heir to the throne—has plans of his own. The battle for Pride Rock is ravaged with betrayal, tragedy and drama, ultimately resulting in Simba''s exile. With help from a curious pair of newfound friends, Simba will have to figure out how to grow up and take back what is rightfully his.',NULL,NULL,12.4876,7.096,0,12.37,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(726,1273309,'tt22310382',NULL,'Firebrand','Firebrand','movie',2023,'https://image.tmdb.org/t/p/w500/paeNSdVJWQqIMq7QK4ssb8urjE0.jpg',NULL,'Following a bitter argument with his abusive girlfriend, blue-collar gearhead, Theo (Jeremy Dash), embarks on a journey towards self harm - resulting in a dire confrontation with his inner demon. FIREBRAND is the debut narrative short by writer/director Rhett Bradbury, in collaboration with accomplished industry veterans Jeremy Dash and Jonah Schwartz. Set to release in 2023, the film aims to resonate with audiences on a cerebral level as we follow Theo''s emotional and existential crisis.',NULL,NULL,0.3164,7.0,0,9.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(727,225728,'tt2884018',NULL,'Macbeth','Macbeth','movie',2015,'https://image.tmdb.org/t/p/w500/a5NEpil29Uns1wEYF8k99qVgj1T.jpg','https://image.tmdb.org/t/p/original/gkJkemR5EUFYRrO6YFZFFMKZIru.jpg','Feature film adaptation of Shakespeare''s Scottish play about General Macbeth whose ambitious wife urges him to use wicked means in order to gain power of the throne over the sitting king, Duncan.',NULL,NULL,1.406,6.438,0,10.285,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(728,10047,'tt0151137',NULL,'The Messenger: The Story of Joan of Arc','Joan of Arc','movie',1999,'https://image.tmdb.org/t/p/w500/lFzOGA2LPdOfQyhEiY74uDf2WKa.jpg','https://image.tmdb.org/t/p/original/iW2ZLRkKJvFuI6ZkSchk5f8kCPc.jpg','In 1429, a French teenager stood before her King with a message she claimed came from God; that she would defeat the world''s greatest army and liberate her country from its political and religious turmoil. As she reclaims God''s diminished kingdom, this courageous young woman has various amazing victories until her violent and untimely death.',NULL,NULL,3.9711,6.426,0,12.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(729,555035,'tt9379356',NULL,'Ophelia','Ophelia','movie',2018,'https://image.tmdb.org/t/p/w500/dyNtV1iZEztMa2GNpJpze8Irygu.jpg','https://image.tmdb.org/t/p/original/2tx305lIUjiRRnfVZ3ERsSwGVPz.jpg','A depressed college student wants to seek psychiatric help from her parents but they have other plans in mind',NULL,NULL,0.134,6.0,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(730,49494,'tt1034389',NULL,'The Eagle','The Eagle','movie',2011,'https://image.tmdb.org/t/p/w500/mbsdwO4lfIARqt35VVTM0UlYkhZ.jpg','https://image.tmdb.org/t/p/original/k78NOxPHrWCDmBnVx0fux37Vv05.jpg','In 140 AD, twenty years after the unexplained disappearance of the entire Ninth Legion in the mountains of Scotland, young centurion Marcus Aquila arrives from Rome to solve the mystery and restore the reputation of his father, the commander of the Ninth. Accompanied only by his British slave Esca, Marcus sets out across Hadrian''s Wall into the uncharted highlands of Caledonia - to confront its savage tribes, make peace with his father''s memory, and retrieve the lost legion''s golden emblem, the Eagle of the Ninth.',NULL,NULL,3.5685,6.237,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(731,197,'tt0112573',NULL,'Braveheart','Braveheart','movie',1995,'https://image.tmdb.org/t/p/w500/or1gBugydmjToAEq7OZY0owwFk.jpg','https://image.tmdb.org/t/p/original/1m1c5gIWWkb1FEC9lzsoXHhhs7b.jpg','Enraged at the slaughter of Murron, his new bride and childhood love, Scottish warrior William Wallace slays a platoon of the local English lord''s soldiers. This leads the village to revolt and, eventually, the entire country to rise up against English rule.',NULL,NULL,11.7903,7.946,0,1.12800000000000011e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(732,375588,'tt4532826',NULL,'Robin Hood','Robin Hood','movie',2018,'https://image.tmdb.org/t/p/w500/AiRfixFcfTkNbn2A73qVJPlpkUo.jpg','https://image.tmdb.org/t/p/original/9KKT8qPAII0VJMpviThOTMLN0Wt.jpg','A war-hardened Crusader and his Moorish commander mount an audacious revolt against the corrupt English crown.',NULL,NULL,8.2119,5.9,0,8.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(733,23759,'tt1020558',NULL,'Centurion','Centurion','movie',2010,'https://image.tmdb.org/t/p/w500/9ZdfrcP2QCqoRSk7JF06tDWtrhP.jpg','https://image.tmdb.org/t/p/original/idcccRSENk7fv4aRMHo7BY6jHoo.jpg','Britain, A.D. 117. Quintus Dias, the sole survivor of a Pictish raid on a Roman frontier fort, marches north with General Virilus'' legendary Ninth Legion, under orders to wipe the Picts from the face of the Earth and destroy their leader, Gorlacon.',NULL,NULL,3.9948,6.235,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(734,2310,'tt0442933',NULL,'Beowulf','Beowulf','movie',2007,'https://image.tmdb.org/t/p/w500/7QsWYyJAV97N9jOh21pdRIqJeJq.jpg','https://image.tmdb.org/t/p/original/lIruQxRCxw5ZI3CmBL6VxwpKtUe.jpg','A 6th-century Scandinavian warrior named Beowulf embarks on a mission to slay the man-like ogre, Grendel.',NULL,NULL,4.3329,5.918,0,11.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(735,4517,'tt0414055',NULL,'Elizabeth: The Golden Age','Elizabeth: The Golden Age','movie',2007,'https://image.tmdb.org/t/p/w500/oBQ64TyPEINgVpwKWriv3QsIDJb.jpg','https://image.tmdb.org/t/p/original/sRx1eyBP8ydHQixz5ejV09YVZrn.jpg','When Queen Elizabeth''s reign is threatened by ruthless familial betrayal and Spain''s invading army, she and her shrewd adviser must act to safeguard the lives of her people.',NULL,NULL,4.5142,6.716,0,11.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(736,375262,'tt5083738',NULL,'The Favourite','The Favourite','movie',2018,'https://image.tmdb.org/t/p/w500/cwBq0onfmeilU5xgqNNjJAMPfpw.jpg','https://image.tmdb.org/t/p/original/iSskYDN193CJfTbSpFfscSwZ9Sx.jpg','England, early 18th century. The close relationship between Queen Anne and Sarah Churchill is threatened by the arrival of Sarah''s cousin, Abigail Hill, resulting in a bitter rivalry between the two cousins to be the Queen''s favourite.',NULL,NULL,3.6022,7.488,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(737,274857,'tt1972591',NULL,'King Arthur: Legend of the Sword','King Arthur: Legend of the Sword','movie',2017,'https://image.tmdb.org/t/p/w500/9kKXH6eJpzoFGhCbTN3FVwSQK3n.jpg','https://image.tmdb.org/t/p/original/sVkjgKq8cwKm95LCyfrLldLbQIG.jpg','When the child Arthur’s father is murdered, Vortigern, Arthur’s uncle, seizes the crown. Robbed of his birthright and with no idea who he truly is, Arthur comes up the hard way in the back alleys of the city. But once he pulls the sword Excalibur from the stone, his life is turned upside down and he is forced to acknowledge his true legacy... whether he likes it or not.',NULL,NULL,7.8835,6.557,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(738,665,'tt0052618',NULL,'Ben-Hur','Ben-Hur','movie',1959,'https://image.tmdb.org/t/p/w500/m4WQ1dBIrEIHZNCoAjdpxwSKWyH.jpg','https://image.tmdb.org/t/p/original/nk5gq5rNLBJiHvNGMRT6I9VRQX7.jpg','In ancient Judea, a Jewish aristocrat opposing Roman occupation of his homeland reunites with his childhood friend, now a Roman commander — setting in motion a saga of betrayal, adventure, tragedy, revenge, and faith.',NULL,NULL,8.3029,7.89,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(739,11834,'tt0076221',NULL,'Jabberwocky','Jabberwocky','movie',1977,'https://image.tmdb.org/t/p/w500/kprcqmFxWPU45L1ZnMXO5yPPMVA.jpg','https://image.tmdb.org/t/p/original/hMtePcTyWLQjBbujHd4kiquQcZ3.jpg','After the death of his father, young Dennis Cooper goes to town where he has to pass several adventures. The town and the whole kingdom is threatened by a terrible monster called ''Jabberwocky''. Will Dennis make his fortune? Is anyone brave enough to defeat the monster?',NULL,NULL,3.1785,6.025,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(740,11527,'tt0082348',NULL,'Excalibur','Excalibur','movie',1981,'https://image.tmdb.org/t/p/w500/cTWF6zkr5mUOnheowKODIijWYcN.jpg','https://image.tmdb.org/t/p/original/mrabn7LREC8HOBBUyQIXZsQvWk3.jpg','Arthur fulfills his fate by bringing together the Knights of the Round Table at Camelot and unifying the country. However, this flawed monarch faces greater tests ahead in pursuit of love, the Holy Grail, and his nation''s survival.',NULL,NULL,4.7413,7.0,0,2.18591666666666668e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(741,55848,'tt0071737',NULL,'Lancelot of the Lake','Lancelot du Lac','movie',1974,'https://image.tmdb.org/t/p/w500/mF5BQro2PC7YG4XY6i70jwXOzbl.jpg','https://image.tmdb.org/t/p/original/rM3lahhi1NnqErDb1Gt8xwCYlw7.jpg','Having failed in their quest for the Holy Grail, the knights of the Round Table return to Camelot, their number reduced to a mere handful. Seeing a rift developing between Lancelot and Mordred, Arthur urges his knights to bury their differences and become friends. However, the king is unaware that Lancelot is having an affair with his queen, Guinevere. Lancelot is torn between his duty to his king and his love for the queen, whilst Mordred is determined to use his infidelity to destroy him.',NULL,NULL,1.9757,6.2,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(742,25360,'tt0056112',NULL,'Jack the Giant Killer','Jack the Giant Killer','movie',1962,'https://image.tmdb.org/t/p/w500/nQYitRN2Wyy2sf8VQ6AvWBaVB2z.jpg','https://image.tmdb.org/t/p/original/6h3rZC93z8MowSokvI5EyJzhmnZ.jpg','The terrible and trecherous Pendragon plans to gain the throne of Cornwall by getting the king to abdicate and to marry his lovely daughter. To help him he has his dreadful witches in his castle and his almost unstoppable sorcery. A giant under his control abducts the princess, but on the way home with her the giant meets farming lad Jack who slays him. This is only the beginning.',NULL,NULL,1.5142,6.554,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(743,848,'tt0082288',NULL,'Dragonslayer','Dragonslayer','movie',1981,'https://image.tmdb.org/t/p/w500/92VXAEwbjebYqTeUa7uX5bBtDuD.jpg','https://image.tmdb.org/t/p/original/wbNKvMdPgOjrsydymIXxHLqIlOZ.jpg','A sorcerer and his apprentice are on a mission to kill an evil dragon to save the King’s daughter from being sacrificed according to a pact that the King himself made with the dragon to protect his kingdom.',NULL,NULL,2.8235,6.5,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(744,276907,'tt3569230',NULL,'Legend','Legend','movie',2015,'https://image.tmdb.org/t/p/w500/4shf5Alq4KWCKqrAAQe0JGJHYp5.jpg','https://image.tmdb.org/t/p/original/v8zOcynvSd6IW3FzZrvst2HJ53s.jpg','Suave, charming and volatile, Reggie Kray and his unstable twin brother Ronnie start to leave their mark on the London underworld in the 1960s. Using violence to get what they want, the siblings orchestrate robberies and murders while running nightclubs and protection rackets. With police Detective Leonard "Nipper" Read hot on their heels, the brothers continue their rapid rise to power and achieve tabloid notoriety.',NULL,NULL,6.3103,7.055,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(745,5256,'tt0244353',NULL,'The Mists of Avalon','The Mists of Avalon','tv',2001,'https://image.tmdb.org/t/p/w500/iVEbAgsYBVwKH8goTkUVd59fIWB.jpg','https://image.tmdb.org/t/p/original/qJUYXYijCL9Q8QkFhjvVBj6dvcM.jpg','The Mists of Avalon is a 2001 miniseries based on the novel of the same name by Marion Zimmer Bradley. It was produced by American cable channel TNT and directed by Uli Edel.',NULL,NULL,2.5498,6.73,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(746,13460,'tt0483607',NULL,'Doomsday','Doomsday','movie',2008,'https://image.tmdb.org/t/p/w500/cKUmTyXgmhv8cMRCY9RYTKcAeTn.jpg','https://image.tmdb.org/t/p/original/2GmnhciVW262POiTCx43TTSvys3.jpg','The lethal Reaper virus spreads throughout Britain—infecting millions and killing hundreds of thousands. Authorities brutally and successfully quarantine the country but, three decades later, the virus resurfaces in a major city. An elite group of specialists is urgently dispatched into the still-quarantined country to retrieve a cure by any means necessary. Shut off from the rest of the world, the unit must battle through a landscape that has become a waking nightmare.',NULL,NULL,3.1101,5.938,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(747,31911,'tt1355642',NULL,'Fullmetal Alchemist: Brotherhood','鋼の錬金術師 FULLMETAL ALCHEMIST','tv',2009,'https://image.tmdb.org/t/p/w500/5ZFUEOULaVml7pQuXxhpR2SmVUw.jpg','https://image.tmdb.org/t/p/original/2UG177tWHy7xRmMKWJHB7nAUmKd.jpg','Disregard for alchemy’s laws ripped half of Edward Elric’s limbs from his body and left his brother Alphonse’s soul clinging to a suit of armor. To restore what was lost, the brothers seek the Philosopher’s Stone. Enemies and allies – the corrupt military, the Homunculi, and foreign alchemists – will alter the Elric brothers course, but their purpose will remain unchanged and their bond unbreakable.',NULL,NULL,59.6287,8.712,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(748,61752,'tt0495212',NULL,'Hellsing Ultimate','ヘルシング アルティメット','tv',2006,'https://image.tmdb.org/t/p/w500/fum0tvBuVVeofFoHI0IXHgrzKEa.jpg','https://image.tmdb.org/t/p/original/PZEdudP5M4FBz5cPoQ4rHCejLj.jpg','For over a century, the mysterious Hellsing Organization has been secretly protecting the British Empire from the undead. When Sir Integra Hellsing succeeded as the head of the organization, she also inherited the ultimate weapon against these supernatural enemies: Alucard, a rogue vampire possessing mysterious and frightening powers. Now, Hellsing must deal with a more dangerous threat than vampires.',NULL,NULL,8.0247,8.44,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(749,25623,'tt0076162',NULL,'House','ハウス','movie',1977,'https://image.tmdb.org/t/p/w500/myMnHnG6kxYaQYknnW76VCHBpYT.jpg','https://image.tmdb.org/t/p/original/ylHdeFztJTQorRtePsLyNt69msB.jpg','Hoping to find a sense of connection to her late mother, Gorgeous takes a trip with her friends to visit her aunt''s ancestral house in the countryside. The girls soon discover that there is more to the old house than meets the eye.',NULL,NULL,3.195,7.327,0,1.23766666666666651e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(750,27425,'tt0140384',NULL,'Blind Beast','盲獣','movie',1969,'https://image.tmdb.org/t/p/w500/klTJKS9iWeEi7XMP6tYvDNIU2yA.jpg','https://image.tmdb.org/t/p/original/eL7DQB1gZZwefgcOfMHPyYAPwUO.jpg','A blind sculptor kidnaps an artists'' model and imprisons her in his warehouse studio – a shadowland of perverse monuments to the female form. Here a deranged passion play of sensual and sexual obsession is acted out in world where sight is replaced by touch.',NULL,NULL,1.2945,6.51,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(751,27459,'tt0067350',NULL,'Little Murders','Little Murders','movie',1971,'https://image.tmdb.org/t/p/w500/i2QOxh6pwgy1MUF4bBYDVdPwbWa.jpg','https://image.tmdb.org/t/p/original/bfJOITZlFbxwHtgZPHa6x8z4Q4y.jpg','A young nihilistic New Yorker copes with pervasive urban violence, obscene phone calls, rusty water pipes, electrical blackouts, paranoia, and ethnic-racial conflict during a typical summer of the 1970s.',NULL,NULL,1.0599,6.722,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(752,1019018,'tt23145828',NULL,'Heck','Heck','movie',2020,'https://image.tmdb.org/t/p/w500/2x6lWLQ1qXkWOC2T0tsHXAPq1bz.jpg','https://image.tmdb.org/t/p/original/bjxsnzhlJG7b7XnE6gtAq9nEhmW.jpg','A little kid wakes up in the middle of night to the sound of his mom''s television blaring.',NULL,NULL,0.7126,6.8,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(753,11481,'tt0059646',NULL,'Repulsion','Repulsion','movie',1965,'https://image.tmdb.org/t/p/w500/dtyCKEPLqv9wxyVazL4b843vtUb.jpg','https://image.tmdb.org/t/p/original/5rbPwIdEZTyLTkpAgvGdacgCr7T.jpg','Beautiful young manicurist Carole suffers from androphobia (the pathological fear of interaction with men). When her sister and roommate, Helen, leaves their London flat to go on an Italian holiday with her married boyfriend, Carole withdraws into her apartment. She begins to experience frightful hallucinations, her fear gradually mutating into madness.',NULL,NULL,3.1747,7.373,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(754,18352,'tt0063633',NULL,'The Cremator','Spalovač mrtvol','movie',1969,'https://image.tmdb.org/t/p/w500/9or2Jzw9HOE4gp9niwXBkZdpTVx.jpg','https://image.tmdb.org/t/p/original/fMjdPM3pdc7T0NVoVqXtXEuJvG2.jpg','In 1930s Prague, a Czech cremator who firmly believes cremation relieves one from earthly suffering is drawn inexorably to Nazism.',NULL,NULL,1.512,7.8,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(755,20620,'tt0060955',NULL,'Seconds','Seconds','movie',1966,'https://image.tmdb.org/t/p/w500/5G3q3OvulFTnFdiouaZdD8wjtIc.jpg','https://image.tmdb.org/t/p/original/guOylbnmrrbylOcxuJ2xpnPR3Mz.jpg','An unhappy middle-aged banker agrees to a procedure that will fake his death and give him a completely new look and identity; one that comes with its own price.',NULL,NULL,2.8777,7.335,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(756,2297,'tt0102181',NULL,'Kafka','Kafka','movie',1991,'https://image.tmdb.org/t/p/w500/eQh6IlLbQzqqgedwGcj3l9Ex3xJ.jpg','https://image.tmdb.org/t/p/original/sMIxDDigJfUhNsaiEBv96JILrU5.jpg','After a colleague is murdered, insurance worker Kafka gets embroiled in an underground group who are attempting to thwart a secret organization that controls the major events in society.',NULL,NULL,1.2754,6.4,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(757,69703,'tt0108388',NULL,'The Trial','The Trial','movie',1993,'https://image.tmdb.org/t/p/w500/t3nlCW5pGQJSdLXlq5rwZFNaggb.jpg','https://image.tmdb.org/t/p/original/h30NyZ2e2MobAoJXUt8ywn5BFTz.jpg','Joseph K. awakes one morning, to find two strange men in his room, telling him he has been arrested. Joseph is not told what he is charged with, and despite being "arrested," is allowed to remain free and go to work. But despite the strange nature of his arrest, Joseph soon learns that his trial, however odd, is very real, and tries desperately to spare himself from the court''s judgement.',NULL,NULL,0.9652,5.986,0,1.10133333333333318e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(758,9792,'tt0454841',NULL,'The Hills Have Eyes','The Hills Have Eyes','movie',2006,'https://image.tmdb.org/t/p/w500/w391167zrbCOljQfJk5vlOmcDjU.jpg','https://image.tmdb.org/t/p/original/vrFI0I3M8ROZduj9XbFDoQKZyao.jpg','Based on Wes Craven''s 1977 suspenseful cult classic, The Hills Have Eyes is the story of a family road trip that goes terrifyingly awry when the travelers become stranded in a government atomic zone. Miles from nowhere, the Carter family soon realizes the seemingly uninhabited wasteland is actually the breeding ground of a blood-thirsty mutant family...and they are the prey.',NULL,NULL,7.9474,6.478,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(759,626,'tt0020530',NULL,'Un Chien Andalou','Un chien andalou','movie',1929,'https://image.tmdb.org/t/p/w500/obvE7ElAvCUhKtWFwDSvNbPw9PV.jpg','https://image.tmdb.org/t/p/original/jQywhaFDVLPlFw864Bgw5eNtWfi.jpg','Un Chien Andalou is an European avant-garde surrealist film, a collaboration between director Luis Buñuel and Salvador Dali.',NULL,NULL,2.626,7.401,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(760,4593,'tt0068361',NULL,'The Discreet Charm of the Bourgeoisie','Le Charme discret de la bourgeoisie','movie',1972,'https://image.tmdb.org/t/p/w500/zN4ILX2x64PvT2jIOAHXxCOi5WA.jpg','https://image.tmdb.org/t/p/original/z6NI6n5MvQZMZJbXKLiyFl1yDeA.jpg','In Luis Buñuel’s deliciously satiric masterpiece, an upper-class sextet sits down to dinner but never eats, their attempts continually thwarted by a vaudevillian mixture of events both actual and imagined.',NULL,NULL,2.8709,7.5,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(761,57283,'tt0013257',NULL,'Häxan','Häxan','movie',1922,'https://image.tmdb.org/t/p/w500/3LtaPLlwlA5HX2FjqAb8lsaBI8P.jpg','https://image.tmdb.org/t/p/original/gZwQip2KQRDNZZOEDe0Yi25tW9Z.jpg','Grave robbing, torture, possessed nuns, and a satanic Sabbath: Benjamin Christensen''s legendary film uses a series of dramatic vignettes to explore the scientific hypothesis that the witches of the Middle Ages suffered the same hysteria as turn-of-the-century psychiatric patients. But the film itself is far from serious-- instead it''s a witches'' brew of the scary, gross, and darkly humorous.',NULL,NULL,2.0399,7.612,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(762,27361,'tt0072709',NULL,'Black Moon','Black Moon','movie',1975,'https://image.tmdb.org/t/p/w500/tsbauHYC5E7YK7UeMl3FM4U9xhK.jpg','https://image.tmdb.org/t/p/original/luRLohOI29820ZKUgPg84wquMqi.jpg','There is a global gender war between men and women. A teenage girl tries to escape this reality and arrives at a hidden place where a strange unicorn lives with a family: sister, brother, many children and an old, bedridden woman who stays in contact with the world through her radio.',NULL,NULL,1.4058,6.0,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(763,3112,'tt0048424',NULL,'The Night of the Hunter','The Night of the Hunter','movie',1955,'https://image.tmdb.org/t/p/w500/rBka0nFWiHxabHRLr0KfIA8Yiaq.jpg','https://image.tmdb.org/t/p/original/7cVEnb4Pth3STa7YfVOk9RtzDLB.jpg','In Depression-era West Virginia, a serial-killing preacher hunts two young children who know the whereabouts of a stash of money.',NULL,NULL,4.3916,7.9,0,1.16833333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(764,805,'tt0063522',NULL,'Rosemary''s Baby','Rosemary''s Baby','movie',1968,'https://image.tmdb.org/t/p/w500/uYgvlHceRFjAFbsNeMInYcLZLUb.jpg','https://image.tmdb.org/t/p/original/qszuXKhzYR24oRpsmh7eZaPbvL8.jpg','A young couple, Rosemary and Guy, moves into an infamous New York apartment building, known by frightening legends and mysterious events, with the purpose of starting a family.',NULL,NULL,6.9622,7.819,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(765,169314,'tt2095004',NULL,'Where the Dead Go to Die','Where the Dead Go to Die','movie',2012,'https://image.tmdb.org/t/p/w500/jJsGWRJ0qGgO5k8o3O1STGwxdzS.jpg','https://image.tmdb.org/t/p/original/9gtZvgMs1bmaUDJ0ITpO6i0g7ZE.jpg','A troubled group of children living on the same block are haunted by a talking dog named Labby who brings them on surreal hell-rides between different dimensions and time periods.',NULL,NULL,0.8156,5.6,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(766,186166,'tt0293777',NULL,'The Burning Crucible','Le Brasier ardent','movie',1923,'https://image.tmdb.org/t/p/w500/zsm3qeAPUNbRZjeeG9mGQSjisBb.jpg','https://image.tmdb.org/t/p/original/1iBss5lTA5YKExRxufT6NfJ2hNc.jpg','A woman, named simply "Elle" and her husband, a wealthy industrialist, are not on the best of terms. While she enjoys the way he caters to her every whim, she wonders whether he really loves her. He, on the other hand, torments himself by imagining rivals. One morning she awakens from a nightmare in which she has been pursued by a man in various guises, who turns out to be the famous Detective Z, whose memoirs she has been reading. When she and her husband quarrel over leaving Paris permanently for a country estate, he goes to the "Trouve Tout" Agency and hires, of all people, Detective Z, to win back her affection.',NULL,NULL,0.1897,6.733,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(767,106,'tt0093773',NULL,'Predator','Predator','movie',1987,'https://image.tmdb.org/t/p/w500/aN3cdjIK70KGmD84et8MMblU87Q.jpg','https://image.tmdb.org/t/p/original/YL3GPOiDcNraIJOVDCZsoOBoDy.jpg','A team of elite commandos on a secret mission in a Central American jungle come to find themselves hunted by an extraterrestrial warrior.',NULL,NULL,16.3779,7.57,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(768,16093,'tt0055830',NULL,'Carnival of Souls','Carnival of Souls','movie',1962,'https://image.tmdb.org/t/p/w500/AdbQsFB8pS090l0NO3uBtLZy2zw.jpg','https://image.tmdb.org/t/p/original/esIoQw7VaykfHsw6fx2VltZ1R7U.jpg','Mary Henry ends up the sole survivor of a fatal car accident through mysterious circumstances. Trying to put the incident behind her, she moves to Utah and takes a job as a church organist. But her fresh start is interrupted by visions of a fiendish man. As the visions begin to occur more frequently, Mary finds herself drawn to the deserted carnival on the outskirts of town. The strangely alluring carnival may hold the secret to her tragic past.',NULL,NULL,2.4097,6.94,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(769,18333,'tt0063759',NULL,'Hour of the Wolf','Vargtimmen','movie',1968,'https://image.tmdb.org/t/p/w500/jSqTnEP1x1OcOglqrInYvGSF1tL.jpg','https://image.tmdb.org/t/p/original/pEHxojfy6EGOZ3e7TU9lREpWvNN.jpg','While vacationing on a remote German island with his younger pregnant wife, an artist has an emotional breakdown while confronting his repressed desires.',NULL,NULL,2.0685,7.429,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(770,293670,'tt5215952',NULL,'The Wailing','곡성','movie',2016,'https://image.tmdb.org/t/p/w500/RbymxgEM5SpDfO2Io2JMFG10Vi.jpg','https://image.tmdb.org/t/p/original/9qxBNfI1QFbiZS62fsgaUd563t2.jpg','A stranger arrives in a little village and soon after a mysterious sickness starts spreading. A policeman is drawn into the incident and is forced to solve the mystery in order to save his daughter.',NULL,NULL,6.2092,7.372,0,1.55233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(771,4174,'tt0038109',NULL,'Spellbound','Spellbound','movie',1945,'https://image.tmdb.org/t/p/w500/dPAox7jGScLBvxKLeRptJIBF7v.jpg','https://image.tmdb.org/t/p/original/dYv4io2HcRMxFGgnErTbvpqSGXe.jpg','When Dr. Anthony Edwardes arrives at a Vermont mental hospital to replace the outgoing hospital director, Dr. Constance Peterson, a psychoanalyst, discovers Edwardes is actually an impostor. The man confesses that the real Dr. Edwardes is dead and fears he may have killed him, but cannot recall anything. Dr. Peterson, however is convinced his impostor is innocent of the man''s murder, and joins him on a quest to unravel his amnesia through psychoanalysis.',NULL,NULL,2.979,7.394,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(772,345,'tt0120663',NULL,'Eyes Wide Shut','Eyes Wide Shut','movie',1999,'https://image.tmdb.org/t/p/w500/knEIz1eNGl5MQDbrEAVWA7iRqF9.jpg','https://image.tmdb.org/t/p/original/aC6wW62V6b0csr5iUnbOjYAqfhg.jpg','After Dr. Bill Harford''s wife, Alice, admits to having sexual fantasies about a man she met, Bill becomes obsessed with having a sexual encounter. He discovers an underground sexual group and attends one of their meetings -- and quickly discovers that he is in over his head.',NULL,NULL,15.4256,7.486,0,14.248,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(773,1090,'tt0139809',NULL,'The Thirteenth Floor','The Thirteenth Floor','movie',1999,'https://image.tmdb.org/t/p/w500/7oaie3ZBc9UuWZLF24crro1pone.jpg','https://image.tmdb.org/t/p/original/nJ0jz1J3zNja31UEMeklhgFeMw5.jpg','In Los Angeles, a wealthy man, known as Mr. Fuller, discovers a shocking secret about the world he lives in. Fearing for his life, he leaves a desperate message for a friend of his in the most unexpected place.',NULL,NULL,4.7863,7.077,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(774,97,'tt0084827',NULL,'Tron','Tron','movie',1982,'https://image.tmdb.org/t/p/w500/jigY9B6TKz4qlfikZcd18qtzTK4.jpg','https://image.tmdb.org/t/p/original/vUmeBHiGp5r2ydd8aEvbNLamTVD.jpg','When brilliant video game maker Flynn hacks the mainframe of his ex-employer, he is beamed inside an astonishing digital world and becomes part of the very game he is designing. In his mission through cyberspace, Flynn matches wits with a maniacal Master Control Program and teams up with Tron, a security measure created to bring balance to the digital environment.',NULL,NULL,5.2397,6.63,0,12.36,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(775,90652,'tt0087129',NULL,'Decoder','Decoder','movie',1984,'https://image.tmdb.org/t/p/w500/lHxPGSwDTgyuw8sivGl81vn3e1k.jpg','https://image.tmdb.org/t/p/original/lppNOAle6eRGnn4nuwjw6auwpDL.jpg','F.M. discovers that different sonic frequencies induce different patterns of behaviour in listeners, first in his own studio but later in the local "H-Burger" restaurant where the passive muzak appears to be wiping people''s emotions.',NULL,NULL,0.5945,6.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(776,19596,'tt0087197',NULL,'Electric Dreams','Electric Dreams','movie',1984,'https://image.tmdb.org/t/p/w500/2XWmN9EXYrHSRDvkAV9VhvngHGn.jpg','https://image.tmdb.org/t/p/original/bMLQAoEtRMi36wq66qXyJ17yVQd.jpg','Miles Harding buys a state-of-the-art computer that starts expressing conscious thought and emotion after an interaction with spilled champagne. Things begin getting out of hand when both Miles and Edgar, the computer, fall in love with beautiful neighbor Madeline Robistat.',NULL,NULL,2.169,6.342,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(777,5548,'tt0093870',NULL,'RoboCop','RoboCop','movie',1987,'https://image.tmdb.org/t/p/w500/esmAU0fCO28FbS6bUBKLAzJrohZ.jpg','https://image.tmdb.org/t/p/original/xcaX6BZ1JUPSVMH2gBkWIckLLaA.jpg','In a violent, near-apocalyptic Detroit, evil corporation Omni Consumer Products wins a contract from the city government to privatize the police force. To test their crime-eradicating cyborgs, the company leads street cop Alex Murphy into an armed confrontation with crime lord Boddicker so they can use his body to support their untested RoboCop prototype. But when RoboCop learns of the company''s nefarious plans, he turns on his masters.',NULL,NULL,7.9359,7.363,0,1.26933333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(778,860,'tt0086567',NULL,'WarGames','WarGames','movie',1983,'https://image.tmdb.org/t/p/w500/zZ1rN4LoPxKNfAp67Xl300WxVeD.jpg','https://image.tmdb.org/t/p/original/qtamfYGFfDLfGRcucx1zNwohRts.jpg','High school student David Lightman has a talent for hacking. But while trying to hack into a computer system to play unreleased video games, he unwittingly taps into the Department of Defense''s war computer and initiates a confrontation of global proportions. Together with his friend and a wizardly computer genius, David must race against time to outwit his opponent and prevent a nuclear Armageddon.',NULL,NULL,4.8136,7.067,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(779,2605,'tt0091949',NULL,'Short Circuit','Short Circuit','movie',1986,'https://image.tmdb.org/t/p/w500/e3eimdUK6lLe0iaSlLrYVQF3yeL.jpg','https://image.tmdb.org/t/p/original/fytpsMuKVm8GynH0n3DCzIBp092.jpg','After a lightning bolt zaps a robot named Number 5, the lovable machine starts to think he''s human and escapes the lab. Hot on his trail is his designer, Newton, who hopes to get to Number 5 before the military does. In the meantime, a spunky animal lover mistakes the robot for an alien and takes him in, teaching her new guest about life on Earth.',NULL,NULL,4.127,6.65,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(780,165,'tt0096874',NULL,'Back to the Future Part II','Back to the Future Part II','movie',1989,'https://image.tmdb.org/t/p/w500/hQq8xZe5uLjFzSBt4LanNP7SQjl.jpg','https://image.tmdb.org/t/p/original/w6tPctxWAsHoQXeKxxNOT6lYKpx.jpg','Marty and Doc are at it again as the time-traveling duo head to 2015 to nip some McFly family woes in the bud. But things go awry thanks to bully Biff Tannen and a pesky sports almanac. In a last-ditch attempt to set things straight, Marty finds himself bound for 1955 and face to face with his teenage parents -- again.',NULL,NULL,9.5081,7.784,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(781,11814,'tt0090305',NULL,'Weird Science','Weird Science','movie',1985,'https://image.tmdb.org/t/p/w500/jaEauZd2joSAKn42D83gm3S0y3F.jpg','https://image.tmdb.org/t/p/original/2oaTLhpbnX8kfrlJTostT27uL5j.jpg','Two unpopular teenagers, Gary and Wyatt, fail at all attempts to be accepted by their peers. Their desperation to be liked leads them to "create" a woman via their computer. Their living and breathing creation is a gorgeous woman, Lisa, whose purpose is to boost their confidence level by putting them into situations which require Gary and Wyatt to act like men.',NULL,NULL,4.409,6.5,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(782,11309,'tt0099740',NULL,'Hardware','Hardware','movie',1990,'https://image.tmdb.org/t/p/w500/ybauOsdo6ColZ1WsALqIYjpUg4X.jpg','https://image.tmdb.org/t/p/original/nC1qaINaRBY1crPCQoFVPhSrq16.jpg','Mark 13 is a government-built killing machine programmed with artificial intelligence, able to repair and recharge itself from any energy source. Through a series of coincidences, the cyborg''s head ends up in the home of a sculptress as a bizarre Christmas present from her boyfriend. Once inside its new home, the cyborg promptly reconstructs the rest of its body using a variety of household utensils and proceeds to go on a murderous rampage.',NULL,NULL,4.3516,5.924,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(783,261560,'tt0115431',NULL,'Haru','(ハル)','movie',1996,'https://image.tmdb.org/t/p/w500/rzXoCe9Cjw30G76FGwW51tPP2RR.jpg','https://image.tmdb.org/t/p/original/q9aWJCH5qEDIueBBVZlzdDCZYBw.jpg','A young Tokyo businessman joins an online movie forum and develops a special bond with one of its members through back and forth e-mails.',NULL,NULL,0.9016,7.9,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(784,115782,'tt2357129',NULL,'Jobs','Jobs','movie',2013,'https://image.tmdb.org/t/p/w500/mOyZ0UAWaOJartFq2G3Cv0soFtQ.jpg','https://image.tmdb.org/t/p/original/k47gSbr0bqEgDAEedfyV2mAw5YU.jpg','The story of Steve Jobs'' ascension from college dropout into one of the most revered creative entrepreneurs of the 20th century.',NULL,NULL,2.2475,6.131,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(785,9886,'tt0113481',NULL,'Johnny Mnemonic','Johnny Mnemonic','movie',1995,'https://image.tmdb.org/t/p/w500/iH8Jgi8qvb7pnBfI8fVGaUbyRna.jpg','https://image.tmdb.org/t/p/original/7FRYVIF2hnh1IbPtqMgF5iygdjz.jpg','In a dystopian 2021, Johnny is a data trafficker who has an implant that allows him to securely store data too sensitive for regular computer networks. On one delivery run, he accepts a package that not only exceeds the implant''s safety limits—and will kill him if the data is not removed in time—but also contains information far more important and valuable than he had ever imagined. On a race against time, he must avoid the assassins sent to kill him and remove the data before it, too, ends his life.',NULL,NULL,3.4048,5.763,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(786,14237,'tt0109327',NULL,'Brainscan','Brainscan','movie',1994,'https://image.tmdb.org/t/p/w500/5JqamPZC7W5rzRNweMGhqltcsIV.jpg','https://image.tmdb.org/t/p/original/wsyVTV1KeQkIscporZdCCWv8kjP.jpg','A lonely teenage horror fan and video gamer plays a new immersive and hypnotic computer game where he becomes a psychopathic killer, but when he emerges, he finds that the murder has actually happened.',NULL,NULL,1.4569,6.2,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(787,16437,'tt0106639',NULL,'Cyborg 2','Cyborg 2','movie',1993,'https://image.tmdb.org/t/p/w500/hYNJ4KNMVaVgR5JAqC5qlgbJEmJ.jpg','https://image.tmdb.org/t/p/original/wyF3MzxcLZyJnEYZsp6XdPvpsdc.jpg','In the year 2074, the cybernetics market is dominated by two rival companies: USA''s Pinwheel Robotics and Japan''s Kobayashi Electronics. Cyborgs are commonplace, used for anything from soldiers to prostitutes. Casella Reese is a prototype cyborg developed for corporate espionage and assassination. She is filled with a liquid explosive called Glass Shadow. Pinwheel plans to eliminate the entire Kobayashi board of directors by using Casella',NULL,NULL,1.3436,4.369,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(788,18491,'tt0169858',NULL,'Neon Genesis Evangelion: The End of Evangelion','新世紀エヴァンゲリオン劇場版 Air／まごころを、君に','movie',1997,'https://image.tmdb.org/t/p/w500/j6G24dqI4WgUtChhWjfnI4lnmiK.jpg','https://image.tmdb.org/t/p/original/AfyuI3glMCBDFmNPj9PY6DwbgGp.jpg','SEELE orders an all-out attack on NERV, aiming to destroy the Evas before Gendo can advance his own plans for the Human Instrumentality Project. Shinji is pushed to the limits of his sanity as he is forced to decide the fate of humanity.',NULL,NULL,12.7598,8.3,0,11.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(789,1483,'tt0101420',NULL,'Begotten','Begotten','movie',1991,'https://image.tmdb.org/t/p/w500/y8GbJny4bBUimJxUGXqq3l3k4OV.jpg','https://image.tmdb.org/t/p/original/GtblqNxBX0fUbLVNhempSYwCWe.jpg','Begotten is the creation myth brought to life, the story of no less than the violent death of God and the (re)birth of nature on a barren earth.',NULL,NULL,4.45,5.9,0,17.7125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(790,1254896,'tt29244917',NULL,'Beware the Boogeyman','Beware the Boogeyman','movie',2024,'https://image.tmdb.org/t/p/w500/2Hm5IP9lPW9DfwNSGkghCEMeUBK.jpg','https://image.tmdb.org/t/p/original/yNeRryoPm5354Qjb27OFZskf85d.jpg','For her first day of orientation, Dr. Tristian Mackenzie makes her way to the Silverdale Psychiatric Hospital for the criminally insane, where she learns of the strange series of cases from the similarly strange Dr. Moon.',NULL,NULL,43.6262,4.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(791,82507,'tt1922777',NULL,'Sinister','Sinister','movie',2012,'https://image.tmdb.org/t/p/w500/nzx10sca3arCeYBAomHan4Q6wa1.jpg','https://image.tmdb.org/t/p/original/jovIEk4cAxWmA2dBcPrfhn3jzYN.jpg','True-crime writer Ellison Oswalt is in a slump; he hasn''t had a best seller in more than 10 years and is becoming increasingly desperate for a hit. So, when he discovers the existence of a snuff film showing the deaths of a family, he vows to solve the mystery. He moves his own family into the victims'' home and gets to work. However, when old film footage and other clues hint at the presence of a supernatural force, Ellison learns that living in the house may be fatal.',NULL,NULL,10.2378,6.875,0,1.55133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(792,345911,'tt4786282',NULL,'Lights Out','Lights Out','movie',2016,'https://image.tmdb.org/t/p/w500/8BnElzAQQpp7ZgdJJiAe1diomr4.jpg','https://image.tmdb.org/t/p/original/xxyAStrE7vVeKto3dGDAKAZRM68.jpg','Rebecca must unlock the terror behind her little brother''s experiences that once tested her sanity, bringing her face to face with a supernatural spirit attached to their mother.',NULL,NULL,3.9584,6.375,0,15.595,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(793,1232827,'tt10236164',NULL,'The Girl with the Needle','Pigen med nålen','movie',2024,'https://image.tmdb.org/t/p/w500/2xkyx8v9G3ePxe1IcFugFQkXHzQ.jpg','https://image.tmdb.org/t/p/original/uwACVNL5OpiI3oT72DVGxnU4SRV.jpg','Struggling to survive in post-WWI Copenhagen, a newly unemployed and pregnant young woman is taken in by a charismatic elder to help run an underground adoption agency. The two form an unexpected bond, until a sudden discovery changes everything.',NULL,NULL,2.1872,7.559,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(794,103689,'tt1754367',NULL,'Post Tenebras Lux','Post Tenebras Lux','movie',2012,'https://image.tmdb.org/t/p/w500/isyc1Hk0L3neLoeWhP7Zktj7ftD.jpg','https://image.tmdb.org/t/p/original/udEbtrxgQmP5rBtcWQRjQaWpL4w.jpg','Juan and his urban family live in the Mexican countryside, where they enjoy and suffer a world apart. And nobody knows if these two worlds are complimentary or if they strive to eliminate one another.',NULL,NULL,0.6385,6.135,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(795,551942,'tt6364564',NULL,'Rabbits','Rabbits','movie',NULL,'https://image.tmdb.org/t/p/w500/tscE2V4CFgOPVgbgENqn7xn43qW.jpg',NULL,'"Set in turn-of-the-century Kansas, an isolated farmer finds the body of a young woman and uses it to get over the death of his wife."',NULL,NULL,0.2263,0.0,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(796,249442,'tt0343687',NULL,'The French Doors','The French Doors','movie',2002,'https://image.tmdb.org/t/p/w500/oAfJWL5Xu9Q7AjBolW74f2j5VHr.jpg',NULL,'A man installs a set of French doors during a renovation. What he doesn''t know is that the doors harbour a secret. A dark secret...',NULL,NULL,0.1563,6.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(797,334536,'tt3286052',NULL,'The Blackcoat''s Daughter','The Blackcoat''s Daughter','movie',2017,'https://image.tmdb.org/t/p/w500/jO2aHAiWgQSlpAIPGZikiMDdMXx.jpg','https://image.tmdb.org/t/p/original/nGYncNCfeAccyhhdGRgj3sbexPn.jpg','Two young women at a prestigious prep school are assailed by an evil, invisible power when they''re stranded over winter break.',NULL,NULL,1.5409,5.882,0,13.9025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(798,228915,'tt2367066',NULL,'Lord of Tears','Lord of Tears','movie',2013,'https://image.tmdb.org/t/p/w500/9owSsTl4NjLXgGkgjsAyRS6LX6c.jpg','https://image.tmdb.org/t/p/original/hicKiGaDavEBjtaUOtovDF3EDps.jpg','Lord of Tears tells the story of James Findlay, a school teacher plagued by recurring nightmares of a mysterious and unsettling entity. Suspecting that his visions are linked to a dark incident in his past, James returns to his childhood home, a notorious mansion in the Scottish Highlands, where he uncovers the disturbing truth behind his dreams, and must fight to survive the brutal consequences of his curiosity.',NULL,NULL,0.438,5.344,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(799,229569,'tt21365994',NULL,'Boisvert','Boisvert','tv',2020,'https://image.tmdb.org/t/p/w500/hmjR6UfRGdTxAvxOHwsAH5BW5jC.jpg','https://image.tmdb.org/t/p/original/lnVpGf6LX6KDPD8135LfiiJxNJU.jpg','A surrealist web series concerning depression and isolation.',NULL,NULL,2.8133,7.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(800,1532610,'tt37967547',NULL,'Ink','Ink','movie',NULL,'https://image.tmdb.org/t/p/w500/ohBhmFl4bHw63ib6vZRurqXLuJ4.jpg','https://image.tmdb.org/t/p/original/yV5ybC6HHzUYCEogtFzOeUvxRYt.jpg','An explosive cinematic rollercoaster about a group of misfits and visionaries who had an idea for a new kind of news - one that would give the people what they want, and would change the face of the world we live in today.',NULL,NULL,1.3964,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(801,9479,'tt0107688',NULL,'The Nightmare Before Christmas','The Nightmare Before Christmas','movie',1993,'https://image.tmdb.org/t/p/w500/oQffRNjK8e19rF7xVYEN8ew0j7b.jpg','https://image.tmdb.org/t/p/original/dSfrsjhqC6lYe7LYDYnzWeXZmEl.jpg','Tired of scaring humans every October 31 with the same old bag of tricks, Jack Skellington, the spindly king of Halloween Town, kidnaps Santa Claus and plans to deliver shrunken heads and other ghoulish gifts to children on Christmas morning. But as Christmas approaches, Jack''s rag-doll girlfriend, Sally, tries to foil his misguided plans.',NULL,NULL,10.3267,7.834,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(802,455499,'tt6536904',NULL,'Flesh of the Void','Flesh of the Void','movie',2017,'https://image.tmdb.org/t/p/w500/1dUGDXGMp1H1L0CxEOXygCDc63T.jpg','https://image.tmdb.org/t/p/original/ucuF6bGeWFqsvIxNiRKHvdwRPB5.jpg','A visualization of what it could feel like if the act of dying was a truly horrible experience - a surreal trip through the deepest and most violent fears of the human condition.',NULL,NULL,0.2581,3.769,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(803,558504,'tt9222182',NULL,'OPERA MORTEM','OPERA MORTEM','movie',1973,'https://image.tmdb.org/t/p/w500/msmo91WhevyrUiaq6ZdDq8e3Txj.jpg','https://image.tmdb.org/t/p/original/dIcqNc0eCs0EVE5c32zLvwzY51o.jpg','OPERA MORTEM is a medium-length film with strong surrealist/dadaist influences where distorted and disturbing images are shown without a real narrative thread which could be a visual dream of death that intersects the story of a suicidal girl and a necrophiliac killer. According to some theological scholars, the film hides a metaphorical evocative code of a satanic ritual. But perhaps David Fleas only followed the manifesto of the Dadaist movement, between anarchist, nihilistic and sarcastic ideas, giving voice to the search for that absolute freedom that art demands.',NULL,NULL,0.1279,2.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(804,779,'tt0023649',NULL,'Vampyr','Vampyr - Der Traum des Allan Grey','movie',1932,'https://image.tmdb.org/t/p/w500/yt3JS5JSoZseSohYkhs6FLU9B0O.jpg','https://image.tmdb.org/t/p/original/rg3hBiQbDet8uNQkgfbpk7306p8.jpg','Allan Gray, a young man fascinated by the supernatural, goes to a small village where he feels a sinister force descending upon him. There, Allan meets an old man who asks him to protect his two daughters, for one of them has been bitten by a vampire.',NULL,NULL,0.9621,7.253,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(805,120462,'tt9064858',NULL,'Them','Them','tv',2021,'https://image.tmdb.org/t/p/w500/bJw1VZ4ACt5TnAvJbHcprzgYc1E.jpg','https://image.tmdb.org/t/p/original/nleG20xwqGsEbCEHnIRRwZmz3l6.jpg','A limited anthology series that explores terror in America.',NULL,NULL,7.557,7.57,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(806,1051896,'tt22939186',NULL,'Arcadian','Arcadian','movie',2024,'https://image.tmdb.org/t/p/w500/h4T8Xeydkw53h9uIbulYsss25UF.jpg','https://image.tmdb.org/t/p/original/9s9o9RT9Yj6nDuRJjnJm78WFoFl.jpg','In the near future, on a decimated Earth, Paul and his twin sons face terror at night when ferocious creatures awaken. When Paul is nearly killed, the boys come up with a plan for survival, using everything their father taught them to keep him alive.',NULL,NULL,7.8486,6.079,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(807,411,'tt0363771',NULL,'The Chronicles of Narnia: The Lion, the Witch and the Wardrobe','The Chronicles of Narnia: The Lion, the Witch and the Wardrobe','movie',2005,'https://image.tmdb.org/t/p/w500/iREd0rNCjYdf5Ar0vfaW32yrkm.jpg','https://image.tmdb.org/t/p/original/tuDhEdza074bA497bO9WFEPs6O6.jpg','Siblings Lucy, Edmund, Susan and Peter step through a magical wardrobe and find the land of Narnia. There, they discover a charming, once peaceful kingdom that has been plunged into eternal winter by the evil White Witch, Jadis. Aided by the wise and magnificent lion, Aslan, the children lead Narnia into a spectacular, climactic battle to be free of the Witch''s glacial powers forever.',NULL,NULL,18.5441,7.139,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(808,22538,'tt0446029',NULL,'Scott Pilgrim vs. the World','Scott Pilgrim vs. the World','movie',2010,'https://image.tmdb.org/t/p/w500/g5IoYeudx9XBEfwNL0fHvSckLBz.jpg','https://image.tmdb.org/t/p/original/6R9nT6m8wmzayV5XOQq3TRA6yZw.jpg','As bass guitarist for a garage-rock band, Scott Pilgrim has never had trouble getting a girlfriend; usually, the problem is getting rid of them. But when Ramona Flowers skates into his heart, he finds she has the most troublesome baggage of all: an army of ex-boyfriends who will stop at nothing to eliminate him from her list of suitors.',NULL,NULL,8.6624,7.485,0,15.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(809,1091,'tt0084787',NULL,'The Thing','The Thing','movie',1982,'https://image.tmdb.org/t/p/w500/tzGY49kseSE9QAKk47uuDGwnSCu.jpg','https://image.tmdb.org/t/p/original/r9leYNa8nTRCceZrZhP1DXkgKVb.jpg','A research team in Antarctica is hunted by a shape-shifting alien that assumes the appearance of its victims.',NULL,NULL,12.4408,8.073,0,15.735,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(810,771,'tt0099785',NULL,'Home Alone','Home Alone','movie',1990,'https://image.tmdb.org/t/p/w500/onTSipZ8R3bliBdKfPtsDuHTdlL.jpg','https://image.tmdb.org/t/p/original/ih2xVgeMS8R5WUetYE8Mr9hVTlB.jpg','Eight-year-old Kevin McCallister makes the most of the situation after his family unwittingly leaves him behind when they go on Christmas vacation. When thieves try to break into his home, he puts up a fight like no other.',NULL,NULL,0.9595,7.467,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(811,671,'tt0241527',NULL,'Harry Potter and the Philosopher''s Stone','Harry Potter and the Philosopher''s Stone','movie',2001,'https://image.tmdb.org/t/p/w500/wuMc08IPKEatf9rnMNXvIDxqP4W.jpg','https://image.tmdb.org/t/p/original/1XAC6RPT01UX9EQGy2JVn5c8pgy.jpg','Harry Potter has lived under the stairs at his aunt and uncle''s house his whole life. But on his 11th birthday, he learns he''s a powerful wizard—with a place waiting for him at the Hogwarts School of Witchcraft and Wizardry. As he learns to harness his newfound powers with the help of the school''s kindly headmaster, Harry uncovers the truth about his parents'' deaths—and about the villain who''s to blame.',NULL,NULL,40.6447,7.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(812,60670,'tt0228786',NULL,'The Crimson Rivers','Les Rivières pourpres','movie',2000,'https://image.tmdb.org/t/p/w500/npvDhiKkpQBuTaQ8cbWRT2iEfkE.jpg','https://image.tmdb.org/t/p/original/1Kzrk49o1oX15yqjWVuGPAEnjgd.jpg','Two French policemen, one investigating a grisly murder at a remote mountain college, the other working on the desecration of a young girl''s grave by skinheads, are brought together by the clues from their respective cases. Soon after they start working together, more murders are committed, and the pair begin to discover just what dark secrets are behind the killings.',NULL,NULL,4.8351,6.924,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(813,1143440,'tt28171985',NULL,'The Ice Tower','La Tour de glace','movie',2025,'https://image.tmdb.org/t/p/w500/b68s4eH45pRE8giLVM5tFUgVDcj.jpg','https://image.tmdb.org/t/p/original/j0Xeb9a4zDpYdkXEEZhfPjz71UN.jpg','Jeanne, a 15-year-old orphan, witnesses the shoot for a film adaptation of the fairy tale The Snow Queen, and she becomes fascinated by its star, Cristina, an actress who is just as mysterious and alluring as the Queen she is playing.',NULL,NULL,1.8279,5.932,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(814,7445,'tt0765010',NULL,'Brothers','Brothers','movie',2009,'https://image.tmdb.org/t/p/w500/skHqceAFYee0JZuYd9MVk2IQggi.jpg','https://image.tmdb.org/t/p/original/xERofiEyzGekTNi3oIppQvdLDZB.jpg','When his helicopter goes down during his fourth tour of duty in Afghanistan, Marine Sam Cahill is presumed dead. Back home, brother Tommy steps in to look over Sam’s wife, Grace, and two children. Sam’s surprise homecoming triggers domestic mayhem.',NULL,NULL,7.1188,7.317,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(815,38701,'tt0072869',NULL,'The Devil’s Rain','The Devil’s Rain','movie',1975,'https://image.tmdb.org/t/p/w500/855mdgEriehXBmjvG5n74CaAjTU.jpg','https://image.tmdb.org/t/p/original/lEJFN23Nvra7VKGZtY67Ikl081w.jpg','A Satanist cult leader is burnt alive by the local church. He vows to come back to hunt down and enslave every descendant of his congregation, by the power of the book of blood contracts, in which they sold their souls to the devil.',NULL,NULL,1.777,5.0,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(816,39891,'tt0062885',NULL,'The Devil Rides Out','The Devil Rides Out','movie',1968,'https://image.tmdb.org/t/p/w500/p1AWO8PIMfT6XGHV8uaa8erencj.jpg','https://image.tmdb.org/t/p/original/kb4pMEB8b54tXSnROhNrMFf63c5.jpg','The powers of good are pitted against the forces of evil as the Duc de Richelieu wrestles with the charming but deadly Satanist, Mocata, for the soul of his friend. Mocata has the knowledge and the power to summon the forces of darkness and, as the Duc de Richelieu and his friends remain within the protected pentacle, they are subjected to ever-increasing horror until thundering hooves herald the arrival of the Angel of Death.',NULL,NULL,1.4701,6.541,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(817,27400,'tt0081432',NULL,'Black Candles','Los Ritos Sexuales del Diablo','movie',1982,'https://image.tmdb.org/t/p/w500/7bxsUfuQ42OxpjAjtWs7u9gc1Wf.jpg','https://image.tmdb.org/t/p/original/1SpoDvFVEkKsSK89AQDqZLtWxNH.jpg','A young woman travels with her partner to England on the unexpected death of her brother. Staying with her sister-in-law, she finds her companion soon drawn into a satanic cult based in the house whose rites seem to centre somewhat on large-scale sexual congress.',NULL,NULL,1.3724,6.2,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(818,8973,'tt0113690',NULL,'Lord of Illusions','Lord of Illusions','movie',1995,'https://image.tmdb.org/t/p/w500/8MZu8s01psozeTuD6OzstP4vSvM.jpg','https://image.tmdb.org/t/p/original/xeoSaPhZ3SCizkCQaofVB9w6iZE.jpg','During a routine case in L.A., NY private investigator Harry D''Amour stumbles over members of a fanatic cult who are preparing for the resurrection of their leader Nix, a powerful magician who was killed 13 years earlier.',NULL,NULL,1.4833,5.931,0,11.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(819,9064,'tt0095294',NULL,'Hellbound: Hellraiser II','Hellbound: Hellraiser II','movie',1988,'https://image.tmdb.org/t/p/w500/auPOq1wgZuYSaADejOskBKG6fuV.jpg','https://image.tmdb.org/t/p/original/pl5OzUABUK5AgAsMlQg2VyybRHL.jpg','Now confined to a mental hospital, young Kirsty insists her supposedly dead father is actually stuck in Hell following his wife’s betrayal. Few believe the young woman’s lurid stories aside from the thrill-seeking Dr. Channard. Kirsty is undeterred and, with the help of a fellow patient, heads to Hell for a rescue.',NULL,NULL,3.2181,6.4,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(820,56292,'tt1229238',NULL,'Mission: Impossible - Ghost Protocol','Mission: Impossible - Ghost Protocol','movie',2011,'https://image.tmdb.org/t/p/w500/eRZTGx7GsiKqPch96k27LK005ZL.jpg','https://image.tmdb.org/t/p/original/ih4lZkUpmSE7AP3maymiO72xJ1z.jpg','Ethan Hunt and his team are racing against time to track down a dangerous terrorist named Hendricks, who has gained access to Russian nuclear launch codes and is planning a strike on the United States. An attempt to stop him ends in an explosion causing severe destruction to the Kremlin and the IMF to be implicated in the bombing, forcing the President to disavow them. No longer being aided by the government, Ethan and his team chase Hendricks around the globe, although they might still be too late to stop a disaster.',NULL,NULL,9.3179,7.115,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(821,841,'tt0087182',NULL,'Dune','Dune','movie',1984,'https://image.tmdb.org/t/p/w500/4kJmUCE7mkVJjXa7A0g2rY4IGTm.jpg','https://image.tmdb.org/t/p/original/5wJ2tckpvwcxGCAgZiccodwEJpf.jpg','In the year 10,191, the most precious substance in the universe is the spice Melange. The spice extends life. The spice expands consciousness. The spice is vital to space travel.  The spice exists on only one planet in the entire universe, the vast desert planet Arrakis, also known as Dune.  Its native inhabitants, the Fremen, have long held a prophecy that a man would come, a messiah who would lead them to true freedom.',NULL,NULL,7.0321,6.188,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(822,28043,'tt0057603',NULL,'Black Sabbath','I tre volti della paura','movie',1963,'https://image.tmdb.org/t/p/w500/vrMcn6CKrLjWAtHHMFL7cj8A5au.jpg','https://image.tmdb.org/t/p/original/vELycsAjczFbhneSJG1V6gvTz0D.jpg','Three tales of supernatural horror include a woman plagued by threatening phone calls, a family targeted by vampiric monsters, and a deceased medium who wreaks havoc upon the living.',NULL,NULL,1.6047,7.177,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(823,27632,'tt0054067',NULL,'Black Sunday','La maschera del demonio','movie',1960,'https://image.tmdb.org/t/p/w500/x41Zx8GeZhducquhOq9nE7z1GBG.jpg','https://image.tmdb.org/t/p/original/wKzY5EGRweXc91eBs1jk9ZSXcp0.jpg','A vengeful witch, Asa Vajda, and her fiendish servant, Igor Jauvitch, return from the grave and begin a bloody campaign to possess the body of the witch''s beautiful look-alike descendant: Katia. Only a handsome doctor with the help of family members stand in her way.',NULL,NULL,2.8759,7.4,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(824,29512,'tt0212830',NULL,'Bruiser','Bruiser','movie',2000,'https://image.tmdb.org/t/p/w500/giOkOy6mqUU5OMhvWPgZFJexZ8S.jpg','https://image.tmdb.org/t/p/original/l7TLxnV6lB9QySMOVcuaOhN4aHC.jpg','After years of being browbeaten and walked on, a man wakes one day wearing an expressionless mask, fitted with a personality that enables him to take revenge.',NULL,NULL,3.3862,5.521,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(825,28532,'tt0057993',NULL,'Castle of Blood','Danza macabra','movie',1964,'https://image.tmdb.org/t/p/w500/A17gEQk617FsLhtPyalRN885KM3.jpg','https://image.tmdb.org/t/p/original/s2MNZ9fEroQrKMagzBl5gO43VlD.jpg','When a cynical journalist accepts a wager that he won''t survive the night in a haunted castle, it unlocks an odyssey of sexual torment, undead vengeance, and a dark seductress who surrenders the gravest of pleasures.',NULL,NULL,0.9915,7.136,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(826,21588,'tt0109592',NULL,'Cemetery Man','DellaMorte DellAmore','movie',1994,'https://image.tmdb.org/t/p/w500/cI5AV3jCuxmoQp0N7Z16SI2b7Xk.jpg','https://image.tmdb.org/t/p/original/fHPTQ18tuwtJ3JvrCeZMZs4X58Q.jpg','Francesco Dellamorte  is the groundskeeper at a cemetery where the dead just won’t stay dead—and it’s up to him to deal with those who come back to life with a hunger for human flesh. But Dellamorte’s job soon becomes much more complicated when he falls for an enigmatic young woman whose husband has recently died.',NULL,NULL,2.8793,6.9,0,1.20233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(827,24920,'tt0081318',NULL,'City of the Living Dead','Paura nella città dei morti viventi','movie',1980,'https://image.tmdb.org/t/p/w500/8ymAiDW9ct2GSywWkqATEiKE8OB.jpg','https://image.tmdb.org/t/p/original/whhv9CuZAQ9NfiNVpl1u7yXAf4N.jpg','A psychic seemingly dies of fright during a séance where she sees a vision of a Dunwich priest hanging himself in a church cemetery. New York City reporter Peter Bell investigates and learns that the priest''s suicide has somehow opened a portal to Hell that must be sealed by All Saints Day, or else the dead will overtake humanity.',NULL,NULL,1.762,6.5,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(828,16281,'tt0083767',NULL,'Creepshow','Creepshow','movie',1982,'https://image.tmdb.org/t/p/w500/4SoyTCEpsgLjX6yAyMsx3AsAyRQ.jpg','https://image.tmdb.org/t/p/original/8aqTmCHLkktH7RZNALeaOMneHSl.jpg','Five grisly tales from a 1950s-style comic, including a murdered father rising from beyond, a bizarre meteor, a vengeful husband, a mysterious crate''s occupant, and a plague of cockroaches.',NULL,NULL,3.3026,6.9,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(829,22440,'tt0027545',NULL,'Dracula''s Daughter','Dracula''s Daughter','movie',1936,'https://image.tmdb.org/t/p/w500/y7xBkkRLcg1I0fXHO4yYC5SwBCX.jpg','https://image.tmdb.org/t/p/original/coZolPUocZJG3Qgd1g4cyI2Qm6L.jpg','A countess from Transylvania seeks a psychiatrist’s help to cure her vampiric cravings.',NULL,NULL,1.5657,6.0,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(830,764,'tt0083907',NULL,'The Evil Dead','The Evil Dead','movie',1981,'https://image.tmdb.org/t/p/w500/54C1qdaiSijIU5NeNb4WsPJdNkG.jpg','https://image.tmdb.org/t/p/original/onq6lsJLX8ay5iwxEbKX3qJKeO9.jpg','In 1979, a group of college students find a Sumerian Book of the Dead in an old wilderness cabin they''ve rented for a weekend getaway.',NULL,NULL,24.9083,7.276,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(831,3035,'tt0021884',NULL,'Frankenstein','Frankenstein','movie',1931,'https://image.tmdb.org/t/p/w500/mu6wHwH0IwCCaEYtpqujuPJYat1.jpg','https://image.tmdb.org/t/p/original/wFbPbJ9uRDpjY7micBTeolgkOA4.jpg','Henry Frankenstein pieces together body parts in the hope of bringing a human-like creature to life. The mad scientist’s dreams are shattered by his monstrous creation awakening with rage to a world that hates and fears him.',NULL,NULL,3.4888,7.466,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(832,10225,'tt0091080',NULL,'Jason Lives - Friday the 13th Part VI','Jason Lives - Friday the 13th Part VI','movie',1986,'https://image.tmdb.org/t/p/w500/6vdUpHvkspQonXBdWcLWW5ciEPJ.jpg','https://image.tmdb.org/t/p/original/93tvkTtV6tQQiYhxhij9tuODNOq.jpg','Tommy Jarvis, tormented by the fear that maybe Jason isn''t really dead, unwittingly resurrects the mass murderer for another bloody rampage.',NULL,NULL,6.2806,6.272,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(833,28734,'tt0089269',NULL,'Hellhole','Hellhole','movie',1985,'https://image.tmdb.org/t/p/w500/g6wm2BVwIjgFoi2ylT2EmksM1Ry.jpg','https://image.tmdb.org/t/p/original/vZEl9im8IQ1ezBhrfAQ8tqT960h.jpg','An unlucky woman’s mother is murdered by a scarf-wielding killer named Silk, leaving the woman injured, traumatised and suffering from amnesia. She’s committed to a mental institution, where Silk follows her, looking for the papers he was trying to get from her mother. And Silk’s only the beginning of her problems, since the asylum is run by a mad doctor, performing experiments in chemical lobotomies!',NULL,NULL,0.8969,4.9,0,6.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(834,28794,'tt0082966',NULL,'The House by the Cemetery','Quella villa accanto al cimitero','movie',1981,'https://image.tmdb.org/t/p/w500/yNUXcoopDqshs5xd2lOwUl1g4Df.jpg','https://image.tmdb.org/t/p/original/vdokrAQX8D2SfNY12GB8f3YdCaT.jpg','After a doctor kills his mistress and himself while researching the mysterious previous owner of his Boston home, his colleague, Dr. Norman Boyle, takes over his studies and moves his family into the Boston mansion. Soon after, Boyle''s young son Bob becomes plagued by visions of a young girl, who warns him of the danger within the house.',NULL,NULL,1.3102,6.316,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(835,8913,'tt0098084',NULL,'Pet Sematary','Pet Sematary','movie',1989,'https://image.tmdb.org/t/p/w500/a1gIACZb04bL8EvLqMpofW2Eqeo.jpg','https://image.tmdb.org/t/p/original/xWq3T9P4NU2pTdZ3hXFygsNnAq4.jpg','After the Creed family''s cat is accidentally killed, a friendly neighbor advises its burial in a mysterious nearby cemetery.',NULL,NULL,4.326,6.7,0,13.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(836,9638,'tt0079714',NULL,'Phantasm','Phantasm','movie',1979,'https://image.tmdb.org/t/p/w500/eR0uJ0Wje1lYJ4aHEpkcjgIM8d7.jpg','https://image.tmdb.org/t/p/original/71L3VXCRqpfdrSVy3iIWmyKXLTX.jpg','A teenage boy and his friends face off against a mysterious grave robber, known only as the Tall Man, who employs a lethal arsenal of unearthly weapons.',NULL,NULL,3.5152,6.5,0,10.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(837,26515,'tt0095925',NULL,'Pumpkinhead','Pumpkinhead','movie',1988,'https://image.tmdb.org/t/p/w500/gx7Gej5Srp3E13oqy1Kghtox2VZ.jpg','https://image.tmdb.org/t/p/original/vCNXAsuDHxHT1ylHqTDSDqaehUG.jpg','When a group of teenagers inadvertently kill his only son, Ed Harley seeks the powers of a backwoods witch to bring the child back to life.',NULL,NULL,1.8658,6.407,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(838,NULL,NULL,484,'Silent Hill: Origins','Silent Hill: Origins','game',2007,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vyq.jpg',NULL,'Silent Hill: Origins is the fifth installment in the Silent Hill survival horror series, and a prequel to the original game. As in the previous entries, the player move back and forth between nightmare and real versions of the town, gathering items used to solve puzzles and open up new areas. Monsters of various types provide obstacles and, in series tradition, are mostly disturbingly twisted versions of humanity. The main character can fight with his bare fists or use melee weapons. Unlike previous games in the series, melee weapons break after a time. There are also one-shot items that can be thrown and several guns. There is no HUD, but the edge of the screen turns red when the protagonist is near death.','https://www.igdb.com/games/silent-hill-origins','["PlayStation Portable", "PlayStation 2"]',NULL,NULL,0,11.5225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(839,439015,'tt5690360',NULL,'Slender Man','Slender Man','movie',2018,'https://image.tmdb.org/t/p/w500/huSncs4RyvQDBmHjBBYHSBYJbSJ.jpg','https://image.tmdb.org/t/p/original/tQPDwl1jNZi59KoFT2oxDDnlqhG.jpg','In a small town in Massachusetts, four high school girls perform a ritual in an attempt to debunk the lore of Slender Man. When one of the girls goes mysteriously missing, they begin to suspect that she is, in fact, his latest victim.',NULL,NULL,3.196,4.306,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(840,3077,'tt0031951',NULL,'Son of Frankenstein','Son of Frankenstein','movie',1939,'https://image.tmdb.org/t/p/w500/oefhX4T3iWo2XFvaOunR7azWAo3.jpg','https://image.tmdb.org/t/p/original/1Ek4nOpkLeBycYUr3SmLsE9Bm1e.jpg','One of the sons of late Dr. Henry Frankenstein finds his father''s ghoulish creation in a coma and revives him, only to find out the monster is controlled by Ygor who is bent on revenge.',NULL,NULL,1.69,6.7,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(841,13885,'tt0408236',NULL,'Sweeney Todd: The Demon Barber of Fleet Street','Sweeney Todd: The Demon Barber of Fleet Street','movie',2007,'https://image.tmdb.org/t/p/w500/gAW4J1bkRjZKmFsJsIiOBASeoAp.jpg','https://image.tmdb.org/t/p/original/obYVvi6eD4rjFeC7g4uoZQPIh7F.jpg','The infamous story of Benjamin Barker, a.k.a Sweeney Todd, who sets up a barber shop down in London which is the basis for a sinister partnership with his fellow tenant, Mrs. Lovett. Based on the hit Broadway musical.',NULL,NULL,4.8905,7.181,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(842,2391,'tt0096708',NULL,'Tales from the Crypt','Tales from the Crypt','tv',1989,'https://image.tmdb.org/t/p/w500/sEQmw4B2eaPWGMlpvbRuzEn2QP4.jpg','https://image.tmdb.org/t/p/original/nwtdRZHTlDqYwuJDc7oVQueHY2l.jpg','Cadaverous scream legend the Crypt Keeper is your macabre host for these forays of fright and fun based on the classic E.C. Comics tales from back in the day. So shamble up to the bar and pick your poison. Will it be an insane Santa on a personal slay ride? Honeymooners out to fulfill the "til death do we part" vow ASAP?',NULL,NULL,17.7687,8.0,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(843,8643,'tt0404032',NULL,'The Exorcism of Emily Rose','The Exorcism of Emily Rose','movie',2005,'https://image.tmdb.org/t/p/w500/qMN0HIP34f736kkQcfvTfmL9TP3.jpg','https://image.tmdb.org/t/p/original/eHT36hVNslbJXCY3SXgtzxPE3cl.jpg','When a younger girl called Emily Rose dies, everyone puts blame on the exorcism which was performed on her by Father Moore prior to her death. The priest is arrested on suspicion of murder. The trial begins with lawyer Erin Bruner representing Moore, but it is not going to be easy, as no one wants to believe what Father Moore says is true.',NULL,NULL,5.207,6.604,0,11.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(844,790,'tt0080749',NULL,'The Fog','The Fog','movie',1980,'https://image.tmdb.org/t/p/w500/12EeSboRofP3CI4SPmMFNNXCbtY.jpg','https://image.tmdb.org/t/p/original/pAOLiapALC7Q5pcCPDTA6P9pRuv.jpg','Strange things begin to occur as a tiny California coastal town prepares to commemorate its centenary. Inanimate objects spring eerily to life; Rev. Malone stumbles upon a dark secret about the town''s founding; radio announcer Stevie witnesses a mystical fire; and hitchhiker Elizabeth discovers the mutilated corpse of a fisherman. Then a mysterious iridescent fog descends upon the village, and more people start to die.',NULL,NULL,3.1283,6.7,0,10.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(845,1663525,'tt41435072',NULL,'Haunted Harmony Mysteries: Key to the Castle','Haunted Harmony Mysteries: Key to the Castle','movie',2026,'https://image.tmdb.org/t/p/w500/l9Pm8DnilY7A1POSOacy1JEYE5Y.jpg','https://image.tmdb.org/t/p/original/p8bXnT5In5gd9vIEDQNfzfHu2pr.jpg','When a ghost hunter show comes to town, it''s up to Gethsemane and Eamon to solve the unexpected murder of the host, allowing the brand-new spirit to cross-over.',NULL,NULL,1.6141,8.5,0,7.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(846,84473,'tt0126004',NULL,'The Iron Rose','La Rose de fer','movie',1973,'https://image.tmdb.org/t/p/w500/wEch3pkYG4w5Zuc296LxjGB1g4T.jpg','https://image.tmdb.org/t/p/original/5HPtthcaZFwnN7Y7skEiDCJsXMe.jpg','A young couple out for a walk decide to take a stroll through a large cemetery. As darkness begins to fall they realize they can''t find their way out, and soon their fears begin to overtake them.',NULL,NULL,0.9486,6.2,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(847,439079,'tt5814060',NULL,'The Nun','The Nun','movie',2018,'https://image.tmdb.org/t/p/w500/sFC1ElvoKGdHJIWRpNB3xWJ9lJA.jpg','https://image.tmdb.org/t/p/original/cMnVmutb5mVgIBeiMOncAbwNjvG.jpg','A priest with a dark past and a novice nearing her final vows are sent by the Vatican to Romania to investigate a nun''s death and face a demonic force.',NULL,NULL,9.4118,5.906,0,13.0225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(848,13666,'tt0034398',NULL,'The Wolf Man','The Wolf Man','movie',1941,'https://image.tmdb.org/t/p/w500/vG8fu5syTtQLzK1hQXyi3ugOPNF.jpg','https://image.tmdb.org/t/p/original/hwMWJ8G5173SGCHzrm0mVjvESaY.jpg','After his brother''s death, Larry Talbot returns home to his father and the family estate. Events soon take a turn for the worse when Larry is bitten by a werewolf.',NULL,NULL,2.3737,7.0,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(849,65086,'tt1596365',NULL,'The Woman in Black','The Woman in Black','movie',2012,'https://image.tmdb.org/t/p/w500/nghQnDZE4EsQJ4J4zxR3UqItTpO.jpg','https://image.tmdb.org/t/p/original/jJ3yFKs6xeVGxtmm7GXZYQ3XAvz.jpg','The story follows a young lawyer, Arthur Kipps, who is ordered to travel to a remote village and sort out a recently deceased client’s papers. As he works alone in the client’s isolated house, Kipps begins to uncover tragic secrets, his unease growing when he glimpses a mysterious woman dressed only in black. Receiving only silence from the locals, Kipps is forced to uncover the true identity of the Woman in Black on his own, leading to a desperate race against time when he discovers her true identity.',NULL,NULL,4.3881,6.145,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(850,36265,'tt0059719',NULL,'Simon of the Desert','Simón del desierto','movie',1965,'https://image.tmdb.org/t/p/w500/ysTa1FtL9DvQ90F6VGVoiOdp5NM.jpg','https://image.tmdb.org/t/p/original/sm7NapjwKYhIH2GzFEgJkiw9hF1.jpg','Simon, a deeply religious man living in the 4th century, wants to be nearer to God so he climbs a column. The Devil wants him come down to Earth and is trying to seduce him.',NULL,NULL,1.1129,7.642,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(851,50183,'tt0075404',NULL,'The Ascent','Восхождение','movie',1977,'https://image.tmdb.org/t/p/w500/hJOju5XZfmq4Lg5dPa8IPVY3mDt.jpg','https://image.tmdb.org/t/p/original/jhQ06TMNzWvQvxd5G4d2wZX3oZY.jpg','During a freezing WWII winter, two Soviet partisans on a mission to gather food contend with the temperature, the occupying Germans, and their own psyches.',NULL,NULL,3.8791,7.8,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(852,922,'tt0112817',NULL,'Dead Man','Dead Man','movie',1995,'https://image.tmdb.org/t/p/w500/jX3wGBVoYoAY3IixBpwYk1fjT4z.jpg','https://image.tmdb.org/t/p/original/a7DtgKB187dUm9n81IlvNzVXsK1.jpg','On the run after committing murder, an accountant encounters a strange Native American man who prepares him for his journey into the spiritual world.',NULL,NULL,2.8765,7.305,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(853,64720,'tt1675192',NULL,'Take Shelter','Take Shelter','movie',2011,'https://image.tmdb.org/t/p/w500/dldIX0q5jewe8rSyCh8d5I1RYx3.jpg','https://image.tmdb.org/t/p/original/7HtE5hLVTEvFKQC33wK7XAnIdFk.jpg','Plagued by a series of apocalyptic visions, a young husband and father questions whether to shelter his family from a coming storm, or from himself.',NULL,NULL,3.001,7.056,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(854,13198,'tt0477139',NULL,'Wristcutters: A Love Story','Wristcutters: A Love Story','movie',2007,'https://image.tmdb.org/t/p/w500/qModiIR60IMLP28ruGZluQOtsOj.jpg','https://image.tmdb.org/t/p/original/wDLgGI6Rswo30YkWoM6TGq0VWVy.jpg','Zia, distraught over breaking up with his girlfriend, decides to end it all. Unfortunately, he discovers that there is no real ending, only a run-down afterlife that is strikingly similar to his old one, just a bit worse. Discovering that his ex-girlfriend has also "offed" herself, he sets out on a road trip to find her.',NULL,NULL,1.5859,6.973,0,13.1525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(855,36129,'tt0073099',NULL,'Hedgehog in the Fog','Ёжик в тумане','movie',1975,'https://image.tmdb.org/t/p/w500/4sMh4bpyy5zhOS7G48WOsOBIhIH.jpg','https://image.tmdb.org/t/p/original/xvk0mFGUojrTiiTo0iutGW5Xd1n.jpg','A little hedgehog, on the way to visit his friend the bear, gets lost in thick fog, where horses, dogs and even falling leaves take on a terrifying new aspect...',NULL,NULL,0.9133,7.428,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(856,1272,'tt0448134',NULL,'Sunshine','Sunshine','movie',2007,'https://image.tmdb.org/t/p/w500/oKGGeJ8qvm0UmClz43VJ31fzPP7.jpg','https://image.tmdb.org/t/p/original/5AIAnucJKZ3sHpm7r1ykFVIoUHK.jpg','Fifty years into the future, the sun is dying, and Earth is threatened by arctic temperatures. A team of astronauts is sent to revive the Sun — but the mission fails. Seven years later, a new team is sent to finish the mission as mankind’s last hope.',NULL,NULL,6.3105,6.973,0,1.16800000000000014e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(857,109463,'tt1756479',NULL,'The Color Out of Space','Die Farbe','movie',2010,'https://image.tmdb.org/t/p/w500/kEmgt2dLFSQy7jX3g2dIn7ECsuY.jpg','https://image.tmdb.org/t/p/original/hEY3GdMZT7aLkQNQb9ssF1yuP9s.jpg','Arkham, 1975: Jonathan Davis'' father has disappeared. His tracks lead to Germany, to the Swabian-Franconian Forest where he was stationed after the Second World War. Jonathan sets out to find him and bring him home, but deep in the woods he discovers a dark mystery from the past. Based on H.P. Lovecraft''s short novel "The Colour Out of Space".',NULL,NULL,0.7979,6.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(858,489412,'tt2396224',NULL,'It''s Such a Beautiful Day','It''s Such a Beautiful Day','movie',2012,'https://image.tmdb.org/t/p/w500/hop0dsM4nxyNENGhBhpJWTCJ5rS.jpg','https://image.tmdb.org/t/p/original/rA9QYI7yTV2F2AvaqBcq1vL3MOr.jpg','Bill struggles to put together his shattered psyche.',NULL,NULL,1.0527,7.92,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(859,4808,'tt0056923',NULL,'Charade','Charade','movie',1963,'https://image.tmdb.org/t/p/w500/qqaPjC5FQidtKY65jbAKZPiOTaS.jpg','https://image.tmdb.org/t/p/original/gj2TBYmOIy4E2GjMIpnbAEZNCQx.jpg','After Regina Lampert falls for the dashing Peter Joshua on a skiing holiday in the French Alps, she discovers upon her return to Paris that her husband has been murdered. Soon, she and Peter are giving chase to three of her late husband''s World War II cronies, Tex, Scobie and Gideon, who are after a quarter of a million dollars the quartet stole while behind enemy lines.',NULL,NULL,3.26,7.7,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(860,15265,'tt0048980',NULL,'The Red Balloon','Le Ballon rouge','movie',1956,'https://image.tmdb.org/t/p/w500/3XrEggEOEnKGi8hTOau44vcvbmV.jpg','https://image.tmdb.org/t/p/original/w9QL9kd2SijhGNxB8cYBrGWUQy2.jpg','A young boy discovers a stray balloon, which seems to have a mind of its own, on the streets of Paris. The two become inseparable, yet the world’s harsh realities finally interfere.',NULL,NULL,1.4157,7.739,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(861,252,'tt0067992',NULL,'Willy Wonka & the Chocolate Factory','Willy Wonka & the Chocolate Factory','movie',1971,'https://image.tmdb.org/t/p/w500/vmpsZkrs4Uvkp9r1atL8B3frA63.jpg','https://image.tmdb.org/t/p/original/aAL7kV0l3yZtbCFs7J8m4gXldqR.jpg','When eccentric candy man Willy Wonka promises a lifetime supply of sweets and a tour of his chocolate factory to five lucky kids, penniless Charlie Bucket seeks the golden ticket that will make him a winner.',NULL,NULL,7.0415,7.484,0,10.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(862,153518,'tt1985949',NULL,'The Angry Birds Movie','The Angry Birds Movie','movie',2016,'https://image.tmdb.org/t/p/w500/iOH0fEFtV9z9rZp9zmBFGGeWicv.jpg','https://image.tmdb.org/t/p/original/o4mhrLxv6I70kvYA42qANGUF7ya.jpg','An island populated entirely by happy, flightless birds or almost entirely. In this paradise, Red, a bird with a temper problem, speedy Chuck, and the volatile Bomb have always been outsiders. But when the island is visited by mysterious green piggies, it’s up to these unlikely outcasts to figure out what the pigs are up to.',NULL,NULL,13.8726,6.282,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(863,11866,'tt0377062',NULL,'Flight of the Phoenix','Flight of the Phoenix','movie',2004,'https://image.tmdb.org/t/p/w500/pj3nKoouBhLkO94XUg8y5IeZ32c.jpg','https://image.tmdb.org/t/p/original/mWXU29QjfjEG37d0c2hE11MWRGq.jpg','When an oil rig in the Gobi Desert of Mongolia proves unproductive, an aircraft crew are sent to shut the operation down and fly them out. On the flight out over the desert on the way to Beijing, Capt. Frank Towns and co-pilot A.J. are unable to keep their cargo plane, a C-119 Flying Boxcar, in the air when a violent sandstorm strikes. Crash-landing in a remote uncharted part of the desert, the two pilots and their passengers -- a crew of oil workers and a drifter -- must work together to survive by rebuilding the aircraft. Soon, low supplies and a band of merciless smugglers add even greater urgency to their task.',NULL,NULL,2.924,6.004,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(864,883083,'tt8296030',NULL,'You Won''t Be Alone','You Won''t Be Alone','movie',2022,'https://image.tmdb.org/t/p/w500/qVRADANU3JpMyapKjV3eM41VlDG.jpg','https://image.tmdb.org/t/p/original/qEYcteWFxQjfyjMrZCWcaLfHSe1.jpg','In an isolated mountain village in 19th century Macedonia, a young feral witch accidentally kills a peasant. She assumes the peasant''s shape to see what life is like in her skin, igniting a deep seated curiosity to experience life inside the bodies of others.',NULL,NULL,2.7162,6.585,0,1.30233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(865,20108,'tt0060138',NULL,'Au Hasard Balthazar','Au hasard Balthazar','movie',1966,'https://image.tmdb.org/t/p/w500/lkLO1HDzzaXpTXtAgnGpVqIQkvF.jpg','https://image.tmdb.org/t/p/original/7LPz7NEYtLXcV44j0kRLLkZ54yH.jpg','The story of a donkey Balthazar as he is passed from owner to owner, some kind and some cruel but all with motivations beyond his understanding. Balthazar, whose life parallels that of his first keeper, Marie, is truly a beast of burden, suffering the sins of humankind. But despite his powerlessness, he accepts his fate nobly.',NULL,NULL,2.5047,7.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(866,348678,'tt4080728',NULL,'A Man Called Ove','En man som heter Ove','movie',2015,'https://image.tmdb.org/t/p/w500/a41uvFqze4PI7N3E9jPNwN9ypV.jpg','https://image.tmdb.org/t/p/original/aWNknDl5kGZTgjqfeIKxdZaKGmm.jpg','Despite being deposed as president of his condominium association, grumpy 59-year-old Ove continues to watch over his neighbourhood with an iron fist. When pregnant Parvaneh and her family move into the terraced house opposite Ove and she accidentally backs into Ove’s mailbox, it sets off a series of unexpected changes in his life.',NULL,NULL,2.6048,7.608,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(867,10227,'tt0062136',NULL,'PlayTime','PlayTime','movie',1967,'https://image.tmdb.org/t/p/w500/kQOrS0DLUXYsqPMedM2G6NJcJBq.jpg','https://image.tmdb.org/t/p/original/pKX8G6IN8ZCRvKeHh6ctqoHZl0K.jpg','Clumsy Monsieur Hulot finds himself perplexed by the intimidating complexity of a gadget-filled Paris. He attempts to meet with a business contact but soon becomes lost. His roundabout journey parallels that of an American tourist, and as they weave through the inventive urban environment, they intermittently meet, developing an interest in one another. They eventually get together at a chaotic restaurant, along with several other quirky characters.',NULL,NULL,4.4534,7.7,0,1.23666666666666653e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(868,427,'tt0050706',NULL,'Mon Oncle','Mon oncle','movie',1958,'https://image.tmdb.org/t/p/w500/wH6RyPiXFy8INLbViVkchLVOmBc.jpg','https://image.tmdb.org/t/p/original/3yYNJeR6JynSE3Y1AfVIJQ6g3UX.jpg','Genial, bumbling Monsieur Hulot loves his top-floor apartment in a grimy corner of the city, and cannot fathom why his sister''s family has moved to the suburbs. Their house is an ultra-modern nightmare, which Hulot only visits for the sake of stealing away his rambunctious young nephew. Hulot''s sister, however, wants to win him over to her new way of life, and conspires to set him up with a wife and job.',NULL,NULL,1.8585,7.4,0,11.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(869,1714,'tt0060390',NULL,'Fahrenheit 451','Fahrenheit 451','movie',1966,'https://image.tmdb.org/t/p/w500/k2CTpexoS9MO9lKVFfnzwVdJuM.jpg','https://image.tmdb.org/t/p/original/gyC9u8GOeNwyKzvXHAOhTsfps5u.jpg','In the future, the government maintains control of public opinion by outlawing literature and maintaining a group of enforcers, known as “firemen,” to perform the necessary book burnings. Fireman Montag begins to question the morality of his vocation…',NULL,NULL,2.799,7.1,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(870,617126,'tt10676052',NULL,'The Fantastic 4: First Steps','The Fantastic 4: First Steps','movie',2025,'https://image.tmdb.org/t/p/w500/nf5qaSEvyYSNeFH0YhSs5EsBLX9.jpg','https://image.tmdb.org/t/p/original/s94NjfKkcSczZ1FembwmQZwsuwY.jpg','Against the vibrant backdrop of a 1960s-inspired, retro-futuristic world, Marvel''s First Family is forced to balance their roles as heroes with the strength of their family bond, while defending Earth from a ravenous space god called Galactus and his enigmatic Herald, Silver Surfer.',NULL,NULL,19.5497,6.953,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(871,185,'tt0066921',NULL,'A Clockwork Orange','A Clockwork Orange','movie',1971,'https://image.tmdb.org/t/p/w500/4sHeTAp65WrSSuc05nRBKddhBxO.jpg','https://image.tmdb.org/t/p/original/nLFxvLokHe3bQmrmAfljIfax2jQ.jpg','In a near-future Britain, young Alexander DeLarge and his pals get their kicks beating and raping anyone they please. When not destroying the lives of others, Alex swoons to the music of Beethoven. The state, eager to crack down on juvenile crime, gives an incarcerated Alex the option to undergo an invasive procedure that''ll rob him of all personal agency. In a time when conscience is a commodity, can Alex change his tune?',NULL,NULL,15.9238,8.176,0,1.47419999999999991e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(872,593,'tt0069293',NULL,'Solaris','Солярис','movie',1972,'https://image.tmdb.org/t/p/w500/pgqj7QoBPWFLLKtLEpPmFYFRMgB.jpg','https://image.tmdb.org/t/p/original/jZv1u7uzpOE5JOc2MmrvPUZWoyb.jpg','A psychologist is sent to a space station orbiting a planet called Solaris to investigate the death of a doctor and the mental problems of cosmonauts on the station. He soon discovers that the water on the planet is a type of brain which brings out repressed memories and obsessions.',NULL,NULL,3.3133,7.8,0,1.42279999999999979e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(873,27834,'tt0254199',NULL,'CQ','CQ','movie',2001,'https://image.tmdb.org/t/p/w500/aFAPOT77Jh7lNWYtojC6nxi4CpJ.jpg','https://image.tmdb.org/t/p/original/uoGTKAi4qTk4lfOlbSkVKZA72lG.jpg','A young filmmaker in 1960s Paris juggles directing a cheesy sci-fi debacle, directing his own personal art film, coping with his crumbling relationship with his girlfriend, and a new-found infatuation with the sci-fi film''s starlet.',NULL,NULL,3.7163,5.905,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(874,8069,'tt0062711',NULL,'Barbarella','Barbarella','movie',1968,'https://image.tmdb.org/t/p/w500/facTz5BZz4AkJal1FWgjYciekih.jpg','https://image.tmdb.org/t/p/original/gY8essk1UcNZMK3VRkPpdaUQLDQ.jpg','In the far future, a highly sexual woman is tasked with finding and stopping the evil Durand-Durand. Along the way she encounters various unusual people.',NULL,NULL,4.2533,5.996,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(875,1267,'tt0396555',NULL,'Meet the Robinsons','Meet the Robinsons','movie',2007,'https://image.tmdb.org/t/p/w500/naya0zF4kT401Sx15AtwB9vpcJr.jpg','https://image.tmdb.org/t/p/original/AsWuvFnzgmG6kZMIpJO7HZpvYRB.jpg','Lewis, a brilliant young inventor, is keen on creating a time machine to find his mother, who abandoned him in an orphanage. Things take a turn when he meets Wilbur Robinson and his family.',NULL,NULL,6.8275,6.9,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(876,75,'tt0116996',NULL,'Mars Attacks!','Mars Attacks!','movie',1996,'https://image.tmdb.org/t/p/w500/hll4O5vSAfnZDb6JbnP06GPtz7b.jpg','https://image.tmdb.org/t/p/original/ELsTifJ2lu4vsMhoHeZ5EnncHw.jpg','A fleet of Martian spacecraft surrounds the world''s major cities and all of humanity waits to see if the extraterrestrial visitors have, as they claim, "come in peace." U.S. President James Dale receives assurance from science professor Donald Kessler that the Martians'' mission is a friendly one. But when a peaceful exchange ends in the total annihilation of the U.S. Congress, military men call for a full-scale nuclear retaliation.',NULL,NULL,6.6832,6.426,0,13.795,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(877,894,'tt0061287',NULL,'The Prisoner','The Prisoner','tv',1967,'https://image.tmdb.org/t/p/w500/1FtqAlj6jsBk25PKwL2NrgzdFSo.jpg','https://image.tmdb.org/t/p/original/dieT9MczvZXpCLrIAjs3vKYWKa7.jpg','After resigning, a secret agent is abducted and taken to what looks like an idyllic village, but is really a bizarre Kafkaesque prison. His warders demand information. He gives them nothing, but only tries to escape.',NULL,NULL,8.2336,7.7,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(878,2560,'tt0063962',NULL,'UFO','UFO','tv',1970,'https://image.tmdb.org/t/p/w500/yJMF2BlJ3M7rXRQQpv91WInBtXO.jpg','https://image.tmdb.org/t/p/original/pYcSxml94LU0Emgc69o3CCcTq5Q.jpg','A secret, high-technology international agency called SHADO defends Earth from alien invaders.',NULL,NULL,9.8686,7.763,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(879,134,'tt0072564',NULL,'Space: 1999','Space: 1999','tv',1975,'https://image.tmdb.org/t/p/w500/77Jn71Aw4mct3phi7wpjLdvO9U5.jpg','https://image.tmdb.org/t/p/original/3igZ4K3pKIEoD2nyvgmmVOMuz3E.jpg','The crew of Moonbase Alpha must struggle to survive when a massive explosion throws the Moon from orbit into deep space.',NULL,NULL,12.2987,7.138,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(880,11561,'tt0070707',NULL,'Sleeper','Sleeper','movie',1973,'https://image.tmdb.org/t/p/w500/YTYSziZZP5aXt5CDvdEMwKDzme.jpg','https://image.tmdb.org/t/p/original/uVTEJPLof6fizkWvmhxEprut9oQ.jpg','Miles Monroe, a clarinet-playing health food store proprietor, is revived out of cryostasis 200 years into a future world in order to help rebels fight an oppressive government regime.',NULL,NULL,3.4424,6.861,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(881,20894,'tt0086723',NULL,'Guest from the Future','Гостья из будущего','movie',1984,'https://image.tmdb.org/t/p/w500/nAYREETmvDPPf3nZJDmMdANyGWp.jpg','https://image.tmdb.org/t/p/original/z9MYzXMqPPa9pLlxH41jc1QwWbS.jpg','6-grader Kolya Gerasimov discovers a time machine in a basement of an old house in Moscow and gets transferred into the 21st century. There he is allowed to look around. Accidentally, Kolya witnesses two space pirates who arrive from Saturn and later try to steal a device called a "Mielophone" (which can read thoughts) from Alisa Seleznyova - a girl that performs experiments with this device and animals. Kolya manages to save the device from the pirates and brings it back to the 20th century. But both pirates and Alisa get there too. Alisa knows where Kolya studies but doesn''t know what he looks like. Pirates saw Kolya, but don''t know anything about him. Written by Boris Shafir',NULL,NULL,0.5778,7.625,0,9.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(882,265712,'tt3331846',NULL,'Stand by Me Doraemon','STAND BY ME ドラえもん','movie',2014,'https://image.tmdb.org/t/p/w500/wc7XQbfx6EIQqCuvmBMt3aisb2Y.jpg','https://image.tmdb.org/t/p/original/1aABIiqBY7yoQESE8qWvR0w9bJZ.jpg','Sewashi and Doraemon find themselves way back in time and meet Nobita. It is up to Doraemon to take care of Nobita or else he will not return to the present.',NULL,NULL,3.4242,7.411,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(883,157820,'tt2027140',NULL,'Mood Indigo','L''Écume des jours','movie',2013,'https://image.tmdb.org/t/p/w500/y41mndWYov3oPSZdHUtyjEdALvF.jpg','https://image.tmdb.org/t/p/original/rqPehvtSbAbMQfYCy2spmPUGUNf.jpg','A woman suffers from an unusual illness caused by a flower growing in her lungs.',NULL,NULL,0.8723,6.139,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(884,9683,'tt0258470',NULL,'Bubble Boy','Bubble Boy','movie',2001,'https://image.tmdb.org/t/p/w500/tFwvUSc8g0HHvDOBQ2rvC9LWVSj.jpg','https://image.tmdb.org/t/p/original/vUq8oKAnONAbYxIDNw4CQcEuADd.jpg','Jimmy is a young man who was born without an immune system and has lived his life within a plastic bubble in his bedroom... who pines for the sweet caresses of girl-next-door Chloe. But when Chloe decides to marry her high school boyfriend, Jimmy – bubble suit and all – treks cross-country to stop her.',NULL,NULL,2.1142,5.774,0,12.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(885,257344,'tt2120120',NULL,'Pixels','Pixels','movie',2015,'https://image.tmdb.org/t/p/w500/d26S5EfVXLNxRXqyFy1yyl3qRq3.jpg','https://image.tmdb.org/t/p/original/41Y3h2FVfoU4baFdTZwRrlD4MDM.jpg','Video game experts are recruited by the military to fight 1980s-era video game characters who''ve attacked New York.',NULL,NULL,10.2722,5.784,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(886,196055,'tt37663169',NULL,'The Wall of the Eye','眼の壁','tv',2022,'https://image.tmdb.org/t/p/w500/pJuqUdziI4Mj4vKMq4PmT3LrfXs.jpg','https://image.tmdb.org/t/p/original/thfBDR9b0rYfrCRELoq6DXGxtfJ.jpg','In 1990, Hagizaki Tatsuo, the accounting department chief of Ukishima Electric Works, was busy negotiating on getting a loan together with Sekino, the company''s general manager. However, just as they were about to get the funds, Sekino was involved in a 200 million yen fraud and he later disappeared with the loan. The company decides to cover up the incident to protect its image, but Hagizaki wants to get to the bottom of the matter with the help of his newspaper reporter friend, Muraki. Hagizaki later notices that the case becomes darker and darker as he continues to investigate. He then meets a beautiful woman, Uezaki Etsuko, whom he believes hold the key to the entire incident.',NULL,NULL,1.4999,8.5,0,1.2916666666666666e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(887,7459,'tt0811080',NULL,'Speed Racer','Speed Racer','movie',2008,'https://image.tmdb.org/t/p/w500/fxRIpx9Op9h71q3tvuabx4GryyP.jpg','https://image.tmdb.org/t/p/original/kH14XvCHKfMRz1sNsAMY0KpAKb0.jpg','Speed Racer is a young and brilliant racing driver. When corruption in the racing leagues costs his brother his life, Speed must team up with the police and the mysterious Racer X to bring an end to the corruption and criminal activities.',NULL,NULL,5.6424,6.371,0,13.9025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(888,10054,'tt0227538',NULL,'Spy Kids','Spy Kids','movie',2001,'https://image.tmdb.org/t/p/w500/j3rUkHIAAoKr6jU30q3Db4fcIF9.jpg','https://image.tmdb.org/t/p/original/wfStsmeSW7MtvYhD9Ac6ETXdbmx.jpg','Carmen and Juni think their parents are boring. Little do they know that in their day, Gregorio and Ingrid Cortez were the top secret agents from their respective countries. They gave up that life to raise their children. Now, the disappearances of several of their old colleagues forces the Cortez'' return from retirement. What they didn''t count on was Carmen and Juni joining the "family business."',NULL,NULL,5.8433,5.817,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(889,10803,'tt0074812',NULL,'Logan''s Run','Logan''s Run','movie',1976,'https://image.tmdb.org/t/p/w500/v3ILN8ROPcrNRJ8S7GH24JyihH8.jpg','https://image.tmdb.org/t/p/original/yJXAo8N60RaVC6pEuXUQ6wFBCCA.jpg','In the 23rd century, inhabitants of a domed city freely experience all of life''s pleasures — but no one is allowed to live past 30. Citizens can try for a chance at being "renewed" in a civic ceremony on their 30th birthday. Escape is the only other option.',NULL,NULL,3.0129,6.619,0,1.13433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(890,52608,'tt0069530',NULL,'Z.P.G.','Z.P.G.','movie',1972,'https://image.tmdb.org/t/p/w500/rAV2ZiU3mAe0fyqGhHp3N8e5XoF.jpg','https://image.tmdb.org/t/p/original/pwkDMraeADUZ7xfHsxwUAKSOjhu.jpg','In the not too distant future, an overpopulated Earth government makes it illegal to have children for a generation. One couple, unsatisfied with their substitute robot baby, breaks the rules.',NULL,NULL,0.7848,6.076,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(891,1410,'tt0069945',NULL,'Dark Star','Dark Star','movie',1974,'https://image.tmdb.org/t/p/w500/aiqLBiH0IWrog2Q78dZTT8Ad9Sp.jpg','https://image.tmdb.org/t/p/original/5I6yjyIKzAeQd5C1ynJnfWCK22u.jpg','A group of scientists are sent on a mission to destroy unstable planets. Twenty years into their mission, they have to battle their alien mascot as well as a "sensitive" and intelligent bombing device that starts to question the meaning of its existence.',NULL,NULL,2.8671,5.992,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(892,8072,'tt0058898',NULL,'Alphaville','Alphaville, une étrange aventure de Lemmy Caution','movie',1965,'https://image.tmdb.org/t/p/w500/fFJP3D5fJDFxN7ChqSye1DZ0fTL.jpg','https://image.tmdb.org/t/p/original/iOUhnp01rP9Xr5QG66LMAKSDkYv.jpg','Lemmy Caution is on a mission to eliminate Professor Von Braun, the creator of a malevolent computer that rules the city of Alphaville. Befriended by the scientist’s daughter Natasha, Lemmy must unravel the mysteries of the strictly logical Alpha 60 and teach Natasha the meaning of the word “love.”',NULL,NULL,2.2763,6.9,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(893,9320,'tt0118661',NULL,'The Avengers','The Avengers','movie',1998,'https://image.tmdb.org/t/p/w500/1p5thyQ4pCy876HpdvFARqJ62N9.jpg','https://image.tmdb.org/t/p/original/ftr9GcaD97CRSKRftx4FtTHfhfa.jpg','British Ministry agent John Steed, under direction from "Mother", investigates a diabolical plot by arch-villain Sir August de Wynter to rule the world with his weather control machine. Steed investigates the beautiful Doctor Mrs. Emma Peel, the only suspect, but simultaneously falls for her and joins forces with her to combat Sir August.',NULL,NULL,2.3902,4.448,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(894,22820,'tt1161418',NULL,'Gentlemen Broncos','Gentlemen Broncos','movie',2009,'https://image.tmdb.org/t/p/w500/eRnUC60trqoRZuAtM8M3gOFT6ED.jpg','https://image.tmdb.org/t/p/original/ypEJQtPUsqb4oD4Z3qpbDfwekup.jpg','A teenager attends a fantasy writers'' convention where he discovers his idea has been stolen by an established novelist.',NULL,NULL,1.396,5.692,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(895,747188,'tt14230388',NULL,'Asteroid City','Asteroid City','movie',2023,'https://image.tmdb.org/t/p/w500/hfo7pvL9Fys7rocfL4VOzw9qDEQ.jpg','https://image.tmdb.org/t/p/original/iloUOSs3Rcq3aMr04CrGRWVVBkq.jpg','In an American desert town circa 1955, the itinerary of a Junior Stargazer/Space Cadet convention is spectacularly disrupted by world-changing events.',NULL,NULL,4.1915,6.452,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(896,19545,'tt0059346',NULL,'Invasion of Astro-Monster','怪獣大戦争','movie',1965,'https://image.tmdb.org/t/p/w500/70gwaushxXcpGRvadHtLD0YLHC1.jpg','https://image.tmdb.org/t/p/original/kpt7UTujy2hU4dfpAVJEaDWB4Uh.jpg','Astronauts Glenn and Fuji investigate Planet X and encounter mysterious aliens known as the Xiliens, who ask Earth''s people to help save their world from "Monster Zero".  In exchange for borrowing Godzilla and Rodan, the Xiliens offer a cure for cancer. As Glenn investigates, he develops a romance with Miss Namikawa and uncovers the Xilien''s true intentions.',NULL,NULL,2.0407,6.814,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(897,4327,'tt0096657',NULL,'Mr. Bean','Mr. Bean','tv',1990,'https://image.tmdb.org/t/p/w500/pUNQV35kDaKuejnXGNiUeEBurNE.jpg','https://image.tmdb.org/t/p/original/lHSLW9lihnuRMs1yYarmMJX4phK.jpg','Mr Bean turns simple everyday tasks into chaotic situations and will leave you in stitches as he creates havoc wherever he goes.',NULL,NULL,18.0396,7.986,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(898,394385,'tt1625140',NULL,'Rainer Werner Fassbinder''s World on a Wire: Looking Ahead to Today','Fassbinders Welt am Draht - Blick voraus ins Heute','movie',2010,'https://image.tmdb.org/t/p/w500/qxu1vtzTKFF7d0lf28Hs7E3b93H.jpg',NULL,'A retrospective look at the making of "World on a Wire".',NULL,NULL,0.1716,6.2,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(899,603,'tt0133093',NULL,'The Matrix','The Matrix','movie',1999,'https://image.tmdb.org/t/p/w500/dXNAPwY7VrqMAo51EKhhCJfaGb5.jpg','https://image.tmdb.org/t/p/original/tlm8UkiQsitc8rSuIAscQDCnP8d.jpg','Set in the 22nd century, The Matrix tells the story of a computer hacker who joins a group of underground insurgents fighting the vast and powerful computers who now rule the earth.',NULL,NULL,44.0275,8.251,0,1.74975000000000022e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(900,12101,'tt0070723',NULL,'Soylent Green','Soylent Green','movie',1973,'https://image.tmdb.org/t/p/w500/5nbkShkOEXUoKVhaX0XG41wyBkq.jpg','https://image.tmdb.org/t/p/original/ga4JUb1dGnpesuztsGeMGMjj0fz.jpg','In the year 2022, overcrowding, pollution,  and resource depletion have reduced society’s leaders to finding food for the teeming masses. The answer is Soylent Green.',NULL,NULL,3.6601,6.931,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(901,525,'tt0080455',NULL,'The Blues Brothers','The Blues Brothers','movie',1980,'https://image.tmdb.org/t/p/w500/rhYJKOt6UrQq7JQgLyQcSWW5R86.jpg','https://image.tmdb.org/t/p/original/bk2fTuIhQIvdAA3RbnrnvLvuaTc.jpg','Jake Blues, just released from prison, puts his old band back together to save the Catholic home where he and his brother Elwood were raised.',NULL,NULL,5.0341,7.7,0,11.785,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(902,43226,'tt0050251',NULL,'The Mysterians','地球防衛軍','movie',1957,'https://image.tmdb.org/t/p/w500/eILFc9gTP1Yxj9oI4hXEBRGnt1w.jpg','https://image.tmdb.org/t/p/original/bS8cS0JcxIe2kV126GINgeOxlVS.jpg','In Japan, scientifically advanced invaders from the war-destroyed planet Mysteroid cause an entire village to vanish, then send a giant robot out to storm the city by night, after which they request a small patch of land on Earth and the right to marry earthling women, claiming to be pacifists.  Mankind must decide whether to capitulate or to resist.',NULL,NULL,0.9873,6.379,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(903,872709,'tt15471560',NULL,'Smoking Causes Coughing','Fumer fait tousser','movie',2022,'https://image.tmdb.org/t/p/w500/7aYwL5VEzGkBvww9YFYKBPGBbRt.jpg','https://image.tmdb.org/t/p/original/89Kubf8TqJqdJBeePY0vmHzXJFB.jpg','After a devastating battle against a diabolical turtle, a team of five avengers — known as the "Tobacco Force" — is sent on a mandatory retreat to strengthen their decaying group cohesion, where they share scary stories the film depicts. Their storytelling sojourn goes wonderfully well until Lézardin, Emperor of Evil, decides to annihilate planet Earth.',NULL,NULL,1.6174,6.028,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(904,49069,'tt0080380',NULL,'The Apple','The Apple','movie',1980,'https://image.tmdb.org/t/p/w500/yQxFFhPzH3hzzmlEeCU0aKyOC4T.jpg','https://image.tmdb.org/t/p/original/3L05HQS4GiR8PXCq0JjqXShoLRF.jpg','In a pseudo-futuristic 1994, a square couple enter the corrupt world of the music industry, and subsequently a maze of drugs, sex, and temptation.',NULL,NULL,0.8539,4.492,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(905,816,'tt0118655',NULL,'Austin Powers: International Man of Mystery','Austin Powers: International Man of Mystery','movie',1997,'https://image.tmdb.org/t/p/w500/5uD4dxNX8JKFjWKYMHyOsqhi5pN.jpg','https://image.tmdb.org/t/p/original/wSm5McaHSAyOx4gGRYdlDHzj00y.jpg','As a swinging fashion photographer by day and a groovy British superagent by night, Austin Powers is the ''60s'' most shagadelic spy. But can he stop megalomaniac Dr. Evil after the bald villain freezes himself and unthaws in the ''90s? With the help of sexy sidekick Vanessa Kensington, he just might.',NULL,NULL,4.662,6.598,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(906,517839,'tt5501104',NULL,'Border','Gräns','movie',2018,'https://image.tmdb.org/t/p/w500/8KzOTRlKjdAKQTemV41hq86ldFS.jpg','https://image.tmdb.org/t/p/original/blHx3LrXsIfefFggOk4gjwdX73i.jpg','When a border guard with a sixth sense for identifying smugglers encounters the first person she cannot prove is guilty, she is forced to confront terrifying revelations about herself and humankind.',NULL,NULL,1.697,6.689,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(907,437583,'tt6164502',NULL,'November','November','movie',2017,'https://image.tmdb.org/t/p/w500/yMqtCSzSAB9Aiw8yiuUKBoxEeAm.jpg','https://image.tmdb.org/t/p/original/ueVnDMPdDDtAAjS8XniAiZkXes9.jpg','In a poor Estonian village, a group of peasants use magic and folk remedies to survive the winter, and a young woman tries to get a young man to love her.',NULL,NULL,1.7598,7.113,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(908,436343,'tt5607714',NULL,'On Body and Soul','Testről és lélekről','movie',2017,'https://image.tmdb.org/t/p/w500/uguWEoZelSSckxgiQctlkZ6gpfU.jpg','https://image.tmdb.org/t/p/original/s5BvDOLava3Z8NjAOnT0Xe96iLS.jpg','Two introverted people find out by pure chance that they share the same dream every night. They are puzzled, incredulous, a bit frightened. As they hesitantly accept this strange coincidence, they try to recreate in broad daylight what happens in their dream.',NULL,NULL,2.3342,7.256,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(909,381034,'tt4303340',NULL,'I Am Not a Serial Killer','I Am Not a Serial Killer','movie',2016,'https://image.tmdb.org/t/p/w500/KXLopjRCCGRaKPMUndVoT9zKsl.jpg','https://image.tmdb.org/t/p/original/vFkAaotkOIMZ2zJWHqVk8cRg2ub.jpg','In a small Midwestern town, a troubled teen with homicidal tendencies must hunt down and destroy a supernatural killer while keeping his own inner demons at bay.',NULL,NULL,1.0818,6.309,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(910,6312,'tt0237534',NULL,'Brotherhood of the Wolf','Le Pacte des loups','movie',2001,'https://image.tmdb.org/t/p/w500/w8CUoGAnP95txmIK2fl7leVmrmN.jpg','https://image.tmdb.org/t/p/original/wxijmbo9Oy5L9M9e4K1QhXVBRgm.jpg','In 18th century France, the Chevalier de Fronsac and his Native American friend Mani are sent by the King to the Gevaudan province to investigate the killings of hundreds by a mysterious beast.',NULL,NULL,6.8982,6.747,0,13.2925,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(911,75191,'tt2708480',NULL,'The Terror','The Terror','tv',2018,'https://image.tmdb.org/t/p/w500/fUVn5mScv83FfwrRUUR694yA7bd.jpg','https://image.tmdb.org/t/p/original/ssyZgYScV9eClakZDwu4sPrgMmy.jpg','A chilling anthology series featuring stories of people in terrifying situations inspired by true historical events.',NULL,NULL,18.0088,7.356,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(912,7305,'tt0106246',NULL,'Alive','Alive','movie',1993,'https://image.tmdb.org/t/p/w500/uQACcCZqd7WCTRin9xRIW5gr1bd.jpg','https://image.tmdb.org/t/p/original/qHXdyDBgetOyetVkWGzHYGp7L72.jpg','The amazing true story of a Uruguayan rugby team''s plane that crashed in the middle of the Andes mountains, and their immense will to survive and pull through alive, forced to do anything and everything they could to stay alive on meager rations and through the freezing cold.',NULL,NULL,4.9727,6.896,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(913,7485,'tt0822854',NULL,'Shooter','Shooter','movie',2007,'https://image.tmdb.org/t/p/w500/2aWGxo1E5polpBjPvtBRkWp7qaS.jpg','https://image.tmdb.org/t/p/original/uy2trYgO8MOQfQXlvMaLhBnkUqg.jpg','A top Marine sniper, Bob Lee Swagger, leaves the military after a mission goes horribly awry and disappears, living in seclusion. He is coaxed back into service after a high-profile government official convinces him to help thwart a plot to kill the President of the United States. Ultimately double-crossed and framed for the attempt, Swagger becomes the target of a nationwide manhunt. He goes on the run to track the real killer and find out who exactly set him up, and why, eventually seeking revenge against some of the most powerful and corrupt leaders in the free world.',NULL,NULL,15.0898,7.127,0,5.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(914,19383,'tt0063671',NULL,'Targets','Targets','movie',1968,'https://image.tmdb.org/t/p/w500/n0xQThLhrymktXzQbD0KwwUMXSB.jpg','https://image.tmdb.org/t/p/original/4BWKgipcFzDOZQPDZtmKGZVhEoU.jpg','An aging horror-movie icon''s fate intersects with that of a seemingly ordinary young man on a psychotic shooting spree around Los Angeles.',NULL,NULL,1.4862,7.1,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(915,10642,'tt0217630',NULL,'Loser','Loser','movie',2000,'https://image.tmdb.org/t/p/w500/nOqWmYfgvpUA6gZjvdB0Cg24kA4.jpg','https://image.tmdb.org/t/p/original/r80VehB1GzdOReLSgr0N4iWo5id.jpg','On a university scholarship, a good natured student from the midwest gets a crash course in city life while dealing with three evil roommates. He befriends a virtually homeless college student whom he falls for, but she''s dating a nasty professor.',NULL,NULL,2.5251,5.404,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(916,190859,'tt2179136',NULL,'American Sniper','American Sniper','movie',2014,'https://image.tmdb.org/t/p/w500/i1U46OwMc6vlm7OoSUKfqUH615e.jpg','https://image.tmdb.org/t/p/original/rl95VDEP3nsUQmGzE0S1S7y6T0N.jpg','U.S. Navy SEAL Chris Kyle takes his sole mission—protect his comrades—to heart and becomes one of the most lethal snipers in American history. His pinpoint accuracy not only saves countless lives but also makes him a prime target of insurgents. Despite grave danger and his struggle to be a good husband and father to his family back in the States, Kyle serves four tours of duty in Iraq. However, when he finally returns home, he finds that he cannot leave the war behind.',NULL,NULL,8.9589,7.412,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(917,15916,'tt0208502',NULL,'Angel''s Egg','天使のたまご','movie',1985,'https://image.tmdb.org/t/p/w500/dcEUGvckbePFzPKhGXnS9T3kZMG.jpg','https://image.tmdb.org/t/p/original/nZn384qWYugXu6U1N8Ya0Iv0NXE.jpg','In the ruins of a strange city, a young girl takes care of a large egg she holds carefully in her arms. She bonds with a boy who is searching for a bird he saw in a dream.',NULL,NULL,2.3553,7.702,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(918,55420,'tt1549572',NULL,'Another Earth','Another Earth','movie',2011,'https://image.tmdb.org/t/p/w500/qvGJK3lFzpifAdyIupMNdWNX0qr.jpg','https://image.tmdb.org/t/p/original/fJfpZnS2pvFCtyaDqoIgKLASvAT.jpg','On the night a duplicate Earth is discovered in the solar system, the lives of a young woman and an accomplished composer become tragically connected after a fatal accident.',NULL,NULL,2.4641,6.724,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(919,104268,'tt0113834',NULL,'August in the Water','水の中の八月','movie',1995,'https://image.tmdb.org/t/p/w500/7DSzmj7srsNMtiYntX2VeZEVufN.jpg','https://image.tmdb.org/t/p/original/miC9OE0Y4tC21k9mMp3cpykvdKM.jpg','A teenage girl gains supernatural power after an accident and comes to understand her place in the universe.',NULL,NULL,0.6626,6.9,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(920,828947,'tt14145426',NULL,'Beavis and Butt-Head Do the Universe','Beavis and Butt-Head Do the Universe','movie',2022,'https://image.tmdb.org/t/p/w500/rVKMA2j8m8hWgsDyXOllXp8DsWI.jpg','https://image.tmdb.org/t/p/original/35xpwiUhgdXofUZe9RCtk0jn6RW.jpg','In 1998, Beavis and Butt-Head are sentenced to Space Camp by a “creative” judge. Their obsession with a docking simulator (huh huh) leads to a trip on the Space Shuttle, with predictably disastrous results. After going through a black hole, they re-emerge in our time, where they look for love, misuse iPhones, and are hunted by the Deep State. Spoiler: They don’t score.',NULL,NULL,1.1051,6.922,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(921,7443,'tt0120630',NULL,'Chicken Run','Chicken Run','movie',2000,'https://image.tmdb.org/t/p/w500/8XgmIsbpVamdhwcNVsYzohFZTtT.jpg','https://image.tmdb.org/t/p/original/3eYkMSjWbvTaZso7ow5ub9ikNNq.jpg','The creators of Wallace & Gromit bring you an exciting and original story about a group of chickens determined to fly the coop–even if they can’t fly! It’s hardly poultry in motion when Rocky attempts to teach Ginger and her feathered friends to fly…but, with teamwork, determination and a little bit o’ cluck, the fearless flock plots one last attempt in a spectacular bid for freedom.',NULL,NULL,6.5356,6.847,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(922,693134,'tt15239678',NULL,'Dune: Part Two','Dune: Part Two','movie',2024,'https://image.tmdb.org/t/p/w500/1pdfLvkbY9ohJlCjQH2CZjjYVvJ.jpg','https://image.tmdb.org/t/p/original/eZ239CUp1d6OryZEBPnO2n87gMG.jpg','Follow the mythic journey of Paul Atreides as he unites with Chani and the Fremen while on a path of revenge against the conspirators who destroyed his family. Facing a choice between the love of his life and the fate of the known universe, Paul endeavors to prevent a terrible future only he can foresee.',NULL,NULL,30.4869,8.128,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(923,343,'tt0067185',NULL,'Harold and Maude','Harold and Maude','movie',1971,'https://image.tmdb.org/t/p/w500/t7qEuGwDjcYu8ajaKZ68DeDnOxw.jpg','https://image.tmdb.org/t/p/original/jKgfnnCATAg4fxMfS0LZThmqOZB.jpg','A deadpan young man obsessed with death meets an eccentric septuagenarian who teaches him to live life to the fullest.',NULL,NULL,2.6029,7.587,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(924,167,'tt0272152',NULL,'K-PAX','K-PAX','movie',2001,'https://image.tmdb.org/t/p/w500/tafXZX0I6rso7EyoEzfygfTqxq6.jpg','https://image.tmdb.org/t/p/original/v8xav2JYqqn3O14s0PR4UgWBz95.jpg','Prot is a patient at a mental hospital who claims to be from a far away planet. His psychiatrist tries to help him, only to begin to doubt his own explanations.',NULL,NULL,3.5876,7.211,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(925,968100,NULL,NULL,'Millennium Actress: Tracks','千年女優 -軌跡-','movie',2001,'https://image.tmdb.org/t/p/w500/rQfutJfJL3SgcThccDdaK8JVp81.jpg','https://image.tmdb.org/t/p/original/rotos6RU7DII22CxlKvasRmj5Eb.jpg','A documentary about the production of the famous Japanese animation "Millennium Actress" by genius director Satoshi Kon, a god-like work. Unfortunately, genius is always short-lived.',NULL,NULL,0.3102,8.5,0,11.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(926,86834,'tt1959490',NULL,'Noah','Noah','movie',2014,'https://image.tmdb.org/t/p/w500/vVLkHabnF5lVpCpqyhZBI5iCYMA.jpg','https://image.tmdb.org/t/p/original/5z75Q6nqgwgYfpMB9fVHQcw9gMz.jpg','A man who suffers visions of an apocalyptic deluge takes measures to protect his family from the coming flood.',NULL,NULL,4.971,5.677,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(927,508883,'tt6587046',NULL,'The Boy and the Heron','君たちはどう生きるか','movie',2023,'https://image.tmdb.org/t/p/w500/f4oZTcfGrVTXKTWg157AwikXqmP.jpg','https://image.tmdb.org/t/p/original/75nSb1fbWooipwcSU5bUttiOriI.jpg','While the Second World War rages, the teenage Mahito, haunted by his mother''s tragic death, is relocated from Tokyo to the serene rural home of his new stepmother Natsuko, a woman who bears a striking resemblance to the boy''s mother.  As he tries to adjust, this strange new world grows even stranger following the appearance of a persistent gray heron, who perplexes and bedevils Mahito, dubbing him the "long-awaited one."',NULL,NULL,7.9402,7.393,0,13.2625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(928,670292,'tt11858890',NULL,'The Creator','The Creator','movie',2023,'https://image.tmdb.org/t/p/w500/3dSivDtOuyxLDxPH4v2tcNG1fP7.jpg','https://image.tmdb.org/t/p/original/iQcCAm8hKWZyUntqrvzyEGtXyJl.jpg','Amid a future war between the human race and the forces of artificial intelligence, a hardened ex-special forces agent grieving the disappearance of his wife, is recruited to hunt down and kill the Creator, the elusive architect of advanced AI who has developed a mysterious weapon with the power to end the war—and mankind itself.',NULL,NULL,7.8201,7.036,0,8.36,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(929,13363,'tt0756683',NULL,'The Man from Earth','The Man from Earth','movie',2007,'https://image.tmdb.org/t/p/w500/V086R82gNgWrotaXZFO4JhdgB1.jpg','https://image.tmdb.org/t/p/original/gt4EnUGbbGbNOX0q47YII3WxB48.jpg','A departing professor gathers his closest colleagues for an intimate farewell, but the night takes an unexpected turn when he shares a stunning secret about his past. As the conversation unfolds, skepticism and curiosity collide, challenging everything they thought they knew about history, science, and belief.',NULL,NULL,4.6983,7.628,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(930,145197,'tt2084989',NULL,'Upstream Color','Upstream Color','movie',2013,'https://image.tmdb.org/t/p/w500/tQ4IWxSYIgZVWnQwLCG8r6sUraU.jpg','https://image.tmdb.org/t/p/original/s1DqTGJ96V0Q8YxL9GZVkJi48jZ.jpg','A man and woman are drawn together, entangled in the lifecycle of an ageless organism. Identity becomes an illusion as they struggle to assemble the loose fragments of wrecked lives.',NULL,NULL,1.0661,6.344,0,1.28180000000000013e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(931,144,'tt0093191',NULL,'Wings of Desire','Der Himmel über Berlin','movie',1987,'https://image.tmdb.org/t/p/w500/iZQs2vUeCzvS1KfZJ6uYNCGJBBV.jpg','https://image.tmdb.org/t/p/original/7TlGXrB4WQ3wbpOCUQnBXseCuOl.jpg','Two angels, Damiel and Cassiel, glide through the streets of Berlin, observing the bustling population, providing invisible rays of hope to the distressed but never interacting with them. When Damiel falls in love with lonely trapeze artist Marion, the angel longs to experience life in the physical world, and finds — with some words of wisdom from actor Peter Falk — that it might be possible for him to take human form.',NULL,NULL,2.9711,7.8,0,1.23566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(932,11906,'tt0076786',NULL,'Suspiria','Suspiria','movie',1977,'https://image.tmdb.org/t/p/w500/sEcvc9h1X3hYZdFgtiiKMm6RB3f.jpg','https://image.tmdb.org/t/p/original/j7rl2LphIbC88FppTfwJ5Gxj9kX.jpg','An American newcomer to a prestigious German ballet academy comes to realize that the school is a front for something sinister amid a series of grisly murders.',NULL,NULL,4.2564,7.467,0,12.56,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(933,414,'tt0112462',NULL,'Batman Forever','Batman Forever','movie',1995,'https://image.tmdb.org/t/p/w500/i0fJS8M5UKoETjjJ0zwUiKaR8tr.jpg','https://image.tmdb.org/t/p/original/snlu32RmjldF9b068UURJg8sQtn.jpg','Batman faces off against two foes: the schizophrenic, horribly scarred former District Attorney Harvey Dent, aka Two-Face, and the Riddler, a disgruntled ex-Wayne Enterprises inventor seeking revenge against his former employer by unleashing his brain-sucking weapon on Gotham City''s residents. As the caped crusader also copes with tortured memories of his parents'' murder, he has a new romance, with psychologist Chase Meridian.',NULL,NULL,6.6943,5.5,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(934,415,'tt0118688',NULL,'Batman & Robin','Batman & Robin','movie',1997,'https://image.tmdb.org/t/p/w500/i7hEUpDuMN2LOrCEifFyGSHZQSY.jpg','https://image.tmdb.org/t/p/original/kEuQWHte2erRpAICrYqkAZaZAAY.jpg','Batman and his sidekick Robin attempt to the foil the sinister schemes of a deranged set of new villains, most notably the melancholy Mr. Freeze, who wants to make Gotham City into an arctic region, and the sultry Poison Ivy, a botanical femme fatale. As the Dynamic Duo contend with these bad guys, a third hero, Batgirl, joins the ranks of the city''s crime-fighters.',NULL,NULL,7.7391,4.394,0,1.2673333333333332e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(935,49010,'tt1640459',NULL,'Hobo with a Shotgun','Hobo with a Shotgun','movie',2011,'https://image.tmdb.org/t/p/w500/xxMaO7VoN2BnZit79PedVHnTjcO.jpg','https://image.tmdb.org/t/p/original/7ugJdVksDA4oYCxZY6tHhsG2NyV.jpg','A vigilante homeless man pulls into a new city and finds himself trapped in urban chaos, a city where crime rules and where the city''s crime boss reigns. Seeing an urban landscape filled with armed robbers, corrupt cops, abused prostitutes and even a pedophile Santa, the Hobo goes about bringing justice to the city the best way he knows how - with a 20-gauge shotgun. Mayhem ensues when he tries to make things better for the future generation. Street justice will indeed prevail.',NULL,NULL,1.5708,5.9,0,1.20566666666666666e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(936,9529,'tt0103919',NULL,'Candyman','Candyman','movie',1992,'https://image.tmdb.org/t/p/w500/jQtgkgDZE7egMq532sOt83DnT83.jpg','https://image.tmdb.org/t/p/original/l0JgqFNxeMb1OoHq1CzdYC3Y5J8.jpg','The Candyman, a murderous soul with a hook for a hand, is accidentally summoned to reality by a skeptic grad student researching the monster''s myth.',NULL,NULL,4.4415,6.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(937,9558,'tt0099939',NULL,'King of New York','King of New York','movie',1990,'https://image.tmdb.org/t/p/w500/1MyH4MJAJZJbb6wDVeOc2bTECtK.jpg','https://image.tmdb.org/t/p/original/oQMuvptruDYovmB9VFpnYDnVk5j.jpg','A former drug lord returns from prison determined to wipe out all his competition and distribute the profits of his operations to New York''s poor and lower classes in this stylish and ultra violent modern twist on Robin Hood.',NULL,NULL,4.922,6.752,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(938,793,'tt0090756',NULL,'Blue Velvet','Blue Velvet','movie',1986,'https://image.tmdb.org/t/p/w500/6v1zYh2FKOYVddY5pCQhd4PO9uX.jpg','https://image.tmdb.org/t/p/original/s1CBwblInR0ZBIv59CSko2QdLD3.jpg','The discovery of a severed human ear found in a field leads a young man on an investigation related to a beautiful, mysterious nightclub singer and a group of psychopathic criminals who have kidnapped her child.',NULL,NULL,6.5425,7.6,0,18.58,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(939,7304,'tt0404390',NULL,'Running Scared','Running Scared','movie',2006,'https://image.tmdb.org/t/p/w500/f2LU6M8wFmt6G1fzv9JFWbIkRd9.jpg','https://image.tmdb.org/t/p/original/p5z5X3GRnaFEqgtEa7fiGhgtUkA.jpg','A low-ranking thug is entrusted by his boss to dispose of a gun that killed corrupt cops, but things spiral out of control when the gun ends up in wrong hands.',NULL,NULL,2.5145,6.997,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(940,328387,'tt3531824',NULL,'Nerve','Nerve','movie',2016,'https://image.tmdb.org/t/p/w500/qmSpHC0CSNyNll9WhlwWYuwoQ28.jpg','https://image.tmdb.org/t/p/original/fg04CQyJzuDJ82jm2meY37n9XyE.jpg','Industrious high school senior Vee Delmonico has had it with living life on the sidelines. When pressured by friends to join the popular online game Nerve, Vee decides to sign up for just one dare in what seems like harmless fun. But as she finds herself caught up in the thrill of the adrenaline-fueled competition partnered with a mysterious stranger, the game begins to take a sinister turn with increasingly dangerous acts, leading her into a high stakes finale that will determine her entire future.',NULL,NULL,2.9294,6.998,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(941,34223,'tt0092147',NULL,'Vamp','Vamp','movie',1986,'https://image.tmdb.org/t/p/w500/fWXjESqmqU8QCrfWowVcdeC8Uij.jpg','https://image.tmdb.org/t/p/original/d3zD3SZbi6mPSOt8BnLvo0OD3MF.jpg','Two fraternity pledges go to a sleazy bar in search of a stripper for their college friends, unaware it is occupied by vampires.',NULL,NULL,3.62,5.813,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(942,2436,'tt0106761',NULL,'Double Dragon','Double Dragon','movie',1994,'https://image.tmdb.org/t/p/w500/9ZTYSD8ZesYMKqLRbmVfZUW1FiE.jpg','https://image.tmdb.org/t/p/original/gJXt3gMz4EF39mdyhvy5EsXdiPk.jpg','Two brothers have half of a powerful ancient Chinese talisman. An evil gang leader has the other half, and determines to get the brothers'' half and have a complete medallion so he can gain absolute power.',NULL,NULL,1.5997,4.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(943,11835,'tt0804461',NULL,'Death Sentence','Death Sentence','movie',2007,'https://image.tmdb.org/t/p/w500/3rdEAMh4a3pc7GO6fSkJwpt7BWX.jpg','https://image.tmdb.org/t/p/original/tlPAcPTRJmHgULtUVIasQWQQiVN.jpg','Nick Hume is a mild-mannered executive with a perfect life, until one gruesome night he witnesses something that changes him forever. Transformed by grief, Hume eventually comes to the disturbing conclusion that no length is too great when protecting his family.',NULL,NULL,2.2358,6.788,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(944,210577,'tt2267998',NULL,'Gone Girl','Gone Girl','movie',2014,'https://image.tmdb.org/t/p/w500/ts996lKsxvjkO2yiYG0ht4qAicO.jpg','https://image.tmdb.org/t/p/original/iWak7wT0j6ycCc8lKr4NBz9c7n5.jpg','With his wife''s disappearance having become the focus of an intense media circus, a man sees the spotlight turned on him when it''s suspected that he may not be innocent.',NULL,NULL,24.818,7.891,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(945,261392,'tt3316948',NULL,'American Ultra','American Ultra','movie',2015,'https://image.tmdb.org/t/p/w500/g9JX6RZQoTInDJhbrKItnOr47qr.jpg','https://image.tmdb.org/t/p/original/wSdXmiaTcdfREfUa3cGfbgYHHlV.jpg','Mike is an unmotivated stoner whose small-town life with his live-in girlfriend, Phoebe, is suddenly turned upside down.  Unbeknownst to him, Mike is actually a highly trained, lethal sleeper agent. In the blink of an eye, as his secret past comes back to haunt him, Mike is thrust into the middle of a deadly government operation and is forced to summon his inner action-hero in order to survive.',NULL,NULL,2.9506,6.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(946,812,'tt0103639',NULL,'Aladdin','Aladdin','movie',1992,'https://image.tmdb.org/t/p/w500/eLFfl7vS8dkeG1hKp5mwbm37V83.jpg','https://image.tmdb.org/t/p/original/nenJjvfe2Eq8uBMXFJnWj5mw4bi.jpg','In the boorish city of Agrabah, kind-hearted street urchin Aladdin and Princess Jasmine fall in love, although she can only marry a prince. He and power-hungry Grand Vizier Jafar vie for a magic lamp that can fulfill their wishes.',NULL,NULL,12.0041,7.7,0,9.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(947,12888,'tt0158493',NULL,'Belly','Belly','movie',1998,'https://image.tmdb.org/t/p/w500/i4QhjdZXxdOpKOhc9kh4qqWjRWr.jpg','https://image.tmdb.org/t/p/original/bmyugjdRl1aEOfBePwUpykIY3x3.jpg','Tommy Bundy and Sincere are best friends as well as infamous and ruthless criminals and shot-callers in the hood. Respected by many but feared by all.  As the police are closing in on them and new players are looking for a come up, will their reign last?',NULL,NULL,2.0714,6.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(948,429476,'tt1999890',NULL,'Hell Fest','Hell Fest','movie',2018,'https://image.tmdb.org/t/p/w500/qgLlnlrUtTKXkdrgMBwUfkyAkya.jpg','https://image.tmdb.org/t/p/original/orfMBe5LbJG7pySD1dxHbLOHJ9r.jpg','On Halloween night at a horror theme park, a costumed killer begins slaying innocent patrons who believe that it''s all part of the festivities.',NULL,NULL,2.0402,5.672,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(949,301365,'tt1974419',NULL,'The Neon Demon','The Neon Demon','movie',2016,'https://image.tmdb.org/t/p/w500/3rBo2AfWSlvsPmYFdJsNUMfkNIo.jpg','https://image.tmdb.org/t/p/original/xcfjWEmSpgJe8htlg1qFTwQfPG7.jpg','When aspiring model Jesse moves to Los Angeles, her youth and vitality are devoured by a group of beauty-obsessed women who will take any means necessary to get what she has.',NULL,NULL,4.1138,6.5,0,1.62771428571428593e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(950,520023,'tt8110652',NULL,'Bodies Bodies Bodies','Bodies Bodies Bodies','movie',2022,'https://image.tmdb.org/t/p/w500/hSuTjDmqRdy7Dii8ymnF2WILTeP.jpg','https://image.tmdb.org/t/p/original/qYCl28dMJwRTzlbteTrW75szZPN.jpg','In an isolated family mansion, a group of rich 20-somethings decides to play Bodies Bodies Bodies, a game where one of them is secretly a "killer" while the rest tries to "escape". Things take a turn for the worse when real bodies start turning up, setting off a paranoid and dangerous chain of events.',NULL,NULL,11.0475,6.143,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(951,466,'tt0067309',NULL,'Klute','Klute','movie',1971,'https://image.tmdb.org/t/p/w500/tVyINAsNGSgD1OIstqwCcs7wyGH.jpg','https://image.tmdb.org/t/p/original/bxh7ybql4p24u9WsX1GI9v9PDLg.jpg','A high-priced call girl is forced to depend on a reluctant private eye when she is stalked by a psychopath.',NULL,NULL,2.6127,6.752,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(952,426268,'tt4245838',NULL,'Into the Void','Into the Void','movie',2000,NULL,NULL,'A college freshman invites his younger brother to hang out with him at his new school, but that one night will ultimately haunt him the rest of his life.',NULL,NULL,0.4713,0.0,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(953,21208,'tt1148204',NULL,'Orphan','Orphan','movie',2009,'https://image.tmdb.org/t/p/w500/lCGpOgoTOGLtZnBiGY9HRg5Xnjd.jpg','https://image.tmdb.org/t/p/original/hHlFspcHTLGFo8BwOSCsX9eHtbY.jpg','After losing their baby, a married couple adopt 9-year old Esther, who may not be as innocent as she seems.',NULL,NULL,5.665,6.991,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(954,63,'tt0114746',NULL,'Twelve Monkeys','Twelve Monkeys','movie',1995,'https://image.tmdb.org/t/p/w500/gt3iyguaCIw8DpQZI1LIN5TohM2.jpg','https://image.tmdb.org/t/p/original/mKIkGoyuR71qz6FdiEiOjxvBQcS.jpg','In the year 2035, convict James Cole reluctantly volunteers to be sent back in time to discover the origin of a deadly virus that wiped out nearly all of the earth''s population and forced the survivors into underground communities. But when Cole is mistakenly sent to 1990 instead of 1996, he''s arrested and locked up in a mental hospital. There he meets psychiatrist Dr. Kathryn Railly and the son of a famous virus expert who may hold the key to the Army of the 12 Monkeys; thought to be responsible for unleashing the killer disease.',NULL,NULL,7.8392,7.61,0,1.27666666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(955,112314,'tt13365348',NULL,'Archive 81','Archive 81','tv',2022,'https://image.tmdb.org/t/p/w500/l1jeSEm6a88GFcLzlHQr60D0dOi.jpg','https://image.tmdb.org/t/p/original/7TYMho2TM6ZcqSv6YaEjlNIyhXn.jpg','An archivist takes a job restoring damaged videotapes and gets pulled into the vortex of a mystery involving the missing director and a demonic cult.',NULL,NULL,4.5021,7.223,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(956,853387,'tt11893676',NULL,'Lord of Misrule','Lord of Misrule','movie',2023,'https://image.tmdb.org/t/p/w500/3cxMwPuV5BroI91DZLGdio6WB34.jpg','https://image.tmdb.org/t/p/original/8mnswbAAq9kvkUpzcbTfSrt1DpN.jpg','When the daughter of the town''s new priest goes missing during the harvest festival, a desperate search begins, uncovering the town''s dark history and resurfacing tales of a mysterious, malevolent spirit that demands sacrifice.',NULL,NULL,0.7204,5.735,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(957,72349,'tt0085515',NULL,'Eyes of Fire','Eyes of Fire','movie',1983,'https://image.tmdb.org/t/p/w500/mxT0psJTjT2yri8QOvHE4N7iANo.jpg','https://image.tmdb.org/t/p/original/8NtxjzJx9poLMx1AXlWlBHdujTA.jpg','In 1750, an adulterous preacher is ejected from a small British colony with his motley crew of followers, who make their way downriver to establish a new settlement of their own beyond the western frontier.',NULL,NULL,1.0709,5.5,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(958,57230,'tt0062453',NULL,'Viy','Вий','movie',1967,'https://image.tmdb.org/t/p/w500/rgkp4X9C1NNobH8bq55zcMTQFCl.jpg','https://image.tmdb.org/t/p/original/8NdbgS3Ndc7Q8cZIuHquhID9C6j.jpg','A seminary student on monastery holiday kills an old witch in a remote village. The hag then transforms into a beautiful young woman whose dying wish is for him to watch over her wake for three nights. With terrors occurring and his faith waning, he reads prayers on the overnight watch and tries to survive the supernatural encounters.',NULL,NULL,2.6543,6.9,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(959,1032950,'tt19724142',NULL,'Hellhole','Ostatnia wieczerza','movie',2022,'https://image.tmdb.org/t/p/w500/y47wBamj9vdqBeGaLEFTrYEPTeC.jpg','https://image.tmdb.org/t/p/original/xXSjMjCdZ6v7NIFvsSMNqe4ySkF.jpg','In a monastery cut off from the world, the monks run a clinic for the possessed. One day, a young policeman Marek comes to the convent. Posing as a clergyman, he penetrates monastic life and tries to explain the recent, mysterious disappearance of several tormented inmates. It turns out, however, that there is no way out of the monastery.',NULL,NULL,1.3859,6.136,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(960,466565,'tt7323600',NULL,'Hagazussa','Hagazussa','movie',2018,'https://image.tmdb.org/t/p/w500/qxUiwpRKagcNHFlly5IpcbX0QPI.jpg','https://image.tmdb.org/t/p/original/4ioXfbRTllE0YsZsBlr7fBTUr4l.jpg','In the 15th century, a young goatherd living alone in a mountain hut feels a dark presence in the woods.',NULL,NULL,1.542,5.722,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(961,931944,'tt29141112',NULL,'The Devil''s Bath','Des Teufels Bad','movie',2024,'https://image.tmdb.org/t/p/w500/txVfrmwFOKB5qczM0ENYSqKMnSv.jpg','https://image.tmdb.org/t/p/original/9oD95lebaaSNQHnLTLjjfITaCg7.jpg','In 1750 Austria, a deeply religious woman named Agnes has just married her beloved, but her mind and heart soon grow heavy as her life becomes a long list of chores and expectations. Day after day, she is increasingly trapped in a murky and lonely path leading to evil thoughts, until the possibility of committing a shocking act of violence seems like the only way out of her inner prison.',NULL,NULL,2.8675,6.608,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(962,848886,'tt14905650',NULL,'Hellbender','Hellbender','movie',2021,'https://image.tmdb.org/t/p/w500/uLDYfeJ9BvrQsC3MBqMUjG4Hgaz.jpg','https://image.tmdb.org/t/p/original/rJcswoyg0pw9oRJarbGC0sIazR1.jpg','A teen and her mother live simply in a home in the woods, spending their time making rock music. A chance encounter with a fellow teen causes her to uncover a connection between her family and witchcraft, which causes a rift with her mother.',NULL,NULL,1.07,5.581,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(963,611651,'tt10556320',NULL,'Sator','Sator','movie',2019,'https://image.tmdb.org/t/p/w500/zij3xfDWx2D8kckKjLPypgwLdK1.jpg','https://image.tmdb.org/t/p/original/lch8GEMczkpRabis40Uhw8zkVA9.jpg','Secluded in a desolate forest, a broken family is observed by Sator, a supernatural entity who is attempting to claim them.',NULL,NULL,0.8287,5.012,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(964,575776,'tt7557108',NULL,'Saint Maud','Saint Maud','movie',2020,'https://image.tmdb.org/t/p/w500/ArNYeeDFLVye7JpqLElYdbE6fOa.jpg','https://image.tmdb.org/t/p/original/1WKxsnrhLoKPHcTyph7lhZnAMjR.jpg','Having recently found God, self-effacing young nurse Maud arrives at a plush home to care for Amanda, a hedonistic dancer left frail from a chronic illness. When a chance encounter with a former colleague throws up hints of a dark past, it becomes clear there is more to sweet Maud than meets the eye.',NULL,NULL,1.8327,6.5,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(965,409297,'tt4805316',NULL,'A Dark Song','A Dark Song','movie',2016,'https://image.tmdb.org/t/p/w500/fguce8M1bZnWjVkRWCFh9P3kt6A.jpg','https://image.tmdb.org/t/p/original/sac5saRWC8zV8GFHL4D45TuUr3s.jpg','A determined young woman and a damaged occultist risk their lives and souls to perform a dangerous ritual that will grant them what they want.',NULL,NULL,1.4998,6.3,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(966,745881,'tt13446168',NULL,'The Medium','ร่างทรง','movie',2021,'https://image.tmdb.org/t/p/w500/tWoSE8SH6XhgWKHIL3p0sj7lA3V.jpg','https://image.tmdb.org/t/p/original/iwCti1LGupsMjCzuhaccUA4OZfo.jpg','A shaman''s family learn that their goddess is supposedly controlling one of them. However, their lives take a frightening turn when they realise the goddess has nothing to do with the possession.',NULL,NULL,6.0748,7.003,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(967,680593,'tt10229558',NULL,'The Dark and the Wicked','The Dark and the Wicked','movie',2020,'https://image.tmdb.org/t/p/w500/4DB9VFVTp0IQEWFEIf9f3f2z3t5.jpg','https://image.tmdb.org/t/p/original/7uEioqlOZrjmUQSX9jYVM00E7hk.jpg','On a secluded farm in a nondescript rural town, a man is slowly dying. His family gathers to mourn, and soon a darkness grows, marked by waking nightmares and a growing sense that something evil is taking over the family.',NULL,NULL,2.3599,6.147,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(968,639933,'tt11138512',NULL,'The Northman','The Northman','movie',2022,'https://image.tmdb.org/t/p/w500/aSSJMnHknzKjlZ6zybwD7eyJ4Po.jpg','https://image.tmdb.org/t/p/original/fMiEp00v8gGWEceL4QeLu6H6z69.jpg','Prince Amleth is on the verge of becoming a man when his father is brutally murdered by his uncle, who kidnaps the boy''s mother. Two decades later, Amleth is now a Viking who''s on a mission to save his mother, kill his uncle and avenge his father.',NULL,NULL,7.3029,7.031,0,11.57,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(969,542224,'tt9086228',NULL,'Gretel & Hansel','Gretel & Hansel','movie',2020,'https://image.tmdb.org/t/p/w500/mBBBXseq4k4dI63k06XIrsc02j8.jpg','https://image.tmdb.org/t/p/original/en1XAePgWqNSXb82luUMmo5u3cF.jpg','A long time ago in a distant fairy tale countryside, a young girl leads her little brother into a dark wood in desperate search of food and work, only to stumble upon a nexus of terrifying evil.',NULL,NULL,2.5852,6.026,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(970,635,'tt0092563',NULL,'Angel Heart','Angel Heart','movie',1987,'https://image.tmdb.org/t/p/w500/h5v3wjJQNB7q2RntEnKDLhKtTFE.jpg','https://image.tmdb.org/t/p/original/viDonz5uLmengw9RUAh3Rf65dQG.jpg','A down-and-out Brooklyn detective is hired to track down a singer on an odyssey that will take him through the desperate streets of Harlem, the smoke-filled jazz clubs of New Orleans, and the swamps of Louisiana and its seedy underworld of voodoo.',NULL,NULL,3.9811,7.122,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(971,74725,'tt1788391',NULL,'Kill List','Kill List','movie',2011,'https://image.tmdb.org/t/p/w500/qwT2I3ons0oD58jIppKmd4qLtvB.jpg','https://image.tmdb.org/t/p/original/ptZypdOBofmADX9JCtgi5E38cnC.jpg','Nearly a year after a botched job, a hitman takes a new assignment with the promise of a big payoff for three killings. What starts off as an easy task soon unravels, sending the killer into the heart of darkness.',NULL,NULL,2.031,6.204,0,14.0225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(972,109428,'tt1288558',NULL,'Evil Dead','Evil Dead','movie',2013,'https://image.tmdb.org/t/p/w500/1gDV0Lm9y8ufIKzyf0h0GBgb9Zj.jpg','https://image.tmdb.org/t/p/original/6RDgtEBzjuF7W25DVziXRABchpX.jpg','Mia, a drug addict, is determined to kick the habit. To that end, she asks her brother, David, his girlfriend, Natalie and their friends Olivia and Eric to accompany her to their family''s remote forest cabin to help her through withdrawal. Eric finds a mysterious Book of the Dead at the cabin and reads aloud from it, awakening an ancient demon. All hell breaks loose when the malevolent entity possesses Mia.',NULL,NULL,32.1608,6.62,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(973,133369,'tt2330322',NULL,'The Conspiracy','The Conspiracy','movie',2012,'https://image.tmdb.org/t/p/w500/y0tpJXx8i4jTVMKAUIoXYb7Hv8y.jpg','https://image.tmdb.org/t/p/original/rw5KkuMdw9wPaHh6HAZNCJUBtUi.jpg','A documentary about conspiracy theories takes a horrific turn after the filmmakers uncover an ancient and dangerous secret society.',NULL,NULL,0.8908,5.987,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(974,490,'tt0050976',NULL,'The Seventh Seal','Det sjunde inseglet','movie',1957,'https://image.tmdb.org/t/p/w500/wcZ21zrOsy0b52AfAF50XpTiv75.jpg','https://image.tmdb.org/t/p/original/6s2BqtDvp1BMiP70zCDU5OW6hMy.jpg','When disillusioned Swedish knight Antonius Block returns home from the Crusades to find his country in the grips of the Black Death, he challenges Death to a chess match for his life. Tormented by the belief that God does not exist, Block sets off on a journey, meeting up with traveling players Jof and his wife, Mia, and becoming determined to evade Death long enough to commit one redemptive act while he still lives.',NULL,NULL,6.6122,8.147,0,13.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(975,516329,'tt7740510',NULL,'Antlers','Antlers','movie',2021,'https://image.tmdb.org/t/p/w500/cMch3tiexw3FdOEeZxMWVel61Xg.jpg','https://image.tmdb.org/t/p/original/10sdvlxjeTZNBxPg0PLl4CKU7v0.jpg','A small-town Oregon teacher and her brother, the local sheriff, discover a young student is harbouring a dangerous secret that could have frightening consequences.',NULL,NULL,2.2514,6.211,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(976,412546,'tt9213244',NULL,'Antrum','Antrum','movie',2018,'https://image.tmdb.org/t/p/w500/20de4Rcmy4B0L5zyOc3Nc5F7c0D.jpg','https://image.tmdb.org/t/p/original/kUfhJUEa4Djx9yCxYCkuEcJFE12.jpg','Rumored to have been lost, Antrum appears as a cursed film from the 1970s. Viewers are warned to proceed with caution. It’s said to be a story about a young boy and girl who enter the forest in an attempt to save the soul of their recently deceased pet. They journey to “The Antrum,” the very spot the devil landed after being cast out of heaven. There, the children begin to dig a hole to hell.',NULL,NULL,1.4358,5.763,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(977,378018,'tt4255304',NULL,'The Void','The Void','movie',2016,'https://image.tmdb.org/t/p/w500/2WhZAPi3vomEQdzAPIYTvmvWaxI.jpg','https://image.tmdb.org/t/p/original/oZwwwezJFlHmQGBRJDLmENXwOIt.jpg','In the middle of a routine patrol, officer Daniel Carter happens upon a blood-soaked figure limping down a deserted stretch of road. He rushes the young man to a nearby rural hospital staffed by a skeleton crew, only to discover that patients and personnel are transforming into something inhuman. As the horror intensifies, Carter leads the other survivors on a hellish voyage into the subterranean depths of the hospital in a desperate bid to end the nightmare before it''s too late.',NULL,NULL,3.5487,6.02,0,1.99530000000000029e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(978,157433,'tt0837563',NULL,'Pet Sematary','Pet Sematary','movie',2019,'https://image.tmdb.org/t/p/w500/7SPhr7Qj39vbnfF9O2qHRYaKHAL.jpg','https://image.tmdb.org/t/p/original/8iZjnNSIH4teZERl0VjUeHHVrec.jpg','Dr. Louis Creed and his wife, Rachel, move from Boston to Ludlow, in rural Maine, with their two young children. Hidden in the woods near the new family home, Ellie, their eldest daughter, discovers a mysterious cemetery where the pets of community members are buried.',NULL,NULL,3.3561,5.743,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(979,609972,'tt10515988',NULL,'Paranormal Activity: Next of Kin','Paranormal Activity: Next of Kin','movie',2021,'https://image.tmdb.org/t/p/w500/wRy3SwJFE55iL2bfKqECzP2qyrd.jpg','https://image.tmdb.org/t/p/original/xAnSELun945cE4kFUD9mI7W3puI.jpg','Margot is a documentary filmmaker looking to meet her long-lost mother and extended family in a secluded Amish community. She and her film crew soon realize the family that welcomes them into their home might be hiding a sinister secret.',NULL,NULL,3.0593,6.134,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(980,1193824,'tt29567402',NULL,'Rabbit Trap','Rabbit Trap','movie',2025,'https://image.tmdb.org/t/p/w500/sKnwnnmBpjo9BEskHtja6ToXUV1.jpg','https://image.tmdb.org/t/p/original/xkKDKUHQKgjgGuyzFihKoWQIvK0.jpg','When a musician and her husband move to a remote house in Wales, the music they make disturbs local ancient folk magic, bringing a nameless child to their door who is intent on infiltrating their lives.',NULL,NULL,1.4314,5.622,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(981,419831,'tt4547194',NULL,'I Kill Giants','I Kill Giants','movie',2017,'https://image.tmdb.org/t/p/w500/cvit6HDbXHE6W5kGPd47jd0wthQ.jpg','https://image.tmdb.org/t/p/original/wqBBbzbJcQKFjmq79Vw1ixcO6Ga.jpg','Sophia, a new high school student, tries to make friends with Barbara, who tells her that “she kills giants,” protecting this way her hometown and its inhabitants, who do not understand her strange behavior.',NULL,NULL,1.9119,6.175,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(982,1086747,'tt26736843',NULL,'The Watchers','The Watchers','movie',2024,'https://image.tmdb.org/t/p/w500/vZVEUPychdvZLrTNwWErr9xZFmu.jpg','https://image.tmdb.org/t/p/original/whnFKx0Y54Ktg6o2TiwbnQfXdZf.jpg','A young artist gets stranded in an extensive, immaculate forest in western Ireland, where, after finding shelter, she becomes trapped alongside three strangers, stalked by mysterious creatures each night.',NULL,NULL,5.9942,6.359,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(983,104755,'tt1731697',NULL,'The Lords of Salem','The Lords of Salem','movie',2013,'https://image.tmdb.org/t/p/w500/nqZ6CGGZpQWt139YioekSYHvvkU.jpg','https://image.tmdb.org/t/p/original/qdrmWfJPewIeZE9gU9ihr9diPbm.jpg','Heidi, a radio DJ, is sent a box containing a record - a "gift from the Lords". The sounds within the grooves trigger flashbacks of her town''s violent past. Is Heidi going mad, or are the Lords back to take revenge on Salem, Massachusetts?',NULL,NULL,2.4398,5.438,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(984,4087,'tt0106179',NULL,'The X-Files','The X-Files','tv',1993,'https://image.tmdb.org/t/p/w500/rcBx0p8h51LHceyhquYMxbspJQu.jpg','https://image.tmdb.org/t/p/original/w00lfexrsOeR25dO4hsWhbcUnmD.jpg','The exploits of FBI Special Agents Fox Mulder and Dana Scully who investigate X-Files: marginalized, unsolved cases involving paranormal phenomena. Mulder believes in the existence of aliens and the paranormal while Scully, a skeptic, is assigned to make scientific analyses of Mulder''s discoveries that debunk Mulder''s work and thus return him to mainstream cases.',NULL,NULL,71.3157,8.374,0,1.53083333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(985,92916,'tt10875696',NULL,'Marianne','Marianne','tv',2019,'https://image.tmdb.org/t/p/w500/hpeaMzflHMEepUGiCjXld7lrnC2.jpg','https://image.tmdb.org/t/p/original/yD01qWyOqc6J2lRutzOt3Wu8Wnz.jpg','When a novelist realizes her terrifying stories are coming true, she returns to her hometown to face the demons from her past that inspire her writing.',NULL,NULL,3.3375,7.6,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(986,129418,'tt11343600',NULL,'Brand New Cherry Flavor','Brand New Cherry Flavor','tv',2021,'https://image.tmdb.org/t/p/w500/cX4acZbi2l4v051NJZfonqY0E3X.jpg','https://image.tmdb.org/t/p/original/mdPiSmQgydmdgZtFwAI4lr60yQY.jpg','A filmmaker heads to Hollywood in the early ’90s to make her movie but tumbles down a hallucinatory rabbit hole of sex, magic, revenge — and kittens.',NULL,NULL,2.6478,6.985,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(987,67752,'tt4820370',NULL,'Channel Zero','Channel Zero','tv',2016,'https://image.tmdb.org/t/p/w500/oCutmhFznao1Pzy6wM1C32kxAEu.jpg','https://image.tmdb.org/t/p/original/iXxiiIuK5KGcleWRq5bTXXoYK11.jpg','A horror anthology series inspired by “Creepypasta” online tales.',NULL,NULL,9.3132,7.046,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(988,103302,'tt2177268',NULL,'Clarice','Clarice','tv',2021,'https://image.tmdb.org/t/p/w500/7OFxU0bBO0HDL4klXmM1ahJPbv8.jpg','https://image.tmdb.org/t/p/original/eSVvx8xys2NuFhl8fevXt41wX7v.jpg','In 1993, six months after the events of The Silence of the Lambs, FBI Agent Clarice Starling returns to the field to pursue serial murderers and sexual predators while navigating the high stakes political world of Washington, D.C.',NULL,NULL,4.3732,6.872,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(989,40008,'tt2243973',NULL,'Hannibal','Hannibal','tv',2013,'https://image.tmdb.org/t/p/w500/pbV2eLnKSIm1epSZt473UYfqaeZ.jpg','https://image.tmdb.org/t/p/original/vlG182ZY2WMzD5bjFZNnhyvv5V4.jpg','Both a gift and a curse, Graham has the extraordinary ability to think like his prey—he sees what they see, feels what they feel. But while Graham is pursuing an especially troubling, cannibalistic murderer, Special Agent Jack Crawford teams him with a highly respected psychiatrist – a man with a taste for the criminal minded – Dr. Hannibal Lecter.',NULL,NULL,34.0306,8.3,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(990,1189735,'tt27828550',NULL,'Fréwaka','Fréamhacha','movie',2025,'https://image.tmdb.org/t/p/w500/pfLylbmY0uxQm6Sh63j6bpb7XB3.jpg','https://image.tmdb.org/t/p/original/1OUEVe8VtA6F1eISGMzIEpyrmcD.jpg','Care worker Shoo, who is haunted by a personal tragedy, is sent to a remote village to care for an agoraphobic woman, who fears both her neighbours and the Na Sídhe – sinister folkloric entities she believes abducted her decades before.',NULL,NULL,1.6242,6.99,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(991,491584,'tt7282468',NULL,'Burning','버닝','movie',2018,'https://image.tmdb.org/t/p/w500/kXiF80o74fE9gf3Utf9moAI7ar0.jpg','https://image.tmdb.org/t/p/original/qQEt2FqF8McryFBNX30dyDJKiEK.jpg','Deliveryman Jong-su is out on a job when he runs into Hae-mi, a girl who once lived in his neighborhood. She asks if he''d mind looking after her cat while she''s away on a trip to Africa. On her return, she introduces to Jong-su an enigmatic young man named Ben, who she met during her trip. One day Ben tells Jong-su about his most unusual hobby.',NULL,NULL,4.2656,7.375,0,13.42,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(992,434773,'tt6412864',NULL,'On the Beach at Night Alone','밤의 해변에서 혼자','movie',2017,'https://image.tmdb.org/t/p/w500/mprIyn1rl5ukAVP9Vi9ZaRKtKkw.jpg','https://image.tmdb.org/t/p/original/r1mfWgKzW0Yb3zsfix8MyFB3zlU.jpg','In a foreign city, an actress wanders through a seaside town, reflecting on her relationship with a married man. How important is love in one’s life? Younghee wants to find out.',NULL,NULL,1.5622,6.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(993,11104,'tt0109424',NULL,'Chungking Express','重慶森林','movie',1994,'https://image.tmdb.org/t/p/w500/43I9DcNoCzpyzK8JCkJYpHqHqGG.jpg','https://image.tmdb.org/t/p/original/vuglA60RqvpHK9rIcG8sXaiWw1L.jpg','Two melancholic Hong Kong policemen fall in love: one with a mysterious underworld figure, the other with a beautiful and ethereal server at a late-night restaurant.',NULL,NULL,8.7738,7.973,0,1.83911111111111118e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(994,376867,'tt4975722',NULL,'Moonlight','Moonlight','movie',2016,'https://image.tmdb.org/t/p/w500/qLnfEmPrDjJfPyyddLJPkXmshkp.jpg','https://image.tmdb.org/t/p/original/jm1oD3eB08LImSwL1LrzF9AJQ5b.jpg','The tender, heartbreaking story of a young man’s struggle to find himself, told across three defining chapters in his life as he experiences the ecstasy, pain, and beauty of falling in love, while grappling with his own sexuality.',NULL,NULL,7.0649,7.357,0,1.42199999999999988e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(995,82,'tt0430357',NULL,'Miami Vice','Miami Vice','movie',2006,'https://image.tmdb.org/t/p/w500/iJPSls4taB09EUKtLj6FjFSprb3.jpg','https://image.tmdb.org/t/p/original/nogFh7eQFbBm0wTr9bb6YlnNoiI.jpg','A case involving drug lords and murder in South Florida takes a personal turn for undercover detectives Sonny Crockett and Ricardo Tubbs. Unorthodox Crockett gets involved romantically with the Chinese-Cuban wife of a trafficker of arms and drugs, while Tubbs deals with an assault on those he loves.',NULL,NULL,5.7787,6.029,0,1.17466666666666679e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(996,782,'tt0119177',NULL,'Gattaca','Gattaca','movie',1997,'https://image.tmdb.org/t/p/w500/eSKr5Fl1MEC7zpAXaLWBWSBjgJq.jpg','https://image.tmdb.org/t/p/original/hPsCR1ny6GnctJkWqeJwihTDD7T.jpg','Vincent is an all-too-human man who dares to defy a system obsessed with genetic perfection. He is an "In-Valid" who assumes the identity of a member of the genetic elite to pursue his goal of traveling into space with the Gattaca Aerospace Corporation.',NULL,NULL,7.6587,7.57,0,1.69637499999999974e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(997,432836,'tt5729348',NULL,'Memoir of a Murderer','살인자의 기억법','movie',2017,'https://image.tmdb.org/t/p/w500/eTdvO9AwJrxq02iYf4Lu5qA0fNc.jpg','https://image.tmdb.org/t/p/original/axRYPjeLD4zjJNaIw4TPopbKVfs.jpg','A former serial killer with Alzheimer''s fights to protect his daughter from her mysterious boyfriend who may be a serial killer too.',NULL,NULL,1.8452,7.441,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(998,76331,'tt7660850',NULL,'Succession','Succession','tv',2018,'https://image.tmdb.org/t/p/w500/z0XiwdrCQ9yVIr4O0pxzaAYRxdW.jpg','https://image.tmdb.org/t/p/original/bcdUYUFk8GdpZJPiSAas9UeocLH.jpg','Follow the lives of the Roy family as they contemplate their future once their aging father begins to step back from the media and entertainment conglomerate they control.',NULL,NULL,31.3183,8.301,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(999,405871,'tt0288189',NULL,'On the Beach','令嬢肉奴隷','movie',1985,'https://image.tmdb.org/t/p/w500/ksl1d50FUHaqNuNnmHSNdPrYyYl.jpg','https://image.tmdb.org/t/p/original/wRWEA3TeGGyocIPKFiTDzPK3HfN.jpg','In a summer in Shonan village, Sumiko is the daughter of an important upper-class Shikishima family, she loves to paint pictures, is going through a cooling-off of an arranged marriage that did not work out. However, she feels attraction for Nishina a rough and obscene man ...  On the other hand, the younger sister, Naomi Sumiko is envious of her sister for her beauty. Naomi feels ugly since all men seem to like Sumiko. Both sisters then become embroiled in a major problem in discovering the real intentions of Nishina, a man who hides behind a mask to rape women.',NULL,NULL,19.5229,5.6,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1000,1710886,'tt42995027',NULL,'Sugar Mommy','Sugar Mommy','movie',2026,'https://image.tmdb.org/t/p/w500/2FBvobFZGibenqKerk786qg9AHD.jpg','https://image.tmdb.org/t/p/original/RO1Jus7kHiuFuW2XTzmCVwj6Sr.jpg','When a non-committal sugar mommy takes in her three sugar babies, jealousy erupts as one of them becomes determined to be her one and only.',NULL,NULL,13.7392,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1001,947502,'tt27672817',NULL,'In Waves','In Waves','movie',2026,'https://image.tmdb.org/t/p/w500/ry9Kj3maM9WllIe9T6C7EnS5kxI.jpg','https://image.tmdb.org/t/p/original/imMuGhPpbCKdukzFigcDVH0c0PA.jpg','In Los Angeles, AJ, a shy teenager, meets Kristen. She lives for surfing; he loves skateboarding and drawing. They fall madly in love, and a happy future seems within reach. But everything changes when Kristen faces a sudden illness. Together, they face adversity, driven by the strength of their love, their friends, and their newly shared passion for surfing and the ocean.',NULL,NULL,2.7867,7.833,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1002,10176,'tt0089869',NULL,'The Quiet Earth','The Quiet Earth','movie',1985,'https://image.tmdb.org/t/p/w500/6uvRcSy1DCh0zONGMRO4bEj44hq.jpg','https://image.tmdb.org/t/p/original/acNTpCRoAHueT1VoJzEQPYXdXy5.jpg','After a top-secret experiment misfires, a scientist may be the only man left alive in the world.',NULL,NULL,2.0381,6.629,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1003,1635,'tt0399201',NULL,'The Island','The Island','movie',2005,'https://image.tmdb.org/t/p/w500/9MaZYEyFmQwNeDTxZGQEN8E0e4p.jpg','https://image.tmdb.org/t/p/original/zZZ1FDl5FPClZ9OnMrlaPA4Iuxv.jpg','In 2019, Lincoln Six-Echo is a resident of a seemingly "Utopian" but contained facility. Like all of the inhabitants of this carefully-controlled environment, Lincoln hopes to be chosen to go to The Island — reportedly the last uncontaminated location on the planet. But Lincoln soon discovers that everything about his existence is a lie.',NULL,NULL,7.9991,6.699,0,13.2925,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1004,122081,'tt2101441',NULL,'Spring Breakers','Spring Breakers','movie',2013,'https://image.tmdb.org/t/p/w500/9tyPnyEkL44qbAliM9jMRWc6bjg.jpg','https://image.tmdb.org/t/p/original/3eMxTkvHM6G1lHugBvFGVpcJFUa.jpg','After four college girls rob a restaurant to fund their spring break in Florida, they get entangled with a weird dude with his own criminal agenda.',NULL,NULL,3.2031,5.257,0,13.2625,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1005,86835,'tt2101383',NULL,'Knight of Cups','Knight of Cups','movie',2015,'https://image.tmdb.org/t/p/w500/xejFBC19Nc7Xi1MiIvcf84ZCy2g.jpg','https://image.tmdb.org/t/p/original/8tupHJ6SDmOHPaeLaEQ2W58Xwlj.jpg','Rick is a screenwriter living in Los Angeles. While successful in his career, his life feels empty. Haunted and confused, he finds temporary solace in the decadent Hollywood excess that defines his existence. Women provide a distraction to his daily pain, and every encounter brings him closer to finding his place in the world.',NULL,NULL,3.1843,5.707,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1006,11305,'tt0097940',NULL,'Mystery Train','Mystery Train','movie',1989,'https://image.tmdb.org/t/p/w500/f11xq7dBGhz9UDc3dabldAGeXVH.jpg','https://image.tmdb.org/t/p/original/t0GxYLiPkTtFBuzoPLmLU3HSKEN.jpg','In Memphis, Tennessee, over the course of a single night, the Arcade Hotel, run by an eccentric night clerk and a clueless bellboy, is visited by a young Japanese couple traveling in search of the roots of rock; an Italian woman in mourning who stumbles upon a fleeing charlatan girl; and a comical trio of accidental thieves looking for a place to hide.',NULL,NULL,4.2509,7.339,0,1.27133333333333329e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1007,339,'tt0102536',NULL,'Night on Earth','Night on Earth','movie',1991,'https://image.tmdb.org/t/p/w500/ktejUHCo6c8DekpOtR3uSb6oDXr.jpg','https://image.tmdb.org/t/p/original/xOeGBXInQnwV9BGlneL8r65nL3q.jpg','A quintet of cabbies in five cities and their remarkable fares on the same eventful night.',NULL,NULL,2.9188,7.512,0,1.13433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1008,597891,'tt7737528',NULL,'Kate','Kate','movie',2021,'https://image.tmdb.org/t/p/w500/uJgdT1boTSP0dDIjdTgGleg71l4.jpg','https://image.tmdb.org/t/p/original/byflnwPMumyvrCW9SfO5Miq3647.jpg','A ruthless criminal operative has less than 24 hours to exact revenge on her enemies and in the process forms an unexpected bond with the daughter of one of her past victims.',NULL,NULL,2.4756,6.622,0,1.24433333333333315e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1009,36250,'tt0258960',NULL,'Shinjuku Triad Society','新宿黒社会 チャイナマフィア戦争','movie',1995,'https://image.tmdb.org/t/p/w500/9C80qHKjbwgxDko88z6rxZ33Jjw.jpg','https://image.tmdb.org/t/p/original/cJVJMpj8f7YhlSC6v6fBBJ4x8k0.jpg','Tatsuhito, a cop, pursues Chinese warlord Wang through the underworld of Shinjuku and over to Taiwan.',NULL,NULL,0.9457,6.3,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1010,8938,'tt0976060',NULL,'Tokyo!','TOKYO!','movie',2008,'https://image.tmdb.org/t/p/w500/6xbq2EBAOwy0V7bzd1um3sJX1jd.jpg','https://image.tmdb.org/t/p/original/hUpP1NUVKCg66xFBWjSSxaLzJx9.jpg','Three distinct tales unfold in the bustling city of Tokyo. Merde, a bizarre sewer-dweller, emerges from a manhole and begins terrorizing pedestrians. After his arrest, he stands trial and lashes out at a hostile courtroom. A man who has resigned himself to a life of solitude reconsiders after meeting a charming pizza delivery woman. And finally, a happy young couple find themselves undergoing a series of frightening metamorphoses.',NULL,NULL,2.7391,6.872,0,9.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1011,6978,'tt0090728',NULL,'Big Trouble in Little China','Big Trouble in Little China','movie',1986,'https://image.tmdb.org/t/p/w500/rCy3CFJfWVBSyiVcFOQMcMAh5R2.jpg','https://image.tmdb.org/t/p/original/ehHskGgDUchxGyG33vUQZWNng43.jpg','Truck driver Jack Burton gets embroiled in a supernatural battle when his best friend Wang Chi''s green-eyed fiancée is kidnapped by henchmen of the sorcerer Lo Pan, who must marry a girl with green eyes in order to return to the human realm.',NULL,NULL,6.123,7.218,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1012,670,'tt0364569',NULL,'Oldboy','올드보이','movie',2003,'https://image.tmdb.org/t/p/w500/pWDtjs568ZfOTMbURQBYuT4Qxka.jpg','https://image.tmdb.org/t/p/original/sdwjQEM869JFwMytTmvr6ggvaUl.jpg','With no clue how he came to be imprisoned, drugged and tortured for 15 years, a desperate man seeks revenge on his captors.',NULL,NULL,14.8298,8.235,0,17.5825,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1013,9696,'tt0296042',NULL,'Ichi the Killer','殺し屋1','movie',2001,'https://image.tmdb.org/t/p/w500/k8j4YLZlda98dqp9ErymKzjYowG.jpg','https://image.tmdb.org/t/p/original/j3P5wkyiigZW8aeogoZoiNIZySL.jpg','As sadomasochistic yakuza enforcer Kakihara searches for his missing boss he comes across Ichi, a repressed and psychotic killer who may be able to inflict levels of pain that Kakihara has only dreamed of.',NULL,NULL,4.0167,6.993,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1014,90296,'tt2887954',NULL,'Tokyo Vice','Tokyo Vice','tv',2022,'https://image.tmdb.org/t/p/w500/za5QWRfCLwgRLLVXUkx3NUSAm6G.jpg','https://image.tmdb.org/t/p/original/fGhZTONMDkwSaE5V4FDxf26uenl.jpg','A first-hand account of the Tokyo Metropolitan Police beat following Jake Adelstein, an American journalist who embeds himself into the Tokyo Vice police squad to reveal corruption. Based on Jake Adelstein’s non-fiction book of the same name.',NULL,NULL,11.1465,7.865,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1015,125858,'tt0388474',NULL,'tokyo.sora','tokyo.sora','movie',2002,'https://image.tmdb.org/t/p/w500/hVTGIJYk8znyhBLb7Hy7lMnEAsC.jpg','https://image.tmdb.org/t/p/original/dWMwZELNaVROqbI507PMqkFIPV3.jpg','Six women attempt to make it in current day Tokyo, living their everyday lives the best and worst they can. For them, every little moment becomes a ritual of the ordinary and the exciting, a balancing act for their dreams and hopes as the days perpetually tug on their heartstrings.',NULL,NULL,0.6948,7.6,0,5.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1016,844,'tt0212712',NULL,'2046','2046','movie',2004,'https://image.tmdb.org/t/p/w500/jIN65qw0Giplo4CshzMrxz204Wn.jpg','https://image.tmdb.org/t/p/original/h3JAMIeywbzobkhu2rt3mQAwRR1.jpg','Women enter and exit a science fiction author''s life over the course of a few years after the author loses the woman he considers his one true love.',NULL,NULL,3.6749,7.2,0,13.0225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1017,34647,'tt1191111',NULL,'Enter the Void','Enter the Void','movie',2010,'https://image.tmdb.org/t/p/w500/krKnsfvSJM1PL40tLicRhVQ6kuG.jpg','https://image.tmdb.org/t/p/original/2Mlw0JRNZHXLYxbeJ0LmiCCTiok.jpg','This psychedelic tour of life after death is seen entirely from the point of view of Oscar, a young American drug dealer and addict living in Tokyo with his prostitute sister, Linda. When Oscar is killed by police during a bust gone bad, his spirit journeys from the past -- where he sees his parents before their deaths -- to the present -- where he witnesses his own autopsy -- and then to the future, where he looks out for his sister from beyond the grave.',NULL,NULL,3.4242,7.291,0,2.73861111111111092e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1018,12140,'tt0347246',NULL,'Ghost in the Shell 2: Innocence','イノセンス','movie',2004,'https://image.tmdb.org/t/p/w500/1ZJRbLDVr90KLtKdmTT4WZhT26E.jpg','https://image.tmdb.org/t/p/original/8Cbzx17QdJ6xBx2uDkdlpWsemGg.jpg','Cyborg detective Batou is assigned to investigate a series of murders committed by gynoids—doll-like cyborgs, which all malfunctioned, killed, then self-destructed afterwards. The brains of the gynoids initialize in order to protect their manufacturer''s software, but in one gynoid, which Batou himself neutralized, one file remains: a voice speaking the phrase "Help me."',NULL,NULL,4.1548,7.341,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1019,56616,'tt0377556',NULL,'Goodbye, Dragon Inn','不散','movie',2003,'https://image.tmdb.org/t/p/w500/js1uTY2FuKspVRQWLudFkEteFI5.jpg','https://image.tmdb.org/t/p/original/lch9NDBb4oM0xKNEz0ZN7Mc27MS.jpg','On a dark, wet night in Taipei City, a cavernous old picture palace is about to close its doors forever. A meager audience, the remaining few staff, and perhaps even a ghost or two, watch King Hu’s wuxia classic "Dragon Inn", each haunted by memories and desires evoked by cinema itself.',NULL,NULL,1.3146,6.786,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1020,57564,'tt0103935',NULL,'Rebels of the Neon God','青少年哪吒','movie',1994,'https://image.tmdb.org/t/p/w500/eVNOoFSpRnaCNSJwerAD0KkeibD.jpg','https://image.tmdb.org/t/p/original/8qF4kkqTYzRJqScGEYFGdAncPLo.jpg','In Taipei, four youths face alienation, loneliness, and moments of existential crisis amidst a series of minor crimes.',NULL,NULL,1.1671,7.306,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1021,4105,'tt0096933',NULL,'Black Rain','Black Rain','movie',1989,'https://image.tmdb.org/t/p/w500/funhGWt9ee3Uwb6Ar8SGCCvbJdV.jpg','https://image.tmdb.org/t/p/original/4xAxAvrcnelGOBA5mQsW0aEHpqW.jpg','Two New York cops get involved in a gang war between members of the Yakuza, the Japanese Mafia. They arrest one of their killers and are ordered to escort him back to Japan. However, in Japan he manages to escape, and as they try to track him down, they get deeper and deeper into the Japanese Mafia scene and they have to learn that they can only win by playing the game—the Japanese way.',NULL,NULL,3.4668,6.58,0,13.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1022,11690,'tt0092675',NULL,'Bloodsport','Bloodsport','movie',1988,'https://image.tmdb.org/t/p/w500/kndxR9TRK0kJ5hxzDprRSS80F2W.jpg','https://image.tmdb.org/t/p/original/aSA7RuKmCQBnYKn70GYPi6ckgoY.jpg','An American Army Major goes AWOL to Hong Kong for an outlawed martial arts contest called the Kumite.',NULL,NULL,5.9678,7.06,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1023,843,'tt0118694',NULL,'In the Mood for Love','花樣年華','movie',2000,'https://image.tmdb.org/t/p/w500/iYypPT4bhqXfq1b6EnmxvRt6b2Y.jpg','https://image.tmdb.org/t/p/original/ffQFnAUm2Uu4RU0nijpjPRf9TBT.jpg','In 1960s Hong Kong, two neighbors form an intimate bond after making a discovery about their spouses in this visually stunning tale of unrequited love.',NULL,NULL,11.0952,8.1,0,1.55133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1024,103,'tt0075314',NULL,'Taxi Driver','Taxi Driver','movie',1976,'https://image.tmdb.org/t/p/w500/ekstpH614fwDX8DUln1a2Opz0N8.jpg','https://image.tmdb.org/t/p/original/9uddYYTNcLWpzUkl5iw1RUYhLhY.jpg','Suffering from insomnia, disturbed loner Travis Bickle takes a job as a New York City cabbie, haunting the streets nightly, growing increasingly detached from reality as he dreams of cleaning up the filthy city.',NULL,NULL,14.6171,8.124,0,13.0375,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1025,186379,'tt0096281',NULL,'Tokyo Pop','Tokyo Pop','movie',1988,'https://image.tmdb.org/t/p/w500/yWVDKeBPzKAT2I42mQxpjhVdapo.jpg','https://image.tmdb.org/t/p/original/6sCnOmBMy1f7MMpD9MOO10aUK8i.jpg','A young rock singer is not appreciated by her band, and gets a postcard from Japan saying "wish you were here". She takes what little money she has including ex-boyfriend''s rent money and goes to Tokyo. She has numerous cross-cultural adventures and ends up singing with a Japanese rock group looking for a gaijin gimmick.',NULL,NULL,0.7217,6.9,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1026,11553,'tt0283283',NULL,'Millennium Mambo','千禧曼波','movie',2001,'https://image.tmdb.org/t/p/w500/wSc6tOp1yoAFbZqxG5XVGHcFvRN.jpg','https://image.tmdb.org/t/p/original/k603HQRxzlSnYAtyz9wNZndaAzg.jpg','In 2011, Vicky looks back on her life a decade earlier, recalling her turbulent relationship with her controlling boyfriend Hao Hao and her growing connection to a compassionate gangster amid the neon haze of Taipei''s nightlife.',NULL,NULL,2.0059,7.0,0,1.16866666666666674e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1027,13754,'tt0831888',NULL,'Tekkonkinkreet','鉄コン筋クリート','movie',2006,'https://image.tmdb.org/t/p/w500/e2x1YDuZPpQiaQS25Ego7xMZYOI.jpg','https://image.tmdb.org/t/p/original/iAlJWcoEqKTmfxVMQ6pDyizPRsK.jpg','Two penniless orphans, Black and White, struggle to survive on the mean streets of Treasure Town. When a megacorporation threatens to tear down the town to build an amusement park, Black and White engage in the fight of their life.',NULL,NULL,2.2462,7.373,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1028,10494,'tt0156887',NULL,'Perfect Blue','PERFECT BLUE','movie',1998,'https://image.tmdb.org/t/p/w500/6WTiOCfDPP8XV4jqfloiVWf7KHq.jpg','https://image.tmdb.org/t/p/original/mHG7dpLb0ZScSY3LpP443IHRmjy.jpg','Rising pop star Mima Kirigoe quits singing to pursue a career as an actress. After she takes up a role on a popular detective show, her handlers and collaborators begin turning up murdered. Harboring feelings of guilt and haunted by visions of her former self, Mima''s reality and fantasy meld into a frenzied paranoia.',NULL,NULL,13.8265,8.305,0,13.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1029,94423,'tt12031040',NULL,'Japan Sinks: 2020','日本沈没2020','tv',2020,'https://image.tmdb.org/t/p/w500/guWqteZJ16ABGGtXIKFyDBAo8Ik.jpg','https://image.tmdb.org/t/p/original/6aJMl28iBbhZLxDIj3Vqfaonzv2.jpg','After catastrophic earthquakes devastate Japan, one family''s resolve is tested on a journey of survival through the sinking archipelago.',NULL,NULL,3.3364,7.158,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1030,77987,'tt1602613',NULL,'Only God Forgives','Only God Forgives','movie',2013,'https://image.tmdb.org/t/p/w500/kWjjFSng1JttmDRwDROoGcIArEh.jpg','https://image.tmdb.org/t/p/original/pRrQMx00P8LaXGwJXYJ2tRGoVOs.jpg','Julian, who runs a Thai boxing club as a front organization for his family''s drug smuggling operation, is forced by his mother Crystal to find and kill the individual responsible for his brother''s recent death.',NULL,NULL,3.9,5.812,0,1.16833333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1031,560016,'tt9214772',NULL,'Monkey Man','Monkey Man','movie',2024,'https://image.tmdb.org/t/p/w500/4lhR4L2vzzjl68P1zJyCH755Oz4.jpg','https://image.tmdb.org/t/p/original/9NSXdVHeSfSHUv49OzLispFcpz1.jpg','Kid is an anonymous young man who ekes out a meager living in an underground fight club where, night after night, wearing a gorilla mask, he is beaten bloody by more popular fighters for cash. After years of suppressed rage, Kid discovers a way to infiltrate the enclave of the city’s sinister elite. As his childhood trauma boils over, his mysteriously scarred hands unleash an explosive campaign of retribution to settle the score with the men who took everything from him.',NULL,NULL,10.142,6.863,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1032,106380,'tt0089866',NULL,'Taipei Story','青梅竹馬','movie',1985,'https://image.tmdb.org/t/p/w500/veJ93QUnTBX4WXk5qSl1s42Uosj.jpg','https://image.tmdb.org/t/p/original/zMNDdSvLxkVjOD5iGacsRsdgjKW.jpg','A young woman urgently seeks to navigate the maze of contemporary Taipei and find a future. She hopes that her boyfriend Lung is the key to the future, but Lung is stuck in a past that combines baseball and traditional loyalty that leads him to squander his nest egg bailing her father out of financial trouble.',NULL,NULL,1.7678,7.445,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1033,105248,'tt12590266',NULL,'Cyberpunk: Edgerunners','Cyberpunk: Edgerunners','tv',2022,'https://image.tmdb.org/t/p/w500/lqcDVZ8pyk08AVftMBildDR3QUK.jpg','https://image.tmdb.org/t/p/original/bRE6zX4iOAejLOQCHryoV5WNu8G.jpg','In a dystopia riddled with corruption and cybernetic implants, a talented but reckless street kid strives to become a mercenary outlaw — an edgerunner.',NULL,NULL,28.7999,8.463,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1034,2517,'tt0408664',NULL,'Nobody Knows','誰も知らない','movie',2004,'https://image.tmdb.org/t/p/w500/kDUUdWrbBBVqzSmm27pHFJcTvCU.jpg','https://image.tmdb.org/t/p/original/gCD0eMZW1pUitLzH93WYWJYQgGk.jpg','In a small Tokyo apartment, twelve-year-old Akira must care for his younger siblings after their mother leaves them and shows no sign of returning.',NULL,NULL,3.6474,7.995,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1035,9344,'tt0113540',NULL,'Kids','Kids','movie',1995,'https://image.tmdb.org/t/p/w500/8qV8hUVCUnFIQKewzlhaFWhdszK.jpg','https://image.tmdb.org/t/p/original/3gmreIMvzQgd1q4hsiUN5ADV88W.jpg','A group of bored, disaffected New York City teenagers spend a day skating, smoking, drinking, partying, deflowering virgins, and getting into fights.',NULL,NULL,8.0967,6.891,0,25.298125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1036,7090,'tt0209077',NULL,'Ken Park','Ken Park','movie',2003,'https://image.tmdb.org/t/p/w500/p6ElNTWEbibYlobVeiIDHBvL1kF.jpg','https://image.tmdb.org/t/p/original/uw5uCdiF0HSCyXml0GsUe95ejuw.jpg','Teen skater Ken Park (nicknamed Krap Nek; his name spelled and pronounced backward) kills himself at a Visalia skate park; his death bookends the lives of four other young people who knew him: Shawn, the most conventional; Tate brims with psychotic rage; Claude is habitually harassed by his brutish father and coddled, rather uncomfortably, by his enormously pregnant mother; and Peaches looks after her devoutly religious father, but yearns for freedom. They''re all rather tight, or so they claim.',NULL,NULL,4.6058,5.991,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1037,18292,'tt0262432',NULL,'George Washington','George Washington','movie',2000,'https://image.tmdb.org/t/p/w500/g9nZi8u5LqSrVKEpSm199EM4hk5.jpg','https://image.tmdb.org/t/p/original/5ZVRnltdsQXrRWhYCw7zHU4lruz.jpg','During an innocent game in an abandoned amusement park, a member of the group dies. Narrated by one of the children, the film follows the kids as they struggle to balance their own ambitions and relationships against a tragic lie.',NULL,NULL,1.0419,6.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1038,268,'tt0096895',NULL,'Batman','Batman','movie',1989,'https://image.tmdb.org/t/p/w500/cij4dd21v2Rk2YtUQbV5kW69WB2.jpg','https://image.tmdb.org/t/p/original/rBN6GPKUDZ6ZKAQiEZegZ0DZb6V.jpg','Having witnessed his parents'' brutal murder as a child, millionaire philanthropist Bruce Wayne fights crime in Gotham City disguised as Batman, a costumed hero who strikes fear into the hearts of villains. But when a deformed madman known as ''The Joker'' seizes control of Gotham''s criminal underworld, Batman must face his most ruthless nemesis ever while protecting both his identity and his love interest, reporter Vicki Vale.',NULL,NULL,8.6957,7.2,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1039,32079,'tt0097074',NULL,'Cohen and Tate','Cohen and Tate','movie',1989,'https://image.tmdb.org/t/p/w500/mtl43J82BOX49DKsplg4KPRkbn8.jpg','https://image.tmdb.org/t/p/original/cmXcXeCfTxod7XTO46MtUHDcCSJ.jpg','A boy kidnapped by two mismatched hitmen puts them at each other''s throats while being driven to their employers, possibly to be killed. Cohen, an older professional becomes increasingly irritated with his partner Tate, a brutish killer, when their prisoner uses unnatural guile and resourcefulness to play them off against each other.',NULL,NULL,1.1056,6.548,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1040,11524,'tt0083190',NULL,'Thief','Thief','movie',1981,'https://image.tmdb.org/t/p/w500/bpjRGwfYJ71bU0hNhLIz7g3t6Oy.jpg','https://image.tmdb.org/t/p/original/3pYudqkEC8rkjqpBw8pqoLUtGHe.jpg','Frank is an expert professional safecracker, specialized in high-profile diamond heists. He plans to use his ill-gotten income to retire from crime and build a nice life for himself complete with a home, wife and kids. To accelerate the process, he signs on with a top gangster for a big score.',NULL,NULL,3.2096,7.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1041,10490,'tt0157503',NULL,'Drop Dead Gorgeous','Drop Dead Gorgeous','movie',1999,'https://image.tmdb.org/t/p/w500/44eTdzCnb27urFheuhBdJxBhrwg.jpg','https://image.tmdb.org/t/p/original/xXSDhhyC853VgF7OCDKpXKeA5Md.jpg','In a small Minnesota town, the annual beauty pageant is being covered by a TV crew. Former winner Gladys Leeman wants to make sure her daughter follows in her footsteps; explosions, falling lights, and trailer fires prove that. As the Leemans are the richest family in town, the police are pretty relaxed about it all. Despite everything, main rival (but sweet) Amber Atkins won''t give up without a fight.',NULL,NULL,2.8167,6.5,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1042,47866,'tt0104321',NULL,'Gas Food Lodging','Gas Food Lodging','movie',1992,'https://image.tmdb.org/t/p/w500/4klEYvGDHmv89NQRfAaDc8qHncs.jpg','https://image.tmdb.org/t/p/original/byckFRHkQnXZezIGjamsYTjCvlb.jpg','Nora, a single mother raising two teenage daughters, Shade and Trudi, waits tables at a truck-stop diner in a small New Mexico town. The beautiful and rebellious Trudi drops out of school and gets a job alongside Nora, while the younger Shade whittles away her time at Spanish movie matinees. Their lives are turned upside down when Trudi becomes pregnant and the girls'' absent father returns.',NULL,NULL,1.2893,6.264,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1043,570,'tt0243255',NULL,'Fat Girl','À ma sœur !','movie',2001,'https://image.tmdb.org/t/p/w500/afzbY1h7huuxlITigPfcyQSkqLs.jpg','https://image.tmdb.org/t/p/original/pnwI95K4pmYeM3LsMRTQYzvhvvO.jpg','Anaïs is twelve and bears the weight of the world on her shoulders. She watches her older sister, Elena, whom she both loves and hates. Elena is fifteen and devilishly beautiful. Neither more futile, nor more stupid than her younger sister, she cannot understand that she is merely an object of desire. And, as such, she can only be taken. Or had. Indeed, this is the subject: a girl''s loss of virginity. And, that summer, it opens a door to tragedy.',NULL,NULL,4.1777,6.177,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1044,11023,'tt0328538',NULL,'Thirteen','Thirteen','movie',2003,'https://image.tmdb.org/t/p/w500/uzTLlZrNF6rMPBh5mUQu6vLnTtX.jpg','https://image.tmdb.org/t/p/original/ow2boWFZWza7D4qDvJohg9GJVoH.jpg','When 13-year-old Tracy befriends Evie, the most popular girl in school, her life is turned upside down as Evie introduces her to a world of sex, drugs, and money. But it isn’t long before Tracy’s new lifestyle begins to take a heavy toll on her and her family.',NULL,NULL,4.2773,6.69,0,1.08583333333333342e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1045,91679,'tt2035630',NULL,'Starlet','Starlet','movie',2012,'https://image.tmdb.org/t/p/w500/8mVU5KjD5b4Df3CRTnJqKFSwg5y.jpg','https://image.tmdb.org/t/p/original/hIRyLinDrbwZ5Lzc5GvoedfR6e3.jpg','An unlikely friendship forms between 21 year-old Jane and the elderly Sadie after Jane discovers a hidden stash of money inside an object at Sadie''s yard sale.',NULL,NULL,1.5628,6.794,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1046,12093,'tt0300140',NULL,'Lilya 4-ever','Lilja 4-ever','movie',2002,'https://image.tmdb.org/t/p/w500/5i1uhvcdv2Iogx0Bb1znvUmkCvN.jpg','https://image.tmdb.org/t/p/original/fJeOpfzQSkzESNPmEXpyNLMmOtI.jpg','In a struggling post-Soviet community, Lilya a teenage girl is abandoned when her mother moves to the United States with her boyfriend. Facing neglect and poverty, she meets Andrei, who offers her a job in Sweden, giving her hope for a better life — and a journey that will change everything.',NULL,NULL,5.1849,7.613,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1047,12247,'tt0952682',NULL,'Shotgun Stories','Shotgun Stories','movie',2007,'https://image.tmdb.org/t/p/w500/aeIlHt28Z8KmHcKEgl4oLHpwZ8M.jpg','https://image.tmdb.org/t/p/original/u5hVdYR4l7Mv8ruYEGVL1mbIoKC.jpg','Shotgun Stories tracks a feud that erupts between two sets of half brothers following the death of their father. Set against the cotton fields and back roads of Southeast Arkansas, these brothers discover the lengths to which each will go to protect their family.',NULL,NULL,1.2333,6.923,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1048,188166,'tt2359024',NULL,'Blue Ruin','Blue Ruin','movie',2014,'https://image.tmdb.org/t/p/w500/q0itEsso2drJXqH9kfdidxIT5dF.jpg','https://image.tmdb.org/t/p/original/epIcUGDXIZVs1jNNFI5lWgWNUIM.jpg','When the quiet life of a beach bum is upended by dreadful news, he sets off for his childhood home to carry out an act of vengeance. However, he proves an inept assassin and finds himself in a brutal fight to protect his estranged family.',NULL,NULL,1.8162,6.789,0,13.645,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1049,253257,'tt1141702',NULL,'I Believe in Unicorns','I Believe in Unicorns','movie',2015,'https://image.tmdb.org/t/p/w500/gxquUhh9IleBnWJFoNJQmfjXqgG.jpg','https://image.tmdb.org/t/p/original/ugSkna6kFW4wRZvZWCaaMprhE0z.jpg','Feeling awkward and isolated, an imaginative and strong-willed teenage girl runs away from home with an older punk rock drifter.',NULL,NULL,1.1538,6.445,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1050,900,'tt0840196',NULL,'Skins','Skins','tv',2007,'https://image.tmdb.org/t/p/w500/cymrUG57i98SWen4lqho1SBWtVx.jpg','https://image.tmdb.org/t/p/original/saBnI34QTYTjG9sj8DsembO4PBK.jpg','Irreverent comedy drama which follows the messy lives, loves, delirious highs and inevitable lows of a group of raucous teenage friends in Bristol.',NULL,NULL,30.5357,8.133,0,6.61,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1051,34614,'tt0381682',NULL,'A Hole in My Heart','Ett hål i mitt hjärta','movie',2005,'https://image.tmdb.org/t/p/w500/nT8SGitqWYH4pfWPiDiFBZTYY0o.jpg','https://image.tmdb.org/t/p/original/lDZiR71OuK3CFX9hAK5DZjPIDuB.jpg','In a decript apartment, a young man watches as his father and a friend shoot an amateur porn film. Issues of morality, reality TV and friendship are explored.',NULL,NULL,0.6363,4.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1052,16723,'tt0186589',NULL,'Sugar & Spice','Sugar & Spice','movie',2001,'https://image.tmdb.org/t/p/w500/fN3xeuVsPaiEKYm65uHSO9JVmeb.jpg','https://image.tmdb.org/t/p/original/r61qpgtIUEuRHGh3VdQpgcxN8zN.jpg','When Jack and Diane find themselves in an unexpected adult situation, the A-Squad comes to their rescue. In order to help their friend Diane, the A-Squad goes where no cheerleader has gone before: taking on a little after-school project known as bank robbery. But the A-Squad does things their way -- with sugar and spice -- forever changing their friendship, their future and the nation''s notion of teen spirit.',NULL,NULL,1.8716,6.4,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1053,14926,'tt0263757',NULL,'Uptown Girls','Uptown Girls','movie',2003,'https://image.tmdb.org/t/p/w500/liazMoopc2fhWq1YlfwasQcvWu.jpg','https://image.tmdb.org/t/p/original/7TvehiVjzE9hMvnq94mOYjP8kGT.jpg','Molly Gunn, the freewheeling daughter of a deceased rock legend, is forced to get a job when her manager steals her money. As nanny to Ray - the precocious, oft-ignored daughter of a music executive - she learns what it means to be an adult while teaching Ray how to be a child.',NULL,NULL,9.1065,6.993,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1054,641,'tt0180093',NULL,'Requiem for a Dream','Requiem for a Dream','movie',2000,'https://image.tmdb.org/t/p/w500/9BTwsLaMVHOGFlmsSlx5QYCaXb.jpg','https://image.tmdb.org/t/p/original/fAGYRJCujRBMw7TCuTp893eSG8e.jpg','The drug-induced utopias of four Coney Island residents are shattered when their addictions run deep.',NULL,NULL,5.0154,8.01,0,1.48760000000000012e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1055,539565,'tt5439812',NULL,'Zola','Zola','movie',2021,'https://image.tmdb.org/t/p/w500/bJLCPROp9bmNndurwZpVnOioVpB.jpg','https://image.tmdb.org/t/p/original/zL7CozbpAbGSdhBsuTI847tu5Fo.jpg','A waitress agrees to accompany an exotic dancer, her put-upon boyfriend, and her mysterious and domineering roommate on a road trip to Florida to seek their fortune at a high-end strip club.',NULL,NULL,3.6697,6.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1056,592984,'tt6772802',NULL,'Hillbilly Elegy','Hillbilly Elegy','movie',2020,'https://image.tmdb.org/t/p/w500/aA0D6DKIfLtXYNy94Qq2IW5NiGR.jpg','https://image.tmdb.org/t/p/original/kCqWQ24m7TjA0RllQMn0JYrcy4a.jpg','An urgent phone call pulls a Yale Law student back to his Ohio hometown, where he reflects on three generations of family history and his own future.',NULL,NULL,2.3298,6.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1057,473033,'tt5727208',NULL,'Uncut Gems','Uncut Gems','movie',2019,'https://image.tmdb.org/t/p/w500/6XN1vxHc7kUSqNWtaQKN45J5x2v.jpg','https://image.tmdb.org/t/p/original/eGljNfNCrPhFYG2RXXmmE0OKu5.jpg','A charismatic New York City jeweler always on the lookout for the next big score makes a series of high-stakes bets that could lead to the windfall of a lifetime. Howard must perform a precarious high-wire act, balancing business, family, and encroaching adversaries on all sides in his relentless pursuit of the ultimate win.',NULL,NULL,5.821,7.2,0,17.84,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1058,20737,'tt0118570',NULL,'Air Bud','Air Bud','movie',1997,'https://image.tmdb.org/t/p/w500/kDfzh6QdX2tseTwwyB7lp2RP7iE.jpg','https://image.tmdb.org/t/p/original/tTUOXTIKnBLOaoNbelpWomPKdho.jpg','A lonely boy befriends a stray dog who has a natural talent for basketball and together they experience the highs and lows of life as their friendship remains solid through a series of escapades.',NULL,NULL,5.0013,5.573,0,10.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1059,14164,'tt1098327',NULL,'Dragonball Evolution','Dragonball Evolution','movie',2009,'https://image.tmdb.org/t/p/w500/ztlqrY7VgFIFmtzVsh3TPYiXCdF.jpg','https://image.tmdb.org/t/p/original/19ChHftp06sllxdgINPSTDIyKHw.jpg','On his 18th birthday, Goku receives a mystical Dragonball as a gift from his grandfather. There are only six others like it in the whole world, and legend has it that whoever possesses all seven will be granted one perfect wish. When the arrival of a dark force triggers a tragedy, Goku and his companions are propelled into an epic quest to collect the seven Dragonballs and save the Earth from destruction.',NULL,NULL,4.1115,2.94,0,9.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1060,2300,'tt0117705',NULL,'Space Jam','Space Jam','movie',1996,'https://image.tmdb.org/t/p/w500/4RN5El3Pj2W4gpwgiAGLVfSJv2g.jpg','https://image.tmdb.org/t/p/original/lWybXICZZpxnSvWSOW53XxTERUg.jpg','With their freedom on the line, the Looney Tunes seek the help of NBA superstar Michael Jordan to win a basketball game against a team of moronic aliens.',NULL,NULL,7.0869,6.811,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1061,937287,'tt16426418',NULL,'Challengers','Challengers','movie',2024,'https://image.tmdb.org/t/p/w500/H6vke7zGiuLsz4v4RPeReb9rsv.jpg','https://image.tmdb.org/t/p/original/tq8COKsI99Bivjd4CZIYVGoKcIx.jpg','Tennis player turned coach Tashi has taken her husband, Art, and transformed him into a world-famous Major champion. To jolt him out of his recent losing streak, she signs him up for a "Challenger" event — close to the lowest level of pro tournament — where he finds himself standing across the net from his former best friend and Tashi''s former boyfriend.',NULL,NULL,7.5523,6.91,0,1.25199999999999977e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1062,50379,'tt0076500',NULL,'One on One','One on One','movie',1977,'https://image.tmdb.org/t/p/w500/xCK4RkUpjt1aKivID3G8eWHnyFc.jpg','https://image.tmdb.org/t/p/original/mk6OaCtoImiLtUHVWaVTT57ia4V.jpg','Henry Steele is a basketball phenom at his small town high school, but when he matriculates to a big city university on a scholarship, soon realizes that he has few skills outside the sport. Expected by his coach to contribute significantly to the team, Henry is overwhelmed by the demands on his time, the "big business" aspect of college sports, and the fact that he never fully learned to read. Things look bleak for Henry when Janet Hays, a pretty graduate student, is assigned as Henry''s tutor. Her intellect and strength lift Henry out of his doldrums just in time to battle the coach, who attempts to rescind Henry''s scholarship.',NULL,NULL,0.7637,5.87,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1063,20726,'tt0110364',NULL,'Little Giants','Little Giants','movie',1994,'https://image.tmdb.org/t/p/w500/AkfXNOeKgJSOD08StGd0599auiZ.jpg','https://image.tmdb.org/t/p/original/gl58xoX8NK95vIgtIMCsKsd2its.jpg','When Danny O''Shea''s daughter is cut from the Peewee football team just for being a girl, he decides to form his own team, composed of other ragtag players who were also cut. Can his team really learn enough to beat the elite team, coached by his brother, a former pro player?',NULL,NULL,2.1505,6.493,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1064,705861,'tt8009428',NULL,'Hustle','Hustle','movie',2022,'https://image.tmdb.org/t/p/w500/xWic7kPq13oRxYjbGLApXCnc7pz.jpg','https://image.tmdb.org/t/p/original/hGr0FrLI74vqpBWTBOPloDBwOAK.jpg','After discovering a once-in-a-lifetime player with a rocky past abroad, a down on his luck basketball scout takes it upon himself to bring the phenom to the States without his team''s approval. Against the odds, they have one final shot to prove they have what it takes to make it in the NBA.',NULL,NULL,3.2928,7.7,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1065,19819,'tt0109305',NULL,'Blue Chips','Blue Chips','movie',1994,'https://image.tmdb.org/t/p/w500/tO71i4Ob64tchCRBB5MoqonPKAF.jpg','https://image.tmdb.org/t/p/original/y9EqhIvXtvKOFLZMSZL3jHybXvZ.jpg','Pete Bell, a college basketball coach is under a lot of pressure. His team isn''t winning and he cannot attract new players. The stars of the future are secretly being paid by boosters. This practice is forbidden in the college game, but Pete is desperate and has pressures from all around.',NULL,NULL,1.549,6.131,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1066,396371,'tt4209788',NULL,'Molly''s Game','Molly''s Game','movie',2017,'https://image.tmdb.org/t/p/w500/zrGQwKNmAz5awZI2V1k5M4eTTTN.jpg','https://image.tmdb.org/t/p/original/rHcBZ6ZKCe4FalWHyvBGsyMsh0k.jpg','Molly Bloom, a young skier and former Olympic hopeful becomes a successful entrepreneur (and a target of an FBI investigation) when she establishes a high-stakes, international poker game.',NULL,NULL,5.121,7.155,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1067,10947,'tt0475293',NULL,'High School Musical','High School Musical','movie',2006,'https://image.tmdb.org/t/p/w500/1DGmWZjUJPeKGFRHGCA6VPFUBML.jpg','https://image.tmdb.org/t/p/original/2p1nyBVSEBiCTrrZeVSV9nIsqHr.jpg','A popular high school athlete and an academically gifted girl get roles in the school musical and develop a friendship that threatens East High''s social order.',NULL,NULL,4.4473,6.546,0,1.22133333333333329e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1068,67740,'tt0082813',NULL,'Butcher, Baker, Nightmare Maker','Butcher, Baker, Nightmare Maker','movie',1981,'https://image.tmdb.org/t/p/w500/a1EpGJRGSxsM8HKOSFpSJYbbZOI.jpg','https://image.tmdb.org/t/p/original/mkYQZ0P75jDNPe6YQoh1B2Qk14f.jpg','Rejected by her lover, the only man left in Cheryl''s life is the orphaned nephew she has raised as her own son. She''ll stop at nothing to keep Billy with her. When her plans misfire, she is swept up into an insane frenzy that means death to anyone who comes between her and her obsession. But the investigating detective is convinced that Billy is the real killer - and determined to prove it. Madness and fanaticism work together to drag all concerned into a terrifying vortex of blood-letting that adds a nightmarish twist to the classic Oedipus story.',NULL,NULL,1.1434,6.528,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1069,7340,'tt0074285',NULL,'Carrie','Carrie','movie',1976,'https://image.tmdb.org/t/p/w500/8tT1rqlsTguyfUBMrbHR9cv1rxM.jpg','https://image.tmdb.org/t/p/original/zwJFfKQdfiptK2GY6N8GkZFrAxJ.jpg','Withdrawn and sensitive teenager Carrie White faces bullying from her classmates and abuse from her fanatically pious mother. When she begins to suspect that she has supernatural powers, things take a dark and violent turn.',NULL,NULL,5.6301,7.3,0,11.095,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1070,85162,'tt0094969',NULL,'Deadly Dreams','Deadly Dreams','movie',1988,'https://image.tmdb.org/t/p/w500/loJaXlYSzX2HFcfMPHYFIda6RfY.jpg','https://image.tmdb.org/t/p/original/8qAAvG4jaT0VolRSANGKWujSSyq.jpg','Alex is caught in a web of distrust between his brother, his best friend, a beautiful stranger and the renewed dreams of the slaughter of his family.',NULL,NULL,0.7907,5.0,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1071,33278,'tt0090917',NULL,'Deadly Friend','Deadly Friend','movie',1986,'https://image.tmdb.org/t/p/w500/24X1pdzeU9x2QCVDu957tpUA0kp.jpg','https://image.tmdb.org/t/p/original/AlCqrEHsJ1c3kYITJPu6VYwNKgp.jpg','When tragedy strikes his remarkable robot and the beautiful girl next door, lonely teenage genius Paul tries to save them by pushing technology beyond its known limits into a terrifying new realm.',NULL,NULL,2.2566,6.186,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1072,11797,'tt0089175',NULL,'Fright Night','Fright Night','movie',1985,'https://image.tmdb.org/t/p/w500/euIh75MwNDrYkTEVSkw7VXWGXoE.jpg','https://image.tmdb.org/t/p/original/2ytds3KqhMWRvMtrQp95JBYTKLD.jpg','Charley Brewster, a high school student, accidentally discovers the true and creepy nature of Jerry Dandrige, his dashing and enigmatic new neighbor; but no one seems willing to believe him.',NULL,NULL,4.9756,7.043,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1073,10234,'tt0119167',NULL,'Funny Games','Funny Games','movie',1997,'https://image.tmdb.org/t/p/w500/48uCNgdyYIoN4ayWjTpLaqSDcWI.jpg','https://image.tmdb.org/t/p/original/79SBe1bU30Dy6QPwJ2KQ3LTr1lr.jpg','Two psychotic young men take a mother, father, and son hostage in their vacation cabin and force them to play sadistic "games" with one another for their own amusement.',NULL,NULL,5.1789,7.311,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1074,419430,'tt5052448',NULL,'Get Out','Get Out','movie',2017,'https://image.tmdb.org/t/p/w500/tFXcEccSQMf3lfhfXKSU9iRBpa3.jpg','https://image.tmdb.org/t/p/original/o8dPH0ZSIyyViP6rjRX1djwCUwI.jpg','Chris and his girlfriend Rose go upstate to visit her parents for the weekend. At first, Chris reads the family''s overly accommodating behavior as nervous attempts to deal with their daughter''s interracial relationship, but as the weekend progresses, a series of increasingly disturbing discoveries lead him to a truth that he never could have imagined.',NULL,NULL,13.2251,7.624,0,11.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1075,948,'tt0077651',NULL,'Halloween','Halloween','movie',1978,'https://image.tmdb.org/t/p/w500/wijlZ3HaYMvlDTPqJoTCWKFkCPU.jpg','https://image.tmdb.org/t/p/original/sHI9xlFRWCJ38AIIfOqnGjuEvXz.jpg','Fifteen years after murdering his sister on Halloween Night 1963, Michael Myers escapes from a mental hospital and returns to the small town of Haddonfield, Illinois to kill again.',NULL,NULL,11.685,7.561,0,1.50166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1076,763368,'tt11486994',NULL,'Incision','Incision','movie',2020,'https://image.tmdb.org/t/p/w500/xxKyBzg3IwU3tCyXovqwbZbDKKw.jpg','https://image.tmdb.org/t/p/original/cxGcMVsRFxRhMbtKpfQ8JdA1HRB.jpg','Beauty Blogger Alexa Landry only had one fear, plastic surgery. She ultimately had to face this fear when she was kidnapped with her friends by Dr. Cunningham. A deranged plastic surgeon who is obsessed with beautifying his victims.',NULL,NULL,0.6119,5.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1077,377,'tt0087800',NULL,'A Nightmare on Elm Street','A Nightmare on Elm Street','movie',1984,'https://image.tmdb.org/t/p/w500/b9rMHAAKISRmIonaQd9Cccx0S4X.jpg','https://image.tmdb.org/t/p/original/nzSjTiecdosBfwMGAdpt9CxltCI.jpg','Teenagers in a small town are dropping like flies, apparently in the grip of mass hysteria causing their suicides. A cop''s daughter, Nancy Thompson, traces the cause to child molester Fred Krueger, who was burned alive by angry parents many years before. Krueger has now come back in the dreams of his killers'' children, claiming their lives as his revenge. Nancy and her boyfriend, Glen, must devise a plan to lure the monster out of the realm of nightmares and into the real world...',NULL,NULL,13.7143,7.348,0,13.82,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1078,609,'tt0084516',NULL,'Poltergeist','Poltergeist','movie',1982,'https://image.tmdb.org/t/p/w500/4eMN3GANH5GG4kXdHkrTZEUuQ9M.jpg','https://image.tmdb.org/t/p/original/bvkPno6U02lLyvPWCnmibq4eIaN.jpg','The Freelings'' suburban home becomes the center of paranormal activity that opens a portal to the ''other side''. With help, they must cross over to get their daughter back.',NULL,NULL,5.5174,7.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1079,158087,'tt0105464',NULL,'Star Time','Star Time','movie',1992,'https://image.tmdb.org/t/p/w500/8KvE6L1vfiPjEqGpdJFgcYxhSha.jpg','https://image.tmdb.org/t/p/original/i73kVKiY0zVZRnyzmLp1etuNHaB.jpg','When his favorite television show is canceled, Henry Pinkle is driven over the edge and decides to commit suicide. Then he meets Sam Bones, a mysterious agent who promises happiness and stardom if he follows his instructions.',NULL,NULL,0.6048,5.661,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1080,395458,'tt0491175',NULL,'Suburbicon','Suburbicon','movie',2017,'https://image.tmdb.org/t/p/w500/yqYwf0kPK2SaCWM80msl4nYK6U7.jpg','https://image.tmdb.org/t/p/original/dmgFJdivUmV4vGLkbPD49KVjlHx.jpg','In the quiet family town of Suburbicon during the 1950s, the best and worst of humanity is hilariously reflected through the deeds of seemingly ordinary people. When a home invasion turns deadly, a picture-perfect family turns to blackmail, revenge and murder.',NULL,NULL,2.9355,5.895,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1081,470229,'tt5774450',NULL,'Summer of 84','Summer of 84','movie',2018,'https://image.tmdb.org/t/p/w500/zastd8zM2ftOJpC7Y6gRFqAB7r.jpg','https://image.tmdb.org/t/p/original/iEYDBciiuW68Q5bLCzkVBgKnfi7.jpg','After suspecting that their police officer neighbor is a serial killer, a group of teenage friends spend their summer spying on him and gathering evidence, but as they get closer to discovering the truth, things get dangerous.',NULL,NULL,2.0949,6.908,0,1.20566666666666666e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1082,1118584,NULL,NULL,'Talk to Me','ABWAB (أبواب)','movie',2022,'https://image.tmdb.org/t/p/w500/9t7gUKSxXjvQpgHdC7VUhJ1BTBK.jpg','https://image.tmdb.org/t/p/original/AnV8SUecu2AHf0moME3qWpk59NS.jpg','Farid, who works abroad, locks himself on the last day of his stay in Beirut in his son Rawad''s room, to find what he is hiding there. Separated by a locked door, the dysfunctional dynamic between them intensifies, and the past resurfaces.',NULL,NULL,0.6297,0.0,0,11.27,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1083,1071215,'tt1448754',NULL,'Thanksgiving','Thanksgiving','movie',2023,'https://image.tmdb.org/t/p/w500/f5f3TEVst1nHHyqgn7Z3tlwnBIH.jpg','https://image.tmdb.org/t/p/original/ktHEdqmMWC1wdfPRMRCTZe2OISL.jpg','After a Black Friday riot ends in tragedy, a mysterious Thanksgiving-inspired killer terrorizes Plymouth, Massachusetts - the birthplace of the holiday. Picking off residents one by one, what begins as random revenge killings are soon revealed to be part of a larger, sinister holiday plan.',NULL,NULL,6.5399,6.473,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1084,11449,'tt0078767',NULL,'The Amityville Horror','The Amityville Horror','movie',1979,'https://image.tmdb.org/t/p/w500/7VMscq0659xKmcXzd86de1DGV4W.jpg','https://image.tmdb.org/t/p/original/gN5OCSeJTJcsYWlQBjJVKwV3zBS.jpg','George Lutz, his wife Kathy, and their three children have just moved into a beautiful, and improbably cheap, Victorian mansion nestled in the sleepy coastal town of Amityville, Long Island. However, their dream home is concealing a horrific past and soon each member of the Lutz family is plagued with increasingly strange and violent visions and impulses.',NULL,NULL,3.3189,6.285,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1085,756999,'tt7144666',NULL,'The Black Phone','The Black Phone','movie',2022,'https://image.tmdb.org/t/p/w500/p9ZUzCyy9wRTDuuQexkQ78R2BgF.jpg','https://image.tmdb.org/t/p/original/AfvIjhDu9p64jKcmohS4hsPG95Q.jpg','Finney Blake, a shy but clever 13-year-old boy, is abducted by a sadistic killer and trapped in a soundproof basement where screaming is of little use. When a disconnected phone on the wall begins to ring, Finney discovers that he can hear the voices of the killer’s previous victims. And they are dead set on making sure that what happened to them doesn’t happen to Finney.',NULL,NULL,9.4329,7.519,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1086,11974,'tt0096734',NULL,'The ''Burbs','The ''Burbs','movie',1989,'https://image.tmdb.org/t/p/w500/jwYKzJS0C3A711hmg1G4ptI0InF.jpg','https://image.tmdb.org/t/p/original/pyeknyOKRLBd4ROOeYL6kV103ov.jpg','When secretive new neighbors move in next door, suburbanite Ray Peterson and his friends let their paranoia get the best of them as they start to suspect the newcomers of evildoings and commence an investigation. But it''s hardly how Ray, who much prefers drinking beer, reading his newspaper and watching a ball game on the tube expected to spend his vacation.',NULL,NULL,3.8326,6.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1087,544431,'tt6269368',NULL,'The Clovehitch Killer','The Clovehitch Killer','movie',2018,'https://image.tmdb.org/t/p/w500/6NmsbUJqnopbnLun2E4KvtVNj8T.jpg','https://image.tmdb.org/t/p/original/vSPUZQr6bsvFOJPsd6NPxGkDd2v.jpg','A picture-perfect family is torn apart after Tyler finds a cache of disturbing images in his father''s possession. He begins to suspect that the man he trusts most in the world may be responsible for the murder of 13 women ten years prior.',NULL,NULL,2.3896,6.407,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1088,25155,'tt0094035',NULL,'The Stepfather','The Stepfather','movie',1987,'https://image.tmdb.org/t/p/w500/r5CKg3VJQjYvSWTRojK2tE7LpM0.jpg','https://image.tmdb.org/t/p/original/dkT3zHMMEULn1o79xktvVbjWM7.jpg','Seemingly mild-mannered Henry Morrison has just murdered his entire family. After adopting a new identity and skipping town, he begins building a new relationship with a widow and her teenage daughter. However, he soon begins struggling to hide his true identity and maintain a grip on reality.',NULL,NULL,1.6614,6.534,0,1.2043333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1089,2655,'tt0161081',NULL,'What Lies Beneath','What Lies Beneath','movie',2000,'https://image.tmdb.org/t/p/w500/2L3Cn0CizbSy2E9KJt1SiOSyb6p.jpg','https://image.tmdb.org/t/p/original/2ormFaKdyP2m8qGcB3cNlk5VjGD.jpg','Norman and Claire Spencer are a seemingly happily married couple who uncover a terrible secret… a secret so disturbing it threatens to destroy them.',NULL,NULL,4.2658,6.44,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1090,81,'tt0087544',NULL,'Warriors of the Wind','風の谷のナウシカ','movie',1984,'https://image.tmdb.org/t/p/w500/tcrkfB8SRPQCgwI88hQScua6nxh.jpg','https://image.tmdb.org/t/p/original/ulVUa2MvnJAjAeRt7h23FFJVRKH.jpg','After a global war, the seaside kingdom known as the Valley of the Wind remains one of the last strongholds on Earth untouched by a poisonous jungle and the powerful insects that guard it. Led by the courageous Princess Nausicaä, the people of the Valley engage in an epic struggle to restore the bond between humanity and Earth.',NULL,NULL,9.5107,7.947,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1091,33441,'tt0093871',NULL,'Robot Carnival','ロボット・カーニバル','movie',1987,'https://image.tmdb.org/t/p/w500/2DTREQNErBYtZd1isRqdqNbbXA8.jpg','https://image.tmdb.org/t/p/original/iV6G3qnnEsZ1CsHXjxoXNBeKMw6.jpg','An anthology of various tales told in various styles with robots being the one common element among them.',NULL,NULL,1.1434,6.671,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1092,204154,'tt21056886',NULL,'Scavengers Reign','Scavengers Reign','tv',2023,'https://image.tmdb.org/t/p/w500/bFlVZV8TQbs8hcIY7PVYonYFMgK.jpg','https://image.tmdb.org/t/p/original/rrREM1cowfMZ8SmrJ9KCFO3y4j6.jpg','When a deep space freighter is damaged by a solar flare its surviving crew are stranded on a beautiful and unforgiving planet. They begin to learn the true nature of this planet as they try to survive long enough to escape or be rescued.',NULL,NULL,6.773,8.473,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1093,464052,'tt7126948',NULL,'Wonder Woman 1984','Wonder Woman 1984','movie',2020,'https://image.tmdb.org/t/p/w500/8UlWHLMpgZm9bx6QYh0NFoq67TZ.jpg','https://image.tmdb.org/t/p/original/egg7KFi18TSQc1s24RMmR9i2zO6.jpg','A botched store robbery places Wonder Woman in a global battle against a powerful and mysterious ancient force that puts her powers in jeopardy.',NULL,NULL,9.0449,6.365,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1094,252171,'tt2326554',NULL,'A Girl Walks Home Alone at Night','A Girl Walks Home Alone at Night','movie',2014,'https://image.tmdb.org/t/p/w500/cd2rCE1nun7CESjBI8PGNEof1tb.jpg','https://image.tmdb.org/t/p/original/5mUTmmBFbsXlJE66XOumJSzYK7M.jpg','In the Iranian ghost-town Bad City, a place that reeks of death and loneliness, the townspeople are unaware they are being stalked by a lonesome vampire.',NULL,NULL,1.708,6.8,0,13.4875,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1095,25062,'tt0055506',NULL,'A Taste of Honey','A Taste of Honey','movie',1961,'https://image.tmdb.org/t/p/w500/5psrZNVZ9E6Eck7OtpO47A8zTbQ.jpg','https://image.tmdb.org/t/p/original/zalZRF7sCtghHFg4xCBJfOqj0h5.jpg','While out to avoid spending time with her narcissistic and promiscuous mother, sixteen-year-old Jo has a brief affair that leaves her pregnant and abandoned. When her mother remarries, Jo''s only support becomes her friend Geoffrey, a homosexual.',NULL,NULL,1.2996,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1096,2204,'tt0069687',NULL,'Alice in the Cities','Alice in den Städten','movie',1974,'https://image.tmdb.org/t/p/w500/lw22wORmENkTZHGXI6bKmAIHxjO.jpg','https://image.tmdb.org/t/p/original/gDibTI8sDBhFnczL3VqHhlnfq78.jpg','German journalist Philip Winter has a case of writer’s block when trying to write an article about the United States. He decides to return to Germany, and while trying to book a flight, encounters a German woman and her nine year old daughter Alice doing the same. The three become friends (almost out of necessity) and while the mother asks Winter to mind Alice temporarily, it quickly becomes apparent that Alice will be his responsibility for longer than he expected.',NULL,NULL,2.0217,7.7,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1097,26535,'tt0056868',NULL,'Billy Liar','Billy Liar','movie',1963,'https://image.tmdb.org/t/p/w500/8YUzVyN3HdedaK7oGVf2nVrsf4R.jpg','https://image.tmdb.org/t/p/original/7GnuKyGYNgIxTd9jC5SZZFSIbSP.jpg','A young Englishman dreams of escaping from his working class family and dead-end job as an undertaker''s assistant. A number of indiscretions cause him to lie in order to avoid the penalties. His life turns into a mess and he has an opportunity to run away and leave it all behind.',NULL,NULL,1.0164,6.824,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1098,32008,'tt0054687',NULL,'Blast of Silence','Blast of Silence','movie',1961,'https://image.tmdb.org/t/p/w500/53vcxT6Ptz5uR9T64IwIudZqcuK.jpg','https://image.tmdb.org/t/p/original/pIoGup7Z6U5MlUbDA4eeLiqzgX8.jpg','A hired killer from Cleveland has a job to do on a second-string mob boss in New York. But a special girl from his past and a fat gun dealer with pet rats get in his way.',NULL,NULL,0.8364,6.968,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1099,386948,'tt1623202',NULL,'Beautiful Brazil','Beautiful Brazil','movie',1952,NULL,NULL,'We start in Rio de Janeiro, with the statue of Cristo Redentor on Mount Corcovado, the avenue along the beach, the beauty of an historic city, and the landmark, Sugarloaf. Brazil''s 47 million people celebrate racial diversity. From the Copacabana, we travel 40 miles to a resort, Quitandinha, where President Truman spoke. Then it''s on to Sao Paulo, a modern, industrial city, and finally to the spectacular waterfalls of Iguazu on the border between Brazil and Argentina.',NULL,NULL,0.2803,7.0,0,1.39074999999999988e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1100,25297,'tt0083717',NULL,'Cannery Row','Cannery Row','movie',1982,'https://image.tmdb.org/t/p/w500/4U0NCom1slWMgGL9dCKsQdq82fP.jpg','https://image.tmdb.org/t/p/original/4pgCm4Z8vH4NVyxB8fDMnhiViUk.jpg','Doc, who has just moved to Cannery Row, realizes that the only entertainment is the brothel. There he meets the spunky Suzy and they fall in love, giving them both a renewed chance at life.',NULL,NULL,0.9629,5.844,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1101,9693,'tt0206634',NULL,'Children of Men','Children of Men','movie',2006,'https://image.tmdb.org/t/p/w500/k9IAS4TehZFcKi4HVByxZNPfqex.jpg','https://image.tmdb.org/t/p/original/gFGLwUBhVrq0bq4j9DU08xQDRU2.jpg','In 2027, in a chaotic world in which humans can no longer procreate, a former activist agrees to help transport a miraculously pregnant woman to a sanctuary at sea, where her child''s birth may help scientists save the future of humankind.',NULL,NULL,8.6825,7.613,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1102,15,'tt0033467',NULL,'Citizen Kane','Citizen Kane','movie',1941,'https://image.tmdb.org/t/p/w500/sav0jxhqiH0bPr2vZFU0Kjt2nZL.jpg','https://image.tmdb.org/t/p/original/ruF3Lmd4A8MHbnEBE6lxPMbsHGL.jpg','Newspaper magnate Charles Foster Kane is taken from his mother as a boy and made the ward of a rich industrialist. As a result, every well-meaning, tyrannical or self-destructive move he makes for the rest of his life appears in some way to be a reaction to that deeply wounding event.',NULL,NULL,6.3221,7.971,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1103,25237,'tt0091251',NULL,'Come and See','Иди и смотри','movie',1985,'https://image.tmdb.org/t/p/w500/qNbMsKVzigERgJUbwf8pKyZogpb.jpg','https://image.tmdb.org/t/p/original/3Na31ta8vDuKOgQuPLdSZLs8bCB.jpg','The invasion of a village in Belarus by German forces sends young Florya into the forest to join the weary Resistance fighters, against his family''s wishes. There he meets a girl, Glasha, who accompanies him back to his village. On returning home, Florya finds his family and fellow peasants massacred. His continued survival amidst the brutal debris of war becomes increasingly nightmarish, a battle between despair and hope.',NULL,NULL,5.232,8.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1104,133121,'tt1753496',NULL,'Resident Evil: Damnation','バイオハザード ダムネーション','movie',2012,'https://image.tmdb.org/t/p/w500/zkHSURVCrt7rpvDDgUXO75CV1v4.jpg','https://image.tmdb.org/t/p/original/xbjOkrAaT4CAIrNJ38oQSBomHvg.jpg','U.S. federal agent Leon S. Kennedy sneaks into the "East Slavic Republic" to verify rumors that Bio-Organic Weapons (BOWs) are being used in the country''s civil war, which the U.S. and Russia are making preparations to jointly intervene in. Right after his infiltration, the U.S. government orders him to leave immediately. Determined to uncover the truth, Leon ignores the order and enters the battlefield to end the chain of tragedies caused by the BOWs.',NULL,NULL,2.8369,6.897,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1105,892,'tt0101700',NULL,'Delicatessen','Delicatessen','movie',1991,'https://image.tmdb.org/t/p/w500/gNtOgQHxE5B8e08zuNRAdDpmK5Z.jpg','https://image.tmdb.org/t/p/original/A3qvUUd36LUF5sfPYOHEd3ahDp2.jpg','In a post-apocalyptic world, the residents of an apartment above the butcher shop receive an occasional delicacy of meat, something that is in low supply. A young man new in town falls in love with the butcher''s daughter, which causes conflicts in her family, who need the young man for other business-related purposes.',NULL,NULL,2.7546,7.314,0,1.25266666666666672e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1106,885,'tt0018839',NULL,'The Docks of New York','The Docks of New York','movie',1928,'https://image.tmdb.org/t/p/w500/rCMZpfPAHeuy02nMCttEX3OJt4B.jpg','https://image.tmdb.org/t/p/original/uLgeOKqBF7PIn9Dz3oa5TSY8k3s.jpg','A blue-collar worker on New York''s depressed waterfront finds his life changed after he saves a woman attempting suicide.',NULL,NULL,1.04,6.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1107,374720,'tt5013056',NULL,'Dunkirk','Dunkirk','movie',2017,'https://image.tmdb.org/t/p/w500/b4Oe15CGLL61Ped0RAS9JpqdmCt.jpg','https://image.tmdb.org/t/p/original/ddIkmH3TpR6XSc47jj0BrGK5Rbz.jpg','The story of the miraculous evacuation of Allied soldiers from Belgium, Britain, Canada and France, who were cut off and surrounded by the German army from the beaches and harbour of Dunkirk between May 26th and June 4th 1940 during World War II.',NULL,NULL,11.8306,7.5,0,12.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1108,181886,'tt2316411',NULL,'Enemy','Enemy','movie',2014,'https://image.tmdb.org/t/p/w500/vf40tyDRKZsBmaLsYeopzfFLzLx.jpg','https://image.tmdb.org/t/p/original/deYWtXTc56YdXyIuuMuA8dvBY16.jpg','A mild-mannered college professor discovers a look-alike actor and delves into the other man''s private affairs.',NULL,NULL,7.0111,6.844,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1109,62214,'tt1142977',NULL,'Frankenweenie','Frankenweenie','movie',2012,'https://image.tmdb.org/t/p/w500/yGjVbLVdZRBlZTTQVBsj2KUjL1s.jpg','https://image.tmdb.org/t/p/original/yfTZ2MSRWc06cBrFOsAF4Lebi4.jpg','When a car hits young Victor''s pet dog Sparky, Victor decides to bring him back to life the only way he knows how. But when the bolt-necked "monster" wreaks havoc and terror in the hearts of Victor''s neighbors, he has to convince them that Sparky''s still the good, loyal friend he was.',NULL,NULL,4.501,7.008,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1110,10461,'tt0208988',NULL,'Get Carter','Get Carter','movie',2000,'https://image.tmdb.org/t/p/w500/xGANaRWD6638ch1qQmqgRp395R6.jpg','https://image.tmdb.org/t/p/original/6TXJyG1MqcSZmcTjk1wrjsrhBWT.jpg','Jack Carter, a mob enforcer living in Las Vegas, travels back to his hometown of Seattle for his brother''s funeral. During this visit, Carter realizes that the death of his brother was not accidental, but a murder. With this knowledge, Carter sets out to kill all those responsible.',NULL,NULL,2.1491,5.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1111,1405,'tt0015881',NULL,'Greed','Greed','movie',1924,'https://image.tmdb.org/t/p/w500/eur2vc2BGiOocBuBLVPXySO7lRh.jpg','https://image.tmdb.org/t/p/original/zc5vjonSbXUUazuQSi0R2bUfWNP.jpg','When housewife Trina wins the lottery, her comfortable life with her dentist husband John slowly deteriorates, in part by her own increasing paranoia and partly by the machinations of villainous acquaintance Marcus.',NULL,NULL,3.7604,7.3,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1112,5544,'tt0052893',NULL,'Hiroshima Mon Amour','Hiroshima mon amour','movie',1959,'https://image.tmdb.org/t/p/w500/zieczjWnvalaxwX5EQASEx0on5f.jpg','https://image.tmdb.org/t/p/original/4fynFAYPPYCkyIdt0bsCwWn3Hxv.jpg','The deep conversation between a Japanese architect and a French actress forms the basis of this celebrated French film, considered one of the vanguard productions of the French New Wave. Set in Hiroshima after the end of World War II, the couple -- lovers turned friends -- recount, over many hours, previous romances and life experiences. The two intertwine their stories about the past with pondering the devastation wrought by the atomic bomb dropped on the city.',NULL,NULL,3.0958,7.666,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1113,16410,'tt0047094',NULL,'Hobson''s Choice','Hobson''s Choice','movie',1954,'https://image.tmdb.org/t/p/w500/kbP7EgoiOw2bIypai50JWRsqP7p.jpg','https://image.tmdb.org/t/p/original/1GeeKCUu77eBU1ut8hTBQRmb7Iq.jpg','A widower refuses to let his three daughters marry in order to avoid paying settlements, so they''ll just have to outsmart him.',NULL,NULL,1.3314,7.381,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1114,43266,'tt0033729',NULL,'How Green Was My Valley','How Green Was My Valley','movie',1941,'https://image.tmdb.org/t/p/w500/8N7OmxBqjRVUrqergUduGgr6exy.jpg','https://image.tmdb.org/t/p/original/ucQESsrG63LsA5HD70aaPxEyORk.jpg','Huw Morgan, the academically inclined youngest son in a proud family of Welsh coal miners, witnesses the tumultuous events of his young life during a period of rapid social change. At the dawn of the 20th-century, a miners'' strike divides the Morgans: the sons demand improvements, and the father doesn''t want to rock the boat.',NULL,NULL,2.638,7.304,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1115,2048,'tt0343818',NULL,'I, Robot','I, Robot','movie',2004,'https://image.tmdb.org/t/p/w500/efwv6F2lGaghjPpBRSINHtoEiZB.jpg','https://image.tmdb.org/t/p/original/jpFcZH2eyh6gcoxCa637TrGe4bT.jpg','In 2035, where robots are commonplace and abide by the three laws of robotics, a technophobic cop investigates an apparent suicide. Suspecting that a robot may be responsible for the death, his investigation leads him to believe that humanity may be in danger.',NULL,NULL,9.2164,6.966,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1116,42836,'tt0022017',NULL,'Comradeship','Kameradschaft','movie',1931,'https://image.tmdb.org/t/p/w500/dSGMzPqWQz2IvjvVx0WDD3z7zBF.jpg','https://image.tmdb.org/t/p/original/x8Ta8xVfffyyGA9k8sdGf3VCFo2.jpg','At a mine on the shared edge of France and Germany, an underground explosion leads to the entrapment of a group of French miners. In an effort to save the trapped Frenchmen, German miners Wittkopp and Kasper take it upon themselves to traverse a crumbling war tunnel leading down into the mines. Yet, though the workers harbor no political biases against one another, their callous, less tolerant bosses hope to halt this cross-cultural rescue mission.',NULL,NULL,0.8403,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1117,13384,'tt0064541',NULL,'Kes','Kes','movie',1970,'https://image.tmdb.org/t/p/w500/r1FMq75irhsQBVGjXhPU4xA9SDo.jpg','https://image.tmdb.org/t/p/original/eWvxOS5g67B1b46Cff9TlYuJleY.jpg','Bullied at school and ignored and abused at home by his indifferent mother and older brother, Billy Casper, a 15-year-old working-class Yorkshire boy, tames and trains his pet kestrel falcon whom he names Kes. Helped and encouraged by his English teacher and his fellow students, Billy finally finds a positive purpose to his unhappy existence.',NULL,NULL,1.9357,7.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1118,20874,'tt0091341',NULL,'Kin-dza-dza!','Кин-дза-дза!','movie',1986,'https://image.tmdb.org/t/p/w500/b38fRsOD7LoPGQSmKeB2jQvVkGx.jpg','https://image.tmdb.org/t/p/original/iN2Sez3yNI5RYAQM6ziEAnlYSms.jpg','Two Soviet humans previously unknown to each other are transported to the planet Pluke in the Kin-dza-dza galaxy due to a chance encounter with an alien teleportation device. They must come to grips with a language barrier and Plukian social norms (not to mention the laws of space and time) if they ever hope to return to Earth.',NULL,NULL,2.5887,7.702,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1119,43904,'tt0024844',NULL,'L''Atalante','L''Atalante','movie',1934,'https://image.tmdb.org/t/p/w500/yDTHSZGk1G33Q3nBNqhnpgmkyk7.jpg','https://image.tmdb.org/t/p/original/dFbCil5MUoRX2s4u2XcK7knJpT.jpg','Newly married couple Juliette and ship captain Jean struggle through marriage as they travel on the L''Atalante along with the captain''s first mate and a cabin boy.',NULL,NULL,1.3583,7.485,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1120,29415,'tt0029957',NULL,'La Bête Humaine','La Bête humaine','movie',1938,'https://image.tmdb.org/t/p/w500/yB8UpOKAz4yorzBqLWXtc6hO3O4.jpg','https://image.tmdb.org/t/p/original/jS9W4jk2vPtq8PIZppYwYAPZpUP.jpg','Returning by train to the French port of Le Havre, Jacques Lantier, a tormented railwayman, meets by chance the impulsive stationmaster Roubard and Séverine, his wife.',NULL,NULL,1.1075,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1121,832,'tt0022100',NULL,'M','M - Eine Stadt sucht einen Mörder','movie',1931,'https://image.tmdb.org/t/p/w500/bTdZk3q2DWpBRnLiaaItKFWOVhI.jpg','https://image.tmdb.org/t/p/original/5Pk1rGAtyblh9Xaq72T7ARCQSDQ.jpg','In this classic German thriller, Hans Beckert, a serial killer who preys on children, becomes the focus of a massive Berlin police manhunt. Beckert''s heinous crimes are so repellant and disruptive to city life that he is even targeted by others in the seedy underworld network. With both cops and criminals in pursuit, the murderer soon realizes that people are on his trail, sending him into a tense, panicked attempt to escape justice.',NULL,NULL,3.2712,8.056,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1122,19119,'tt0042788',NULL,'Night and the City','Night and the City','movie',1950,'https://image.tmdb.org/t/p/w500/2NBmzm8z5fd283eWeECkPrkwta8.jpg','https://image.tmdb.org/t/p/original/15mrnCjsVRJafPhdsRKvmbhu3S0.jpg','Londoner Harry Fabian is a second-rate con man looking for an angle. After years of putting up with Harry''s schemes, his girlfriend, Mary, becomes fed up when he taps her for yet another loan.',NULL,NULL,2.6983,7.476,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1123,52362,'tt0037135',NULL,'None But the Lonely Heart','None But the Lonely Heart','movie',1944,'https://image.tmdb.org/t/p/w500/st37wKa1ZUbVSlKFI1fuUWb0rbi.jpg','https://image.tmdb.org/t/p/original/iwSuFnsieEdzAt943GzhmHTU6V3.jpg','When an itinerant reluctantly returns home to help his sickly mother run her shop, they''re both tempted to turn to crime to help make ends meet.',NULL,NULL,1.0069,6.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1124,780354,'tt0272220',NULL,'Now Voyager','Now Voyager','movie',1985,'https://image.tmdb.org/t/p/w500/xgI6XxlsvMYWzIs0Aejeau0aWcb.jpg',NULL,'A spoiled pop star crashes his car in an irrigation ditch and comes to in a public indoor pool supervised by a mysterious man who attempts to show him the error of his ways.',NULL,NULL,1.5761,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1125,29785,'tt1232790',NULL,'Of Time and the City','Of Time and the City','movie',2008,'https://image.tmdb.org/t/p/w500/1kdvuMUOTBkcjtWNwL9W0sEmaQG.jpg','https://image.tmdb.org/t/p/original/oaymUCmgnw6pAsQyWsB8cdCbc6F.jpg','British director Terence Davies reflects on his birthplace of Liverpool - his memories of growing up there and how it has changed in the years since - in the process meditating on the internal struggles and conflicts that have wracked him throughout his life and the history of England during the second half of the 20th century.',NULL,NULL,0.4347,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1126,654,'tt0047296',NULL,'On the Waterfront','On the Waterfront','movie',1954,'https://image.tmdb.org/t/p/w500/v1RtJ1qR4v9nrnfoBVBl6hjTW9.jpg','https://image.tmdb.org/t/p/original/amGiUn4YUuphqmpN8yyuuwDhRPa.jpg','A prizefighter-turned-longshoreman with a conscience goes up against labor leaders to expose corruption, extortion, and murder among the union ranks.',NULL,NULL,4.2488,7.9,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1127,59189,'tt0070531',NULL,'Phase IV','Phase IV','movie',1974,'https://image.tmdb.org/t/p/w500/x6fQtAmCD4JlAcUnTfYoinPp1zz.jpg','https://image.tmdb.org/t/p/original/qMxhl5NeeXj4Rs0stsGgC7GsB9C.jpg','Arizona ants mock the food chain on their way to a desert lab to get two scientists and a woman.',NULL,NULL,1.3219,6.3,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1128,46326,'tt0030643',NULL,'Port of Shadows','Le quai des brumes','movie',1938,'https://image.tmdb.org/t/p/w500/2S8O2V50TZlXV8uabOvGUJ1i5CZ.jpg','https://image.tmdb.org/t/p/original/tdRp4HCCw4YoWtZuqlePNcZ0nCA.jpg','Down a foggy, desolate road to the port city of Le Havre travels Jean, an army deserter looking for another chance to make good on life. Fate, however, has a different plan for him, as acts of both revenge and kindness render him front-page news.',NULL,NULL,1.3919,7.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1129,45945,'tt0079773',NULL,'Radio On','Radio On','movie',1979,'https://image.tmdb.org/t/p/w500/4KHfHnCq0GEEJSHNaKGsFppNQbv.jpg','https://image.tmdb.org/t/p/original/pwDuUpAypSJJuNsE4WJ8l0YpSL9.jpg','A London radio DJ receives news of his brother''s suicide and travels west to Bristol to find out more.',NULL,NULL,0.5519,5.815,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1130,26638,'tt0058003',NULL,'Red Desert','Il deserto rosso','movie',1964,'https://image.tmdb.org/t/p/w500/rGcTVdyhaGzMxPPRVApXre6F7SD.jpg','https://image.tmdb.org/t/p/original/xe43LKesFXjQgP4W1s2juf7Tb4t.jpg','In an industrializing Italian town, a married woman, rendered mentally unstable after a traffic accident, drifts into an affair with a friend of her husband.',NULL,NULL,2.0446,7.31,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1131,305494,'tt1830238',NULL,'Salad Fingers','Salad Fingers','tv',2004,'https://image.tmdb.org/t/p/w500/mQp7p7gpQLoQMMNRFERDWBaDeb5.jpg','https://image.tmdb.org/t/p/original/8tVsqiCvi1Q4eCKNFvdYvoyxMYT.jpg','The surreal life of Salad Fingers, an unknown creature living in an apocalyptic wasteland.',NULL,NULL,0.9472,8.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1132,31414,'tt0111341',NULL,'Satantango','Sátántangó','movie',1994,'https://image.tmdb.org/t/p/w500/y38z0v4HJ12MHiKddLEoFlvPiBt.jpg','https://image.tmdb.org/t/p/original/5a4Gmk2HNeefI4Rmwdmbyoy79oy.jpg','Inhabitants of a small village in Hungary deal with the effects of the fall of Communism. The town''s source of revenue, a factory, has closed, and the locals, who include a doctor and three couples, await a cash payment offered in the wake of the shuttering. Irimias, a villager thought to be dead, returns and, unbeknownst to the locals, is a police informant. In a scheme, he persuades the villagers to form a commune with him.',NULL,NULL,3.4554,8.0,0,1.3036666666666667e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1133,37230,'tt0054269',NULL,'Saturday Night and Sunday Morning','Saturday Night and Sunday Morning','movie',1960,'https://image.tmdb.org/t/p/w500/ifhjfo8lZoJ9dvDQiWcnc3GeFK4.jpg','https://image.tmdb.org/t/p/original/3FCisYSoJXlW2UdJwJq2tEtUP5Y.jpg','A 22-year-old factory worker lets loose on the weekends: drinking, brawling, and dating two women, one of whom is older and married.',NULL,NULL,1.0504,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1134,187,'tt0401792',NULL,'Sin City','Sin City','movie',2005,'https://image.tmdb.org/t/p/w500/i66G50wATMmPrvpP95f0XP6ZdVS.jpg','https://image.tmdb.org/t/p/original/t9kQnqiaxQ8TLB25rTzDKLd0fdM.jpg','Welcome to Sin City. This town beckons to the tough, the corrupt, the brokenhearted. Some call it dark… Hard-boiled. Then there are those who call it home — Crooked cops, sexy dames, desperate vigilantes. Some are seeking revenge, others lust after redemption, and then there are those hoping for a little of both. A universe of unlikely and reluctant heroes still trying to do the right thing in a city that refuses to care.',NULL,NULL,6.6067,7.465,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1135,469,'tt0088184',NULL,'Stranger Than Paradise','Stranger Than Paradise','movie',1984,'https://image.tmdb.org/t/p/w500/Q9wdlNjBOti4JhAjAQXphzShw3.jpg','https://image.tmdb.org/t/p/original/zhSELy6slpnyDTkCX8bIyBtwoK6.jpg','New York layabout Willie forms an unexpected bond with his young Hungarian cousin Eva when she pays him a surprise visit. Later, Eva moves in with their aunt in Cleveland, and Willie takes his best friend Eddie to see her—a visit that culminates in a strange, eventful trip to Florida.',NULL,NULL,2.8815,7.153,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1136,43001,'tt0055910',NULL,'Sundays and Cybele','Cybèle ou les dimanches de ville d''Avray','movie',1962,'https://image.tmdb.org/t/p/w500/9L5DtYYlO3yrg2qtTCxROLnLl2V.jpg','https://image.tmdb.org/t/p/original/dMQcHcEMDLuCjtrIY1nfuktoLW8.jpg','The tragic story of a young orphan girl who is befriended by an innocent but emotionally disabled veteran of the French Indochina War.',NULL,NULL,1.1194,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1137,37924,'tt0479760',NULL,'Sweeney Todd','Sweeney Todd','movie',2006,'https://image.tmdb.org/t/p/w500/40ntPvTqjqEJlME1AtBEzwVUPHC.jpg','https://image.tmdb.org/t/p/original/d118NiMInfjuMRGmEmfF5qif9Wf.jpg','A BBC adaptation of the Victorian "penny dreadful" tale of 19th century "demon barber" Sweeney Todd, of Fleet Street, who cuts the throats of unsuspecting clients in his London shop.',NULL,NULL,1.3571,6.346,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1138,41428,'tt0096251',NULL,'Tetsuo: The Iron Man','鉄男','movie',1989,'https://image.tmdb.org/t/p/w500/skAxIP1DgnVIXaUaPFozWXtsbhs.jpg','https://image.tmdb.org/t/p/original/xt75NSIlfzwPwuBsuarB3i1mBxj.jpg','A "metal fetishist", driven mad by the maggots wriggling in the wound he''s made to embed metal into his flesh, runs out into the night and is accidentally run down by a Japanese businessman and his girlfriend. The pair dispose of the corpse in hopes of quietly moving on with their lives. However, the businessman soon finds that he is now plagued by a vicious curse that transforms his flesh into iron.',NULL,NULL,2.8064,6.967,0,14.628,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1139,20504,'tt1037705',NULL,'The Book of Eli','The Book of Eli','movie',2010,'https://image.tmdb.org/t/p/w500/1H1y9ZiqNFaLgQiRDDZLA55PviW.jpg','https://image.tmdb.org/t/p/original/aPrrrGtSjXbw8XnpzsVJgF0ioq3.jpg','A post-apocalyptic tale, in which a lone man fights his way across America in order to protect a sacred book that holds the secrets to saving humankind.',NULL,NULL,6.4147,6.804,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1140,9063,'tt0087280',NULL,'The Element of Crime','Forbrydelsens element','movie',1984,'https://image.tmdb.org/t/p/w500/sfg5KUOdR4bfoPiDf63LVG7mlfw.jpg','https://image.tmdb.org/t/p/original/zpkSkHXm81jlFgXmTmmGQ4TuUzo.jpg','Fisher, an ex-detective, decides to take one final case when a mysterious serial killer claims the lives of several young girls. Fisher, unable to find the culprit, turns to Osbourne, a writer who was once respected for his contributions to the field of criminology. Fisher begins to use Osbourne''s technique, which involves empathizing with serial killers; however, as the detective becomes increasingly engrossed in this method, things take a disturbing turn.',NULL,NULL,1.4536,6.368,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1141,1955,'tt0080678',NULL,'The Elephant Man','The Elephant Man','movie',1980,'https://image.tmdb.org/t/p/w500/u0wpPYjuSt8DIe1Y3Vapnh8jcKE.jpg','https://image.tmdb.org/t/p/original/6huSptAsqYg3wbsi1jbMognSgmp.jpg','A Victorian surgeon rescues a heavily disfigured man being mistreated by his "owner" as a side-show freak. Behind his monstrous façade, there is revealed a person of great intelligence and sensitivity. Based on the true story of Joseph Merrick (called John Merrick in the film), a severely deformed man in 19th century London.',NULL,NULL,6.0826,8.048,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1142,24650,'tt0041386',NULL,'The Fountainhead','The Fountainhead','movie',1949,'https://image.tmdb.org/t/p/w500/2uo8tfSwzrDeRS5YpmLVSXHSjOl.jpg','https://image.tmdb.org/t/p/original/7AHYt8RanRRMhLpazdlWXh3ehoY.jpg','An uncompromising, visionary architect struggles to maintain his integrity and individualism despite personal, professional and economic pressures to conform to popular standards.',NULL,NULL,1.8568,6.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1143,596,'tt0032551',NULL,'The Grapes of Wrath','The Grapes of Wrath','movie',1940,'https://image.tmdb.org/t/p/w500/eUcxMVBIA0Jg8l1RGUqycrc3eIQ.jpg','https://image.tmdb.org/t/p/original/eMgflonfRY89Zj4LZykJKPpG4wg.jpg','Tom Joad returns to his home after a jail sentence to find his family kicked out of their farm due to foreclosure. He catches up with them on his Uncle’s farm, and joins them the next day as they head for California and a new life... Hopefully.',NULL,NULL,2.8588,7.801,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1144,21344,'tt0099951',NULL,'The Krays','The Krays','movie',1990,'https://image.tmdb.org/t/p/w500/e7GqmnQJRWXYs8Y8uXma6p7Amcw.jpg','https://image.tmdb.org/t/p/original/r0W2dFpNgQKzowI7q9IbJ5P5vLI.jpg','Twins Ronnie and Reggie Kray are raised in east London, under the influence of their hateful but doting mother Violet. As they grow up, Ronnie''s violent nature takes over, and Reggie follows his brother''s lead. The two become notorious crime lords who rule over the East End club scene. But at the height of their power, the brothers veer into different lives, giving the older crime bosses a chance to reclaim what the Krays took from them.',NULL,NULL,1.0965,6.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1145,343887,'tt2102508',NULL,'The Last Laugh','The Last Laugh','movie',2016,'https://image.tmdb.org/t/p/w500/aSx9GuubOqbCUWAJjt62UogsES2.jpg','https://image.tmdb.org/t/p/original/zPC3pggrGzuYotp9ZbQFsS69K66.jpg','Feature documentary about humor and the Holocaust, examining whether it is ever acceptable to use humor in connection with a tragedy of that scale, and the implications for other seemingly off-limits topics in a society that prizes free speech.',NULL,NULL,1.4521,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1146,31262,'tt0415127',NULL,'The Man from London','A Londoni férfi','movie',2008,'https://image.tmdb.org/t/p/w500/poBhgpN4fJfzaRuG4wMLah3rHLw.jpg','https://image.tmdb.org/t/p/original/xgJt1f0OkcSsbWNQaoKddPIOgCh.jpg','A switchman at a seaside railway witnesses a murder but does not report it after he finds a suitcase full of money at the scene of the crime.',NULL,NULL,1.0924,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1147,980,'tt0036244',NULL,'The Ox-Bow Incident','The Ox-Bow Incident','movie',1943,'https://image.tmdb.org/t/p/w500/1rzmL32QaewQbpO1zbhZKMDn5Gz.jpg','https://image.tmdb.org/t/p/original/dmmiwTfk4AraKkK8DwmrXYas5rS.jpg','A posse discovers a trio of men they suspect of murder and cow theft and are split between handing them over to the law or lynching them on the spot.',NULL,NULL,1.9503,7.713,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1148,20766,'tt0898367',NULL,'The Road','The Road','movie',2009,'https://image.tmdb.org/t/p/w500/qLaXnLzqleBWQtjvZ6JGVSaKoC3.jpg','https://image.tmdb.org/t/p/original/6188iOmUAitGThYUjyx20fO4LJd.jpg','A father and his son walk alone through burned America. Nothing moves in the ravaged landscape save the ash on the wind and water. It is cold enough to crack stones and, when the snow falls, it is gray. Their destination is the warmer south, although they don''t know what, if anything, awaits them there.',NULL,NULL,4.9593,7.022,0,1.43566666666666673e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1149,13580,'tt0059749',NULL,'The Spy Who Came In from the Cold','The Spy Who Came In from the Cold','movie',1965,'https://image.tmdb.org/t/p/w500/lN3PWv6cW22mqXDcgGZgK1Aa2gh.jpg','https://image.tmdb.org/t/p/original/llwusQFdHmHCWS7jySP2r6bbAIm.jpg','British agent Alec Leamas refuses to come in from the Cold War during the 1960s, choosing to face another mission, which may prove to be his final one.',NULL,NULL,1.6989,7.084,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1150,43822,'tt0031976',NULL,'The Stars Look Down','The Stars Look Down','movie',1940,'https://image.tmdb.org/t/p/w500/aUmcGT0ghKBc82fXvJYypkVt2Pg.jpg','https://image.tmdb.org/t/p/original/AkgwfE8aOS3BNpqCD2g9ujmmpmU.jpg','Davey Fenwick leaves his mining village on a university scholarship intent on returning to better support the miners against the owners. But he falls in love with Jenny who gets him to marry her and return home as local schoolteacher before finishing his degree.',NULL,NULL,0.7787,6.518,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1151,1092,'tt0041959',NULL,'The Third Man','The Third Man','movie',1949,'https://image.tmdb.org/t/p/w500/rO2Fq0AZZx9obs52KJdx4mRE8p5.jpg','https://image.tmdb.org/t/p/original/rLLhOCgAjuvlKmjUqVb7P1UAbUI.jpg','In postwar Vienna, Austria, Holly Martins, a writer of pulp Westerns, arrives penniless as a guest of his childhood chum Harry Lime, only to learn he has died. Martins develops a conspiracy theory after learning of a "third man" present at the time of Harry''s death, running into interference from British officer Major Calloway, and falling head-over-heels for Harry''s grief-stricken lover, Anna.',NULL,NULL,4.283,7.893,0,14.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1152,346685,'tt3631112',NULL,'The Girl on the Train','The Girl on the Train','movie',2016,'https://image.tmdb.org/t/p/w500/AhTO2QWG0tug7yDoh0XoaMhPt3J.jpg','https://image.tmdb.org/t/p/original/hmMnCqNnHPvQhuxynSVAqQWmQVK.jpg','Rachel Watson, devastated by her recent divorce, spends her daily commute fantasizing about the seemingly perfect couple who live in a house that her train passes every day, until one morning she sees something shocking happen there and becomes entangled in the mystery that unfolds.',NULL,NULL,5.3078,6.441,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1153,3090,'tt0040897',NULL,'The Treasure of the Sierra Madre','The Treasure of the Sierra Madre','movie',1948,'https://image.tmdb.org/t/p/w500/pWcst7zVbi8Z8W6GFrdNE7HHRxL.jpg','https://image.tmdb.org/t/p/original/osytHgkv86CTFKxo46l9P7ACEjm.jpg','Two jobless Americans convince a prospector to travel to the mountains of Mexico with them in search of gold. But the hostile wilderness, local bandits, and greed all get in the way of their journey.',NULL,NULL,4.2329,7.955,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1154,81401,'tt1316540',NULL,'The Turin Horse','A torinói ló','movie',2011,'https://image.tmdb.org/t/p/w500/2kSElneXSKmMsGL55k0CbPGqLbu.jpg','https://image.tmdb.org/t/p/original/eMgNa5dbU34qyF0KA9DMA4TrEzn.jpg','A look at the monotonous daily struggle of a father and daughter in a windswept, desolate landscape. Over six days, their routine of eating boiled potatoes and tending a failing horse crumbles, symbolizing a slow descent into darkness, emptiness, and the end of existence.',NULL,NULL,2.1353,7.566,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1155,204,'tt0046268',NULL,'The Wages of Fear','Le Salaire de la peur','movie',1953,'https://image.tmdb.org/t/p/w500/sNOvIp4X0fmCMfgEs2ww5IyMgFm.jpg','https://image.tmdb.org/t/p/original/hTP6H7sNlWXdGxAciXQSjNJ1ob7.jpg','In a run-down South American town, four men are paid to drive trucks loaded with nitroglycerin into the jungle through to the oil field. Friendships are tested and rivalries develop as they embark upon the perilous journey.',NULL,NULL,3.9623,8.001,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1156,516981,'tt7775536',NULL,'The Wolf House','The Wolf House','movie',NULL,NULL,NULL,'A whimsical house goes up for sale. Who will buy it? And who created it?',NULL,NULL,0.0809,0.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1157,18774,'tt0057578',NULL,'This Sporting Life','This Sporting Life','movie',1963,'https://image.tmdb.org/t/p/w500/lOxaN1ziYdOJgAQouWO1pGEBU7H.jpg','https://image.tmdb.org/t/p/original/fuVL383GZ1uA8Jltt5ckMHbZU9q.jpg','In early 1960s Northern England, Frank Machin is mean, tough and ambitious enough to become an immediate star in the rugby league team run by local employer Weaver.',NULL,NULL,1.4575,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1158,1480,'tt0052311',NULL,'Touch of Evil','Touch of Evil','movie',1958,'https://image.tmdb.org/t/p/w500/1pvRgmfBaoMczIJBOi9gCOZ4FMC.jpg','https://image.tmdb.org/t/p/original/ousBoWTm1CltjAGSYOELYP0jFFC.jpg','A border-town bombing draws Mexican investigator Miguel Vargas into a corruption-ridden police investigation led by crooked captain Hank Quinlan, setting off a deadly struggle over power, justice, and truth.',NULL,NULL,3.3917,7.741,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1159,23160,'tt0249241',NULL,'Werckmeister Harmonies','Werckmeister harmóniák','movie',2001,'https://image.tmdb.org/t/p/w500/ix3pquGqTkCW86UbVTdRcrhGEFm.jpg','https://image.tmdb.org/t/p/original/pyCUjcPHZrMY125lWpWAxEexe7C.jpg','A naive young man witnesses an escalation of violence in his small hometown following the arrival of a mysterious circus attraction.',NULL,NULL,2.1856,7.8,0,13.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1160,419704,'tt2935510',NULL,'Ad Astra','Ad Astra','movie',2019,'https://image.tmdb.org/t/p/w500/xBHvZcjRiWyobQ9kxBhO6B2dtRI.jpg','https://image.tmdb.org/t/p/original/AeDS2MKGFy6QcjgWbJBde0Ga6Hd.jpg','The near future, a time when both hope and hardships drive humanity to look to the stars and beyond. While a mysterious phenomenon menaces to destroy life on planet Earth, astronaut Roy McBride undertakes a mission across the immensity of space and its many perils to uncover the truth about a lost expedition that decades before boldly faced emptiness and silence in search of the unknown.',NULL,NULL,3.126,6.133,0,9.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1161,842924,'tt12908150',NULL,'The Life of Chuck','The Life of Chuck','movie',2025,'https://image.tmdb.org/t/p/w500/oumprkO9bThExP8NwxBIBnvBu2v.jpg','https://image.tmdb.org/t/p/original/1SgD8XMa6dDSBKbPU4TDe2cmfGK.jpg','In this extraordinary story of an ordinary man, Charles ''Chuck'' Krantz experiences the wonder of love, the heartbreak of loss, and the multitudes contained in all of us.',NULL,NULL,5.2302,7.295,0,6.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1162,586810,'tt26915336',NULL,'Mars Express','Mars Express','movie',2023,'https://image.tmdb.org/t/p/w500/g8rUn0khoYB3G4gPPGTF1Xv9Olu.jpg','https://image.tmdb.org/t/p/original/yIOw17XdfsoCaydtrkzlZBCcHk6.jpg','In 2200, private detective Aline Ruby and her android partner Carlos Rivera are hired by a wealthy businessman to track down a notorious hacker. On Mars, they descend deep into the underbelly of the planet''s capital city where they uncover a darker story of brain farms, political corruption, and a missing girl who holds a secret about the robots that threatens to change the face of the universe.',NULL,NULL,1.7833,7.46,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1163,70981,'tt1446714',NULL,'Prometheus','Prometheus','movie',2012,'https://image.tmdb.org/t/p/w500/qsYQflQhOuhDpQ0W2aOcwqgDAeI.jpg','https://image.tmdb.org/t/p/original/sM42bpH73dmf3kJrE8xr4kztYqR.jpg','A team of explorers discover a clue to the origins of mankind on Earth, leading them on a journey to the darkest corners of the universe. There, they must fight a terrifying battle to save the future of the human race.',NULL,NULL,10.725,6.6,0,9.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1164,2103,'tt0307479',NULL,'Solaris','Solaris','movie',2002,'https://image.tmdb.org/t/p/w500/drdrB1hEZmzFlK1xtW5HMxK3LUJ.jpg','https://image.tmdb.org/t/p/original/avjG5EPgWXyLvsUId6hEn0iqT4A.jpg','A troubled psychologist is sent to investigate the crew of an isolated research station orbiting a bizarre planet.',NULL,NULL,2.3781,5.952,0,8.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1165,9659,'tt0079501',NULL,'Mad Max','Mad Max','movie',1979,'https://image.tmdb.org/t/p/w500/5LrI4GiCSrChgkdskVZiwv643Kg.jpg','https://image.tmdb.org/t/p/original/2eYiXlynI2mSuYJPUkHupJm2dJp.jpg','In the ravaged near-future, a savage motorcycle gang rules the road. Terrorizing innocent civilians while tearing up the streets, the ruthless gang laughs in the face of a police force hell-bent on stopping them.',NULL,NULL,8.7989,6.682,0,10.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1166,426249,'tt4669296',NULL,'Lords of Chaos','Lords of Chaos','movie',2018,'https://image.tmdb.org/t/p/w500/5jDShbwEsILXa2AAmAbOLxyNwyq.jpg','https://image.tmdb.org/t/p/original/oaDTXNmyqeNEEBat3h4ijiu27jv.jpg','A teenager''s quest to launch Norwegian Black Metal in Oslo in the 1990s results in a very violent outcome.',NULL,NULL,1.3689,6.768,0,1.23566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1167,310135,'tt3672742',NULL,'Turbo Kid','Turbo Kid','movie',2015,'https://image.tmdb.org/t/p/w500/ArUqADkwycYtNVuXSoSXVrdJ8iJ.jpg','https://image.tmdb.org/t/p/original/21fNILK2g4tzsY6IHWXc7Plujne.jpg','In a post-apocalyptic wasteland, an orphaned teen must battle a ruthless warlord to save the girl of his dreams.',NULL,NULL,1.986,6.493,0,11.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1168,1948,'tt0479884',NULL,'Crank','Crank','movie',2006,'https://image.tmdb.org/t/p/w500/rsKmhnvzJezjwC1Ud2Hh37oNpdQ.jpg','https://image.tmdb.org/t/p/original/8JPz1636hMcaADngF4H4KOxXfp1.jpg','Chev Chelios, a hit man wanting to go straight, lets his latest target slip away. Then he awakes the next morning to a phone call that informs him he has been poisoned and has only an hour to live unless he keeps adrenaline coursing through his body while he searches for an antidote.',NULL,NULL,5.768,6.663,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1169,12508,'tt0202470',NULL,'Rock Star','Rock Star','movie',2001,'https://image.tmdb.org/t/p/w500/8pRMweo9WA1MvYOLsD2hWyFpZ1V.jpg','https://image.tmdb.org/t/p/original/oImvpyBfpXQgFevXWrh1adswdOn.jpg','A wannabe rock star who fronts a Pennsylvania-based tribute band is devastated when his bandmates kick him out of the group he founded. Things begin to look up for Izzy when he is asked to join Steel Dragon, the heavy metal rockers he had been imitating for so long. This film is loosely based on the true story of the band Judas Priest.',NULL,NULL,3.9256,6.721,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1170,11031,'tt0088258',NULL,'This Is Spinal Tap','This Is Spinal Tap','movie',1984,'https://image.tmdb.org/t/p/w500/b3lllDltoBws5uKZzBYVSjpjjJx.jpg','https://image.tmdb.org/t/p/original/a3FaHEGActk76BeCBingyOvEqnm.jpg','"This Is Spinal Tap" shines a light on the self-contained universe of a metal band struggling to get back on the charts, including everything from its complicated history of ups and downs, gold albums, name changes and undersold concert dates, along with the full host of requisite groupies, promoters, hangers-on and historians, sessions, release events and those special behind-the-scenes moments that keep it all real.',NULL,NULL,4.7407,7.407,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1171,679,'tt0090605',NULL,'Aliens','Aliens','movie',1986,'https://image.tmdb.org/t/p/w500/r1x5JGpyqZU8PYhbs4UcrO1Xb6x.jpg','https://image.tmdb.org/t/p/original/4kix6fAblJIH6eMs0Ku2loyZJXK.jpg','Ripley, the sole survivor of the Nostromo''s deadly encounter with the monstrous Alien, returns to Earth after drifting through space in hypersleep for 57 years. Although her story is initially met with skepticism, she agrees to accompany a team of Colonial Marines back to LV-426.',NULL,NULL,11.6272,7.965,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1172,460885,'tt6998518',NULL,'Mandy','Mandy','movie',2018,'https://image.tmdb.org/t/p/w500/m0yf7J7HsKeK6E81SMRcX8vx6mH.jpg','https://image.tmdb.org/t/p/original/tNa19CK0CQZl5rxZ35QRdKAT2s0.jpg','The Shadow Mountains, 1983. Red and Mandy lead a loving and peaceful existence; but when their pine-scented haven is savagely destroyed, Red is catapulted into a phantasmagoric journey filled with bloody vengeance and laced with fire.',NULL,NULL,3.0272,6.206,0,2.24515384615384618e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1173,157834,'tt2333804',NULL,'The Zero Theorem','The Zero Theorem','movie',2013,'https://image.tmdb.org/t/p/w500/nlm2r6ER5J6x046ne61CuOgWAQX.jpg','https://image.tmdb.org/t/p/original/6RcWkHz1LT8wJBlAwYRoq2nOzG6.jpg','A computer hacker''s goal to discover the reason for human existence continually finds his work interrupted thanks to the Management; this time, they send a teenager and lusty love interest to distract him.',NULL,NULL,3.7458,6.086,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1174,36724,'tt0094980',NULL,'The Decline of Western Civilization Part II: The Metal Years','The Decline of Western Civilization Part II: The Metal Years','movie',1988,'https://image.tmdb.org/t/p/w500/4XoeABOgfPzYIzv2UoGKAdZbbR7.jpg','https://image.tmdb.org/t/p/original/AlpslskDPx4RuAXdRcdRakzRn7U.jpg','An exploration of the heavy metal scene in Los Angeles, with particular emphasis on glam metal. It features concert footage and interviews of legendary heavy metal and hard rock bands and artists such as Aerosmith, Alice Cooper, Kiss, Megadeth, Motörhead, Ozzy Osbourne and W.A.S.P..',NULL,NULL,1.1421,6.8,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1175,12569,'tt1225822',NULL,'Extract','Extract','movie',2009,'https://image.tmdb.org/t/p/w500/cjen0vxjybwItQPH3NNCJuME2MY.jpg','https://image.tmdb.org/t/p/original/vSUz6gjbK0x9LfaDxZcIKk84Dxs.jpg','The owner of a factory that produces flavor extracts, Joel Reynold seems to have it all, but really doesn''t. What''s missing is sexual attention from his wife, Suzie. Joel hatches a convoluted plan to get Suzie to cheat on him, thereby clearing the way for Joel to have an affair with Cindy, an employee. But what Joel doesn''t know is that Cindy is a sociopathic con artist, and a freak workplace accident clears the way for her to ruin Joel forever.',NULL,NULL,2.1781,5.85,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1176,17654,'tt1136608',NULL,'District 9','District 9','movie',2009,'https://image.tmdb.org/t/p/w500/tuGlQkqLxnodDSk6mp5c2wvxUEd.jpg','https://image.tmdb.org/t/p/original/jhM3wgWUrrOkz9r4xwV5cV5RhI4.jpg','Thirty years ago, aliens arrive on Earth. Not to conquer or give aid, but to find refuge from their dying planet. Separated from humans in a South African area called District 9, the aliens are managed by Multi-National United, which is unconcerned with the aliens'' welfare but will do anything to master their advanced technology. When a company field agent contracts a mysterious virus that begins to alter his DNA, there is only one place he can hide: District 9.',NULL,NULL,8.6049,7.474,0,19.619,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1177,339403,'tt3890160',NULL,'Baby Driver','Baby Driver','movie',2017,'https://image.tmdb.org/t/p/w500/tYzFuYXmT8LOYASlFCkaPiAFAl0.jpg','https://image.tmdb.org/t/p/original/yir5430WblZSZuIMd9C6pIZerfA.jpg','After being coerced into working for a crime boss, a young getaway driver finds himself taking part in a heist doomed to fail.',NULL,NULL,10.9803,7.444,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1178,21589,'tt0116488',NULL,'Hard Core Logo','Hard Core Logo','movie',1996,'https://image.tmdb.org/t/p/w500/xE6BqwOxHjjFniKXsW1Zg4F04RC.jpg','https://image.tmdb.org/t/p/original/4EcUnkCoGcD0SOeyUeKt3hKMj3I.jpg','Bruce Macdonald follows punk bank Hard Core Logo on a harrowing last-gasp reunion tour throughout Western Canada. As magnetic lead-singer Joe Dick holds the whole magilla together through sheer force of will, all the tensions and pitfalls of life on the road come bubbling to the surface.',NULL,NULL,1.4676,6.6,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1179,1728819,NULL,NULL,'RADIOHEAD: A Job That Slowly Kills You','RADIOHEAD: A Job That Slowly Kills You','movie',NULL,'https://image.tmdb.org/t/p/w500/7paHvYEbhzq0HQTWY1coKc4AqvM.jpg',NULL,'Biopic documenting the career of Radiohead that focuses on the psychological affects of fame at a young age and the disconnect between what an artist gives and a consumer takes.',NULL,NULL,0.0904,7.0,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1180,24746,'tt0118736',NULL,'Six-String Samurai','Six-String Samurai','movie',1998,'https://image.tmdb.org/t/p/w500/4Lo0pT1gnDAL4hTVMYLwpVWcqR1.jpg','https://image.tmdb.org/t/p/original/bMPIc12GOP0PlOKNVwLmigEi3Dz.jpg','In a post-apocalyptic world where the Russians have taken over a nuked USA and Elvis is king of Lost Vegas, Buddy is a ''50s rocker and wandering warrior rolled into one, too-cool package. Armed with his six-string in one hand and his sword in the other, Buddy is on his way to Vegas to succeed Elvis as King. Along the way, he saves an orphan who decides to tag along.',NULL,NULL,1.0045,6.265,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1181,27936,'tt1149361',NULL,'Micmacs','Micmacs à tire-larigot','movie',2009,'https://image.tmdb.org/t/p/w500/yiqooJWNDEVsp8lbdTrTBvLAk0m.jpg','https://image.tmdb.org/t/p/original/awhWLCEmA4Suxf3po9xXAGDwzZY.jpg','While standing in the doorway of the video shop where he works, Bazil is inadvertently shot in the head. Now homeless and jobless, he is taken in by a troupe of misfits who live in a giant mound of trash. There Bazil begins his quest for revenge against the people who produced the gun that shot him.',NULL,NULL,1.4868,6.643,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1182,4141,'tt0465602',NULL,'Shoot ''Em Up','Shoot ''Em Up','movie',2007,'https://image.tmdb.org/t/p/w500/hZ4p0MvSUWnCCL0IUn47UXTVPCs.jpg','https://image.tmdb.org/t/p/original/1bYY2WUsHyCl66gQAGoF40JIryW.jpg','A man named Mr. Smith delivers a woman''s baby during a shootout, and is then called upon to protect the newborn from the army of gunmen.',NULL,NULL,4.1672,6.506,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1183,13531,'tt0112950',NULL,'Empire Records','Empire Records','movie',1995,'https://image.tmdb.org/t/p/w500/qKP7hVdjAAvRvbF3GBCbzi5LzMf.jpg','https://image.tmdb.org/t/p/original/8ohWBqEn3Zh9ro0JulFKPfk0XDE.jpg','The employees of an independent music store learn about each other as they try to stop the store from being absorbed by a large chain.',NULL,NULL,6.2639,6.639,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1184,502033,'tt5363618',NULL,'Sound of Metal','Sound of Metal','movie',2020,'https://image.tmdb.org/t/p/w500/3178oOJKKPDeQ2legWQvMPpllv.jpg','https://image.tmdb.org/t/p/original/7b5R8FfGUzlxfhOkPpL3xyIeuyF.jpg','Metal drummer Ruben begins to lose his hearing. When a doctor tells him his condition will worsen, he thinks his career and life is over. His girlfriend Lou checks the former addict into a rehab for the deaf hoping it will prevent a relapse and help him adapt to his new life. After being welcomed and accepted just as he is, Ruben must choose between his new normal and the life he once knew.',NULL,NULL,4.3639,7.7,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1185,325348,'tt3072482',NULL,'Hardcore Henry','Hardcore Henry','movie',2015,'https://image.tmdb.org/t/p/w500/ik1uZyiMSxF9HqrgRKUNfMCfr3z.jpg','https://image.tmdb.org/t/p/original/agxzi8QIXWnZgLxwHck8wdjfYk7.jpg','Henry, a newly resurrected cyborg who must save his wife/creator from the clutches of a psychotic tyrant with telekinetic powers, AKAN, and his army of mercenaries. Fighting alongside Henry is Jimmy, who is Henry''s only hope to make it through the day. Hardcore Henry takes place over the course of one day, in Moscow, Russia.',NULL,NULL,3.5486,6.412,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1186,8224,'tt0134273',NULL,'8MM','8MM','movie',1999,'https://image.tmdb.org/t/p/w500/mhr9xRpjOBqlBjgDwtiOx6FsLvV.jpg','https://image.tmdb.org/t/p/original/eEP8pyCmldfbnml0SFMvPK7kE4x.jpg','A small, seemingly innocuous plastic reel of film leads surveillance specialist Tom Welles down an increasingly dark and frightening path. With the help of the streetwise Max, he relentlessly follows a bizarre trail of evidence to determine the fate of a complete stranger. As his work turns into obsession, he drifts farther and farther away from his wife, family and simple life as a small-town PI.',NULL,NULL,4.6858,6.495,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1187,530074,'tt8846416',NULL,'A Self-Induced Hallucination','A Self-Induced Hallucination','movie',2018,'https://image.tmdb.org/t/p/w500/f97ruGbsuHVPajBoHcHPUxjfXRs.jpg','https://image.tmdb.org/t/p/original/usCNN9qedHzC0wpkUbHH5TgJFWO.jpg','A documentary about the mythos and real-world effects of the internet legend, Slender Man, consisting of clips from various sources from across the internet.',NULL,NULL,1.0554,6.286,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1188,1156118,'tt28494518',NULL,'Aggro Dr1ft','Aggro Dr1ft','movie',2024,'https://image.tmdb.org/t/p/w500/yPgdBXbqeeCYFd0boZvpoSgGDnx.jpg','https://image.tmdb.org/t/p/original/A9Jau8tle2CUdR2HtAALUqSi41o.jpg','In the seedy domain of Miami’s criminal underbelly, a seasoned hitman embarks on the relentless pursuit of his next target. As shot entirely through thermal lens, he navigates a twisted world where violence and madness reign supreme. Tensions unravel, leading to a psychedelic journey that blurs the lines between predator and prey.',NULL,NULL,1.0985,6.0,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1189,8839,'tt0112642',NULL,'Casper','Casper','movie',1995,'https://image.tmdb.org/t/p/w500/2ah8fNJFZVU3vcXhU5xfAYi2eym.jpg','https://image.tmdb.org/t/p/original/sQPckU0TfSeYIlUneHfIXwzQC2f.jpg','Casper is a kind young ghost who peacefully haunts a mansion in Maine. When specialist James Harvey arrives to communicate with Casper and his fellow spirits, he brings along his teenage daughter, Kat. Casper quickly falls in love with Kat, but their budding relationship is complicated not only by his transparent state, but also by his troublemaking apparition uncles and their mischievous antics.',NULL,NULL,5.8045,6.343,0,10.815,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1190,548473,'tt5073642',NULL,'Color Out of Space','Color Out of Space','movie',2020,'https://image.tmdb.org/t/p/w500/k7rD7LzlsPS4jmE6Siah0QO4tAc.jpg','https://image.tmdb.org/t/p/original/vj2gCvD5vZDJ865izTU0J0wJBVc.jpg','The Gardner family moves to a remote farmstead in rural New England to escape the hustle of the 21st century. They are busy adapting to their new life when a meteorite crashes into their front yard, melts into the earth, and infects both the land and the properties of space-time with a strange, otherworldly colour. To their horror, the family discovers this alien force is gradually mutating every life form that it touches—including them.',NULL,NULL,3.9392,6.1,0,14.73,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1191,114982,'tt2400275',NULL,'Goodbye to Language','Adieu au langage','movie',2014,'https://image.tmdb.org/t/p/w500/dQ0qBocOIz5VgoEPQDptOXRwWEv.jpg','https://image.tmdb.org/t/p/original/bOHq7n79I3gNDI3yMGidlLadJGA.jpg','"The idea is simple / A married woman and a single man meet / They love, they argue, fists fly / A dog strays between town and country / The seasons pass / The man and woman meet again / The dog finds itself between them / The other is in one, / the one is in the other / and they are three / The former husband shatters everything / A second film begins: / the same as the first, / and yet not / From the human race we pass to metaphor / This ends in barking / and a baby''s cries / In the meantime, we will have seen people talking of the demise of the dollar, of truth in mathematics and of the death of a robin." -JLG',NULL,NULL,1.1022,5.995,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1192,667216,'tt10365998',NULL,'Infinity Pool','Infinity Pool','movie',2023,'https://image.tmdb.org/t/p/w500/cQKyNm0Nz6KWiDBQF9w4aZAmOfC.jpg','https://image.tmdb.org/t/p/original/1xhcEecvRJXQ2OAVO7l9btlrN6D.jpg','While staying at an isolated island resort, James and Em are enjoying a perfect vacation of pristine beaches, exceptional staff, and soaking up the sun. But guided by the seductive and mysterious Gabi, they venture outside the resort grounds and find themselves in a culture filled with violence, hedonism, and untold horror. A tragic accident leaves them facing a zero tolerance policy for crime: either you''ll be executed, or, if you’re rich enough to afford it, you can watch yourself die instead.',NULL,NULL,3.6646,6.063,0,11.285,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1193,13811,'tt0448011',NULL,'Knowing','Knowing','movie',2009,'https://image.tmdb.org/t/p/w500/OG0mxQt4YaNIWiz8EKJSHe9lPh.jpg','https://image.tmdb.org/t/p/original/oZqounvawm4hDxpDGDHLmVBGJBr.jpg','A teacher opens a time capsule that has been dug up at his son''s elementary school; in it are some chilling predictions -- some that have already occurred and others that are about to -- that lead him to believe his family plays a role in the events that are about to unfold.',NULL,NULL,7.5663,6.265,0,10.15,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1194,27040,'tt0036154',NULL,'Meshes of the Afternoon','Meshes of the Afternoon','movie',1943,'https://image.tmdb.org/t/p/w500/yHjEjRU81RcxKFNU5hhiPYMzlsu.jpg','https://image.tmdb.org/t/p/original/otRHDr3aMJboh9N4AMbuKKnlHYL.jpg','A woman returning home falls asleep and has vivid dreams that may or may not be happening in reality. Through repetitive images and complete mismatching of the objective view of time and space, her dark inner desires play out on-screen.',NULL,NULL,0.6829,7.6,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1195,1990,'tt0842929',NULL,'Paranoid Park','Paranoid Park','movie',2007,'https://image.tmdb.org/t/p/w500/qdxQ8vZJoZuLqU9MXYW2vnRwhan.jpg','https://image.tmdb.org/t/p/original/xRTTlWBks6IAmkehS2JjOtzdZXC.jpg','A teenage skateboarder becomes suspected of being connected with a security guard who suffered a brutal death in a skate park called "Paranoid Park".',NULL,NULL,1.5728,6.526,0,1.53566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1196,435615,'tt5918982',NULL,'Possessor','Possessor','movie',2020,'https://image.tmdb.org/t/p/w500/xC9GZeJZ3NagdkGg9nLQx0aPG6J.jpg','https://image.tmdb.org/t/p/original/owTL741kAuvJDKYnXKJCgTRGRud.jpg','Tasya Vos, an elite corporate assassin, uses brain-implant technology to take control of other people’s bodies to terminate high profile targets. As she sinks deeper into her latest assignment, Vos becomes trapped inside a mind that threatens to obliterate her.',NULL,NULL,2.9141,6.379,0,10.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1197,38410,'tt1010271',NULL,'The Poughkeepsie Tapes','The Poughkeepsie Tapes','movie',2007,'https://image.tmdb.org/t/p/w500/8ppkhu3pO3fnXr05YeE7ryKloVd.jpg','https://image.tmdb.org/t/p/original/tAi9xQKBgYJVkBTfAtZ0OHEaXfb.jpg','When hundreds of videotapes showing torture, murder and dismemberment are found in an abandoned house, they reveal a serial killer''s decade-long reign of terror and become the most disturbing collection of evidence homicide detectives have ever seen.',NULL,NULL,3.4391,6.536,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1198,912480,'tt22207786',NULL,'Red Rooms','Les Chambres rouges','movie',2023,'https://image.tmdb.org/t/p/w500/uBJvbf0g9rcsYElcwZCMYU0Vrj8.jpg','https://image.tmdb.org/t/p/original/83g3gkDw6oc2mxkyB8DSoXQZJHl.jpg','The high-profile case of serial killer Ludovic Chevalier has just gone to trial, and Kelly-Anne is obsessed. When reality blurs with her morbid fantasies, she goes down a dark path to seek the final piece of the case’s puzzle.',NULL,NULL,3.7598,7.088,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1199,48191,'tt0227408',NULL,'Rubber''s Lover','ラバーズ・ラバー','movie',1996,'https://image.tmdb.org/t/p/w500/e3gnezLmqQUfAsNIJZcPRmbPTlE.jpg','https://image.tmdb.org/t/p/original/4POvX5h1jDY95SXhPRzdvjppCSw.jpg','After the explosive demise of their last subject, scientists must look for a replacement on whom to continue their bizarre experiments with brain-altering drugs.',NULL,NULL,0.4925,6.5,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1200,1087,'tt0500092',NULL,'Serial Experiments Lain','serial experiments lain','tv',1998,'https://image.tmdb.org/t/p/w500/93M6d0pAqVQySKrp43LfBYDTvZ.jpg','https://image.tmdb.org/t/p/original/uwwB7mYqrMk8fgJfa5nvVIafuWY.jpg','Lain—driven by the abrupt suicide of a classmate—logs on to the Wired and promptly loses herself in a twisted mass of hallucinations, memories, and interconnected-psyches.',NULL,NULL,8.2663,8.225,0,1.53566666666666655e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1201,12720,'tt0312843',NULL,'Suicide Club','自殺サークル','movie',2001,'https://image.tmdb.org/t/p/w500/oMjWlKHzR9cwhf3oCUy9j57o67O.jpg','https://image.tmdb.org/t/p/original/pK8jgMF9o5SBq7grQzVnpeqib7Y.jpg','When the bizarre mass suicide of 54 high school girls throwing themselves in front of a subway train appears to instigate a string of suicides around the country, Detective Kuroda strives to find the answer, which isn''t as simple as he had hoped.',NULL,NULL,1.5105,6.5,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1202,260604,'tt0176047',NULL,'The Touch','Прикосновение','movie',1992,'https://image.tmdb.org/t/p/w500/vRSC6Rx60zmGFTMIYqlAgdPOqNc.jpg','https://image.tmdb.org/t/p/original/tLNG1uAVNv0tGf01jtdzPjBNvKg.jpg','Olga Nikolayevna kills her little son Kolya and then herself. Andrey, the most laid-back and friendly cop in Russia, gets on the case.',NULL,NULL,0.3933,5.714,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1203,37165,'tt0120382',NULL,'The Truman Show','The Truman Show','movie',1998,'https://image.tmdb.org/t/p/w500/vuza0WqY239yBXOadKlGwJsZJFE.jpg','https://image.tmdb.org/t/p/original/aCHn2TXYJfzPXQKA6r9mKPbMlUB.jpg','In a picture-perfect seaside town, an insurance salesman begins to realize that his entire existence may be staged and observed by a vast unseen audience as part of a long-running real-time reality TV show.',NULL,NULL,19.3238,8.155,0,13.1875,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1204,47386,'tt1398428',NULL,'YellowBrickRoad','YellowBrickRoad','movie',2010,'https://image.tmdb.org/t/p/w500/oZRnAPskc9fhVetTm7XaVrUxs7p.jpg','https://image.tmdb.org/t/p/original/4JiVd7xqClEKTKM9NKm2HkqfUBo.jpg','In the Fall of 1940, the entire population of Friar, New Hampshire walked together up a winding mountain trail and into the wilderness. Without warning, they left behind everything: their homes, their clothes, and their money. The only clue where they went was a single word etched into stone near the forest’s edge: YELLOWBRICKROAD.',NULL,NULL,2.6456,4.699,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1205,458723,'tt6857112',NULL,'Us','Us','movie',2019,'https://image.tmdb.org/t/p/w500/ux2dU1jQ2ACIMShzB3yP93Udpzc.jpg','https://image.tmdb.org/t/p/original/sC0b8iPUHfZdD8kseLiHw3N8gkp.jpg','Husband and wife Gabe and Adelaide Wilson take their kids to their beach house expecting to unplug and unwind with friends. But as night descends, their serenity turns to tension and chaos when some shocking visitors arrive uninvited.',NULL,NULL,5.5469,6.945,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1206,31417,'tt0053459',NULL,'Eyes Without a Face','Les Yeux sans visage','movie',1960,'https://image.tmdb.org/t/p/w500/8y7Z9Gvcq52uOlJlUWyn2epGGRd.jpg','https://image.tmdb.org/t/p/original/pZVrDhIPF30JTRSkal2Lfk7NwrI.jpg','Dr. Génessier is riddled with guilt after an accident that he caused disfigures the face of his daughter, the once beautiful Christiane, who outsiders believe is dead. Dr. Génessier, along with accomplice and laboratory assistant Louise, kidnaps young women and brings them to the Génessier mansion. After rendering his victims unconscious, Dr. Génessier removes their faces and attempts to graft them on to Christiane''s.',NULL,NULL,4.9176,7.6,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1207,103445,'tt12313914',NULL,'Ju-On: Origins','呪怨：呪いの家','tv',2020,'https://image.tmdb.org/t/p/w500/18cT0p9UbJGhKDlwcOF214SXnsZ.jpg','https://image.tmdb.org/t/p/original/b95YFESueMaNpQ9AebQZpYSvYo2.jpg','A paranormal researcher searches obsessively for a cursed home where something terrible happened to a mother and her child long ago.',NULL,NULL,3.4113,6.5,0,10.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1208,50037,'tt1534085',NULL,'Beyond the Black Rainbow','Beyond the Black Rainbow','movie',2010,'https://image.tmdb.org/t/p/w500/uhomcCTQ3lO8L6mLhkCMypsnroO.jpg','https://image.tmdb.org/t/p/original/ax9TM12FIYiEPOto4vDw5gLdGCU.jpg','In 1983, a young mute woman with psychic abilities is held captive within the Arboria Institute, a secluded futuristic facility overseen by a sinister doctor with an unraveling mind and a growing obsession with her.',NULL,NULL,1.0533,5.658,0,1.28733333333333348e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1209,1645603,'tt33296064',NULL,'Night of the Living Dead','Night of the Living Dead','movie',2026,'https://image.tmdb.org/t/p/w500/5l0klDtj2v4FMFOGGCEH23AQb30.jpg','https://image.tmdb.org/t/p/original/h1x4YiBtQEGY2dMx7k0fvlErlSn.jpg','A ragtag group barricade themselves in an old Pennsylvania farmhouse to remain safe from a horde of flesh-eating ghouls ravaging the Northeast.',NULL,NULL,121.1641,5.275,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1210,465086,'tt3612126',NULL,'The Grudge','The Grudge','movie',2019,'https://image.tmdb.org/t/p/w500/vN7JHlHOT9rHNDU27tfYqhABBj5.jpg','https://image.tmdb.org/t/p/original/nr5smF4avc77lhWHNcGLF7guXv1.jpg','After a young mother murders her family in her own house, a detective attempts to investigate the mysterious case, only to discover that the house is cursed by a vengeful ghost. Now targeted by the demonic spirits, the detective must do anything to protect herself and her family from harm.',NULL,NULL,2.4161,5.417,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1211,11324,'tt1130884',NULL,'Shutter Island','Shutter Island','movie',2010,'https://image.tmdb.org/t/p/w500/nrmXQ0zcZUL8jFLrakWc90IR8z9.jpg','https://image.tmdb.org/t/p/original/rbZvGN1A1QyZuoKzhCw8QPmf2q0.jpg','World War II soldier-turned-U.S. Marshal Teddy Daniels investigates the disappearance of a patient from a hospital for the criminally insane, but his efforts are compromised by troubling visions and a mysterious doctor.',NULL,NULL,19.2367,8.198,0,1.23533333333333317e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1212,297608,'tt3387648',NULL,'The Taking of Deborah Logan','The Taking of Deborah Logan','movie',2014,'https://image.tmdb.org/t/p/w500/77i7EBUyQKOUiZeYQ5tWDGQb0AI.jpg','https://image.tmdb.org/t/p/original/xqhTXB86dkKe4jalwUFIjiFgaYB.jpg','What starts as a poignant medical documentary about Deborah Logan''s descent into Alzheimer''s disease and her daughter''s struggles as caregiver degenerates into a maddening portrayal of dementia at its most frightening, as hair-raising events begin to plague the family and crew and an unspeakable malevolence threatens to tear the very fabric of sanity from them all.',NULL,NULL,5.559,6.565,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1213,327148,'tt16492574',NULL,'The Mandela Catalogue','The Mandela Catalogue','tv',2021,'https://image.tmdb.org/t/p/w500/px6pys6pmP7VB7yaWAqebVu23o4.jpg','https://image.tmdb.org/t/p/original/rAmYAZJJvdLpGXZL1JnuVp68ehW.jpg','In the fictional Mandela County, WI, otherworldly entities called Alternates have invaded, in order to psychologically torture their victims with the ultimate goal of assuming their identities as doppelgängers.',NULL,NULL,0.9496,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1214,11219,'tt0048750',NULL,'The Trouble with Harry','The Trouble with Harry','movie',1955,'https://image.tmdb.org/t/p/w500/uUXLq7fEG3hI46ZFMZzgHj11S6S.jpg','https://image.tmdb.org/t/p/original/i5MaRm0FsJIpXVLAvrMsMt5YQ5p.jpg','In a quiet Vermont village, a corpse creates unexpected chaos as several townspeople each believe they may be to blame.',NULL,NULL,2.2585,6.983,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1215,766475,'tt13640696',NULL,'See How They Run','See How They Run','movie',2022,'https://image.tmdb.org/t/p/w500/r3rpSAi2yukZwr9H2km0WKGODWo.jpg','https://image.tmdb.org/t/p/original/cn9GQzCaeYylEV2hymVR8bskRMJ.jpg','In the West End of 1950s London, plans for a movie version of a smash-hit play come to an abrupt halt after a pivotal member of the crew is murdered. When world-weary Inspector Stoppard and eager rookie Constable Stalker take on the case, the two find themselves thrown into a puzzling whodunit within the glamorously sordid theater underground, investigating the mysterious homicide at their own peril.',NULL,NULL,2.1783,6.34,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1216,274,'tt0102926',NULL,'The Silence of the Lambs','The Silence of the Lambs','movie',1991,'https://image.tmdb.org/t/p/w500/uS9m8OBk1A8eM9I042bx8XXpqAq.jpg','https://image.tmdb.org/t/p/original/aYcnDyLMnpKce1FOYUpZrXtgUye.jpg','Clarice Starling is a top student at the FBI''s training academy.  Jack Crawford wants Clarice to interview Dr. Hannibal Lecter, a brilliant psychiatrist who is also a violent psychopath, serving life behind bars for various acts of murder and cannibalism.  Crawford believes that Lecter may have insight into a case and that Starling, as an attractive young woman, may be just the bait to draw him out.',NULL,NULL,6.198,8.345,0,1.26966666666666654e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1217,22828,'tt0102048',NULL,'Homicide','Homicide','movie',1991,'https://image.tmdb.org/t/p/w500/1CywcTyQ2Dbh7LA0Lcf13iaC1ig.jpg','https://image.tmdb.org/t/p/original/7GoQaUpyJPL7WaDQSBMrCXemUFF.jpg','While investigating the ruthless murder of an elderly woman, a Jewish police detective unravels a bizarre conspiracy involving a Zionist organization.',NULL,NULL,1.1518,6.28,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1218,807,'tt0114369',NULL,'Se7en','Se7en','movie',1995,'https://image.tmdb.org/t/p/w500/191nKfP0ehp3uIvWqgPbFmI4lv9.jpg','https://image.tmdb.org/t/p/original/i5H7zusQGsysGQ8i6P361Vnr0n2.jpg','Two homicide detectives are on a desperate hunt for a serial killer whose crimes are based on the "seven deadly sins" in this dark and haunting film that takes viewers from the tortured remains of one victim to the next. The seasoned Det. Somerset researches each sin in an effort to get inside the killer''s mind, while his novice partner, Mills, scoffs at his efforts to unravel the case.',NULL,NULL,27.7554,8.381,0,14.416,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1219,11423,'tt0353969',NULL,'Memories of Murder','살인의 추억','movie',2003,'https://image.tmdb.org/t/p/w500/jcgUjx1QcupGzjntTVlnQ15lHqy.jpg','https://image.tmdb.org/t/p/original/6Kn6qW3an3DkPl3MahWemTzrjCt.jpg','A sadistic serial rapist and murderer of young women terrorizes a small province in 1980s South Korea. To prevent further crimes, three increasingly desperate detectives with conflicting methods race against time to unravel the violent mind of the killer in a futile effort to solve the case.',NULL,NULL,15.1428,8.062,0,13.5125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1220,5955,'tt0237572',NULL,'The Pledge','The Pledge','movie',2001,'https://image.tmdb.org/t/p/w500/9QOzFL3FPMAUNNPrNiKC3mEDxco.jpg','https://image.tmdb.org/t/p/original/o62VYsoyEUYgYMn21Thd9GHTuUE.jpg','A police chief, about to retire, pledges to help a woman find her daughter''s killer.',NULL,NULL,2.5143,6.572,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1221,4977,'tt0851578',NULL,'Paprika','パプリカ','movie',2006,'https://image.tmdb.org/t/p/w500/bLUUr474Go1DfeN1HLjE3rnZXBq.jpg','https://image.tmdb.org/t/p/original/6oXn0037WWw4fTCc3Qczof71lSp.jpg','Dr. Atsuko Chiba is a research psychologist who uses a device called the DC Mini to enter her patients'' dreams, wherein she adopts the alter-ego "Paprika". When the device is stolen, she must stop rogue elements from merging the dream and waking worlds.',NULL,NULL,6.5244,7.816,0,1.35575000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1222,5488,'tt0497137',NULL,'I''m a Cyborg, But That''s OK','싸이보그지만 괜찮아','movie',2006,'https://image.tmdb.org/t/p/w500/ehcwVb99DkRa1tgIwJsoILmMUFu.jpg','https://image.tmdb.org/t/p/original/eLgZPEG4994T2gjB1YtgQJrp8b3.jpg','Young-goon, mentally deranged and frequently electro-charging herself with a transistor radio, has been admitted into a mental institution. Firmly believing herself to be a cyborg, she refuses to consume like a human being. Il-soon is another patient, who catches the eye of Young-goon and soon becomes a close friend. Il-soon is now confronted with the biggest task: to cure Young-goon''s mental problem and have her eat real food.',NULL,NULL,2.5577,7.0,0,1.23733333333333312e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1223,180,'tt0181689',NULL,'Minority Report','Minority Report','movie',2002,'https://image.tmdb.org/t/p/w500/ccqpHq5tk5W4ymbSbuoy4uYOxFI.jpg','https://image.tmdb.org/t/p/original/PrMb3oeEluauy0q9ZO5xL33A6C.jpg','John Anderton is a top ''Precrime'' cop in the late-21st century, when technology can predict crimes before they''re committed. But Anderton becomes the quarry when another investigator targets him for a murder charge.',NULL,NULL,9.4063,7.355,0,1.03466666666666675e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1224,31011,'tt0485947',NULL,'Mr. Nobody','Mr. Nobody','movie',2009,'https://image.tmdb.org/t/p/w500/qNkIONc4Rgmzo23ph7qWp9QfVnW.jpg','https://image.tmdb.org/t/p/original/y9zcjxEilWr44c4vJbEaLTgE0Uw.jpg','Nemo Nobody leads an ordinary existence with his wife and 3 children; one day, he wakes up as a mortal centenarian in the year 2092.',NULL,NULL,5.1622,7.794,0,11.27,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1225,16664,'tt0297721',NULL,'All About Lily Chou-Chou','リリイ・シュシュのすべて','movie',2001,'https://image.tmdb.org/t/p/w500/mR2Znr5WAzL0lI0YEcBtHnqTeUB.jpg','https://image.tmdb.org/t/p/original/nZ7PeP09wioVQppxopmXHUfrAn1.jpg','Charts the troubled teenage years of students Yūichi Hasumi and Shūsuke Hoshino, exploring the shifting and complex power dynamics of their relationship against the backdrop of Yūichi''s love for the dreamy and abstract music of pop star Lily Chou-Chou.',NULL,NULL,5.0987,7.4,0,1.51000000000000014e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1226,73529,'tt1754177',NULL,'Mardock Scramble: The First Compression','マルドゥック・スクランブル 圧縮','movie',2010,'https://image.tmdb.org/t/p/w500/xdeuUQGv0nZMnztMUjzrxlG0nnN.jpg','https://image.tmdb.org/t/p/original/tHXVS60sI0jeU2RcMb3ry9aHrG1.jpg','Rune Ballot is a down-and-out teen prostitute in Mardock City. One day, she''s picked up by an ambitious casino manager named Shell who gives her everything she could want. Renewed by a false innocence, a false past, and now the false life Shell has given her, Ballot feels grateful. However, she can''t help but be curious about why he''s done so much for her, so she does some research about his past on a computer. This turns out to be a mistake which will change her life greatly. When Shell finds out what she''s done, he attempts to burn her to death by blowing up her car.',NULL,NULL,1.325,6.9,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1227,9806,'tt0317705',NULL,'The Incredibles','The Incredibles','movie',2004,'https://image.tmdb.org/t/p/w500/2LqaLgk4Z226KkgPJuiOQ58wvrm.jpg','https://image.tmdb.org/t/p/original/lxwzY9vNwjDgxWKt3zZ6zcU6rEJ.jpg','Bob Parr has given up his superhero days to log in time as an insurance adjuster and raise his three children with his formerly heroic wife in suburbia. But when he receives a mysterious assignment, it''s time to get back into costume.',NULL,NULL,17.0288,7.727,0,11.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1228,543033,'tt6241872',NULL,'Ruben Brandt, Collector','Ruben Brandt: A Gyűjtő','movie',2018,'https://image.tmdb.org/t/p/w500/wE88Mwcs90Cr3sGxEzLSgnTS7uE.jpg','https://image.tmdb.org/t/p/original/A3XTaySQAI6p18XSKCEgRbitBwB.jpg','Psychotherapist Ruben Brandt becomes the most wanted criminal in the world when he and four of his patients steal paintings from the world''s most renowned museums and art collections.',NULL,NULL,1.0124,7.169,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1229,14919,'tt0106364',NULL,'Batman: Mask of the Phantasm','Batman: Mask of the Phantasm','movie',1993,'https://image.tmdb.org/t/p/w500/hT4ehUteagUrhUOHAtmYiY7mp5l.jpg','https://image.tmdb.org/t/p/original/cMUuAgVsMWOCawXonZ4D1dSMd6h.jpg','Andrea Beaumont leaves her father to return to Gotham, rekindling an old romance with Bruce Wayne. At the same time, a mysterious figure begins to hunt down Gotham''s criminals, wrongly implicating Batman in the murders. Now on the run from the law, Batman must find and stop the culprit, while also navigating his relationship with Andrea.',NULL,NULL,4.4819,7.499,0,12.085,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1230,10843,'tt0088680',NULL,'After Hours','After Hours','movie',1985,'https://image.tmdb.org/t/p/w500/eamOBurHBu0MIxohTIVcfxmZ6Z7.jpg','https://image.tmdb.org/t/p/original/tV2KZZR5JaqTSXiNKowGqQMQtex.jpg','Desperate to escape his mind-numbing routine, uptown Manhattan office worker Paul Hackett ventures downtown for a hookup with a mystery woman.',NULL,NULL,3.7796,7.5,0,12.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1231,8592,'tt0099422',NULL,'Dick Tracy','Dick Tracy','movie',1990,'https://image.tmdb.org/t/p/w500/sjeP4bpgsUvAGE8oFcICy2GaHxw.jpg','https://image.tmdb.org/t/p/original/zW4vA16M8h8GPPmJFosTY6MUhBR.jpg','The comic strip detective finds his life vastly complicated when Breathless Mahoney makes advances towards him while he is trying to battle Big Boy Caprice''s united mob.',NULL,NULL,4.6869,6.161,0,1.30233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1232,8850,'tt0111143',NULL,'The Shadow','The Shadow','movie',1994,'https://image.tmdb.org/t/p/w500/xAbFJH3vQYZvUyzzGAtG4OLy492.jpg','https://image.tmdb.org/t/p/original/j3CMtQbRS4bBAuRuoTBpnPAaHSj.jpg','Based on the 1930s comic strip, The Shadow is put up against his archenemy Shiwan Khan, who plans to take over the world by holding a city to ransom using an atom bomb. Using his powers of invisibility and "the power to cloud men''s minds", The Shadow comes blazing to the rescue with explosive results.',NULL,NULL,2.7592,6.075,0,12.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1233,11934,'tt0110074',NULL,'The Hudsucker Proxy','The Hudsucker Proxy','movie',1994,'https://image.tmdb.org/t/p/w500/xBQBr6Q1OTivouBK66oFgy86n03.jpg','https://image.tmdb.org/t/p/original/gXo423uIRgBOsfQrrqJfVVcySif.jpg','A naive business graduate is installed as president of a manufacturing company as part of a stock scam.',NULL,NULL,2.3598,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1234,120467,'tt2278388',NULL,'The Grand Budapest Hotel','The Grand Budapest Hotel','movie',2014,'https://image.tmdb.org/t/p/w500/zOVCqKUzjFKqa1eDMcOzvXwthY4.jpg','https://image.tmdb.org/t/p/original/9udCLTxTFl28RxnK8Q05E154ZGa.jpg','The Grand Budapest Hotel tells of a legendary concierge at a famous European hotel between the wars and his friendship with a young employee who becomes his trusted protégé. The story involves the theft and recovery of a priceless Renaissance painting, the battle for an enormous family fortune and the slow and then sudden upheavals that transformed Europe during the first half of the 20th century.',NULL,NULL,11.2766,8.027,0,1.30066666666666677e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1235,12593,'tt0068612',NULL,'Fritz the Cat','Fritz the Cat','movie',1972,'https://image.tmdb.org/t/p/w500/llgCW1Y99WO7DNiX3ZOncLJBIAm.jpg','https://image.tmdb.org/t/p/original/udY0Gw8BB99jsJzARsJhctLqUZ6.jpg','In late 1960s New York City, fed up with monotonous college life and police repression, free-spirited Fritz, an impenitent seducer and unrestrained party-animal, decides to explore the world. And just like that, as he flees NYC, heading to San Francisco, Fritz embarks on an endless adventure of illumination. Immersed in a world surrounded by drugs and sex, Fritz participates in mad orgies, brings about a revolution, incites mass urban riots, and crosses paths with drug-addled Nazi bikers.',NULL,NULL,4.347,6.214,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1236,29204,'tt0082009',NULL,'American Pop','American Pop','movie',1981,'https://image.tmdb.org/t/p/w500/svrATPrggBUauEhCyhiF7K175T9.jpg','https://image.tmdb.org/t/p/original/n82OZ74V3KBDQKrSVqgVzE8nnjs.jpg','The history of American popular music runs parallel with the history of a Russian Jewish immigrant family, with each male descendant possessing different musical abilities.',NULL,NULL,1.9431,6.898,0,12.7,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1237,854,'tt0110475',NULL,'The Mask','The Mask','movie',1994,'https://image.tmdb.org/t/p/w500/jPC2eYub74zwf2tPGVtzSlBW6Oy.jpg','https://image.tmdb.org/t/p/original/bQlw59HncOXX9alFlOYKHAvSnm.jpg','Timid bank clerk Stanley Ipkiss discovers a magical mask infused with the spirit of the Norse god Loki. Donning it transforms him into an unrestrained, green-faced, cartoon-like wild man. While the mask grants him the confidence to woo a local singer, it also makes him the target of a ruthless mobster.',NULL,NULL,11.2547,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1238,14239,'tt0104009',NULL,'Cool World','Cool World','movie',1992,'https://image.tmdb.org/t/p/w500/mqzRUHNtFwmgJCmSnvq3JnX0xgZ.jpg','https://image.tmdb.org/t/p/original/uRUAwzXOU75vmO0CD1RzY0CaZ8d.jpg','While incarcerated for murder, cartoonist Jack Deebs found escape by creating Cool World, a series featuring a voluptuous femme fatale named Holli Would. But the artist becomes a prisoner of his own fantasies when Holli transports Jack into Cool World with a scheme to seduce him and bring herself to life. Hard-boiled detective Frank Harris – the only other human in Cool World – cautions Jack with the law: Noids (humans) don''t have sex with doodles (cartoons). However, flesh proves weaker than ink as Holli takes human form in Las Vegas, staring in a trans-universal chase that threatens the destruction of both worlds.',NULL,NULL,2.2643,5.675,0,1.26833333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1239,2098,'tt0103359',NULL,'Batman: The Animated Series','Batman: The Animated Series','tv',1992,'https://image.tmdb.org/t/p/w500/lBomQFW1vlm1yUYMNSbFZ45R4Ox.jpg','https://image.tmdb.org/t/p/original/4QnFxk03yAn7U2ZTL5oMCCqxlPc.jpg','Vowing to avenge the murder of his parents, Bruce Wayne devotes his life to wiping out crime in Gotham City as the masked vigilante "Batman".',NULL,NULL,27.7326,8.579,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1240,508442,'tt2948372',NULL,'Soul','Soul','movie',2020,'https://image.tmdb.org/t/p/w500/6jmppcaubzLF8wkXM36ganVISCo.jpg','https://image.tmdb.org/t/p/original/rQaHA74pevnGsxcKGaoZVGWe9TC.jpg','Joe Gardner is a middle school teacher with a love for jazz music. After a successful audition at the Half Note Club, he suddenly gets into an accident that separates his soul from his body and is transported to the You Seminar, a center in which souls develop and gain passions before being transported to a newborn child. Joe must enlist help from the other souls-in-training, like 22, a soul who has spent eons in the You Seminar, in order to get back to Earth.',NULL,NULL,15.0741,8.091,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1241,52660,'tt0101550',NULL,'Cast a Deadly Spell','Cast a Deadly Spell','movie',1991,'https://image.tmdb.org/t/p/w500/aLGaVrMBga6TyLYSGfSnPB3WkN5.jpg','https://image.tmdb.org/t/p/original/2dkxyWdrclt4QGZ7sCdgtaQdWpG.jpg','In a fantastical 1940s where magic is used by everyone, a hard-boiled detective investigates the theft of a mystical tome.',NULL,NULL,1.8798,6.056,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1242,856,'tt0096438',NULL,'Who Framed Roger Rabbit','Who Framed Roger Rabbit','movie',1988,'https://image.tmdb.org/t/p/w500/lYfRc57Kx9VgLZ48iulu0HKnM15.jpg','https://image.tmdb.org/t/p/original/udIE8Cdon9wnYmVIOFYrBPfA2Mq.jpg','Toon star Roger is worried that his wife Jessica is playing pattycake with someone else, so the studio hires detective Eddie Valiant to snoop on her. But the stakes are quickly raised when Marvin Acme is found dead and Roger is the prime suspect.',NULL,NULL,6.837,7.539,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1243,23685,'tt0166276',NULL,'Monkeybone','Monkeybone','movie',2001,'https://image.tmdb.org/t/p/w500/lgH7Wej9922C1MQv0wciAfesKH8.jpg','https://image.tmdb.org/t/p/original/ntVB3LgyvKIaw6Dk29ZuDsV3TSR.jpg','After a car crash sends repressed cartoonist Stu into a coma, he and the mischievous Monkeybone, his hilarious alter-ego, wake up in a wacked-out waystation for lost souls. When Monkeybone takes over Stu''s body and escapes to wreak havoc on the real world, Stu has to find a way to stop him before his sister pulls the plug on reality forever!',NULL,NULL,3.2389,5.2,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1244,49948,'tt0120910',NULL,'Fantasia 2000','Fantasia 2000','movie',2000,'https://image.tmdb.org/t/p/w500/5rwAtUaKEK48CPUijVfVU0IPKPZ.jpg','https://image.tmdb.org/t/p/original/n92EzFFg2cMkJiEhnMfD5sKHSH3.jpg','Blending lively music and brilliant animation, this sequel to the original ''Fantasia'' restores ''The Sorcerer''s Apprentice'' and adds seven new shorts.',NULL,NULL,3.5251,7.0,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1245,28580,'tt0037884',NULL,'The Lost Weekend','The Lost Weekend','movie',1945,'https://image.tmdb.org/t/p/w500/yL6EJxPeYIcB9TChm56lHqXKzHC.jpg','https://image.tmdb.org/t/p/original/vyINER8nv4kAJyCIq2Sr1xjOOjC.jpg','Longtime alcoholic Don Birnam has been sober for ten days and appears to be over the worst... but his craving has just become more insidious. Evading a country weekend planned by his brother and girlfriend, he begins a four-day bender that just might be his last – one way or another.',NULL,NULL,2.4216,7.627,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1246,18030,'tt0048261',NULL,'Kiss Me Deadly','Kiss Me Deadly','movie',1955,'https://image.tmdb.org/t/p/w500/z7me91nrpWLHY1mZOB2v20cK0zY.jpg','https://image.tmdb.org/t/p/original/znL0K0hPJndT7IAddNWBfAEYSRC.jpg','One evening, Hammer gives a ride to Christina, an attractive hitchhiker on a lonely country road, who has escaped from the nearby lunatic asylum. Thugs waylay them and force his car to crash. When Hammer returns to semi-consciousness, he hears Christina being tortured until she dies. Hammer, both for vengeance and in hopes that "something big" is behind it all, decides to pursue the case.',NULL,NULL,2.4545,7.219,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1247,20367,'tt0037638',NULL,'Detour','Detour','movie',1945,'https://image.tmdb.org/t/p/w500/gJb9HRAs1V4bA0VKsWpT6mhv2RT.jpg','https://image.tmdb.org/t/p/original/uGOKN4VeCsf249zypWfaAzfTxAB.jpg','The life of Al Roberts, a pianist in a New York nightclub, turns into a nightmare when he decides to hitchhike to Los Angeles to visit his girlfriend.',NULL,NULL,1.1525,7.221,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1248,11827,'tt0082509',NULL,'Heavy Metal','Heavy Metal','movie',1981,'https://image.tmdb.org/t/p/w500/atUtWrDlLzT1yeVK2EoYtvbS963.jpg','https://image.tmdb.org/t/p/original/obApq0Prmf740t0b3QoxoSxjYW1.jpg','The embodiment of ultimate evil, a glowing orb terrorizes a young girl with bizarre stories of dark fantasy, eroticism and horror.',NULL,NULL,3.9197,6.5,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1249,30593,'tt0070165',NULL,'Heavy Traffic','Heavy Traffic','movie',1973,'https://image.tmdb.org/t/p/w500/76z4KHEicnCILz5rePLyZmvcXV4.jpg','https://image.tmdb.org/t/p/original/ryJkiGj5M9R6401MvqfFjFUEC90.jpg','A white dropout struggles to become a cartoonist and filmmaker, drawing inspiration from the harsh, gritty world around him. Still sharing his rundown apartment with his middle-aged parents, an oafish slob of an Italian father and a ditzy nutcase of a Jewish mother, he''s ridiculed and looked down upon by his friends, hypocrites who run with violent gangs and the Italian Mafia, and a shallow Black girl who makes her living downtown with the pimps and pushers. The cartoonist gets a chance to pitch a film idea to a movie mogul, but the story proves too outrageous: a far-future Earth, depleted by war and pollution, where a mutant antihero challenges and kills God.',NULL,NULL,1.6126,6.5,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1250,10720,'tt0309530',NULL,'Down with Love','Down with Love','movie',2003,'https://image.tmdb.org/t/p/w500/74lG2SGDJdyiS8hB4kkFcRIviSi.jpg','https://image.tmdb.org/t/p/original/gncvmif7zzVOpMNxnpAOPfSXgUq.jpg','In 1962 New York City, love blossoms between a playboy journalist and a feminist advice author.',NULL,NULL,2.5009,6.114,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1251,8649,'tt0163988',NULL,'Bringing Out the Dead','Bringing Out the Dead','movie',1999,'https://image.tmdb.org/t/p/w500/gE2Q8mL0m0EA6HakRyc92uzSPJn.jpg','https://image.tmdb.org/t/p/original/aCBbGxcbWgUJxmIiv5JDC7p5vmN.jpg','Once called "Father Frank" for his efforts to rescue lives, Frank Pierce sees the ghosts of those he failed to save around every turn. He has tried everything he can to get fired, calling in sick, delaying taking calls where he might have to face one more victim he couldn''t help, yet cannot quit the job on his own.',NULL,NULL,3.5054,6.604,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1252,9662,'tt0286244',NULL,'The Triplets of Belleville','Les Triplettes de Belleville','movie',2003,'https://image.tmdb.org/t/p/w500/enw6C4fDw88g0nOQgIJXjgH3NHi.jpg','https://image.tmdb.org/t/p/original/9ZIOZcYY0NLKVLg6Pwxr0GwEJyV.jpg','When her grandson is kidnapped during the Tour de France, Madame Souza and her beloved pooch Bruno team up with the Belleville Sisters—an aged song-and-dance team from the days of Fred Astaire—to rescue him.',NULL,NULL,2.2502,7.393,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1253,25468,'tt0082783',NULL,'My Dinner with Andre','My Dinner with Andre','movie',1981,'https://image.tmdb.org/t/p/w500/nJAn4vkJEX5G3Bsms8UElSTVLlL.jpg','https://image.tmdb.org/t/p/original/r3zwnGMmRb7LaDNQluHVXAkZNoY.jpg','Two old friends meet for dinner; as one tells anecdotes detailing his experiences, the other notices their differing worldviews.',NULL,NULL,3.2536,7.5,0,11.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1254,262,'tt0085794',NULL,'The King of Comedy','The King of Comedy','movie',1982,'https://image.tmdb.org/t/p/w500/m24EbHxT9NGYEkOlu29YcLOgjgK.jpg','https://image.tmdb.org/t/p/original/7Mh1DM4kCMbN93C2MlUavYbH5YM.jpg','Aspiring comic Rupert Pupkin attempts to achieve success in show business by stalking his idol, a late night talk-show host who craves his own privacy.',NULL,NULL,3.3842,7.778,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1255,976,'tt0051036',NULL,'Sweet Smell of Success','Sweet Smell of Success','movie',1957,'https://image.tmdb.org/t/p/w500/akzvV8JasNrgEl5iAP9K6zPHGJe.jpg','https://image.tmdb.org/t/p/original/6L1Co3uRWuoaqDxpWvGDvgXms7T.jpg','New York City newspaper writer J.J. Hunsecker holds considerable sway over public opinion with his Broadway column, but one thing that he can''t control is his younger sister, Susan, who is in a relationship with aspiring jazz guitarist Steve Dallas. Hunsecker strongly disapproves of the romance and recruits publicist Sidney Falco to find a way to split the couple, no matter how ruthless the method.',NULL,NULL,2.164,7.6,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1256,5236,'tt0373469',NULL,'Kiss Kiss Bang Bang','Kiss Kiss Bang Bang','movie',2005,'https://image.tmdb.org/t/p/w500/aWfjIkpENFX6Uw82pET7EQ6jnrd.jpg','https://image.tmdb.org/t/p/original/kKdBNPXfjENj3wG5qtiCrZ2wflp.jpg','A petty thief posing as an actor is brought to Los Angeles for an unlikely audition and finds himself in the middle of a murder investigation along with his high school dream girl and a detective who''s been training him for his upcoming role...',NULL,NULL,6.4172,7.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1257,59387,'tt0289408',NULL,'The Powerpuff Girls Movie','The Powerpuff Girls Movie','movie',2002,'https://image.tmdb.org/t/p/w500/yAFalW8UtdJg1z1gPjXx8C1sXZq.jpg','https://image.tmdb.org/t/p/original/9JYhHvfdLC0rUI1AtXyw6l4bUpV.jpg','After destroying the city of Townsville in a game of tag, a trio of superpowered little girls must redeem themselves by stopping a vengeful monkey''s plot for world domination.',NULL,NULL,3.2431,6.79,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1258,17058,'tt0038057',NULL,'Scarlet Street','Scarlet Street','movie',1945,'https://image.tmdb.org/t/p/w500/eGEDor1BWSQGaLtOntPHUSqNzRC.jpg','https://image.tmdb.org/t/p/original/g0phljbAcccz7bkSZpFEPVLuIRP.jpg','Cashier and part-time starving artist Christopher Cross is absolutely smitten with the beautiful Kitty March. Kitty plays along, but she''s really only interested in Johnny, a two-bit crook. When Kitty and Johnny find out that art dealers are interested in Chris''s work, they con him into letting Kitty take credit for the paintings. Cross allows it because he is in love with Kitty, but his love will only let her get away with so much.',NULL,NULL,1.7059,7.603,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1259,3767,'tt0038559',NULL,'Gilda','Gilda','movie',1946,'https://image.tmdb.org/t/p/w500/46eKPjoWEyNBAQKDoXEcDFBcaUw.jpg','https://image.tmdb.org/t/p/original/2oQ9hnAYsoZH61PnjSkuX4Uvd2d.jpg','A gambler discovers an old flame while in Argentina, but she''s married to his new boss.',NULL,NULL,3.4014,7.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1260,607,'tt0175058',NULL,'The Powerpuff Girls','The Powerpuff Girls','tv',1998,'https://image.tmdb.org/t/p/w500/468mmhMd21pY4Yx0S0woqeEcxtL.jpg','https://image.tmdb.org/t/p/original/gnK2nptRXra4RnKgGqAWFSqP5aG.jpg','The Powerpuff Girls is a animated television series about Blossom, Bubbles, and Buttercup, three kindergarten-aged girls with superpowers, as well as their "father", the brainy scientist Professor Utonium, who all live in the fictional city of Townsville, USA. The girls are frequently called upon by the town''s childlike and naive mayor to help fight nearby criminals using their powers.',NULL,NULL,32.8721,7.5,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1261,916224,'tt16428256',NULL,'Suzume','すずめの戸締まり','movie',2022,'https://image.tmdb.org/t/p/w500/yStW1TXF5s7Tbtu9KjIZEaWl6HL.jpg','https://image.tmdb.org/t/p/original/4tdV5AeojEdbvn6VpeQrbuDlmzs.jpg','Suzume, 17, lost her mother as a little girl. On her way to school, she meets a mysterious young man. But her curiosity unleashes a calamity that endangers the entire population of Japan, and so Suzume embarks on a journey to set things right.',NULL,NULL,8.683,7.889,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1262,11654,'tt0085701',NULL,'The Hunger','The Hunger','movie',1983,'https://image.tmdb.org/t/p/w500/lFTDtRtK8J55A1LTpwigV7QGQg7.jpg','https://image.tmdb.org/t/p/original/qw9p7gBroQt99fjG0cwtLHohQR9.jpg','Five-thousand-year-old vampire Miriam promises her lovers the gift of eternal life. When John, her cellist companion for centuries, discovers that he has suddenly begun growing old, he attempts to seek out the help of Dr. Sarah Roberts, a researcher on the mechanisms of aging.',NULL,NULL,2.7222,6.65,0,13.1675,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1263,79707,'tt1839494',NULL,'Children Who Chase Lost Voices','星を追う子ども','movie',2011,'https://image.tmdb.org/t/p/w500/8RE7Zz9oTzOeMcahqm74AWkOVpV.jpg','https://image.tmdb.org/t/p/original/gB8eFFUw6UA97A7TzrNVrc3D08o.jpg','The film centers on Asuna, a young girl who spends her solitary days listening to the mysterious music emanating from the crystal radio she received from her late father as a memento. One day while walking home she is attacked by a fearsome monster and saved by a mysterious boy named Shun. However, Shun disappears and Asuna embarks on a journey of adventure to the land of Agartha with her teacher Mr. Morisaki to meet a Shun again. Through her journey she comes to know the cruelty and beauty of the world, as well as loss.',NULL,NULL,2.8352,7.255,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1264,1391,'tt0245574',NULL,'Y Tu Mamá También','Y tu mamá también','movie',2001,'https://image.tmdb.org/t/p/w500/aj3rqjab8jfc2fWmcS3H3c5qbur.jpg','https://image.tmdb.org/t/p/original/7aW9IZjpsoTXYEARlnOvTtl6EBr.jpg','In Mexico, two teenage boys and an attractive older woman embark on a road trip and learn a thing or two about life, friendship, sex, and each other.',NULL,NULL,6.9229,7.43,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1265,113,'tt0374546',NULL,'Spring, Summer, Fall, Winter... and Spring','봄 여름 가을 겨울 그리고 봄','movie',2003,'https://image.tmdb.org/t/p/w500/6SQQ5REuAz7k0FMQ9mSCT40T2LN.jpg','https://image.tmdb.org/t/p/original/dgjR7X6WjgjuwJ02idEOxvMyFjP.jpg','An isolated lake, where an old monk lives in a small floating temple. The monk has a young boy living with him, learning to become a monk. We watch as seasons and years pass by.',NULL,NULL,3.4437,7.797,0,1.2036666666666667e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1266,12516,'tt0100998',NULL,'Dreams','夢','movie',1990,'https://image.tmdb.org/t/p/w500/ua17wrOrUjyqxuYmnUrmOVBMf4G.jpg','https://image.tmdb.org/t/p/original/g2Y4A9qgkHhecPBnYMaAIzTlmcN.jpg','Eight visually rich vignettes drawn from Kurosawa’s own dreams—fox weddings and vanished orchards, a soldier’s ghosts, a walk through Van Gogh’s canvases, nuclear nightmares, and a water-mill utopia—meditate on childhood, art, mortality, and humanity’s uneasy bond with nature.',NULL,NULL,2.9267,7.75,0,13.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1267,12159,'tt0120889',NULL,'What Dreams May Come','What Dreams May Come','movie',1998,'https://image.tmdb.org/t/p/w500/78wCdphUzeb528wLZw2W0fn7yGB.jpg','https://image.tmdb.org/t/p/original/586n41CjDveXtwmQgP41YtyHKUV.jpg','Chris Nielsen dies to find himself in a heaven more amazing than he could have ever dreamed of. There is one thing missing: his wife. After he died, his wife Annie killed herself and went to hell. Chris decides to risk eternity in Hades for the small chance that he will be able to bring her back to heaven.',NULL,NULL,4.7011,7.239,0,15.075,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1268,42994,'tt0113799',NULL,'Memories','MEMORIES','movie',1995,'https://image.tmdb.org/t/p/w500/e0HIBRiKS5dWmXkxWvEh6JQZcc2.jpg','https://image.tmdb.org/t/p/original/hNf6J498veQVdq5FhHmL08ardwf.jpg','Three back-to-back anime films by three different directors make up this sci-fi trilogy three years in the making.',NULL,NULL,3.235,7.49,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1269,337703,'tt3666024',NULL,'The Red Turtle','La tortue rouge','movie',2016,'https://image.tmdb.org/t/p/w500/wOBU3SLjQ9358Km9YWYasPZyebp.jpg','https://image.tmdb.org/t/p/original/dotEMpAXmAp6lAYulMVK4lqKFiX.jpg','The dialogue-less film follows the major life stages of a castaway on a deserted tropical island populated by turtles, crabs and birds.',NULL,NULL,2.4657,7.431,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1270,256274,'tt2870612',NULL,'As Above, So Below','As Above, So Below','movie',2014,'https://image.tmdb.org/t/p/w500/oJZSajKLJkoTOzSZQN2ZwRnPwHZ.jpg','https://image.tmdb.org/t/p/original/w2IVckABEbAZOhuuLcQRHdyI6uk.jpg','When a team of explorers venture into the catacombs that lie beneath the streets of Paris, they uncover the dark secret that lies within this city of the dead.',NULL,NULL,9.0103,6.748,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1271,508642,'tt8119752',NULL,'Gonjiam: Haunted Asylum','곤지암','movie',2018,'https://image.tmdb.org/t/p/w500/fNqlsmu2tiI1bXcpU31yjHPkiJz.jpg','https://image.tmdb.org/t/p/original/x1j5VVU4ypEx1hM0PDYGwCJvwtS.jpg','The crew of a horror web series travels to an abandoned asylum for a live broadcast, but they encounter much more than expected as they move deeper inside the nightmarish old building.',NULL,NULL,8.5302,7.276,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1272,683020,'tt11330188',NULL,'9 Days Awake','9 Tage wach','movie',2020,'https://image.tmdb.org/t/p/w500/tMCH3MVjwiGdSu3IyO0Jao3K4dM.jpg','https://image.tmdb.org/t/p/original/dWBYkUi01X695vDiukFViwbP5wu.jpg','“9 Days Awake”, the film adaptation of the eponymous novel by Eric Stehfest. Jannik Schümann plays Eric, a junkie who lives to party. He is addicted to the one drug that makes him feel invincible- "like Jesus and the terminator at the same time." When he is accepted to an acting school in Berlin, he tries to reconnect with his great love Anja (Peri Baumeister), change his life, and strive to be better. But numerous conflicts and issues follow him, leaving him to retreat back to his old ways as other situations escalate.',NULL,NULL,0.3552,6.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1273,124396,'tt14642342',NULL,'Sonny Boy','Sonny Boy','tv',2021,'https://image.tmdb.org/t/p/w500/5R1UmoGInl3mHixVVngApV1Ap3T.jpg','https://image.tmdb.org/t/p/original/rgmBS8zkk6RrGUOdWqzZs8hjZer.jpg','On August 16, midway through a seemingly endless summer vacation, middle school third-year student Nagara, transfer student Nozomi, classmates Mizuho, Asakaze and their entire class are suddenly transported from their tranquil lives to a school adrift in an alternate dimension. They must survive with the super powers that have awakened within them.',NULL,NULL,10.0645,7.295,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1274,18197,'tt0112040',NULL,'The Langoliers','The Langoliers','tv',1995,'https://image.tmdb.org/t/p/w500/xcySnh6hHc98G94dF8sXNJuD0Rp.jpg','https://image.tmdb.org/t/p/original/AeYiW8dRyZbNElQmJ8I4lgTF1O4.jpg','A jet leaves on a red-eye flight from Los Angeles to Boston. But early in the flight, ten passengers awaken to a startling realization: All of the other passengers have vanished.',NULL,NULL,4.6023,6.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1275,1408208,'tt35222590',NULL,'Exit 8','８番出口','movie',2025,'https://image.tmdb.org/t/p/w500/nQXYTvm6AY4WmtcPskroqC7Skh.jpg','https://image.tmdb.org/t/p/original/3cVrg7tzSf5AgEecYWDOSAzXAeX.jpg','A man trapped in an endless sterile subway passageway sets out to find Exit 8. The rules of his quest are simple: do not overlook anything out of the ordinary. If you discover an anomaly, turn back immediately. If you don’t, carry on. Then leave from Exit 8. But even a single oversight will send him back to the beginning. Will he ever reach his goal and escape this infinite corridor?',NULL,NULL,17.9915,7.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1276,43933,'tt1470827',NULL,'Monsters','Monsters','movie',2010,'https://image.tmdb.org/t/p/w500/qpJyTxR33KG9qFmXoCD5AUTToPl.jpg','https://image.tmdb.org/t/p/original/imiBIsvNU3TbMB3sbqKanKODS33.jpg','Six years ago NASA discovered the possibility of alien life within our solar system. A probe was launched to collect samples, but crashed upon re-entry over Central America. Soon after, new life forms began to appear and half of Mexico was quarantined as an infected zone. Today, the American and Mexican military still struggle to contain "the creatures," while a journalist agrees to escort a shaken tourist through the infected zone in Mexico to the safety of the U.S. border.',NULL,NULL,2.2586,6.187,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1277,755898,'tt13186306',NULL,'War of the Worlds','War of the Worlds','movie',2025,'https://image.tmdb.org/t/p/w500/yvirUYrva23IudARHn3mMGVxWqM.jpg','https://image.tmdb.org/t/p/original/iZLqwEwUViJdSkGVjePGhxYzbDb.jpg','Will Radford is a top analyst for Homeland Security who tracks potential threats through a mass surveillance program, until one day an attack by an unknown entity leads him to question whether the government is hiding something from him... and from the rest of the world.',NULL,NULL,63.4211,4.105,0,1.42399999999999984e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1278,223895,'tt3187076',NULL,'Class Enemy','Razredni sovražnik','movie',2013,'https://image.tmdb.org/t/p/w500/3N76HlJc6QtPkMakGyDtVBFoaQe.jpg','https://image.tmdb.org/t/p/original/9mOlshHISZdjUcVoCVgk5FsFb3H.jpg','Relations between the students and the new teacher of German are extremely tense. When one female student commits suicide, her schoolmates blame the teacher for her death. An awareness that things are not quite so black and white comes too late.',NULL,NULL,0.8078,6.724,0,1.55233333333333316e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1279,7191,'tt1060277',NULL,'Cloverfield','Cloverfield','movie',2008,'https://image.tmdb.org/t/p/w500/qIegUGJqyMMCRjkKV1s7A9MqdJ8.jpg','https://image.tmdb.org/t/p/original/6ms6RdNcQUAnjBY26aM85xC2wV0.jpg','Five young New Yorkers throw their friend a going-away party the night that a monster the size of a skyscraper descends upon the city. Told from the point of view of their video camera, the film is a document of their attempt to survive the most surreal, horrifying event of their lives.',NULL,NULL,8.3374,6.72,0,1.31900000000000012e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1280,698232,'tt4698852',NULL,'Under the Skin','Sob a Pele','movie',2013,'https://image.tmdb.org/t/p/w500/kX41SU4XFBbeXvVzEb0vbzpkGgO.jpg',NULL,'Man and Woman are reunited after a long time. Sorrow and desire cannot break the silence. But that''s okay: when words don''t come, it''s the body that speaks.',NULL,NULL,0.3447,6.417,0,1.53766666666666651e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1281,4256,'tt0306047',NULL,'Scary Movie 3','Scary Movie 3','movie',2003,'https://image.tmdb.org/t/p/w500/8dLsax5KSwlCY5uWXETKjud5k6U.jpg','https://image.tmdb.org/t/p/original/nF74HKjNe7X54XMcIc7ulK5InxR.jpg','News anchorwoman Cindy Campbell has to investigate mysterious crop circles and killing video tapes, and help the President stop an alien invasion in the process.',NULL,NULL,8.8482,5.978,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1282,333371,'tt1179933',NULL,'10 Cloverfield Lane','10 Cloverfield Lane','movie',2016,'https://image.tmdb.org/t/p/w500/q8A39vcBDruhvoDTJd6L8a4lnTi.jpg','https://image.tmdb.org/t/p/original/dMERTVrObB7TkRVIFmcndR2sZFH.jpg','After a catastrophic car crash, a young woman wakes up in a survivalist''s underground bunker, where he claims to have saved her from an apocalyptic attack that has left the outside world uninhabitable.',NULL,NULL,5.9049,7.004,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1283,66732,'tt4574334',NULL,'Stranger Things','Stranger Things','tv',2016,'https://image.tmdb.org/t/p/w500/uOOtwVbSr4QDjAGIifLDwpb2Pdl.jpg','https://image.tmdb.org/t/p/original/56v2KjBlU4XaOv9rVYEQypROD7P.jpg','When a young boy vanishes, a small town uncovers a mystery involving secret experiments, terrifying supernatural forces, and one strange little girl.',NULL,NULL,117.587,8.56,0,10.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1284,124905,'tt0831387',NULL,'Godzilla','Godzilla','movie',2014,'https://image.tmdb.org/t/p/w500/z0CpCYiaUikJrcftPnb0jYCYmoo.jpg','https://image.tmdb.org/t/p/original/cHvwgJPaT59H1HiQsvBrGD5I46g.jpg','Ford Brody, a Navy bomb expert, has just reunited with his family in San Francisco when he is forced to go to Japan to help his estranged father, Joe. Soon, both men are swept up in an escalating crisis when an ancient alpha predator arises from the sea to combat malevolent adversaries that threaten the survival of humanity. The creatures leave colossal destruction in their wake, as they make their way toward their final battleground: San Francisco.',NULL,NULL,9.6513,6.4,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1285,1678,'tt0047034',NULL,'Godzilla','ゴジラ','movie',1954,'https://image.tmdb.org/t/p/w500/2W0Yw0qrgVMgdsSCZRKtfvaAh0i.jpg','https://image.tmdb.org/t/p/original/UD0PBqGgXJOOqsNMOHeZ9Apjde.jpg','Japan is thrown into a panic after several ships are sunk near Odo Island. An expedition to the island led by Dr. Kyohei Yamane soon discover something far more devastating than imagined in the form of a 50 meter tall monster whom the natives call Gojira. Now the monster begins a rampage that threatens to destroy not only Japan, but the rest of the world as well.',NULL,NULL,7.8612,7.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1286,166822,'tt1830713',NULL,'Big Ass Spider!','Big Ass Spider!','movie',2013,'https://image.tmdb.org/t/p/w500/uW4ayPN4B1mjrwb3OURRy0m9Hh7.jpg','https://image.tmdb.org/t/p/original/7BOTTnRZ5kT0UV5FECrxfqbaW1g.jpg','When a giant alien spider escapes from a military lab and rampages across the city of Los Angeles, it is up to one clever exterminator and his security guard sidekick to kill the creature before the entire city is destroyed.',NULL,NULL,1.1852,5.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1287,145221,'tt1935302',NULL,'Monsters: Dark Continent','Monsters: Dark Continent','movie',2014,'https://image.tmdb.org/t/p/w500/sQ3uSRb0wrgJf9sWc8LxYbnqltC.jpg','https://image.tmdb.org/t/p/original/97tEx5wgsdukAzC32NkcAFRvTGZ.jpg','Seven years on from the events of Monsters, and the ‘Infected Zones’ have spread worldwide. Humans have been knocked off the top of the food chain, with disparate communities struggling for survival. American soldiers are being sent abroad to protect US interests from the Monsters, but the war is far from being won.',NULL,NULL,1.4955,4.712,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1288,188541,'tt2511906',NULL,'Giant God Warrior Appears in Tokyo','巨神兵東京に現わる','movie',2012,'https://image.tmdb.org/t/p/w500/oObJQ17AL0cD1KijlbX63K7Tm3u.jpg','https://image.tmdb.org/t/p/original/7qpo9BgJzhIDY1SejOKPhTaa8Ze.jpg','The short focuses on the God Warrior from Nausicaa of The Valley of The Wind (1984). Super-powered bio-weapons in ceramic armor begin attacking Tokyo, annihilating human civilization.',NULL,NULL,0.4152,6.643,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1289,24362,'tt0368575',NULL,'The Second Renaissance Part II','The Second Renaissance Part II','movie',2003,'https://image.tmdb.org/t/p/w500/dI6Z5vpy78ZJkdOV2qvE6IjWTjl.jpg',NULL,'The battle for Earth turns against the humans, despite their infamous desperate act of blackening the skies.',NULL,NULL,1.2064,7.492,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1290,20453,'tt1187043',NULL,'3 Idiots','3 Idiots','movie',2009,'https://image.tmdb.org/t/p/w500/66A9MqXOyVFCssoloscw79z8Tew.jpg','https://image.tmdb.org/t/p/original/8gT3UKtglLVpu0YfccwbmXZ5Eis.jpg','Rascal. Joker. Dreamer. Genius... You''ve never met a college student quite like "Rancho." From the moment he arrives at India''s most prestigious university, Rancho''s outlandish schemes turn the campus upside down—along with the lives of his two newfound best friends. Together, they make life miserable for "Virus," the school’s uptight and heartless dean. But when Rancho catches the eye of the dean''s daughter, Virus sets his sights on flunking out the "3 idiots" once and for all.',NULL,NULL,22.7148,8.005,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1291,340485,'tt3721936',NULL,'American Honey','American Honey','movie',2016,'https://image.tmdb.org/t/p/w500/41SVO0AElBAl7zks9dFhJ0OjHni.jpg','https://image.tmdb.org/t/p/original/fLvgZEMv012AHZk2PAxMyG8WROt.jpg','A restless teenager escapes her troubled home and joins a traveling crew of young drifters selling magazines across the American Midwest. Immersed in a world of reckless partying, risky hustles, and fleeting romances, she searches for freedom and belonging on the open road.',NULL,NULL,1.4218,6.8,0,1.25279999999999986e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1292,580175,'tt10288566',NULL,'Another Round','Druk','movie',2020,'https://image.tmdb.org/t/p/w500/aDcIt4NHURLKnAEu7gow51Yd00Q.jpg','https://image.tmdb.org/t/p/original/a2pPepVPtKY7E4XEkT7W3ZxUOY5.jpg','Four stagnant high school teachers decide to test out a theory that maintaining a constant level of intoxication will improve their overall lives.',NULL,NULL,5.7693,7.626,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1293,9517,'tt0242193',NULL,'Bully','Bully','movie',2001,'https://image.tmdb.org/t/p/w500/vMJ2WHBbK4Jr3eDuF1e7O6lbC8m.jpg','https://image.tmdb.org/t/p/original/nT0jNH7ttu5Sy00rchmf2UloEsZ.jpg','A group of teenagers in South Florida enact a murder plot against their mutual bully, Bobby, who has emotionally, physically, and sexually abused them for years.',NULL,NULL,4.3168,6.682,0,12.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1294,22970,'tt1259521',NULL,'The Cabin in the Woods','The Cabin in the Woods','movie',2012,'https://image.tmdb.org/t/p/w500/zZZe5wn0udlhMtdlDjN4NB72R6e.jpg','https://image.tmdb.org/t/p/original/dWLoSzvw52y1gt7ni9gZXdy693e.jpg','Five friends set out for a weekend at a remote cabin in the woods, expecting nothing more than fun and relaxation. As night falls, they discover that something far more unsettling is at work and that nothing about their getaway is what it seems.',NULL,NULL,7.5016,6.654,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1295,17745,'tt0109369',NULL,'Camp Nowhere','Camp Nowhere','movie',1994,'https://image.tmdb.org/t/p/w500/5DmempuEgWyHCu5lMVyICTRgZUp.jpg','https://image.tmdb.org/t/p/original/hUqpbtSns4usIVA1vhclCYj0lDu.jpg','Morris "Mud" Himmel has a problem. His parents desperately want to send him away to summer camp. He hates going to summer camp, and would do anything to get out of it. Talking to his friends, he realizes that they are all facing the same sentence: a boring summer camp. Together with his friends, he hatches a plan to trick all the parents into sending them to a camp of their own design.',NULL,NULL,1.9867,5.9,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1296,2292,'tt0109445',NULL,'Clerks','Clerks','movie',1994,'https://image.tmdb.org/t/p/w500/9IiSgiq4h4siTIS9H3o4nZ3h5L9.jpg','https://image.tmdb.org/t/p/original/sjfbZVKRGh84lNxhqvuhdvovh18.jpg','Convenience and video store clerks Dante and Randal are sharp-witted, potty-mouthed and bored out of their minds. So in between needling customers, the counter jockeys play hockey on the roof, visit a funeral home and deal with their love lives.',NULL,NULL,4.8098,7.369,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1297,207,'tt0097165',NULL,'Dead Poets Society','Dead Poets Society','movie',1989,'https://image.tmdb.org/t/p/w500/erzbMlcNHOdx24AXOcn2ZKA7R1q.jpg','https://image.tmdb.org/t/p/original/lFIXZpwwlF9hg8NM3RazaIJDuaj.jpg','At an elite, old-fashioned boarding school in New England, a passionate English teacher inspires his students to rebel against convention and seize the potential of every day, courting the disdain of the stern headmaster.',NULL,NULL,20.4006,8.299,0,2.0831818181818182e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1298,1158915,'tt30319503',NULL,'Dìdi (弟弟)','Dìdi (弟弟)','movie',2024,'https://image.tmdb.org/t/p/w500/3UCTNaZgxW6BbeHMMTe6uL07MpV.jpg','https://image.tmdb.org/t/p/original/jD1oLRnLSKiLhutjiZ6OzgCgBsr.jpg','In 2008, during the last month of summer before high school begins, an impressionable 13-year-old Taiwanese American boy learns what his family can''t teach him: how to skate, how to flirt, and how to love your mom.',NULL,NULL,2.43,7.185,0,12.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1299,295490,'tt3704416',NULL,'Digging for Fire','Digging for Fire','movie',2015,'https://image.tmdb.org/t/p/w500/rJjT0uoqWl2ETSshtNg3Wv2MkMT.jpg','https://image.tmdb.org/t/p/original/ApCT32tQjQZ7we8GVedIuY5F0Oj.jpg','Tim and Lee are married with a young child. The chance to stay at a fancy home in the Hollywood Hills is complicated by Tim''s discovery of a bone and a rusty old gun in the yard. Tim is excited by the idea of a mystery, but Lee doesn''t want him to dig any further, preferring that he focus on the family taxes, which he promised to do weeks ago. This disagreement sends them on separate and unexpected adventures over the course of a weekend, as Tim and his friends seek clues to the mystery while Lee searches for answers to the bigger questions of marriage and parenthood.',NULL,NULL,1.4316,5.213,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1300,88,'tt0092890',NULL,'Dirty Dancing','Dirty Dancing','movie',1987,'https://image.tmdb.org/t/p/w500/9Jw6jys7q9gjzVX5zm1z0gC8gY9.jpg','https://image.tmdb.org/t/p/original/6iDQCBUSZKzY8Rnu8ECwl2gXcfG.jpg','Expecting the usual tedium that accompanies a summer in the Catskills with her family, 17-year-old Frances ''Baby'' Houseman is surprised to find herself stepping into the shoes of a professional hoofer—and unexpectedly falling in love.',NULL,NULL,8.1472,7.3,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1301,13342,'tt0083929',NULL,'Fast Times at Ridgemont High','Fast Times at Ridgemont High','movie',1982,'https://image.tmdb.org/t/p/w500/s1DA8H7qwoOcAEhow2rCzuQtpuO.jpg','https://image.tmdb.org/t/p/original/mHbnNX6jxpndW03yGXslHcBOaZv.jpg','A group of Southern-California high school students ignore their studies in favor of indulging in their teenage distractions.',NULL,NULL,4.5365,6.807,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1302,4488,'tt0080761',NULL,'Friday the 13th','Friday the 13th','movie',1980,'https://image.tmdb.org/t/p/w500/uGGpnWHOmWTARVN9wbC1nPxNgps.jpg','https://image.tmdb.org/t/p/original/16zzKM5vDxnYiqG6Tg6wOkOLSmj.jpg','Camp counselors are stalked and murdered by an unknown assailant while trying to reopen a summer camp that was the site of a child''s drowning.',NULL,NULL,8.0395,6.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1303,621,'tt0077631',NULL,'Grease','Grease','movie',1978,'https://image.tmdb.org/t/p/w500/2rM7fQKpb7cs1Iq7IBqub9LFDzJ.jpg','https://image.tmdb.org/t/p/original/2SRJMIoJzABzgyGw01U6VbQbvJD.jpg','Australian good girl Sandy and greaser Danny fell in love over the summer. But when they unexpectedly discover they''re now in the same high school, will they be able to rekindle their romance despite their eccentric friends?',NULL,NULL,14.3376,7.368,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1304,20210,'tt0338077',NULL,'Grind','Grind','movie',2003,'https://image.tmdb.org/t/p/w500/3ijvfbWQYLaFQ2PaX6hywnMW3Hv.jpg','https://image.tmdb.org/t/p/original/5DSsPOA54cb5ffIqJX9Dp5IKgtb.jpg','Four skaters follow their idol on his summer tour in an attempt to get noticed, get sponsored, and become stars themselves.',NULL,NULL,2.1034,5.972,0,1.20133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1305,10074,'tt0787475',NULL,'Hot Rod','Hot Rod','movie',2007,'https://image.tmdb.org/t/p/w500/jRkt03dXCVKnbvcQm3ygU1cjg9Y.jpg','https://image.tmdb.org/t/p/original/R0p2aJVD7NTrCJFbDlTPKoVCCz.jpg','For Rod Kimble, performing stunts is a way of life, even though he is rather accident-prone. Poor Rod cannot even get any respect from his stepfather, Frank, who beats him up in weekly sparring matches. When Frank falls ill, Rod devises his most outrageous stunt yet to raise money for Frank''s operation -- and then Rod will kick Frank''s butt.',NULL,NULL,4.5861,6.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1306,1052280,'tt14577874',NULL,'It''s What''s Inside','It''s What''s Inside','movie',2024,'https://image.tmdb.org/t/p/w500/6jzwaLoDurD6Jn2ILb42nFcn3xq.jpg','https://image.tmdb.org/t/p/original/xU2C64VWhYJMBDrjEsFPbVTWAjN.jpg','A pre-wedding reunion descends into a psychological nightmare for a group of college friends when a surprise guest arrives with a mysterious suitcase.',NULL,NULL,3.1065,6.473,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1307,578,'tt0073195',NULL,'Jaws','Jaws','movie',1975,'https://image.tmdb.org/t/p/w500/lxM6kqilAdpdhqUl2biYp5frUxE.jpg','https://image.tmdb.org/t/p/original/i1yf91svRHX45l9BXL8rVFzLoPH.jpg','When the seaside community of Amity finds itself under attack by a dangerous great white shark, the town''s chief of police, a young marine biologist, and a grizzled shark hunter embark on a desperate quest to kill the beast before it strikes again.',NULL,NULL,13.9978,7.683,0,11.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1308,38096,'tt0064573',NULL,'Last Summer','Last Summer','movie',1969,'https://image.tmdb.org/t/p/w500/ajbvQYVVnYHixttt1Qgw0dd2mGA.jpg','https://image.tmdb.org/t/p/original/oIoRJIWrYFuJUL5CYlAmkJAIRql.jpg','During summer vacation on Fire Island, three young people become very close. When an uncool girl tries to infiltrate the trio''s newly found relationship, they construct an elaborate plot that has violent results.',NULL,NULL,1.4251,6.104,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1309,10847,'tt0100054',NULL,'Lord of the Flies','Lord of the Flies','movie',1990,'https://image.tmdb.org/t/p/w500/xhxWsFgBYyDfRWfOhM1OrV88QDJ.jpg','https://image.tmdb.org/t/p/original/wQJnGGTqEDXzXbgic2T3kHt0I7a.jpg','When their plane crashes, 25 schoolboys find themselves trapped on a tropical island, miles from civilization.',NULL,NULL,3.5524,6.4,0,1.18499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1310,493066,'tt7434324',NULL,'Low Tide','Low Tide','movie',2019,'https://image.tmdb.org/t/p/w500/iEZrBPoWu4QYgOh594uCxDCEQDx.jpg','https://image.tmdb.org/t/p/original/kLzejJTaJvgCVaVvk6O0oVS06BL.jpg','In the long days of summer in a beach town on the New Jersey shore, high schooler Alan and his friends Red and Smitty break into vacation homes to steal valuables, funding dates at the boardwalk and lunches at the burger stand. When Alan and his younger brother Peter find a bag of gold coins, they try to hide them from the others — but Red, suspicious and violently unpredictable, seems willing to do anything to get the money.',NULL,NULL,0.8663,6.136,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1311,2293,'tt0113749',NULL,'Mallrats','Mallrats','movie',1995,'https://image.tmdb.org/t/p/w500/2ip0sGIMPN0XEN6q3lQIoaNI6tP.jpg','https://image.tmdb.org/t/p/original/h8fMLx6zJ5qfp8uT2DXzbHCFoJC.jpg','Both dumped by their girlfriends, two best friends seek refuge in the local mall. Eventually, they decide to try and win back their significant others and take care of their respective nemeses.',NULL,NULL,3.0651,6.757,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1312,12281,'tt0377091',NULL,'Mean Creek','Mean Creek','movie',2004,'https://image.tmdb.org/t/p/w500/nlU3SJzt5focTIkhLcO0ggnvbpW.jpg','https://image.tmdb.org/t/p/original/lFjONSYWA01SFDxnwRLxjUrh0GR.jpg','Teenagers living in small-town Oregon take a boat trip for a birthday celebration. When they get an idea to play a mean trick on the town bully, it suddenly goes too far. Soon they''re forced to deal with the unexpected consequences of their actions.',NULL,NULL,1.3043,6.829,0,1.23466666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1313,616825,'tt10332416',NULL,'Oil Capital Underground: The Genesis & Evolution of Punk Rock in Tulsa-Late 70''s to Mid 90''s','Oil Capital Underground: The Genesis & Evolution of Punk Rock in Tulsa-Late 70''s to Mid 90''s','movie',2018,'https://image.tmdb.org/t/p/w500/yGH9eKJkpsJuzPgjQSksd0dH5WT.jpg',NULL,'A documentary about the underground punk/new wave/thrash scene in Tulsa Oklahoma, focusing on the late 70s up until the mid 90s. Going against the grain in the conservative atmosphere of the city formerly known as the Oil Capital of the World, bands such as Los Reactors, NOTA, Pitbulls On Crack, Bunnies of Doom, Baby M, Brother Inferior, Tex Montana''s Green Party and many others struggled to make a name for themselves releasing their own music and playing local and national venues. Oil Capital Underground is filled with rare live footage, flyers, photos and interviews with many of the colorful musicians, promoters and club owners discussing the music, personalities and social climate of the time.',NULL,NULL,0.079,0.0,0,16.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1314,9263,'tt0114011',NULL,'Now and Then','Now and Then','movie',1995,'https://image.tmdb.org/t/p/w500/q31Ks8oAmM4Nq2CcGjyYYpdBAmh.jpg','https://image.tmdb.org/t/p/original/ic529Vlnxmp2ArVSYr5vBLoNFEK.jpg','Waxing nostalgic about the bittersweet passage from childhood to puberty, four childhood girlfriends — Teeny, Chrissy, Samantha and Roberta — recall the magical summer of 1970. During their walk down memory lane, they reconcile experiences with boys, secrets, bullies and more.',NULL,NULL,3.6213,6.875,0,1.59166666666666678e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1315,100757,'tt10293938',NULL,'Outer Banks','Outer Banks','tv',2020,'https://image.tmdb.org/t/p/w500/ovDgO2LPfwdVRfvScAqo9aMiIW.jpg','https://image.tmdb.org/t/p/original/vHuoq8HAmBFge8aiiyhHVVtmQr3.jpg','A tight-knit group of teens unearths a long-buried secret, setting off a chain of illicit events that takes them on an adventure they''ll never forget.',NULL,NULL,17.0897,8.269,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1316,463257,'tt4364194',NULL,'The Peanut Butter Falcon','The Peanut Butter Falcon','movie',2019,'https://image.tmdb.org/t/p/w500/qyQcRGvdW3VtxHR4fSDgPOePEip.jpg','https://image.tmdb.org/t/p/original/lewYqqt8epnjFhEOIIIINX9Z8EE.jpg','A down-on-his-luck crab fisherman embarks on a journey to get a young man with Down syndrome to a professional wrestling school in rural North Carolina and away from the retirement home where he’s lived for the past two and a half years.',NULL,NULL,2.4129,7.393,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1317,34307,'tt1586680',NULL,'Shameless','Shameless','tv',2011,'https://image.tmdb.org/t/p/w500/ifo31fMWLmyOVpdak9K0kY4jldQ.jpg','https://image.tmdb.org/t/p/original/5s9XHTB9SLPdg3mNU6BlSLnZ9Qq.jpg','Chicagoan Frank Gallagher is the proud single dad of six smart, industrious, independent kids, who without him would be... perhaps better off. When Frank''s not at the bar spending what little money they have, he''s passed out on the floor. But the kids have found ways to grow up in spite of him. They may not be like any family you know, but they make no apologies for being exactly who they are.',NULL,NULL,125.9295,8.168,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1318,13567,'tt0086320',NULL,'Sleepaway Camp','Sleepaway Camp','movie',1983,'https://image.tmdb.org/t/p/w500/lZ7KjSyHjP4ula5ybiXuQcDvZLg.jpg','https://image.tmdb.org/t/p/original/nQbvPYjj3U3pz8alPpHIdvVIoHx.jpg','Years after a terrible boating accident, Angela is sent to Camp Arawak where a series of bizarre and violent "accidents" begin to claim the lives of various campers.',NULL,NULL,2.0666,6.278,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1319,1037113,'tt22004344',NULL,'Snack Shack','Snack Shack','movie',2024,'https://image.tmdb.org/t/p/w500/wCXd5tpUSc12LVPd2oN9OKU1EVQ.jpg','https://image.tmdb.org/t/p/original/UxPjfVl50OGlJ6Ww8DXEDFzx7g.jpg','Inseparable best friends AJ and Moose decide to run the local pool''s snack shack after their plan to sell home-brewed beer goes down the drain. Things take a turn when they meet Brooke, an effortlessly cool lifeguard who puts their big plans, and friendship, at risk.',NULL,NULL,7.9724,7.19,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1320,118887,'tt0079966',NULL,'Sunburn','Sunburn','movie',1979,'https://image.tmdb.org/t/p/w500/pP9qJHqqxCxX0QGIJzTCH8W3kYQ.jpg','https://image.tmdb.org/t/p/original/8amGEzIXCsbbaqMRC5FWG9pXvpW.jpg','A model and a private eye help a New York insurance investigator on a deadly case in Acapulco.',NULL,NULL,0.9452,4.958,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1321,347031,'tt4034354',NULL,'Swiss Army Man','Swiss Army Man','movie',2016,'https://image.tmdb.org/t/p/w500/xE2QfqvAGI8n8ckIiy9FzS9XF94.jpg','https://image.tmdb.org/t/p/original/xo6Sedrdj4DVnh4ZEzDM4D0QQYU.jpg','Alone on a tiny deserted island, Hank has given up all hope of ever making it home again. But one day everything changes when a dead body washes ashore, and he soon realizes it may be his last opportunity to escape certain death. Armed with his new “friend” and an unusual bag of tricks, the duo go on an epic adventure to bring Hank back to the woman of his dreams.',NULL,NULL,3.0194,6.919,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1322,10474,'tt0112461',NULL,'The Basketball Diaries','The Basketball Diaries','movie',1995,'https://image.tmdb.org/t/p/w500/AhvO1GGDPIgN0hOqZEgaFCbswMK.jpg','https://image.tmdb.org/t/p/original/oDdRrwTCgaDzAshScrFO09qWqPB.jpg','A high school basketball player’s life turns upside down after free-falling into the harrowing world of drug addiction.',NULL,NULL,6.1718,7.405,0,1.20133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1323,1907,'tt0163978',NULL,'The Beach','The Beach','movie',2000,'https://image.tmdb.org/t/p/w500/4y7LxD8TSi6AtsM2xSYqUm1gu7u.jpg','https://image.tmdb.org/t/p/original/f7sQHmdZdPHaRVt3428XmdoZ8Hs.jpg','Twenty-something Richard travels to Thailand and finds himself in possession of a strange map. Rumours state that it leads to a solitary beach paradise, a tropical bliss - excited and intrigued, he sets out to find it.',NULL,NULL,3.7949,6.485,0,13.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1324,5689,'tt0080453',NULL,'The Blue Lagoon','The Blue Lagoon','movie',1980,'https://image.tmdb.org/t/p/w500/k6KsThCeoxxHDbVnlHLdTlf5wsy.jpg','https://image.tmdb.org/t/p/original/4HYBkZPz2Gb7LWXludvvOfATzGS.jpg','Two small children and a ship''s cook survive a shipwreck and find safety on an idyllic tropical island. Soon, however, the cook dies and the young boy and girl are left on their own. Days become years and Emmeline and Richard make a home for themselves surrounded by exotic creatures and nature''s beauty. But will they ever see civilization again?',NULL,NULL,6.3412,6.141,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1325,24124,'tt0082118',NULL,'The Burning','The Burning','movie',1981,'https://image.tmdb.org/t/p/w500/d8as1GtCAhlc5rirarnUUd85gJA.jpg','https://image.tmdb.org/t/p/original/hkt9cbyS3gRkiBqc9a8oukd3oXt.jpg','A caretaker at a summer camp is burned when a prank goes tragically wrong. After several years of intensive treatment at hospital, he is released back into society, albeit missing some social skills. What follows is a bloody killing spree with the caretaker making his way back to his old stomping ground to confront one of the youths that accidentally burned him.',NULL,NULL,1.8328,6.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1326,9340,'tt0089218',NULL,'The Goonies','The Goonies','movie',1985,'https://image.tmdb.org/t/p/w500/eBU7gCjTCj9n2LTxvCSIXXOvHkD.jpg','https://image.tmdb.org/t/p/original/5qsyqA7FeYRymBmNbPBqBgqWPO4.jpg','Young teen Mikey Walsh and his friends set off on a quest to find Pirate One-Eyed Willie''s treasure in hopes of saving their homes from demolition. However, on their quest to find the treasure, they run into a family of recently escaped criminals, determined to capture the kids and reach the treasure first.',NULL,NULL,8.196,7.513,0,1.36275000000000012e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1327,579583,'tt9686708',NULL,'The King of Staten Island','The King of Staten Island','movie',2020,'https://image.tmdb.org/t/p/w500/zQFjMmE3K9AX5QrBL1SXIxYQ9jz.jpg','https://image.tmdb.org/t/p/original/5rwcd24GGltKiqdPT4G2dmchLr9.jpg','Scott has been a case of arrested development ever since his firefighter father died when he was seven. He''s now reached his mid-20s having achieved little, chasing a dream of becoming a tattoo artist that seems far out of reach. As his ambitious younger sister heads off to college, Scott is still living with his exhausted ER nurse mother and spends his days smoking weed, hanging with the guys — Oscar, Igor and Richie — and secretly hooking up with his childhood friend Kelsey. But when his mother starts dating a loudmouth firefighter named Ray, it sets off a chain of events that will force Scott to grapple with his grief and take his first tentative steps toward moving forward in life.',NULL,NULL,3.051,6.979,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1328,1547,'tt0093437',NULL,'The Lost Boys','The Lost Boys','movie',1987,'https://image.tmdb.org/t/p/w500/nH1lvyQvfbL5GKScTtT6zkIvDEn.jpg','https://image.tmdb.org/t/p/original/6zvbeKxgc80xQsZLJ4eQVZSKXO8.jpg','When an unsuspecting town newcomer is drawn to local blood fiends, the Frog brothers and other unlikely heroes gear up to rescue him.',NULL,NULL,5.0826,7.108,0,1.62542857142857144e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1329,11528,'tt0108037',NULL,'The Sandlot','The Sandlot','movie',1993,'https://image.tmdb.org/t/p/w500/7PYqz0viEuW8qTvuGinUMjDWMnj.jpg','https://image.tmdb.org/t/p/original/wjxyKpUAZu6OVbKx9krhgI9KMl2.jpg','During a summer of friendship and adventure, one boy becomes a part of the gang, nine boys become a team and their leader becomes a legend by confronting the terrifying mystery beyond the right field wall.',NULL,NULL,6.7226,7.568,0,1.27333333333333325e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1330,147773,'tt1727388',NULL,'The Way Way Back','The Way Way Back','movie',2013,'https://image.tmdb.org/t/p/w500/4DgA0EDDVv37C8xISc3Vv0rhxlL.jpg','https://image.tmdb.org/t/p/original/bPm5kQLlc2KypdYkUxGbrGfLJ82.jpg','Shy 14-year-old Duncan goes on summer vacation with his mother, her overbearing boyfriend, and her boyfriend''s daughter. Having a rough time fitting in, Duncan finds an unexpected friend in Owen, manager of the Water Wizz water park.',NULL,NULL,3.3232,7.138,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1331,460019,'tt6772950',NULL,'Truth or Dare','Truth or Dare','movie',2018,'https://image.tmdb.org/t/p/w500/ei2waWQAG8NP244WShIFgGu9IOu.jpg','https://image.tmdb.org/t/p/original/eQ5xu2pQ5Kergubto5PbbUzey28.jpg','A harmless game of "Truth or Dare" among friends turns deadly when someone—or something—begins to punish those who tell a lie—or refuse the dare.',NULL,NULL,2.3803,5.939,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1332,9796,'tt0454970',NULL,'Turistas','Turistas','movie',2006,'https://image.tmdb.org/t/p/w500/nvQqTMPVL8NDeHKEkzAL0ADIECS.jpg','https://image.tmdb.org/t/p/original/kN1YmRDoCoxauUoj0CCcYDzpQ9h.jpg','A group of young backpackers'' vacation turns sour when a bus accident leaves them marooned in a remote Brazilian rural area that holds an ominous secret.',NULL,NULL,1.8877,5.469,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1333,2171,'tt0243655',NULL,'Wet Hot American Summer','Wet Hot American Summer','movie',2001,'https://image.tmdb.org/t/p/w500/skKRPj1Cdsxqzn8BwKxvNV20rRW.jpg','https://image.tmdb.org/t/p/original/boct1C0KWZ533T6o5qjFVfaUpSt.jpg','It''s the last day of Camp Firewood''s season, but there''s still time for the big talent show, a little romance… and for everyone to be wiped out by the piece of NASA''s Skylab that''s hurtling toward Earth.',NULL,NULL,3.2429,6.247,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1334,10307,'tt0145531',NULL,'Stigmata','Stigmata','movie',1999,'https://image.tmdb.org/t/p/w500/sKS1Vuqj7OQpOumfs6ArC0TICTN.jpg','https://image.tmdb.org/t/p/original/i9tMK3nzmZJ8MBG92iIxGXHWDq4.jpg','A young woman with no strong religious beliefs, Frankie Paige begins having strange and violent experiences, showing signs of the wounds that Jesus received when crucified. When the Vatican gets word of Frankie''s situation, a high-ranking cardinal requests that the Rev. Andrew Kiernan investigate her case. Soon Kiernan realizes that very sinister forces are at work, and tries to rescue Frankie from the entity that is plaguing her.',NULL,NULL,3.4676,6.3,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1335,9286,'tt0414982',NULL,'Final Destination 3','Final Destination 3','movie',2006,'https://image.tmdb.org/t/p/w500/p7ARuNKUGPGvkBiDtIDvAzYzonX.jpg','https://image.tmdb.org/t/p/original/nSV1NIAK0Sp5dM1oiobtqbJ8Jrv.jpg','High school senior Wendy''s premonition of a deadly rollercoaster ride saves her life and a lucky few, but not from death itself — which seeks out those who escaped their fate.',NULL,NULL,7.9225,6.154,0,9.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1336,2649,'tt0119174',NULL,'The Game','The Game','movie',1997,'https://image.tmdb.org/t/p/w500/4UOa079915QjiTA2u5hT2yKVgUu.jpg','https://image.tmdb.org/t/p/original/k7GM13qRYSour3lk90Dq1EwdpoW.jpg','In honor of his birthday, San Francisco banker Nicholas Van Orton, a financial genius and a cold-hearted loner, receives an unusual present from his younger brother, Conrad: a gift certificate to play a unique kind of game. In nary a nanosecond, Nicholas finds himself consumed by a dangerous set of ever-changing rules, unable to distinguish where the charade ends and reality begins.',NULL,NULL,8.0801,7.575,0,11.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1337,15472,'tt1132620',NULL,'The Girl with the Dragon Tattoo','Män som hatar kvinnor','movie',2009,'https://image.tmdb.org/t/p/w500/6w0TKhfR0Rzby5SXxgfuI99Jrva.jpg','https://image.tmdb.org/t/p/original/dPE25PbaeE6fCR2SQb4H4MeBmml.jpg','Swedish thriller based on Stieg Larsson''s novel about a male journalist and a young female hacker. In the opening of the movie, Mikael Blomkvist, a middle-aged publisher for the magazine Millennium, loses a libel case brought by corrupt Swedish industrialist Hans-Erik Wennerström. Nevertheless, he is hired by Henrik Vanger in order to solve a cold case, the disappearance of Vanger''s niece',NULL,NULL,4.4035,7.531,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1338,36647,'tt0120611',NULL,'Blade','Blade','movie',1998,'https://image.tmdb.org/t/p/w500/oWT70TvbsmQaqyphCZpsnQR7R32.jpg','https://image.tmdb.org/t/p/original/7NKfxJrQn053UJeLftlx4m4NTzo.jpg','The Daywalker known as "Blade" - a half-vampire, half-mortal man - becomes the protector of humanity against an underground army of vampires.',NULL,NULL,10.0176,6.843,0,2.03345454545454558e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1339,24421,'tt1082599',NULL,'Stag Night','Stag Night','movie',2008,'https://image.tmdb.org/t/p/w500/gscnLqGWWC1q1HBvzfu35uwsQC0.jpg','https://image.tmdb.org/t/p/original/gSZ7t9K3dY8tSy0oHZTpHTInDZV.jpg','Four guys on a bachelor party get off the subway at a station that shut down in the 70''s and, after watching a transit cop get brutally murdered, find themselves running for their lives beneath the streets of NY.',NULL,NULL,1.5795,4.8,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1340,8555,'tt0381966',NULL,'Creep','Creep','movie',2004,'https://image.tmdb.org/t/p/w500/w5oxV6MDEfL48FMK9BmYTD2wQRm.jpg','https://image.tmdb.org/t/p/original/ooPtDdWP2nuYCoyLJAVwdthf5dN.jpg','Trapped in a London subway station, a woman who''s being pursued by a potential attacker heads into the unknown labyrinth of tunnels beneath the city''s streets',NULL,NULL,2.2723,5.998,0,9.68333333333333357e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1341,240832,'tt2872732',NULL,'Lucy','Lucy','movie',2014,'https://image.tmdb.org/t/p/w500/kRbpUTRNm6QbLQFPFWUcNC4czEm.jpg','https://image.tmdb.org/t/p/original/1hzH1Wu2xhXBNOWzw3RMwNTJX5q.jpg','A woman, accidentally caught in a dark deal, turns the tables on her captors and transforms into a merciless warrior evolved beyond human logic.',NULL,NULL,10.1209,6.474,0,12.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1342,2112,'tt0120784',NULL,'Payback','Payback','movie',1999,'https://image.tmdb.org/t/p/w500/8Bqlv2kbOyZFqfiPNgzdBscqYPn.jpg','https://image.tmdb.org/t/p/original/nlppU9QYqqfrnVGYEgSsCHzgMr8.jpg','With friends like these, who needs enemies? That''s the question bad guy Porter is left asking after his wife and partner steal his heist money and leave him for dead -- or so they think. Five months and an endless reservoir of bitterness later, Porter''s partners and the crooked cops on his tail learn how bad payback can be.',NULL,NULL,4.8367,6.828,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1343,11601,'tt0164181',NULL,'Stir of Echoes','Stir of Echoes','movie',1999,'https://image.tmdb.org/t/p/w500/9CyJ5aYF27cITX1WSUTENeP4wBE.jpg','https://image.tmdb.org/t/p/original/puVlXLW2gVWQFKJsd9fjYWpdTgZ.jpg','After being hypnotized by his sister-in-law, Tom Witzky begins seeing haunting visions of a girl''s ghost and a mystery begins to unfold around her.',NULL,NULL,4.1366,6.69,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1344,1900,'tt0181865',NULL,'Traffic','Traffic','movie',2000,'https://image.tmdb.org/t/p/w500/jbccmnqE4oAPI67bApgt2JiRPz8.jpg','https://image.tmdb.org/t/p/original/nkMgY1XFLWr91najzfvwie8LyYF.jpg','An exploration of the United States of America''s war on drugs from multiple perspectives. For the new head of the Office of National Drug Control Policy, the war becomes personal when he discovers his well-educated daughter is abusing cocaine within their comfortable suburban home. In Mexico, a flawed, but noble policeman agrees to testify against a powerful general in league with a cartel, and in San Diego, a drug kingpin''s sheltered trophy wife must learn her husband''s ruthless business after he is arrested, endangering her luxurious lifestyle.',NULL,NULL,4.9244,7.095,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1345,550,'tt0137523',NULL,'Fight Club','Fight Club','movie',1999,'https://image.tmdb.org/t/p/w500/jSziioSwPVrOy9Yow3XhWIBDjq1.jpg','https://image.tmdb.org/t/p/original/c6OLXfKAk5BKeR6broC8pYiCquX.jpg','A ticking-time-bomb insomniac and a slippery soap salesman channel primal male aggression into a shocking new form of therapy. Their concept catches on, with underground "fight clubs" forming in every town, until an eccentric gets in the way and ignites an out-of-control spiral toward oblivion.',NULL,NULL,36.816,8.437,0,8.504999999999999e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1346,9544,'tt0295254',NULL,'FearDotCom','FearDotCom','movie',2002,'https://image.tmdb.org/t/p/w500/phcd5AJvA1S45JMKYoNLhTzFwsE.jpg','https://image.tmdb.org/t/p/original/5gnBqLDi1pjJxxCgpOJCu5VSLp1.jpg','When four bodies are discovered among the industrial decay and urban grime of New York City, brash young detective Mike Reilly teams with ambitious Department of Health researcher Terry Huston to uncover the cause behind their violent and inexplicable deaths. The only common factor shared by the victims? Each died exactly 48 hours after logging onto a website called feardotcom.',NULL,NULL,3.2321,3.799,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1347,10185,'tt0805570',NULL,'The Midnight Meat Train','The Midnight Meat Train','movie',2008,'https://image.tmdb.org/t/p/w500/x5YbfyUA8huK0shr008xwzNVJ5Y.jpg','https://image.tmdb.org/t/p/original/jexPGBtylbr0mo4DrVKaEWHQrk.jpg','A photographer''s obsessive pursuit of dark subject matter leads him into the path of a serial killer who stalks late night commuters, ultimately butchering them in the most gruesome ways.',NULL,NULL,3.2814,6.184,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1348,9682,'tt0454919',NULL,'Pulse','Pulse','movie',2006,'https://image.tmdb.org/t/p/w500/9ePdNzKVvGHsMMphfS3HeoMvuEX.jpg','https://image.tmdb.org/t/p/original/dTDETgmTPeEbnI3cwfQhTETgygv.jpg','When the dead discover a means to contact the living through electronic devices, cellphones and computers become open gateways to monstrosities and destruction.',NULL,NULL,2.6947,5.1,0,1.18433333333333319e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1349,13455,'tt0465580',NULL,'Push','Push','movie',2009,'https://image.tmdb.org/t/p/w500/fHStfRjQGstuqtUz4Q22lbFU58M.jpg','https://image.tmdb.org/t/p/original/uQ5xARQz6BiKlppKCBnKmkfW76m.jpg','After his father, an assassin, is brutally murdered, Nick Gant vows revenge on Division, the covert government agency that dabbles in psychic warfare and experimental drugs. Hiding in Hong Kong''s underworld, Nick assembles a band of rogue psychics dedicated to destroying Division. Together with Cassie, a teenage clairvoyant, Nick goes in search of a missing girl and a stolen suitcase that could be the key to accomplishing their mutual goal.',NULL,NULL,2.2321,6.146,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1350,11222,'tt0075675',NULL,'The American Friend','Der amerikanische Freund','movie',1977,'https://image.tmdb.org/t/p/w500/jHVe5EHDFj9ac2F2aU86sWTGKnn.jpg','https://image.tmdb.org/t/p/original/h59F8NcFSlucTK7fUcndD9TB9jg.jpg','Tom Ripley, an American who deals in forged art, is slighted at an auction in Hamburg by picture framer Jonathan Zimmerman. When Ripley is asked by gangster Raoul Minot to kill a rival, he suggests Zimmerman, and the two, exploiting Zimmerman''s terminal illness, coerce him into being a hitman.',NULL,NULL,1.5405,7.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1351,1817,'tt0183649',NULL,'Phone Booth','Phone Booth','movie',2003,'https://image.tmdb.org/t/p/w500/r6lIwPKVDa6Q76qH2TbIBqPhXL3.jpg','https://image.tmdb.org/t/p/original/iYOEONglnxIsykyOGfzyc01fyg4.jpg','A slick New York publicist who picks up a ringing receiver in a phone booth is told that if he hangs up, he''ll be killed... and the little red light from a laser rifle sight is proof that the caller isn''t kidding.',NULL,NULL,4.5815,6.872,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1352,979,'tt0290673',NULL,'Irreversible','Irréversible','movie',2002,'https://image.tmdb.org/t/p/w500/rxeDxo8FvZpLu6iplNpxdtAVnfu.jpg','https://image.tmdb.org/t/p/original/xV1EfNSEg6id6juJPr1vM6p9x5X.jpg','A woman’s lover and her ex-boyfriend take justice into their own hands after she becomes the victim of a rapist. Because some acts can’t be undone. Because man is an animal. Because the desire for vengeance is a natural impulse. Because most crimes remain unpunished.',NULL,NULL,24.7017,7.2,0,1.63242857142857147e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1353,7299,'tt0238380',NULL,'Equilibrium','Equilibrium','movie',2002,'https://image.tmdb.org/t/p/w500/q6VzUsHs4Z3myBHkrPAA3avfGwn.jpg','https://image.tmdb.org/t/p/original/dQutbCXdvcoRORJTcnakrICCkDb.jpg','In a dystopian future, a totalitarian regime maintains peace by subduing the populace with a drug, and displays of emotion are punishable by death. A man in charge of enforcing the law rises to overthrow the system.',NULL,NULL,6.4902,7.055,0,14.684,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1354,11804,'tt0375210',NULL,'White Noise','White Noise','movie',2005,'https://image.tmdb.org/t/p/w500/ncB9SvOclmXYALlcAsF1jRIuISl.jpg','https://image.tmdb.org/t/p/original/71X982Z2hHTRSc2Ez70cpgeGuVu.jpg','An architect''s desire to speak with his wife from beyond the grave using EVP (Electronic Voice Phenomenon), becomes an obsession with supernatural repercussions.',NULL,NULL,1.8651,5.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1355,34015,'tt0498329',NULL,'We Live in Public','We Live in Public','movie',2009,'https://image.tmdb.org/t/p/w500/eGKZn41ckFwyfXeQS7mtfIG8u4G.jpg','https://image.tmdb.org/t/p/original/3xLSOfe8BbNQy4FQO1zaZFZSZ7a.jpg','In 1999, Internet entrepreneur Josh Harris recruits dozens of young men and women who agree to live in underground apartments for weeks at a time while their every movement is broadcast online. Soon, Harris and his girlfriend embark on their own subterranean adventure, with cameras streaming live footage of their meals, arguments, bedroom activities, and bathroom habits. This documentary explores the role of technology in our lives, as it charts the fragile nature of dot-com economy.',NULL,NULL,0.8246,6.852,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1356,21450,'tt0107653',NULL,'Naked','Naked','movie',1993,'https://image.tmdb.org/t/p/w500/xMYP4uaNeyPmX4FQ2xxWk2eIN6K.jpg','https://image.tmdb.org/t/p/original/uIh3mW3AuSM7ww7NYtvSWDQ1zc7.jpg','An unemployed Brit vents his rage on unsuspecting strangers as he embarks on a nocturnal London odyssey.',NULL,NULL,2.8274,7.274,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1357,2501,'tt0258463',NULL,'The Bourne Identity','The Bourne Identity','movie',2002,'https://image.tmdb.org/t/p/w500/aP8swke3gmowbkfZ6lmNidu0y9p.jpg','https://image.tmdb.org/t/p/original/kJaRWmy1BGq3pHyE94LOTteiHer.jpg','Wounded to the brink of death and suffering from amnesia, Jason Bourne is rescued at sea by a fisherman. With nothing to go on but a Swiss bank account number, he starts to reconstruct his life, but finds that many people he encounters want him dead. However, Bourne realizes that he has the combat and mental skills of a world-class spy—but who does he work for?',NULL,NULL,12.3607,7.48,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1358,8202,'tt0402022',NULL,'Æon Flux','Æon Flux','movie',2005,'https://image.tmdb.org/t/p/w500/5958Nt4QX6aRSUdQnvNw8wqjTJQ.jpg','https://image.tmdb.org/t/p/original/uTqxyztRGHSq96JYhByyNFuqqld.jpg','400 years into the future, disease has wiped out the majority of the world''s population, except one walled city, Bregna, ruled by a congress of scientists. When Æon Flux, the top operative in the underground ''Monican'' rebellion, is sent on a mission to kill a government leader, she uncovers a world of secrets.',NULL,NULL,3.4617,5.643,0,13.9225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1359,5204,'tt0373981',NULL,'Kontroll','Kontroll','movie',2003,'https://image.tmdb.org/t/p/w500/rEf7jXTm4oaI4YWTLlqQCukn63j.jpg','https://image.tmdb.org/t/p/original/x1i0wTxKqT86n1M71GBnc13mxLX.jpg','A subway enforcement officer working in the oppressively gray Budapest metro gets a chance at love — but first he needs to find out why passengers are jumping — or being pushed — to their deaths onto the tracks.',NULL,NULL,1.2489,7.194,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1360,1613,'tt0227984',NULL,'The 51st State','The 51st State','movie',2001,'https://image.tmdb.org/t/p/w500/aYlrGirWrRCTU1PF6Svghn1EMAc.jpg','https://image.tmdb.org/t/p/original/lTn6AUlpKn70quBaANug12n07xj.jpg','An American master chemist plans to score big on a once in a lifetime drug deal. All does not go as planned and he is soon entangled in a web of deceit.',NULL,NULL,2.0895,6.079,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1361,18501,'tt1034032',NULL,'Gamer','Gamer','movie',2009,'https://image.tmdb.org/t/p/w500/d5BTNmr87p7EvguTFW72vlL9l9H.jpg','https://image.tmdb.org/t/p/original/nRBt4c7X56HexYhgt9Exl7upvRo.jpg','Mind-control technology has taken society by a storm, a multiplayer on-line game called "Slayers" allows players to control human prisoners in mass-scale. Simon controls Kable, the online champion of the game. Kable''s ultimate challenge becomes regaining his identity and independence by defeating the game''s mastermind.',NULL,NULL,3.4318,5.692,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1362,7451,'tt0295701',NULL,'xXx','xXx','movie',2002,'https://image.tmdb.org/t/p/w500/xeEw3eLeSFmJgXZzmF2Efww0q3s.jpg','https://image.tmdb.org/t/p/original/qwK9soQmmJ7kRdjLZVXblw3g7AQ.jpg','Xander Cage is your standard adrenaline junkie with no fear and a lousy attitude. When the US Government "recruits" him to go on a mission, he''s not exactly thrilled. His mission: to gather information on an organization that may just be planning the destruction of the world, led by the nihilistic Yorgi.',NULL,NULL,20.2796,5.989,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1363,107,'tt0208092',NULL,'Snatch','Snatch','movie',2000,'https://image.tmdb.org/t/p/w500/kJZoAHq1SLDdWjeNGtlHAnGpmFV.jpg','https://image.tmdb.org/t/p/original/gTghF8ardwJ48XLHkiapWk3ZmSo.jpg','Unscrupulous boxing promoters, violent bookies, a Russian gangster, incompetent amateur robbers, and supposedly Jewish jewellers fight to track down a priceless stolen diamond.',NULL,NULL,12.3381,7.826,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1364,245891,'tt2911666',NULL,'John Wick','John Wick','movie',2014,'https://image.tmdb.org/t/p/w500/wXqWR7dHncNRbxoEGybEy7QTe9h.jpg','https://image.tmdb.org/t/p/original/ff2ti5DkA9UYLzyqhQfI2kZqEuh.jpg','Ex-hitman John Wick comes out of retirement to track down the gangsters that took everything from him.',NULL,NULL,10.5254,7.46,0,13.0725,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1365,39335,'tt0117069',NULL,'Moebius','Moebius','movie',1996,'https://image.tmdb.org/t/p/w500/kmZZNYULK60E0socp5mH9OOvpHS.jpg','https://image.tmdb.org/t/p/original/6pbVy9jV0dCiyoJsGjs8hjywguh.jpg','Deep within Buenos Aires''s labyrinthine subway system, a train mysteriously disappears along with it''s 30 passengers. The subway officials are greatly troubled and call in topographer Daniel Pratt to help them find it. Unfortunately, the tunnels are so vast and complex, that Pratt needs his mentor Hugo Mistein to help him. Unfortunately, he too has vanished.',NULL,NULL,0.6772,6.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1366,13552,'tt0112887',NULL,'The Doom Generation','The Doom Generation','movie',1995,'https://image.tmdb.org/t/p/w500/tLfp9fHjydH6wzxukch5PWclga.jpg','https://image.tmdb.org/t/p/original/9mHvO0PzmEgxDtmRq3VeTVELYqb.jpg','Jordan White and Amy Blue, two troubled teens, pick up an adolescent drifter, Xavier Red. Together, the threesome embarks on a sex- and violence-filled journey through a United States of psychos and quickie marts.',NULL,NULL,3.4301,6.5,0,13.545,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1367,23535,'tt0099277',NULL,'Class of 1999','Class of 1999','movie',1990,'https://image.tmdb.org/t/p/w500/yz5dyOHrJ5SdzWrue6ofkdX6cXI.jpg','https://image.tmdb.org/t/p/original/aSNagpdVCD9UFI1PWrH8jOLnRN1.jpg','The time is in the future and the youth gang violence is so high that the areas around some schools have become "free-fire zones", into which not even the police will venture. When Miles Langford, the head of Kennedy High School, decides to take his school back from the gangs, robotics specialist Dr. Robert Forrest provides "tactical education units". These are amazingly human-like androids that have been programmed to teach and are supplied with devastatingly effective solutions to discipline problems. So when the violent, out-of-control students of Kennedy High report for class tomorrow, they''re going to get a real education... in staying alive!',NULL,NULL,1.8954,6.075,0,10.7,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1368,17814,'tt0074156',NULL,'Assault on Precinct 13','Assault on Precinct 13','movie',1976,'https://image.tmdb.org/t/p/w500/RtGDEmXbSxE8NThCCY1SXFXLLw.jpg','https://image.tmdb.org/t/p/original/dm1bqDSw3MJTjYCeuNUv122BXFp.jpg','A highway patrol officer, two criminals, and a station secretary form an unlikely alliance to defend a defunct Los Angeles precinct against a siege by a bloodthirsty street gang.',NULL,NULL,2.7937,7.264,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1369,123025,'tt2313197',NULL,'Batman: The Dark Knight Returns, Part 1','Batman: The Dark Knight Returns, Part 1','movie',2012,'https://image.tmdb.org/t/p/w500/rVr2Tdp2LcL3DheXUrVN345Myhg.jpg','https://image.tmdb.org/t/p/original/bNLLjc6NT80FmFknvHn8demDHhl.jpg','Batman has not been seen for ten years. A new breed of criminal ravages Gotham City, forcing 55-year-old Bruce Wayne back into the cape and cowl. But, does he still have what it takes to fight crime in a new era?',NULL,NULL,2.7886,7.737,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1370,27601,'tt0212879',NULL,'Citizen Toxie: The Toxic Avenger IV','Citizen Toxie: The Toxic Avenger IV','movie',2001,'https://image.tmdb.org/t/p/w500/wR4VvqrRd2r9M4GYXPnoV02aUNG.jpg','https://image.tmdb.org/t/p/original/rydjFBcArIdctIRD9kgRcoIyH6U.jpg','A horrific explosion creates a dimensional portal between Tromaville and its dimensional mirror image, Amortville. While the Toxie is trapped in the mirror dimension, Tromaville comes under the control of his evil doppelganger, the Noxious Offender.',NULL,NULL,1.1008,6.075,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1371,72508,'tt0089679',NULL,'The New Kids','The New Kids','movie',1985,'https://image.tmdb.org/t/p/w500/rFmDfsFgEtqhc49e95QK1rvg2l7.jpg','https://image.tmdb.org/t/p/original/64mrdtS30ubr8lprr6yGR5cs7LS.jpg','A brother and his young sister come to a small town to find out a local gang terrorizes the population.',NULL,NULL,1.3423,6.432,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1372,629017,'tt11456054',NULL,'Run Hide Fight','Run Hide Fight','movie',2021,'https://image.tmdb.org/t/p/w500/wlP25H14OvKoFORIwuKomZzioA5.jpg','https://image.tmdb.org/t/p/original/hUfnYsVMmXcbcwzWHr62jTtpdkE.jpg','A 17-year-old girl uses her wits, survival skills, and compassion to fight for her life, and those of her fellow classmates, against a group of live-streaming school shooters.',NULL,NULL,2.0847,6.57,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1373,1103,'tt0082340',NULL,'Escape from New York','Escape from New York','movie',1981,'https://image.tmdb.org/t/p/w500/vH9llaphjAssRGi0k7e75tD40Ce.jpg','https://image.tmdb.org/t/p/original/6vNuos23LwWjY1FJuojwPAgo8Ss.jpg','In a world ravaged by crime, the entire island of Manhattan has been converted into a walled prison where brutal prisoners roam free. After the US president crash-lands inside, war hero Snake Plissken has 24 hours to bring him back.',NULL,NULL,6.3436,7.052,0,10.56,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1374,91088,'tt2086830',NULL,'The King of Pigs','돼지의 왕','movie',2011,'https://image.tmdb.org/t/p/w500/o93tMT3eyeOXBZ8F8TiGQWUq3Ta.jpg','https://image.tmdb.org/t/p/original/qEKkA07NBx2FPpciIXZQrTkEvXi.jpg','Two friends, Jung Jong-suk and Hwang Kyung-min, meet after several years and talk about their time in school, which left them scarred.',NULL,NULL,0.7172,6.1,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1375,14746,'tt0088194',NULL,'Streets of Fire','Streets of Fire','movie',1984,'https://image.tmdb.org/t/p/w500/tmYHBKCZkbmiUfhfOQKgfh0jvXK.jpg','https://image.tmdb.org/t/p/original/7rE6SyTySkcpnHSuBMkOOTivOxg.jpg','Raven Shaddock and his gang of merciless biker friends kidnap rock singer Ellen Aim. Ellen''s former lover, soldier-for-hire Tom Cody, happens to be passing through town on a visit. In an attempt to save his star act, Ellen''s manager hires Tom to rescue her. Along with a former soldier, they battle through dangerous cityscapes, determined to get Ellen back.',NULL,NULL,3.0286,6.887,0,1.20166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1376,286805,'tt3625970',NULL,'Dark Dungeons','Dark Dungeons','movie',2014,'https://image.tmdb.org/t/p/w500/ztwYgEmSfx5tbCBDeuGx6U0Bqng.jpg','https://image.tmdb.org/t/p/original/6iWPlVHpi7v5s57uOiUIFeafhsr.jpg','College freshmen Debbie and Marcie are excited to start their new lives at a Pacific Northwest university but after being invited to a Zeta Omega Epsilon party the two suddenly find themselves in the strange and occult world of Role Playing Games.  The duo are soon hooked on the highly addictive experience that is RPGing and the game quickly becomes a habit that consumes their lives. After Debbie’s intense pagan training through the RPGs lead her to accept an invitation to join a witches’ coven, her grades begin to plummet and she is in danger of flunking out of college. She calls on darker and deeper magical forces to use a “mind bondage” spell on her professor. Meanwhile, Marcie foolishly reads from the Necronomicon and summons Cthulhu.',NULL,NULL,0.3697,2.9,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1377,60777,'tt0250793',NULL,'Ultimate Teacher','恐怖のバイオ人間 最終教師','movie',1988,'https://image.tmdb.org/t/p/w500/hUrx9cWLiAsvfWA9yQmQlzUeO6.jpg','https://image.tmdb.org/t/p/original/kKQFWJKYDIGXQM4SVCpK9jN8R6n.jpg','At a run down school the "Ultimate Teacher" Ganpachi is sent to get things back on track and prepare the delinquent students for the real world. But the students don''t want Ganpachi ruining the gang they got going so their boss, Hinako, fights back Ganpachi aided by her secret power...her lucky kitty underwear. Things get more interesting when we findout Ganpachi is the result of genetic experiments.',NULL,NULL,0.6808,5.286,0,5.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1378,14621,'tt0097722',NULL,'Lean On Me','Lean On Me','movie',1989,'https://image.tmdb.org/t/p/w500/7xOyz2NlaoqZ6xIjJh0Goptm0tP.jpg','https://image.tmdb.org/t/p/original/f4cilOhPkg90LfH8jgzNuuVx12H.jpg','When principal Joe Clark takes over decaying Eastside High School, he''s faced with students wearing gang colors and graffiti-covered walls. Determined to do anything he must to turn the school around, he expels suspected drug dealers, padlocks doors and demands effort and results from students, staff and parents. Autocratic to a fault, this real-life educator put it all on the line.',NULL,NULL,2.6783,7.3,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1379,11379,'tt0086856',NULL,'The Adventures of Buckaroo Banzai Across the 8th Dimension','The Adventures of Buckaroo Banzai Across the 8th Dimension','movie',1984,'https://image.tmdb.org/t/p/w500/jWZh2ChereoxKgTl3AmSAKNpnmO.jpg','https://image.tmdb.org/t/p/original/rYla2HuNYbuVU0ZhszkjtGDw3si.jpg','Adventurer/surgeon/rock musician Buckaroo Banzai and his band of men, the Hong Kong Cavaliers, take on evil alien invaders from the 8th dimension.',NULL,NULL,3.6298,5.955,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1380,3176,'tt0266308',NULL,'Battle Royale','バトル・ロワイアル','movie',2000,'https://image.tmdb.org/t/p/w500/aLGKAQKgzWpJ6egyWzzC11jXBRJ.jpg','https://image.tmdb.org/t/p/original/gtYmm8HeM6CneomZ98flixAGsBe.jpg','In the future, the Japanese government captures a class of ninth-grade students and forces them to kill each other under the revolutionary "Battle Royale" act.',NULL,NULL,6.329,7.3,0,11.825,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1381,26516,'tt0047885',NULL,'Blackboard Jungle','Blackboard Jungle','movie',1955,'https://image.tmdb.org/t/p/w500/vPGvWlsMg4niyuGCSzvAiyjYNWC.jpg','https://image.tmdb.org/t/p/original/75QBPYzOgSZWiYXRWoshRuO201z.jpg','Richard Dadier is a teacher at North Manual High School, an inner-city school where many of the pupils frequently engage in anti-social behavior. Dadier makes various attempts to engage the students'' interest in education, challenging both the school staff and the pupils. He is subjected to violence as well as duplicitous schemes.',NULL,NULL,1.7231,6.9,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1382,23957,'tt0079688',NULL,'Over the Edge','Over the Edge','movie',1979,'https://image.tmdb.org/t/p/w500/qSOYYtslBhH1kXIqA3h8FgecQe7.jpg','https://image.tmdb.org/t/p/original/ijjgLPyxPrAUF551LV6cII9hYpx.jpg','A group of bored teenagers rebel against authority in the community of New Granada.',NULL,NULL,1.7227,7.097,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1383,221,'tt0048545',NULL,'Rebel Without a Cause','Rebel Without a Cause','movie',1955,'https://image.tmdb.org/t/p/w500/yHStsC8rRRfIjqRN38BQsLh6S7k.jpg','https://image.tmdb.org/t/p/original/iRUBsjkPeK21nlHqH4szJCz2Ma1.jpg','After moving to a new town, troublemaking teen Jim Stark is supposed to have a clean slate, although being the new kid in town brings its own problems. While searching for some stability, Stark forms a bond with a disturbed classmate, Plato, and falls for local girl Judy. However, Judy is the girlfriend of neighborhood tough, Buzz. When Buzz violently confronts Jim and challenges him to a drag race, the new kid''s real troubles begin.',NULL,NULL,3.4202,7.5,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1384,144662,'tt0070795',NULL,'A Thief in the Night','A Thief in the Night','movie',1972,'https://image.tmdb.org/t/p/w500/2Ro89vq51F4Q9AKyF0wwwiqFJHl.jpg','https://image.tmdb.org/t/p/original/vydt0FSMu3LLQQzZAIP7GrUYdTu.jpg','Patty, a young woman caught up in living for the present with little concern for the future, awakens one day to find her husband missing and the radio reporting that millions of people around the globe have mysteriously vanished. As dramatic, earth-shaking events begin to unfold around her, Patty realizes she is living in the end times spoken of in biblical prophecy.',NULL,NULL,0.2969,5.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1385,1630433,'tt39744394',NULL,'The Red Line','เส้นตาย สายลวง','movie',2026,'https://image.tmdb.org/t/p/w500/q3ROA6OqVA9rWSsC2DzdkPQvxWW.jpg','https://image.tmdb.org/t/p/original/qbbx3NDw6FrtQSrKdxn9n72xJzO.jpg','Three women fall prey to a ruthless phone scam. To settle the score, they''ll take on the criminal network that stole their money — and their dignity.',NULL,NULL,7.0137,6.783,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1386,1809,'tt0292644',NULL,'The Rules of Attraction','The Rules of Attraction','movie',2002,'https://image.tmdb.org/t/p/w500/6OybelUmwUkDm7fbX1BI7OhpYeQ.jpg','https://image.tmdb.org/t/p/original/yTHvJqk7IFqnDCBBQ0ou60p2qvO.jpg','The incredibly spoiled and overprivileged students of Camden College are a backdrop for an unusual love triangle between a drug dealer, a virgin and a bisexual classmate.',NULL,NULL,2.8471,6.2,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1387,26326,'tt0079813',NULL,'Rock ''n'' Roll High School','Rock ''n'' Roll High School','movie',1979,'https://image.tmdb.org/t/p/w500/kxoDBrtLqMsjMlfWb2caRRY92Xg.jpg','https://image.tmdb.org/t/p/original/5LIIvrECXVaWyiwWrflkOJh9og0.jpg','A group of rock-music-loving students, with the help of the Ramones, take over their school to combat its newly installed oppressive administration.',NULL,NULL,1.419,6.318,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1388,1807,'tt0363589',NULL,'Elephant','Elephant','movie',2003,'https://image.tmdb.org/t/p/w500/1a4VU9z2hxEvugHMK7VsobB9xTX.jpg','https://image.tmdb.org/t/p/original/n9irXcigQGlcub5JJ6RV1EdDW1J.jpg','Several ordinary high school students go through their daily routine as two others prepare for something more malevolent.',NULL,NULL,3.6133,7.024,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1389,9322,'tt0100263',NULL,'Nikita','Nikita','movie',1990,'https://image.tmdb.org/t/p/w500/1ulQDewUG4KKHOhpXdGKm3GdLFq.jpg','https://image.tmdb.org/t/p/original/rk56vslwBXUCcNlQ74s6gmpJqxa.jpg','A beautiful felon, sentenced to life in prison for the murder of a policeman, is given a second chance – as a secret political assassin controlled by the government.',NULL,NULL,3.0621,7.1,0,1.28433333333333337e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1390,16606,'tt0262246',NULL,'Attack the Gas Station!','주유소 습격사건','movie',1999,'https://image.tmdb.org/t/p/w500/z4EXiiifZCfqE9nc4FYhcCt12Kw.jpg','https://image.tmdb.org/t/p/original/kwAj4O11akIxRUj0mfxILKLGmK9.jpg','A quartet of disaffected Korean youths have robbed a Seoul gas station. After taking the gas station over, their wacky antics ensue; forcing the manager to sing, kidnapping customers that complain about the service, and staging fist-fights between street gang members and gas station employees; all of these reflect their own gripes against society.',NULL,NULL,1.1492,6.564,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1391,2255,'tt0118842',NULL,'Chasing Amy','Chasing Amy','movie',1997,'https://image.tmdb.org/t/p/w500/tqydORBcNlQxy3ijgSpPurgDHM2.jpg','https://image.tmdb.org/t/p/original/9dsOweKYJ6XAJteBIKEGOI0T2bf.jpg','Holden and Banky are comic book artists. Everything is going good for them until they meet Alyssa, also a comic book artist. Holden falls for her, but his hopes are crushed when he finds out she''s a lesbian.',NULL,NULL,2.9498,6.746,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1392,2640,'tt0097493',NULL,'Heathers','Heathers','movie',1989,'https://image.tmdb.org/t/p/w500/dGbVfM4WlM7uvIbyRehfPZUIgp2.jpg','https://image.tmdb.org/t/p/original/5pLaYZGbweHYULiNiRehPxYuUnn.jpg','A girl who halfheartedly tries to be part of the "in crowd" of her school meets a rebel who teaches her a more devious way to play social politics: by killing the popular kids.',NULL,NULL,4.522,7.3,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1393,323373,'tt3705412',NULL,'Deathgasm','Deathgasm','movie',2015,'https://image.tmdb.org/t/p/w500/e4dF2KRSZ0l7PaZg3XvSsCMAeNZ.jpg','https://image.tmdb.org/t/p/original/6K51xq7nKPyiPW4VbU25Xvqsmjo.jpg','Two teenage boys unwittingly summon an ancient evil entity known as The Blind One by delving into black magic while trying to escape their mundane lives.',NULL,NULL,6.0994,6.267,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1394,15895,'tt0087127',NULL,'Deathstalker','Deathstalker','movie',1983,'https://image.tmdb.org/t/p/w500/vuX0IwRF03lcNXuhRNIVbBEByqo.jpg','https://image.tmdb.org/t/p/original/1yCnjiA0maCWlCGr2vvql7jWZPP.jpg','The warrior Deathstalker is tasked by an old witch lady to obtain and unite the three powers of creation - a chalice, an amulet, and a sword - lest the evil magician Munkar get them and use them for nefarious purposes. After obtaining the sword, Deathstalker joins with other travelers going to the Big Tournament to determine the strongest warrior. The false king holds the true princess in captivity, and plots to have Deathstalker killed, and Deathstalker must fight to free the princess.',NULL,NULL,1.3784,4.808,0,1.30133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1395,28218,'tt0092860',NULL,'Deathstalker II: Duel of the Titans','Deathstalker II: Duel of the Titans','movie',1987,'https://image.tmdb.org/t/p/w500/uWWGVspUqMezWpXcaaB3yglWp8F.jpg','https://image.tmdb.org/t/p/original/bDFayg4joYfc21ynNKmRIJZKx6M.jpg','Deathstalker helps Reena the Seer out of a few jams, and she solicits his help for a bigger task. She reveals that she is actually Princess Evie, but the evil sorcerer had her abducted and cloned in order to seize control of the kingdom. Together they travel to the evil sorcerer''s stronghold to restore the princess to her rightful position, encountering challenges along the way both from the sorcerer''s goons and the fierce Amazon women.',NULL,NULL,2.2218,5.7,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1396,9387,'tt0082198',NULL,'Conan the Barbarian','Conan the Barbarian','movie',1982,'https://image.tmdb.org/t/p/w500/qw2A587Ee61IwcSOLNFRhuOACZZ.jpg','https://image.tmdb.org/t/p/original/4rICId8WQBhOIzl7iZCVvc0QoJW.jpg','A horde of rampaging warriors massacre the parents of young Conan and enslave the young child for years on The Wheel of Pain. As the sole survivor of the childhood massacre, Conan is released from slavery and taught the ancient arts of fighting. Transforming himself into a killing machine, Conan travels into the wilderness to seek vengeance on Thulsa Doom, the man responsible for killing his family. In the wilderness, Conan takes up with the thieves Valeria and Subotai. The group comes upon King Osric, who wants the trio of warriors to help rescue his daughter who has joined Doom in the hills.',NULL,NULL,7.2494,6.8,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1397,68737,'tt1121096',NULL,'Seventh Son','Seventh Son','movie',2014,'https://image.tmdb.org/t/p/w500/7Q8DfXSjcFSSQDOxz1Sk865wNqI.jpg','https://image.tmdb.org/t/p/original/2EyK8wpLdYFaS35o0worjqsiuZn.jpg','John Gregory, who is a seventh son of a seventh son and also the local spook, has protected the country from witches, boggarts, ghouls and all manner of things that go bump in the night. However John is not young anymore, and has been seeking an apprentice to carry on his trade. Most have failed to survive. The last hope is a young farmer''s son named Thomas Ward. Will he survive the training to become the spook that so many others couldn''t?',NULL,NULL,5.093,5.528,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1398,8840,'tt0116136',NULL,'DragonHeart','DragonHeart','movie',1996,'https://image.tmdb.org/t/p/w500/1J2FvxEoEKMFT9TjUdfhm0MJhZD.jpg','https://image.tmdb.org/t/p/original/xbqluNfftDJtxDsqcpx9kKme4LF.jpg','In an ancient time when majestic fire-breathers soared through the skies, a knight named Bowen comes face to face and heart to heart with the last dragon on Earth, Draco. Taking up arms to suppress a tyrant king, Bowen soon realizes his task will be harder than he''d imagined: If he kills the king, Draco will die as well.',NULL,NULL,5.1473,6.6,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1399,15035,'tt0085542',NULL,'Fire and Ice','Fire and Ice','movie',1983,'https://image.tmdb.org/t/p/w500/v0fi9KgmdsUsGtopxxRzbtQ5NIX.jpg','https://image.tmdb.org/t/p/original/tMOukv9bSjVW2AMevSmkU5l9sGb.jpg','The villainous Nekron and his mother, Queen Juliana, plot against the human race from their frigid fortress. Creating mass destruction with huge glaciers, mother and son incur the wrath of Larn, a warrior whose entire village was destroyed by ice. When Nekron''s underlings kidnap the beautiful Princess Teegra, Larn sets out to rescue her, assisted by the fierce and enigmatic Darkwolf.',NULL,NULL,3.0916,6.683,0,12.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1400,849,'tt0085811',NULL,'Krull','Krull','movie',1983,'https://image.tmdb.org/t/p/w500/izDbySIrTmID0Nh6UqcWrUvOMjU.jpg','https://image.tmdb.org/t/p/original/92C1qvCfarT0GVNtRujJywONi39.jpg','A prince and a fellowship of companions set out to rescue his bride from a fortress of alien invaders who have arrived on their home planet.',NULL,NULL,6.1309,6.05,0,1.26933333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1401,1534,'tt0446013',NULL,'Pathfinder','Pathfinder','movie',2007,'https://image.tmdb.org/t/p/w500/mME7efKNTU7jzXTgFkI1t0aQUiz.jpg','https://image.tmdb.org/t/p/original/x1iHrvnxB3IuNBiTvqdfQqeh2mk.jpg','A Viking boy is left behind after his clan battles a Native American tribe. Raised within the tribe, he ultimately becomes their savior in a fight against the Norsemen.',NULL,NULL,2.401,5.663,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1402,9626,'tt0089893',NULL,'Red Sonja','Red Sonja','movie',1985,'https://image.tmdb.org/t/p/w500/83v0W5cCSFsWpI0cAj8DRlihySN.jpg','https://image.tmdb.org/t/p/original/iWFnany1vDQ4EoBgvm7E3Pb0RyS.jpg','The tyrant Gedren seeks the total power in a world of barbarism. She raids the city Hablac and kills the keeper of a talisman that gives her great power. Red Sonja, sister of the keeper, sets out with her magic sword to overthrow Gedren.',NULL,NULL,3.6381,5.37,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1403,41215,'tt1181791',NULL,'Black Death','Black Death','movie',2010,'https://image.tmdb.org/t/p/w500/gXRERDpyT9s3m2yk6wNmrTWbZfG.jpg','https://image.tmdb.org/t/p/original/dQhVu7ZSgvgAuYAEoD9mXvqpp1.jpg','As the plague decimates medieval Europe, rumours circulate of a village immune from the plague. There is talk of a necromancer who leads the village and is able to raise the dead. A fearsome knight joined by a cohort of soldiers and a young monk are charged by the church to investigate. Their journey is filled with danger, but it''s upon entering the village that their true horror begins.',NULL,NULL,2.7335,6.074,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1404,17832,'tt0119484',NULL,'Kull the Conqueror','Kull the Conqueror','movie',1997,'https://image.tmdb.org/t/p/w500/cgKK2eCdb5LLaQBDQZbmR312q1O.jpg','https://image.tmdb.org/t/p/original/YlAjS4vKnymLPexNPhx1ChsqFr.jpg','A barbarian named Kull becomes ruler after defeating the old king in battle. In an effort to regain the throne, the former king''s heirs resurrect Akivasha, a witch queen. However, Akivasha has plans of her own for the throne, and only Kull stands in the way.',NULL,NULL,1.7761,5.015,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1405,27232,'tt0085356',NULL,'Conquest','Conquest','movie',1983,'https://image.tmdb.org/t/p/w500/fwEZHv3nksttbsSkRYAdb5dfaBn.jpg','https://image.tmdb.org/t/p/original/5if7wtyH95UM8QuTKuSp5Quc1L2.jpg','To mark his passage into manhood, young Ilias is gifted a magical bow by his father and embarks upon a journey into the wilderness to rid the land of evil, all the while battling the witch Ocron, who wishes to steal the bow for her own nefarious ends.',NULL,NULL,1.3818,5.261,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1406,40104,'tt0087142',NULL,'The Devil''s Sword','Golok Setan','movie',1984,'https://image.tmdb.org/t/p/w500/26XunDjetXxQzNqg2GwWzFU44xp.jpg','https://image.tmdb.org/t/p/original/gmiL67rZHOlRCPDkv8dBH9lYTDm.jpg','A legendary warrior embarks on a deadly quest to retrieve the cursed Devil’s Sword, a mystical weapon with dark powers capable of unleashing unimaginable destruction. When the sword falls into the wrong hands, chaos, and bloodshed follow. Now, it’s up to our hero to confront an army of evil warriors, deadly assassins, and supernatural creatures in a battle for the fate of the world.',NULL,NULL,1.4355,5.159,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1407,13945,'tt0084749',NULL,'The Sword and the Sorcerer','The Sword and the Sorcerer','movie',1982,'https://image.tmdb.org/t/p/w500/3804sBcpgNvpNpLc53hb4MMB6f7.jpg','https://image.tmdb.org/t/p/original/2UPzDBkfOsClubCtG6Hk44jI2rT.jpg','A mercenary with a three-bladed sword rediscovers his royal heritage when he is recruited to help a princess foil a brutal tyrant and a powerful sorcerer''s plans to conquer the land.',NULL,NULL,1.874,5.493,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1408,10336,'tt0120177',NULL,'Spawn','Spawn','movie',1997,'https://image.tmdb.org/t/p/w500/3svvunKXkhRvEKByGDua1Qu0otq.jpg','https://image.tmdb.org/t/p/original/cSR1BXlqaKXhexFQQU4NJdI3KDy.jpg','After being murdered by corrupt colleagues in a covert government agency, Al Simmons makes a pact with the devil to be resurrected to see his beloved wife Wanda. In exchange for his return to Earth, Simmons agrees to lead Hell''s Army in the destruction of mankind.',NULL,NULL,5.1774,5.46,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1409,16441,'tt0083630',NULL,'The Beastmaster','The Beastmaster','movie',1982,'https://image.tmdb.org/t/p/w500/ytaKNYpHdQnClTbWL2m19Xv6PXZ.jpg','https://image.tmdb.org/t/p/original/zHTnieWaWlObW2wLQO3ePkwHlom.jpg','Dar, the son of a king, is hunted by a priest after his birth and grows up in another family. When he becomes a grown man, his new father is murdered by savages and he discovers that he has the ability to communicate with animals, which leads him on a quest for revenge against his father''s killers.',NULL,NULL,3.2013,6.3,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1410,16225,'tt0119273',NULL,'Heavy Metal 2000','Heavy Metal 2000','movie',2000,'https://image.tmdb.org/t/p/w500/dCggUkmi3Fyc1HrSnyaSxKPrG4n.jpg','https://image.tmdb.org/t/p/original/f5C03doOWiauu37bToKXtpgP5bS.jpg','Upon discovery of a shard of what could be the Loc-Nar, a miner named Tyler becomes possessed with an insatiable hunger for power and a thirst for immortality. On his way to the planet of youth, Tyler wipes out most of a space colony and kidnaps a beautiful young woman. His only mistake is that he doesn''t kill her sister, Julie, who then sets out on a mission of rescue and revenge.',NULL,NULL,2.383,6.0,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1411,11649,'tt0093507',NULL,'Masters of the Universe','Masters of the Universe','movie',1987,'https://image.tmdb.org/t/p/w500/gaUecXFd31V68yOTJPJYaB9YhAf.jpg','https://image.tmdb.org/t/p/original/2O19YXjdom34ecJPwqGTvYGHvFy.jpg','When the evil Skeletor finds a mysterious power called the Cosmic Key, he becomes nearly invincible, seizing Castle Grayskull and the surrounding city. The Sorceress is now Skeletor''s prisoner and he begins to drain her life-force as he waits for the moon of Eternia to align with the Great Eye of the Universe which will bestow god-like power upon him. However, courageous warrior He-Man locates the locksmith inventor Gwildor, who created the Key and has another version of it. During a battle, one of the Keys is transported to Earth, where it is found by teenagers Julie and Kevin. Now, both He-Man and Skeletor''s forces arrive on Earth searching for the potent weapon.',NULL,NULL,15.1802,5.8,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1412,392139,'tt0345239',NULL,'Flesh and Blood','Flesh and Blood','movie',2002,'https://image.tmdb.org/t/p/w500/qvsmvHUgpoe4mzO3ajlNMK9uJF1.jpg',NULL,'A man who was adopted at birth traces his real parents, and discovers that they have severe learning disabilities and do not know he exists.',NULL,NULL,0.8168,5.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1413,32985,'tt0970452',NULL,'Solomon Kane','Solomon Kane','movie',2009,'https://image.tmdb.org/t/p/w500/jwwVNuGRUBXcudG6wOKP9U60BzU.jpg','https://image.tmdb.org/t/p/original/5BqdQshlGWtn43YIFHIlYJzhFsR.jpg','A nomadic 16th century warrior, condemned to hell for his brutal past, seeks redemption by renouncing violence, but finds some things are worth burning for as he fights to free a young Puritan woman from the grip of evil.',NULL,NULL,5.3605,6.039,0,12.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1414,493529,'tt2906216',NULL,'Dungeons & Dragons: Honor Among Thieves','Dungeons & Dragons: Honor Among Thieves','movie',2023,'https://image.tmdb.org/t/p/w500/v7UF7ypAqjsFZFdjksjQ7IUpXdn.jpg','https://image.tmdb.org/t/p/original/AdBXP8e6K3FYdDrMx3Wr6WZqCYF.jpg','A charming thief and a band of unlikely adventurers undertake an epic heist to retrieve a lost relic, but things go dangerously awry when they run afoul of the wrong people.',NULL,NULL,9.0011,7.357,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1415,795522,'tt3885422',NULL,'The Spine of Night','The Spine of Night','movie',2021,'https://image.tmdb.org/t/p/w500/fn2Qf36nD7CvduaaJ1EbLdSpDo7.jpg','https://image.tmdb.org/t/p/original/hqS6WKgGBKZITXLCiBBIBfxvE2J.jpg','When ancient dark magic falls into sinister hands and unleashes ages of suffering onto mankind, a group of heroes from different eras and cultures must band together in order to defeat it at all costs.',NULL,NULL,1.5825,5.98,0,1.2709999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1416,705015,'tt11463324',NULL,'Inspector Ike','Inspector Ike','movie',2020,'https://image.tmdb.org/t/p/w500/rPdMgFvIQQHntooSjhN1NlVbs4Y.jpg','https://image.tmdb.org/t/p/original/5s3E49gFk2Mr9Xaoa2RkYrVYXIN.jpg','After the conniving understudy of an avant-garde theater group knocks off the star actor, he finds himself in a high-stakes game of cat-and-mouse with Inspector Ike, New York City''s Greatest Police Detective.',NULL,NULL,0.4405,6.5,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1417,1608921,NULL,NULL,'Short cuts : L''Armée des 12 singes de Terry Gilliam','Short cuts : L''Armée des 12 singes de Terry Gilliam','movie',2026,'https://image.tmdb.org/t/p/w500/vsD5b9yGOf5w5drpibacuAEJqu5.jpg',NULL,'',NULL,NULL,0.5183,5.5,0,1.60183333333333344e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1418,16858,'tt0078754',NULL,'All That Jazz','All That Jazz','movie',1979,'https://image.tmdb.org/t/p/w500/culCEdj4srLljefgn4XKd6k3C5t.jpg','https://image.tmdb.org/t/p/original/u218sykbUQIh6EWtTdJzguU5LcG.jpg','Joe Gideon is at the top of the heap, one of the most successful directors and choreographers in musical theater. But he can feel his world slowly collapsing around him - his obsession with work has almost destroyed his personal life, and only his bottles of pills keep him going.',NULL,NULL,3.0513,7.5,0,14.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1419,11542,'tt0080360',NULL,'Altered States','Altered States','movie',1980,'https://image.tmdb.org/t/p/w500/fsoaPN5SWYgZ4B7GG9nRNj33so.jpg','https://image.tmdb.org/t/p/original/4iJQItnH2qmV7fZVDGvdE4XyxcO.jpg','A research scientist explores the boundaries and frontiers of human consciousness. Using sensory deprivation and hallucinogenic mixtures from Native American shamans, he explores these altered states of cognizance and finds that memory, time, and reality itself are states of mind.',NULL,NULL,2.2313,6.7,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1420,186745,'tt0074141',NULL,'Rape of Love','L''Amour violé','movie',1978,'https://image.tmdb.org/t/p/w500/qVGL9xgGCzXtRwexUTmpz7z1MVg.jpg','https://image.tmdb.org/t/p/original/xGJT18qN8lzELAnHRyfoe1vLTiI.jpg','Nicole, nurse in Grenoble, is raped one night by four men. Deeply scarred, emotionally and physically, she thinks she will never recover from the trauma. Following a friend''s advice, she decides to file a lawsuit.',NULL,NULL,46.6635,5.8,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1421,13483,'tt0211933',NULL,'Awake','Awake','movie',2007,'https://image.tmdb.org/t/p/w500/xqooV6lR1Kdx4Q52Sim0aGbDTYP.jpg','https://image.tmdb.org/t/p/original/nAVntSurtINQNtYPU7ijgCtgz7W.jpg','While undergoing heart surgery, a man experiences a phenomenon called ‘anesthetic awareness’, which leaves him awake but paralyzed throughout the operation. As various obstacles present themselves, his wife must make life-altering decisions while wrestling with her own personal drama.',NULL,NULL,2.587,6.572,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1422,462183,'tt6126506',NULL,'Wild Awakening','Salvaje despertar','movie',2016,'https://image.tmdb.org/t/p/w500/jD9MILmkIeBBoFJbOjHAaCQ3sEA.jpg','https://image.tmdb.org/t/p/original/lJJUpqjlZYKxIO1YdlmA15pa1Bf.jpg','Toni and Emma are brother and sister who owns a stable farm. Ramon and his son, Aaron works for them. Toni is openly gay and loves to party, Emma has a crush on Aaron who is a closeted gay who is afraid that his father might find out, but his father also has a secret.',NULL,NULL,4.2673,5.3,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1423,819876,'tt14549466',NULL,'Crimes of the Future','Crimes of the Future','movie',2022,'https://image.tmdb.org/t/p/w500/RAFYMC0NgK9In9aGY6k6wsIL8w.jpg','https://image.tmdb.org/t/p/original/sqdsuvy8X6Maila4IAc7deMtPAA.jpg','With his partner Caprice, celebrity performance artist Saul Tenser publicly showcases the metamorphosis of his organs in avant-garde performances. An investigator from the National Organ Registry obsessively tracks their movements, which is when a mysterious group is revealed... Their mission — to use Tenser''s notoriety to shed light on the next phase of human evolution.',NULL,NULL,3.4017,6.012,0,13.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1424,115100,'tt1798181',NULL,'Enemy At The Dead End','죽이고 싶은','movie',2010,'https://image.tmdb.org/t/p/w500/oIRYCJ47FU4z8G8MK4WMptH842o.jpg','https://image.tmdb.org/t/p/original/p5w4BR4AhkOV5JR5b5FYzSPR1m4.jpg','A post-traumatic stress disorder patient bound to his bed finds himself sharing his room with a gang looking for a paralyzed amnesia patient. And he must kill him off before he is recognized.',NULL,NULL,0.7699,6.3,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1425,171372,'tt1605717',NULL,'Frank','Frank','movie',2014,'https://image.tmdb.org/t/p/w500/mGzqs4CHW8LomreoPATnyrTXk7j.jpg','https://image.tmdb.org/t/p/original/jBkKw0GSAOTBsnar5RstD7MzkmL.jpg','A young wannabe musician discovers he has bitten off more than he can chew when he joins an eccentric pop band led by the mysterious and enigmatic Frank.',NULL,NULL,1.3097,6.843,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1426,1279493,'tt32321803',NULL,'The Get Out','The Get Out','movie',2026,'https://image.tmdb.org/t/p/w500/zlkeH0s7dDxcnuPcHBqAyXFUxqN.jpg','https://image.tmdb.org/t/p/original/mVHyU4pnu9b2LWByPGGM0GGCA1v.jpg','A nightclub owner is on the verge of leaving his dangerous past behind for retirement with his girlfriend. When masked gunmen rob him and he finds himself squeezed by ruthless cartels, a mysterious newcomer arrives with an interest in buying the business. With danger closing in from all sides, he must navigate a deadly web of deception, power, and survival  -  where escape may no longer be an option.',NULL,NULL,131.4427,6.4,0,11.545,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1427,9740,'tt0212985',NULL,'Hannibal','Hannibal','movie',2001,'https://image.tmdb.org/t/p/w500/v5wAZwRqpGWmyAaaJ8BBHYuNXnj.jpg','https://image.tmdb.org/t/p/original/3Nb9AQaq3elLNCUBxG8VprmqfhZ.jpg','After having successfully eluded the authorities for years, Hannibal peacefully lives in Italy in disguise as an art scholar. Trouble strikes again when he''s discovered leaving a deserving few dead in the process. He returns to America to make contact with now disgraced Agent Clarice Starling, who is suffering the wrath of a malicious FBI rival as well as the media.',NULL,NULL,1.4309,6.8,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1428,45698,'tt0070628',NULL,'The Hourglass Sanatorium','Sanatorium pod Klepsydrą','movie',1973,'https://image.tmdb.org/t/p/w500/wV6LsDuRHPGbQqRsaAAu3xHgflW.jpg','https://image.tmdb.org/t/p/original/ljvMYpPSsW51rRABYkyNLnDvfvb.jpg','Jozef visits a dilapidated Sanatorium to see his father. Jozef undertakes a strange journey through the many rooms of the sanatorium, each which conjures worlds composed of his memories, dreams and nightmares.',NULL,NULL,1.5783,7.536,0,1.30466666666666668e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1429,86829,'tt2042568',NULL,'Inside Llewyn Davis','Inside Llewyn Davis','movie',2013,'https://image.tmdb.org/t/p/w500/nNxK3pC3DMpPpWKMvo2p3liREVT.jpg','https://image.tmdb.org/t/p/original/kdkCTC6Cl20TJSf4B1eIJXAFeXl.jpg','In Greenwich Village in the early 1960s, gifted but volatile folk musician Llewyn Davis struggles with money, relationships, and his uncertain future.',NULL,NULL,4.0921,7.186,0,13.645,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1430,12109,'tt0388139',NULL,'It''s All Gone Pete Tong','It''s All Gone Pete Tong','movie',2004,'https://image.tmdb.org/t/p/w500/4AvbVwbejmSMKGEdLmVYDLAss1i.jpg','https://image.tmdb.org/t/p/original/o3prcL5cI97VFmhN6yVDgnulz8R.jpg','A comedy following the tragic life of the legendary Frankie Wilde. The story takes us through Frankie''s life from being one of the best DJs alive, through a subsequent battle with a hearing disorder, culminating in his mysterious disappearance from the scene.',NULL,NULL,1.2732,6.547,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1431,16328,'tt0067277',NULL,'Johnny Got His Gun','Johnny Got His Gun','movie',1971,'https://image.tmdb.org/t/p/w500/ryIY3FPmTtXu9g6W4I69qCdkxKj.jpg','https://image.tmdb.org/t/p/original/cnf41Zu7ue1VgYdJEIYRC9w5yhS.jpg','A young American soldier, rendered in pseudocoma from an artillery shell from WWI, recalls his life leading up to that point.',NULL,NULL,1.7831,7.476,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1432,8619,'tt0311113',NULL,'Master and Commander: The Far Side of the World','Master and Commander: The Far Side of the World','movie',2003,'https://image.tmdb.org/t/p/w500/s1cVTQEZYn4nSjZLnFbzLP0j8y2.jpg','https://image.tmdb.org/t/p/original/zMHyNxNt4zhL939XX8QLBW3gWfu.jpg','After an abrupt and violent encounter with a French warship inflicts severe damage upon his ship, a captain of the British Royal Navy begins a chase over two oceans to capture or destroy the enemy, though he must weigh his commitment to duty and ferocious pursuit of glory against the safety of his devoted crew, including the ship''s thoughtful surgeon, his best friend.',NULL,NULL,4.1423,7.198,0,1.26433333333333344e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1433,97020,'tt1234721',NULL,'RoboCop','RoboCop','movie',2014,'https://image.tmdb.org/t/p/w500/gM5ql3BKYmHG3WtZ0buKXN7xY8O.jpg','https://image.tmdb.org/t/p/original/xACuC5FwpCdayrcCsJPxYzrl8BO.jpg','In RoboCop, the year is 2028 and multinational conglomerate OmniCorp is at the center of robot technology.  Overseas, their drones have been used by the military for years, but have been forbidden for law enforcement in America.  Now OmniCorp wants to bring their controversial technology to the home front, and they see a golden opportunity to do it.  When Alex Murphy – a loving husband, father and good cop doing his best to stem the tide of crime and corruption in Detroit – is critically injured, OmniCorp sees their chance to build a part-man, part-robot police officer.  OmniCorp envisions a RoboCop in every city and even more billions for their shareholders, but they never counted on one thing: there is still a man inside the machine.',NULL,NULL,5.9746,5.886,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1434,244403,'tt1798243',NULL,'Rudderless','Rudderless','movie',2014,'https://image.tmdb.org/t/p/w500/ka3gEmHph5FTJouSdOOK02Ck6bx.jpg','https://image.tmdb.org/t/p/original/aSrP7Xmk4EDL1iqWX2cbtnXqmT7.jpg','A grieving father in a downward spiral stumbles across a box of his recently deceased son''s demo tapes and lyrics. Shocked by the discovery of this unknown talent, he forms a band in the hope of finding some catharsis.',NULL,NULL,1.6642,7.171,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1435,839640,'tt12227948',NULL,'The Country I Saw, Part 3','내가 본 나라 3','movie',2009,'https://image.tmdb.org/t/p/w500/plyiG0xAkrMZWy1kEC5Rz9lSu7s.jpg',NULL,'Having already added to the tensions between North Korea and Japan, a university professor finds that her views are considered even more dangerous now. Things quickly take a turn for the worse when missiles are launched from North Korea directly over Japanese air space.',NULL,NULL,0.4406,0.0,0,11.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1436,951491,'tt21807222',NULL,'Saw X','Saw X','movie',2023,'https://image.tmdb.org/t/p/w500/u7Lp1Hi8aBS73jv4KRMIv5aK4ax.jpg','https://image.tmdb.org/t/p/original/uUJp5I4IbzuhdUiEx4R9OAoFpbz.jpg','Between the events of ''Saw'' and ''Saw II'', a sick and desperate John Kramer travels to Mexico for a risky and experimental medical procedure in hopes of a miracle cure for his cancer, only to discover the entire operation is a scam to defraud the most vulnerable. Armed with a newfound purpose, the infamous serial killer returns to his work, turning the tables on the con artists in his signature visceral way through devious, deranged, and ingenious traps.',NULL,NULL,6.3981,7.164,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1437,788734,'tt18816518',NULL,'Sick of Myself','Syk pike','movie',2022,'https://image.tmdb.org/t/p/w500/ynePU5z7JFn2Gf82RmfZgV84H8X.jpg','https://image.tmdb.org/t/p/original/lJXHuyY622HcA0RHJvkeJcvzamK.jpg','Increasingly overshadowed by her boyfriend''s recent rise to fame as a contemporary artist creating sculptures from stolen furniture, Signe hatches a vicious plan to reclaim her rightfully deserved attention within the milieu of Oslo''s cultural elite.',NULL,NULL,1.4973,7.173,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1438,502356,'tt6718170',NULL,'The Super Mario Bros. Movie','The Super Mario Bros. Movie','movie',2023,'https://image.tmdb.org/t/p/w500/qNBAXBIQlnOThrVvA6mA2B5ggV6.jpg','https://image.tmdb.org/t/p/original/9n2tJBplPbgR2ca05hS5CKXwP2c.jpg','While working underground to fix a water main, Brooklyn plumbers—and brothers—Mario and Luigi are transported down a mysterious pipe and wander into a magical new world. But when the brothers are separated, Mario embarks on an epic quest to find Luigi.',NULL,NULL,33.5716,7.604,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1439,376134,'tt5155780',NULL,'The Discovery','The Discovery','movie',2017,'https://image.tmdb.org/t/p/w500/nLIDouFvreSrs8xK62zuvpEPDw0.jpg','https://image.tmdb.org/t/p/original/dA7YLnc5ztTGiVPWz3GsaMRRz9r.jpg','In the near future, due to a breakthrough scientific discovery by Dr. Thomas Harbor, there is now definitive proof of an afterlife. While countless people have chosen suicide to reset their existence, others try to decide what it all means. Among them is Dr. Harbor''s son Will, who has arrived at his father''s isolated compound with a mysterious young woman named Isla. There, they discover the strange acolytes who help Dr. Harbor with his experiments.',NULL,NULL,2.2582,6.261,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1440,2013,'tt0401383',NULL,'The Diving Bell and the Butterfly','Le Scaphandre et le Papillon','movie',2007,'https://image.tmdb.org/t/p/w500/6NkJ4gnLrvLj0PZDW6sNM85JMbj.jpg','https://image.tmdb.org/t/p/original/8v9UL4hL4WDC58IrKb9bkBz0kIQ.jpg','Jean-Dominique Bauby, editor-in-chief of French fashion bible Elle magazine, has a devastating stroke at age 43. The damage to his brain stem results in locked-in syndrome, with which he is almost completely paralyzed and only able to communicate by blinking an eye. Bauby painstakingly dictates his memoir via the only means of expression left to him.',NULL,NULL,2.1591,7.571,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1441,244786,'tt2582802',NULL,'Whiplash','Whiplash','movie',2014,'https://image.tmdb.org/t/p/w500/7fn624j5lj3xTme2SgiLCeuedmO.jpg','https://image.tmdb.org/t/p/original/wbQa0EnWUyRzQ5d1pHLNRlmsCUP.jpg','Under the direction of a ruthless instructor, a talented young drummer begins to pursue perfection at any cost, even his humanity.',NULL,NULL,27.8101,8.376,0,1.23733333333333312e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1442,515195,'tt8079248',NULL,'Yesterday','Yesterday','movie',2019,'https://image.tmdb.org/t/p/w500/9fYka5CQt9nrb6LOtKicysUf9NA.jpg','https://image.tmdb.org/t/p/original/t5Kp02Jzixl0KfpwthHp9ZUex9t.jpg','A struggling musician realizes he''s the only person on Earth who can remember The Beatles after waking up in an alternate reality where the group was forgotten.',NULL,NULL,2.8989,6.687,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1443,9270,'tt0393109',NULL,'Brick','Brick','movie',2006,'https://image.tmdb.org/t/p/w500/5WVk8JpNIxepn4fpZzQeCumkOL5.jpg','https://image.tmdb.org/t/p/original/sDr2KjWpEbJ8M1F88rEmhoczLkX.jpg','A teenage loner pushes his way into the underworld of a high school crime ring to investigate the disappearance of his ex-girlfriend.',NULL,NULL,2.3333,6.818,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1444,351211,'tt1540011',NULL,'Blair Witch','Blair Witch','movie',2016,'https://image.tmdb.org/t/p/w500/Ai73frMEz68bibFGRlPKdWBaIaq.jpg','https://image.tmdb.org/t/p/original/vFktlnv1cEKeyCuSLd02DVNUoRC.jpg','Students on a camping trip discover something sinister is lurking beyond the trees.',NULL,NULL,2.6087,5.248,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1445,1062528,'tt15560132',NULL,'Lovely, Dark, and Deep','Lovely, Dark, and Deep','movie',2023,'https://image.tmdb.org/t/p/w500/d4maZqH6a4vOUKuFzUrARZAiNc3.jpg','https://image.tmdb.org/t/p/original/59oZSqxeBVwRgye5gWjGjAHHM7o.jpg','Lennon, a new back-country ranger, travels alone through the dangerous wilderness, hoping to uncover the origins of a tragedy that has haunted her since she was a child.',NULL,NULL,0.6978,5.022,0,9.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1446,8066,'tt0371257',NULL,'Stay','Stay','movie',2005,'https://image.tmdb.org/t/p/w500/nrLZVP8jG0KBcabahRPp6UP7Oy2.jpg','https://image.tmdb.org/t/p/original/eUNQJ0XKHoGDDQzj1Y4WhE5zAFJ.jpg','Psychiatrist Sam Foster has a new patient, Henry Letham, who claims to be suicidal. In trying to diagnose him, Sam visits Henry''s prior therapist and also finds Henry''s mother -- even though Henry has said that he murdered both of his parents. As reality starts to contradict fact, Sam spirals into an unstable mental state. Then he finds a clue as to how and when Henry may try to kill himself, and races to try to stop him.',NULL,NULL,3.6509,6.6,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1447,10836,'tt0264508',NULL,'Dagon','Dagon','movie',2001,'https://image.tmdb.org/t/p/w500/8S648eMKObi8ERFS7cSYDocxSaZ.jpg','https://image.tmdb.org/t/p/original/nO8lpaJLo1UVIXL7eM5ewwudvtY.jpg','A boating accident off the coast of Spain sends Paul and his girlfriend Barbara to the decrepit fishing village of Imboca. As night falls, people start to disappear and things not quite human start to appear. Paul is pursued by the entire town. Running for his life, he uncovers Imboca''s secret..they worship Dagon, a monstrous god of the sea...and Dagon''s unholy offspring are on the loose...',NULL,NULL,3.2279,6.1,0,12.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1448,3558,'tt0172493',NULL,'Girl, Interrupted','Girl, Interrupted','movie',1999,'https://image.tmdb.org/t/p/w500/dOBdatHIVppvmRFw2z7bf9VKJr9.jpg','https://image.tmdb.org/t/p/original/jDePFWhpfkY4GJm41qiRffJ0NGq.jpg','Set in the changing world of the late 1960s, Susanna Kaysen''s prescribed "short rest" from a psychiatrist she had met only once becomes a strange, unknown journey into Alice''s Wonderland, where she struggles with the thin line between normal and crazy. Susanna soon realizes how hard it is to get out once she has been committed, and she ultimately has to choose between the world of people who belong inside or the difficult world of reality outside.',NULL,NULL,8.0664,7.566,0,1.28540000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1449,50837,'tt1441326',NULL,'Martha Marcy May Marlene','Martha Marcy May Marlene','movie',2011,'https://image.tmdb.org/t/p/w500/bgB4sa9UfCyGdamfKAZXyEWuAwR.jpg','https://image.tmdb.org/t/p/original/eN60BXsEWxFfgatPpYbGMVO5qdM.jpg','After several years of living with a cult, Martha finally escapes and calls her estranged sister, Lucy, for help. Martha finds herself at the quiet Connecticut home Lucy shares with her new husband, Ted, but the memories of what she experienced in the cult make peace hard to find. As flashbacks continue to torment her, Martha fails to shake a terrible sense of dread, especially in regard to the cult''s manipulative leader.',NULL,NULL,3.301,6.579,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1450,553,'tt0276919',NULL,'Dogville','Dogville','movie',2003,'https://image.tmdb.org/t/p/w500/lraVawavIXh5geMlVjpzCw9TGwR.jpg','https://image.tmdb.org/t/p/original/r3xsFBD1VTUusk393bBc7SsDUJe.jpg','A woman on the run from the mob is reluctantly accepted in a small Colorado community in exchange for labor, but when a search visits the town, she learns that their support has a price.',NULL,NULL,4.0364,7.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1451,65507,'tt0298120',NULL,'Purgatory House','Purgatory House','movie',2003,'https://image.tmdb.org/t/p/w500/du3Zee90mKeZ9mRHmIOqpK3zovC.jpg',NULL,'An inside glimpse of how it feels to be a teen in today''s disconnected world. PURGATORY HOUSE chronicles the after-life journey of Silver Strand: a lonely teen who abandons her life of turmoil and drug addiction, only to find herself caught somewhere between heaven and hell. There, she must choose whether she will accept her drab existence or discover within herself the power to change.',NULL,NULL,0.4529,7.0,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1452,9785,'tt0435670',NULL,'The Invisible','The Invisible','movie',2007,'https://image.tmdb.org/t/p/w500/vSJloUNJSKWJzQ4RbxBFKOA2p2m.jpg','https://image.tmdb.org/t/p/original/6gmgk1rWMj5USt3Q9iy05MslNeM.jpg','After an attack leaves him in limbo -- invisible to the living and also near death -- a teenager discovers the only person who might be able help him is his attacker.',NULL,NULL,2.2173,6.363,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1453,8942,'tt1152850',NULL,'Wendy and Lucy','Wendy and Lucy','movie',2008,'https://image.tmdb.org/t/p/w500/cVtF8SW4zMbculTXD52RDvmQAAR.jpg','https://image.tmdb.org/t/p/original/wUScRcpPtfFPZpWZmUIIbHLEsBJ.jpg','A near-penniless drifter''s journey to Alaska in search of work is interrupted when she loses her dog while attempting to shoplift food for it.',NULL,NULL,1.9592,6.819,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1454,25636,'tt0186253',NULL,'Jesus'' Son','Jesus'' Son','movie',2000,'https://image.tmdb.org/t/p/w500/A2lVDbF1oTuCMlh69vLnqugWEAM.jpg','https://image.tmdb.org/t/p/original/doYCHWCvXbst9vukstxxl3klBW7.jpg','A young man turns from drug addiction and petty crime to a life redeemed by a discovery of compassion.',NULL,NULL,3.8555,6.23,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1455,16725,'tt0801526',NULL,'The Tracey Fragments','The Tracey Fragments','movie',2007,'https://image.tmdb.org/t/p/w500/9a99MNftmHNTLIYHfKXtGdAV6oF.jpg','https://image.tmdb.org/t/p/original/7KPnd9oxvzrr968h2ODd0xnfFp8.jpg','Tracey Berkowitz, 15, a self-described normal girl, loses her 9-year old brother, Sonny. In flashbacks and fragments, we meet her overbearing parents and the sweet, clueless Sonny. We watch Tracey navigate high school, friendless, picked on and teased. She develops a thing for Billy Zero, a new student, imagining he''s her boyfriend. We see the day she loses Sonny and we watch her try to find him.',NULL,NULL,0.7459,5.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1456,15058,'tt0378793',NULL,'Speak','Speak','movie',2004,'https://image.tmdb.org/t/p/w500/oRjQJG2PziTl2bUvzUCFS16ncfj.jpg','https://image.tmdb.org/t/p/original/9J759jTIcQhmeeiD5bDuXI7iOoC.jpg','Freshman high-school student Melinda has refused to speak ever since she called the cops on a popular summer party. With her old friends snubbing her for being a rat, and her parents too busy to notice her troubles, she folds into herself, trying to hide her secret: that star senior Andy raped her at the party. But Melinda does manage to find solace in her art class headed by Mr. Freeman.',NULL,NULL,4.2536,7.077,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1457,1151031,'tt32246771',NULL,'Bring Her Back','Bring Her Back','movie',2025,'https://image.tmdb.org/t/p/w500/1Q3GlCXGYWELifxANYZ5OVMRVZl.jpg','https://image.tmdb.org/t/p/original/2IIKts2A9vnUdM9tTC76B8tDmuZ.jpg','Following the death of their father, a brother and sister are sent to live with a foster mother, only to learn that she is hiding a terrifying secret.',NULL,NULL,9.5084,7.352,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1458,8846,'tt0433770',NULL,'Alone','Allein','movie',2004,'https://image.tmdb.org/t/p/w500/qcRdeDMxJZs1FwhrzyCDgshnYV1.jpg','https://image.tmdb.org/t/p/original/n6OjX6YnbeEeWDcCgO0ZeTtKbah.jpg','Maria is a student at the university of Essen, Germany, living and working in a gray, unpleasant, and anonymous environment. While she has little problem finding someone for a one night stand, she rebuffs her lovers in such a rude way that they actually don''t know what''s going on. But what seems to be a negative attitude at first glance is in fact much worse: Maria is suffering from borderline syndrome, a serious psychotic disease that makes her fail to develop a continuous, reliable personality, from her own perspective as well as from the perspective of those she meets. Then one day, she bumps into Jan, a student who falls in love with her without delay. He''s awaiting a hard time when he has to learn how hard it is to stay loyal and faithful to a person who, in her own words, "has a different world inside of her head" and who feels that "there is something inside of me that eats me up."',NULL,NULL,0.41,6.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1459,515454,'tt7026488',NULL,'Come True','Come True','movie',2020,'https://image.tmdb.org/t/p/w500/hGPGRRz6FTIRed1zestdWrV2Iwd.jpg','https://image.tmdb.org/t/p/original/ewCNsgQ8m12Ul6vfDVQCOHHnJs1.jpg','Looking for an escape from her recurring nightmares, 18-year-old Sarah submits to a university sleep study, but soon realizes she''s become the conduit to a frightening new discovery.',NULL,NULL,1.6239,5.893,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1460,77949,'tt1687901',NULL,'The Awakening','The Awakening','movie',2011,'https://image.tmdb.org/t/p/w500/txmiJkl8su0jkEABLIHZBqVHrTj.jpg','https://image.tmdb.org/t/p/original/1Rw3KOjmKY4QrJ9MKugIo3F5FjO.jpg','In post–War England, a writer and sometime-ghost hunter investigates a reported haunting at a boys boarding school.',NULL,NULL,2.8001,6.389,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1461,56653,'tt0166808',NULL,'Sombre','Sombre','movie',1998,'https://image.tmdb.org/t/p/w500/wjhjIkeBaNONWoIpLusg7DSxWWt.jpg','https://image.tmdb.org/t/p/original/4STEylBCabNW3Zx689YrqAj6Hwa.jpg','A serial killer stalks a woman he befriended after her car broke down.',NULL,NULL,1.6269,6.3,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1462,398181,'tt5742374',NULL,'You Were Never Really Here','You Were Never Really Here','movie',2017,'https://image.tmdb.org/t/p/w500/nx4lUyQNEzJowcF55VAP0TQEaX0.jpg','https://image.tmdb.org/t/p/original/g2yZ1kiGwLO5AUSmtsEJeFEWghJ.jpg','A traumatized veteran, unafraid of violence, tracks down missing girls for a living. When a job spins out of control, Joe''s nightmares overtake him as a conspiracy is uncovered—leading to what may be his death trip or his awakening.',NULL,NULL,4.2063,6.545,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1463,286538,'tt3722062',NULL,'Bokeh','Bokeh','movie',2017,'https://image.tmdb.org/t/p/w500/cedeEgSeKpsFZH9z9LgWbEqILlW.jpg','https://image.tmdb.org/t/p/original/juRiTXkHfKaW5S4nZDkAleSWi4T.jpg','On a romantic getaway to Iceland, a young American couple wake up one morning to discover every person on Earth has disappeared. Their struggle to survive and to reconcile the mysterious event lead them to reconsider everything they know about themselves and the world.',NULL,NULL,1.8913,5.417,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1464,67355,'tt0119795',NULL,'No Child of Mine','No Child of Mine','movie',1997,'https://image.tmdb.org/t/p/w500/fp71SYGc6XKJ8WRXSVSpGvwQ2Wv.jpg','https://image.tmdb.org/t/p/original/3ypL04aYSYgvfgQNA63ng4k2eHF.jpg','Thirteen-year-old Kerry is repeatedly sexually abused by several adults, including at one point her mother. Her father sets her up as a prostitute. Kerry finally calls Childline and is put in a safe house, where she tries to come to terms with what has been done to her. Based on a true story, with the names changed to protect the real Kerry''s identity.',NULL,NULL,1.7035,6.775,0,7.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1465,550757,'tt0795416',NULL,'Lycan Colony','Lycan Colony','movie',2006,'https://image.tmdb.org/t/p/w500/62f9qG3DLq1VGhCYh6w64mKuZbH.jpg','https://image.tmdb.org/t/p/original/uQbHrcCCqJ1r6zZ0aMkF5kzmzgx.jpg','Some small towns hold many secrets. Two siblings and a newly settled doctor''s family are about to find out this town''s darkest secret...the hard way. The town folk are good and evil werewolves! And all things are not as they appear.',NULL,NULL,0.9823,1.9,0,7.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1466,987577,'tt23640302',NULL,'The Fifth Thoracic Vertebra','다섯 번째 흉추','movie',2023,'https://image.tmdb.org/t/p/w500/d29bvgq2WX50y1NGDOJB89IS0.jpg','https://image.tmdb.org/t/p/original/flws9qEEUCZM5EUr4QFXAZ83MsY.jpg','A creature born in an abandoned mattress travels around the country feasting on its victims’ vertebrae, struggling to break free from the bed, the mold, and its past.',NULL,NULL,0.3757,5.9,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1467,1668454,'tt41673747',NULL,'Junkhead','Junkhead','movie',2025,'https://image.tmdb.org/t/p/w500/eka3XxfyU8TqcnyuMKVgueuuWRo.jpg','https://image.tmdb.org/t/p/original/97NRLa2mt0GDyrIHr6HdgfLH5bC.jpg','After yet another relapse, Don spirals through a night of drugs, alcohol, and inner torment. Haunted by Jamie , a manifestation of his darker self, Don is forced to confront the parts of him he’s been trying to drown. As the boundary between reality and hallucination blurs, he faces the question: can he silence the voice in his head before it consumes him?',NULL,NULL,6.7884,0.0,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1468,323423,'tt0829097',NULL,'Analife','ANALIFE アナライフ','movie',2005,'https://image.tmdb.org/t/p/w500/eCYOIEcVHWQnPgw41gOPXBIr0yF.jpg','https://image.tmdb.org/t/p/original/OOmnmdKx6e6dFuuP0nXTneupbr.jpg','The story of 2 men and 1 woman who lose their virtues in order to fill the hole in their hearts. These characters are caught up in the vicious spiral created by their desires. By coincidence, or perhaps not, the three become injured anally and find themselves in the waiting room of the same proctologist. It is here that they find a way out of their seemingly never-ending cycles.',NULL,NULL,0.4481,8.7,0,4.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1469,420240,'tt5896468',NULL,'Dog Star Man','Dog Star Man','movie',1965,'https://image.tmdb.org/t/p/w500/oZbENblOS67gRW3s0LJBj00m1CL.jpg','https://image.tmdb.org/t/p/original/yM2UfbcVD0aym1zNa8acIL6Ci0M.jpg','Experimental film following a cycle of seasons as well as the stretch of a single day as a man and his dog slowly ascend a mountain.',NULL,NULL,0.211,6.4,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1470,815,'tt0387764',NULL,'Peep Show','Peep Show','tv',2003,'https://image.tmdb.org/t/p/w500/6rdoQ0cTjsEQLIwEjhBV8U98oUm.jpg','https://image.tmdb.org/t/p/original/pYEFwZj6YDR8OhX9tyO78IoJADe.jpg','Peep Show follows the lives of two men from their twenties to thirties, Mark Corrigan, who has steady employment for most of the series, and Jeremy "Jez" Usbourne, an unemployed would-be musician.',NULL,NULL,11.9596,8.018,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1471,9003,'tt0093177',NULL,'Hellraiser','Hellraiser','movie',1987,'https://image.tmdb.org/t/p/w500/3Z0oPHyLnk3Vx6ZMC1MiVwIrKhO.jpg','https://image.tmdb.org/t/p/original/jInJNDIyzlYBV79nx8Qb5s2xjfM.jpg','A hedonistic man finds a mysterious puzzle box that summons a group of gruesome beings known as the Cenobites. These otherworldly entities open the doors to a dominion where pain and pleasure are indivisible.',NULL,NULL,4.5993,6.884,0,14.62,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1472,479574,'tt3158830',NULL,'Elliot','Elliot','movie',2017,'https://image.tmdb.org/t/p/w500/2xbvCl5Rh8OGemkZihx5t4EkXtx.jpg','https://image.tmdb.org/t/p/original/juyGTfHQZdr7tyLIwfdPnvjgHtB.jpg','Set in the dark depths of a strange and mysterious power supply complex, ELLIOT tells the tale of a conflicted humanoid (Elliot) struggling to maintain his reality and understand his true identity. Elliot is thrust into a disconcerting downward spiral of despair in which he is forced to recognize the perils of his own cognition and constructed ideals in a crumbling universe where the lines between fantasy, simulation, and reality are blurred, and the fibers of Elliot’s fragile existence are ruptured.',NULL,NULL,0.2777,5.0,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1473,NULL,NULL,128698,'SuteF','SuteF','game',2010,'https://images.igdb.com/igdb/image/upload/t_cover_big/co3tol.jpg',NULL,'suteF is a puzzle platforming game where you must push boxes, grapple walls, activate switches, and avoid lasers to make your escape from the dreaded land known only as the ''Abyss.''','https://www.igdb.com/games/sutef','["PC (Microsoft Windows)"]',NULL,NULL,0,4.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1474,10155,'tt0120399',NULL,'U Turn','U Turn','movie',1997,'https://image.tmdb.org/t/p/w500/nBPTj1ApIDWo04M14rXFwLPdtr2.jpg','https://image.tmdb.org/t/p/original/rq6duKhgffOtMs9LqgyhrJ9Y8EX.jpg','When a desperate man’s car breaks down in a bizarre desert town while evading vengeful bookies, he becomes entangled in a dangerous love triangle. Caught between a married couple, he’s faced with deadly contracts to kill them both.',NULL,NULL,2.9632,6.624,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1475,6519,'tt0377818',NULL,'The Dukes of Hazzard','The Dukes of Hazzard','movie',2005,'https://image.tmdb.org/t/p/w500/2ZrNyYJEgE0VIqhelQPqFTR20xF.jpg','https://image.tmdb.org/t/p/original/luOLydz3H319kUl79MbBcfGsCgz.jpg','Cousins, Bo and Luke Duke, with the help of their eye-catching cousin, Daisy and moonshine-running Uncle Jesse, try and save the family farm from being destroyed by Hazzard County''s corrupt commissioner, Boss Hogg. Their efforts constantly find the ''Duke Boys'' eluding authorities in ''The General Lee'', their 1969 orange Dodge Charger that keeps them one step ahead of the dimwitted antics of the small southern town''s Sheriff, Roscoe P. Coltrane.',NULL,NULL,4.1286,5.623,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1476,95,'tt0120591',NULL,'Armageddon','Armageddon','movie',1998,'https://image.tmdb.org/t/p/w500/eTM3qtGhDU8cvjpoa6KEt5E2auU.jpg','https://image.tmdb.org/t/p/original/1cO6OQJxz7YhTZ4V1OlkYfebeJa.jpg','When an asteroid threatens to collide with Earth, NASA honcho Dan Truman determines the only way to stop it is to drill into its surface and detonate a nuclear bomb. This leads him to renowned driller Harry Stamper, who agrees to helm the dangerous space mission provided he can bring along his own hotshot crew. Among them is the cocksure A.J. who Harry thinks isn''t good enough for his daughter, until the mission proves otherwise.',NULL,NULL,9.5849,6.834,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1477,9768,'tt0099329',NULL,'Cry-Baby','Cry-Baby','movie',1990,'https://image.tmdb.org/t/p/w500/d2QusoWfW4azJtHtJkyLMGSv33n.jpg','https://image.tmdb.org/t/p/original/2PQTdo555CTsSfgPWCHv7sxmDxR.jpg','A prim and proper schoolgirl goes against her society grandmother''s wishes when she dates a motorcycle-riding juvenile delinquent.',NULL,NULL,3.5034,6.5,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1478,9090,'tt0114682',NULL,'To Wong Foo, Thanks for Everything! Julie Newmar','To Wong Foo, Thanks for Everything! Julie Newmar','movie',1995,'https://image.tmdb.org/t/p/w500/8bkJiI6N8wDxAtQ49bLUt0qCBII.jpg','https://image.tmdb.org/t/p/original/xga9dXEIJHAjNLGMjw4VDPH7LJB.jpg','Manhattan drag queens Vida Boheme and Noxeema Jackson impress regional judges in competition, securing berths in the Nationals in Los Angeles. When the two meet pathetic drag novice Chi-Chi Rodriguez — one of the losers that evening — the charmed Vida and Noxeema agree to take the hopeless youngster under their joined wing. Soon the three set off on a madcap road trip across America and struggle to make it to Los Angeles in time.',NULL,NULL,4.697,7.441,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1479,36826,'tt0085872',NULL,'The Loveless','The Loveless','movie',1984,'https://image.tmdb.org/t/p/w500/3aZcW9NBsLX7ZldQkDtbKkHMfUq.jpg','https://image.tmdb.org/t/p/original/dpfIsCtDkXw6zX5Dlf3En8Tygho.jpg','Trouble ensues when a motorcycle gang stops in a small southern town while heading to the races at Daytona.',NULL,NULL,1.1616,5.625,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1480,6282,'tt0200550',NULL,'Coyote Ugly','Coyote Ugly','movie',2000,'https://image.tmdb.org/t/p/w500/xYM0laKrEqjiRSQNvqRrXPXN3iL.jpg','https://image.tmdb.org/t/p/original/f2MzXz3vjuNtSPn17ugFa6oTUmc.jpg','Graced with a velvet voice, 21-year-old Violet Sanford heads to New York to pursue her dream of becoming a songwriter only to find her aspirations sidelined by the accolades and notoriety she receives at her "day" job as a barmaid at Coyote Ugly. The "Coyotes" as they are affectionately called tantalize customers and the media alike with their outrageous antics, making Coyote Ugly the watering hole for guys on the prowl.',NULL,NULL,7.5377,6.26,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1481,2105,'tt0163651',NULL,'American Pie','American Pie','movie',1999,'https://image.tmdb.org/t/p/w500/5P68by2Thn8wHAziyWGEw2O7hco.jpg','https://image.tmdb.org/t/p/original/z9DFGaWj4G4kZUWLZ6ESs1NP1Fp.jpg','At a high-school party, four friends find that losing their collective virginity isn''t as easy as they had thought. But they still believe that they need to do so before college. To motivate themselves, they enter a pact to all "score" by their senior prom.',NULL,NULL,13.353,6.613,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1482,3121,'tt0073440',NULL,'Nashville','Nashville','movie',1975,'https://image.tmdb.org/t/p/w500/twl4ovyjb8muFKvZmcCDzPR0hy1.jpg','https://image.tmdb.org/t/p/original/lHH8o3YWBjoteijAI8yTxG3qqpX.jpg','The intersecting stories of twenty-four characters—from country star to wannabe to reporter to waitress—connect to the music business in Nashville, Tennessee.',NULL,NULL,5.439,7.2,0,13.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1483,10956,'tt0245686',NULL,'Joe Dirt','Joe Dirt','movie',2001,'https://image.tmdb.org/t/p/w500/yykDEtHk6DMtZK8EaxW88YyQ054.jpg','https://image.tmdb.org/t/p/original/1g04YnMJQvWFRKOXJlUeZe1rOxF.jpg','Joe Dirt is a janitor with a mullet hairdo, acid-washed jeans and a dream to find the parents that he lost at the Grand Canyon when he was a belligerent, trailer park-raised eight-year-old. Now, blasting Van Halen in his jacked-up economy car, the irrepressibly optimistic Joe hits the road alone in search of his folks.',NULL,NULL,3.2432,5.642,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1484,9980,'tt0091499',NULL,'Maximum Overdrive','Maximum Overdrive','movie',1986,'https://image.tmdb.org/t/p/w500/8pGYesuatPnMS8lhS4NvwiDjKbG.jpg','https://image.tmdb.org/t/p/original/m6q0Q6bwJnzoMHWFCplDarmBtIK.jpg','When a comet passes close to the earth, machines all over the world come alive and go on homicidal rampages. A group of people at a desolate truck stop are held hostage by a gang of murderous 18-wheelers. The frightened people set out to defeat the killer machines…Or be killed by them.',NULL,NULL,3.1571,5.8,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1485,118075,'tt0119209',NULL,'Going All the Way','Going All the Way','movie',1997,'https://image.tmdb.org/t/p/w500/sWNjMpcmlsCJ7Sp1WzojIvh3Zpv.jpg','https://image.tmdb.org/t/p/original/lOi3quqDsAnfyvadtpfyox7m66Q.jpg','Korean War--era veterans and ex-classmates "Gunner" Casselman and "Sonny" Burns reunite upon their return home. Gunner, who spent the war years abroad, is trying to convince his mother that his gal Marty is good enough for him, while Sonny, who was stationed stateside, is torn between loyal Buddy and tempting Gale Ann. As they commiserate, the men realize that they''re outgrowing the lives they lived before the war.',NULL,NULL,1.3467,4.771,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1486,10152,'tt0329028',NULL,'Dumb and Dumberer: When Harry Met Lloyd','Dumb and Dumberer: When Harry Met Lloyd','movie',2003,'https://image.tmdb.org/t/p/w500/qxD6P3UXASFCdbrVavceZzgOfI9.jpg','https://image.tmdb.org/t/p/original/e2Ppz6IQcukpqyYYJsRkWcsGXvT.jpg','This wacky prequel to the 1994 blockbuster goes back to the lame-brained Harry and Lloyd''s days as classmates at a Rhode Island high school, where the unprincipled principal puts the pair in remedial courses as part of a scheme to fleece the school.',NULL,NULL,2.5132,4.146,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1487,17908,'tt0156812',NULL,'My Dog Skip','My Dog Skip','movie',2000,'https://image.tmdb.org/t/p/w500/nnPv7RuSn6UaPjZussIFljZdWS8.jpg','https://image.tmdb.org/t/p/original/mrhdbBV44O87ikOObJpIMuHoMNL.jpg','A shy boy is unable to make friends in Yazoo City, Mississippi in 1942, until his parents give him a terrier puppy for his ninth birthday. The dog, which he names Skip, becomes well known and loved throughout the community and enriches the life of the boy, Willie, as he grows into manhood.',NULL,NULL,2.6319,6.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1488,12163,'tt1125849',NULL,'The Wrestler','The Wrestler','movie',2008,'https://image.tmdb.org/t/p/w500/6OTR8dSoNGjWohJNo3UhIGd3Tj.jpg','https://image.tmdb.org/t/p/original/wcJmFsz8RqIhozMwvU81hreTX4i.jpg','Aging wrestler Randy "The Ram" Robinson is long past his prime but still ready and rarin'' to go on the pro-wrestling circuit. After a particularly brutal beating, however, Randy hangs up his tights, pursues a serious relationship with a long-in-the-tooth stripper, and tries to reconnect with his estranged daughter. But he can''t resist the lure of the ring and readies himself for a comeback.',NULL,NULL,4.7443,7.54,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1489,763329,'tt13453006',NULL,'Red Rocket','Red Rocket','movie',2021,'https://image.tmdb.org/t/p/w500/345gLhiNpItU1ICx8OxJQwjgPmH.jpg','https://image.tmdb.org/t/p/original/nRfJFQQ6OUVW4NV7wFzNDu57J3E.jpg','After hitting rock bottom in Los Angeles, former porn star Mikey Saber returns to his hometown in Texas to stay with his estranged wife and mother-in-law. Just as tensions begin to ease, he becomes infatuated with a young doughnut shop worker named Strawberry.',NULL,NULL,1.759,6.8,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1490,1788,'tt0087277',NULL,'Footloose','Footloose','movie',1984,'https://image.tmdb.org/t/p/w500/9JEDjBCXCx3eKTSkXwispf0UN3O.jpg','https://image.tmdb.org/t/p/original/t8n5mvmnJUYJkyfOPWYEtvqePuM.jpg','When teenager Ren and his family move from big-city Chicago to a small town in the West, he''s in for a real case of culture shock after discovering he''s living in a place where music and dancing are illegal.',NULL,NULL,4.0049,6.688,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1491,1299134,'tt15208256',NULL,'The Good Guys','The Good Guys','movie',NULL,'https://image.tmdb.org/t/p/w500/9J0vh2uve0cL5Xgu1SCNKnVQl6B.jpg',NULL,'When a pest control company is on the verge of collapse, it is up to the boss to figure out who is to blame.',NULL,NULL,0.2712,0.0,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1492,547009,'tt7422822',NULL,'Greener Grass','Greener Grass','movie',2019,'https://image.tmdb.org/t/p/w500/eN56wiM2M84GBOQnp4TAQXcZucg.jpg','https://image.tmdb.org/t/p/original/rgwaip4U0psmZu0kiuYOgwJzPrQ.jpg','Suburban soccer moms find themselves constantly competing against each other in their personal lives as their kids settle their differences on the field.',NULL,NULL,1.3422,6.187,0,1.13533333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1493,87818,'tt1333125',NULL,'Movie 43','Movie 43','movie',2013,'https://image.tmdb.org/t/p/w500/uYa06GxHsCsELx9vOQ11vsT0Aa6.jpg','https://image.tmdb.org/t/p/original/9bOjEovR9cdiFUYwZY7fyfNGWyL.jpg','A series of interconnected short films are the backdrop for a maniac screenwriter who pitches insane storylines featuring some of Hollywood''s biggest and brightest.  In some countries, like the United Kingdom and the Netherlands, the structure differs. Instead of a pitch, the films are connected by a group of three teenagers searching for the most banned film in the world, Movie 43, which will ultimately lead to the destruction of civilization.',NULL,NULL,4.5038,4.662,0,9.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1494,10683,'tt0147612',NULL,'Happiness','Happiness','movie',1998,'https://image.tmdb.org/t/p/w500/rYfUcEV88Z3gENrfYTE6i8yBkDr.jpg','https://image.tmdb.org/t/p/original/3AE92av4pGYx9NKKss7x5zEgEOS.jpg','The lives of several individuals intertwine as they go about their lives in their own unique ways, engaging in acts which society as a whole might find disturbing in a desperate search for human connection.',NULL,NULL,2.4211,7.426,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1495,928344,'tt17076046',NULL,'Weird: The Al Yankovic Story','Weird: The Al Yankovic Story','movie',2022,'https://image.tmdb.org/t/p/w500/qcj2z13G0KjaIgc01ifiUKu7W07.jpg','https://image.tmdb.org/t/p/original/8hSx5b4YfD2dzvGtrE6mdXF0xrZ.jpg','Exploring every facet of ‘Weird Al’ Yankovic’s life, from his meteoric rise to fame with early hits like ‘Eat It’ and ‘Like a Surgeon’ to his torrid celebrity love affairs and famously depraved lifestyle, this biopic takes audiences on a truly unbelievable journey through Yankovic’s life and career, from gifted child prodigy to the greatest musical legend of all time.',NULL,NULL,2.8035,6.725,0,10.27,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1496,1075,'tt0118843',NULL,'Black Cat, White Cat','Crna mačka, beli mačor','movie',1998,'https://image.tmdb.org/t/p/w500/xxQ9jgYf3xhbUTW98VtCjA1wMLv.jpg','https://image.tmdb.org/t/p/original/vx5Mla7OfNzibnVat2HQuqGrUkc.jpg','A small-time hustler makes a deal with a notorious gangster to whom he owes money: marry his teenage son to the latter''s daughter. However, the young lovers are not as agreeable.',NULL,NULL,2.835,7.7,0,8.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1497,338,'tt0301357',NULL,'Good Bye, Lenin!','Good Bye, Lenin!','movie',2003,'https://image.tmdb.org/t/p/w500/uHk1oGEbnvQGLnyiiYxTslZLoog.jpg','https://image.tmdb.org/t/p/original/uBLmfG7MyNXPXI50eMs1ZjxpbnV.jpg','Alex Kerner''s mother was in a coma while the Berlin wall fell. When she wakes up he must try to keep her from learning what happened (as she was an avid communist supporter) to avoid shocking her which could lead to another heart attack.',NULL,NULL,2.9511,7.539,0,1.21766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1498,762504,'tt10954984',NULL,'Nope','Nope','movie',2022,'https://image.tmdb.org/t/p/w500/AcKVlWaNVVVFQwro3nLXqPljcYA.jpg','https://image.tmdb.org/t/p/original/yRutvYkM3OP8N9oqqfjSK1VC7fs.jpg','Residents in a lonely gulch of inland California bear witness to an uncanny, chilling discovery.',NULL,NULL,7.1431,6.826,0,1.20233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1499,109587,'tt0365089',NULL,'The Red Colored Grey Truck','Сиви камион црвене боје','movie',2004,'https://image.tmdb.org/t/p/w500/eGJaWVzJY2k60a7kNSkw1iFVlmA.jpg','https://image.tmdb.org/t/p/original/2xTQ0djQw6e6SUKTigPFNWLh5f3.jpg','Belgrade, the summer of 1991. Yugoslavia is falling apart. Gavran can''t get a driving licence because he is color blind. He is a rural Bosnian introvert obsessed with trucks. So, as soon as he is released from prison, he steals a truck to go on a joyride. Suzana, a city girl, discovers she is pregnant, but until she''s due for an abortion, she decides to go to Dubrovnik. She hitchikes and Gavran almost runs her over. She is unhurt, but she blackmails him to take her to Dubrovnik. Two people from different worlds, equally removed from the real one. For him she is the first woman he can talk to; for her he is just another idiot to add to the long list of them that she has so far compiled. But the pressure of danger and the intimations of war force them together. The world about them has become so absurd that they seem to each other the only sober people left.',NULL,NULL,0.4579,6.817,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1500,985,'tt0122365',NULL,'Wacky Races','Wacky Races','tv',1968,'https://image.tmdb.org/t/p/w500/yHeolC3qvELoeq8poh7BsMpBKd9.jpg','https://image.tmdb.org/t/p/original/wJgLiMIaptq7jfY0tXTYQEcbevw.jpg','Wacky Races is an animated television series produced by Hanna-Barbera that originally aired in 1968. The show is a parody of traditional car races, featuring a variety of eccentric characters and their outlandish vehicles, all racing across different terrains in a madcap competition for first place.

The series is centered around a group of 11 racers, each with their own unique vehicle and distinct personality. The main characters include Dick Dastardly and his dog Muttley, who are always trying to cheat and sabotage the other competitors, although they never succeed. Other notable racers include Penelope Pitstop, the glamorous but tough driver; the adventurous Red Max; and the lovable duo, the Slag Brothers, who drive a massive, rock-like car.',NULL,NULL,4.2433,7.3,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1501,8193,'tt0374900',NULL,'Napoleon Dynamite','Napoleon Dynamite','movie',2004,'https://image.tmdb.org/t/p/w500/6Iv6Uwa2SBLN0dSGM00rdrwN4MJ.jpg','https://image.tmdb.org/t/p/original/vVMMgWiQkXNB6YpE1ecs8FsXDh2.jpg','A listless and alienated teenager decides to help his new friend win the class presidency in their small western high school, while he must deal with his bizarre family life back home.',NULL,NULL,3.2187,6.795,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1502,46788,'tt1488163',NULL,'Trash Humpers','Trash Humpers','movie',2010,'https://image.tmdb.org/t/p/w500/sNMA5i8w6MsyTKPULhJuLUHB2Wd.jpg','https://image.tmdb.org/t/p/original/zzcHLjsYwWzr76um4VZ3dbdZ03B.jpg','Follow a small group of elderly “Peeping Toms” through the shadows and margins of an unfamiliar world. Crudely documented by the participants themselves, we follow the debased and shocking actions of a group of true sociopaths the likes of which have never been seen before. Inhabiting a world of broken dreams and beyond the limits of morality, they crash against a torn and frayed America.',NULL,NULL,2.7076,5.167,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1503,17414,'tt0116151',NULL,'Dunston Checks In','Dunston Checks In','movie',1996,'https://image.tmdb.org/t/p/w500/xR2cWC04kWNr7TBeXNOf4uOqn00.jpg','https://image.tmdb.org/t/p/original/ArNNCDc3Ndg9d0PkkOYHsZeLsbo.jpg','Hotel manager Robert Grant is forced by his boss to postpone his family vacation when a hotel critic checks in. Trouble is, the critic is really a villainous jewel thief with an orangutan assistant named Dunston. When Dunston gets loose and tries to escape a life of crime -- aided by Robert''s sons -- havoc, hijinks and lots of laughs abound!',NULL,NULL,2.5131,5.424,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1504,13777,'tt0172543',NULL,'He Died with a Felafel in His Hand','He Died with a Felafel in His Hand','movie',2001,'https://image.tmdb.org/t/p/w500/ceB5SP5dmoeaQUq2RM1uANAwu0L.jpg','https://image.tmdb.org/t/p/original/6YyQkBsVOs0Ju5ojfHwwDWSXZC0.jpg','A search for love, meaning and bathroom solitude. Danny goes through a series of shared housing experiences in a succession of cities on the east coast of Australia. Together these vignettes form a narrative that is surprisingly reflective.',NULL,NULL,0.918,6.956,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1505,13685,'tt0115734',NULL,'Bottle Rocket','Bottle Rocket','movie',1996,'https://image.tmdb.org/t/p/w500/6E7mJ5wpzTFbYFbJvTzzZ8Til9C.jpg','https://image.tmdb.org/t/p/original/wWZjmgJC2m2jy4UAPtRAsakNtG7.jpg','Upon his release from a mental hospital following a nervous breakdown, the directionless Anthony joins his friend Dignan, who seems far less sane than the former. Dignan has hatched a harebrained scheme for an as-yet-unspecified crime spree that somehow involves his former boss, the (supposedly) legendary Mr. Henry.',NULL,NULL,2.0593,6.7,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1506,7512,'tt0387808',NULL,'Idiocracy','Idiocracy','movie',2006,'https://image.tmdb.org/t/p/w500/6cTHBq49ApwsJaRr3ojlY1cmiXk.jpg','https://image.tmdb.org/t/p/original/9Z4msMhKvNp63sOB1ZvxPMPvqz3.jpg','To test its top-secret Human Hibernation Project, the Pentagon picks the most average European-Americans it can find - an Army private and a prostitute - and sends them to the year 2505 after a series of freak events. But when they arrive, they find a civilization so dumbed-down that they''re the smartest people around.',NULL,NULL,7.6206,6.376,0,13.5725,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1507,848818,'tt15010292',NULL,'Flux Gourmet','Flux Gourmet','movie',2022,'https://image.tmdb.org/t/p/w500/gg9jup8MM9HjT7nvQ0h2gKDpi5W.jpg','https://image.tmdb.org/t/p/original/5nsS8KmpSLGiPvjGlBkOAhvDIPm.jpg','At an institute devoted to culinary and alimentary performance, a collective finds themselves embroiled in power struggles, artistic vendettas and gastrointestinal disorders.',NULL,NULL,0.916,5.55,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1508,324003,'tt3214344',NULL,'A Universal Language','A Universal Language','movie',2013,NULL,NULL,'A Universal Language, documents the exciting once in a life time journey of six Canadian comedians, among them Canadian comedy icon Mark Breslin, as they explore comedy, identity and history throughout the Holy Land and use the weapons of comedy to try an',NULL,NULL,0.1627,0.0,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1509,41602,'tt1196948',NULL,'Charlie Countryman','Charlie Countryman','movie',2013,'https://image.tmdb.org/t/p/w500/7BbrgKfnRfEFIePqdRcWzuHs3KI.jpg','https://image.tmdb.org/t/p/original/9iKFQ0Ka2tWL1k9baXwYoyCjZ0D.jpg','A young American falls hard for a Romanian cellist whose father has recently died -- and whose violent past could bring about his own demise.',NULL,NULL,2.457,6.384,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1510,340,'tt0404030',NULL,'Everything Is Illuminated','Everything Is Illuminated','movie',2005,'https://image.tmdb.org/t/p/w500/gk469Y3fJTlbcAkSNMZc4OtETOK.jpg','https://image.tmdb.org/t/p/original/v6DoiKp2ThK0VUgWt73JrEN4qa4.jpg','A young Jewish American man endeavors—with the help of eccentric, distant relatives—to find the woman who saved his grandfather during World War II—in a Ukrainian village which was ultimately razed by the Nazis.',NULL,NULL,2.077,7.3,0,10.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1511,11902,'tt0114787',NULL,'Underground','Подземље','movie',1995,'https://image.tmdb.org/t/p/w500/h8N6y13t4VusrDdH5PzTkwvBvgN.jpg','https://image.tmdb.org/t/p/original/2nerKhF40OzjnGGOyzHcsAw8T53.jpg','Black marketeers Marko and Blacky manufacture and sell weapons to the Communist resistance in WWII Belgrade, living the good life along the way. Marko''s surreal duplicity propels him up the ranks of the Communist Party, and he eventually abandons Blacky and steals his girlfriend. After a lengthy stay in a below-ground shelter, the couple reemerges during the Yugoslav Civil War of the 1990s as Marko sees the opportunity to exploit the situation.',NULL,NULL,2.0303,7.704,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1512,8937,'tt0938341',NULL,'Tokyo Sonata','トウキョウソナタ','movie',2008,'https://image.tmdb.org/t/p/w500/6Y0ZRyh5eH7WLY4fcF92swhtgUz.jpg','https://image.tmdb.org/t/p/original/1aAR1XHBYaqnKzRUH3bL7KpXMhs.jpg','The winds of change blow as a family grapples with unemployment, alienation, mistrust and a lack of communication. When a Japanese salaryman loses his job to outsourcing to China, it''s simply the beginning of a series of shattering incidents, leading to the implosion of the family unit.',NULL,NULL,3.8957,7.4,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1513,27337,'tt0468795',NULL,'Linda Linda Linda','リンダ リンダ リンダ','movie',2005,'https://image.tmdb.org/t/p/w500/wX3xwuJ9uhCamndfGUePDkpAggZ.jpg','https://image.tmdb.org/t/p/original/xSwyEYimb59e8Xcxvd3yZgR4249.jpg','Only three days before the school festival, a newly formed high school band rushes to put together a set for their big show — including a hit single by ''80s by the Japanese punk rock band The Blue Hearts.',NULL,NULL,1.8243,7.587,0,9.34333333333333371e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1514,480001,'tt7339248',NULL,'The Art of Self-Defense','The Art of Self-Defense','movie',2019,'https://image.tmdb.org/t/p/w500/bTq793Qwl3tCXb94zrDPAwppbsC.jpg','https://image.tmdb.org/t/p/original/cUkpSTVt0iUbIVFDxvUGs747OMW.jpg','Casey is attacked at random on the street and enlists in a local dojo led by a charismatic and mysterious Sensei in an effort to learn how to defend himself. What he uncovers is a sinister world of fraternity, violence and hypermasculinity and a woman fighting for her place in it.',NULL,NULL,1.5951,6.565,0,10.56,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1515,496243,'tt6751668',NULL,'Parasite','기생충','movie',2019,'https://image.tmdb.org/t/p/w500/7IiTTgloJzvGI1TAYymCfbfl3vT.jpg','https://image.tmdb.org/t/p/original/wCuUKiRaz0wEESsYqmQy005xvTE.jpg','All unemployed, Ki-taek''s family takes peculiar interest in the wealthy and glamorous Parks for their livelihood until they get entangled in an unexpected incident.',NULL,NULL,28.995,8.491,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1516,666277,'tt13238346',NULL,'Past Lives','Past Lives','movie',2023,'https://image.tmdb.org/t/p/w500/k3waqVXSnvCZWfJYNtdamTgTtTA.jpg','https://image.tmdb.org/t/p/original/7HR38hMBl23lf38MAN63y4pKsHz.jpg','After decades apart, childhood friends Nora and Hae Sung are reunited in New York for one fateful weekend as they confront notions of destiny, love, and the choices that make a life.',NULL,NULL,10.4821,7.7,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1517,585378,'tt8633464',NULL,'After Yang','After Yang','movie',2022,'https://image.tmdb.org/t/p/w500/qjEuDeKOhA7JqaaqhLSfoS9titb.jpg','https://image.tmdb.org/t/p/original/y8ZholsWIn4jR3JoDWOSSFY87vf.jpg','When his young daughter''s beloved companion — an android named Yang — malfunctions, Jake searches for a way to repair him. In the process, Jake discovers the life that has been passing in front of him, reconnecting with his wife and daughter across a distance he didn''t know was there.',NULL,NULL,2.4678,6.4,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1518,795811,'tt14034966',NULL,'Wheel of Fortune and Fantasy','偶然と想像','movie',2021,'https://image.tmdb.org/t/p/w500/z3xqVWOsetW6pSEgx1uiqXfzRet.jpg','https://image.tmdb.org/t/p/original/58IBSEDDSzOEFowz9qs9QbUZ8bg.jpg','An unexpected love triangle, a seduction trap, and a random encounter are the three episodes, told in three movements to depict three female characters and trace the trajectories between their choices and regrets.',NULL,NULL,2.2922,7.206,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1519,976893,'tt27503384',NULL,'Perfect Days','PERFECT DAYS','movie',2023,'https://image.tmdb.org/t/p/w500/mjEk5Wwx6TYVqw29zSaUHclMIgp.jpg','https://image.tmdb.org/t/p/original/hjWxngV6tidwDkfJDEgMjHD2KEz.jpg','Hirayama is content with his life as a toilet cleaner in Tokyo. Outside of his structured routine, he cherishes music on cassette tapes, books, and taking photos of trees. Through unexpected encounters, he reflects on finding beauty in the world.',NULL,NULL,18.4571,7.802,0,1.73774999999999977e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1520,1208348,'tt14142060',NULL,'Rental Family','Rental Family','movie',2025,'https://image.tmdb.org/t/p/w500/A5lswNlytTUrnMWsuD0NFfhZlf3.jpg','https://image.tmdb.org/t/p/original/euoXeFAOt9o7yAWA9zGZk7DdZWZ.jpg','An American actor in Tokyo struggles to find purpose until he lands an unusual gig: working for a Japanese ''rental family'' agency, playing stand-in roles for strangers. As he immerses himself in his clients'' worlds, he begins to form genuine bonds that blur the lines between performance and reality.',NULL,NULL,7.053,7.732,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1521,11075,'tt0235198',NULL,'Audition','オーディション','movie',2000,'https://image.tmdb.org/t/p/w500/zwGaUMm0wAqi0wkO7LJDlwoA5LP.jpg','https://image.tmdb.org/t/p/original/xmtmZc5aylqDMRKYlU8pmsgG0HF.jpg','Seven years after the death of his wife, widower Shigeharu seeks advice on how to find a new wife from a colleague. Taking advantage of their position as a film company, they stage an audition. Interviewing a series of women, Shigeharu is enchanted by the quiet Asami. But soon things take a twisted turn as Asami isn’t what she seems to be.',NULL,NULL,3.5022,7.1,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1522,42425,'tt1409053',NULL,'Asura Cryin''','アスラクライン','tv',2009,'https://image.tmdb.org/t/p/w500/2aPuDNtfDRSTsZznGXRNwrc4gSi.jpg','https://image.tmdb.org/t/p/original/pGCKkACejNJ5rN710X09EOfRTxJ.jpg','Tomoharu is a normal high school student... except for the fact that he is never alone. Haunted by the ghost of his dead childhood friend, he moves into a new residence at the beginning of the school year.

Life turns out to be a little more difficult than expected, though, when his house is overrun by various female occult users. To make things even worse he is pulled into an epic struggle to protect a mysterious trunk, that is presently hidden in the house.',NULL,NULL,5.3528,7.167,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1523,758866,'tt14039582',NULL,'Drive My Car','ドライブ・マイ・カー','movie',2021,'https://image.tmdb.org/t/p/w500/a2lxHS6Au35k5XtFQEQW44yWHeH.jpg','https://image.tmdb.org/t/p/original/r6aqhlmJmu8Dv5E7QYEruaEXKYm.jpg','Yusuke Kafuku, a stage actor and director, still unable, after two years, to cope with the loss of his beloved wife, accepts to direct Uncle Vanya at a theater festival in Hiroshima. There he meets Misaki, an introverted young woman, appointed to drive his car. In between rides, secrets from the past and heartfelt confessions will be unveiled.',NULL,NULL,3.0247,7.434,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1524,1153576,'tt27419420',NULL,'Street Fighter','Street Fighter','movie',2026,'https://image.tmdb.org/t/p/w500/wOnoOeDcsLSo72ON1UC6c1VHKk1.jpg','https://image.tmdb.org/t/p/original/m45xBFqUT4EYpb8eIbamPGK3qea.jpg','In 1993, estranged Street Fighters Ryu and Ken Masters are thrown back into combat when the mysterious Chun-Li recruits them for the next World Warrior Tournament: a brutal clash of fists, fate, and fury. But behind this battle royale lies a deadly conspiracy that forces them to face off against each other and the demons of their past. And if they don''t, it''s GAME OVER!',NULL,NULL,3.6921,0.0,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1525,62637,'tt0097195',NULL,'Why Has Bodhi-Dharma Left for the East?','달마가 동쪽으로 간 까닭은?','movie',1989,'https://image.tmdb.org/t/p/w500/vkdKLYsfIzr1ImacKMQDJmtScky.jpg','https://image.tmdb.org/t/p/original/2zyawAgCpCEfi017Uoulk3MsRIS.jpg','About three monks in a remote monastery; an aging master, a small orphan and a young man who left his city life to seek Enlightenment.',NULL,NULL,1.1963,7.128,0,9.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1526,1281425,'tt33029349',NULL,'Night Silence','Cisza nocna','movie',2024,'https://image.tmdb.org/t/p/w500/gBYhjuq0ZEDN710C5sKVq45y1pA.jpg','https://image.tmdb.org/t/p/original/1Xi0FNU0uj82GfUw2vWHsVCiRv5.jpg','A theatre actor whose health is failing gets admitted to a nursing home. Soon, he starts having nightmares that seemingly become deceptively real. The so-called nightmares were able to make him live in two parallel dimensions.',NULL,NULL,3.4977,4.7,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1527,424113,'tt4010204',NULL,'Hara Kiri','Hara Kiri','movie',2016,'https://image.tmdb.org/t/p/w500/8PaTO4ZsP1x47CjrWgfNYLqd7Ul.jpg','https://image.tmdb.org/t/p/original/jUPRo9BxruGm2bt9lTIjQnOzWnF.jpg','A punk infused love story of two street skaters, August and Beto, and their last day on earth: they''re gonna end it.',NULL,NULL,0.5595,5.1,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1528,18493,'tt0088919',NULL,'Chronos','Chronos','movie',1985,'https://image.tmdb.org/t/p/w500/ciGeeT92K7wMu8wAJntoizImwvG.jpg','https://image.tmdb.org/t/p/original/vmqc6VqNknAjoHYJ1Hen1g9qtq2.jpg','Carefully picked scenes of nature and civilization are viewed at high speed using time-lapse cinematography in an effort to demonstrate the history of various regions.',NULL,NULL,1.2657,7.5,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1529,44154,'tt0064451',NULL,'A Touch of Zen','俠女','movie',1970,'https://image.tmdb.org/t/p/w500/y0VDLox8ufaR4Ry1mFceELYJbKq.jpg','https://image.tmdb.org/t/p/original/8Owq1pLkjT7YiKahStSh8VIKU6C.jpg','Yang Hui-zhen, a mysterious princess on the run from corrupt government officials, is joined in her endeavors by skilled Buddhist monks and an unambitious painter named Gu Sheng-zhai.',NULL,NULL,1.8536,7.6,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1530,746036,'tt1684562',NULL,'The Fall Guy','The Fall Guy','movie',2024,'https://image.tmdb.org/t/p/w500/e7olqFmzcIX5c23kX4zSmLPJi8c.jpg','https://image.tmdb.org/t/p/original/2rjI2uXmjitMAaXVO21r9ao7v2j.jpg','Fresh off an almost career-ending accident, stuntman Colt Seavers has to track down a missing movie star, solve a conspiracy and try to win back the love of his life while still doing his day job.',NULL,NULL,9.0924,6.955,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1531,589964,'tt8747560',NULL,'K. D.','கே.டி.','movie',2019,'https://image.tmdb.org/t/p/w500/7xwBhwz89UtTgp8KiCbwz7QP2Xs.jpg','https://image.tmdb.org/t/p/original/xh4NhfDVjAK55qWdX1VWDg91ucN.jpg','As his children plot his death to claim their inheritance, an aging patriarch leaves home, befriending a spunky boy who adds direction to his life.',NULL,NULL,0.2944,7.8,0,5.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1532,17707,'tt0120620',NULL,'Brokedown Palace','Brokedown Palace','movie',1999,'https://image.tmdb.org/t/p/w500/pWxoggA0KCS5oMPDOjIDYZYzryE.jpg','https://image.tmdb.org/t/p/original/iwcvWOyT04GHLSevuFROL3SGSb6.jpg','Best friends Alice and Darlene take a trip to Thailand after graduating high school. In Thailand, they meet a captivating Australian man, who calls himself Nick Parks. Darlene is particularly smitten with Nick and convinces Alice to take Nick up on his offer to treat the two of them to what amounts to a day trip to Hong Kong. In the airport, the girls are seized by the police and shocked to discover that one of their bags contains heroin.',NULL,NULL,2.6069,6.448,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1533,14002,'tt0103767',NULL,'Baraka','Baraka','movie',1992,'https://image.tmdb.org/t/p/w500/ldEuJQ4z7zEvL7iXraESWBUfQcz.jpg','https://image.tmdb.org/t/p/original/c0QYwNyeURswT7fxmR2mlfpdk0l.jpg','A paralysingly beautiful documentary with a global vision—an odyssey through landscape and time—that attempts to capture the essence of life.',NULL,NULL,2.9228,8.228,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1534,1689,'tt0107426',NULL,'Little Buddha','Little Buddha','movie',1993,'https://image.tmdb.org/t/p/w500/xy70xtdoKZ3PxlKkakwdhL3UFDQ.jpg','https://image.tmdb.org/t/p/original/roWqJp8dXekp1DShC1RNpG9Yr3y.jpg','After the death of Lama Dorje, Tibetan Buddhist monks find three children — one American and two Nepalese — who may be the rebirth of their great teacher.',NULL,NULL,2.5068,6.28,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1535,89708,'tt0770802',NULL,'Samsara','Samsara','movie',2011,'https://image.tmdb.org/t/p/w500/qodkea4k0pNUmNTl5TJO2PdTqgW.jpg','https://image.tmdb.org/t/p/original/tbSjemOf1nXPOjWELdaeZ7qj1iX.jpg','Filmed over nearly five years in twenty-five countries on five continents, and shot on seventy-millimetre film, Samsara transports us to the varied worlds of sacred grounds, disaster zones, industrial complexes, and natural wonders.',NULL,NULL,3.4359,8.061,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1536,359228,'tt4365566',NULL,'Ghost House','Ghost House','movie',2017,'https://image.tmdb.org/t/p/w500/qhb9xJQCWCXICXV8Liy7zZFaIpe.jpg','https://image.tmdb.org/t/p/original/7cjjwapZGnzVnvFCYg5AE2jHh7J.jpg','A young couple go on an adventurous vacation to Thailand only to find themselves haunted by a malevolent spirit after naively disrespecting a Ghost House.',NULL,NULL,2.1176,5.577,0,5.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
