INSERT OR IGNORE INTO "recommendations" VALUES(1538,616,'tt0325710',NULL,'The Last Samurai','The Last Samurai','movie',2003,'https://image.tmdb.org/t/p/w500/a8jmJPs5eZBARmnuEEvZwbjwyz4.jpg','https://image.tmdb.org/t/p/original/piXBj3FKEGNb6XCfAM7w5s4BI7O.jpg','Nathan Algren is an American hired to instruct the Japanese army in the ways of modern warfare, which finds him learning to respect the samurai and the honorable principles that rule them. Pressed to destroy the samurai''s way of life in the name of modernization and open trade, Algren decides to become an ultimate warrior himself and to fight for their right to exist.',NULL,NULL,13.1537,7.608,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1539,574475,'tt9619824',NULL,'Final Destination Bloodlines','Final Destination Bloodlines','movie',2025,'https://image.tmdb.org/t/p/w500/6WxhEvFsauuACfv8HyoVX6mZKFj.jpg','https://image.tmdb.org/t/p/original/uIpJPDNFoeX0TVml9smPrs9KUVx.jpg','Plagued by a violent recurring nightmare, college student Stefanie heads home to track down the one person who might be able to break the cycle and save her family from the grisly demise that inevitably awaits them all.',NULL,NULL,21.473,7.0,0,11.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1540,44896,'tt1192628',NULL,'Rango','Rango','movie',2011,'https://image.tmdb.org/t/p/w500/A5MP1guV8pbruieG0tnpPIbaJtt.jpg','https://image.tmdb.org/t/p/original/mOtKQlXdL5J4lwqcSFlkZmgmFeZ.jpg','When Rango, a lost family pet, accidentally winds up in the gritty, gun-slinging Western town of Dirt, the theater-loving lizard suddenly finds himself the newly appointed sheriff. Welcomed as the last hope the town has been waiting for, Rango is forced to play his new role to the hilt and uncover the truth behind a looming water crisis—before his act catches up with him.',NULL,NULL,10.4545,6.912,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1541,14943,'tt1016290',NULL,'Crows Zero','クローズZERO','movie',2007,'https://image.tmdb.org/t/p/w500/so1E9wUAXJi9hqGRNPgoVQd7HaX.jpg','https://image.tmdb.org/t/p/original/43FpZytJjlReDAPrByR77i81mnr.jpg','The students of Suzuran High compete for the King of School title. An ex-graduate yakuza is sent to kill the son of a criminal group, but he can''t make himself do it as he reminds him of his youth.',NULL,NULL,5.7042,7.079,0,13.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1542,499556,'tt8020896',NULL,'An Elephant Sitting Still','大象席地而坐','movie',2018,'https://image.tmdb.org/t/p/w500/bJfkDnsY9z9ohWdyzyCAqYZxbnS.jpg','https://image.tmdb.org/t/p/original/5b1r0b77BovGp4ejUsYsx3arQoe.jpg','In the northern Chinese city of Manzhouli, they say there is an elephant that simply sits and ignores the world. Manzhouli becomes an obsession for the protagonists of this film, a longed-for escape from the downward spiral in which they find themselves.',NULL,NULL,1.4798,7.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
