INSERT OR IGNORE INTO "recommendations" VALUES(1544,8818,'tt0116250',NULL,'Evita','Evita','movie',1996,'https://image.tmdb.org/t/p/w500/mVdQatilUGMtB6sV4FXA7O473UD.jpg','https://image.tmdb.org/t/p/original/198CRubmWRqeRRsjdeN7DgzCLUl.jpg','The hit musical based on the life of Evita Duarte, an Argentinian actress who eventually became the wife of Argentinian president Juan Perón, and the most beloved and hated woman in Argentina.',NULL,NULL,2.7234,6.096,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1545,33333,'tt0309291',NULL,'Blue Spring','青い春','movie',2001,'https://image.tmdb.org/t/p/w500/nucvbLWcQmdyGxqMtfIHjUeEHyU.jpg','https://image.tmdb.org/t/p/original/2272w58dxCPAd4Pez6agyeJWaL0.jpg','Soon after being named the new leader of his high school''s gang system, Kujo grows bored with the violence and hatred that surround him. He wants desperately to abandon his post… but his once-enviable position of power has a strange way of making him feel powerless.',NULL,NULL,1.4124,7.1,0,1.30166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1546,276624,'tt3775202',NULL,'I Am a Hero','アイアムアヒーロー','movie',2016,'https://image.tmdb.org/t/p/w500/4RnmHtCLtbBHD9jagVlcSzJTWX6.jpg','https://image.tmdb.org/t/p/original/jBeCis93wE55vsvHxkLY3jbeO7A.jpg','A man witnesses a fatal traffic accident on his way home from work, and the victim is clearly killed on impact. A moment later, when the corpse stands up and walks away, it could be a hallucination or something far more extraordinary.',NULL,NULL,2.3248,7.5,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
