INSERT OR IGNORE INTO "recommendations" VALUES(1549,21519,'tt0085127',NULL,'Project A','A計劃','movie',1983,'https://image.tmdb.org/t/p/w500/AvTu2bmJbVZGXPxdx6VllGXCtLG.jpg','https://image.tmdb.org/t/p/original/q44ti4QwHJidHhqAUeU33QnUanR.jpg','In late 19th century Hong Kong, the British may rule the land, but the pirates rule the waters. Coast Guard officer Dragon Ma is determined that his beloved Coast Guard will not be made a fool of.',NULL,NULL,3.8927,7.217,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1550,763,'tt0103873',NULL,'Braindead','Braindead','movie',1992,'https://image.tmdb.org/t/p/w500/pa39D8TQs6aNw3hiUs4jLjHVUB0.jpg','https://image.tmdb.org/t/p/original/ecZ6MQ3Y63dtn35km6odO0e39aQ.jpg','When a Sumatran rat-monkey bites Lionel Cosgrove''s mother, she''s transformed into a zombie and begins killing (and transforming) the entire town while Lionel races to keep things under control.',NULL,NULL,6.9533,7.391,0,13.5275,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1551,24804,'tt1190536',NULL,'Black Dynamite','Black Dynamite','movie',2009,'https://image.tmdb.org/t/p/w500/u3oWQDz0JggzzsVlsuHY7XVxp5Y.jpg','https://image.tmdb.org/t/p/original/gpcJuvH1tRWfdGv6ysWVRN3EZXL.jpg','This is the story of 1970s African-American action legend Black Dynamite. The Man killed his brother, pumped heroin into local orphanages, and flooded the ghetto with adulterated malt liquor. Black Dynamite was the one hero willing to fight The Man all the way from the blood-soaked city streets to the hallowed halls of the Honky House.',NULL,NULL,1.9183,7.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
