INSERT OR IGNORE INTO "recommendations" VALUES(1554,670428,'tt11252440',NULL,'PG: Psycho Goreman','PG: Psycho Goreman','movie',2020,'https://image.tmdb.org/t/p/w500/28Y3pxfkRZMhLsw4if6e3J0HD7Q.jpg','https://image.tmdb.org/t/p/original/aLDQl8iUzrapHOob3VHgmyX1ijj.jpg','Siblings Mimi and Luke unwittingly resurrect an ancient alien overlord. Using a magical amulet, they force the monster to obey their childish whims, and accidentally attract a rogues’ gallery of intergalactic assassins to small-town suburbia.',NULL,NULL,2.0756,6.017,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
