INSERT OR IGNORE INTO "recommendations" VALUES(1561,83899,'tt1853739',NULL,'You''re Next','You''re Next','movie',2013,'https://image.tmdb.org/t/p/w500/l163jakfKvchUTVTtBi0KA7ZhIc.jpg','https://image.tmdb.org/t/p/original/okjEw4GrEqn4seWkvUHIUXogQZD.jpg','When the Davison family comes under attack during their wedding anniversary getaway, the gang of mysterious killers soon learns that one of their victims harbors a secret talent for fighting back.',NULL,NULL,3.7205,6.604,0,1.0129999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
