INSERT OR IGNORE INTO "recommendations" VALUES(1601,952701,'tt19719836',NULL,'Return to Seoul','Retour à Séoul','movie',2022,'https://image.tmdb.org/t/p/w500/uEz1pAW2r1tECDI8ipttabaLHhW.jpg','https://image.tmdb.org/t/p/original/ngsAuG8JYOiuwgGejN7xljgETNt.jpg','After an impulsive travel decision to visit friends, Freddie, 25, returns to South Korea for the first time, where she was born before being adopted and raised in France. Freddie suddenly finds herself embarking on an unexpected journey in a country she knows so little about, taking her life in new and unexpected directions.',NULL,NULL,0.9562,6.259,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1602,320007,'tt4226388',NULL,'Victoria','Victoria','movie',2015,'https://image.tmdb.org/t/p/w500/9P8QgfoMcFX7vp2Gj2cYFecHVRZ.jpg','https://image.tmdb.org/t/p/original/dGEBDMw3FaUmVGLn4vpjdgoTunk.jpg','A young Spanish woman who has newly moved to Berlin finds her flirtation with a local guy turn potentially deadly as their night out with his friends reveals a dangerous secret.',NULL,NULL,1.6479,7.58,0,12.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1603,1359,'tt0144084',NULL,'American Psycho','American Psycho','movie',2000,'https://image.tmdb.org/t/p/w500/9uGHEgsiUXjCNq8wdq4r49YL8A1.jpg','https://image.tmdb.org/t/p/original/5oaMV2q0qzxkIW2ukU3lldLu5q2.jpg','A wealthy New York investment banking executive hides his alternate psychopathic ego from his co-workers and friends as he escalates deeper into his illogical, gratuitous fantasies.',NULL,NULL,15.0692,7.402,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1604,9509,'tt0328107',NULL,'Man on Fire','Man on Fire','movie',2004,'https://image.tmdb.org/t/p/w500/grCGLCcTHv9TChibzOwzUpykcjB.jpg','https://image.tmdb.org/t/p/original/6c7j7MQCczzNVvcrNEiXbs8Kt2p.jpg','Jaded ex-CIA operative John Creasy reluctantly accepts a job as the bodyguard for a 10-year-old girl in Mexico City. They clash at first, but eventually bond, and when she''s kidnapped he''s consumed by fury and will stop at nothing to save her life.',NULL,NULL,7.5231,7.47,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1605,1811,'tt0119809',NULL,'Nowhere','Nowhere','movie',1997,'https://image.tmdb.org/t/p/w500/c1TZKfzvATep5x5DthqWjjWtU2l.jpg','https://image.tmdb.org/t/p/original/bTS9PZp8GQa8XqC9eMT1FrtRXnM.jpg','In Los Angeles, a colorful assortment of bohemians try to make sense of their intersecting lives. The moody Dark Smith, his bisexual girlfriend, her lesbian lover and their shy gay friend plan on attending the wildest party of the year. But they''ll only make it if they can survive the drug trips, suicides, trysts, mutilations and alien abductions that occur as one surreal day unfolds.',NULL,NULL,6.1991,6.8,0,12.7,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1606,10159,'tt0327850',NULL,'The Rundown','The Rundown','movie',2003,'https://image.tmdb.org/t/p/w500/dJX06UwlLIwbLLt9UQ6DlkHF4jz.jpg','https://image.tmdb.org/t/p/original/i7ClLxhjClTCXGBt3FLC4hbEvU.jpg','When Travis, the mouthy son of a criminal, disappears in the Amazon in search of a treasured artifact, his father sends in Beck, who becomes Travis''s rival for the affections of Mariana, a mysterious Brazilian woman. With his steely disposition, Beck is a man of few words -- but it takes him all the discipline he can muster to work with Travis to nab a tyrant who''s after the same treasure.',NULL,NULL,4.9315,6.447,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1607,3600,'tt0130018',NULL,'I Still Know What You Did Last Summer','I Still Know What You Did Last Summer','movie',1998,'https://image.tmdb.org/t/p/w500/eg3d6hvTaOmW3lNErFfutBmWmAR.jpg','https://image.tmdb.org/t/p/original/gF1BbDac7ONryE5jezRzXVe31Ud.jpg','Ever since killing the Fisherman one year ago, Julie James is still haunted by images of him after her. When her best friend Karla wins free tickets to the Bahamas, Julie finds this a perfect opportunity to finally relax. But someone is waiting for her. Someone who she thought was dead. Someone who is out again for revenge.',NULL,NULL,3.1784,5.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1608,8961,'tt0172156',NULL,'Bad Boys II','Bad Boys II','movie',2003,'https://image.tmdb.org/t/p/w500/yCvB5fG5aEPqa1St7ihY6KEAsHD.jpg','https://image.tmdb.org/t/p/original/gxSVZCUlDd8upT1G2wdrUdz2hxG.jpg','Detectives Marcus Burnett and Mike Lowrey of the Miami Narcotics Task Force are tasked with stopping the flow of the drug Ecstasy into Miami. They track the drugs to the whacked-out Cuban drug lord Johnny Tapia, who is also involved in a bloody war with Russian and Haitian mobsters. If that isn''t bad enough, there''s tension between the two detectives when Marcus discovers that playboy Mike is secretly romancing Marcus’ sister, Syd.',NULL,NULL,7.2892,6.657,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1609,1257425,'tt31643435',NULL,'Rave On','Rave On','movie',2025,'https://image.tmdb.org/t/p/w500/20PIVsVADzvccIq1dW79lRGwEBC.jpg','https://image.tmdb.org/t/p/original/oRAR2WXJVlDZTjdCsosvLIGVyCm.jpg','A deep dive into Berlin’s club scene, following a musician over one night in a legendary techno club, which turns into a rave odyssey.',NULL,NULL,1.6056,6.1,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1610,1180629,'tt27367464',NULL,'Kneecap','Kneecap','movie',2024,'https://image.tmdb.org/t/p/w500/gEbQi5QWUg3CQ9R5dwvPBvbOX17.jpg','https://image.tmdb.org/t/p/original/224f3zy21srh9WnBLFU2z3axIFA.jpg','When fate brings Belfast teacher JJ into the orbit of self-confessed "low life scum" Naoise and Liam Óg, the needle drops on a hip-hop act like no other. Rapping in their native Irish, they lead a movement to save their mother tongue.',NULL,NULL,3.767,7.27,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1611,38142,'tt0983213',NULL,'5 Centimeters per Second','秒速5センチメートル','movie',2007,'https://image.tmdb.org/t/p/w500/dFipUR6W0y3PPkuVS8gjFd929m2.jpg','https://image.tmdb.org/t/p/original/8sM6d8a4GrpYG77lBznvh2cwKIB.jpg','Three moments in Takaki''s life: his relationship with Akari and their forced separation; his friendship with Kanae, who is secretly in love with him; the demands and disappointments of adulthood, an unhappy life in a cold city.',NULL,NULL,4.517,7.3,0,10.56,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1612,45098,'tt1454545',NULL,'More Than Blue','슬픔보다 더 슬픈 이야기','movie',2009,'https://image.tmdb.org/t/p/w500/b6KJB752HdXZhEiiXkoGwzVVV2c.jpg','https://image.tmdb.org/t/p/original/g0a62Nui7spwCRGVP8SSJQpD2jQ.jpg','A terminally ill man tries to find a suitable husband for the friend he has loved since childhood.',NULL,NULL,1.1886,7.493,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1613,124578,'tt15381716',NULL,'More than Blue: The Series','比悲傷更悲傷的故事：影集版','tv',2021,'https://image.tmdb.org/t/p/w500/wxRVfOEPSDikkBIugO76CSVDxc0.jpg','https://image.tmdb.org/t/p/original/j65k5GKtqiF4gaomL6ArScIivrs.jpg','The series revolves around the journey of music producer Wang Po Han and his assistant An Yi Qi to find the copyright owner of the mysterious song for their artist, A-Lin. They also came across a diary belonging to K who is the producer of the mysterious song and traveled into the life story of K through the diary. The diary tells the story of K and Cream, two orphans who journey through life and share experiences in sadness and joy together. However, K is diagnosed with fatal leukemia cancer. Knowing that Cream''s biggest fear is to be left alone, K keeps the fact that he has terminal cancer a secret.',NULL,NULL,3.2834,6.947,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1614,575813,'tt9586294',NULL,'Better Days','少年的你','movie',2019,'https://image.tmdb.org/t/p/w500/csVZ2ZQCj98XdZoCuW1aixMYJ0W.jpg','https://image.tmdb.org/t/p/original/putsivYODgbKrhvwl9n4OqhPOkO.jpg','A bullied teenage girl forms an unlikely friendship with a mysterious young man who protects her from her assailants, while she copes with the pressures of her final examinations.',NULL,NULL,5.8477,8.11,0,11.275,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1615,8292,'tt0430105',NULL,'Four Brothers','Four Brothers','movie',2005,'https://image.tmdb.org/t/p/w500/8cO39cnWSZQi2ncPG5TxL3YRzKc.jpg','https://image.tmdb.org/t/p/original/2pITFeesu6aikrEknoH6bNXOdhk.jpg','Four adopted brothers return to their Detroit hometown when their mother is murdered and vow to exact revenge on the killers.',NULL,NULL,4.4533,6.812,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1616,85525,'tt1922561',NULL,'The Day He Arrives','북촌방향','movie',2011,'https://image.tmdb.org/t/p/w500/nYgTNFSFKJMDQF4mq9vt3ieJ7eQ.jpg','https://image.tmdb.org/t/p/original/6KmUwyVzHTaq30Q3LWfNeFj2lcT.jpg','A film director who no longer makes films arrives in Seoul to meet a close friend. When the friend doesn''t show up, he wanders the city aimlessly for three days, grabbing drinks and meeting women, with each day playing out like a version of the last.',NULL,NULL,1.1572,6.9,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1617,10219,'tt0120834',NULL,'Snow Falling on Cedars','Snow Falling on Cedars','movie',1999,'https://image.tmdb.org/t/p/w500/h1CujbeKvwkR6LMr4jVuMM0C94X.jpg','https://image.tmdb.org/t/p/original/aAIobmR0vHtbmUgVeEBLXrGcipm.jpg','In the 1950s, a Japanese-American fisherman is suspected of killing his neighbour at sea. For Ishmael, a local reporter, the trial strikes a deep emotional chord when he finds his ex-lover is linked to the case. As he investigates the killing, he uncovers some startling clues that lead him to a shocking discovery.',NULL,NULL,1.6605,6.1,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1618,64847,'tt0071203',NULL,'Belladonna of Sadness','哀しみのベラドンナ','movie',1973,'https://image.tmdb.org/t/p/w500/2okYZVVw7RdMwlOKcAJsQ7Nsrpr.jpg','https://image.tmdb.org/t/p/original/gpCfsRtAiOTG1H4sTVQpl6edZQV.jpg','An evil feudal lord rapes a village girl on her wedding night and proceeds to ruin her and her husband''s lives. After she''s eventually banished from her village, the girl makes a pact with the devil to gain magical ability and take revenge.',NULL,NULL,2.4919,7.37,0,1.17366666666666681e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1619,15139,'tt0110763',NULL,'The Pagemaster','The Pagemaster','movie',1994,'https://image.tmdb.org/t/p/w500/iIWUuCjN8VND7BDugvf45LveA6p.jpg','https://image.tmdb.org/t/p/original/60XduQspYjRnvKQszuBtQwhzCDc.jpg','Rich knows a lot about accidents. So much so, he is scared to do anything that might endanger him, like riding his bike, or climbing into his treehouse. While in an old library, he is mystically transported into the unknown world of books, and he has to try and get home again.',NULL,NULL,3.4342,6.424,0,1.2623333333333333e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1620,16391,'tt0039192',NULL,'Black Narcissus','Black Narcissus','movie',1947,'https://image.tmdb.org/t/p/w500/jSbFWWbkUq5N5ikewJHNATcWnxS.jpg','https://image.tmdb.org/t/p/original/hAyWibhJjMHyWXrMVX8N2MrEqF8.jpg','A group of Anglican nuns, led by Sister Clodagh, are sent to a mountain in the Himalayas. The climate in the region is hostile and the nuns are housed in an odd old palace. They work to establish a school and a hospital, but slowly their focus shifts. Sister Ruth falls for a government worker, Mr. Dean, and begins to question her vow of celibacy. As Sister Ruth obsesses over Mr. Dean, Sister Clodagh becomes immersed in her own memories of love.',NULL,NULL,2.2092,7.5,0,1.35300000000000011e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1621,11953,'tt0080979',NULL,'Kagemusha','影武者','movie',1980,'https://image.tmdb.org/t/p/w500/fJgqj9s8HNZz9zwX6femVJn8HEB.jpg','https://image.tmdb.org/t/p/original/7qsKE8GsgjreeQ2mTLd5oKZ7Tbf.jpg','Akira Kurosawa''s lauded feudal epic presents the tale of a petty thief who is recruited to impersonate Shingen, an aging warlord, in order to avoid attacks by competing clans. When Shingen dies, his generals reluctantly agree to have the impostor take over as the powerful ruler. He soon begins to appreciate life as Shingen, but his commitment to the role is tested when he must lead his troops into battle against the forces of a rival warlord.',NULL,NULL,3.0049,7.832,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1622,26302,'tt0063555',NULL,'The Color of Pomegranates','Նռան գույնը','movie',1969,'https://image.tmdb.org/t/p/w500/rMUbQf7RgsYgQ47AFf1wpoSt4dX.jpg','https://image.tmdb.org/t/p/original/xd4P9EIV3T2Keh3aGnuEVWt5lh4.jpg','The life of the revered 18th-century Armenian poet and musician Sayat-Nova. Portraying events in the life of the artist from childhood up to his death, the movie addresses in particular his relationships with women, including his muse. The production tells Sayat-Nova''s dramatic story by using both his poems and largely still camerawork, creating a work hailed as revolutionary by Mikhail Vartanov.',NULL,NULL,3.4192,7.4,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1623,37958,'tt1253864',NULL,'Immortals','Immortals','movie',2011,'https://image.tmdb.org/t/p/w500/4SPPX5KIyaQ9O8n5rLvvUIiIhpF.jpg','https://image.tmdb.org/t/p/original/vbcUqIQZl7q7O2op2NT0ZqTLXxH.jpg','Theseus is a mortal man chosen by Zeus to lead the fight against the ruthless King Hyperion, who is on a rampage across Greece to obtain a weapon that can destroy humanity.',NULL,NULL,5.3694,6.049,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1624,1100988,'tt10548174',NULL,'28 Years Later','28 Years Later','movie',2025,'https://image.tmdb.org/t/p/w500/n5FygjEppOvac6yEaowi26nTyw3.jpg','https://image.tmdb.org/t/p/original/6WqqEjiycNvDLjbEClM1zCwIbDD.jpg','Twenty-eight years after the Rage virus outbreak, a heavily-defended island survives connected to the mainland by a single causeway. When one of the group leaves the island into the dark heart of the mainland, he discovers secrets, wonders, and horrors that have mutated not only the infected but other survivors as well.',NULL,NULL,18.3156,6.614,0,3.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1625,985939,'tt15325794',NULL,'Fall','Fall','movie',2022,'https://image.tmdb.org/t/p/w500/spCAxD99U1A6jsiePFoqdEcY0dG.jpg','https://image.tmdb.org/t/p/original/hT3OqvzMqCQuJsUjZnQwA5NuxgK.jpg','For best friends Becky and Hunter, life is all about conquering fears and pushing limits. But after they climb 2,000 feet to the top of a remote, abandoned radio tower, they find themselves stranded with no way down. Now Becky and Hunter''s expert climbing skills will be put to the ultimate test as they desperately fight to survive the elements, a lack of supplies, and vertigo-inducing heights.',NULL,NULL,12.892,7.143,0,6.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1626,279,'tt0086879',NULL,'Amadeus','Amadeus','movie',1984,'https://image.tmdb.org/t/p/w500/gQRfiyfGvr1az0quaYyMram3Aqt.jpg','https://image.tmdb.org/t/p/original/rnQyWw68dPHPRtvSWMtLSueXf05.jpg','Disciplined Italian composer Antonio Salieri becomes consumed by jealousy and resentment towards the hedonistic and remarkably talented young Salzburger composer Wolfgang Amadeus Mozart.',NULL,NULL,6.8375,8.021,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1627,16646,'tt0318034',NULL,'Russian Ark','Русский ковчег','movie',2002,'https://image.tmdb.org/t/p/w500/dkFM8Q7J0wNpEnbtD1AcWumkShj.jpg','https://image.tmdb.org/t/p/original/lLQgQy1nX3qocg83BLTCz1911R4.jpg','A ghost and a French marquis wander through the Winter Palace in St Petersburg, encountering scenes from many different periods of its history.',NULL,NULL,1.3359,7.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1628,290098,'tt4016934',NULL,'The Handmaiden','아가씨','movie',2016,'https://image.tmdb.org/t/p/w500/dLlH4aNHdnmf62umnInL8xPlPzw.jpg','https://image.tmdb.org/t/p/original/3upEZ0ltY7WwOSFVXrtiP34D48p.jpg','1930s Korea, in the period of Japanese occupation, a new girl, Sook-hee, is hired as a handmaiden to a Japanese heiress, Hideko, who lives a secluded life on a large countryside estate with her domineering Uncle Kouzuki. But the maid has a secret. She is a pickpocket recruited by a swindler posing as a Japanese Count to help him seduce the Lady to steal her fortune.',NULL,NULL,20.6386,8.184,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1629,11163,'tt0064940',NULL,'Satyricon','Fellini – satyricon','movie',1969,'https://image.tmdb.org/t/p/w500/83urUMl04GtwuuGIFpezqzi7n6m.jpg','https://image.tmdb.org/t/p/original/kPdvXDdXIbuKKAt9gEy13FNYgbm.jpg','After his young lover, Gitone, leaves him for another man, Encolpio decides to kill himself, but a sudden earthquake destroys his home before he has a chance to do so. Now wandering around Rome in the time of Nero, Encolpio encounters one bizarre and surreal scene after another.',NULL,NULL,1.4139,6.694,0,10.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1630,33583,'tt0065622',NULL,'The Decameron','Il Decameron','movie',1971,'https://image.tmdb.org/t/p/w500/iL5mmuIL6fqFSWJeHE417WWrocz.jpg','https://image.tmdb.org/t/p/original/9CbH2EktREWAur7XLBeFNFNr5BQ.jpg','A young Sicilian is swindled twice, but ends up rich; a man poses as a deaf-mute in a convent of curious nuns; a woman must hide her lover when her husband comes home early; a scoundrel fools a priest on his deathbed; three brothers take revenge on their sister''s lover; a young girl sleeps on the roof to meet her boyfriend at night; a group of painters wait for inspiration; a crafty priest attempts to seduce his friend''s wife; and two friends make a pact to find out what happens after death.',NULL,NULL,2.6167,6.827,0,10.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1631,1271,'tt0416449',NULL,'300','300','movie',2007,'https://image.tmdb.org/t/p/w500/h7Lcio0c9ohxPhSZg42eTlKIVVY.jpg','https://image.tmdb.org/t/p/original/lgBZlJ1LHQel5nneNQMoesmvc7l.jpg','A story very loosely based the 480 B.C. Battle of Thermopylae, where the King of Sparta led his army against the advancing Persians.',NULL,NULL,10.302,7.207,0,10.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1632,9300,'tt0107756',NULL,'Orlando','Orlando','movie',1992,'https://image.tmdb.org/t/p/w500/seRawEs8eQ8rWfkBm6QC39EQEAU.jpg','https://image.tmdb.org/t/p/original/AoMYwa8yRvXcbRKdD5s8VwIN3NA.jpg','England, 1600. Queen Elizabeth I promises Orlando, a young nobleman obsessed with poetry, that she will grant him land and fortune if he agrees to satisfy a very particular request.',NULL,NULL,1.6485,6.918,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1633,88302,'tt0064815',NULL,'Pirosmani','ფიროსმანი','movie',1969,'https://image.tmdb.org/t/p/w500/xXCfzNcX0NcOgYeaB9hIXqDc0rB.jpg','https://image.tmdb.org/t/p/original/2K7fr05VMRM20o6HsjxmUFZDcL3.jpg','A biography of the Georgian primitive artist Nikoloz Pirosmanishvili (1862–1918), better known as Pirosmani, who died of starvation and sold his paintings to bars and restaurants for food and drink. The film experiments with color control techniques based on the painter’s style.',NULL,NULL,0.4752,6.975,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1634,79,'tt0299977',NULL,'Hero','英雄','movie',2002,'https://image.tmdb.org/t/p/w500/vxgZto2Cz7ILHAlmRXt50I2brB2.jpg','https://image.tmdb.org/t/p/original/jDz6RYN3nKYtlo7J9IMvGoJit7B.jpg','During China''s Warring States period, a district prefect arrives at the palace of Qin Shi Huang, claiming to have killed the three assassins who had made an attempt on the king''s life three years ago.',NULL,NULL,10.1969,7.508,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1635,1904,'tt0397535',NULL,'Memoirs of a Geisha','Memoirs of a Geisha','movie',2005,'https://image.tmdb.org/t/p/w500/pBwYsQaSTgnPphIy02DJjCF2cqs.jpg','https://image.tmdb.org/t/p/original/zJDnqXtGNHUmexiaWNa52Vslve5.jpg','In the years before World War II, a penniless Japanese child is torn from her family to work as a maid in a geisha house.',NULL,NULL,5.6787,7.635,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1636,8054,'tt1054606',NULL,'The Imaginarium of Doctor Parnassus','The Imaginarium of Doctor Parnassus','movie',2009,'https://image.tmdb.org/t/p/w500/DtrqQHa0wT9AWrk2WA9beROJJx.jpg','https://image.tmdb.org/t/p/original/vBw4z7l3NI32th7nR34zqRgdvXS.jpg','After a carnival troupe saves his life, a man agrees to help its immortal leader collect five souls and win a bet with the devil.',NULL,NULL,3.7047,6.384,0,1.54266666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1637,45958,'tt1164999',NULL,'Biutiful','Biutiful','movie',2010,'https://image.tmdb.org/t/p/w500/4BLshBMp8INRDhvfuKwxMlHDIIt.jpg','https://image.tmdb.org/t/p/original/s1r2aBDzkvlFkNnAgxWFTCQjKPe.jpg','This is a story of a man in free fall. On the road to redemption, darkness lights his way. Connected with the afterlife, Uxbal is a tragic hero and father of two who''s sensing the danger of death. He struggles with a tainted reality and a fate that works against him in order to forgive, for love, and forever.',NULL,NULL,5.5198,7.249,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1638,308084,'tt3824458',NULL,'Tangerine','Tangerine','movie',2015,'https://image.tmdb.org/t/p/w500/EKLR5c61XQzBTeMokFrmS3kdt8.jpg','https://image.tmdb.org/t/p/original/q18pdMKGX4wSHaT3lllt5jLjp8d.jpg','It''s Christmas Eve in Tinseltown and Sin-Dee is back on the block. Upon hearing that her pimp boyfriend hasn''t been faithful during the 28 days she was locked up, the working girl and her best friend, Alexandra, embark on a mission to get to the bottom of the scandalous rumor. Their rip-roaring odyssey leads them through various subcultures of Los Angeles, including an Armenian family dealing with their own repercussions of infidelity.',NULL,NULL,1.4764,6.864,0,10.21,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1639,11879,'tt0093605',NULL,'Near Dark','Near Dark','movie',1987,'https://image.tmdb.org/t/p/w500/hVhFNn3IQxxARvnpLIKMx8ZfTtG.jpg','https://image.tmdb.org/t/p/original/fLqhMfRyMySsqORn0xq7iFWRdcM.jpg','A farm boy reluctantly becomes a member of the undead when a girl he meets turns out to be part of a band of vampires who roam the highways in stolen cars.',NULL,NULL,4.0473,6.855,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1640,12079,'tt0283003',NULL,'Spun','Spun','movie',2003,'https://image.tmdb.org/t/p/w500/jiwNobUsd29ooowQyTeh0cvPBFL.jpg','https://image.tmdb.org/t/p/original/57CjdO0N8erYJq234HCyYwkhq5K.jpg','Over the course of three days Ross, a college dropout addicted to crystal-meth, encounters a variety of oddball folks - including a stripper named Nikki and her boyfriend, the local meth producer, The Cook - but all he really wants to do is hook up with his old girlfriend, Amy.',NULL,NULL,1.8885,6.577,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1641,22094,'tt0073092',NULL,'Hard Times','Hard Times','movie',1975,'https://image.tmdb.org/t/p/w500/yWIh8cMGd9XubkdhJB2TJ7buGy3.jpg','https://image.tmdb.org/t/p/original/cl9rUfhtzrKhdzjtQJfBjzpdGrm.jpg','In the depression, Chaney, a strong silent streetfighter, joins with Speed, a promoter of no-holds-barred street boxing bouts. They go to New Orleans where Speed borrows money to set up fights for Chaney, but Speed gambles away any winnings.',NULL,NULL,4.0627,6.829,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1642,14695,'tt0285175',NULL,'Havoc','Havoc','movie',2005,'https://image.tmdb.org/t/p/w500/xY4c4bHPCRrwIvkxJ6qRLoyxQVo.jpg','https://image.tmdb.org/t/p/original/elHZI1SgKLYJimhl8ZKvUnZQxgW.jpg','A wealthy Los Angeles teen and her superficial friends wants to break out of suburbia and experience Southern California''s "gangsta" lifestyle. But problems arise when the preppies get in over their heads and provoke the wrath of a violent Latino gang. Suddenly, their role-playing seems a little too real.',NULL,NULL,3.4832,5.3,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1643,471507,'tt7137380',NULL,'Destroyer','Destroyer','movie',2018,'https://image.tmdb.org/t/p/w500/sHw9gTdo43nJL82py0oaROkXXNr.jpg','https://image.tmdb.org/t/p/original/o2dRMwUUUg601AaFiPXBNwurAhM.jpg','When Erin Bell was a young cop, she was given an undercover assignment that ended badly and destroyed her life. Years later, she must face her demons in order to make peace with her past.',NULL,NULL,1.272,5.907,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1644,582883,'tt8193790',NULL,'Deerskin','Le Daim','movie',2019,'https://image.tmdb.org/t/p/w500/spb0cChTS5KcOHtVIxZPvh2RZNY.jpg','https://image.tmdb.org/t/p/original/exqNtu2l1b8cpAnFnGcBPVqccHg.jpg','A man''s obsession with owning the designer deerskin jacket of his dreams leads him to turn his back on his humdrum life in the suburbs, blow his life savings, and even turn him to crime.',NULL,NULL,0.861,6.464,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1645,986280,'tt21027780',NULL,'Fallen Leaves','Kuolleet lehdet','movie',2023,'https://image.tmdb.org/t/p/w500/9ayYOpeqHhxfHHUoyt3kXzznECO.jpg','https://image.tmdb.org/t/p/original/cru4rjGcdHGhnPyjNXvW82jOrif.jpg','In modern-day Helsinki, two lonely souls in search of love meet by chance in a karaoke bar. However, their path to happiness is beset by obstacles – from lost phone numbers to mistaken addresses, alcoholism, and a charming stray dog.',NULL,NULL,2.1812,7.121,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1646,949,'tt0113277',NULL,'Heat','Heat','movie',1995,'https://image.tmdb.org/t/p/w500/e09dLw1Ljtccd2P4NsuUvVtS5du.jpg','https://image.tmdb.org/t/p/original/xKsnZDERG1dk95wuZ5q9iks3OL3.jpg','Obsessive master thief Neil McCauley leads a top-notch crew on various daring heists throughout Los Angeles while determined detective Vincent Hanna pursues him without rest. Each man recognizes and respects the ability and the dedication of the other even though they are aware their cat-and-mouse game may end in violence.',NULL,NULL,19.3329,7.939,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1647,44835,'tt1403177',NULL,'Hesher','Hesher','movie',2010,'https://image.tmdb.org/t/p/w500/dD03azf3h1hUHVzVkkqJs96Kkay.jpg','https://image.tmdb.org/t/p/original/1naAvovOZDe21QOvdJ4e6GnFqcs.jpg','A young boy has lost his mother and is losing touch with his father and the world around him. Then he meets Hesher who manages to make his life even more chaotic.',NULL,NULL,5.9689,6.796,0,1.1009999999999998e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1648,1847,'tt0070334',NULL,'The Long Goodbye','The Long Goodbye','movie',1973,'https://image.tmdb.org/t/p/w500/16Gu0Vg7tBdoRxg1NJDwlTKx1hG.jpg','https://image.tmdb.org/t/p/original/eXCKkX8LVo1vRK4GhVoo0bA8jHM.jpg','In 1970s Hollywood, Detective Philip Marlowe tries to help a friend who is accused of murdering his wife.',NULL,NULL,3.1519,7.384,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1649,39210,'tt1421051',NULL,'Somewhere','Somewhere','movie',2010,'https://image.tmdb.org/t/p/w500/zOf1sdfF4eH3CVRCpmRO5ugVGdo.jpg','https://image.tmdb.org/t/p/original/bzCuOfoZ9ZC9AGLs8ZVZ5yo1X16.jpg','After withdrawing to the Chateau Marmont, a passionless Hollywood actor reexamines his life when his eleven-year-old daughter surprises him with a visit.',NULL,NULL,2.1813,6.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1650,1064213,'tt28607951',NULL,'Anora','Anora','movie',2024,'https://image.tmdb.org/t/p/w500/cgXk2tNYhJZLXdBDO5DidAVzQ82.jpg','https://image.tmdb.org/t/p/original/87GU2ifjNYtgYtcRH1NNH1P4ODo.jpg','A young sex worker from Brooklyn gets her chance at a Cinderella story when she meets and impulsively marries the son of an oligarch. Once the news reaches Russia, her fairytale is threatened as his parents set out to get the marriage annulled.',NULL,NULL,12.0833,7.073,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1651,24739,'tt0097889',NULL,'Miracle Mile','Miracle Mile','movie',1989,'https://image.tmdb.org/t/p/w500/9qRCVO9L3s3CsPnoUO9c3iZm6aB.jpg','https://image.tmdb.org/t/p/original/5BXxxMvcnWQiFnrnB756uyOl7RX.jpg','After 30 years of searching, Harry has finally met the girl of his dreams. Unfortunately, before they even have a chance to go on their first date, Harry intercepts some chilling news: WWIII has begun and nuclear missiles will destroy Los Angeles in less than an hour!',NULL,NULL,1.9243,6.9,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1652,423204,'tt6189022',NULL,'Angel Has Fallen','Angel Has Fallen','movie',2019,'https://image.tmdb.org/t/p/w500/fapXd3v9qTcNBTm39ZC4KUVQDNf.jpg','https://image.tmdb.org/t/p/original/sGqqnvOqJg2HDHrjtCPIlCwF4Mu.jpg','After a treacherous attack, Secret Service agent Mike Banning is charged with attempting to assassinate President Trumbull. Chased by his own colleagues and the FBI, Banning begins a race against the clock to clear his name.',NULL,NULL,6.5152,6.604,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1653,27554,'tt0067549',NULL,'The Panic in Needle Park','The Panic in Needle Park','movie',1971,'https://image.tmdb.org/t/p/w500/rhJ8Dnl6Z9KR9R2zskBKIfrFeFs.jpg','https://image.tmdb.org/t/p/original/rHhNgpxeuIglRO7Fskmk7Ru6Nke.jpg','A stark portrayal of life among a group of heroin addicts who hang out in Needle Park in New York City. Played against this setting is a low-key love story between Bobby, a young addict and small-time hustler, and Helen, a homeless girl who finds in her relationship with Bobby the stability she craves.',NULL,NULL,2.4514,6.8,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1654,80560,'tt0067961',NULL,'Wanda','Wanda','movie',1970,'https://image.tmdb.org/t/p/w500/izuJ7cUhcihFnTpfsdSnkMCHsRQ.jpg','https://image.tmdb.org/t/p/original/bL1etbhvRGhHhpjbwzHZbXNwM5R.jpg','After a string of abusive relationships, Wanda abandons her family and seeks solace in the company of a petty criminal.',NULL,NULL,3.78,6.8,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1655,14469,'tt0115781',NULL,'Bullet','Bullet','movie',1996,'https://image.tmdb.org/t/p/w500/plsSRQwRfF2FIvoLmVsjo1ELqbl.jpg','https://image.tmdb.org/t/p/original/w3CQNq8On5Vg39WVoCDwNsNDoGo.jpg','A tough, Jewish ex-con just released from prison crosses a powerful drug dealer and former prison rival in his return to a life of crime.',NULL,NULL,1.3546,6.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1656,380,'tt0095953',NULL,'Rain Man','Rain Man','movie',1988,'https://image.tmdb.org/t/p/w500/iTNHwO896WKkaoPtpMMS74d8VNi.jpg','https://image.tmdb.org/t/p/original/b3tos7Tsd6lsTe52Nn4TMrEQg65.jpg','When car dealer Charlie Babbitt learns that his estranged father has died, he returns home to Cincinnati, where he discovers that he has a savant older brother named Raymond and that his father''s $3 million fortune is being left to the mental institution in which Raymond lives. Motivated by his father''s money, Charlie checks Raymond out of the facility in order to return with him to Los Angeles. The brothers'' cross-country trip ends up changing both their lives.',NULL,NULL,7.0104,7.751,0,1.30266666666666672e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1657,37094,'tt0106856',NULL,'Falling Down','Falling Down','movie',1993,'https://image.tmdb.org/t/p/w500/7ujqyF96Zg3rfrsh9M0cEF0Yzqj.jpg','https://image.tmdb.org/t/p/original/cS45swrlrTJijH1RblBLe8LlW2p.jpg','An ordinary man frustrated with the various flaws he sees in society begins to psychotically and violently lash out against them.',NULL,NULL,5.2818,7.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1658,32511,'tt1337051',NULL,'Police, Adjective','Polițist, adjectiv','movie',2010,'https://image.tmdb.org/t/p/w500/yiimBQLll8l6SXyNjder7ToilDi.jpg','https://image.tmdb.org/t/p/original/bzUJzGxmQdD3I7gFFLSalEN9ikx.jpg','A cop named Cristi must go undercover to trail teen Victor who is suspected of selling pot in the north-eastern city of Vaslui.',NULL,NULL,1.0955,6.453,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1659,4816,'tt0165798',NULL,'Ghost Dog: The Way of the Samurai','Ghost Dog: The Way of the Samurai','movie',1999,'https://image.tmdb.org/t/p/w500/gjcl07r9zgQ9tVo9alyHmysPFfX.jpg','https://image.tmdb.org/t/p/original/9oRbHgbJf1Zr2fct8jBIKadpKya.jpg','A Black hitman who models after the samurai of old finds himself targeted for death by the mob.',NULL,NULL,3.1221,7.337,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1660,7555,'tt0462499',NULL,'Rambo','Rambo','movie',2008,'https://image.tmdb.org/t/p/w500/3mInub5c8o00H7EJ1TrjAqOzIuc.jpg','https://image.tmdb.org/t/p/original/wzfTG1obTazlGXiIcfRIviBZ1QU.jpg','In Thailand, ex-Green Beret John James Rambo joins a group of mercenaries to venture into war-torn neighboring Myanmar to rescue a group of Christian aid workers who have been kidnapped by a ruthless local infantry unit.',NULL,NULL,7.0394,6.699,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1661,54898,'tt0091830',NULL,'The Green Ray','Le Rayon vert','movie',1986,'https://image.tmdb.org/t/p/w500/1E3pliSC7lXWw6zJhMvG6ba0UNX.jpg','https://image.tmdb.org/t/p/original/jfDTQuovn57QIBvoGDom6FNQrkl.jpg','A lonely Parisian woman comes to terms with her isolation and anxieties during a long summer vacation.',NULL,NULL,2.003,7.484,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1662,9675,'tt0375063',NULL,'Sideways','Sideways','movie',2004,'https://image.tmdb.org/t/p/w500/zOsaxYLgvZVU7cJBpPn8CuE0MrP.jpg','https://image.tmdb.org/t/p/original/zmuRxro8AxPDjACjXTIIDCUNwDl.jpg','Two middle-aged men embark on a spiritual journey through Californian wine country. One is an unpublished novelist suffering from depression, and the other is only days away from walking down the aisle.',NULL,NULL,3.1396,7.116,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1663,36351,'tt0102307',NULL,'Light Sleeper','Light Sleeper','movie',1992,'https://image.tmdb.org/t/p/w500/fFSdOYKp80rcK81KuNW3rz7FcLX.jpg','https://image.tmdb.org/t/p/original/kTu8o04UGSB1n0OV8cXwenHzg2k.jpg','John LeTour is a recovering drug user who suffers insomnia and still deals to a high-end New York clientele, even though he’s trying to move on from the business. John’s professional midlife crisis becomes something more acute — and dangerous — when he re-encounters an old flame while a string of seemingly drug-related murders rocks the city.',NULL,NULL,1.2988,6.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1664,16229,'tt0236640',NULL,'Prozac Nation','Prozac Nation','movie',2003,'https://image.tmdb.org/t/p/w500/4QB1h6mxlmQVM8BtYMybTwL2foc.jpg','https://image.tmdb.org/t/p/original/j06D4plPJNP1s0h3FKB8qwGRGpW.jpg','When talented young writer Elizabeth Wurtzel earns a scholarship to Harvard, she sees it as her chance to escape the pressures of her working-class background and concentrate on her true talent. But what starts out so promising leads to self-destructive behavior and paralyzing depression that reflects an entire generation''s struggle to navigate the effects of divorce, drugs, sex, and high expectations.',NULL,NULL,1.7246,6.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1665,225171,'tt22202452',NULL,'Pluribus','Pluribus','tv',2025,'https://image.tmdb.org/t/p/w500/z7Nga7Q9IGFWs5OEduY2gGFxnX3.jpg','https://image.tmdb.org/t/p/original/ulm1ex4JFYJByyaPyqTr47MFyEQ.jpg','The most miserable person on Earth must save the world from happiness.',NULL,NULL,22.2287,7.931,0,5.38,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1666,11007,'tt0349205',NULL,'Cheaper by the Dozen','Cheaper by the Dozen','movie',2003,'https://image.tmdb.org/t/p/w500/afclGGoQslTYFTnyW1LRMtJMiBp.jpg','https://image.tmdb.org/t/p/original/h1jqCWsSWudxQv7uYguDkXaAjPF.jpg','The Baker brood moves to Chicago after patriarch Tom gets a job coaching football at Northwestern University, forcing his writer wife, Kate, and the couple''s 12 children to make a major adjustment. The transition works well until work demands pull the parents away from home, leaving the kids bored -- and increasingly mischievous.',NULL,NULL,5.6067,6.288,0,10.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1667,137106,'tt1490017',NULL,'The Lego Movie','The Lego Movie','movie',2014,'https://image.tmdb.org/t/p/w500/lbctonEnewCYZ4FYoTZhs8cidAl.jpg','https://image.tmdb.org/t/p/original/6gI1dAkOaUQ6659OdRPsTLlsem5.jpg','An ordinary Lego mini-figure, mistakenly thought to be the extraordinary MasterBuilder, is recruited to join a quest to stop an evil Lego tyrant from conquering the universe.',NULL,NULL,11.0076,7.431,0,10.11,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1668,9352,'tt0356150',NULL,'EuroTrip','EuroTrip','movie',2004,'https://image.tmdb.org/t/p/w500/iLdO4PwbZCCQSa9rchZMwuJm9xe.jpg','https://image.tmdb.org/t/p/original/fuKb0cuIU9DpUhHrN0ycoFmr63e.jpg','When Scott learns that his longtime cyber-buddy from Berlin is a gorgeous young woman, he and his friends embark on a trip across Europe.',NULL,NULL,6.3455,6.621,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1669,114150,'tt1981677',NULL,'Pitch Perfect','Pitch Perfect','movie',2012,'https://image.tmdb.org/t/p/w500/gsFoJk9g8W3zgaipRrrURk7LbiF.jpg','https://image.tmdb.org/t/p/original/2sE6hrwfn9IV7eDlMvpIb9q1EWy.jpg','College student Beca knows she does not want to be part of a clique, but that''s exactly where she finds herself after arriving at her new school. Thrust in among mean gals, nice gals and just plain weird gals, Beca finds that the only thing they have in common is how well they sing together. She takes the women of the group out of their comfort zone of traditional arrangements and into a world of amazing harmonic combinations in a fight to the top of college music competitions.',NULL,NULL,6.7991,7.265,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1670,46451,'tt1328909',NULL,'All American Orgy','All American Orgy','movie',2010,'https://image.tmdb.org/t/p/w500/9A81dNo6pVpJVJERSA1ODGL3pmL.jpg','https://image.tmdb.org/t/p/original/6w4rClmoUUQKcKPyG6FLkGlBY8h.jpg','Three couples try group sex at a lakeside strawberry farm, naively hoping it will lead to enlightenment.',NULL,NULL,0.5802,2.9,0,4.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1671,890,'tt0112159',NULL,'Neon Genesis Evangelion','新世紀エヴァンゲリオン','tv',1995,'https://image.tmdb.org/t/p/w500/y2ah9t0navXyIvoHg1uIbIHO3tt.jpg','https://image.tmdb.org/t/p/original/z2RumCOIZ6HO3oMvfINzZlFnPAw.jpg','At the turn of the century, the Angels returned to Earth, seeking to wipe out humanity in an apocalyptic fury. Devastated, mankind''s last remnants moved underground to wait for the day when the Angels would come back to finish the job. Fifteen years later, that day has come... but this time, humanity is ready to fight back with terrifying bio-mechanical weapons known as the Evangelions. Watch as Shinji, Rei, Asuka and the rest of the mysterious shadow agency Nerv battle to save earth from total annihilation.',NULL,NULL,27.8588,8.6,0,9.25,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1672,76203,'tt2024544',NULL,'12 Years a Slave','12 Years a Slave','movie',2013,'https://image.tmdb.org/t/p/w500/xdANQijuNrJaw1HA61rDccME4Tm.jpg','https://image.tmdb.org/t/p/original/4Bb1kMIfrT2tYRZ9M6Jhqy6gkeF.jpg','In the pre-Civil War United States, Solomon Northup, a free black man from upstate New York, is abducted and sold into slavery. Facing cruelty as well as unexpected kindnesses Solomon struggles not only to stay alive, but to retain his dignity. In the twelfth year of his unforgettable odyssey, Solomon’s chance meeting with a Canadian abolitionist will forever alter his life.',NULL,NULL,7.0425,7.931,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1673,5336,'tt0073650',NULL,'Salò, or the 120 Days of Sodom','Salò o le 120 giornate di Sodoma','movie',1976,'https://image.tmdb.org/t/p/w500/xnaDdiRfZlJaTf6JRc4in40eaeI.jpg','https://image.tmdb.org/t/p/original/wP1wgntZ6VIja8hprxV6UKdQugk.jpg','Four corrupted fascist libertines round up 9 teenage boys and girls and subject them to 120 days of sadistic physical, mental and sexual torture.',NULL,NULL,5.1555,6.347,0,6.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1674,1100782,'tt29268110',NULL,'Smile 2','Smile 2','movie',2024,'https://image.tmdb.org/t/p/w500/ht8Uv9QPv9y7K0RvUyJIaXOZTfd.jpg','https://image.tmdb.org/t/p/original/iR79ciqhtaZ9BE7YFA1HpCHQgX4.jpg','About to embark on a new world tour, global pop sensation Skye Riley begins experiencing increasingly terrifying and inexplicable events. Overwhelmed by the escalating horrors and the pressures of fame, Skye is forced to face her dark past to regain control of her life before it spirals out of control.',NULL,NULL,11.2621,6.589,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1675,64328,'tt1204342',NULL,'The Muppets','The Muppets','movie',2011,'https://image.tmdb.org/t/p/w500/h5N6x5gS45wAALt5fsWVn0oCYQR.jpg','https://image.tmdb.org/t/p/original/60PR4UC3D20dycVAoWadUzFio5R.jpg','When Kermit the Frog and the Muppets learn that their beloved theater is slated for demolition, a sympathetic human, Gary, and his felt-faced brother, Walter, swoop in to help the gang put on a telethon show and raise the $10 million they need to save the day.',NULL,NULL,4.1546,6.7,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1676,1833,'tt0294870',NULL,'Rent','Rent','movie',2005,'https://image.tmdb.org/t/p/w500/fomBrfOHWxlaVcjPk4yCQgIwAnh.jpg','https://image.tmdb.org/t/p/original/Aby2bp5yZYLSvs8Ql32bZAamTFb.jpg','In New York City''s gritty East Village, a group of bohemians strive for success and acceptance while enduring the obstacles of poverty, illness and the AIDS epidemic.',NULL,NULL,1.7165,6.8,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1677,1668,'tt0108778',NULL,'Friends','Friends','tv',1994,'https://image.tmdb.org/t/p/w500/2koX1xLkpTQM4IZebYvKysFW1Nh.jpg','https://image.tmdb.org/t/p/original/l0qVZIpXtIo7km9u5Yqh0nKPOr5.jpg','Six young people from New York City, on their own and struggling to survive in the real world, find the companionship, comfort and support they get from each other to be the perfect antidote to the pressures of life.',NULL,NULL,113.7073,8.4,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1678,37169,'tt1467304',NULL,'The Human Centipede (First Sequence)','The Human Centipede (First Sequence)','movie',2009,'https://image.tmdb.org/t/p/w500/gMtjxIkEi0hnTV5lPHbgeZ4ZpUZ.jpg','https://image.tmdb.org/t/p/original/wubUakLEAAnKeXmuTks5insTKQx.jpg','During a stopover in Germany in the middle of a carefree road trip through Europe, two American girls find themselves alone at night when their car breaks down in the woods. Searching for help at a nearby villa, they are wooed into the clutches of a deranged retired surgeon, who has a very disturbed vision.',NULL,NULL,12.0451,5.181,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1679,172533,'tt2265398',NULL,'Drinking Buddies','Drinking Buddies','movie',2013,'https://image.tmdb.org/t/p/w500/iunbsMWtkwfrtRzU7hdCHhPjjJf.jpg','https://image.tmdb.org/t/p/original/d8CHsjcTWV7HylrAXdR9UtY3HFG.jpg','Weekend trips, office parties, late night conversations, drinking on the job, marriage pressure, biological clocks, holding eye contact a second too long… you know what makes the line between “friends” and “more than friends” really blurry? Beer.',NULL,NULL,1.7263,5.956,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1680,33339,'tt0342167',NULL,'Camp','Camp','movie',2003,'https://image.tmdb.org/t/p/w500/7aOOZisCXvI26i7wgMqBaWQxTY3.jpg','https://image.tmdb.org/t/p/original/1DamXq2CtwO0uwM8bPjtZMI6uYl.jpg','Misfits in their lives back home, a group of young people live it up at musical-theater camp. While the sports counselor is completely ignored, the kids'' spend all their time in rehearsal for a grueling schedule that involves a new show every two weeks. Several personal stories come to the fore.',NULL,NULL,4.0368,5.543,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1681,10022,'tt0395699',NULL,'The Pacifier','The Pacifier','movie',2005,'https://image.tmdb.org/t/p/w500/ayVLPibrtazh7U5FliWRLDMmG3d.jpg','https://image.tmdb.org/t/p/original/p0HdiQZVYylWy5JG8iuwzT1Ssdl.jpg','Navy SEAL Shane Wolfe is handed a new assignment: Protect the five Plummer kids from enemies of their recently deceased father -- a government scientist whose top-secret experiment remains hidden in the kids'' house.',NULL,NULL,5.9915,6.075,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1682,79940,'tt1855401',NULL,'Tim and Eric''s Billion Dollar Movie','Tim and Eric''s Billion Dollar Movie','movie',2012,'https://image.tmdb.org/t/p/w500/bcipzEhr7xh9bfvqLq3iqJjnFdk.jpg','https://image.tmdb.org/t/p/original/qylFMbocdDIiC0uE2Fnw1nL7mWT.jpg','Two guys get a billion dollars to make a movie, only to watch their dream run off course.',NULL,NULL,0.8142,5.5,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1683,18347,'tt1439629',NULL,'Community','Community','tv',2009,'https://image.tmdb.org/t/p/w500/3KUjDt8XY7w2Ku70UE0SECmv1zP.jpg','https://image.tmdb.org/t/p/original/1xRfgONYmK3T6FSmbtcuo8eyxVt.jpg','Follow the lives of a group of students at what is possibly the world’s worst community college in the fictional locale of Greendale, Colorado.',NULL,NULL,48.2567,7.997,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1684,75761,'tt1783732',NULL,'John Dies at the End','John Dies at the End','movie',2013,'https://image.tmdb.org/t/p/w500/1IsviP0Tb05xUAFWz5b7FJ0qIHP.jpg','https://image.tmdb.org/t/p/original/iAmTmSUzpxrxz1KJwhrXsdMFRfi.jpg','A new drug promises out-of-body experiences, but users are coming back changed forever, and an otherworldly invasion of Earth is underway.',NULL,NULL,3.3491,6.258,0,1.26866666666666656e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1685,14574,'tt0914798',NULL,'The Boy in the Striped Pyjamas','The Boy in the Striped Pyjamas','movie',2008,'https://image.tmdb.org/t/p/w500/2C8QCXdMlojTxZjfBlINr4FWcb6.jpg','https://image.tmdb.org/t/p/original/6aRuABAdhuuDypLGscM7HoEWHx4.jpg','When his family moves from their home in Berlin to a strange new house in Poland, young Bruno befriends Shmuel, a boy who lives on the other side of the fence where everyone seems to be wearing striped pajamas. Unaware of Shmuel''s fate as a Jewish prisoner or the role his own Nazi father plays in his imprisonment, Bruno embarks on a dangerous journey inside the camp''s walls.',NULL,NULL,7.8171,7.823,0,10.81,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1686,10380,'tt0101329',NULL,'An American Tail: Fievel Goes West','An American Tail: Fievel Goes West','movie',1991,'https://image.tmdb.org/t/p/w500/k4aLupAkHWwHiEDwvqsZFAnUYF.jpg','https://image.tmdb.org/t/p/original/8UpJ8svNnwVtpu8n62vGke8MOJf.jpg','Some time after the Mousekewitz''s have settled in America, they find that they are still having problems with the threat of cats. That makes them eager to try another home out in the west, where they are promised that mice and cats live in peace. Unfortunately, the one making this claim is an oily con artist named Cat R. Waul who is intent on his own sinister plan.',NULL,NULL,1.9701,6.3,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1687,592041,'tt7243754',NULL,'Dirty Work','Dirty Work','movie',2018,'https://image.tmdb.org/t/p/w500/y5occobBEyikzlUczDG90KO6SB1.jpg','https://image.tmdb.org/t/p/original/yqPPu1IeEmm1gcAy92KiAHhdjeu.jpg','Arabella, a struggling fashion designer takes on a job working as a personal shopper for Marylin- a successful erotic novelist. One day, Arabella is sneakily trying on some of Marilyn''s expensive garments, when Marylin unexpectedly comes home early......but she is not alone. Arabella hides and watches as Marilyn enters with an attractive man who is not her husband. The pair make love on the bed and Arabella is turned on by what she sees. Arabella continues to hide and watches Marilyn''s many affairs take place in the bedroom, until one day she is caught by Marilyn who admits that she knew Arabella had been watching the whole time. Things get steamy between the pair, but soon they will be confronted by someone who knows about their affair and will do anything to stop it.',NULL,NULL,2.3011,4.4,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1688,4946,'tt0064816',NULL,'The Swimming Pool','La Piscine','movie',1969,'https://image.tmdb.org/t/p/w500/pIR9bZM0bN1TwM1tppP7wZ2eJrL.jpg','https://image.tmdb.org/t/p/original/pQpGA6XsWlmlAyicVIxVXHIW02P.jpg','Set in a magnificent villa near a sun-drenched St. Tropez, lovers Jean-Paul and Marianne are spending a happy, lazy summer holiday. Their only concern is to gratify their mutual passion - until the day when Marianne invites her former lover and his beautiful teenage daughter to spend a few days with them. From the first moment, a certain uneasiness and tension begin to develop between the four, which soon escalates in a dangerous love-game.',NULL,NULL,6.2017,7.0,0,11.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1689,17880,'tt0317132',NULL,'Because of Winn-Dixie','Because of Winn-Dixie','movie',2005,'https://image.tmdb.org/t/p/w500/oMUFS7HmIyTeui5xuoIEkPYTWC8.jpg','https://image.tmdb.org/t/p/original/A7DkuH1XcN9DKITdVdpRIwh7aVN.jpg','A girl, abandoned by her mother when she was three, moves to a small town in Florida with her father. There, she adopts an orphaned dog she names Winn-Dixie. The bond between the girl and her special companion brings together the people in a small Florida town and heals her own troubled relationship with her father.',NULL,NULL,2.4331,6.488,0,11.24,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1690,48287,'tt0112435',NULL,'The Baby-Sitters Club','The Baby-Sitters Club','movie',1995,'https://image.tmdb.org/t/p/w500/cdICP1AzQPgBWsEHwKTZH9ziNyE.jpg','https://image.tmdb.org/t/p/original/lO7kLQ9EVcpSTlEFDBElDVl5fJL.jpg','Seven junior-high-school girls organize a daycare camp for children while at the same time experiencing classic adolescent growing pains.',NULL,NULL,1.6131,5.4,0,11.24,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1691,11626,'tt0066265',NULL,'Pippi on the Run','På rymmen med Pippi Långstrump','movie',1970,'https://image.tmdb.org/t/p/w500/2iUh3aslpUL2ek7SDp78axm3w3Z.jpg','https://image.tmdb.org/t/p/original/oFMyC3ZE6hIrZFnl0zoEoOKMl2p.jpg','Fed up with their strict parents, Tommy and Annika run away from home, with their friend Pippi Longstocking to look after them in their long trek.',NULL,NULL,1.2407,6.702,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1692,20283,'tt0078902',NULL,'Breaking Away','Breaking Away','movie',1979,'https://image.tmdb.org/t/p/w500/k7b5GsVJK1hfdwoYqcczN9pBba6.jpg','https://image.tmdb.org/t/p/original/yNjrT8bsr5WR9bmRjLsIwIoZtFR.jpg','Dave, nineteen, has just graduated high school, with his three friends: the comical Cyril, the warm hearted but short-tempered Moocher, and the athletic, spiteful but good-hearted Mike. Now, Dave enjoys racing bikes and hopes to race the Italians one day, and even takes up the Italian culture, much to his friends'' and parents'' annoyance.',NULL,NULL,1.5306,7.133,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1693,11176,'tt0079588',NULL,'The Muppet Movie','The Muppet Movie','movie',1979,'https://image.tmdb.org/t/p/w500/s1bZUzf2hmKp7aaB8MeP2AnqkJv.jpg','https://image.tmdb.org/t/p/original/9mbXZSLINbwNQateHLGRhtaZzZB.jpg','The Muppets gather to watch their newly-finished big-budget rich-and-famous feature film: a talent agent persuades Kermit the Frog to leave the swamp to pursue a career in Hollywood. On his way there, he meets a bear, a pig, a whatever (his future muppet crew), and some special celebrity guest stars, while being chased by the desperate owner of a frog-leg restaurant!',NULL,NULL,3.3891,7.22,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1694,43949,'tt0817177',NULL,'Flipped','Flipped','movie',2010,'https://image.tmdb.org/t/p/w500/6zDYFigohwncqFL00MKbFV01dWb.jpg','https://image.tmdb.org/t/p/original/xBSwwkAYl9h8QVG2OxNpSaSgJwr.jpg','When Juli meets Bryce in the second grade, she knows it''s true love. After spending six years trying to convince Bryce the same, she''s ready to give up - until he starts to reconsider.',NULL,NULL,9.573,8.013,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1695,17474,'tt0102388',NULL,'The Man in the Moon','The Man in the Moon','movie',1991,'https://image.tmdb.org/t/p/w500/57r0TXlqV5GIn4h0Htgh81OZou9.jpg','https://image.tmdb.org/t/p/original/8odZHjwMWWUg2gntUjndLIb8sT0.jpg','Maureen Trant and her younger sibling Dani share a strong connection, but local boy Court Foster threatens to throw their bond off balance. Dani and Court meet first and have a flirtatious rapport -- but when he meets Maureen, he falls hard and they begin a passionate affair. The new couple try to keep their love hidden from Dani, but she soon learns the truth, disavowing her sister. But a heartbreaking accident later reunites the girls.',NULL,NULL,3.1249,7.381,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1696,804095,'tt14208870',NULL,'The Fabelmans','The Fabelmans','movie',2022,'https://image.tmdb.org/t/p/w500/h7llKkqkkJtJrTOaDLuVeUYDQ7I.jpg','https://image.tmdb.org/t/p/original/xQyGkQ8ICa4lgifGr3oZjkm3AJ2.jpg','Growing up in post-World War II era Arizona, young Sammy Fabelman aspires to become a filmmaker as he reaches adolescence, but soon discovers a shattering family secret and explores how the power of films can help him see the truth.',NULL,NULL,3.9936,7.568,0,12.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1697,73861,'tt1273235',NULL,'A Serbian Film','Srpski film','movie',2010,'https://image.tmdb.org/t/p/w500/yIQqiw3Az5QYNHLCUoCTtxXH24G.jpg','https://image.tmdb.org/t/p/original/wa0UGYppc6uWOdVow4Ko2CG4jk9.jpg','Retired porn star Milos leads a normal family life trying to make ends meet. Presented with the opportunity of a lifetime to financially support his family for the rest of their lives, Milos must participate in one last mysterious film. From then on, Milos is drawn into a maelstrom of unbelievable cruelty and mayhem.',NULL,NULL,14.6519,5.452,0,3.91,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1698,9583,'tt0279778',NULL,'Divine Secrets of the Ya-Ya Sisterhood','Divine Secrets of the Ya-Ya Sisterhood','movie',2002,'https://image.tmdb.org/t/p/w500/hI05FJ8wgPROHQgLtfJ4ZuH3l4b.jpg','https://image.tmdb.org/t/p/original/nTB7rsZ1JTCrolj91bRBFgi9G4x.jpg','In a sleepy Louisiana parish, a group of lifelong friends stage a rather unorthodox intervention to help a young playwright unravel the truth about her complicated mother and let go of her painful past.',NULL,NULL,1.2954,6.081,0,11.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1699,9820,'tt0120783',NULL,'The Parent Trap','The Parent Trap','movie',1998,'https://image.tmdb.org/t/p/w500/p4dGmi8u9W0HHyVXcgWPoiFfKTF.jpg','https://image.tmdb.org/t/p/original/y3zUOMWRoI2vC4ck2GBJyFWhzyA.jpg','Hallie Parker and Annie James are identical twins who were separated at a young age due to their parents'' divorce. Unbeknownst to their parents, the girls are sent to the same summer camp, where they meet, discover the truth about their relationship, and come up with a plan to switch places in an effort to reunite their mother and father.',NULL,NULL,12.7309,7.218,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1700,37062,'tt0114099',NULL,'The Passion of Darkly Noon','The Passion of Darkly Noon','movie',1995,'https://image.tmdb.org/t/p/w500/nx459fssgbvYTBcL5CC0lH1gbwq.jpg','https://image.tmdb.org/t/p/original/eA4zo1RWNuzGbxMSLGYrkuEIZCw.jpg','Desire torments a former cultist taking refuge at the home of a scantily clad woman whose husband is away.',NULL,NULL,0.8795,5.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1701,10860,'tt0098384',NULL,'Steel Magnolias','Steel Magnolias','movie',1989,'https://image.tmdb.org/t/p/w500/7ExUSN9s9gX9bhVM17zDLEizano.jpg','https://image.tmdb.org/t/p/original/fYqV4AVj2c9C3mFL0dddWVdCOva.jpg','A young beautician, newly arrived in a small Louisiana town, finds work at the local salon, where a small group of women share a close bond of friendship and welcome her into the fold.',NULL,NULL,3.5657,7.187,0,1.23533333333333317e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1702,49009,'tt1023114',NULL,'The Way Back','The Way Back','movie',2010,'https://image.tmdb.org/t/p/w500/xQ6hxfpD5XQGJz0ekVle5zegam7.jpg','https://image.tmdb.org/t/p/original/jcQfgcq1j7Vit4wQ54niXiLfvE8.jpg','A small band of multicultural convicts stages a daring escape from a WWII-era Siberian gulag, and embarks on a treacherous journey across five countries in a desperate race for freedom and survival.',NULL,NULL,4.4045,6.997,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1703,13258,'tt0845046',NULL,'Son of Rambow','Son of Rambow','movie',2007,'https://image.tmdb.org/t/p/w500/hOCdlpTs91eDohj5LhCGQF4bxqe.jpg','https://image.tmdb.org/t/p/original/v6O8vBT6vlzVIC35wWe3TR7RIi0.jpg','Will is looking for an escape from his family when he encounters Lee, the school bully. Armed with a video camera and a copy of Rambo, Lee plans to make his own action-packed video epic.',NULL,NULL,1.556,6.725,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1704,508943,'tt12801262',NULL,'Luca','Luca','movie',2021,'https://image.tmdb.org/t/p/w500/9x4i9uKGXt8IiiIF5Ey0DIoY738.jpg','https://image.tmdb.org/t/p/original/620hnMVLu6RSZW6a5rwO8gqpt0t.jpg','Luca and his best friend Alberto experience an unforgettable summer on the Italian Riviera. But all the fun is threatened by a deeply-held secret: they are sea monsters from another world just below the water’s surface.',NULL,NULL,11.1913,7.78,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1705,12139,'tt0106701',NULL,'Dennis the Menace','Dennis the Menace','movie',1993,'https://image.tmdb.org/t/p/w500/t642WwGifbQ2fEuKTJRgpPzsgtX.jpg','https://image.tmdb.org/t/p/original/etFlyQjyo64NbMV8P85x3b12Rxg.jpg','Mr. Wilson''s ever-present annoyance comes in the form of one mischievous kid named Dennis. But he''ll need Dennis''s tricks to uncover a collection of gold coins that go missing when a shady drifter named Switchblade Sam comes to town.',NULL,NULL,5.6254,5.889,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1706,35645,'tt0113188',NULL,'Gold Diggers: The Secret of Bear Mountain','Gold Diggers: The Secret of Bear Mountain','movie',1995,'https://image.tmdb.org/t/p/w500/rbiCeXOKdTJXhuWTrIzcfrFNKHT.jpg','https://image.tmdb.org/t/p/original/gQCnA0hibRyhXMPlzfkKMH4bSet.jpg','Two teen girls, one from the city, one from the country, try to find the hidden gold of Bear Mountain learning about friendship, loyalty and courage on the way.',NULL,NULL,1.2433,6.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
