INSERT OR IGNORE INTO "recommendations" VALUES(1714,506069,'tt35274207',NULL,'Rock Milestones: Pink Floyd''s The Wall (The Ultimate Critical Review)','Rock Milestones: Pink Floyd''s The Wall (The Ultimate Critical Review)','movie',2007,'https://image.tmdb.org/t/p/w500/3yvNU4CP9L42z2fuWofUuKtC8CC.jpg',NULL,'It is now over 25 years since the release of The Wall. Conceived by Roger Waters as an ambitious double album, a spectacular live show and a ground breaking feature film. The Wall has gone on to achieve iconic status in the history of popular music. This program draws on live performance footage of Pink Floyd and highlights from the film. Also includes extracts from archive interviews with Gerald Scarfe and Alan Parker, the director of The Wall, along with the views of a team of leading musicians and musicologists. This is the independent critical review of a milestone in popular culture, which strips away the prejudice to produce the ultimate retrospective on one of the most important and iconoclastic popular works of the twentieth century. Featuring Highlights From: • Another Brick in The Wall Part 2 • Comfortably Numb • One Of My Turns • Plus Many More!',NULL,NULL,0.7762,6.0,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
