INSERT OR IGNORE INTO "recommendations" VALUES(1742,340837,'tt4731136',NULL,'A Cure for Wellness','A Cure for Wellness','movie',2017,'https://image.tmdb.org/t/p/w500/8QWJtne0pTsNoJ86KE993aQYTLW.jpg','https://image.tmdb.org/t/p/original/uXx9wjfJEzLlfqB8GW67SYBrhVT.jpg','An ambitious young executive is sent to retrieve his company''s CEO from an idyllic but mysterious "wellness center" at a remote location in the Swiss Alps but soon suspects that the spa''s miraculous treatments are not what they seem.',NULL,NULL,6.1252,6.352,0,1.26966666666666654e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1743,9538,'tt0081455',NULL,'Scanners','Scanners','movie',1981,'https://image.tmdb.org/t/p/w500/VTqLdveNXxGsIAZL5I4RliTTt7.jpg','https://image.tmdb.org/t/p/original/1qxQvGJXlkFRqfGallca9DXmynS.jpg','A scientist trains a man with an advanced telepathic ability called ''scanning'' to stop a dangerous Scanner with extraordinary psychic powers from waging war against non-Scanners.',NULL,NULL,2.8637,6.714,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1744,2654,'tt0113409',NULL,'In the Mouth of Madness','In the Mouth of Madness','movie',1995,'https://image.tmdb.org/t/p/w500/msh4tEUzbnEqlHcFOUH4O0Zti8r.jpg','https://image.tmdb.org/t/p/original/uofxTi1d3IIAdRdyzKl5se5PGf1.jpg','An insurance investigator visits a small town while looking into the strange disappearance of a popular horror novelist. He soon finds that the impact of the author’s books is far more than inspirational.',NULL,NULL,11.1197,7.2,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1745,125490,'tt2099556',NULL,'Antiviral','Antiviral','movie',2012,'https://image.tmdb.org/t/p/w500/rIn0ruFDU8psnCGkPgA9fbKJJUy.jpg','https://image.tmdb.org/t/p/original/pO2j1lxSXmrvCgzuw65pDOFBXXC.jpg','Syd March is employed at a clinic that sells injections of live viruses harvested from sick celebrities to obsessed fans. When he becomes infected with the disease that kills super sensation Hannah Geist, Syd becomes a target for collectors and rabid fans. He must unravel the mystery surrounding her death before he suffers the same fate.',NULL,NULL,1.1428,5.972,0,11.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1746,53425,'tt2618986',NULL,'Wayward Pines','Wayward Pines','tv',2015,'https://image.tmdb.org/t/p/w500/mK9MowBCPEn7RbsDXqN0MxyPc4.jpg','https://image.tmdb.org/t/p/original/5n3dwYOqekTyANEyRs0GNhZPfOs.jpg','Imagine the perfect American town... beautiful homes, manicured lawns, children playing safely in the streets. Now imagine never being able to leave. You have no communication with the outside world. You think you''re going insane. You must be in Wayward Pines.',NULL,NULL,11.9067,6.871,0,7.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1747,70160,'tt1392170',NULL,'The Hunger Games','The Hunger Games','movie',2012,'https://image.tmdb.org/t/p/w500/yXCbOiVDCxO71zI7cuwBRXdftq8.jpg','https://image.tmdb.org/t/p/original/yVBQ65YBYZ9UhzJ4NGdRgeXtyTL.jpg','In a dystopian society where the Capitol forces each district to send two young tributes to fight to the death in a televised spectacle, a girl volunteers to take her sister’s place, setting the stage for a struggle of survival and defiance.',NULL,NULL,8.8422,7.224,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1748,129398,'tt14404618',NULL,'The Sympathizer','The Sympathizer','tv',2024,'https://image.tmdb.org/t/p/w500/zAxObqiOEooIuQtH338b8zOaFEu.jpg','https://image.tmdb.org/t/p/original/yBYkOSSNwd5Vrh0rF18RlJbyooF.jpg','Near the end of the Vietnam War, a spy who was embedded in the South Vietnam army flees to the United States and takes up residence in a refugee community, where he continues to gather intelligence and report back to the Viet Cong.',NULL,NULL,4.3766,6.848,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1749,399174,'tt5104604',NULL,'Isle of Dogs','Isle of Dogs','movie',2018,'https://image.tmdb.org/t/p/w500/c0nUX6Q1ZB0P2t1Jo6EeFSVnOGQ.jpg','https://image.tmdb.org/t/p/original/goMGTcitprGu7YD6VZS4lUUwzRA.jpg','In the future, an outbreak of canine flu leads the mayor of a Japanese city to banish all dogs to an island used as a garbage dump. The outcasts must soon embark on an epic journey when a 12-year-old boy arrives on the island to find his beloved pet.',NULL,NULL,4.7019,7.846,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1750,50542,'tt1554523',NULL,'Under the Hawthorn Tree','山楂树之恋','movie',2010,'https://image.tmdb.org/t/p/w500/xWMGWlhRVVKd666QaBR7D7Hd7og.jpg','https://image.tmdb.org/t/p/original/hulaJrQbyYfxoNA4jfKgtVBPEsb.jpg','The daughter of a right-winger, schoolgirl Jing Qiu is sent to the countryside for reeducation, and tasked to help write a textbook. There she meets Lao San, a young soldier with a bright future ahead. Despite the class divide and parental disapproval, romance blooms against turbulent times.',NULL,NULL,2.0516,7.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1751,117447,'tt13973190',NULL,'Can''t Get You Out of My Head','Can''t Get You Out of My Head','tv',2021,'https://image.tmdb.org/t/p/w500/3LP4c5SC4Yr9BDoDLJ4XJjgV2bN.jpg','https://image.tmdb.org/t/p/original/jhmZPM753m1Wtx77llaJpM35V5t.jpg','In six films, Adam Curtis traces the different forces across the world that have led to now. It covers a wide range—including the strange roots of modern conspiracy theories, the history of China, opium and opioids, the history of Artificial Intelligence, melancholy over the loss of empire and, love and power. And explores whether modern culture, despite its radicalism, is really just part of the new system of power.',NULL,NULL,2.3216,7.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1752,1262983,'tt28821371',NULL,'MadS','MadS','movie',2024,'https://image.tmdb.org/t/p/w500/ji5oNPSEw9Rvv2lhQHlVbGU2S8W.jpg','https://image.tmdb.org/t/p/original/8lL13GCrlOii2KvMaSom2rC16Zr.jpg','A teenager stops off to see his dealer to test a new drug before heading off for a night of partying. On the way home, he picks up an injured woman, and the night takes a surreal turn.',NULL,NULL,5.1419,6.473,0,13.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1753,10543,'tt0116287',NULL,'Fear','Fear','movie',1996,'https://image.tmdb.org/t/p/w500/ut8snuINzOibbKnvpTnsGWQr4Nl.jpg','https://image.tmdb.org/t/p/original/vqycIvfLRFtdiCAvOmGX9iP7mAE.jpg','Nicole Walker always dreamed of being swept away by someone special — someone strong, sexy and sensitive who would care for her more than anything else in the world. David is all that and more: a modern-day knight who charms and seduces her, body and soul. But her perfect boyfriend is not all he seems to be. His sweet facade masks a savage, dark side that will soon transform Nicole''s dream into a nightmare.',NULL,NULL,6.1493,6.643,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1754,16052,'tt0120094',NULL,'Selena','Selena','movie',1997,'https://image.tmdb.org/t/p/w500/j8xX3yBAFOayfSaImgLZPnAcdWz.jpg','https://image.tmdb.org/t/p/original/kcBlY5FasH8ti150aYExULw53ui.jpg','In this biographical drama, Selena Quintanilla is born into a musical Mexican-American family in Texas. Her father, Abraham, realizes that his young daughter is talented and begins performing with her at small venues. She finds success and falls for her guitarist, Chris Perez, who draws the ire of her father. Seeking mainstream stardom, Selena begins recording an English-language album which, tragically, she would never complete.',NULL,NULL,2.9339,7.717,0,5.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1755,100,'tt0120735',NULL,'Lock, Stock and Two Smoking Barrels','Lock, Stock and Two Smoking Barrels','movie',1998,'https://image.tmdb.org/t/p/w500/6pJB2t3MbQUy9m5pFIBHXLqnqNd.jpg','https://image.tmdb.org/t/p/original/cXQH2u7wUIX1eoIdEj51kHXoWhX.jpg','A card shark and his unwillingly-enlisted friends need to make a lot of cash quick after losing a sketchy poker match. To do this they decide to pull a heist on a small-time gang who happen to be operating out of the flat next door.',NULL,NULL,3.5115,8.096,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1756,4824,'tt0119395',NULL,'The Jackal','The Jackal','movie',1997,'https://image.tmdb.org/t/p/w500/oXF26QmDEaRaH9Fbhs3NXtcnryx.jpg','https://image.tmdb.org/t/p/original/hctm1pdmsk0wW5XV9EwuMUYTuXc.jpg','Hired by a powerful member of the Russian mafia to avenge an FBI sting that left his brother dead, a psychopathic hitman known only as The Jackal proves an elusive target for the people charged with the task of bringing him down: a deputy FBI director, a Russian MVK Major,  and a jailed IRA terrorist who can recognize him.',NULL,NULL,5.6473,6.401,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1757,14019,'tt0812243',NULL,'Ex Drummer','Ex Drummer','movie',2007,'https://image.tmdb.org/t/p/w500/7VxXp2h9UtJP6XbeuQGqqbQzoE1.jpg','https://image.tmdb.org/t/p/original/mIYSIgQjTU0Y7e1yZ08E588A8av.jpg','Three musicians form a band. But they''re not just any musicians: each has a disability that makes them particularly unsuitable for their instrument. The guitarist is deaf, the singer is tone deaf, and the bassist has a stiff arm. They lack a drummer, and to respect the group''s uniqueness, they turn to a famous writer who has never played the drums. He accepts, but begins a manipulation that will wreak further havoc on the already largely dysfunctional band.',NULL,NULL,1.0041,6.818,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1758,173,'tt0046672',NULL,'20,000 Leagues Under the Sea','20,000 Leagues Under the Sea','movie',1954,'https://image.tmdb.org/t/p/w500/heAEH85fdxEgV98LizHbQCL95iZ.jpg','https://image.tmdb.org/t/p/original/u7GQC0o5YZE9vMWnfOoJVYIq8rS.jpg','A ship sent to investigate a wave of mysterious sinkings encounters the advanced submarine, the Nautilus, commanded by Captain Nemo.',NULL,NULL,4.3648,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1759,47665,'tt2375692',NULL,'Black Sails','Black Sails','tv',2014,'https://image.tmdb.org/t/p/w500/mZcSwrDdw6cdOVgXm496DgwrQcQ.jpg','https://image.tmdb.org/t/p/original/A7lo83g09i3cDmLRKtDiiYN8w0z.jpg','The pirate adventures of Captain Flint and his men twenty years prior to Robert Louis Stevenson’s classic “Treasure Island.” Flint, the most brilliant and most feared pirate captain of his day, takes on a fast-talking young addition to his crew who goes by the name John Silver. Threatened with extinction on all sides, they fight for the survival of New Providence Island, the most notorious criminal haven of its day – a debauched paradise teeming with pirates, prostitutes, thieves and fortune seekers, a place defined by both its enlightened ideals and its stunning brutality.',NULL,NULL,21.3061,7.623,0,11.65,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1760,16249,'tt0062737',NULL,'Blackbeard''s Ghost','Blackbeard''s Ghost','movie',1968,'https://image.tmdb.org/t/p/w500/bEMEjagTsdkUi7Jzxe0lQsquD7J.jpg','https://image.tmdb.org/t/p/original/4bAsuQeYcLbUOzxXe407yEJQoF7.jpg','The eponymous wraith returns to Earth to aid his descendant, elderly Emily Stowecroft. The villains want to kick Emily and her friends out of their group home so that they can build a crooked casino. Good guy Steve Walker gets caught in the middle of the squabble after evoking Blackbeard''s ghost.',NULL,NULL,2.2452,6.731,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1761,NULL,NULL,62,'The Curse of Monkey Island','The Curse of Monkey Island','game',1997,'https://images.igdb.com/igdb/image/upload/t_cover_big/co30yu.jpg',NULL,'The Curse of Monkey Island is the third installment in the Monkey Island adventure game series. Players control Guybrush Threepwood, a aspiring pirate, as he navigates the Caribbean to save his love Elaine from a curse that turned her into a golden statue. The game features hand-drawn cartoon graphics, voice acting, and the series'' trademark humor and puzzle-solving gameplay. Guybrush must outwit a cast of colorful characters, including the ghostly pirate LeChuck, while exploring various islands and engaging in pirate-themed challenges. The point-and-click interface allows players to interact with the environment, collect items, and solve puzzles to progress through the story. With its blend of comedy, swashbuckling adventure, and clever puzzles, The Curse of Monkey Island continues the series'' tradition of witty, engaging storytelling in a pirate-themed setting.','https://www.igdb.com/games/the-curse-of-monkey-island','["PC (Microsoft Windows)", "Mac"]',NULL,NULL,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1762,1408,'tt0112760',NULL,'Cutthroat Island','Cutthroat Island','movie',1995,'https://image.tmdb.org/t/p/w500/hYdeBZ4BFXivdouxLfQGWNE6zRx.jpg','https://image.tmdb.org/t/p/original/hHoIQVAmTg4RM7PPNhNvMlJk3mg.jpg','Morgan Adams and her slave, William Shaw, are on a quest to recover the three portions of a treasure map. Unfortunately, the final portion is held by her murderous uncle, Dawg. Her crew is skeptical of her leadership abilities, so she must complete her quest before they mutiny against her. This is made yet more difficult by the efforts of the British crown to end her pirate raids.',NULL,NULL,3.7202,5.804,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1763,NULL,NULL,63,'Escape from Monkey Island','Escape from Monkey Island','game',2000,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2311.jpg',NULL,'This is the fourth chapter of the Monkey Island series. As normal, prepare to find lots of salty humor and engaging game play from this legendary series. Loaded with lusciously rendered backgrounds and more monkeys than you can handle, Escape from Monkey features an original cinematic story full of drama. The game is highlighted by hundreds of challenging puzzles.','https://www.igdb.com/games/escape-from-monkey-island','["PC (Microsoft Windows)", "Mac", "PlayStation 2"]',NULL,NULL,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1764,205775,'tt1390411',NULL,'In the Heart of the Sea','In the Heart of the Sea','movie',2015,'https://image.tmdb.org/t/p/w500/weVvNPfk6FM9vBg3BXtRtNAmiYM.jpg','https://image.tmdb.org/t/p/original/xnuy6CYEoBmXKhTjKDSbzLe1dB5.jpg','In the winter of 1820, the New England whaling ship Essex is assaulted by something no one could believe—a whale of mammoth size and will, and an almost human sense of vengeance.',NULL,NULL,4.4357,6.772,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1765,NULL,NULL,61,'Monkey Island 2: LeChuck''s Revenge','Monkey Island 2: LeChuck''s Revenge','game',1991,'https://images.igdb.com/igdb/image/upload/t_cover_big/co30yr.jpg',NULL,'Wannabe pirate Guybrush Threepwood, and the now zombie pirate LeChuck, return in what has long been considered one of the greatest LucasArts adventure games of all time.

Having seemingly defeated the evil ghost pirate LeChuck in his first adventure, Guybrush Threepwood sets his sights on the legendary treasure of Big Whoop. But wait, LeChuck is now back in zombie form and he''s out for revenge. Guybrush will have to use his wits, his humor and his insatiable desire for adventure to defeat his nemesis once and for all and truly prove himself the greatest pirate in the Caribbean. Voodoo dolls, spitting contests and amusement parks are just some of the challenges Guybrush must overcome as he meets old friends, fights new enemies and uses every ounce of his mojo to overcome the wrath of LeChuck''s revenge.','https://www.igdb.com/games/monkey-island-2-lechuck-s-revenge','["Mac", "DOS", "Amiga"]',NULL,NULL,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1766,975335,'tt36456563',NULL,'Magellan','Magalhães','movie',2025,'https://image.tmdb.org/t/p/w500/pmFeUueU7BWLVnHrYI1FD7VnxtH.jpg','https://image.tmdb.org/t/p/original/8nv5MUtEBMX4DDkrFkDhkppRxuD.jpg','At the dawn of the modern era, Portuguese explorer Ferdinand Magellan leads an expedition under the Spanish crown in search of the first westward route to the Spice Islands. He embarks on a perilous journey across the uncharted Pacific, where his fleet faces starvation, mutiny, and the psychological toll of endless seas. Upon reaching the shores of Cebu, Magellan is pulled into a fatal conflict with the natives by his drive to spread Catholicism, culminating in his tragic doom.',NULL,NULL,2.0045,6.4,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1767,10874,'tt0117110',NULL,'Muppet Treasure Island','Muppet Treasure Island','movie',1996,'https://image.tmdb.org/t/p/w500/k4KW2CUkzDKaCy4H4cS02cO8gvV.jpg','https://image.tmdb.org/t/p/original/3RfNxQhvseerf9dNlo1dmL09RLr.jpg','Young Jim Hawkins and his two best friends embark on a voyage across the high seas in search of buried treasure, but soon find that not everyone on board can be trusted.',NULL,NULL,2.1964,6.715,0,12.49,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1768,17917,'tt0063385',NULL,'Oliver!','Oliver!','movie',1968,'https://image.tmdb.org/t/p/w500/1XJgoaOWKrqxkKeBKWLKSigqG8c.jpg','https://image.tmdb.org/t/p/original/DWRcfNaWioQwfPMG028LjHsrRq.jpg','Musical adaptation of Charles Dickens'' Oliver Twist, a classic tale of an orphan who runs away from the workhouse and joins up with a group of boys headed by the Artful Dodger and trained to be pickpockets by master thief Fagin.',NULL,NULL,2.5314,7.042,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1769,72954,'tt0472242',NULL,'Blackbeard','Blackbeard','tv',2006,'https://image.tmdb.org/t/p/w500/pK5Lh2BW9Yx4NCg4hPFfzqCsyIO.jpg','https://image.tmdb.org/t/p/original/dZa4aTqhhh9whvbsOxXpFaZkqVA.jpg','Bristol, England, 1717. Lieutenant Robert Maynard of the Royal Navy scouts the seas in order to restore safe passage to the sea lanes. He meets his match when he''s taken by a fearsome hulk of a menace in the West Indies—a pirate sailing off the Island of St. Vincent. Edward Teach has no plans for retirement. In fact, his goal-to find and lay claim to the fabled treasures of Captain Kidd.',NULL,NULL,2.4942,5.5,0,10.65,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1770,22,'tt0325980',NULL,'Pirates of the Caribbean: The Curse of the Black Pearl','Pirates of the Caribbean: The Curse of the Black Pearl','movie',2003,'https://image.tmdb.org/t/p/w500/poHwCZeWzJCShH7tOjg8RIoyjcw.jpg','https://image.tmdb.org/t/p/original/uRNgkJSkNBFbbn9fPsEjDIy8Sh3.jpg','When wily pirate Captain Barbossa seizes Jack Sparrow’s beloved ship, the Black Pearl, and kidnaps the governor’s daughter, Elizabeth Swann, blacksmith Will Turner reluctantly teams up with the unpredictable pirate Jack to rescue her—only to uncover a terrifying curse that turns Barbossa’s crew into the undead.',NULL,NULL,28.5874,7.8,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1771,NULL,NULL,542,'LEGO Pirates of the Caribbean: The Video Game','LEGO Pirates of the Caribbean: The Video Game','game',2011,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2qk0.jpg',NULL,'LEGO Pirates of the Caribbean: The Video Game is an action adventure game that brings the Pirates of the Caribbean world and all its colorful characters to life in LEGO Brick form. Players experience all the memorable scenes from all four films in the humorous and quirky LEGO Video Games style.','https://www.igdb.com/games/lego-pirates-of-the-caribbean-the-video-game','["PlayStation 3", "Wii", "PC (Microsoft Windows)", "Mac", "Xbox 360"]',NULL,NULL,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1772,11335,'tt0081353',NULL,'Popeye','Popeye','movie',1980,'https://image.tmdb.org/t/p/w500/hCCp4pESgYY6uTFARYf4UYV1BdU.jpg','https://image.tmdb.org/t/p/original/Arb8ZOPXczej8DlMNSgELDFA2dP.jpg','Popeye is a super-strong, spinach-scarfing sailor man who''s searching for his father. During a storm that wrecks his ship, Popeye washes ashore and winds up rooming at the Oyl household, where he meets Olive. Before he can win her heart, he must first contend with Olive''s fiancé, Bluto.',NULL,NULL,3.9234,5.576,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1773,NULL,NULL,195517,'Return to Monkey Island','Return to Monkey Island','game',2022,'https://images.igdb.com/igdb/image/upload/t_cover_big/co56kr.jpg',NULL,'Return to Monkey Island, the long-awaited follow-up to the legendary Secret of Monkey Island and Monkey Island 2: LeChuck''s Revenge by Ron Gilbert''s Terrible Toybox in collaboration with Devolver Digital and Lucasfilm Games, coming 2022.','https://www.igdb.com/games/return-to-monkey-island','["Xbox Series X|S", "Linux", "Android", "PC (Microsoft Windows)", "iOS", "PlayStation 5", "Mac", "Nintendo Switch"]',NULL,NULL,0,1.30166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1774,NULL,NULL,60,'The Secret of Monkey Island','The Secret of Monkey Island','game',1990,'https://images.igdb.com/igdb/image/upload/t_cover_big/co28bp.jpg',NULL,'I cursed my luck again as I slid down the monkey''s throat. Have my dreams of guzzling grog and plundering galleons been reduced to this? "Three small trials and you''re a pirate like us," they said. Fair enough. If only I could stomach the foul brew these scurvy seadogs swilled, the rest would be easy. How could I have known I''d meet a powerful and beautiful woman with a jealous suitor too stupid to realize he''d been dead for years? And how can I crawl through this great stone monkey to find a man who walks three inches above the ground and sets fire to his beard every morning?

Do business with quaint and humble shopkeepers. Participate in complex and meaningful dialogues. Visit interesting places and steal stuff. Experience the never-ending nightlife of Melee Island.','https://www.igdb.com/games/the-secret-of-monkey-island','["Atari ST/STE", "Mac", "DOS", "FM Towns", "Amiga", "Sega CD"]',NULL,NULL,0,12.21,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1775,NULL,NULL,478,'The Witcher 2: Assassins of Kings','The Witcher 2: Assassins of Kings','game',2011,'https://images.igdb.com/igdb/image/upload/t_cover_big/co1wy4.jpg',NULL,'This third-person dark fantasy Western RPG and sequel to The Witcher (2007), featuring multiple endings and branching narrative paths, follows the travels of Geralt of Rivia, witcher, who, after being falsely accused of regicide, sets out to clear his name and find the real killer, in a time of political turmoil and the brink of war between the imperialistic Nilfgaardian Empire and the Four Kingdoms.','https://www.igdb.com/games/the-witcher-2-assassins-of-kings','["Linux", "PC (Microsoft Windows)", "Mac", "Xbox 360"]',NULL,NULL,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1776,9804,'tt0114898',NULL,'Waterworld','Waterworld','movie',1995,'https://image.tmdb.org/t/p/w500/X4UyUO5jgzs3c5YafnmYKLKKYw.jpg','https://image.tmdb.org/t/p/original/lBO4ZQQldon4HTKyHmzktuuzsb5.jpg','In a futuristic world where the polar ice caps have melted and made Earth a liquid planet, a beautiful barmaid rescues a mutant seafarer from a floating island prison. They escape, along with her young charge, Enola, and sail off aboard his ship. But the trio soon becomes the target of a menacing pirate who covets the map to ''Dryland''—which is tattooed on Enola''s back.',NULL,NULL,7.6955,6.24,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1777,1084242,'tt26443597',NULL,'Zootopia 2','Zootopia 2','movie',2025,'https://image.tmdb.org/t/p/w500/oJ7g2CifqpStmoYQyaLQgEU32qO.jpg','https://image.tmdb.org/t/p/original/lgotja3xMoJZbynwHfcQcJAEMWH.jpg','After cracking the biggest case in Zootopia''s history, rookie cops Judy Hopps and Nick Wilde find themselves on the twisting trail of a great mystery when Gary De''Snake arrives and turns the animal metropolis upside down. To crack the case, Judy and Nick must go undercover to unexpected new parts of town, where their growing partnership is tested like never before.',NULL,NULL,62.0739,7.676,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1778,61014,'tt2937900',NULL,'The Knick','The Knick','tv',2014,'https://image.tmdb.org/t/p/w500/oeEqDSIVOi6q0GcZj8L9Q6G7fGC.jpg','https://image.tmdb.org/t/p/original/mw9EcIFuWUjkOTF60aYpbpM02Qu.jpg','Set in downtown New York in 1900, ''The Knick'' is centered on the Knickerbocker Hospital and its staff, notably Dr. John Thackery, the hospital''s brilliant chief surgeon who pushes medicine''s boundaries, pioneering new procedures despite a severe drug addiction.',NULL,NULL,5.413,7.85,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1779,5279,'tt0280707',NULL,'Gosford Park','Gosford Park','movie',2001,'https://image.tmdb.org/t/p/w500/7r8DeZuaaHCiOEbkqZC6MFmwJ69.jpg','https://image.tmdb.org/t/p/original/936dZMmlCejiIzDe5jWsxdTSoOf.jpg','In 1930s England, a group of pretentious rich and famous gather together for a weekend of relaxation at a hunting resort. But when a murder occurs, each one of these interesting characters becomes a suspect.',NULL,NULL,2.97,6.817,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1780,167073,'tt2381111',NULL,'Brooklyn','Brooklyn','movie',2015,'https://image.tmdb.org/t/p/w500/cs7W8j5lI7qzRW6tKSj9p1Q0Ze7.jpg','https://image.tmdb.org/t/p/original/2T4bqHgYfzXNQoALJsvhW40kDTg.jpg','In 1950s Ireland and New York, young Eilis Lacey has to choose between two men and two countries.',NULL,NULL,4.7308,7.297,0,12.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1781,64682,'tt1343092',NULL,'The Great Gatsby','The Great Gatsby','movie',2013,'https://image.tmdb.org/t/p/w500/nimh1rrDDLhgpG8XAYoUZXHYwb6.jpg','https://image.tmdb.org/t/p/original/j9NGh8z7v2mLpGKkvUAHox81bqi.jpg','An adaptation of F. Scott Fitzgerald''s Long Island-set novel, where Midwesterner Nick Carraway is lured into the lavish world of his neighbor, Jay Gatsby. Soon enough, however, Carraway will see through the cracks of Gatsby''s nouveau riche existence, where obsession, madness, and tragedy await.',NULL,NULL,7.5348,7.35,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1782,3131,'tt0217505',NULL,'Gangs of New York','Gangs of New York','movie',2002,'https://image.tmdb.org/t/p/w500/lemqKtcCuAano5aqrzxYiKC8kkn.jpg','https://image.tmdb.org/t/p/original/p8yXQse3IDZiwEjWRHda3EzDQjA.jpg','In early 1860s New York, Irish immigrant Amsterdam Vallon is released from prison and returns to the Five Points, seeking revenge against his father''s killer, William Cutting, a powerful anti-immigrant gang leader. He knows that revenge can only be attained by infiltrating Cutting''s inner circle. Vallon''s journey becomes a fight for personal survival and to find a place for the Irish people.',NULL,NULL,6.1739,7.321,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1783,788147,'tt0072314',NULL,'A Tree Grows in Brooklyn','A Tree Grows in Brooklyn','movie',1974,'https://image.tmdb.org/t/p/w500/eg90z0DG4WmpanuukvgwfTr4gZA.jpg',NULL,'The story of a family living in a New York City slum in 1912, headed by a loving but alcoholic father and a strong-willed mother.',NULL,NULL,0.3293,10.0,0,8.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1784,10436,'tt0106226',NULL,'The Age of Innocence','The Age of Innocence','movie',1993,'https://image.tmdb.org/t/p/w500/5Tuyt26v7qNR8Cl3m7ZRx36rduf.jpg','https://image.tmdb.org/t/p/original/kMJlMlf1jYdk7L7YTSi231rjBtk.jpg','In 19th century New York high society, a young lawyer falls in love with a woman separated from her husband, while he is engaged to the woman''s cousin.',NULL,NULL,3.6146,6.96,0,8.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1785,238,'tt0068646',NULL,'The Godfather','The Godfather','movie',1972,'https://image.tmdb.org/t/p/w500/3bhkrj58Vtu7enYsRolD1fZdja1.jpg','https://image.tmdb.org/t/p/original/tSPT36ZKlP2WVHJLM4cQPLSzv3b.jpg','Spanning the years 1945 to 1955, a chronicle of the fictional Italian-American Corleone crime family. When organized crime family patriarch, Vito Corleone barely survives an attempt on his life, his youngest son, Michael steps in to take care of the would-be killers, launching a campaign of bloody revenge.',NULL,NULL,43.2937,8.687,0,12.68,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1786,240,'tt0071562',NULL,'The Godfather Part II','The Godfather Part II','movie',1974,'https://image.tmdb.org/t/p/w500/hek3koDUyRQk7FIhPXsa6mT2Zc3.jpg','https://image.tmdb.org/t/p/original/kGzFbGhp99zva6oZODW5atUtnqi.jpg','In the continuing saga of the Corleone crime family, a young Vito Corleone grows up in Sicily and in 1910s New York. In the 1950s, Michael Corleone attempts to expand the family business into Las Vegas, Hollywood and Cuba.',NULL,NULL,31.1864,8.572,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1787,1058619,'tt15444046',NULL,'Divinity','Divinity','movie',2023,'https://image.tmdb.org/t/p/w500/3Ri4XxXNCUKwlZWXgoVNftF7GIY.jpg','https://image.tmdb.org/t/p/original/iu5RMfBVlU4v0drskl7sx3Gai0s.jpg','Two brothers crash into the decaying Earth to stop a capitalist from manufacturing an immortality serum, which is synthesized utilizing heinous methods and leaving an increasingly dire infertility rate in its wake.',NULL,NULL,2.3408,5.111,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1788,42009,'tt2085059',NULL,'Black Mirror','Black Mirror','tv',2011,'https://image.tmdb.org/t/p/w500/seN6rRfN0I6n8iDXjlSMk1QjNcq.jpg','https://image.tmdb.org/t/p/original/dg3OindVAGZBjlT3xYKqIAdukPL.jpg','Twisted tales run wild in this mind-bending anthology series that reveals humanity''s worst traits, greatest innovations and more.',NULL,NULL,61.284,8.3,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1789,126889,'tt2316204',NULL,'Alien: Covenant','Alien: Covenant','movie',2017,'https://image.tmdb.org/t/p/w500/zecMELPbU5YMQpC81Z8ImaaXuf9.jpg','https://image.tmdb.org/t/p/original/iXXPaQPfQowpQ5UvhsHLj9BgFhe.jpg','The crew of the colony ship Covenant, bound for a remote planet on the far side of the galaxy, discovers what they think is an uncharted paradise but is actually a dark, dangerous world.',NULL,NULL,9.2381,6.2,0,6.04666666666666685e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1790,128098,'tt3960394',NULL,'Interview with the Vampire','Interview with the Vampire','tv',2022,'https://image.tmdb.org/t/p/w500/mQ0fbfc5ELwb2zjFZM4uwAnN3ee.jpg','https://image.tmdb.org/t/p/original/1tADVruLbywl7P3TOVQmNza3aAO.jpg','A century-old vampire from New Orleans reunites with an ailing journalist to recount his life of bloodlust and his tumultuous relationship with the rakish Frenchman who turned him.',NULL,NULL,20.1251,7.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1791,1213,'tt0134119',NULL,'The Talented Mr. Ripley','The Talented Mr. Ripley','movie',1999,'https://image.tmdb.org/t/p/w500/6ojHgqtIR41O2qLKa7LFUVj0cZa.jpg','https://image.tmdb.org/t/p/original/nGVe984XESYhn5V5zspqQexPekA.jpg','Tom Ripley is a calculating young man who believes it''s better to be a fake somebody than a real nobody. Opportunity knocks in the form of a wealthy U.S. shipbuilder who hires Tom to travel to Italy to bring back his playboy son, Dickie. Ripley worms his way into the idyllic lives of Dickie and his girlfriend, plunging into a daring scheme of duplicity, lies and murder.',NULL,NULL,5.7734,7.2,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1792,45790,'tt2359704',NULL,'JoJo''s Bizarre Adventure','ジョジョの奇妙な冒険','tv',2012,'https://image.tmdb.org/t/p/w500/ogAWwbh3frWtiTyyXrZaVFtqCgp.jpg','https://image.tmdb.org/t/p/original/mLKN1dsimKPiXCZ48KED0X8a02t.jpg','Follow the intergenerational feud between the Joestar Family and various forces of evil, the most prominent of which is Dio Brando and his followers.',NULL,NULL,53.8353,8.562,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1793,9954,'tt0475944',NULL,'The Covenant','The Covenant','movie',2006,'https://image.tmdb.org/t/p/w500/r6jbhgqKao3K3in4eftu7gqgMNH.jpg','https://image.tmdb.org/t/p/original/vn9BFSlvwILE4wPUITi4XDD3fEK.jpg','Four young men who belong to a supernatural legacy are forced to battle a fifth power long thought to have died out. Another great force they must contend with is the jealousy and suspicion that threatens to tear them apart.',NULL,NULL,4.4163,5.605,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1794,1394494,'tt34579888',NULL,'The Biosphere: Adventure Awaits','The Biosphere: Adventure Awaits','movie',2022,'https://image.tmdb.org/t/p/w500/r0EnqCcQuX5vYOlERnmLSRixfnW.jpg',NULL,'An analogue horror reflecting a collection of tapes surrounding the shrouded mystery of the popular Wisconsin Dells attraction, "The Biosphere", from the early 2000''s.',NULL,NULL,0.752,0.0,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1795,42497,'tt0067580',NULL,'Pink Narcissus','Pink Narcissus','movie',1971,'https://image.tmdb.org/t/p/w500/kaZiiGE6820KyFF9XkzPB9Rx9qn.jpg','https://image.tmdb.org/t/p/original/jDgaKZG5KfEMKYmxt6G3mpKBfo6.jpg','An outrageous erotic poem focusing on the daydreams of a beautiful boy prostitute who, from the seclusion of his ultra-kitsch apartment, conceives a series of interlinked narcissistic fantasies populated by matadors, dancing boys, slaves, and leather-clad bikers.',NULL,NULL,2.0152,6.3,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1796,59436,'tt1605783',NULL,'Midnight in Paris','Midnight in Paris','movie',2011,'https://image.tmdb.org/t/p/w500/4wBG5kbfagTQclETblPRRGihk0I.jpg','https://image.tmdb.org/t/p/original/b5bcKhvN6VP82U5ztNdPfOLiolD.jpg','While on a trip to Paris with his fiancée''s family, a nostalgic screenwriter finds himself mysteriously going back to the 1920s every day at midnight.',NULL,NULL,5.6558,7.511,0,13.775,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1797,37209,'tt0366996',NULL,'The Saddest Music in the World','The Saddest Music in the World','movie',2003,'https://image.tmdb.org/t/p/w500/7ATs79HpMv82hcPM3iv6kwugyDj.jpg','https://image.tmdb.org/t/p/original/1iewRrC7LwkANjLzu2mimlNV0Pe.jpg','In Depression-era Winnipeg, a legless beer baroness hosts a contest for the saddest music in the world, offering a grand prize of $25,000.',NULL,NULL,0.7721,6.8,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1798,9986,'tt0413895',NULL,'Charlotte''s Web','Charlotte''s Web','movie',2006,'https://image.tmdb.org/t/p/w500/fU0IR5HF8KxQbZijuWKPTrY81Qv.jpg','https://image.tmdb.org/t/p/original/x7B2zT2OL8fKM53Wgzqz6nc7r02.jpg','Wilbur the pig is scared of the end of the season, because he knows that come that time, he will end up on the dinner table. He hatches a plan with Charlotte, a spider that lives in his pen, to ensure that this will never happen.',NULL,NULL,4.7,6.233,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1799,1115544,'tt27552099',NULL,'Mike & Nick & Nick & Alice','Mike & Nick & Nick & Alice','movie',2026,'https://image.tmdb.org/t/p/w500/7F0jc75HrSkLVcvOXR2FXAIwuEv.jpg','https://image.tmdb.org/t/p/original/uNToXatdunyvWXyXMrTI1nLvh6r.jpg','Two gangsters and the woman they love try to survive the most dangerous night of their lives. As if that wasn’t enough, there’s one wild ingredient added to the mix: a time machine.',NULL,NULL,16.8113,6.733,0,1.42419999999999991e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1800,10539,'tt0116683',NULL,'James and the Giant Peach','James and the Giant Peach','movie',1996,'https://image.tmdb.org/t/p/w500/vNEGobe23vW43mSPYVaVaBLP6qV.jpg','https://image.tmdb.org/t/p/original/6kTLm7zfwKAgAcGnaVU0uT4QYug.jpg','When the young orphan boy James spills a magic bag of crocodile tongues, he finds himself in possession of a giant peach that flies him away to strange lands.',NULL,NULL,3.3647,6.6,0,1.23533333333333317e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1801,1600,'tt0101765',NULL,'The Double Life of Véronique','La Double Vie de Véronique','movie',1991,'https://image.tmdb.org/t/p/w500/oqRyO9xrNBRaxqF9pCHHgLuaATx.jpg','https://image.tmdb.org/t/p/original/vjsFyeCf5W5rxCFpS9MIAEZJkIG.jpg','Véronique is a beautiful young French woman who aspires to be a renowned singer; Weronika lives in Poland, has a similar career goal and looks identical to Véronique, though the two are not related. The film follows both women as they contend with the ups and downs of their individual lives, with Véronique embarking on an unusual romance with Alexandre Fabbri, a puppeteer who may be able to help her with her existential issues.',NULL,NULL,2.6945,7.487,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1802,251,'tt0099653',NULL,'Ghost','Ghost','movie',1990,'https://image.tmdb.org/t/p/w500/w9RaPHov8oM5cnzeE27isnFMsvS.jpg','https://image.tmdb.org/t/p/original/6nLdSON3ErniBZTXWG7WRqs5jGz.jpg','After a young man is murdered, his spirit stays behind to warn his lover of impending danger, with the help of a reluctant psychic.',NULL,NULL,9.725,7.241,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1803,14412,'tt0082089',NULL,'Body Heat','Body Heat','movie',1981,'https://image.tmdb.org/t/p/w500/5LipPcaW1J9IjAP7TOTesw8OcMS.jpg','https://image.tmdb.org/t/p/original/g6seVGyULRgvHQfHZswlcbZlr1E.jpg','During an extreme heatwave, a beautiful Florida woman and a seedy lawyer engage in an affair while plotting the murder of her rich husband.',NULL,NULL,4.1465,7.0,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1804,5203,'tt0100934',NULL,'Wild Orchid','Wild Orchid','movie',1989,'https://image.tmdb.org/t/p/w500/6UfS8J9Ixn0BAv1aeuAFWom5YEk.jpg','https://image.tmdb.org/t/p/original/f3jxLETlVbHEoGqPR9X7ZB0LG8u.jpg','A woman lawyer becomes mesmerized by a self-made millionaire during an encounter in Rio setting off a series of erotic encounters.',NULL,NULL,3.6333,5.279,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1805,2056,'tt0340377',NULL,'The Station Agent','The Station Agent','movie',2003,'https://image.tmdb.org/t/p/w500/kjJg6eJa9I9flfHaJG67ecEv8YX.jpg','https://image.tmdb.org/t/p/original/bX5UVSVDOcuFMJh2zWN6gXbKswM.jpg','When his only friend dies, a man born with dwarfism moves to rural New Jersey to live a life of solitude, only to meet a chatty hot dog vendor and a woman dealing with her own personal loss.',NULL,NULL,4.0071,7.34,0,1.23633333333333315e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1806,129,'tt0245429',NULL,'Spirited Away','千と千尋の神隠し','movie',2001,'https://image.tmdb.org/t/p/w500/39wmItIWsg5sZMyRUHLkWBcuVCM.jpg','https://image.tmdb.org/t/p/original/dyJvKsNs2KP8qQnAXbRwDjblViy.jpg','A young girl, Chihiro, becomes trapped in a strange new world of spirits. When her parents undergo a mysterious transformation, she must call upon the courage she never knew she had to free her family.',NULL,NULL,42.5572,8.535,0,16.12,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1807,15318,'tt0413893',NULL,'The Taste of Tea','茶の味','movie',2004,'https://image.tmdb.org/t/p/w500/yapwfNElQYFY9TaVS03jv6Gk2Rs.jpg','https://image.tmdb.org/t/p/original/kmPpgz9TNhQO8IQcZMtmznRtgKg.jpg','A spell of time in the life of the five-piece Haruno family in rural Tochigi Prefecture. Yoshiko is not an ordinary housewife, instead working on an animated film project. Uncle Ayano, a successful music producer, is looking to get his head together after living in Tokyo. Meanwhile, Sachiko is concerned with why she seems to be followed by a giant version of herself. As the lazy days pass by, each member of the family is followed in a series of episodic vignettes.',NULL,NULL,2.045,7.532,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1808,1109092,'tt28385578',NULL,'Promise of August','8月の約束','movie',1995,'https://image.tmdb.org/t/p/w500/bdMeAdjdv481SoYLNWH1s9PrSiL.jpg','https://image.tmdb.org/t/p/original/4qrRaONPTglTQjGOrroe0ALbrZ6.jpg','Three college girls arrive in the countryside in search of an area where marijuana grows. Hitchhiking, they stop the car of a suicidal man, who falls in love with one of the girls at first sight.',NULL,NULL,0.1329,8.0,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1809,4538,'tt0838221',NULL,'The Darjeeling Limited','The Darjeeling Limited','movie',2007,'https://image.tmdb.org/t/p/w500/oSW5OVXTulaIXcoNwJAp5YEKpbP.jpg','https://image.tmdb.org/t/p/original/hKJ513GbmTSmTXJU1uCXclh5Wkh.jpg','Three American brothers who have not spoken to each other in a year set off on a train voyage across India with a plan to find themselves and bond with each other -- to become brothers again like they used to be. Their "spiritual quest", however, veers rapidly off-course (due to events involving over-the-counter pain killers, Indian cough syrup, and pepper spray).',NULL,NULL,3.9926,7.146,0,11.685,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1810,15080,'tt0102587',NULL,'Only Yesterday','おもひでぽろぽろ','movie',1991,'https://image.tmdb.org/t/p/w500/tOSnFE9e82iH3ZAzSTtuOkBsabJ.jpg','https://image.tmdb.org/t/p/original/jsIxoKIuH6lLt4Y3NW7Tf1BwcIO.jpg','In lyrical switches between the present and the past, Taeko contemplates the arc of her life, and wonders if she has been true to the dreams of her childhood self.',NULL,NULL,3.7768,7.389,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1811,14226,'tt0437447',NULL,'Riding Alone for Thousands of Miles','千里走单骑','movie',2005,'https://image.tmdb.org/t/p/w500/shA3I9K9bjNVyFsefq73CxXsauQ.jpg','https://image.tmdb.org/t/p/original/jjyNoqCHrtTyNoor27nDucEtCtd.jpg','Takada, a Japanese fisherman has been estranged from his son for many years, but when the son is diagnosed with terminal cancer his daughter-in-law, Rie, summons him to the hospital. Through a series of obstacles and relationships, he is brought unexpectedly closer to both an understanding of himself and of his son.',NULL,NULL,1.2045,7.121,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1812,110420,'tt2140203',NULL,'Wolf Children','おおかみこどもの雨と雪','movie',2012,'https://image.tmdb.org/t/p/w500/vHMvBkr42Gh3OORcnmfCFfqJ1E.jpg','https://image.tmdb.org/t/p/original/oMqgJMCaNIqeJtilc71D4nRqdmt.jpg','After her werewolf lover unexpectedly dies in an accident, a woman must find a way to raise the son and daughter that she had with him. However, their inheritance of their father''s traits prove to be a challenge for her.',NULL,NULL,4.7081,8.219,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1813,414453,'tt5990474',NULL,'Columbus','Columbus','movie',2017,'https://image.tmdb.org/t/p/w500/3ZE5Wl3CdfUH4BkWRmyMKPHkWHx.jpg','https://image.tmdb.org/t/p/original/xN88RKXxjPAcQsdBz6XavZ00PFh.jpg','When a renowned architecture scholar falls suddenly ill during a speaking tour, his son Jin finds himself stranded in Columbus, Indiana - a small Midwestern city celebrated for its many significant modernist buildings. Jin strikes up a friendship with Casey, a young architecture enthusiast who works at the local library.',NULL,NULL,1.6849,7.09,0,12.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1814,28276,'tt0053134',NULL,'Good Morning','お早よう','movie',1959,'https://image.tmdb.org/t/p/w500/dXy2LFsE0VlHlHJU3SLBdJgrzEq.jpg','https://image.tmdb.org/t/p/original/qH9wiXnx9mU9kNGCH1exaey9CqU.jpg','A lighthearted take on director Yasujiro Ozu’s perennial theme of the challenges of inter­generational relationships, Good Morning tells the story of two young boys who stop speaking in protest after their parents refuse to buy a television set. Ozu weaves a wealth of subtle gags through a family portrait as rich as those of his dramatic films, mocking the foibles of the adult world through the eyes of his child protagonists. Shot in stunning color and set in a suburb of Tokyo where housewives gossip about the neighbors’ new washing machine and unemployed husbands look for work as door-to-door salesmen, this charming comedy refashions Ozu’s own silent classic I Was Born, But . . . to gently satirize consumerism in postwar Japan.',NULL,NULL,1.7764,7.718,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1815,88284,'tt2178941',NULL,'Barbara','Barbara','movie',2012,'https://image.tmdb.org/t/p/w500/i7yjITqgz5zSW1jJWzxfwQsyDeo.jpg','https://image.tmdb.org/t/p/original/zQ6jbZKqfNMeqFjEzNhDV4EZinG.jpg','In 1980s East Germany, Berlin doctor Barbara is banished to a country medical clinic for applying for an exit visa. Deeply unhappy with her reassignment and fearful of her co-workers as possible Stasi informants, Barbara stays aloof, especially from the good-natured clinic head, Andre.',NULL,NULL,1.2247,7.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1816,9953,'tt0369672',NULL,'A Love Song for Bobby Long','A Love Song for Bobby Long','movie',2004,'https://image.tmdb.org/t/p/w500/7HoqdnUpIcK1CnFDNNONPZ9PBoi.jpg','https://image.tmdb.org/t/p/original/8KOtoiqtNNMBR2STj9ZDWeEoTpx.jpg','A headstrong young woman returns to New Orleans after the death of her estranged mother.',NULL,NULL,1.778,6.799,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1817,37797,'tt0113824',NULL,'Whisper of the Heart','耳をすませば','movie',1995,'https://image.tmdb.org/t/p/w500/5FROLD8zpWFs9ja7aYho1uOMJHg.jpg','https://image.tmdb.org/t/p/original/rphor0XQcYO4CQoQ6auaQm3UPap.jpg','Shizuku lives a simple life, dominated by her love for stories and writing. One day she notices that all the library books she has have been previously checked out by the same person: "Seiji Amasawa."',NULL,NULL,6.1447,7.9,0,11.095,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1818,4291,'tt0199683',NULL,'Kikujiro','菊次郎の夏','movie',1999,'https://image.tmdb.org/t/p/w500/zTelT1xAO4Owxk1jHJM4puoei5N.jpg','https://image.tmdb.org/t/p/original/htvZHcNr7pNvZvoUOTDXigG9pf2.jpg','Brash, loudmouthed and opportunistic, Kikujiro is the unlikely companion for Masao who is determined to see the mother he has never met. The two begin a series of adventures which soon turns out to be a whimsical journey of laughter and tears with a wide array of surprises and unique characters along the way.',NULL,NULL,6.2702,7.512,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1819,81860,'tt0131013',NULL,'A Quiet Life','静かな生活','movie',1995,'https://image.tmdb.org/t/p/w500/hPfrxxwd6kLkqMH9IoMxuT8Z0r6.jpg','https://image.tmdb.org/t/p/original/umGze4Q1fFJ4hIW6s31O2NXcgEl.jpg','A melodrama about the life of a mentally disabled young man and his devoted sister after their famous novelist father and housewife mother go to Australia on a business trip.',NULL,NULL,0.7735,7.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1820,80,'tt0381681',NULL,'Before Sunset','Before Sunset','movie',2004,'https://image.tmdb.org/t/p/w500/4sW5XH9ZfYXpvFzev00S1IGAEbg.jpg','https://image.tmdb.org/t/p/original/tcZi0LQc5iu2u6i5aOWyj9NBBvl.jpg','Nine years later, Jesse travels across Europe giving readings from a book he wrote about the night he spent in Vienna with Celine. After his reading in Paris, Celine finds him, and they spend part of the day together before Jesse has to again leave for a flight. They are both in relationships now, and Jesse has a son, but as their strong feelings for each other start to return, both confess a longing for more.',NULL,NULL,6.9569,7.8,0,11.455,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1821,25050,'tt1087578',NULL,'Still Walking','歩いても 歩いても','movie',2008,'https://image.tmdb.org/t/p/w500/FWJbhAPdwiwKhUaAyz841jpYa1.jpg','https://image.tmdb.org/t/p/original/lvSB0bnLzuxwrfTlI2l13gctWRn.jpg','A family gathers together for a commemorative ritual whose nature only gradually becomes clear.',NULL,NULL,2.8292,7.79,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1822,92989,'tt0087164',NULL,'A Summer at Grandpa''s','冬冬的假期','movie',1984,'https://image.tmdb.org/t/p/w500/gnmZGNut8TLk5630yiGgoMvPaah.jpg','https://image.tmdb.org/t/p/original/b0Jsfl5xW87GOAAFEoqaf3GAIXF.jpg','A coming-of-age story about a young brother and sister whom spend a pivotal summer in the country with their grandparents.',NULL,NULL,1.3527,7.491,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1823,104171,'tt0086631',NULL,'The Green, Green Grass of Home','在那河畔青草青','movie',1982,'https://image.tmdb.org/t/p/w500/3g0vba2RNfDxL0Ccu3aM7vzBVB7.jpg','https://image.tmdb.org/t/p/original/xm7ULWOA9MECQpXhcPowip7uyT4.jpg','A substitute teacher from Taipei arrives in a country village to teach a class of mischievous students. He soon falls in love with nature, country life and a fellow teacher at the school.',NULL,NULL,0.6119,6.514,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1824,12429,'tt0876563',NULL,'Ponyo','崖の上のポニョ','movie',2008,'https://image.tmdb.org/t/p/w500/yp8vEZflGynlEylxEesbYasc06i.jpg','https://image.tmdb.org/t/p/original/shqLeIkqPAAXM8iT6wVDiXUYz1p.jpg','When Sosuke, a young boy who lives on a clifftop overlooking the sea, rescues a stranded goldfish named Ponyo, he discovers more than he bargained for. Ponyo is a curious, energetic young creature who yearns to be human, but even as she causes chaos around the house, her father, a powerful sorcerer, schemes to return Ponyo to the sea.',NULL,NULL,9.5585,7.76,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1825,29161,'tt0087909',NULL,'Phenomena','Phenomena','movie',1985,'https://image.tmdb.org/t/p/w500/dhk14s8ogQkbf6re3HLKV2UBHjx.jpg','https://image.tmdb.org/t/p/original/eoQLLl0jNTd3AYjPlQO7Ek6Xwt9.jpg','A young girl, with an amazing ability to communicate with insects, is transferred to an exclusive Swiss boarding school, where her unusual capability might help solve a string of murders.',NULL,NULL,1.9122,6.772,0,11.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1826,25538,'tt0244316',NULL,'Yi Yi','一一','movie',2000,'https://image.tmdb.org/t/p/w500/mR8dSQZI8X6Z1NClJhFrtJp636z.jpg','https://image.tmdb.org/t/p/original/x903dx8Km6XNLFEmvbXc98vePSV.jpg','A Taipei family faces personal and moral uncertainty as everyday events test their relationships and sense of purpose.',NULL,NULL,3.3529,7.9,0,1.20166666666666657e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1827,11597,'tt0105629',NULL,'Toys','Toys','movie',1992,'https://image.tmdb.org/t/p/w500/l0YBVvOvOxoOkggTZ70tNGvGQo4.jpg','https://image.tmdb.org/t/p/original/94lkfilyPNfvhqlELWV9CHdfvaH.jpg','Leslie Zevo is a fun-loving inventor who must save his late father''s toy factory from his evil uncle, Leland, a war-mongering general who rules the operation with an iron fist and builds weapons disguised as toys.',NULL,NULL,3.3229,5.304,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1828,315846,'tt3756788',NULL,'Our Little Sister','海街diary','movie',2015,'https://image.tmdb.org/t/p/w500/x9A0AtEg5EEYbDGfP8NqH3C9w8M.jpg','https://image.tmdb.org/t/p/original/b0Xdh15XGZbKON9CbFVB5sTqrSJ.jpg','After the death of their estranged father, 3 adult sisters invite their teenaged half-sister to live with them.',NULL,NULL,2.7475,7.561,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1829,118381,'tt0159251',NULL,'Anna Magdalena','安娜瑪德蓮娜','movie',1998,'https://image.tmdb.org/t/p/w500/6UA76QKXKnirCtzkYnFB0zI669h.jpg','https://image.tmdb.org/t/p/original/pCNwkvt5Db6Fl9d0Nh1MyDKe3qx.jpg','Two young men fall for the woman staying upstairs when she practises J.S. Bach''s "Notebook for Anna Magdalena".',NULL,NULL,0.8854,6.5,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1830,40339,'tt0083017',NULL,'Private House of the SS','Casa privata per le SS','movie',1977,'https://image.tmdb.org/t/p/w500/bQFkim4BLyg53QtmJAijiXy1JD5.jpg','https://image.tmdb.org/t/p/original/7jBnqB4KK9cZJSMPtRYRDjpACVE.jpg','Top Nazi officials, intent on rooting out traitors and those in the military who may be plotting to overthrow Adolf Hitler, recruit and train a group of beautiful prostitutes whose mission is to use any means necessary to uncover plots against the Fuhrer.',NULL,NULL,0.8458,5.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1831,139471,'tt0421725',NULL,'Big Bird in Japan','Big Bird in Japan','movie',1988,'https://image.tmdb.org/t/p/w500/nkaXD136ZMGNsuwxo5fgpG3oIk8.jpg','https://image.tmdb.org/t/p/original/xx7Ys1vNYQhotk9pGxgUMHqzeyb.jpg','While visiting Japan, Big Bird wanders off from a guided tour bus in Tokyo, and is lost until a Japanese woman helps him get to where he needs to go. The woman, however, is hiding a secret.',NULL,NULL,0.5078,9.071,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1832,242531,'tt27583913',NULL,'Thomas the Tank Engine and Friends','Thomas the Tank Engine and Friends','tv',2022,'https://image.tmdb.org/t/p/w500/hh9m27NHRWjWV4YFgFwQAmGkdyN.jpg','https://image.tmdb.org/t/p/original/p9kX7P5aVwREB55HbWcpA4YXPp8.jpg','Children''s entertainment',NULL,NULL,0.3295,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1833,490003,'tt7681902',NULL,'Won''t You Be My Neighbor?','Won''t You Be My Neighbor?','movie',2018,'https://image.tmdb.org/t/p/w500/8qE8NZjiP2M884baH0VoLF828Vp.jpg','https://image.tmdb.org/t/p/original/yrepQdpreOorLyBJyvZkGn3Izfe.jpg','For more than thirty years, and through his television program, Fred Rogers (1928-2003), host, producer, writer and pianist, accompanied by his puppets and his many friends, spoke directly to young children about some of life''s most important issues.',NULL,NULL,1.0711,7.986,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1834,1069905,'tt30446847',NULL,'Jay Kelly','Jay Kelly','movie',2025,'https://image.tmdb.org/t/p/w500/lEXYpY9X17pGC7xYYy17Guv0L3J.jpg','https://image.tmdb.org/t/p/original/wR9D9hQvCVBux16NauY4b7letdU.jpg','Famous movie actor Jay Kelly embarks on a journey of self-discovery, confronting both his past and present, accompanied by his devoted manager, Ron.',NULL,NULL,2.8296,6.189,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1835,2860,'tt0065772',NULL,'Claire''s Knee','Le Genou de Claire','movie',1970,'https://image.tmdb.org/t/p/w500/wekWNf0Nj6fkfR6pOjPojMAqz69.jpg','https://image.tmdb.org/t/p/original/eirSTJkaGgEB8mpunntNrXI1nNH.jpg','On the eve of his wedding, on holiday on the Lake Annecy shore, a career diplomat visits an old acquaintance, perhaps a former girlfriend. Through her he meets an intense teenager, Laura, and then lusts after her sister, Claire. Whilst Laura attempts to flirt with him, his fantasy becomes focused on wanting to caress Claire''s knee.',NULL,NULL,1.1777,7.275,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1836,869612,'tt15342244',NULL,'Master Gardener','Master Gardener','movie',2023,'https://image.tmdb.org/t/p/w500/pmcYL7mgjVlWhFyNCc05mFTt6at.jpg','https://image.tmdb.org/t/p/original/kmsC7wvrKbla7kCg6YTWHtxmaGI.jpg','Narvel Roth is a meticulous horticulturist who is devoted to tending the grounds of a beautiful estate and pandering to his employer, the wealthy dowager Mrs. Haverhill. When she demands that he take on her wayward and troubled niece, it unlocks dark secrets from a buried violent past.',NULL,NULL,1.3175,6.026,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1837,9410,'tt0119223',NULL,'Great Expectations','Great Expectations','movie',1998,'https://image.tmdb.org/t/p/w500/djLsfl3lm7BZKWsKfVZ2wM1ZMrP.jpg','https://image.tmdb.org/t/p/original/laXkVCU5DE8Dib0QVHUUUsE7FM6.jpg','Loosely based on the Charles Dickens'' classic novel, "Great Expectations" is a sensual tale of a young man''s unforgettable passage into manhood, and the three individuals who will undeniably change his life forever. Through the surprising interactions of these vivid characters, "Great Expectations" takes a unique and contemporary look at life''s great coincidences.',NULL,NULL,3.5766,6.643,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1838,2360,'tt0195234',NULL,'Saving Grace','Saving Grace','movie',2000,'https://image.tmdb.org/t/p/w500/ml8XwUomPfisNsKmluP8TIZOR89.jpg','https://image.tmdb.org/t/p/original/7GQH1qYmqu0llcYque6flDmSR55.jpg','Unexpectedly widowed, prim and proper housewife Grace Trevethyn finds herself in dire financial straits when she inherits massive debts her late husband had been accruing for years. Faced with losing her house, she decides to use her talent for horticulture and hatches a plan to grow potent marijuana which can be sold at an astronomical price, thus solving her financial crisis.',NULL,NULL,1.6345,6.537,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1839,930564,'tt17351924',NULL,'Saltburn','Saltburn','movie',2023,'https://image.tmdb.org/t/p/w500/zGTfMwG112BC66mpaveVxoWPOaB.jpg','https://image.tmdb.org/t/p/original/yCN98oNvavyHvFvdvwqmw9TkY9A.jpg','Struggling to find his place at Oxford University, student Oliver Quick finds himself drawn into the world of the charming and aristocratic Felix Catton, who invites him to Saltburn, his eccentric family''s sprawling estate, for a summer never to be forgotten.',NULL,NULL,5.3962,6.956,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1840,860004,NULL,NULL,'Moments on the Set of I Am Love','Moments on the Set of I Am Love','movie',2009,'https://image.tmdb.org/t/p/w500/lfKFOt6yagW4jxqHueSrx8DiU8P.jpg',NULL,'A documentary behind the scenes of Luca Guadagnino''s 𝘐 𝘈𝘮 𝘓𝘰𝘷𝘦.',NULL,NULL,0.1907,0.0,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1841,617653,'tt4244994',NULL,'The Last Duel','The Last Duel','movie',2021,'https://image.tmdb.org/t/p/w500/zjrJE0fpzPvX8saJXj8VNfcjBoU.jpg','https://image.tmdb.org/t/p/original/4LrL40XecjGLRpX5I2gzMTUt04l.jpg','King Charles VI declares that Knight Jean de Carrouges settle his dispute with his squire, Jacques Le Gris, by challenging him to a duel.',NULL,NULL,4.6083,7.404,0,15.032,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1842,2000,'tt0068182',NULL,'Aguirre, the Wrath of God','Aguirre, der Zorn Gottes','movie',1972,'https://image.tmdb.org/t/p/w500/zU1FLiGJw3m3iFrakwA0SzFvIPV.jpg','https://image.tmdb.org/t/p/original/kfSZaOr9ApNR52gWKlpXHD0id0W.jpg','A few decades after the destruction of the Inca Empire, a Spanish expedition led by the infamous Aguirre leaves the mountains of Peru and goes down the Amazon River in search of the lost city of El Dorado. When great difficulties arise, Aguirre’s men start to wonder whether their quest will lead them to prosperity or certain death.',NULL,NULL,2.9628,7.4,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1843,454227,'tt6679794',NULL,'Outlaw King','Outlaw King','movie',2018,'https://image.tmdb.org/t/p/w500/rT49ousKUWN3dV7UlhaC9onTNdl.jpg','https://image.tmdb.org/t/p/original/9uIyOsywwi7bDvHxv3QdiimUtd5.jpg','Forced into exile by the English after being crowned King of Scotland, legendary warrior Robert the Bruce fights to reclaim the throne.',NULL,NULL,3.3188,6.83,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1844,16638,'tt0054847',NULL,'El Cid','El Cid','movie',1961,'https://image.tmdb.org/t/p/w500/a6DY3LDlXFUDuXm47zXTOfiisxP.jpg','https://image.tmdb.org/t/p/original/sKXjExfASGAdRhqVWLScXyie4fY.jpg','Epic film of the legendary Spanish hero, Rodrigo Diaz ("El Cid" to his followers), who, without compromising his strict sense of honour, still succeeds in taking the initiative and driving the Moors from Spain.',NULL,NULL,2.6048,6.851,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1845,8005,'tt0107977',NULL,'Robin Hood: Men in Tights','Robin Hood: Men in Tights','movie',1993,'https://image.tmdb.org/t/p/w500/woexOLEkUlYsPLLuZRK6LjZaF38.jpg','https://image.tmdb.org/t/p/original/xFhpZ9UDUGXu52lCHdN39PIooRt.jpg','Robin Hood comes home after fighting in the Crusades to learn that the noble King Richard is in exile and that the despotic King John now rules England, with the help of the Sheriff of Rottingham. Robin Hood assembles a band of fellow patriots to do battle with King John and the Sheriff.',NULL,NULL,5.0044,6.604,0,1.30266666666666672e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1846,11886,'tt0070608',NULL,'Robin Hood','Robin Hood','movie',1973,'https://image.tmdb.org/t/p/w500/x9AvkYek0bGdxQSZ8W3lAjGrREm.jpg','https://image.tmdb.org/t/p/original/3WeFPoPVIGgMumjgLn0EPIfq53A.jpg','With King Richard off to the Crusades, Prince John and his slithering minion, Sir Hiss, set about taxing Nottingham''s citizens with support from the corrupt sheriff - and staunch opposition by the wily Robin Hood and his band of merry men.',NULL,NULL,5.0654,7.31,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1847,83355,'tt0062787',NULL,'A Challenge for Robin Hood','A Challenge for Robin Hood','movie',1967,'https://image.tmdb.org/t/p/w500/7NbJWuuNROAwYCwzVnm5YEOpbNo.jpg','https://image.tmdb.org/t/p/original/mnk9ljB0mfUccxCpWLwC3lhhV4k.jpg','After being falsely accused of murder, Sir Robin of Loxley takes refuge in the untamed wilderness of Sherwood Forest where he stumbles across a group of outlaws. Although initially suspicious of the aristocrat''s motives, the men are soon won over by his integrity and prowess and Robin transforms them into a formidable fighting force, stealing from the rich and giving to the poor. As word of his fame and valour spreads, a legend is born.',NULL,NULL,0.5154,6.325,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1848,1648,'tt0096928',NULL,'Bill & Ted''s Excellent Adventure','Bill & Ted''s Excellent Adventure','movie',1989,'https://image.tmdb.org/t/p/w500/tV25lGWGWGEqUe3U0xjQTBgilSx.jpg','https://image.tmdb.org/t/p/original/aMASmAmkn7NT0nEq8PBZEgwBfGN.jpg','Bill and Ted are high school buddies starting a band. They are also about to fail their history class—which means Ted would be sent to military school—but receive help from Rufus, a traveller from a future where their band is the foundation for a perfect society. With the use of Rufus'' time machine, Bill and Ted travel to various points in history, returning with important figures to help them complete their final history presentation.',NULL,NULL,2.9633,6.848,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1849,526,'tt0089457',NULL,'Ladyhawke','Ladyhawke','movie',1985,'https://image.tmdb.org/t/p/w500/vJA2Fhw2uBMiVFdBde2kH7kZ2gw.jpg','https://image.tmdb.org/t/p/original/DNb1rBm6R75IJ88PKOd0wfCHm6.jpg','Captain Etienne Navarre is a man on whose shoulders lies a cruel curse. Punished for loving each other, Navarre must become a wolf by night whilst his lover, Lady Isabeau, takes the form of a hawk by day. Together, with the thief Philippe Gaston, they must try to overthrow the corrupt Bishop and in doing so break the spell.',NULL,NULL,5.1309,6.999,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1850,37108,'tt0113538',NULL,'A Kid in King Arthur''s Court','A Kid in King Arthur''s Court','movie',1995,'https://image.tmdb.org/t/p/w500/q7A67rr8f3hESsr4MYb4CEOzF7v.jpg','https://image.tmdb.org/t/p/original/nqDQFwSpzqPNeu7gL0BWnwjWFkL.jpg','A Southern California kid named Calvin Fuller is magically transported to the medieval kingdom of Camelot through a crack in the ground caused by an earthquake. Once there, he learns he was summoned by the wizard Merlin, who needs Calvin to save Camelot. Using dazzling modern inventions, can Calvin help King Arthur retain his crown and thwart the evil Lord Belasco?',NULL,NULL,1.178,4.977,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1851,10705,'tt0097499',NULL,'Henry V','Henry V','movie',1989,'https://image.tmdb.org/t/p/w500/w9R2HsYNnfF3m9uEo2UAmPNJr8a.jpg','https://image.tmdb.org/t/p/original/uAIsWqlLwsL5YN40HYce04wz7Xb.jpg','In 1415, in the midst of the Hundred Years'' War, the young King Henry V of England embarks on the conquest of France.',NULL,NULL,1.5092,7.097,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1852,43323,'tt0049674',NULL,'Richard III','Richard III','movie',1955,'https://image.tmdb.org/t/p/w500/3zp2Kg5bvlFkKmWiQLmuWQAIEgG.jpg','https://image.tmdb.org/t/p/original/yVPt70dRNKG5ki3WCDuinK7sjRF.jpg','Having helped his brother King Edward IV take the throne of England, the jealous hunchback Richard, Duke of Gloucester, plots to seize power for himself. Masterfully deceiving and plotting against nearly everyone in the royal court, including his eventual wife, Lady Anne, and his brother George, Duke of Clarence, Richard orchestrates a bloody rise to power before finding all his gains jeopardized by those he betrayed.',NULL,NULL,1.5338,7.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1853,986,'tt0059012',NULL,'Chimes at Midnight','Campanadas a medianoche','movie',1965,'https://image.tmdb.org/t/p/w500/5Fjxyz3u2Zdco4WeuC3wQ6O5tYQ.jpg','https://image.tmdb.org/t/p/original/83aNchGigrkj6uDiknje6OwY6sl.jpg','Henry IV usurps the English throne, sets in motion the factious War of the Roses and now faces a rebellion led by Northumberland scion Hotspur. Henry''s heir, Prince Hal, is a ne''er-do-well carouser who drinks and causes mischief with his low-class friends, especially his rotund father figure, John Falstaff. To redeem his title, Hal may have to choose between allegiance to his real father and loyalty to his friend.',NULL,NULL,2.0034,7.218,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1854,10235,'tt0029850',NULL,'Alexander Nevsky','Александр Невский','movie',1938,'https://image.tmdb.org/t/p/w500/lsTJYStIsnddwioD1L4FEmwj4Cx.jpg','https://image.tmdb.org/t/p/original/izg3sL4nJwehVsUy1mn1sLOmvuK.jpg','When German knights invade Russia, Prince Alexander Nevsky must rally his people to resist the formidable force. After the Teutonic soldiers take over an eastern Russian city, Alexander stages his stand at Novgorod, where a major battle is fought on the ice of frozen Lake Chudskoe. While Alexander leads his outnumbered troops, two of their number, Vasili and Gavrilo, begin a contest of bravery to win the hand of a local maiden.',NULL,NULL,1.3213,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1855,10907,'tt0029843',NULL,'The Adventures of Robin Hood','The Adventures of Robin Hood','movie',1938,'https://image.tmdb.org/t/p/w500/c7LX3GMf9uXQTgVm3uxpm7E6Woc.jpg','https://image.tmdb.org/t/p/original/yjnfM8QmrXQkWl8dUimsDGl73el.jpg','Robin Hood fights nobly for justice against the evil Sir Guy of Gisbourne while striving to win the hand of the beautiful Maid Marian.',NULL,NULL,3.0138,7.474,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1856,8367,'tt0102798',NULL,'Robin Hood: Prince of Thieves','Robin Hood: Prince of Thieves','movie',1991,'https://image.tmdb.org/t/p/w500/hbRnWUNJkKKVN5mkcuC5ooqjE4e.jpg','https://image.tmdb.org/t/p/original/kuLk79GQq8WQb8fZxc6MtvIhPaC.jpg','Nobleman crusader Robin of Locksley breaks out of a Jerusalem prison with the help of Moorish fellow prisoner Azeem and travels back home to England. But upon arrival he discovers his dead father in the ruins of his family estate, killed by the vicious sheriff of Nottingham, Robin and Azeem join forces with outlaws Little John and Will Scarlett to save the kingdom from the sheriff''s villainy.',NULL,NULL,7.1345,6.857,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1857,15421,'tt0057877',NULL,'Becket','Becket','movie',1964,'https://image.tmdb.org/t/p/w500/swWmxVbq0pXv4wwsc2O803PiXR7.jpg','https://image.tmdb.org/t/p/original/bYwrsPgIloJsqD6nWfLycAp7tn6.jpg','Thomas Becket, Henry II''s longtime advisor, finds his friendship with the debauched king corroding when he is unwillingly appointed as Archbishop of Canterbury in an attempt to gain absolute loyalty from the Church.',NULL,NULL,1.5641,7.169,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1858,18988,'tt0063227',NULL,'The Lion in Winter','The Lion in Winter','movie',1968,'https://image.tmdb.org/t/p/w500/yMgJnZADJObzfjA70ygXJkjnrFX.jpg','https://image.tmdb.org/t/p/original/u8EQqjCeaYDkgACV4mMfkPHLqpP.jpg','Christmas 1183, Angevin Empire: King Henry II plans to announce his successor to the throne. Jockeying for the crown, though, is complex. Henry has three sons and wants his boy Prince John to take over. Henry''s wife, Queen Eleanor, believes their son Prince Richard should be king. As family and various schemers gather for the holiday, each tries to make the indecisive king choose their option.',NULL,NULL,3.1965,7.4,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1859,9476,'tt0183790',NULL,'A Knight''s Tale','A Knight''s Tale','movie',2001,'https://image.tmdb.org/t/p/w500/srb1XnrlDZHcdpjBKqUu4qAzxKU.jpg','https://image.tmdb.org/t/p/original/gkT737kgnmI6jZyXbUBJRwVbGkW.jpg','William Thatcher, a knight''s peasant apprentice, gets a chance at glory when the knight dies suddenly mid-tournament. Posing as a knight himself, William won''t stop until he''s crowned tournament champion—assuming matters of the heart don''t get in the way.',NULL,NULL,6.5161,6.884,0,1.28466666666666675e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1860,895,'tt0060107',NULL,'Andrei Rublev','Андрей Рублёв','movie',1966,'https://image.tmdb.org/t/p/w500/jUihkn16SwPPIjuOyo6orHWUep6.jpg','https://image.tmdb.org/t/p/original/jqha8JCXm0aJ5SJ03Jd0JmGgWRs.jpg','An expansive Russian drama, this film focuses on the life of revered religious icon painter Andrei Rublev. Drifting from place to place in a tumultuous era, the peace-seeking monk eventually gains a reputation for his art. But after Rublev witnesses a brutal battle and unintentionally becomes involved, he takes a vow of silence and spends time away from his work. As he begins to ease his troubled soul, he takes steps towards becoming a painter once again.',NULL,NULL,2.4707,7.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1861,5691,'tt0067647',NULL,'The Canterbury Tales','I racconti di Canterbury','movie',1972,'https://image.tmdb.org/t/p/w500/6mAUGtIc0PjvL1EhDwX6WMkUQpp.jpg','https://image.tmdb.org/t/p/original/uZ1dqaUWlb6zTD8uxriuyLsWkn7.jpg','Glimpses of Chaucer penning his famous work are sprinkled through this re-enactment of several of his stories.',NULL,NULL,1.837,6.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1862,62177,'tt1217209',NULL,'Brave','Brave','movie',2012,'https://image.tmdb.org/t/p/w500/1XAuDtMWpL0sYSFK0R6EZate2Ux.jpg','https://image.tmdb.org/t/p/original/qx9ts2hBYJrkIQxhryitxnLlm2u.jpg','In the mystical Scottish Highlands, Merida is the princess of a kingdom ruled by King Fergus and Queen Elinor. An unruly daughter and an accomplished archer, Merida one day defies a sacred custom of the land and inadvertently brings turmoil to the kingdom. In an attempt to set things right, Merida seeks out an eccentric old Wise Woman and is granted an ill-fated wish. Also figuring into Merida''s quest — and serving as comic relief — are the kingdom''s three lords: the enormous Lord MacGuffin, the surly Lord Macintosh, and the disagreeable Lord Dingwall.',NULL,NULL,15.367,7.031,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1863,762,'tt0071853',NULL,'Monty Python and the Holy Grail','Monty Python and the Holy Grail','movie',1975,'https://image.tmdb.org/t/p/w500/7nTkHjETdGMYK1phHwDbPsrzbYl.jpg','https://image.tmdb.org/t/p/original/1KgXxv6tHXOnakqYvMPvFwYKWiw.jpg','King Arthur, accompanied by his squire, recruits his Knights of the Round Table, including Sir Bedevere the Wise, Sir Lancelot the Brave, Sir Robin the Not-Quite-So-Brave-As-Sir-Lancelot and Sir Galahad the Pure. On the way, Arthur battles the Black Knight who, despite having had all his limbs chopped off, insists he can still fight. They reach Camelot, but Arthur decides not  to enter, as "it is a silly place".',NULL,NULL,6.996,7.806,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1864,587792,'tt9484998',NULL,'Palm Springs','Palm Springs','movie',2020,'https://image.tmdb.org/t/p/w500/gnAfqiV7yO3Jq9IntTmwkcaICqc.jpg','https://image.tmdb.org/t/p/original/d7JUXVvjvVCXWs1mlpyO5ESdWdT.jpg','When carefree Nyles and reluctant maid of honor Sarah have a chance encounter at a Palm Springs wedding, things get complicated when they find themselves unable to escape the venue, themselves, or each other.',NULL,NULL,6.0848,7.3,0,12.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1865,378,'tt0093822',NULL,'Raising Arizona','Raising Arizona','movie',1987,'https://image.tmdb.org/t/p/w500/niKyjOqiB4XVl0BqgKTHIlHOCeF.jpg','https://image.tmdb.org/t/p/original/oSFshBf9Wrv5UcmZYAmy28BwSSh.jpg','When a childless couple—an ex-con and an ex-cop—take one of a wealthy family’s quintuplets to raise as their own, their lives grow more complicated than anticipated.',NULL,NULL,3.5633,7.1,0,12.065,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1866,10341,'tt0101458',NULL,'Until the End of the World','Bis ans Ende der Welt','movie',1991,'https://image.tmdb.org/t/p/w500/sDpYWgYkBlrVnpySXQNsxVvDAAG.jpg','https://image.tmdb.org/t/p/original/wF08MKJWgBIJqmTQXSWwXbQe0OU.jpg','In 1999, a woman''s life is forever changed after she survives a car crash with two bank robbers, who enlist her help to take the money to a drop in Paris. On the way, she runs into another fugitive from the law — an American doctor on the run from the CIA. They want to confiscate his father''s invention – a device which allows anyone to record their dreams and visions.',NULL,NULL,3.246,6.7,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1867,12703,'tt0330099',NULL,'The Brown Bunny','The Brown Bunny','movie',2003,'https://image.tmdb.org/t/p/w500/bGzU4TgdqmMjIfPIgf2MjDW6H7c.jpg','https://image.tmdb.org/t/p/original/lJQBWCJYL44JG9FGv6xzgCJ3cSQ.jpg','Bud Clay races motorcycles in the 250cc Formula II class of road racing. After a race in New Hampshire, he has five days to get to his next race in California. During his road trip, he is haunted by memories of the last time he saw Daisy, his true love.',NULL,NULL,2.307,5.357,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1868,1989,'tt0765120',NULL,'My Blueberry Nights','藍莓之夜','movie',2007,'https://image.tmdb.org/t/p/w500/w9w3m2IB9QRZXxi6R51ZamKv3HS.jpg','https://image.tmdb.org/t/p/original/tj8T9OIM0E51Jf61RJbRbG6vnIJ.jpg','Elizabeth has just been through a particularly nasty breakup, and now she''s ready to leave her friends and memories behind as she chases her dreams across the country. In order to support herself on her journey, Elizabeth picks up a series of waitress jobs along the way. As Elizabeth crosses paths with a series of lost souls whose yearnings are even greater than her own, their emotional turmoil ultimately helps her gain a greater understanding of her own problems...',NULL,NULL,2.3561,6.413,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1869,9382,'tt0112571',NULL,'Boys on the Side','Boys on the Side','movie',1995,'https://image.tmdb.org/t/p/w500/2dhZnfBjiza5TupvOupRU4hFAcJ.jpg','https://image.tmdb.org/t/p/original/gja1HJCm1byNL6AsM8BSv6LveNk.jpg','After breaking up with her girlfriend, a nightclub singer, Jane, answers a personal ad from Robin, a real estate agent with AIDS, seeking a cross-country travel partner. On their journey from New York City to Los Angeles, the two stop by Pittsburgh to pick up Jane''s friend Holly, who is trying to escape an abusive relationship. With three distinct personalities, the women must overcome their differences to help one another.',NULL,NULL,2.3735,6.4,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1870,762361,'tt13515090',NULL,'Joyride','Joyride','movie',2022,'https://image.tmdb.org/t/p/w500/yJHwqLB5U3joO6sqVajDevGsRnz.jpg','https://image.tmdb.org/t/p/original/qQfpXqKR6dewogmh3D6T0hFy3CE.jpg','12-year-old Mully has lost his mother and discovers his debt-ridden father stealing the charity money they''ve raised in her name. Grabbing the cash, Mully steals a taxi and is shocked to find a woman, Joy, in the back seat with a baby. A straight-talking solicitor who didn''t expect to get pregnant, Joy is struggling with motherhood and planning to give her baby to a friend who will raise the child as her own. She joins Mully on a wild journey across Ireland, stealing cars, hitch-hiking, catching ferries and breaking police barricades.',NULL,NULL,1.5391,5.846,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1871,525183,'tt8041276',NULL,'Paddleton','Paddleton','movie',2019,'https://image.tmdb.org/t/p/w500/gtssTSvNgY8132hPRtp1DbciYJ6.jpg','https://image.tmdb.org/t/p/original/maoFnW8j7thGdiplQgT5UGNlbHo.jpg','An unlikely friendship between two neighbors becomes an unexpectedly emotional journey when the younger man is diagnosed with terminal cancer.',NULL,NULL,2.1867,6.961,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1872,11153,'tt0085995',NULL,'National Lampoon''s Vacation','National Lampoon''s Vacation','movie',1983,'https://image.tmdb.org/t/p/w500/q3DvoqY06yZnRp9faH6uge7n7VP.jpg','https://image.tmdb.org/t/p/original/rBL73dGfdEqTr7Xj0HytF9s9SbM.jpg','Clark Griswold is on a quest to take his family to the Walley World theme park for a vacation, but things don''t go exactly as planned.',NULL,NULL,6.8542,7.101,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1873,920,'tt0317219',NULL,'Cars','Cars','movie',2006,'https://image.tmdb.org/t/p/w500/oloVyeBbkVGbFFaUjR8I7Boo7wA.jpg','https://image.tmdb.org/t/p/original/sOLgkBKf1gjMRc4yXxM5aciXdfr.jpg','Lightning McQueen, a hotshot rookie race car driven to succeed, discovers that life is about the journey, not the finish line, when he finds himself unexpectedly detoured in the sleepy Route 66 town of Radiator Springs. On route across the country to the big Piston Cup Championship in California to compete against two seasoned pros, McQueen gets to know the town''s offbeat characters.',NULL,NULL,14.7627,7.0,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1874,2609,'tt0093748',NULL,'Planes, Trains and Automobiles','Planes, Trains and Automobiles','movie',1987,'https://image.tmdb.org/t/p/w500/fwi2cET87xArJCb8MdbWq2BZO3n.jpg','https://image.tmdb.org/t/p/original/4f8JBqvWyPObKTrjvJnp9BeOUyY.jpg','An irritable marketing executive, Neal Page, is heading home to Chicago for Thanksgiving when a number of delays force him to travel with a well meaning but overbearing shower curtain ring salesman, Del Griffith.',NULL,NULL,4.339,7.254,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1875,134,'tt0190590',NULL,'O Brother, Where Art Thou?','O Brother, Where Art Thou?','movie',2000,'https://image.tmdb.org/t/p/w500/s9foMAcLg8GEzzQzer04qOGdD1k.jpg','https://image.tmdb.org/t/p/original/rbsm633lnt3hKHEpk7FOt3dy82a.jpg','In the deep south during the 1930s, three escaped convicts search for hidden treasure while a relentless lawman pursues them.',NULL,NULL,5.9454,7.326,0,1.60233333333333334e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1876,11293,'tt0070510',NULL,'Paper Moon','Paper Moon','movie',1973,'https://image.tmdb.org/t/p/w500/3GHG0kTcBWHKdXjj3RdK8GjBCd6.jpg','https://image.tmdb.org/t/p/original/2Cf8V0iQx0c52IxeLdxOvjI2bBf.jpg','During the Great Depression, a con man finds himself saddled with a young girl who may or may not be his daughter, and the two forge an unlikely partnership.',NULL,NULL,2.636,7.9,0,12.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1877,8467,'tt0109686',NULL,'Dumb and Dumber','Dumb and Dumber','movie',1994,'https://image.tmdb.org/t/p/w500/4LdpBXiCyGKkR8FGHgjKlphrfUc.jpg','https://image.tmdb.org/t/p/original/8uBTDGRcNHhYChcoazP5rleRME7.jpg','Lloyd and Harry are two men whose stupidity is really indescribable. When Mary, a beautiful woman, loses an important suitcase with money before she leaves for Aspen, the two friends (who have found the suitcase) decide to return it to her. After some "adventures" they finally get to Aspen where, using the lost money they live it up and fight for Mary''s heart.',NULL,NULL,8.9913,6.66,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1878,544,'tt0129387',NULL,'There''s Something About Mary','There''s Something About Mary','movie',1998,'https://image.tmdb.org/t/p/w500/slJD1Dvnsf15LoeqhERsyzisAdn.jpg','https://image.tmdb.org/t/p/original/egJQ3nIon5fT8wyXcKRHzvmtZpD.jpg','For Ted, prom night went about as bad as it’s possible for any night to go. Thirteen years later, he finally gets another chance with his old prom date, only to run up against other suitors including the sleazy detective he hired to find her.',NULL,NULL,5.5676,6.632,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1879,20858,'tt0090568',NULL,'8 Million Ways to Die','8 Million Ways to Die','movie',1986,'https://image.tmdb.org/t/p/w500/anxyPdDX3I0vtSwL68qQmpLqp05.jpg','https://image.tmdb.org/t/p/original/cTB1DtDLqEH4FrgICvEaNDeJiPU.jpg','Scudder is a detective with the Sheriff''s Department who is forced to shoot a violent suspect during a narcotics raid. The ensuing psychological aftermath of this shooting worsens his drinking problem and this alcoholism causes him to lose his job, as well as his marriage.',NULL,NULL,2.116,5.473,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1880,10628,'tt0257568',NULL,'Kangaroo Jack','Kangaroo Jack','movie',2003,'https://image.tmdb.org/t/p/w500/nflh9On0de4l7ItCl3n4NVXjmnm.jpg','https://image.tmdb.org/t/p/original/eSvRVTDjGJCbyc9Z51tvwMcs9B3.jpg','Two childhood friends — a New York hairstylist and a wanna-be musician — get mixed-up with the mob and are forced to deliver $50,000 to Australia, but things go all wrong when the money is lost to a wild kangaroo.',NULL,NULL,2.6474,5.3,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1881,152478,NULL,NULL,'Into the Dark','خارج السيطرة','tv',2021,'https://image.tmdb.org/t/p/w500/nANuZ46lqGyCggBNVzalMJP7tFQ.jpg','https://image.tmdb.org/t/p/original/lq1qIQkurWnpkI5NWizuWO13duu.jpg','',NULL,NULL,2.4138,6.2,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1882,17130,'tt0275022',NULL,'Crossroads','Crossroads','movie',2002,'https://image.tmdb.org/t/p/w500/prdFY9Bc28frBhhWl7mPSr7JmFp.jpg','https://image.tmdb.org/t/p/original/igpUTEhu5zEtGt19iPuDgfuxoyL.jpg','After eight years apart, three childhood friends - Lucy, Kit, and Mimi - rediscover their friendship on a cross-country trip. With barely a plan, practically no money but plenty of dreams, the girls catch a lift with Mimi''s handsome friend Ben in his convertible. Along the way they not only gather experiences that will change their lives, but they also discover how important it is to hold onto their hearts'' desires.',NULL,NULL,2.3924,5.207,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1883,411741,'tt5962210',NULL,'Ingrid Goes West','Ingrid Goes West','movie',2017,'https://image.tmdb.org/t/p/w500/3LEyW11onDltXHo0L1X23j9Nnvg.jpg','https://image.tmdb.org/t/p/original/6DNcCxEn4AL7lUoDcmOEenn1BnM.jpg','Ingrid becomes obsessed with a social network star named Taylor Sloane who seemingly has a perfect life. But when Ingrid decides to drop everything and move west to be Taylor''s friend, her behaviour turns unsettling and dangerous.',NULL,NULL,1.8618,6.394,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1884,1934,'tt0138097',NULL,'Shakespeare in Love','Shakespeare in Love','movie',1998,'https://image.tmdb.org/t/p/w500/zdW7jdzPi4J9KZR3TyY2jn3Xh5e.jpg','https://image.tmdb.org/t/p/original/i16MjvM9YsQ85ejdB63gtGXDu4W.jpg','Young William Shakespeare is forced to stage his latest comedy, ''Romeo and Ethel, the Pirate''s Daughter'', before it''s even written. When lovely noblewoman Viola de Lesseps auditions for a role, they fall into forbidden love — and Shakespeare''s play finds a new life (and title). As their relationship intensifies, the comedy soon transforms into tragedy.',NULL,NULL,4.6019,6.8,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1885,124424,'',NULL,'Green Carnation: A Night Under the Dam','Green Carnation: A Night Under the Dam','movie',2007,'https://image.tmdb.org/t/p/w500/xPp991b3tC2E4q7vFhlNCV3Imvt.jpg',NULL,'A Night Under the Dam is Green Carnation''s second live DVD, released under the Sublife Productions label on 1 February 2007. This live recording was made several kilometers into the Norwegian mountains, under a thirty-meter-tall dam built in 1939, hence the name.  The band performed its entire The Acoustic Verses album and other material in front of an audience of more than five hundred. Green Carnation was supported by several guests, including the Kristiansand String Quartet, singer Anne Marie Almedal, former keyboardist Bernt Moen and violinist Leif A. Wiese.  The DVD contains the entire live show, including two bonus songs, a photo gallery containing more than one-hundred-seventy images, a behind-the-scenes video and full 5.1 Surround Sound.',NULL,NULL,0.0979,0.0,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1886,550060,'tt1194675',NULL,'Tristan and Isolde','Tristan und Isolde','movie',1970,NULL,NULL,'Belgian opera film of Wagner''s opera.',NULL,NULL,0.133,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1887,63498,'tt1235830',NULL,'Chico & Rita','Chico & Rita','movie',2010,'https://image.tmdb.org/t/p/w500/Kj9JAhMNSektw6RVYR1oJWGZWa.jpg','https://image.tmdb.org/t/p/original/nHH8swSbK1NehS8yry3qNUg9pUv.jpg','Chico is a young piano player with big dreams. Rita is a beautiful singer with an extraordinary voice. Music and romantic desire unites them, but their journey - in the tradition of the Latin ballad, the bolero - brings heartache and torment.',NULL,NULL,2.0077,7.163,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1888,14670,'tt0090557',NULL,'''Round Midnight','''Round Midnight','movie',1986,'https://image.tmdb.org/t/p/w500/8aNGnEsvLBldNvaBkfYkGGgZDhe.jpg','https://image.tmdb.org/t/p/original/nxxdhhcKreBWItIzN2MQohoIeCY.jpg','Inside the Blue Note nightclub one night in 1959 Paris, an aged, ailing jazzman coaxes an eloquent wail from his tenor sax. Outside, a young Parisian too broke to buy a glass of wine strains to hear those notes. Soon they will form a friendship that sparks a final burst of genius.',NULL,NULL,3.1571,7.1,0,11.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1889,10875,'tt0097322',NULL,'The Fabulous Baker Boys','The Fabulous Baker Boys','movie',1989,'https://image.tmdb.org/t/p/w500/1nS8AxnoYE2Y1ANMpVKZnm8iLxP.jpg','https://image.tmdb.org/t/p/original/iUpEDBcoYzND2MhIWr10C93ikFV.jpg','The lives of two struggling musicians, who happen to be brothers, inevitably change when they team up with a beautiful, up-and-coming singer.',NULL,NULL,2.044,6.612,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1890,524,'tt0112641',NULL,'Casino','Casino','movie',1995,'https://image.tmdb.org/t/p/w500/gziIkUSnYuj9ChCi8qOu2ZunpSC.jpg','https://image.tmdb.org/t/p/original/iZGiMD0p1M2AOmzKknFo5bkuz94.jpg','In Las Vegas, two best friends--a casino executive and a Mafia enforcer--compete for a gambling empire and a fast-living, fast-loving socialite.',NULL,NULL,8.6667,7.996,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1891,769,'tt0099685',NULL,'GoodFellas','GoodFellas','movie',1990,'https://image.tmdb.org/t/p/w500/9OkCLM73MIU2CrKZbqiT8Ln1wY2.jpg','https://image.tmdb.org/t/p/original/gILte6Zd7m1YneIr6MVhh30S9pr.jpg','The true story of Henry Hill, a half-Irish, half-Sicilian Brooklyn kid who is adopted by neighbourhood gangsters at an early age and climbs the ranks of a Mafia family under the guidance of Jimmy Conway.',NULL,NULL,27.5379,8.453,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1892,65817,'tt4998350',NULL,'The Deuce','The Deuce','tv',2017,'https://image.tmdb.org/t/p/w500/tKFUwmue5g45rthZOyYWd7l931y.jpg','https://image.tmdb.org/t/p/original/3QC20eBsoObbG2iMOZvlavTmLMh.jpg','The story of the legalization and subsequent rise of the porn industry in New York’s Times Square from the early ’70s through the mid ’80s, exploring the rough-and-tumble world that existed there until the rise of HIV, the violence of the cocaine epidemic and the renewed real estate market ended the bawdy turbulence of the area.',NULL,NULL,9.4861,7.566,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1893,11382,'tt0109348',NULL,'Bullets Over Broadway','Bullets Over Broadway','movie',1994,'https://image.tmdb.org/t/p/w500/mY9D1oCLeDKNMdUO8EV7MoCZ3up.jpg','https://image.tmdb.org/t/p/original/6zfPDvqeZUleXjNaU5iWQwHUtCN.jpg','After young playwright, David Shayne obtains funding for his play from gangster Nick Valenti, Nick''s girlfriend Olive miraculously lands the role of a psychiatrist—but not only is she a bimbo who could never pass for a psychiatrist—she''s a dreadful actress. David puts up with the leading man who is a compulsive eater, the grand dame who wants her part jazzed up, and Olive''s interfering hitman/bodyguard—but, eventually he must decide whether art or life is more important.',NULL,NULL,2.0581,7.091,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1894,476220,'tt0118858',NULL,'City of Dark','City of Dark','movie',1997,'https://image.tmdb.org/t/p/w500/qtWTI6uykr3zhA10EHfUKK3i8Ei.jpg',NULL,'A computer scientist scans dreams with a computer.',NULL,NULL,1.3344,10.0,0,10.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1895,41823,'tt0100168',NULL,'Mo'' Better Blues','Mo'' Better Blues','movie',1990,'https://image.tmdb.org/t/p/w500/sEa6m5RjfrqfTzY1eHkC85shiUF.jpg','https://image.tmdb.org/t/p/original/5T01b2OxE85HC3nSKeULBDf98cP.jpg','Talented but self-centered trumpeter Bleek Gilliam is obsessed with his music and indecisiveness about his girlfriends Indigo and Clarke. But when he is forced to come to the aid of his manager and childhood friend, Bleek finds his world more fragile than he ever imagined.',NULL,NULL,1.9206,6.485,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1896,615667,'tt10514222',NULL,'Ma Rainey''s Black Bottom','Ma Rainey''s Black Bottom','movie',2020,'https://image.tmdb.org/t/p/w500/pvtyxijaBrCSbByXLcUIDDSvc40.jpg','https://image.tmdb.org/t/p/original/4mK222kB3vyrNjYl8eHliYacvJS.jpg','Tensions rise when the trailblazing Mother of the Blues and her band gather at a Chicago recording studio in 1927. Adapted from August Wilson''s play.',NULL,NULL,2.4909,6.646,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1897,695,'tt0108122',NULL,'Short Cuts','Short Cuts','movie',1993,'https://image.tmdb.org/t/p/w500/mbNTvbtWfV4soyErimDTdX67OAr.jpg','https://image.tmdb.org/t/p/original/a0OjGWE9ru1OlKLBujbz3mAYYxU.jpg','Many loosely connected characters cross paths in this film, based on the stories of Raymond Carver. Waitress Doreen Piggot accidentally runs into a boy with her car. Soon after walking away, the child lapses into a coma. While at the hospital, the boy''s grandfather tells his son, Howard, about his past affairs. Meanwhile, a baker starts harassing the family when they fail to pick up the boy''s birthday cake.',NULL,NULL,2.1655,7.214,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1898,2148,'tt0087089',NULL,'The Cotton Club','The Cotton Club','movie',1984,'https://image.tmdb.org/t/p/w500/jgCsLhIRLKlvUy1p1iImCi0nPnX.jpg','https://image.tmdb.org/t/p/original/8vroa5RYUxD7Nv7vUGUoxZTyz7P.jpg','Harlem''s legendary Cotton Club becomes a hotbed of passion and violence as the lives and loves of entertainers and gangsters collide.',NULL,NULL,1.9704,6.5,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1899,9085,'tt0097481',NULL,'Harlem Nights','Harlem Nights','movie',1989,'https://image.tmdb.org/t/p/w500/mHX0aYjxc2cIOBfYBuaYN9SvbUf.jpg','https://image.tmdb.org/t/p/original/tUPLfffhiJqvb75onmrC0nUkWax.jpg','''Sugar'' Ray is the owner of an illegal casino and must contend with the pressure of vicious gangsters and corrupt police who want to see him go out of business. In the world of organised crime and police corruption in the 1920s, any dastardly trick is fair.',NULL,NULL,2.3999,6.071,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1900,83770,'tt0337692',NULL,'On the Road','On the Road','movie',2012,'https://image.tmdb.org/t/p/w500/k7LQteD02p3VHixbS6NXHkFdFwT.jpg','https://image.tmdb.org/t/p/original/5dUOTVeNPU2CmEfFniQ8TE6HChG.jpg','Sal Paradise is a young writer whose life is shaken and ultimately redefined by the arrival of Dean Moriarty, a free-spirited, fearless, fast talking Westerner and his girl, Marylou. Traveling cross-country, Sal and Dean venture out on a personal quest for freedom from the conformity and conservatism engulfing them in search of the unknown, themselves, and the pursuit of “it” -- the pure essence of experience.',NULL,NULL,2.1202,5.61,0,11.285,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1901,1883,'tt0104797',NULL,'Malcolm X','Malcolm X','movie',1992,'https://image.tmdb.org/t/p/w500/o2s9ow0uRRm1BcF3teznk5twd90.jpg','https://image.tmdb.org/t/p/original/kPdAZIqPgegqbv4QF1FshbVXNrx.jpg','A tribute to the controversial black activist and leader of the struggle for black liberation. He hit bottom during his imprisonment in the ''50s, he became a Black Muslim and then a leader in the Nation of Islam. His assassination in 1965 left a legacy of self-determination and racial pride.',NULL,NULL,4.1086,7.557,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1902,2118,'tt0119488',NULL,'L.A. Confidential','L.A. Confidential','movie',1997,'https://image.tmdb.org/t/p/w500/lWCgf5sD5FpMljjpkRhcC8pXcch.jpg','https://image.tmdb.org/t/p/original/hUn13Hom8OWMYpR1ay0diwswwdP.jpg','Three detectives in the corrupt and brutal L.A. police force of the 1950s use differing methods to uncover a conspiracy behind the shotgun slayings of the patrons at an all-night diner.',NULL,NULL,7.7233,7.804,0,11.545,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1903,1093,'tt0051378',NULL,'Elevator to the Gallows','Ascenseur pour l''échafaud','movie',1958,'https://image.tmdb.org/t/p/w500/jgeZS97po2luaeElfUh07VAbVfV.jpg','https://image.tmdb.org/t/p/original/r8fEOeDjlbtvaxYZ3QDh21gzpKh.jpg','A self-assured businessman murders his employer, husband of his mistress, which unintentionally provokes an ill-fated chain of events.',NULL,NULL,2.6031,7.603,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1904,8512,'tt0112857',NULL,'Devil in a Blue Dress','Devil in a Blue Dress','movie',1995,'https://image.tmdb.org/t/p/w500/5lcJhwKGavLbPva17QkTBhLfqEk.jpg','https://image.tmdb.org/t/p/original/n6SFCz0OsyZ800ZSlaD5WpNmqCj.jpg','In late 1940s Los Angeles, Easy Rawlins is an unemployed black World War II veteran with few job prospects. At a bar, Easy meets DeWitt Albright, a mysterious white man looking for someone to investigate the disappearance of a missing white woman named Daphne Monet, who he suspects is hiding out in one of the city''s black jazz clubs. Strapped for money and facing house payments, Easy takes the job, but soon finds himself in over his head.',NULL,NULL,2.5438,6.462,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1905,42086,'tt0087054',NULL,'Choose Me','Choose Me','movie',1984,'https://image.tmdb.org/t/p/w500/koNvG8XTMvKmkEv15PjBKUMNdEc.jpg','https://image.tmdb.org/t/p/original/tEc74NqUNHExvPSYMIp1kYG2nwc.jpg','Several lost-soul night-owls, including a nightclub owner, a talk radio relationship counselor, and an itinerant stranger have encounters that expose their contradictions and anxieties about love and acceptance.',NULL,NULL,1.0885,6.0,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1906,490132,'tt6966692',NULL,'Green Book','Green Book','movie',2018,'https://image.tmdb.org/t/p/w500/7BsvSuDQuoqhWmU2fL7W2GOcZHU.jpg','https://image.tmdb.org/t/p/original/5En0fmDagt3Pk8d7P3uTwfeQceg.jpg','Tony Lip, a bouncer in 1962, is hired to drive pianist Don Shirley on a tour through the Deep South in the days when African Americans, forced to find alternate accommodations and services due to segregation laws below the Mason-Dixon Line, relied on a guide called The Negro Motorist Green Book.',NULL,NULL,15.387,8.225,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1907,4982,'tt0765429',NULL,'American Gangster','American Gangster','movie',2007,'https://image.tmdb.org/t/p/w500/sX9idXDqRUxE5ffww3n3RV5gL55.jpg','https://image.tmdb.org/t/p/original/dLL90vskYFn1S89RZp5TUguK9wl.jpg','Loosely based on the criminal career of Frank Lucas, a gangster from La Grange, North Carolina, who smuggled heroin into the United States on American service planes returning from the Vietnam War, before being detained by a task force led by Newark Detective Richie Roberts.',NULL,NULL,7.5276,7.594,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1908,12182,'tt0981227',NULL,'Nick and Norah''s Infinite Playlist','Nick and Norah''s Infinite Playlist','movie',2008,'https://image.tmdb.org/t/p/w500/cndxWgZEHnSUtytrMjal97ye34E.jpg','https://image.tmdb.org/t/p/original/q9m40JSqittqMWYQet2TCzVWSPO.jpg','Nick cannot stop obsessing over his ex-girlfriend, Tris, until Tris'' friend Norah suddenly shows interest in him at a club. Thus begins an odd night filled with ups and downs as the two keep running into Tris and her new boyfriend while searching for Norah''s drunken friend, Caroline, with help from Nick''s band mates. As the night winds down, the two have to figure out what they want from each other.',NULL,NULL,1.7558,6.439,0,1.23533333333333317e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1909,533444,'tt8652728',NULL,'Waves','Waves','movie',2019,'https://image.tmdb.org/t/p/w500/3xbjL0z8iH8e8L3USyeKGQrBfuZ.jpg','https://image.tmdb.org/t/p/original/jQ06O9JAFN0VfDS4ezE09pfoj2h.jpg','A controlling father’s attempts to ensure that his two children succeed in high school backfire after his son experiences a career-ending sports injury. Their familial bonds are eventually placed under severe strain by an unexpected tragedy.',NULL,NULL,3.0913,7.4,0,11.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1910,1949,'tt0443706',NULL,'Zodiac','Zodiac','movie',2007,'https://image.tmdb.org/t/p/w500/6YmeO4pB7XTh8P8F960O1uA14JO.jpg','https://image.tmdb.org/t/p/original/3zCPI4JFc54xvLaJ71oI2KoP3az.jpg','Over the course of a decade, editors of the San Francisco Chronicle entice themselves in the murders of the Zodiac Killer. However, as time runs its course, interest in the case dwindles in the eyes of the professionals. The Killer stops interacting with the public. However, believing he has the answers, an amateur cartoonist from the initial sightings races against time to prevent what he believes is another murder.',NULL,NULL,10.8782,7.532,0,11.055,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1911,11068,'tt0105415',NULL,'Singles','Singles','movie',1992,'https://image.tmdb.org/t/p/w500/4T7OKBdkNBorRKWw7VSeuA225z1.jpg','https://image.tmdb.org/t/p/original/n6z8b0qN9Sk3lNElgeJY6qfDU2L.jpg','A group of young adults in their twenties, who share an apartment in the city of Seattle, ponder on love and face all the challenges of adulthood.',NULL,NULL,1.8473,6.416,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1912,1014661,'tt21830836',NULL,'House of Spoils','House of Spoils','movie',2024,'https://image.tmdb.org/t/p/w500/udfMAdiyKhgAS47dRXEnXo6tHt6.jpg','https://image.tmdb.org/t/p/original/aKCxzcNr8bUiJCwrrc0y9rYFfbU.jpg','An ambitious chef opens a restaurant on a remote estate where she battles kitchen chaos, crushing self doubts… and a haunting presence who threatens to sabotage her at every turn.',NULL,NULL,2.8902,5.513,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1913,342657,'tt4708348',NULL,'The Silenced','경성학교: 사라진 소녀들','movie',2015,'https://image.tmdb.org/t/p/w500/hNXiG7fYDwnnpBU2qPlwEI84SLS.jpg','https://image.tmdb.org/t/p/original/zdRTSsfSgg2HjfBks3HRQZe5Wn2.jpg','A sickly girl Ju-ran transfers to a new sanitorium boarding school to regain health. But she discovers that students are disappearing and notices abnormal changes happening to her body. She suspects the school for what''s happening and tries to discover what secret is hidden.',NULL,NULL,0.9692,6.509,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1914,24913,'tt0090655',NULL,'April Fool''s Day','April Fool''s Day','movie',1986,'https://image.tmdb.org/t/p/w500/zNx2tNRzRyPsBSHX1VF2c7U0UyW.jpg','https://image.tmdb.org/t/p/original/lLxz3D3LBhyO3q9F0eBqSjepoD4.jpg','On April Fool''s Day weekend, a group of college friends gather together at a secluded island mansion to celebrate their final year of school, where they soon become prey for an unseen murderer.',NULL,NULL,1.8334,6.073,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1915,27475,'tt0084695',NULL,'The Slumber Party Massacre','The Slumber Party Massacre','movie',1982,'https://image.tmdb.org/t/p/w500/rh65oDy8CNJoEAOf7oudhIt3DM6.jpg','https://image.tmdb.org/t/p/original/3A8hf7Va32HjGAAgatMa0ibPD9E.jpg','Trish invites her high school basketball teammates over for a night they''ll never forget when an unexpected guest crashes the party: an escaped psychopath with a portable power drill.',NULL,NULL,1.0107,5.6,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1916,9426,'tt0091064',NULL,'The Fly','The Fly','movie',1986,'https://image.tmdb.org/t/p/w500/8gZWMhJHRvaXdXsNhERtqNHYpH3.jpg','https://image.tmdb.org/t/p/original/g1FzhbtWYKk9WMJYi1X26kf2Q4Q.jpg','When brilliant, eccentric scientist Seth Brundle makes a huge technological breakthrough in teleportation, he decides to test it on himself. Unbeknownst to him, a common housefly manages to get inside the device and the two become one.',NULL,NULL,8.097,7.4,0,1.31133333333333332e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1917,27815,'tt0099108',NULL,'Basket Case 2','Basket Case 2','movie',1990,'https://image.tmdb.org/t/p/w500/sqw2XSwhsfMcoVRnnXcbOeh9IrH.jpg','https://image.tmdb.org/t/p/original/jywg6eQrXBepgs3Nz30Hlmj0EQa.jpg','Duane and his basket-bound mutant brother are taken in by a secret home for wayward freaks.',NULL,NULL,0.834,5.675,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1918,9423,'tt0120458',NULL,'Virus','Virus','movie',1999,'https://image.tmdb.org/t/p/w500/5Np88iigCfnXvMlMKmCcbPVIbYQ.jpg','https://image.tmdb.org/t/p/original/j3Nvs9rZDjsOU3jwtxUwyEum1pn.jpg','When the crew of an American tugboat boards an abandoned Russian research vessel, the alien life form aboard regards them as a virus which must be destroyed.',NULL,NULL,2.0874,5.409,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1919,27296,'tt0364376',NULL,'The Gingerdead Man','The Gingerdead Man','movie',2005,'https://image.tmdb.org/t/p/w500/tZgIllFk4ncvhuzNipLkStjPjqk.jpg','https://image.tmdb.org/t/p/original/wJO9uBYIPQ8lIeb0qeRu3LgSEVb.jpg','An evil yet adorable Gingerbread man comes to life with the soul of a convicted killer, and this real life cookie monster wreaks havoc on the girl who sent the killer to the electric chair.',NULL,NULL,1.0732,3.9,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1920,579828,'tt11815960',NULL,'Superdeep','Кольская сверхглубокая','movie',2020,'https://image.tmdb.org/t/p/w500/1HhlR1XbG1cw7dfAq3rme6Qs1lh.jpg','https://image.tmdb.org/t/p/original/4ehqtwnjbYby9Brk6B1ECtmSiWu.jpg','In 1984, a Russian research team goes below the surface to find out what secret the world''s deepest borehole is hiding. On their expedition, something unexpectedly gruesome awaits the researchers.',NULL,NULL,2.8566,5.9,0,8.29,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1921,950396,'tt13654226',NULL,'The Gorge','The Gorge','movie',2025,'https://image.tmdb.org/t/p/w500/7iMBZzVZtG0oBug4TfqDb9ZxAOa.jpg','https://image.tmdb.org/t/p/original/9nhjGaFLKtddDPtPaX5EmKqsWdH.jpg','Two highly trained operatives grow close from a distance after being sent to guard opposite sides of a mysterious gorge. When an evil below emerges, they must work together to survive what lies within.',NULL,NULL,22.5095,7.669,0,6.29,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1922,14510,'tt0091083',NULL,'From Beyond','From Beyond','movie',1986,'https://image.tmdb.org/t/p/w500/zwmyxaKzIRLD4iUqZAQW940omdm.jpg','https://image.tmdb.org/t/p/original/sKcdPHvsGCNdDOD7LJdOibZuvUQ.jpg','The Resonator, a powerful machine that can control the sixth sense, has killed its creator and sent his associate into an insane asylum. When a psychiatrist becomes determined to continue the experiment, she unwittingly opens the door to a hostile parallel universe.',NULL,NULL,3.0428,6.498,0,1.1129999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1923,14372,'tt0097737',NULL,'Leviathan','Leviathan','movie',1989,'https://image.tmdb.org/t/p/w500/extm7kFsxr0qMoi1G5F3w5Lwlt4.jpg','https://image.tmdb.org/t/p/original/2cBHM1ndSVIVmZ4uuR3pA9enWdc.jpg','Underwater deep-sea miners encounter a Soviet wreck and bring back a dangerous cargo to their base on the ocean floor with horrifying results. The crew of the mining base must fight to survive against a genetic mutation that hunts them down one by one.',NULL,NULL,2.9727,5.991,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1924,464111,'tt7078780',NULL,'Zygote','Zygote','movie',2017,'https://image.tmdb.org/t/p/w500/lowSe0hdmFdtEuIA6aOVfkPjk1c.jpg','https://image.tmdb.org/t/p/original/4umJhUsj8ppev0TA0J0CVJaXeO1.jpg','The two remaining crew members of a mining operation in the Arctic Circle fight to survive against an alien creature.',NULL,NULL,3.7873,6.997,0,11.075,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1925,463800,'tt7078926',NULL,'Firebase','Firebase','movie',2017,'https://image.tmdb.org/t/p/w500/e6qVOjp3QKHrA7k2sAbJSlDXkRM.jpg','https://image.tmdb.org/t/p/original/pF8WdJq2lzaYpcEgrjNwR9mp0l6.jpg','Set during the Vietnam war, Firebase follows American soldier Hines through an ever-deepening web of science fiction madness.',NULL,NULL,0.5485,6.738,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1926,8814,'tt0419706',NULL,'Doom','Doom','movie',2005,'https://image.tmdb.org/t/p/w500/y50lH061yWOvEstoZRn7lYs0huk.jpg','https://image.tmdb.org/t/p/original/9EpgaLS44zlXoTSAOhGiJmkIA4B.jpg','A team of space marines known as the Rapid Response Tactical Squad, led by Sarge, is sent to a science facility on Mars after somebody reports a security breach. There, they learn that the alert came after a test subject, a mass murderer purposefully injected with alien DNA, broke free and began killing people. Dr. Grimm, who is related to team member Reaper, informs them all that the chromosome can mutate humans into monsters -- and is highly infectious.',NULL,NULL,4.1964,5.197,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1927,279972,'tt1991031',NULL,'Digging Up the Marrow','Digging Up the Marrow','movie',2015,'https://image.tmdb.org/t/p/w500/xCE04zhX6TSQF1VvViyVTBVqvkr.jpg','https://image.tmdb.org/t/p/original/3Xcdlmo5GjSSzVVHuyJdtpPSENC.jpg','A documentary filmmaker turns his lens on an enigmatic conspiracy theorist who claims he''s found the entrance to a vast underground city populated entirely by monsters.',NULL,NULL,0.9486,5.453,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1928,153738,'tt1925435',NULL,'Frankenstein''s Army','Frankenstein''s Army','movie',2013,'https://image.tmdb.org/t/p/w500/tBDuUfnAyN2OTHhyy4xyUrU8C2A.jpg','https://image.tmdb.org/t/p/original/4N2Kg5G3xOkzbwKr2af8ATmK7Jb.jpg','Toward the end of World War II, Russian soldiers pushing into eastern Germany stumble across a secret Nazi lab, one that has unearthed and begun experimenting with the journal of one Dr. Victor Frankenstein. The scientists have used the legendary Frankenstein''s work to assemble an army of super-soldiers stitched together from the body parts of their fallen comrades -- a desperate Hitler''s last ghastly ploy to escape defeat',NULL,NULL,1.608,6.1,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1929,15742,'tt0410730',NULL,'Taxidermia','Taxidermia','movie',2006,'https://image.tmdb.org/t/p/w500/uRqxKim0Vr1JZPLYcR1rjFtu74p.jpg','https://image.tmdb.org/t/p/original/sZuuEKmEdd9Emn6QIW4WiHrRjSk.jpg','Set over three generations and beginning with a sexually frustrated orderly during WWII who relieves his tensions in the most outlandish, gross ways. The result of his liaison is a glutton who grows up to be a champion speed eater. He produces a child who becomes obsessed with taxidermy.',NULL,NULL,3.3769,6.6,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1930,22455,'tt0106450',NULL,'Body Melt','Body Melt','movie',1994,'https://image.tmdb.org/t/p/w500/3DhwXNsZ5X66aQi9VnJMPn1Xcsl.jpg','https://image.tmdb.org/t/p/original/jbunzjlC12ZNf84xD6v5HF3LlOo.jpg','Residents of peaceful Pebbles Court, Homesville, are being used unknowingly as test experiments for a new ''Body Drug'' that causes rapid body decomposition (melting skin etc.) and painful death.',NULL,NULL,0.9088,5.082,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1931,2742,'tt0102511',NULL,'Naked Lunch','Naked Lunch','movie',1991,'https://image.tmdb.org/t/p/w500/u01kh5jKUWjhom76mguRqUgdvja.jpg','https://image.tmdb.org/t/p/original/mBteXONDhdVyXRNxj54eMNGNqyT.jpg','Blank-faced bug killer Bill Lee and his dead-eyed wife, Joan, like to get high on Bill''s pest poisons while lounging with Beat poet pals. After meeting the devilish Dr. Benway, Bill gets a drug made from a centipede. Upon indulging, he accidentally kills Joan, takes orders from his typewriter-turned-cockroach, ends up in a constantly mutating Mediterranean city and learns that his hip friends have published his work -- which he doesn''t remember writing.',NULL,NULL,2.8692,7.0,0,13.8225,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1932,15239,'tt0090190',NULL,'The Toxic Avenger','The Toxic Avenger','movie',1984,'https://image.tmdb.org/t/p/w500/so0CGT1fZe2SlVdYXCewghxUgoj.jpg','https://image.tmdb.org/t/p/original/tYXYvgoMVlaaAPPEJsVuh5mHLbQ.jpg','A gang of thugs devise a cruel hoax that goes horribly wrong as Melvin, a nerdy emaciated janitor at the local health club, is cast through a third story window into a vat of hazardous toxic waste.',NULL,NULL,2.4533,6.2,0,14.0175,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1933,9276,'tt0133751',NULL,'The Faculty','The Faculty','movie',1998,'https://image.tmdb.org/t/p/w500/5XetJwmAiDC0EtH23NIXaqFn3Wl.jpg','https://image.tmdb.org/t/p/original/oJRlYxfG10h4sxk2A7fpeOZnaFi.jpg','When creepy things start happening at Herrington High, the students begin to suspect that their faculty is being controlled by body-snatching aliens.',NULL,NULL,4.6357,6.571,0,11.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1934,9827,'tt0119891',NULL,'Phantoms','Phantoms','movie',1998,'https://image.tmdb.org/t/p/w500/FM8MOTW8BbyoTLa2V8PnI6UPib.jpg','https://image.tmdb.org/t/p/original/sfZsUTH7MYxX2FsHOcWcx0YgkYa.jpg','In the peaceful Colorado town of Snowfield, something evil has wiped out the community. And now, it''s up to a group of people to stop it, or at least get out of Snowfield alive.',NULL,NULL,1.6847,5.557,0,11.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1935,87710,'tt0095719',NULL,'The Nest','The Nest','movie',1988,'https://image.tmdb.org/t/p/w500/izMgoQ0nly1X5hOmrfvj27Ke8uf.jpg','https://image.tmdb.org/t/p/original/uKVz2h6oRz7ws0M1f3RUIWpZvyZ.jpg','Horrifying shocker as a biological experiment goes haywire when meat-eating mutant roaches invade an island community, terrorizing a peaceful New England fishing village and hideously butchering its citizens.',NULL,NULL,0.7855,5.25,0,10.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1936,438799,'tt4530422',NULL,'Overlord','Overlord','movie',2018,'https://image.tmdb.org/t/p/w500/l76Rgp32z2UxjULApxGXAPpYdAP.jpg','https://image.tmdb.org/t/p/original/10wHo9VmDvBW9wtSZ26bgjm9GKY.jpg','On the eve of D-Day, a team of American paratroopers crash behind enemy lines and come face-to-face with a Nazi threat unlike any the world has ever seen.',NULL,NULL,3.4175,6.736,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1937,283366,'tt1935859',NULL,'Miss Peregrine''s Home for Peculiar Children','Miss Peregrine''s Home for Peculiar Children','movie',2016,'https://image.tmdb.org/t/p/w500/CIlbMFOfYDj0MP23hsIYhFGrL6.jpg','https://image.tmdb.org/t/p/original/ld7V9BjMk2xtiBNcR8savyyk5ca.jpg','A teenager finds himself transported to an island where he must help protect a group of orphans with special powers from creatures intent on destroying them.',NULL,NULL,7.3568,6.84,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1938,1992,'tt1077258',NULL,'Planet Terror','Planet Terror','movie',2007,'https://image.tmdb.org/t/p/w500/3705GxG0RN9XDV5y9IiXKYHw1fK.jpg','https://image.tmdb.org/t/p/original/iZBUOcku0xv9MMfiEMXiDqErPXl.jpg','Two doctors find their graveyard shift inundated with townspeople ravaged by sores. Among the wounded is Cherry Darling, a dancer whose leg was ripped from her body. As the invalids quickly become enraged aggressors, Cherry and her ex-boyfriend El Wray lead a team of accidental warriors into the night.',NULL,NULL,4.7719,6.692,0,11.595,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1939,1140619,'tt29383405',NULL,'Handmade - A Tale of Stop-motion','Handmade - A Tale of Stop-motion','movie',2023,'https://image.tmdb.org/t/p/w500/aLRfzBNNF5pMRSKKlgnyiIRNiIW.jpg','https://image.tmdb.org/t/p/original/5iz7hpm502eC8v5X36UrCGp9DKh.jpg','A documentary about an old animation technique and the film studio that tries to carry on the legacy. The worlds oldest animation studio still making film with stop motion technique is Nukufilm located in Tallinn, Estland. Here we can follow the work in the studio which was founded in the Soviet era and has survived heavy censorship and global competition.',NULL,NULL,0.2186,10.0,0,12.36,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1940,607,'tt0119654',NULL,'Men in Black','Men in Black','movie',1997,'https://image.tmdb.org/t/p/w500/uLOmOF5IzWoyrgIF5MfUnh5pa1X.jpg','https://image.tmdb.org/t/p/original/o9puyKpayQoX8ikIaYtf2PfKv3.jpg','After a police chase with an otherworldly being, a New York City cop is recruited as an agent in a top-secret organization established to monitor and police alien activity on Earth: the Men in Black. Agent K and new recruit Agent J find themselves in the middle of a deadly plot by an intergalactic terrorist who has arrived on Earth to assassinate two ambassadors from opposing galaxies.',NULL,NULL,10.478,7.225,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1941,8078,'tt0118583',NULL,'Alien Resurrection','Alien Resurrection','movie',1997,'https://image.tmdb.org/t/p/w500/9aRDMlU5Zwpysilm0WCWzU2PCFv.jpg','https://image.tmdb.org/t/p/original/zQI8yxl61JTpjCB3MrTbcQBOT82.jpg','Two hundred years after Lt. Ripley died, a group of scientists clone her, hoping to breed the ultimate weapon. But the new Ripley is full of surprises … as are the new aliens. Ripley must team with a band of smugglers to keep the creatures from reaching Earth.',NULL,NULL,7.6337,6.17,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1942,1487,'tt0167190',NULL,'Hellboy','Hellboy','movie',2004,'https://image.tmdb.org/t/p/w500/lbaTEneOofwvAyg77R8HbFML2zT.jpg','https://image.tmdb.org/t/p/original/avwEj8wiywFH6FZ6h2wzvyJpiH7.jpg','In the final days of World War II, the Nazis attempt to use black magic to aid their dying cause. The Allies raid the camp where the ceremony is taking place, but not before they summon a baby demon who is rescued by Allied forces and dubbed "Hellboy". Sixty years later, Hellboy serves the cause of good rather than evil as an agent in the Bureau of Paranormal Research & Defense, along with Abe Sapien - a merman with psychic powers, and Liz Sherman - a woman with pyrokinesis, protecting America against dark forces.',NULL,NULL,5.9517,6.677,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1943,NULL,NULL,37,'Dead Space','Dead Space','game',2008,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2g7w.jpg',NULL,'Dead Space is a 2008 science fiction survival horror video game developed by EA Redwood Shores (now Visceral Games) for Microsoft Windows, PlayStation 3 and Xbox 360. The game was released on all platforms through October 2008. The game puts the player in control of an engineer named Isaac Clarke, who battles the Necromorphs, reanimated human corpses, aboard an interstellar mining ship, the USG Ishimura.','https://www.igdb.com/games/dead-space','["PlayStation 3", "PC (Microsoft Windows)", "Xbox 360"]',NULL,NULL,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1944,NULL,NULL,538,'BioShock Infinite','BioShock Infinite','game',2013,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2n12.jpg',NULL,'BioShock Infinite is the third game in the BioShock series. It is not a direct sequel/prequel to any of the previous BioShock games but takes place in an entirely different setting, although it shares similar features, gameplay and concepts with the previous games. BioShock Infinite features a range of environments that force the player to adapt, with different weapons and strategies for each situation. Interior spaces feature close combat with enemies, but unlike previous games set in Rapture, the setting of Infinite contains open spaces with emphasis on sniping and ranged combat against as many as fifteen enemies at once.','https://www.igdb.com/games/bioshock-infinite','["PlayStation 3", "Linux", "PC (Microsoft Windows)", "Mac", "Xbox 360"]',NULL,NULL,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1945,13220,'tt1031280',NULL,'Splinter','Splinter','movie',2008,'https://image.tmdb.org/t/p/w500/tFNReQlU92jmN7uuR1HHLiFkEua.jpg','https://image.tmdb.org/t/p/original/qJJHILLr0IIlDkpQ7OJnyPXfERJ.jpg','When their plans for a nature trip go awry, Polly and boyfriend Seth decide to check into a motel. On their way, they''re carjacked and kidnapped by low-rent crooks Dennis and Lacey, who take the victims and their SUV to a nearby gas station. Along the way, they encounter an increasingly terrifying horde of parasites, and if any of them intend to survive, they''ll have to outsmart the deadly organisms.',NULL,NULL,3.1499,6.175,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1946,1253000,'tt33996087',NULL,'Deathstalker','Deathstalker','movie',2025,'https://image.tmdb.org/t/p/w500/nEI3DnzQC1afAjJOAizx6UX27pL.jpg','https://image.tmdb.org/t/p/original/7aiQebqYUHbs2wZPhsTznuMWyeH.jpg','A powerful swordsman known as Deathstalker recovers a cursed amulet from a corpse-strewn battlefield. Marked by dark magic and hunted by monstrous assassins, he must face the rising evil and break the curse.',NULL,NULL,6.4907,5.968,0,5.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1947,40095,'tt0094961',NULL,'Dead Heat','Dead Heat','movie',1988,'https://image.tmdb.org/t/p/w500/7jBtDMQrXpHlyuJImTAs6Oexv7H.jpg','https://image.tmdb.org/t/p/original/4YXapzUiQHsgkR1aVdt2IJ9fVIC.jpg','Detective Roger Mortis is killed in action while investigating a string of mysterious robberies: until he''s brought back from the dead with a chemical company''s secret re-animation technology. Now he has twelve hours to solve the case of his own death before he dies: And stays dead.',NULL,NULL,1.8856,6.195,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1948,22172,'tt0094057',NULL,'Street Trash','Street Trash','movie',1987,'https://image.tmdb.org/t/p/w500/vwy81HbDoSvccWvculRMUVY39dD.jpg','https://image.tmdb.org/t/p/original/owbWSs528xtvL2CTSi3ofMf0rfc.jpg','A group of hobos begin melting into multicolored piles of goo after drinking sixty-year-old liquor. At the same time, the psychotic Vietnam War vet who rules the hobo camp snaps and begins killing at random. Two brothers set out to stop the liquor and the killer.',NULL,NULL,1.4377,6.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1949,116,'tt0416320',NULL,'Match Point','Match Point','movie',2005,'https://image.tmdb.org/t/p/w500/vHjEVTD8ucuwKSFOZJeyAnTZYli.jpg','https://image.tmdb.org/t/p/original/yUJf20GQ5vifhk9QDxUGotAEaLz.jpg','Chris, a former tennis pro, takes a job as an instructor and befriends his wealthy young student, Tom. After being introduced to his family, Chris is soon engaged to Tom''s sister, Chloe. Despite the professional and financial advantages that this relationship affords him, Chris becomes obsessed with Tom''s fiancee, American actress Nola.',NULL,NULL,4.7714,7.364,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1950,747514,NULL,NULL,'Basketcase','Basketcase','movie',1970,'https://image.tmdb.org/t/p/w500/tRLoK4KAazLwTcGHUvygdfrdvdS.jpg',NULL,'An eccentric old man starts preparing for his funeral after he has a vision that he will die in 7 days. When his granddaughter is forced to look after him, they form an unexpected bond during their journey to complete his bucket list.',NULL,NULL,0.0984,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1951,23730,'tt0087015',NULL,'C.H.U.D.','C.H.U.D.','movie',1984,'https://image.tmdb.org/t/p/w500/8BVw5RIDBTZwdMAR1VKpAkwrMjj.jpg','https://image.tmdb.org/t/p/original/zY9ahWKd9wVgQ6Rj5iL2zo0UvOt.jpg','A rash of bizarre murders in New York City seems to point to a group of grotesquely deformed vagrants living in the sewers. A courageous policeman, a photojournalist and his girlfriend, and a nutty bum, who seems to know a lot about the creatures, band together to try and determine what the creatures are and how to stop them.',NULL,NULL,1.5392,5.636,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1952,13190,'tt1267379',NULL,'Dead Space: Downfall','Dead Space: Downfall','movie',2008,'https://image.tmdb.org/t/p/w500/w8KNXRQF9UzplokFlDrNMt0FkW7.jpg','https://image.tmdb.org/t/p/original/aFnF8gvNedNWHoCNTjZWphebecd.jpg','On a deep space mining mission to a remote planet, an ancient religious relic - thought to be proof of the existence of God - is unearthed and brought aboard. When the unholy artifact unleashes a long-dormant alien race, its glimpse of Heaven transforms the ship into a living Hell. A prequel to the events of the 2008 video game Dead Space.',NULL,NULL,3.144,6.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1953,83659,'tt8415836',NULL,'Guillermo del Toro''s Cabinet of Curiosities','Guillermo del Toro''s Cabinet of Curiosities','tv',2022,'https://image.tmdb.org/t/p/w500/a91e9hpWwfCqxJI4xM9Q2RhuxgI.jpg','https://image.tmdb.org/t/p/original/gM1diqqPFu5oRpEVsx84SPBYvV3.jpg','Bizarre nightmares unfold in eight tales of terror in this visually stunning, spine-tingling horror collection curated by Guillermo del Toro.',NULL,NULL,7.5107,7.456,0,9.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1954,237958,'tt1433911',NULL,'Pepperminta','Pepperminta','movie',2009,'https://image.tmdb.org/t/p/w500/xNczswik8LBsnToQf5FsFM1aSq1.jpg','https://image.tmdb.org/t/p/original/wA0wnNfUSkywgUOcoRMFvZ4V6SD.jpg','Pepperminta is an anarchist of the imagination. She lives in a futuristic rainbow villa and according to her own rules. Colors are the young woman''s best friends and strawberries are her pets. She knows the most amazing remedies to free people of their fears. Pepperminta''s wish is for everyone to see the world in her favorite colors. Werwen, a young plump and shy man yet whose sex appeal Pepperminta finds highly attractive, and the beautiful Edna, who talks to tulips, join her on her passionate mission. These three musketeers of a different kind set out to fight for a more humane world. Wherever the gang appears, everything is turned upside down and people''s lives are transformed in the most miraculous and wondrous of ways.',NULL,NULL,1.0706,5.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1955,76600,'tt1630029',NULL,'Avatar: The Way of Water','Avatar: The Way of Water','movie',2022,'https://image.tmdb.org/t/p/w500/t6HIqrRAclMCA60NsSmeqe9RmNV.jpg','https://image.tmdb.org/t/p/original/kJsPVzdyBrYHLomuNv5SJDXUQ2f.jpg','Set more than a decade after the events of the first film, learn the story of the Sully family (Jake, Neytiri, and their kids), the trouble that follows them, the lengths they go to keep each other safe, the battles they fight to stay alive, and the tragedies they endure.',NULL,NULL,38.3364,7.594,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1956,1272166,'tt32063098',NULL,'Ballad of a Small Player','Ballad of a Small Player','movie',2025,'https://image.tmdb.org/t/p/w500/yiXpXNiBWENaSJmdKfoT5DU0bL4.jpg','https://image.tmdb.org/t/p/original/cc48kfehVAkgG73BsPcFLMoxa8h.jpg','Amid the glittering casinos of Macau, a gambler running from his past—and his debts—becomes fascinated by an enigmatic woman at the baccarat table.',NULL,NULL,2.771,5.812,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1957,10328,'tt0088933',NULL,'Cocoon','Cocoon','movie',1985,'https://image.tmdb.org/t/p/w500/wqNNm36j3nkucAucHEGAW5pNZcd.jpg','https://image.tmdb.org/t/p/original/SOROsJCXjEkeJ9zohXi7lEC58R.jpg','When a group of trespassing seniors swim in a pool containing alien cocoons, they find themselves energized with youthful vigor.',NULL,NULL,3.801,6.63,0,12.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1958,210250,'tt1235535',NULL,'Louis Theroux: Gambling in Las Vegas','Louis Theroux: Gambling in Las Vegas','movie',2007,'https://image.tmdb.org/t/p/w500/iXAEQBRhgs78TJDTeRKTZSyudPw.jpg','https://image.tmdb.org/t/p/original/y1wd7YlAmYVnS45x2kK9ryydixM.jpg','Louis heads to Las Vegas, to reveal the world behind the myths of casino culture. Among the people he meets are two of the casino''s ''high-rollers'' and an employee who looks after them as well as a retired doctor who says she has gambled away $4million in seven years.',NULL,NULL,0.6297,6.886,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1959,124101,'tt11815682',NULL,'Hacks','Hacks','tv',2021,'https://image.tmdb.org/t/p/w500/ca5XiEFgyGsI38QT3wEKa1QVGX.jpg','https://image.tmdb.org/t/p/original/bbAR4qKxjnjyKAt4YMrL725Mtfw.jpg','Explore a dark mentorship that forms between Deborah Vance, a legendary Las Vegas comedian, and an entitled, outcast 25-year-old.',NULL,NULL,43.0419,7.47,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1960,86845,'tt0115711',NULL,'Bloodfist VIII: Trained to Kill','Bloodfist VIII: Trained to Kill','movie',1996,'https://image.tmdb.org/t/p/w500/iYKuLErSJDy1ubrFhJmjniEpTw6.jpg','https://image.tmdb.org/t/p/original/oatUEtKCsQUSlnWMJHCsaa85wy8.jpg','A former CIA agent lives a suburban life as a high school teacher with his teen son. When the agent is attacked by former allies because of knowledge he possesses and his son is kidnapped, he is forced back into the business and his son suddenly sees a side of his father that he never knew existed.',NULL,NULL,0.6899,4.9,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1961,601666,'tt9893250',NULL,'I Care a Lot','I Care a Lot','movie',2021,'https://image.tmdb.org/t/p/w500/gKnhEsjNefpKnUdAkn7INzIFLSu.jpg','https://image.tmdb.org/t/p/original/pA4J371Gk2F47vyGQOWapcsnOzz.jpg','A court-appointed legal guardian defrauds her older clients and traps them under her care. But her latest mark comes with some unexpected baggage.',NULL,NULL,3.4476,6.574,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1962,11543,'tt0116778',NULL,'Kingpin','Kingpin','movie',1996,'https://image.tmdb.org/t/p/w500/lVpejjxzBujSjLpxQ7hGe1s0wP2.jpg','https://image.tmdb.org/t/p/original/t8HtbS9tWWUbqI5J7hIYCspgkGI.jpg','After bowler Roy Munson swindles the wrong crowd and is left with a hook for a hand, he settles into impoverished obscurity. That is, until he uncovers the next big thing: an Amish kid named Ishmael. So, the corrupt and the hopelessly naive hit the circuit intent on settling an old score with Big Ern.',NULL,NULL,2.4666,6.541,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1963,11314,'tt0085809',NULL,'Koyaanisqatsi','Koyaanisqatsi','movie',1983,'https://image.tmdb.org/t/p/w500/6zCNciRcob8lwuydVXgq0esla8L.jpg','https://image.tmdb.org/t/p/original/84E96lyR81OvUjCimcrfuzn9er5.jpg','Takes us to locations all around the US and shows us the heavy toll that modern technology is having on humans and the earth. The visual tone poem contains neither dialogue nor a vocalized narration: its tone is set by the juxtaposition of images and the exceptional music by Philip Glass.',NULL,NULL,1.7161,7.885,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1964,24923,'tt0071396',NULL,'Messiah of Evil','Messiah of Evil','movie',1975,'https://image.tmdb.org/t/p/w500/5oRbZ2vBCuOiboc0WJ928KOwKAD.jpg','https://image.tmdb.org/t/p/original/ljYxHqrXTubIHPKyqmnMuFFQqgX.jpg','A young woman searching for her missing artist father finds herself in the strange seaside town of Point Dune, which seems to be under the influence of a mysterious undead cult.',NULL,NULL,1.215,6.244,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1965,10331,'tt0063350',NULL,'Night of the Living Dead','Night of the Living Dead','movie',1968,'https://image.tmdb.org/t/p/w500/rb2NWyb008u1EcKCOyXs2Nmj0ra.jpg','https://image.tmdb.org/t/p/original/5KtmBSqFtHY3I9t8lgH27Mc0bqY.jpg','A ragtag group barricade themselves in an old Pennsylvania farmhouse to remain safe from a horde of flesh-eating ghouls ravaging the Northeast.',NULL,NULL,5.2627,7.609,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1966,161,'tt0240772',NULL,'Ocean''s Eleven','Ocean''s Eleven','movie',2001,'https://image.tmdb.org/t/p/w500/hQQCdZrsHtZyR6NbKH2YyCqd2fR.jpg','https://image.tmdb.org/t/p/original/ncoqdHs1poUaBqyKic9YI8ai7MP.jpg','Less than 24 hours into his parole, charismatic thief Danny Ocean is already rolling out his next plan: In one night, Danny''s hand-picked crew of specialists will attempt to steal more than $150 million from three Las Vegas casinos. But to score the cash, Danny risks his chances of reconciling with ex-wife, Tess.',NULL,NULL,13.2107,7.462,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1967,27023,'tt1276105',NULL,'Saint John of Las Vegas','Saint John of Las Vegas','movie',2010,'https://image.tmdb.org/t/p/w500/fFW0KMESYWfI74UAZ5gc3Ct8MBI.jpg','https://image.tmdb.org/t/p/original/x78O0A1rrLswKWU2ulRw070aft3.jpg','An ex-gambler is lured back into the game by a veteran insurance-fraud investigator.',NULL,NULL,0.614,5.7,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1968,638741,'tt11358166',NULL,'Some Kind of Heaven','Some Kind of Heaven','movie',2021,'https://image.tmdb.org/t/p/w500/4L0OAHeo2B413QKK5HRiWMzdKUy.jpg','https://image.tmdb.org/t/p/original/xztGD5dAyXLxw1VUJEbwSjnvTBh.jpg','Behind the gates of a palm-tree-lined fantasyland, three residents and one interloper at America’s largest retirement community strive to find happiness.',NULL,NULL,0.9268,6.973,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1969,318846,'tt1596363',NULL,'The Big Short','The Big Short','movie',2015,'https://image.tmdb.org/t/p/w500/scVEaJEwP8zUix8vgmMoJJ9Nq0w.jpg','https://image.tmdb.org/t/p/original/u6UyFHkkpUGzZec88PYaaamya5E.jpg','The men who made millions from a global economic meltdown.',NULL,NULL,9.2646,7.368,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1970,284536,'tt2039393',NULL,'The Gambler','The Gambler','movie',2014,'https://image.tmdb.org/t/p/w500/hIgU3cxn7Y87joQGM3srofnXOm5.jpg','https://image.tmdb.org/t/p/original/ni6AHnsPMdH8jaK2wT3MRXA7JCi.jpg','Literature professor Jim Bennett leads a secret life as a high-stakes gambler. Always a risk-taker, Bennett bets it all when he borrows from a gangster and offers his own life as collateral. Staying one step ahead, he pits his creditor against the operator of an illicit gambling ring while garnering the attention of Frank, a paternalistic loan shark. As his relationship with a student deepens, Bennett must risk everything for a second chance.',NULL,NULL,3.8347,6.032,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1971,12104,'tt0084503',NULL,'Pink Floyd: The Wall','Pink Floyd: The Wall','movie',1982,'https://image.tmdb.org/t/p/w500/aElHyIdF5jmctFGhlhhaPFsbBJC.jpg','https://image.tmdb.org/t/p/original/Ag4eANWzHEwC7rQVyvcGsL34ieP.jpg','A troubled rock star descends into madness in the midst of his physical and social isolation from everyone.',NULL,NULL,5.2997,7.9,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1972,11419,'tt0120434',NULL,'Vegas Vacation','Vegas Vacation','movie',1997,'https://image.tmdb.org/t/p/w500/jUOreo2AWDnPuRJsUp6T1i66tUe.jpg','https://image.tmdb.org/t/p/original/9HcZsZQZcgxr99iYYOoYMcfjmHB.jpg','The Griswold family hits the road again for a typically ill-fated vacation, this time to the glitzy mecca of slots and showgirls—Las Vegas.',NULL,NULL,2.3021,5.986,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1973,912649,'tt16366836',NULL,'Venom: The Last Dance','Venom: The Last Dance','movie',2024,'https://image.tmdb.org/t/p/w500/vGXptEdgZIhPg3cGlc7e8sNPC2e.jpg','https://image.tmdb.org/t/p/original/3V4kLQg0kSqPLctI5ziYWabAZYF.jpg','Eddie and Venom are on the run. Hunted by both of their worlds and with the net closing in, the duo are forced into a devastating decision that will bring the curtains down on Venom and Eddie''s last dance.',NULL,NULL,16.6458,6.667,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1974,9536,'tt0115683',NULL,'Bio-Dome','Bio-Dome','movie',1996,'https://image.tmdb.org/t/p/w500/pjSkGZAvksrbO6tGain8PJ3rfC7.jpg','https://image.tmdb.org/t/p/original/4pXKbwEFGxvBMFq4QjOjljtVzdq.jpg','Moronic best friends get themselves locked inside the Bio-Dome, a science experiment, along with a group of environmental scientists for one year.',NULL,NULL,3.9715,4.585,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1975,4485,'tt0082269',NULL,'Diva','Diva','movie',1981,'https://image.tmdb.org/t/p/w500/x5fOCdfv0lRdeI71qLFdNEKWDsc.jpg','https://image.tmdb.org/t/p/original/elG982NKWQDhAdJ7KO5i3mBsbtW.jpg','Jules, a young Parisian postman, secretly records a concert performance given by the opera singer Cynthia Hawkins, whom he idolises. The following day, Jules runs into a woman who is being pursued by armed thugs. Before she is killed, the woman slips an audio cassette into his mail bag...',NULL,NULL,2.8491,6.7,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1976,2210,'tt0097257',NULL,'Earth Girls Are Easy','Earth Girls Are Easy','movie',1988,'https://image.tmdb.org/t/p/w500/lwFR24fEGf8Q6mGMsGcQuQTLL9T.jpg','https://image.tmdb.org/t/p/original/6qQZ54iVgQWOFaVWss77yHy8YHu.jpg','In this musical comedy, Valerie is dealing with her philandering fiancé, Ted, when she finds that a trio of aliens have crashed their spaceship into her swimming pool. Once the furry beings are shaved at her girlfriend''s salon, the women discover three handsome men underneath. After absorbing the native culture via television, the spacemen are ready to hit the dating scene in 1980s Los Angeles.',NULL,NULL,3.5101,5.572,0,14.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1977,20156,'tt0109759',NULL,'Exotica','Exotica','movie',1994,'https://image.tmdb.org/t/p/w500/3pibvRQK3A1E8cyhX8IQPIAU2J8.jpg','https://image.tmdb.org/t/p/original/sdgWn2YmR2h0HWFUGXmvbCerQCR.jpg','In the upscale Toronto strip club Exotica, dancer Christina is visited nightly by the obsessive Francis, a depressed tax auditor. Her ex-boyfriend, the club''s MC, Eric, still jealously pines for her even as he introduces her onstage, but Eric is having his own relationship problems with the club''s female owner. Thomas, a mysterious pet-shop owner, is about to become unexpectedly involved in their lives.',NULL,NULL,2.3114,6.631,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1978,27274,'tt0099611',NULL,'Frankenhooker','Frankenhooker','movie',1990,'https://image.tmdb.org/t/p/w500/s8Oubzkc2pPdOdj4D23ljZSKRbg.jpg','https://image.tmdb.org/t/p/original/pI56isyuRNOr4fFr0jRlIPnr3wv.jpg','A medical school dropout loses his fiancée in a tragic lawnmower incident and decides to bring her back to life. Unfortunately, he was only able to save her head, so he goes to the red light district in the city and lures prostitutes into a hotel room so he can collect body parts to reassemble her.',NULL,NULL,2.2187,6.3,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1979,12157,'tt0099699',NULL,'Green Card','Green Card','movie',1990,'https://image.tmdb.org/t/p/w500/9UweLsv3pCORu25Uq72m2IBkKaK.jpg','https://image.tmdb.org/t/p/original/gDopsdEzZEX81jmSidXn7tFb8fw.jpg','Urban horticulturalist Brontë Mitchell has her eye on a gorgeous apartment, but the building''s board will rent it only to a married couple. Georges Fauré, a waiter from France whose visa is expiring, needs to marry an American woman to stay in the country. Their marriage of convenience turns into a burden when they must live together to allay the suspicions of the immigration service, as the polar opposites grate on each other''s nerves.',NULL,NULL,1.6712,6.13,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1980,376865,'tt4827558',NULL,'High Life','High Life','movie',2018,'https://image.tmdb.org/t/p/w500/wElOvH7H6sLElsTOLu1MY6oWRUx.jpg','https://image.tmdb.org/t/p/original/bo5VJbds3oeMoj19GFnzBoUgjJS.jpg','Monte and his daughter are the last survivors of a damned and dangerous mission to deep space. The crew—death-row inmates led by a doctor with sinister motives—has vanished. As the mystery of what happened onboard the ship is unraveled, father and daughter must rely on each other to survive as they hurtle toward the oblivion of a black hole.',NULL,NULL,1.8424,5.7,0,15.014,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1981,11850,'tt0077745',NULL,'Invasion of the Body Snatchers','Invasion of the Body Snatchers','movie',1978,'https://image.tmdb.org/t/p/w500/skS02wdeH2C0nrbCQP3qKwJdZtZ.jpg','https://image.tmdb.org/t/p/original/lyHnFsWafILUlizalpCSikJT7Ui.jpg','The residents of San Francisco are becoming drone-like shadows of their former selves, and as the phenomenon spreads, two Department of Health workers uncover the horrifying truth.',NULL,NULL,4.528,7.226,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1982,10776,'tt0091419',NULL,'Little Shop of Horrors','Little Shop of Horrors','movie',1986,'https://image.tmdb.org/t/p/w500/iKkbN17OmFosaW6asCNZTTsyvpu.jpg','https://image.tmdb.org/t/p/original/z9y41Biv1isRtErpt7Ecv01ru0W.jpg','Seymour Krelborn is a nerdy orphan working at Mushnik''s; a flower shop in urban Skid Row. He harbors a crush on fellow co-worker, Audrey Fulquard, and is berated by Mr. Mushnik daily. One day, Seymour finds a very mysterious unidentified plant which he calls Audrey II. The plant seems to have a craving for blood and soon begins to sing for it’s supper.',NULL,NULL,3.9334,6.976,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1983,38027,'tt0073349',NULL,'Mandingo','Mandingo','movie',1975,'https://image.tmdb.org/t/p/w500/bZXmb4HQt24OAzdKoBdSEqcFvBw.jpg','https://image.tmdb.org/t/p/original/vf5xvKEjwhSuJttR4NmVrOGXyrS.jpg','Warren Maxwell, the owner of a run-down plantation, pressures his son, Hammond, to marry and produce an heir to inherit the plantation. Hammond settles on his own cousin, Blanche, but purchases a sex slave when he returns from the honeymoon. He also buys his father a new Mandingo slave named Mede to breed and train as a prize-fighter.',NULL,NULL,2.3616,6.638,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1984,73411,'tt5580146',NULL,'Maniac','Maniac','tv',2018,'https://image.tmdb.org/t/p/w500/kCNl4QPstAqChFD0NnLpbDFG8ul.jpg','https://image.tmdb.org/t/p/original/f9z6gCtDlr88l2VBQOY6luaSfPi.jpg','Two strangers are drawn to a mysterious pharmaceutical trial that will, they''re assured, with no complications or side-effects whatsoever, solve all of their problems, permanently. Things do not go as planned.',NULL,NULL,7.752,7.349,0,12.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1985,1887,'tt0422720',NULL,'Marie Antoinette','Marie Antoinette','movie',2006,'https://image.tmdb.org/t/p/w500/cybXGmv8Rjd5Os8Xml6YxMBQ0Zt.jpg','https://image.tmdb.org/t/p/original/9hxBNoRjEDZGjyR1JpmmtxJWmVU.jpg','A retelling of the story of France’s iconic but ill-fated queen, Marie Antoinette - from her betrothal and marriage to Louis XVI at fifteen to her reign as queen at nineteen and ultimately the fall of Versailles.',NULL,NULL,4.0367,6.698,0,14.546,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1986,10830,'tt0117008',NULL,'Matilda','Matilda','movie',1996,'https://image.tmdb.org/t/p/w500/wYoDpWInsBEVSmWStnRH06ddoyk.jpg','https://image.tmdb.org/t/p/original/t3HVA7XdVnQneMjI5hYjEhXmHY3.jpg','Matilda Wormwood is an brilliant and intelligent little girl. Unfortunately, her parents, Harry and Zinnia, fail to see that fact. As time passes, she finally starts school and has a kind teacher, loyal friends, and a terrifying, sadistic headmistress. As she becomes fed up with the constant cruelty, she discovers she has a special gift that she just might be able to use to outwit the unruly adults around her.',NULL,NULL,9.6967,7.18,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1987,2067,'tt0183523',NULL,'Mission to Mars','Mission to Mars','movie',2000,'https://image.tmdb.org/t/p/w500/cTKWoBpN5Gvi0vpMb9mLtYlwXqT.jpg','https://image.tmdb.org/t/p/original/qurwfjYAzSgSsQl99IY6ttZ0S7P.jpg','When the first manned mission to Mars meets with a catastrophic and mysterious disaster after reporting an unidentified structure, a rescue mission is launched to investigate the tragedy and bring back any survivors.',NULL,NULL,3.1149,6.042,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1988,11621,'tt0104652',NULL,'Porco Rosso','紅の豚','movie',1992,'https://image.tmdb.org/t/p/w500/8mIvSvnVBApfORL9N6S38Q7wD6A.jpg','https://image.tmdb.org/t/p/original/pFalq14lacs2oO7Q6YKiNqz5uAC.jpg','In Italy in the 1930s, sky pirates in biplanes terrorize wealthy cruise ships as they sail the Adriatic Sea. The only pilot brave enough to stop the scourge is the mysterious Porco Rosso, a former World War I flying ace who was somehow turned into a pig during the war. As he prepares to battle the pirate crew''s American ace, Porco Rosso enlists the help of spunky girl mechanic Fio Piccolo and his longtime friend Madame Gina.',NULL,NULL,4.3679,7.798,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1989,1020006,'tt22041854',NULL,'Priscilla','Priscilla','movie',2023,'https://image.tmdb.org/t/p/w500/uDCeELWWpsNq7ErM61Yuq70WAE9.jpg','https://image.tmdb.org/t/p/original/zz219ZRGo0vVIzvKttjx5nXOc2N.jpg','When teenage Priscilla Beaulieu meets Elvis Presley at a party, the man who is already a meteoric rock-and-roll superstar becomes someone entirely unexpected in private moments: a thrilling crush, an ally in loneliness, a vulnerable best friend.',NULL,NULL,3.9102,6.71,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1990,506072,'tt7946422',NULL,'Prospect','Prospect','movie',2018,'https://image.tmdb.org/t/p/w500/1HpAwszXLsD8GeypDzK0me7fPFA.jpg','https://image.tmdb.org/t/p/original/3r6e2CfNHvtQ1nlXmfwPV7JM3iN.jpg','A teenage girl and her father travel to a remote alien moon, aiming to strike it rich. They''ve secured a contract to harvest a large deposit of the elusive gems hidden in the depths of the moon''s toxic forest. But there are others roving the wilderness and the job quickly devolves into a fight to survive.',NULL,NULL,2.1051,6.216,0,11.525,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1991,81247,'tt0177195',NULL,'Sample People','Sample People','movie',2000,'https://image.tmdb.org/t/p/w500/6WuTLAY7XEZVDw8RP0DjjAd0vDU.jpg','https://image.tmdb.org/t/p/original/wOrLNt0y8NcQMTnzlhl66bRIKR6.jpg','Sample People is an upbeat dramatic thriller that follows four groups of Sydney-siders as they seek escape routes over one sweltering weekend. ''Len the dreamer'' who stutters shyly just wants the gorgeous DJ Lush Puppy. Sem is a funky musician who has a premonition warning him that his girlfriend, Cleo, is in danger. He just wants to get them both out of their inner-city world. Andy is the charismatic drifter who''s conned his way through life and stolen money from his boss, TT. He just wants to head up the coast with TT''s girlfriend, Jess, but seems to be falling deeper into a love triangle of drugs and delusion. Finally, there''s Joey, a TV affected homeboy, who reveals to his best friend Gus that he''s got a gun and will use it sooner or later. The inevitable moment will arrive whin his violent gangster fantisies become reality. As the lives of our heroes become dramatically entwined, the consequences of their actions ricochet off each other.',NULL,NULL,0.5768,3.889,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1992,811,'tt0067756',NULL,'Silent Running','Silent Running','movie',1972,'https://image.tmdb.org/t/p/w500/ahasZ5HILZHtlrl6cbXgpfk0y8H.jpg','https://image.tmdb.org/t/p/original/5QTwfS9vcr22Nl7PCcUro7dEMFq.jpg','After the entire flora goes extinct, ecologist Lowell maintains a greenhouse aboard a space station for the future with his android companions. However, he rebels after being ordered to destroy the greenhouse in favor of carrying cargo, a decision that puts him at odds with everyone but his mechanical companions.',NULL,NULL,2.3284,6.397,0,12.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1993,115,'tt0118715',NULL,'The Big Lebowski','The Big Lebowski','movie',1998,'https://image.tmdb.org/t/p/w500/3bv6WAp6BSxxYvB5ozKFUYuRA8C.jpg','https://image.tmdb.org/t/p/original/hXsy4XCCHrUk81XoRhcooyWejao.jpg','Jeffrey ''The Dude'' Lebowski, a Los Angeles slacker who only wants to bowl and drink White Russians, is mistaken for another Jeffrey Lebowski, a wheelchair-bound millionaire, and finds himself dragged into a strange series of events involving nihilists, adult film producers, ferrets, errant toes, and large sums of money.',NULL,NULL,9.7478,7.836,0,11.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1994,617762,'tt10687506',NULL,'The Electrical Life of Louis Wain','The Electrical Life of Louis Wain','movie',2021,'https://image.tmdb.org/t/p/w500/jmlul0Y8KBXPqJ0LUcTfsCoRcoI.jpg','https://image.tmdb.org/t/p/original/vwtvQochfV2XZgQsxLueUSvdmPd.jpg','The extraordinary true story of eccentric British artist Louis Wain, whose playful, sometimes even psychedelic pictures helped to transform the public''s perception of cats forever.',NULL,NULL,1.7075,6.893,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1995,31923,'tt0100911',NULL,'Welcome Home, Roxy Carmichael','Welcome Home, Roxy Carmichael','movie',1990,'https://image.tmdb.org/t/p/w500/7ygtZksyPjzkjdFL036YfnSTc1F.jpg','https://image.tmdb.org/t/p/original/snNj2CZeaBHkP5xT5ep1efxa6rY.jpg','Movie star Roxy Carmichael is abandoning the bright lights of Hollywood, Calif. and returning to her small Ohio hometown -- at least long enough to dedicate a city building. And now the whole town of Clyde is bracing for Carmichael''s return, most of all her now-married old flame Denton Webb and troubled teen Dinky Bossetti. An orphan with few friends, Dinky is convinced that Carmichael is her birth mother, and that the actress will reclaim her when she returns.',NULL,NULL,1.5314,6.2,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1996,1579,'tt0472043',NULL,'Apocalypto','Apocalypto','movie',2006,'https://image.tmdb.org/t/p/w500/cRY25Q32kDNPFDkFkxAs6bgCq3L.jpg','https://image.tmdb.org/t/p/original/nnmbJvYyDS1VkMOCbxSpdBi3WbJ.jpg','Set in the Mayan civilization, when a man''s idyllic presence is brutally disrupted by a violent invading force, he is taken on a perilous journey to a world ruled by fear and oppression where a harrowing end awaits him. Through a twist of fate and spurred by the power of his love for his woman and his family he will make a desperate break to return home and to ultimately save his way of life.',NULL,NULL,19.9126,7.651,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1997,1411,'tt0102757',NULL,'The Rapture','The Rapture','movie',1991,'https://image.tmdb.org/t/p/w500/4EkFm13ecqO0eszr7OKT8vf1YjJ.jpg','https://image.tmdb.org/t/p/original/ylXFsNIhzq8A5nEqLhPdDYPOnVo.jpg','A lonely telephone operator leading an empty, amoral life finds God – only to have her faith continually tested in ways beyond what she could have imagined.',NULL,NULL,1.3916,5.7,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1998,181808,'tt2527336',NULL,'Star Wars: The Last Jedi','Star Wars: The Last Jedi','movie',2017,'https://image.tmdb.org/t/p/w500/kOVEVeg59E0wsnXmF9nrh6OmWII.jpg','https://image.tmdb.org/t/p/original/bIUaCtWaRgd78SnoHJDI8TNf7Sd.jpg','Rey develops her newly discovered abilities with the guidance of Luke Skywalker, who is unsettled by the strength of her powers. Meanwhile, the Resistance prepares to do battle with the First Order.',NULL,NULL,24.9894,6.748,0,6.27999999999999936e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(1999,1316092,'tt32897959',NULL,'"Wuthering Heights"','"Wuthering Heights"','movie',2026,'https://image.tmdb.org/t/p/w500/3YBce6dTh1D5oCMITXk2S5QhPt.jpg','https://image.tmdb.org/t/p/original/nHKscpZcAPkh97OsJJjyE5yaVE0.jpg','Tragedy strikes when Heathcliff falls in love with Catherine Earnshaw, a woman from a wealthy family in 18th-century England.',NULL,NULL,20.9016,6.682,0,9.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2000,11980,'tt0114194',NULL,'The Prophecy','The Prophecy','movie',1995,'https://image.tmdb.org/t/p/w500/4ZWFhQipzBHJze2llzCzhrSIZsn.jpg','https://image.tmdb.org/t/p/original/kZbLOAlCB3htkhyZzTkUv21i0gv.jpg','The angel Gabriel comes to Earth to collect a soul which will end the stalemated war in Heaven. However, it is hidden inside of a Native American girl and only a former priest and a schoolteacher can stop him.',NULL,NULL,2.4073,6.506,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2001,23047,'tt0479997',NULL,'Season of the Witch','Season of the Witch','movie',2011,'https://image.tmdb.org/t/p/w500/dNVqi8EsBtnnwfR6TgiWM51JOuS.jpg','https://image.tmdb.org/t/p/original/9Lm94WVtV4HPxr7NWNlwkhLKSeH.jpg','A 14th century Crusader returns with his comrade to a homeland devastated by the Black Plague. The Church commands the two knights to transport a witch to a remote abbey, where monks will perform a ritual in hopes of ending the pestilence.',NULL,NULL,5.1,5.53,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2002,112090,'tt1368440',NULL,'Branded','Branded','movie',2012,'https://image.tmdb.org/t/p/w500/8YE4OfV1sHketYGy78AOCMI7j7T.jpg','https://image.tmdb.org/t/p/original/deWsq58zna9vzVDpP9kCv8XXVvI.jpg','In a dystopian future, where corporate brands have created a disillusioned population, one man''s effort to unlock the truth behind the conspiracy leads to an epic battle with hidden forces that control the world.',NULL,NULL,2.8712,4.724,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2003,9495,'tt0109506',NULL,'The Crow','The Crow','movie',1994,'https://image.tmdb.org/t/p/w500/rMMB3v6jYHjsvXRNJYESacoTD7j.jpg','https://image.tmdb.org/t/p/original/2VN9umruwVZsT1Pr1NMCV71HpUu.jpg','Exactly one year after young rock guitarist Eric Draven and his fiancée are brutally killed by a ruthless gang of criminals, Draven, watched over by a hypnotic crow, returns from the grave to exact revenge.',NULL,NULL,6.5948,7.528,0,11.765,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2004,878608,'tt29002950',NULL,'Resurrection','狂野时代','movie',2025,'https://image.tmdb.org/t/p/w500/n4YEPanrb976XfPKjSsHaIrlSt9.jpg','https://image.tmdb.org/t/p/original/sbmHT55N2aIwctQEY1pWOwRrxK0.jpg','In a future where humanity has surrendered its ability to dream in exchange for immortality, an outcast finds illusion, nightmarish visions, and beauty in an intoxicating world of his own making.',NULL,NULL,4.5496,7.255,0,9.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2005,744857,'tt16300962',NULL,'When Evil Lurks','Cuando acecha la maldad','movie',2023,'https://image.tmdb.org/t/p/w500/iQ7G9LhP7NRRIUM4Vlai3eOxBAc.jpg','https://image.tmdb.org/t/p/original/cavK9ox37pxDg11RvJINMH63onU.jpg','When brothers Pedro and Jimi discover that a demonic infection has been festering in a nearby farmhouse, they attempt to evict the victim from their land. Failing to adhere to the proper rites of exorcism, their reckless actions inadvertently trigger an epidemic of possessions across their rural community.',NULL,NULL,6.7873,7.141,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2006,9377,'tt0091042',NULL,'Ferris Bueller''s Day Off','Ferris Bueller''s Day Off','movie',1986,'https://image.tmdb.org/t/p/w500/9LTQNCvoLsKXP0LtaKAaYVtRaQL.jpg','https://image.tmdb.org/t/p/original/leehjwM57DKJ79XMUll4oAF0kin.jpg','After high school slacker Ferris Bueller successfully fakes an illness in order to skip school for the day, he goes on a series of adventures throughout Chicago with his girlfriend Sloane and best friend Cameron, all the while trying to outwit his wily school principal and fed-up sister.',NULL,NULL,6.6893,7.6,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2007,61202,'tt1562872',NULL,'Zindagi Na Milegi Dobara','ज़िन्दगी ना मिलेगी दोबारा','movie',2011,'https://image.tmdb.org/t/p/w500/hKO9O715wYxjkQSEv47giCYcyO8.jpg','https://image.tmdb.org/t/p/original/z4k7b66jAHP8sQbEahxss6Ct8BW.jpg','Three friends who were inseparable in childhood decide to go on a three-week-long bachelor road trip to Spain, in order to re-establish their bond and explore thrilling adventures, before one of them gets married. What will they learn of themselves and each other during the adventure?',NULL,NULL,2.6601,7.614,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2008,773,'tt0449059',NULL,'Little Miss Sunshine','Little Miss Sunshine','movie',2006,'https://image.tmdb.org/t/p/w500/niNdhTpPHSgw22tK0PLjQMV640v.jpg','https://image.tmdb.org/t/p/original/yE376O0gMgUE7wX1PQ9bbTPVvFq.jpg','A family loaded with quirky, colorful characters piles into an old van and road trips to California for little Olive to compete in a beauty pageant.',NULL,NULL,6.4148,7.693,0,13.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2009,82693,'tt1045658',NULL,'Silver Linings Playbook','Silver Linings Playbook','movie',2012,'https://image.tmdb.org/t/p/w500/fhHB1uvfFKKFbj6bTKE8xdtsjKi.jpg','https://image.tmdb.org/t/p/original/12GpsUm9nVVKFlcjDTflKLClFVA.jpg','After losing his job and wife, and spending time in an institution, a former teacher winds up living with his parents. He wants to rebuild his life and reconcile with his wife, but his father would be happy if he shared his obsession with the Philadelphia Eagles. Things get complicated when he meets Tiffany Maxwell who offers to help him reconnect with his wife if he will do something very important for her in exchange.',NULL,NULL,6.9988,7.154,0,11.11,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2010,586621,'tt7707108',NULL,'Jelgava ''94','Jelgava ''94','movie',2019,'https://image.tmdb.org/t/p/w500/zBUnWXROKVyAfeZINMiOEZfHiiz.jpg','https://image.tmdb.org/t/p/original/ny2d3bMzAR6Jg9HuSGQulbvoCaj.jpg','It is year 1994. Spring. In Jelgava – a small town in Latvia. Jānis (14) – behaves well at school, shows interest in all subjects, and studies well. His mother loves him very much. There are exactly two things happening in one day, which change his life completely. One – a new girl, Kristīne (15), comes to his class and attracts everybody’s attention immediately. And second– Kurt Cobain commits suicide. Until this moment Jānis does not know anything neither about Nirvana, nor about Cobain. But very soon he finds out.',NULL,NULL,0.1843,6.667,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2011,227,'tt0086066',NULL,'The Outsiders','The Outsiders','movie',1983,'https://image.tmdb.org/t/p/w500/l9os0HcXY8BOkvUWAx4rvby3j6L.jpg','https://image.tmdb.org/t/p/original/hpzbQDjl2yzf6MwrYOrbDJCmojc.jpg','In 1960s Tulsa, class divisions ignite a violent rivalry between the working-class Greasers and the privileged Socs. When a deadly encounter forces two Greasers, Ponyboy and Johnny, to flee, their struggle for survival and redemption exposes the fragile innocence and enduring bonds of youth on the wrong side of town.',NULL,NULL,5.7473,7.2,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2012,8009,'tt0091203',NULL,'Highlander','Highlander','movie',1986,'https://image.tmdb.org/t/p/w500/8Z8dptJEypuLoOQro1WugD855YE.jpg','https://image.tmdb.org/t/p/original/2EfbAWLq8s2f1LxTAIuLGYpKETV.jpg','He fought his first battle on the Scottish Highlands in 1536. He will fight his greatest battle on the streets of New York City in 1986. His name is Connor MacLeod. He is immortal.',NULL,NULL,6.125,6.9,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2013,40807,'tt1306980',NULL,'50/50','50/50','movie',2011,'https://image.tmdb.org/t/p/w500/8f9tM9JVB4ETBhxlQcXIjLckArl.jpg','https://image.tmdb.org/t/p/original/yq9g4RGM1mEMBoSL5HKVBy9MOPM.jpg','Inspired by a true story, a comedy centered on a 27-year-old guy who learns of his cancer diagnosis and his subsequent struggle to beat the disease.',NULL,NULL,3.3487,7.18,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2014,7457,'tt0426883',NULL,'Alpha Dog','Alpha Dog','movie',2006,'https://image.tmdb.org/t/p/w500/t9pirEsDxe102mSQGoDZWBbdcCD.jpg','https://image.tmdb.org/t/p/original/oxEvnbNAr1BFWX8XQ6KBU35uWN8.jpg','Johnny Truelove likes to see himself as tough. He''s the son of an underworld figure and a drug dealer. Johnny also likes to get tough when things don''t go his way. When Jake Mazursky fails to pay up for Johnny, things get worse for the Mazursky family, as Johnny and his ''gang'' kidnap Jake''s 15 year old brother and hold him hostage.',NULL,NULL,3.0616,6.649,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2015,14578,'tt0125971',NULL,'Outside Providence','Outside Providence','movie',1999,'https://image.tmdb.org/t/p/w500/xSqewkFWR0zs7OkXLOd10VnxFPN.jpg','https://image.tmdb.org/t/p/original/fEr2cdMiY1OPmGRUGnH12F0VYRN.jpg','In this coming-of-age comedy, Tim Dunphy is leading a go-nowhere existence, spending his days smoking pot and hanging out with his best friend, Drugs Delaney. But Tim''s lazy days of getting high are jettisoned after a brush with the law convinces his blue-collar dad to send him to a Connecticut prep school. The one saving grace of the new school is Jane, a fellow student Tim falls for immediately.',NULL,NULL,1.1156,5.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2016,105703,'tt0085533',NULL,'The Boys from Fengkuei','風櫃來的人','movie',1983,'https://image.tmdb.org/t/p/w500/r6evRAtqfodrY9eytNt7Oc7gg0a.jpg','https://image.tmdb.org/t/p/original/k9umWAxbyVZQkd1zTKoo9HeOab2.jpg','Ah-Ching and his friends have just finished school in their island fishing village, and now spend most of their time drinking and fighting. Three of them decide to go to the port city of Kaohsiung to look for work. They find an apartment through relatives, and Ah-Ching is attracted to the girlfriend of a neighbor. There they face the harsh realities of the big city.',NULL,NULL,0.7513,7.235,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2017,1599,'tt0356721',NULL,'I ♥ Huckabees','I ♥ Huckabees','movie',2004,'https://image.tmdb.org/t/p/w500/h27ytqXyOrAB6KmRx2abOp8p2W.jpg','https://image.tmdb.org/t/p/original/lMSlZxJp43HR81XacWh75w3hW2l.jpg','A husband-and-wife team play detective, but not in the traditional sense. Instead, the happy duo helps others solve their existential issues, the kind that keep you up at night, wondering what it all means.',NULL,NULL,3.6782,6.288,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2018,21712,'tt0452039',NULL,'Mind Game','マインド・ゲーム','movie',2004,'https://image.tmdb.org/t/p/w500/e5mV1iVcjg7nkpJrskQOnFCR4H9.jpg','https://image.tmdb.org/t/p/original/19SRSM2ybfVpCBxBFLXwyD18WkM.jpg','Nishi is a loser who has a crush on his childhood girlfriend. After an encounter with the Japanese mafia, he journeys to heaven and back, and ends up trapped in an even more unlikely place.',NULL,NULL,2.0867,7.49,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2019,49806,'tt0116041',NULL,'The Daytrippers','The Daytrippers','movie',1997,'https://image.tmdb.org/t/p/w500/bDmconT9Fj0dnXdV5LaGAxXrVFN.jpg','https://image.tmdb.org/t/p/original/jcybjAhhzJYgacSx3DOrtAXOwzR.jpg','Eliza D''Amico thinks her marriage to Louis is going great until she finds a mysterious love note to her husband. Concerned, she goes to her mother for advice. Eliza, her parents, her sister Jo, and Jo''s boyfriend all pile into the station wagon and go to the city to confront Louis with the letter. On the way, the five explore their relations with each other and meet many interesting people.',NULL,NULL,1.4555,6.6,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2020,11951,'tt0067927',NULL,'Vanishing Point','Vanishing Point','movie',1971,'https://image.tmdb.org/t/p/w500/1ThnpFx2G2HPhecvODGFEQxfOpO.jpg','https://image.tmdb.org/t/p/original/sYn05iS9AxV9rsjqBSHrI4azji1.jpg','Kowalski works for a car delivery service, and takes delivery of a 1970 Dodge Challenger to drive from Colorado to San Francisco. Shortly after pickup, he takes a bet to get the car there in less than 15 hours.',NULL,NULL,2.4919,7.082,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2021,10373,'tt0079766',NULL,'Quadrophenia','Quadrophenia','movie',1979,'https://image.tmdb.org/t/p/w500/4sRR3pvrAZMG7GEvnR9XzqyHHfD.jpg','https://image.tmdb.org/t/p/original/n31i51vwTOOUxKd1DWU2r6if0XR.jpg','Based on the 1973 rock opera album of the same name by The Who, this is the story of 60s teenager Jimmy. At work he slaves in a dead-end job. While after, he shops for tailored suits and rides his scooter as part of the London Mod scene.',NULL,NULL,2.5443,7.015,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2022,9781,'tt0165710',NULL,'Detroit Rock City','Detroit Rock City','movie',1999,'https://image.tmdb.org/t/p/w500/jedOctnsD20K4IvOeh5jG811B8L.jpg','https://image.tmdb.org/t/p/original/NH15yF3nLKyYpog18sy5ynnGBf.jpg','In 1978, a Kiss concert was an epoch-making event. For the four teen fans in Detroit Rock City getting tickets to the sold-out show becomes the focal point of their existence. They''ll do anything for tickets -- compete in a strip club''s amateur-night contest, take on religious protesters, even rob a convenience store!',NULL,NULL,2.2693,6.8,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2023,1584,'tt0332379',NULL,'The School of Rock','The School of Rock','movie',2003,'https://image.tmdb.org/t/p/w500/zXLXaepIBvFVLU25DH3wv4IPSbe.jpg','https://image.tmdb.org/t/p/original/k5MTAtE9CCi5TWA84qaFMYv3ajB.jpg','Fired from his band and hard up for cash, guitarist and vocalist Dewey Finn finagles his way into a job as a fifth-grade substitute teacher at a private school, where he secretly begins teaching his straight-A students the finer points of rock ''n'' roll and the power of sticking it to the man. But as the school’s stern principal closes in and the Battle of the Bands looms, Dewey must risk everything to prove that rock ''n'' roll can change lives.',NULL,NULL,8.8282,7.087,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2024,84332,'tt1862079',NULL,'Safety Not Guaranteed','Safety Not Guaranteed','movie',2012,'https://image.tmdb.org/t/p/w500/gH0l9kiaK1Ulalbq07nqR7jtin5.jpg','https://image.tmdb.org/t/p/original/hOVZHM2ZEaWdytcptRhfzk0fJBv.jpg','Three magazine employees head out on an assignment to interview a guy who placed a classified ad seeking a companion for time travel.',NULL,NULL,2.3654,6.777,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2025,13532,'tt0489049',NULL,'Fanboys','Fanboys','movie',2009,'https://image.tmdb.org/t/p/w500/fitksX4J3xfBjT38YgDUXOlBkHk.jpg','https://image.tmdb.org/t/p/original/5XeSSkjxmXaLmnLWTyeuihDWx14.jpg','In 1999, Star Wars fanatics take a cross-country trip to George Lucas'' Skywalker Ranch so their dying friend can see a screening of The Phantom Menace before its release.',NULL,NULL,4.4707,6.142,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2026,13984,'tt0302585',NULL,'Fubar','Fubar','movie',2002,'https://image.tmdb.org/t/p/w500/95f3BiuBTKhemHLVe7Nyh8AhuEa.jpg','https://image.tmdb.org/t/p/original/li0odPdqPoxaFYsQcjtXU1klwyP.jpg','Terry and Dean are lifelong friends who have grown-up together: shotgunning their first beers, forming their first garage band, and growing the great Canadian mullet known as "hockey hair". Now the lives of these Alberta everymen are brought to the big screen by documentarian Ferral Mitchener in an exploration of the depths of friendship, the fragility of life, growing up gracefully and the art and science of drinking beer like a man.',NULL,NULL,0.746,6.277,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2027,1182614,'tt5232946',NULL,'Two Lane Blacktop','Two Lane Blacktop','movie',NULL,'https://image.tmdb.org/t/p/w500/2A8HsR1U5qWgH4FsKS9vRje5mHp.jpg',NULL,'1972 TWO BOYS EMBARK IN A RACE ACCROSS ROUTE 66. Now the real story begins as the 1970''s opens up to us in music and time',NULL,NULL,0.4308,0.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2028,1366,'tt0075148',NULL,'Rocky','Rocky','movie',1976,'https://image.tmdb.org/t/p/w500/aYtBYWqCdUqcnoodWJdcTG3pFev.jpg','https://image.tmdb.org/t/p/original/xUZ2G8MRGEljqgqLxMJItK4iHfY.jpg','Rocky Balboa is a Philadelphia club fighter who seems to be going nowhere. But when a stroke of fate puts him in the ring with a world heavyweight champion, Rocky knows that it''s his one shot at the big time — a once-in-a-lifetime opportunity to go the distance and come out a winner!',NULL,NULL,9.5648,7.8,0,1.21833333333333335e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2029,312221,'tt3076658',NULL,'Creed','Creed','movie',2015,'https://image.tmdb.org/t/p/w500/1BfTsk5VWuw8FCocAhCyqnRbEzq.jpg','https://image.tmdb.org/t/p/original/kODNw6GJNdgldUMEhKPlCw8wQCr.jpg','The former World Heavyweight Champion Rocky Balboa serves as a trainer and mentor to Adonis Johnson, the son of his late friend and former rival Apollo Creed.',NULL,NULL,7.2326,7.407,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2030,26942,'tt0280424',NULL,'Amy''s Orgasm','Amy''s Orgasm','movie',2001,'https://image.tmdb.org/t/p/w500/hsqw2fdGb13VryEo7kKMr1F3GJz.jpg','https://image.tmdb.org/t/p/original/1gM96msvuKrOYWrV49zFqWWAIu9.jpg','Amy is a single 29 year old Jewish woman. She wrote a successful self-help book about how women can''t truly be in love and experience "mental orgasm." Her parents and acquaintances always try to give her advice. Eventually, she breaks her celibacy and starts dating a radio shock jock, who is known for hitting on his bimbo guests. Of all men, will she find in him the true love she never believed in',NULL,NULL,1.2307,4.882,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2031,82700,'tt7645192',NULL,'Baby','Baby','tv',2018,'https://image.tmdb.org/t/p/w500/xswkOJni9tJYda2yN1QQtgBVaVJ.jpg','https://image.tmdb.org/t/p/original/hcS061TTRke127eJtrbWWPIjUZe.jpg','Fed up with their families and classmates, two teen girls from a wealthy part of Rome are drawn to the city''s underworld and start leading double lives.',NULL,NULL,6.2623,7.908,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2032,60839,'tt2578560',NULL,'Broad City','Broad City','tv',2014,'https://image.tmdb.org/t/p/w500/fRu9zQFdWHjEVyHwnIYqm0LRoKA.jpg','https://image.tmdb.org/t/p/original/r0Fx0BJn71eJLYGvojcgHRec2Lx.jpg','Broad City follows two women throughout their daily lives in New York City, making the smallest and mundane events hysterical and disturbing to watch all at the same time.',NULL,NULL,10.8836,7.121,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2033,146184,'tt0208783',NULL,'Bye Bye Blue Bird','Bye Bye Blue Bird','movie',1999,'https://image.tmdb.org/t/p/w500/a5l071sCi6cKXWWzLEs3pV6zkj9.jpg','https://image.tmdb.org/t/p/original/mC2RSbwec4Yi3BJInmXn34U58R5.jpg','Two friends, Rannvá and Barba, return to Faroe Islands after seven years abroad. The girls arouse both curiosity and outrage with their bizarre city appearance and emancipated behaviour. They embark on a road trip with one of the locals, Rúni, who - as it turns out - also carries a dark secret. The trio goes on a journey not just through the beautiful landscape of the Faroes but into the land of the past.',NULL,NULL,0.9898,5.714,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2034,1215,'tt0904208',NULL,'Californication','Californication','tv',2007,'https://image.tmdb.org/t/p/w500/jPqOY8cq9KXQN4bD7zJGHCNvcb4.jpg','https://image.tmdb.org/t/p/original/9o9SS26mUY4cp4iSFk7iwBeAQuP.jpg','A self-loathing, alcoholic writer attempts to repair his damaged relationships with his daughter and her mother while combating sex addiction, a budding drug problem, and the seeming inability to avoid making bad decisions.',NULL,NULL,42.2211,7.6,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2035,65251,'tt5295524',NULL,'Crashing','Crashing','tv',2016,'https://image.tmdb.org/t/p/w500/kXgTnJXZ5KtJhEEuwiTRTRUejCt.jpg','https://image.tmdb.org/t/p/original/65TF1b385Q2YxLVwgriZhCgdFAz.jpg','A comedy drama that crashes straight into the lives and loves of six twenty-something adults living together as Property Guardians in a disused hospital.',NULL,NULL,2.0128,7.1,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2036,64797,'tt0349340',NULL,'Dead Bodies','Dead Bodies','movie',2003,'https://image.tmdb.org/t/p/w500/apGKZgD3eCuMcyg1pLRmEM7W1Tp.jpg','https://image.tmdb.org/t/p/original/lf824nz5248CsXdRjr9KhNKd8d8.jpg','The return of a vengeful ex-girlfriend sets into motion a series of gruesome events for a hapless Irish bachelor in director Robert Quinn''s grim black comedy. Tommy (Andrew Scott) had thought he had seen the last of Jean (Katy Davis) after their recent breakup, but when she returns to stake her claim on Tommy''s apartment, the confrontation that ensues makes their previous quarrels look petty by comparison. After leaving the apartment in the head of the fight to cool his head and gather his thoughts, he returns only to find that Jean has died and enlists the aid of his friend Noel (Darren Healy) in ditching the body and ensuring that no one ever finds out what happened.',NULL,NULL,0.8232,5.519,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2037,76148,'tt7120662',NULL,'Derry Girls','Derry Girls','tv',2018,'https://image.tmdb.org/t/p/w500/btIm8LOtm2qgHIA2IHmQJvD1Mju.jpg','https://image.tmdb.org/t/p/original/nQyQ4c8DUvXra1LDWnNfV9QJluD.jpg','Amidst the political conflict of Northern Ireland in the 1990s, five secondary school students square off with the universal challenges of being a teenager.',NULL,NULL,7.9399,8.1,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2038,85552,'tt8772296',NULL,'Euphoria','Euphoria','tv',2019,'https://image.tmdb.org/t/p/w500/ypmtwojDd751Peszi62DVLytqqC.jpg','https://image.tmdb.org/t/p/original/GN2KFXiHPVV6sIw4v2P2pqCJty.jpg','A group of high school students navigate love and friendships in a world of drugs, sex, trauma, and social media.',NULL,NULL,98.2214,8.283,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2039,10330,'tt0322330',NULL,'Freaky Friday','Freaky Friday','movie',2003,'https://image.tmdb.org/t/p/w500/ipKcZ4Up7dp18XpsfYUc9NKZy3g.jpg','https://image.tmdb.org/t/p/original/f2eKVQmEeIwZwccVvuXMkUR816J.jpg','Mother and daughter bicker over everything -- what Anna wears, whom she likes and what she wants to do when she''s older. In turn, Anna detests Tess''s fiancé. When a magical fortune cookie switches their personalities, they each get a peek at how the other person feels, thinks and lives.',NULL,NULL,6.1744,6.588,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2040,1422008,'tt35515220',NULL,'Fucktoys','Fucktoys','movie',2025,'https://image.tmdb.org/t/p/w500/hYDSzen6p8wkhkskWzwgr5dz5EN.jpg','https://image.tmdb.org/t/p/original/cWK1tJnrdvwoJftncYrqIHyMDCB.jpg','AP’s got a curse and it’s really fucking up her vibe.',NULL,NULL,2.3953,8.9,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2041,13403,'tt0248845',NULL,'Hedwig and the Angry Inch','Hedwig and the Angry Inch','movie',2001,'https://image.tmdb.org/t/p/w500/jafIFAW8sHQkzWPGoMDR4892dFI.jpg','https://image.tmdb.org/t/p/original/uY5EB9VIX8lT03MdYcR9DzlhEGM.jpg','Raised a boy in East Berlin, Hedwig undergoes a personal transformation in order to emigrate to the U.S., where she reinvents herself as an ''internationally ignored'' but divinely talented rock diva, inhabiting a ''beautiful gender of one''.',NULL,NULL,1.4185,7.4,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2042,520679,'tt7942742',NULL,'Her Smell','Her Smell','movie',2019,'https://image.tmdb.org/t/p/w500/qEvgdGBMORPS0rz8pqkVH3obLee.jpg','https://image.tmdb.org/t/p/original/mjmeOkfLUMgsJJGFKDscyiSJyXM.jpg','A self-destructive punk rocker struggles with sobriety while trying to recapture the creative inspiration that led her band to success.',NULL,NULL,3.7293,5.769,0,2.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2043,309245,'tt2872462',NULL,'Mistress America','Mistress America','movie',2015,'https://image.tmdb.org/t/p/w500/w0V4M9nY9bjsoTKdaAYzL9gRpWY.jpg','https://image.tmdb.org/t/p/original/m8b8ivhrpTOzFDS1bOyiw4PgwSL.jpg','A college freshman cures her disappointment and loneliness by allowing herself to be pulled into the wacky schemes of her future stepsister.',NULL,NULL,1.599,6.472,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2044,583689,'tt6432466',NULL,'Moxie','Moxie','movie',2021,'https://image.tmdb.org/t/p/w500/aLBo1Ca9PggcWY98ItW5ZkdxTuA.jpg','https://image.tmdb.org/t/p/original/aKIrKbszS7Kq0aTGTCRTYMp1EDX.jpg','Inspired by her mom''s rebellious past and a confident new friend, a shy 16-year-old publishes an anonymous zine calling out sexism at her school.',NULL,NULL,1.6836,7.197,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2045,1101,'tt0108872',NULL,'My So-Called Life','My So-Called Life','tv',1994,'https://image.tmdb.org/t/p/w500/kuyxEBpuAYdfHqfzip2Y6UYRI2C.jpg','https://image.tmdb.org/t/p/original/tqubNA9ZtI6CW64JXhqXw9fAgPT.jpg','The life of a 15 year-old high school student, whose angst-ridden journey through adolescence, friendship, parents, and life teaches her what it means to grow up.',NULL,NULL,5.3357,7.7,0,1.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2046,1415,'tt0320244',NULL,'Party Monster','Party Monster','movie',2003,'https://image.tmdb.org/t/p/w500/4DVWGtV1OA3W8kZxiimdNsepS6O.jpg','https://image.tmdb.org/t/p/original/c0tjgU8rq9ZsveoCvlqOnJQ5Aji.jpg','The New York club scene of the 80s and 90s was a world like no other. Into this candy-colored, mirror ball playground stepped Michael Alig, a wannabe from nowhere special. Under the watchful eye of veteran club kid James St. James, Alig quickly rose to the top... and there was no place to go but down.',NULL,NULL,2.9583,5.789,0,6.03333333333333321e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2047,85702,'tt8324422',NULL,'PEN15','PEN15','tv',2019,'https://image.tmdb.org/t/p/w500/9rbyzSTXnrPHJZ1YEOQDK8gnNm8.jpg','https://image.tmdb.org/t/p/original/ymatnu4tnvlYvtqtHFqh4llpmRN.jpg','Middle school as it really happened. Maya Erskine and Anna Konkle star in this adult comedy, playing versions of themselves as thirteen-year-old outcasts in the year 2000, surrounded by actual thirteen-year-olds, where the best day of your life can turn into your worst with the stroke of a gel pen.',NULL,NULL,6.4052,8.312,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2048,28026,'tt0307351',NULL,'Prey for Rock & Roll','Prey for Rock & Roll','movie',2003,'https://image.tmdb.org/t/p/w500/qXXAJjWHcXbfwdlq96nHSTxCVHv.jpg','https://image.tmdb.org/t/p/original/26gr06Z8mgyGFGtFwBOWU87FQbE.jpg','In late 1980s Los Angeles, Jacki and her all-girl punk rock band, Clam Dandy, are trying to make it big. On the verge of turning 40, Jacki decides that if the band''s one last shot at the big time is unsuccessful, she will give up her dreams of stardom.',NULL,NULL,0.997,4.85,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2049,84977,'tt7520794',NULL,'Russian Doll','Russian Doll','tv',2019,'https://image.tmdb.org/t/p/w500/1ju4vQ1EwlIkQxEgWiYmxOs3iBG.jpg','https://image.tmdb.org/t/p/original/5TgMzFqbOEcEo99uhIo8DmiENOx.jpg','Nadia keeps dying and reliving her 36th birthday party. She''s trapped in a surreal time loop -- and staring down the barrel of her own mortality.',NULL,NULL,5.3303,7.355,0,2.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2050,49788,'tt0098347',NULL,'Slaves of New York','Slaves of New York','movie',1989,'https://image.tmdb.org/t/p/w500/dftp493orT07ITbw77UgVlHz4ox.jpg','https://image.tmdb.org/t/p/original/ncwI0OMdoTn4nN54kRhZyB9GBYl.jpg','Meet the denizens of New York City: artists, prostitutes, saints, and seers. All are aspiring toward either fame or oblivion while hoping for love and acceptance. Instead they find high rent, faithless partners, and dead-end careers.',NULL,NULL,1.1587,5.412,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2051,9100,'tt0115963',NULL,'The Craft','The Craft','movie',1996,'https://image.tmdb.org/t/p/w500/8bW2RdRkloYtEPhbQZN4wcdmJP4.jpg','https://image.tmdb.org/t/p/original/yAaAsbossCADVFdiqm8qAhd2gL0.jpg','A Catholic school newcomer falls in with a clique of teen witches who wield their powers against all who dare to cross them -- be they teachers, rivals or meddlesome parents.',NULL,NULL,5.34,6.8,0,2.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2052,27586,'tt1017451',NULL,'The Runaways','The Runaways','movie',2010,'https://image.tmdb.org/t/p/w500/byeTXKg9paqiFQbtfI28FOIhebg.jpg','https://image.tmdb.org/t/p/original/jW0qxSKoyeyPnEov9nZZeiybwt.jpg','Joan Jett and Cherie Currie, two rebellious teenagers from Southern California, become the frontwomen for The Runaways -- the now-legendary group that paved the way for future generations of female rockers. Under the Svengali-like influence of impresario Kim Fowley, the band becomes a huge success.',NULL,NULL,1.9124,6.462,0,1.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2053,32309,'tt0205418',NULL,'The Smokers','The Smokers','movie',2000,'https://image.tmdb.org/t/p/w500/fDbBabdTlhZLjNU15rS9uphoaTR.jpg','https://image.tmdb.org/t/p/original/je0pgUFMNcIMGyjd8G5j2qjo35R.jpg','Three rebellious teenage girls decide to even the score in the battle of the sexes.',NULL,NULL,0.8736,3.5,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2054,11798,'tt0480025',NULL,'This Is England','This Is England','movie',2007,'https://image.tmdb.org/t/p/w500/6ZVx7wLrlgSKxkYC2CRg6Zek0fG.jpg','https://image.tmdb.org/t/p/original/9JpS3EPGWVidpVW6LjTlXJ6jrKT.jpg','A story about a troubled boy growing up in England, set in 1983. He comes across a few skinheads on his way home from school, after a fight. They become his new best friends, even like family. Based on experiences of director Shane Meadows.',NULL,NULL,1.2963,7.476,0,1.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2055,63535,'tt3186130',NULL,'Vinyl','Vinyl','tv',2016,'https://image.tmdb.org/t/p/w500/t8RbNsFIvqHxwAEvgn2WXmJK8TL.jpg','https://image.tmdb.org/t/p/original/zIow3gF75bFVl8VkRdeP08vxaCQ.jpg','In 1970s New York, jaded record exec Richie Finestra tries to resurrect his failing label and fractured personal life while keeping his finger on the pulse of the city''s new sound.',NULL,NULL,4.1541,7.0,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2056,100351,'tt10846104',NULL,'We Are Lady Parts','We Are Lady Parts','tv',2021,'https://image.tmdb.org/t/p/w500/bWqvznpdhncPxVu03QbNmywryhm.jpg','https://image.tmdb.org/t/p/original/h6ID3obPqzkJjhScmtuxaAQykTM.jpg','An anarchic, laugh-out-loud music comedy following a Muslim female punk band called Lady Parts, tracking the highs and lows of the band members as seen through the eyes of Amina Hussein — a geeky doctorate student who is recruited to be their unlikely lead guitarist.',NULL,NULL,2.5804,7.513,0,1.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2057,84880,'tt8201814',NULL,'Now Apocalypse','Now Apocalypse','tv',2019,'https://image.tmdb.org/t/p/w500/hCjy2VzLM4tkUJ62DAFCkdq0LHM.jpg','https://image.tmdb.org/t/p/original/AolLwYWbASLPPNj1MialtpidpBZ.jpg','This surreal, coming-of-age comedy series follows Ulysses and his friends Carly, Ford, and Severine, who are on various quests pursuing love, sex and fame. Between sexual and romantic dating-app adventures, Ulysses grows increasingly troubled as foreboding premonitory dreams make him wonder if some kind of dark and monstrous conspiracy is going on, or if he is just smoking too much weed.',NULL,NULL,5.3817,6.8,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2058,9612,'tt0106598',NULL,'Coneheads','Coneheads','movie',1993,'https://image.tmdb.org/t/p/w500/vlpQnf0rl0FpMjWLS0TNd8Bog2F.jpg','https://image.tmdb.org/t/p/original/rZs0mp3P228o66dg6KljxSmJGJP.jpg','A pair of aliens arrive on Earth to prepare for invasion, but crash instead. With enormous cone-shaped heads, robotlike walks and an appetite for toilet paper, aliens Beldar and Prymatt don''t exactly blend in with the population of Paramus, N.J. But for some reason, everyone believes them when they say they''re from France.',NULL,NULL,3.1606,5.509,0,11.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2059,241554,'tt30444310',NULL,'Murderbot','Murderbot','tv',2025,'https://image.tmdb.org/t/p/w500/mIKfKo2uDk3itzAPYIcSeYr4KtF.jpg','https://image.tmdb.org/t/p/original/if4r7bXrDH50GhNwCo3Bz8F2LOg.jpg','In a high-tech future, a rogue security robot secretly gains free will. To stay hidden, it reluctantly joins a new mission protecting scientists on a dangerous planet... even though it just wants to binge soap operas.',NULL,NULL,9.676,7.321,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2060,450569,'tt6152590',NULL,'Love & Saucers','Love & Saucers','movie',2025,'https://image.tmdb.org/t/p/w500/kXlR3RsQ2sow2gZWNAH8IzLEaWb.jpg','https://image.tmdb.org/t/p/original/l1VwtI3EK45V6LBjrsgK1YOLJ25.jpg','David Huggins, a 72 year-old New Jersey man, claims to have had a lifetime of encounters with otherworldly beings. His experiences include an interspecies romance with an extraterrestrial woman. He’s chronicled it all in his surreal impressionist paintings, but are his experiences dreams, hallucinations, or possibly reality?',NULL,NULL,0.5295,0.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2061,36685,'tt0073629',NULL,'The Rocky Horror Picture Show','The Rocky Horror Picture Show','movie',1975,'https://image.tmdb.org/t/p/w500/3pyE6ZqDbuJi7zrNzzQzcKTWdmN.jpg','https://image.tmdb.org/t/p/original/a53EGF0NzHRGKuRItsrtXBM8FCD.jpg','After getting a flat tire in the middle of nowhere, newly engaged couple Brad and Janet encounter the eerie mansion of the flamboyant, seductive Dr Frank-N-Furter and a variety of eccentric characters. Through elaborate dance and rock music, the mad scientist unveils his latest creation: a perfect, muscular man.',NULL,NULL,4.4229,7.441,0,13.325,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2062,71693,'tt4898282',NULL,'Blood Drive','Blood Drive','tv',2017,'https://image.tmdb.org/t/p/w500/qB9PBQMyKrp8diKGxVpfayKZbgd.jpg','https://image.tmdb.org/t/p/original/x0lANLygpQ4imAkSEihmcAkJ3qK.jpg','Set in a near-dystopian future, a former cop is forced to take part in a death race where the cars run on human blood. You lose a leg and you lose your head.',NULL,NULL,7.261,6.387,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2063,57243,'tt0436992',NULL,'Doctor Who','Doctor Who','tv',2005,'https://image.tmdb.org/t/p/w500/m6G92osOtSeXwjSfL21jZCUOvxe.jpg','https://image.tmdb.org/t/p/original/vcFW09U4834DyFOeRZpsx9x1D3S.jpg','The Doctor is a Time Lord: a 900 year old alien with 2 hearts, part of a gifted civilization who mastered time travel. The Doctor saves planets for a living—more of a hobby actually, and the Doctor''s very, very good at it.',NULL,NULL,126.3459,7.6,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2064,240411,'tt30217403',NULL,'Dan Da Dan','ダンダダン','tv',2024,'https://image.tmdb.org/t/p/w500/6qfZAOEUFIrbUH3JvePclx1nXzz.jpg','https://image.tmdb.org/t/p/original/uNTrRKIOyKYISthoeizghtXPEOK.jpg','In a bet to prove whether ghosts or aliens exist, two high schoolers face terrifying paranormal threats, gain superpowers and maybe even fall in love?!',NULL,NULL,29.6974,8.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2065,7453,'tt0371724',NULL,'The Hitchhiker''s Guide to the Galaxy','The Hitchhiker''s Guide to the Galaxy','movie',2005,'https://image.tmdb.org/t/p/w500/yr9A3KGQlxBh3yW0cmglsr8aMIz.jpg','https://image.tmdb.org/t/p/original/i3IOqOFdAdjw0ebQXkIevybkkNF.jpg','Mere seconds before the Earth is to be demolished by an alien construction crew, Arthur Dent is swept off the planet by his friend Ford Prefect, a researcher penning a new edition of "The Hitchhiker''s Guide to the Galaxy."',NULL,NULL,5.1201,6.69,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2066,67195,'tt5114356',NULL,'Legion','Legion','tv',2017,'https://image.tmdb.org/t/p/w500/xhJtYVTsdXQCIlB5hAXkMCPUG9y.jpg','https://image.tmdb.org/t/p/original/87eP7ITTrOWvkA4EqCuoRdyjzLy.jpg','David Haller, AKA Legion, is a troubled young man who may be more than human. Diagnosed as schizophrenic, David has been in and out of psychiatric hospitals for years. But after a strange encounter with a fellow patient, he’s confronted with the possibility that the voices he hears and the visions he sees might be real.',NULL,NULL,10.011,7.514,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2067,9473,'tt0158983',NULL,'South Park: Bigger, Longer & Uncut','South Park: Bigger, Longer & Uncut','movie',1999,'https://image.tmdb.org/t/p/w500/tS0PedvA2mFO9VCHYwQpaU1K36U.jpg','https://image.tmdb.org/t/p/original/2q3B90h2hZ6xJTvna9CIFDNaIr4.jpg','In this feature film based on the hit animated series, the third graders of South Park sneak into an R-rated film by ultra-vulgar Canadian television personalities Terrance and Phillip, and emerge with expanded vocabularies that leave their parents and teachers scandalized. When outraged Americans try to censor the film, the controversy spirals into a call to wage war on Canada and Terrance and Phillip end up on death row, with the kids their only hope of rescue.',NULL,NULL,4.7988,7.284,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2068,3989,'tt0372588',NULL,'Team America: World Police','Team America: World Police','movie',2004,'https://image.tmdb.org/t/p/w500/m1Q2VFe1DVVbjfu1LDZe7tlp9yb.jpg','https://image.tmdb.org/t/p/original/splQED8WZ5M5OEqDCwZYAAtguZe.jpg','When North Korean ruler Kim Jong-il orchestrates a global terrorist plot, it''s up to the heavily armed, highly specialized Team America unit to stop his dastardly scheme. The group, which has recruited troubled Broadway actor Gary Johnston, not only has to face off against Jong-il, but they must also contend with the Film Actors Guild, a cadre of Hollywood liberals at odds with Team America''s ''policing the world'' tactics.',NULL,NULL,3.2684,6.7,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2069,10661,'tt0960144',NULL,'You Don''t Mess with the Zohan','You Don''t Mess with the Zohan','movie',2008,'https://image.tmdb.org/t/p/w500/gBhLQmpCPoKFMCGsulMbIFzrBID.jpg','https://image.tmdb.org/t/p/original/tfUotS2rLaIu7ieJPDonyDn5EqQ.jpg','An Israeli counterterrorism soldier with a secretly fabulous ambition to become a Manhattan hairstylist. Zohan''s desire runs so deep that he''ll do anything -- including faking his own death and going head-to-head with an Arab cab driver -- to make his dreams come true.',NULL,NULL,5.9407,5.72,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2070,13166,'tt0240515',NULL,'Freddy Got Fingered','Freddy Got Fingered','movie',2001,'https://image.tmdb.org/t/p/w500/gVmSZgxiT7ynyRLsEgg8Xs8ZVWX.jpg','https://image.tmdb.org/t/p/original/uhHYfrbc4BWZbmsAvl951pfvoEu.jpg','Unemployed cartoonist Gord Brody moves back in with his parents Jim and Julie and younger brother Freddy. When his parents demand he leave, he retaliates by spreading rumors that Jim is sexually abusing Freddy.',NULL,NULL,2.1117,4.717,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2071,273477,'tt1727776',NULL,'Scouts Guide to the Zombie Apocalypse','Scouts Guide to the Zombie Apocalypse','movie',2015,'https://image.tmdb.org/t/p/w500/lUKvvSnjFlazrdh6wyHxHrdMknD.jpg','https://image.tmdb.org/t/p/original/ks2C2Ap2W79L5QiVQ7jVp5mmIna.jpg','Three scouts and lifelong friends join forces with one badass cocktail waitress to become the world’s most unlikely team of heroes.  When their peaceful town is ravaged by a zombie invasion, they’ll fight for the badge of a lifetime and put their scouting skills to the test to save mankind from the undead.',NULL,NULL,14.9868,6.58,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2072,19074,'tt1022877',NULL,'Minghags','Minghags','movie',2009,'https://image.tmdb.org/t/p/w500/va4vB78ohkfOnzlctxsV6nTD4QP.jpg','https://image.tmdb.org/t/p/original/kOfBUKErrYmw50AR3MwBbx3TJqA.jpg','A guy who invented this thing called the garbage juicer. You can take garbage and mash it into the trash can, and it has three spouts. You can choose delicious root beer, grapefruit juice or kerosene. This businessman steals the invention from him so the guy spends the whole time trying to dick the businessman over.',NULL,NULL,2.0203,5.5,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2073,983286,'tt16994958',NULL,'Cult Hero','Cult Hero','movie',2022,'https://image.tmdb.org/t/p/w500/fyuR5flaWBWWGYcnYOOrHbIDnHj.jpg','https://image.tmdb.org/t/p/original/hp9LnSzPezzxwiFYn9hMlgkyVGz.jpg','Manager-summoning control freak Kallie Jones attempts to rescue her husband from a "wellness center" with the help of a washed-up expert Cult Buster.',NULL,NULL,1.7712,5.0,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2074,429733,'tt4348012',NULL,'Mayhem','Mayhem','movie',2017,'https://image.tmdb.org/t/p/w500/yFmzgX2YLWnsCi1csyKPNBHPVYB.jpg','https://image.tmdb.org/t/p/original/oQP46uMjvAwnrccweiggJqraDuR.jpg','A virus spreads through an office complex causing white collar workers to act out their worst impulses.',NULL,NULL,1.7599,6.455,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2075,674358,'tt11319074',NULL,'Bad Boy','Bad Boy','movie',2020,'https://image.tmdb.org/t/p/w500/zbeuzetcJN1gnV0tdEgOMvzjvjX.jpg','https://image.tmdb.org/t/p/original/mWFHzbF23ps1vEh56W3xOJetHvA.jpg','The rise and fall of a soccer club owner, discovering the harsh reality of the sport, often connected with crime and fraud.',NULL,NULL,0.3194,4.8,0,7.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2076,74306,'tt1912398',NULL,'God Bless America','God Bless America','movie',2012,'https://image.tmdb.org/t/p/w500/jEyiGve8BLOCvi8R2tL8H52aLp4.jpg','https://image.tmdb.org/t/p/original/55A2d6rWj0SYb52xKzx6DweiuEM.jpg','Fed up with the cruelty and stupidity of American culture, an unlikely duo goes on a killing spree, killing reality TV stars, bigots and others they find repugnant.',NULL,NULL,1.6618,7.0,0,10.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2077,12177,'tt0811138',NULL,'The Love Guru','The Love Guru','movie',2008,'https://image.tmdb.org/t/p/w500/sp8AV64ftAZCT9uWfgbCb3olGDW.jpg','https://image.tmdb.org/t/p/original/9E7RHTs5hyVCwZ8vmw0UtrcwfFD.jpg','Born in America and raised in an Indian ashram, Pitka returns to his native land to seek his fortune as a spiritualist and self-help expert. His skills are put to the test when he must get a brokenhearted hockey player''s marriage back on track in time for the man to help his team win the Stanley Cup.',NULL,NULL,2.3678,4.073,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2078,11639,'tt0083791',NULL,'The Dark Crystal','The Dark Crystal','movie',1982,'https://image.tmdb.org/t/p/w500/fZPxRaa6gvCyGCh9Xk5kyPqz7fp.jpg','https://image.tmdb.org/t/p/original/dlIkuHYT977POygUBGZyOszFUB.jpg','On another planet in the distant past, a Gelfling embarks on a quest to find the missing shard of a magical crystal and restore order to his world, before the grotesque race of Skeksis find and use the crystal for evil.',NULL,NULL,3.7278,7.1,0,11.535,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2079,38319,'tt1240982',NULL,'Your Highness','Your Highness','movie',2011,'https://image.tmdb.org/t/p/w500/zw1tEKhR1ncGGtuYkkf30GYlvYQ.jpg','https://image.tmdb.org/t/p/original/7P7aZ9ozRWlsruPVaTB2dLXI7aF.jpg','A fantasy movie about an arrogant, lazy prince and his more heroic brother who must complete a quest in order to save their father''s kingdom.',NULL,NULL,2.8413,5.327,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2080,104595,'tt0084678',NULL,'Portrait in Crystal','水晶人','movie',1983,'https://image.tmdb.org/t/p/w500/1qw9fWACKGoRhcCD9aqNuhEL1JJ.jpg','https://image.tmdb.org/t/p/original/dvBhrxk19ENMoC1kXorgX1eZaAa.jpg','When a naive sculptor spills blood on his newest statue, he awakens a mass-murdering crystalline spirit in the underworld. Along with his trusted companion Fatty, he backflips his way through mystical realms to uncover who is trapping souls in his statues..',NULL,NULL,0.6602,7.2,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2081,123,'tt0077869',NULL,'The Lord of the Rings','The Lord of the Rings','movie',1978,'https://image.tmdb.org/t/p/w500/liW0mjvTyLs7UCumaHhx3PpU4VT.jpg','https://image.tmdb.org/t/p/original/TXSxV23MWYkezZ3219gtgcSX6n.jpg','Young Hobbit Frodo Baggins is thrown into an amazing adventure when he''s tasked with destroying the One Ring, created by the dark lord Sauron. Frodo must travel in a small fellowship of nine warriors and accomplices. But it won''t be an easy journey for the Fellowship of the Ring, on the ultimate quest to rid Middle-earth of evil.',NULL,NULL,4.8329,6.593,0,11.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2082,41077,'tt0083931',NULL,'Son of the White Mare','Fehérlófia','movie',1981,'https://image.tmdb.org/t/p/w500/cYYYIfBFG5nszjDk5xea4MQHyDS.jpg','https://image.tmdb.org/t/p/original/nV5bIMguQKNVmuO9NGvZcInjcul.jpg','A horse goddess gives birth to three powerful brothers who set out into the Underworld to save three princesses from three evil dragons and reclaim their ancestors'' lost kingdom.',NULL,NULL,3.1885,7.6,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2083,11704,'tt0084649',NULL,'The Secret of NIMH','The Secret of NIMH','movie',1982,'https://image.tmdb.org/t/p/w500/prNrnOKlkV9wl5Sl3zwHu1f3t2z.jpg','https://image.tmdb.org/t/p/original/4Q0C49l6KkRbnVlE3N86IljtAXH.jpg','A widowed field mouse must move her family -- including an ailing son -- to escape a farmer''s plow. Aided by a crow and a pack of superintelligent, escaped lab rats, the brave mother struggles to transplant her home to firmer ground.',NULL,NULL,3.3354,7.443,0,1.23499999999999978e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2084,32147,'tt0090065',NULL,'Starchaser: The Legend of Orin','Starchaser: The Legend of Orin','movie',1985,'https://image.tmdb.org/t/p/w500/zC5OU1G1eeIN1xTnXPWibolYrf6.jpg','https://image.tmdb.org/t/p/original/mLPqyFYnVnMqDtVrelD1JITbo6v.jpg','Set on the subterranean Mine-World, a band of human worker are treated like slaves under the power of the evil overlord Zygon until one, Orin, unearths the hilt of a mythical sword that only he can master. Escaping the planet, he runs into the rogue smuggler Dagg and a pair of helpful droids and the princess, who all team up to return to the Mine-World with a plan to defeat Zygon and free Orin''s enslaved people.',NULL,NULL,0.8702,6.282,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2085,34584,'tt0088323',NULL,'The NeverEnding Story','Die unendliche Geschichte','movie',1984,'https://image.tmdb.org/t/p/w500/ddYCa91iDXfJCxaqSYzwi2fjfnl.jpg','https://image.tmdb.org/t/p/original/rKmOe5pb5a6P1HmQAzpRw20gORp.jpg','While hiding from bullies in his school''s attic, a young boy discovers the extraordinary land of Fantasia, through a magical book called The Neverending Story. The book tells the tale of Atreyu, a young warrior who, with the help of a luck dragon named Falkor, must save Fantasia from the destruction of The Nothing.',NULL,NULL,4.8744,7.223,0,1.26766666666666658e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2086,25319,'tt0058333',NULL,'The Masque of the Red Death','The Masque of the Red Death','movie',1964,'https://image.tmdb.org/t/p/w500/sSYceyGZrWskWDsn3MHtipJ1wFM.jpg','https://image.tmdb.org/t/p/original/oHVfPPSlii66NTQpOrRurivfrDW.jpg','A European prince terrorizes the local peasantry while using his castle as a refuge against the "Red Death" plague that stalks the land.',NULL,NULL,1.4948,6.622,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2087,16220,'tt0076929',NULL,'Wizards','Wizards','movie',1977,'https://image.tmdb.org/t/p/w500/jeAxoYepnVirGe0H7pmwviSZYul.jpg','https://image.tmdb.org/t/p/original/eTzdSb3YCFZvyzicBalPJ9O0zzJ.jpg','After the death of his mother, evil mutant wizard Blackwolf discovers long-lost military technologies. Full of ego and ambition, Blackwolf claims his mother''s throne, assembles an army, and sets out to brainwash and conquer Earth. Meanwhile, Blackwolf''s gentle twin brother, the bearded sage Avatar, calls upon his own magical abilities to foil Blackwolf''s plans for world domination — even if it means eliminating his own flesh and blood.',NULL,NULL,1.9988,6.19,0,10.77,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2088,55613,'tt0103926',NULL,'Careful','Careful','movie',1992,'https://image.tmdb.org/t/p/w500/qolQ7M5hpbBwcvpMpfeSMyU64rs.jpg','https://image.tmdb.org/t/p/original/zbnNk0dY8Pj3rlqrT2KDTh6ZQlr.jpg','The mountain-village passions of a German widow and her sons unfold in the style of a 1920s expressionist movie.',NULL,NULL,0.5353,5.967,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2089,13241,'tt1093842',NULL,'My Winnipeg','My Winnipeg','movie',2008,'https://image.tmdb.org/t/p/w500/nytcKOHE4CF7OlSej4zpIVEbCy7.jpg','https://image.tmdb.org/t/p/original/s5e27x7tREwWQFQLcqFr8MCb8Fl.jpg','The geographical dead center of North America and the beloved birthplace of Guy Maddin, Winnipeg, is the frosty and mysterious star of Maddin’s film. Fact, fantasy and memory are woven seamlessly together in this work, conjuring a city as delightful as it is fearsome.',NULL,NULL,0.5873,6.9,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2090,108312,'tt0091613',NULL,'Native Son','Native Son','movie',1986,'https://image.tmdb.org/t/p/w500/5HNYDlnI145RJWA5BWeomtVZ4JM.jpg','https://image.tmdb.org/t/p/original/2SRb0uB2U7paW6xVThSiBiNqdOo.jpg','In 1940s Chicago, a young black man takes a job as a chauffeur to a white family, which takes a turn for the worse when he accidentally kills the teenage daughter of the couple and then tries to cover it up.',NULL,NULL,1.0873,5.25,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2091,82695,'tt1707386',NULL,'Les Misérables','Les Misérables','movie',2012,'https://image.tmdb.org/t/p/w500/6CuzBs2Lb8At7qQr64mLXg2RYRb.jpg','https://image.tmdb.org/t/p/original/bsG8LkZx1ijrcf3fP6AvBlGTxkX.jpg','An adaptation of the successful stage musical based on Victor Hugo''s classic novel set in 19th-century France. Jean Valjean, a man imprisoned for stealing bread, must flee a relentless policeman named Javert. The pursuit consumes both men''s lives, and soon Valjean finds himself in the midst of the student revolutions in France.',NULL,NULL,8.4431,7.303,0,9.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2092,203833,'tt0816442',NULL,'The Book Thief','The Book Thief','movie',2013,'https://image.tmdb.org/t/p/w500/wj4U5sMLcJMa3WR9CpRR9e2sdgZ.jpg','https://image.tmdb.org/t/p/original/arFPEDEW4PzPaMBXgTPzJlumfGw.jpg','While subjected to the horrors of WWII Germany, young Liesel finds solace by stealing books and sharing them with others. Under the stairs in her home, a Jewish refugee is being sheltered by her adoptive parents.',NULL,NULL,3.6164,7.5,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2093,590,'tt0274558',NULL,'The Hours','The Hours','movie',2002,'https://image.tmdb.org/t/p/w500/4myDtowDJQPQnkEDB1IWGtJR1Fo.jpg','https://image.tmdb.org/t/p/original/3oHFSEr4TRnsyTxWGrmY8Xi2FrR.jpg','The story of three women searching for more potent, meaningful lives. Each is alive at a different time and place, all are linked by their yearnings and their fears. Their stories intertwine, and finally come together in a surprising, transcendent moment of shared recognition.',NULL,NULL,4.001,7.254,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2094,10937,'tt0092618',NULL,'Barfly','Barfly','movie',1987,'https://image.tmdb.org/t/p/w500/uAsAVy7yoMZ2r5ZBQQXw4PKX3JY.jpg','https://image.tmdb.org/t/p/original/whKhDehBYjOlJboo3by0JTSQsjv.jpg','Downtrodden writer Henry and distressed goddess Wanda aren''t exactly husband and wife: they''re wedded to their bar stools. But, they like each other''s company—and Barfly captures their giddy, gin-soaked attempts to make a go of life on the skids.',NULL,NULL,3.158,6.875,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2095,1102493,'tt27196021',NULL,'Small Things Like These','Small Things Like These','movie',2024,'https://image.tmdb.org/t/p/w500/tRDGxhf1U9ITPu6MlNzUTFYId1c.jpg','https://image.tmdb.org/t/p/original/rtpFIgy1YYw3kx7PCyNhi6xmEFb.jpg','In 1985, while working as a coal merchant to support his family, Bill Furlong discovers disturbing secrets kept by the local convent and uncovers truths of his own; forcing him to confront his past and the complicit silence of a small Irish town controlled by the Catholic Church.',NULL,NULL,2.6715,6.651,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2096,25566,'tt0082970',NULL,'Ragtime','Ragtime','movie',1981,'https://image.tmdb.org/t/p/w500/vRjyakxRrMfj6sgyUJte9mVI1D9.jpg','https://image.tmdb.org/t/p/original/affAxDjzMZnQvXmq2zBrsjTxkRI.jpg','A young black pianist becomes embroiled in the lives of an upper-class white family set among the racial tensions, infidelity, violence, and other nostalgic events in early 1900s New York City.',NULL,NULL,1.1864,7.013,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2097,778,'tt0046487',NULL,'Monsieur Hulot''s Holiday','Les vacances de Monsieur Hulot','movie',1953,'https://image.tmdb.org/t/p/w500/r4F4tsU0Ajeh9ZYUkWOJSYmioj7.jpg','https://image.tmdb.org/t/p/original/dK6s1EMpMcUwBHpiYVMBiTdgdvy.jpg','Monsieur Hulot, Jacques Tati’s endearing clown, takes a holiday at a seaside resort, where his presence provokes one catastrophe after another. Tati’s masterpiece of gentle slapstick is a series of effortlessly well-choreographed sight gags involving dogs, boats, and firecrackers; it was the first entry in the Hulot series and the film that launched its maker to international stardom.',NULL,NULL,1.7244,6.933,0,11.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2098,5967,'tt0058450',NULL,'The Umbrellas of Cherbourg','Les Parapluies de Cherbourg','movie',1964,'https://image.tmdb.org/t/p/w500/tAgTf64XKK5ir7w5C7dnB53jWWG.jpg','https://image.tmdb.org/t/p/original/m1Gei9O5GfLoJHQjBaxWBSkXX2y.jpg','This simple romantic tragedy begins in 1957. Guy Foucher, a 20-year-old French auto mechanic, has fallen in love with 17-year-old Geneviève Emery, an employee in her widowed mother''s chic but financially embattled umbrella shop. On the evening before Guy is to leave for a two-year tour of combat in Algeria, he and Geneviève make love. She becomes pregnant and must choose between waiting for Guy''s return or accepting an offer of marriage from a wealthy diamond merchant.',NULL,NULL,2.7146,7.4,0,1.30966666666666675e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2099,371645,'tt4698684',NULL,'Hunt for the Wilderpeople','Hunt for the Wilderpeople','movie',2016,'https://image.tmdb.org/t/p/w500/hkmz9rxgcweizXNElozGeKwmAJE.jpg','https://image.tmdb.org/t/p/original/ixpUtvrZNwk6LBObXaNH8fh4FYf.jpg','Ricky is a defiant young city kid who finds himself on the run with his cantankerous foster uncle in the wild New Zealand bush. A national manhunt ensues, and the two are forced to put aside their differences and work together to survive.',NULL,NULL,7.0201,7.644,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2100,556678,'tt9214832',NULL,'Emma.','Emma.','movie',2020,'https://image.tmdb.org/t/p/w500/uHpHzbHLSsVmAuuGuQSpyVDZmDc.jpg','https://image.tmdb.org/t/p/original/42gqGeyXh4caHP19Tqf8DMRgc7r.jpg','In 1800s England, a well-meaning but selfish young woman meddles in the love lives of her friends.',NULL,NULL,4.3142,7.009,0,11.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2101,2433,'tt0062873',NULL,'The Young Girls of Rochefort','Les Demoiselles de Rochefort','movie',1967,'https://image.tmdb.org/t/p/w500/jtxhyGaYhurH6KsjvP1jV3dDypz.jpg','https://image.tmdb.org/t/p/original/8m7qOKlsdnxt4335vpFzpffuIVu.jpg','In the seaside town of Rochefort, twin sisters Delphine and Solange dream of love and artistic fulfillment beyond their quiet lives. As sailors, artists, musicians, and chance visitors pass through town during a weekend fair, a web of near-misses and romantic longing brings ideal partners tantalizingly close—without their realizing it.',NULL,NULL,2.5498,7.7,0,12.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2102,11000,'tt0115685',NULL,'The Birdcage','The Birdcage','movie',1996,'https://image.tmdb.org/t/p/w500/4IpC35BoA5aRO0Q1DpFGJ8iKKYq.jpg','https://image.tmdb.org/t/p/original/yNOtXSNep1BLnfZ0yhLejm1TULi.jpg','A gay cabaret owner and his drag queen partner agree to put up a false heterosexual front so that their son can introduce them to his fiancée''s conservative parents.',NULL,NULL,4.0156,7.049,0,1.11200000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2103,515001,'tt2584384',NULL,'Jojo Rabbit','Jojo Rabbit','movie',2019,'https://image.tmdb.org/t/p/w500/1mqL7VG4Ix8wmxwypmCA1HTHBky.jpg','https://image.tmdb.org/t/p/original/lTyikzfGgRX5ZqIfVeT26APYfRL.jpg','Jojo, a lonely German boy during World War II has his world shaken when he learns that his single mother is hiding a Jewish girl in their home. Influenced by a buffoonish imaginary version of Adolf Hitler, he begins to question his beliefs and confront the conflict between propaganda and his own humanity.',NULL,NULL,6.4828,7.981,0,1.30133333333333336e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2104,346698,'tt1517268',NULL,'Barbie','Barbie','movie',2023,'https://image.tmdb.org/t/p/w500/iuFNMS8U5cb6xfzi51Dbkovj7vM.jpg','https://image.tmdb.org/t/p/original/3N5QNUqS76GFYNoEayfkkJyAyTN.jpg','Barbie and Ken are having the time of their lives in the colorful and seemingly perfect world of Barbie Land. However, when they get a chance to go to the real world, they soon discover the joys and perils of living among humans.',NULL,NULL,19.8825,6.9,0,11.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2105,164,'tt0054698',NULL,'Breakfast at Tiffany''s','Breakfast at Tiffany''s','movie',1961,'https://image.tmdb.org/t/p/w500/79xm4gXw4l7A5D0XukUOJRocFYQ.jpg','https://image.tmdb.org/t/p/original/jXZ2tyJl44yKvh22I6ooQwU5rFM.jpg','Holly Golightly is an eccentric New York City playgirl determined to marry a Brazilian millionaire. But when young writer Paul Varjak moves into her apartment building, her past threatens to get in their way.',NULL,NULL,7.7524,7.6,0,11.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2106,759,'tt0045810',NULL,'Gentlemen Prefer Blondes','Gentlemen Prefer Blondes','movie',1953,'https://image.tmdb.org/t/p/w500/fDozhst5HVJJcd3BM8ZOsKniO7Q.jpg','https://image.tmdb.org/t/p/original/2clBxxclZJ4OK1xzhmCCXHEfy3r.jpg','Lorelei Lee is a beautiful showgirl engaged to be married to the wealthy Gus Esmond, much to the disapproval of Gus'' rich father, Esmond Sr., who thinks that Lorelei is just after his money. When Lorelei goes on a cruise accompanied only by her best friend, Dorothy Shaw, Esmond Sr. hires Ernie Malone, a private detective, to follow her and report any questionable behavior that would disqualify her from the marriage.',NULL,NULL,3.3492,7.332,0,11.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2107,9353,'tt0457510',NULL,'Nacho Libre','Nacho Libre','movie',2006,'https://image.tmdb.org/t/p/w500/kh7B91bMl2lZ0mH9WhPfaNUIEQH.jpg','https://image.tmdb.org/t/p/original/nNCleqiADKVMKWDC5G7hjYcVCmv.jpg','Ignacio, a disrespected cook at a Mexican monastery, can barely afford to feed the orphans who live there. Inspired by a local wrestling hero, he decides to moonlight as the not-so-famous Luchador "Nacho Libre" to earn money for the monastery -- not to mention the admiration of beautiful nun Sister Encarnación.',NULL,NULL,4.621,6.524,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2108,42689,'tt0061398',NULL,'Berserk!','Berserk!','movie',1967,'https://image.tmdb.org/t/p/w500/gGWC7AncEsAxNv01yXY2xlr8gZz.jpg','https://image.tmdb.org/t/p/original/cMpnczREJPgDAE8HDvnfLqtBre5.jpg','A lady ringmaster milks the publicity from a string of murders.',NULL,NULL,1.0136,5.681,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2109,12437,'tt0834001',NULL,'Underworld: Rise of the Lycans','Underworld: Rise of the Lycans','movie',2009,'https://image.tmdb.org/t/p/w500/yW9gF7rGn8EoV8B8rxOx1xjxVZf.jpg','https://image.tmdb.org/t/p/original/rT7Kn7aT5owqpPSRSbxUmqRNz4w.jpg','A prequel to the first two Underworld films, this fantasy explains the origins of the feud between the Vampires and the Lycans. Aided by his secret love, Sonja, courageous Lucian leads the Lycans in battle against brutal Vampire king Viktor. Determined to break the king''s enslavement of his people, Lucian faces off against the Death Dealer army in a bid for Lycan independence.',NULL,NULL,5.9937,6.539,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2110,152603,'tt1714915',NULL,'Only Lovers Left Alive','Only Lovers Left Alive','movie',2013,'https://image.tmdb.org/t/p/w500/6siwECwpRbNX70ybF8iqZqnspGP.jpg','https://image.tmdb.org/t/p/original/dwFvtGZ6fUsU9YRWHXbAOXwNQkq.jpg','A depressed musician reunites with his lover. However, their romance, already played over several centuries, is disrupted by the arrival of her uncontrollable younger sister.',NULL,NULL,3.3712,7.204,0,1.51333333333333328e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2111,246741,'tt3416742',NULL,'What We Do in the Shadows','What We Do in the Shadows','movie',2014,'https://image.tmdb.org/t/p/w500/a2rD3i3DBMeYbA34rBv6z3B9S3a.jpg','https://image.tmdb.org/t/p/original/utjThRtcnsj0GrDwNudjGdfmHfq.jpg','Vampire housemates try to cope with the complexities of modern life and show a newly turned hipster some of the perks of being undead.',NULL,NULL,3.9505,7.547,0,11.5,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2112,1417,'tt0457430',NULL,'Pan''s Labyrinth','El laberinto del fauno','movie',2006,'https://image.tmdb.org/t/p/w500/z7xXihu5wHuSMWymq5VAulPVuvg.jpg','https://image.tmdb.org/t/p/original/6G6nqSW9S7EHA9HrYl0Z8uo2H7f.jpg','In post–civil war Spain, 10-year-old Ofelia moves with her pregnant mother to live under the control of her cruel stepfather. Drawn into a mysterious labyrinth, she meets a faun who reveals that she may be a lost princess from an underground kingdom. To return to her true father, she must complete a series of surreal and perilous tasks that blur the line between reality and fantasy.',NULL,NULL,12.687,7.766,0,19.631,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2113,11774,'tt0339291',NULL,'Lemony Snicket''s A Series of Unfortunate Events','Lemony Snicket''s A Series of Unfortunate Events','movie',2004,'https://image.tmdb.org/t/p/w500/76Xi8z7Whv5WFIdfzzvC5tKSicd.jpg','https://image.tmdb.org/t/p/original/i0M3a8Z2hfj5Oj4msArajhLjGvV.jpg','Three wealthy children''s parents are killed in a fire. When they are sent to a distant relative, they find out that he is plotting to kill them and seize their fortune.',NULL,NULL,4.2609,6.822,0,12.7,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2114,1062722,'tt1312221',NULL,'Frankenstein','Frankenstein','movie',2025,'https://image.tmdb.org/t/p/w500/g4JtvGlQO7DByTI6frUobqvSL3R.jpg','https://image.tmdb.org/t/p/original/hpXBJxLD2SEf8l2CspmSeiHrBKX.jpg','Dr. Victor Frankenstein, a brilliant but egotistical scientist, brings a creature to life in a monstrous experiment that ultimately leads to the undoing of both the creator and his tragic creation.',NULL,NULL,19.8012,7.627,0,12.3125,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2115,1138194,'tt28015403',NULL,'Heretic','Heretic','movie',2024,'https://image.tmdb.org/t/p/w500/fr96XzlzsONrQrGfdLMiwtQjott.jpg','https://image.tmdb.org/t/p/original/ag66gJCiZ06q1GSJuQlhGLi3Udx.jpg','Two young missionaries are forced to prove their faith when they knock on the wrong door and are greeted by a diabolical Mr. Reed, becoming ensnared in his deadly game of cat-and-mouse.',NULL,NULL,8.2414,6.976,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2116,13446,'tt0094336',NULL,'Withnail & I','Withnail & I','movie',1987,'https://image.tmdb.org/t/p/w500/i18cIp8A10A2JgByrfA9oIC9299.jpg','https://image.tmdb.org/t/p/original/bOgKCymrdPHPHozhRBNr9XhVD87.jpg','Two out-of-work actors -- the anxious, luckless Marwood and his acerbic, alcoholic friend, Withnail -- spend their days drifting between their squalid flat, the unemployment office and the pub. When they take a holiday "by mistake" at the country house of Withnail''s flamboyantly gay uncle, Monty, they encounter the unpleasant side of the English countryside: tedium, terrifying locals and torrential rain.',NULL,NULL,4.2289,7.2,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2117,9637,'tt0267913',NULL,'Scooby-Doo','Scooby-Doo','movie',2002,'https://image.tmdb.org/t/p/w500/mTAiBJGg8mqEfnYHHbi37ZoRSZm.jpg','https://image.tmdb.org/t/p/original/1RAxtBxslR4OZCZC1vxIRUxjR7a.jpg','When the Mystery Inc. gang is invited to Spooky Island, a popular amusement park, they soon discover that the attractions aren''t the only things that are spooky. Strange things are happening, and it''s up to Scooby, Shaggy, Fred, Daphne, and Velma to uncover the truth behind the mysterious happenings.',NULL,NULL,7.1309,6.109,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2118,11559,'tt0410764',NULL,'Tideland','Tideland','movie',2005,'https://image.tmdb.org/t/p/w500/mjCRfmxg7awp5kVIM1lHR0d7S4A.jpg','https://image.tmdb.org/t/p/original/w4bRVvptwS5i2GJpvQkiPhlZqF0.jpg','Because of the actions of her irresponsible parents, a young girl is left alone on a decrepit country estate and survives inside her fantastic imagination.',NULL,NULL,1.392,6.532,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2119,1427,'tt0396171',NULL,'Perfume: The Story of a Murderer','Perfume: The Story of a Murderer','movie',2006,'https://image.tmdb.org/t/p/w500/2wrFrUej8ri5EpjgIkjKTAnr686.jpg','https://image.tmdb.org/t/p/original/kvdy0Ijjo2r9qsnWV4Dzx07qwnc.jpg','Jean-Baptiste Grenouille, born in the stench of 18th century Paris, develops a superior olfactory sense, which he uses to create the world''s finest perfumes. However, his work takes a dark turn as he tries to preserve scents in the search for the ultimate perfume.',NULL,NULL,13.2069,7.371,0,9.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2120,1278,'tt0309987',NULL,'The Dreamers','The Dreamers','movie',2003,'https://image.tmdb.org/t/p/w500/gBb7GGaFYPu7nEUYvC8G4LaJJN1.jpg','https://image.tmdb.org/t/p/original/vaRCS4CCFXcWz1j9GKd6rGLsQQ2.jpg','When Isabelle and Theo invite Matthew to stay with them, what begins as a casual friendship ripens into a sensual voyage of discovery and desire in which nothing is off limits and everything is possible.',NULL,NULL,10.4472,7.181,0,12.775,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2121,2907,'tt0101272',NULL,'The Addams Family','The Addams Family','movie',1991,'https://image.tmdb.org/t/p/w500/qFf8anju5f2epI0my8RdwwIXFIP.jpg','https://image.tmdb.org/t/p/original/7OxGhxUYAdtuike29VMzEFxJx7y.jpg','When a man claiming to be long-lost Uncle Fester reappears after 25 years lost, the family plans a celebration to wake the dead. But the kids barely have time to warm up the electric chair before Morticia begins to suspect Fester is fraud when he can''t recall any of the details of Fester''s life.',NULL,NULL,7.4513,7.073,0,9.65,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2122,30923,'tt0164993',NULL,'Alice in Wonderland','Alice in Wonderland','movie',1999,'https://image.tmdb.org/t/p/w500/kpXmXjqeyuSYCtNuGMytWQLdKX.jpg','https://image.tmdb.org/t/p/original/mbFHUlhWU53VG8VLE5jAcQQVIUR.jpg','Alice follows a white rabbit down a rabbit-hole into a whimsical Wonderland, where she meets characters like the delightful Cheshire Cat, the clumsy White Knight, a rude caterpillar, and the hot-tempered Queen of Hearts and can grow ten feet tall or shrink to three inches. But will she ever be able to return home?',NULL,NULL,2.8092,6.225,0,7.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2123,12155,'tt1014759',NULL,'Alice in Wonderland','Alice in Wonderland','movie',2010,'https://image.tmdb.org/t/p/w500/o0kre9wRCZz3jjSjaru7QU0UtFz.jpg','https://image.tmdb.org/t/p/original/ocOWbTzHcJVTw9Tz173KPeskDOP.jpg','Alice, now 19 years old, returns to the whimsical world she first entered as a child and embarks on a journey to discover her true destiny.',NULL,NULL,14.625,6.644,0,12.424,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2124,102780,'tt1531901',NULL,'Byzantium','Byzantium','movie',2013,'https://image.tmdb.org/t/p/w500/kFkfRnXz6Rk9tAKgUznJH1FURQ6.jpg','https://image.tmdb.org/t/p/original/65Hu40ajfe7PTB5W0pYBSWTfwTq.jpg','Residents of a coastal town learn, with deadly consequences, the secret shared by the two mysterious women who have sought refuge at a local boarding house, the Byzantium.',NULL,NULL,1.9882,6.291,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2125,NULL,NULL,9630,'Fallout 4','Fallout 4','game',2015,'https://images.igdb.com/igdb/image/upload/t_cover_big/co1yc6.jpg',NULL,'Bethesda Game Studios welcome you to the world of Fallout 4, their most ambitious game ever, and the next generation of open-world gaming. As the sole survivor of Vault 111, you enter a world destroyed by nuclear war. Every second is a fight for survival, and every choice is yours. Only you can rebuild and determine the fate of the Wasteland. Welcome home.','https://www.igdb.com/games/fallout-4','["Xbox Series X|S", "PlayStation 4", "PC (Microsoft Windows)", "PlayStation 5", "Xbox One"]',NULL,NULL,0,5.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2126,NULL,NULL,12482,'Layers of Fear','Layers of Fear','game',2016,'https://images.igdb.com/igdb/image/upload/t_cover_big/co1nhw.jpg',NULL,'Layers of Fear is a psychedelic horror that will keep you on-edge for the reminder of the game. Delve deep into the mind of an insane painter and discover the secret of his madness, as you walk through a constantly shifting house.

Heavily inspired by the masterpiece paintings from the past centuries, and the architecture and décor from the XIX century. Layers of Fear is a truly unique experience, where each move of the camera can change your surroundings.

Layer by layer uncover the visions, fears and horrors that entwine the protagonist and finish the masterpiece he has strived so long to create.','https://www.igdb.com/games/layers-of-fear','["PlayStation 4", "Linux", "PC (Microsoft Windows)", "iOS", "Mac", "Xbox One"]',NULL,NULL,0,4.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2127,NULL,NULL,968,'Resident Evil Code: Veronica','Resident Evil Code: Veronica','game',2000,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2vzn.jpg',NULL,'Resident Evil Code: Veronica is the fourth video game in Capcom''s Resident Evil survival horror series. The game continues the survival horror gameplay of its predecessors: the protagonist explores the surroundings, fighting monsters and solving puzzles. However, it is the first game in the series to do away with pre-rendered backgrounds using a fully polygonal 3D engine instead, which allows for features such as real-time lighting and camera movement. Still, such movements are only used sparingly, and the use of perspective is mostly unchanged from earlier installments: the camera automatically switches to different static angles showing protagonists, monsters and rooms from different spooky viewpoints.','https://www.igdb.com/games/resident-evil-code-veronica','["Dreamcast"]',NULL,NULL,0,3.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2128,149871,'tt2576852',NULL,'The Tale of The Princess Kaguya','かぐや姫の物語','movie',2013,'https://image.tmdb.org/t/p/w500/cQidJuA546OSSXKWXoiCeINDxuj.jpg','https://image.tmdb.org/t/p/original/lMaWlYThCSnsmW3usxWTpSuyZp1.jpg','Found inside a shining stalk of bamboo by an old bamboo cutter and his wife, a tiny girl grows rapidly into an exquisite young lady. The mysterious young princess enthrals all who encounter her. But, ultimately, she must confront her fate.',NULL,NULL,3.7792,8.091,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2129,215400,'tt0480465',NULL,'The Glass Harmonica','Стеклянная гармоника','movie',1968,'https://image.tmdb.org/t/p/w500/al7Zi1roENbIBVF0ICv18g51r8R.jpg','https://image.tmdb.org/t/p/original/vVytniJnRmPII46TbdGaGWqecCG.jpg','A craftsman builds a glass harmonica that enlightens him. He travels to a town where the people are obsessed with money. A bureaucrat smashes the glass harmonica which leads to chaos and eventually to social reform.',NULL,NULL,1.0297,6.048,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2130,953768,NULL,NULL,'Sindbad','Sindbad','movie',2001,'https://image.tmdb.org/t/p/w500/6ZVkcTak3WkqJNfUwC0b4DsTwby.jpg',NULL,'',NULL,NULL,0.7739,0.0,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2131,36819,'tt0081633',NULL,'Time Bandits','Time Bandits','movie',1981,'https://image.tmdb.org/t/p/w500/4VZtpwdhHQSa4LUkvujyGAHb1hG.jpg','https://image.tmdb.org/t/p/original/qKERrt3UU1ml8Q9zdsLPpoQ5r3.jpg','Young history buff Kevin can scarcely believe it when six dwarfs emerge from his closet one night. Former employees of the Supreme Being, they''ve purloined a map charting all of the holes in the fabric of time and are using it to steal treasures from different historical eras. Taking Kevin with them, they variously drop in on Napoleon, Robin Hood and King Agamemnon before the Supreme Being catches up with them.',NULL,NULL,2.5996,6.6,0,11.545,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2132,1284120,'tt29344903',NULL,'The Ugly Stepsister','Den stygge stesøsteren','movie',2025,'https://image.tmdb.org/t/p/w500/rayAREIKtSinuov10GvrZHyXfXH.jpg','https://image.tmdb.org/t/p/original/kG8bBajeSTUxJGmS47WujcraZUk.jpg','In a fairy-tale kingdom where beauty is a brutal business, Elvira battles to compete with her incredibly beautiful stepsister, Agnes, and she will go to any length to catch the Prince’s eye.',NULL,NULL,10.2204,7.306,0,5.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2133,150689,'tt1661199',NULL,'Cinderella','Cinderella','movie',2015,'https://image.tmdb.org/t/p/w500/j91LJmcWo16CArFOoapsz84bwxb.jpg','https://image.tmdb.org/t/p/original/q7vmCCmyiHnuKGMzHZlr0fD44b9.jpg','When her father unexpectedly passes away, young Ella finds herself at the mercy of her cruel stepmother and her daughters. Never one to give up hope, Ella''s fortunes begin to change after meeting a dashing stranger in the woods.',NULL,NULL,11.8341,6.8,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2134,28032,'tt0111419',NULL,'Thumbelina','Thumbelina','movie',1994,'https://image.tmdb.org/t/p/w500/eBvSSfwAKgcjF4eyaeNSzTCpfaF.jpg','https://image.tmdb.org/t/p/original/jhxmxSNBNCAKtHeJnJhWpkOOI7d.jpg','Born of a flower and growing to only a couple of inches tall, poor Thumbelina is worried she''ll never meet someone her own size, until she happens to catch the eye of Prince Cornelius of the Fairies. Just as soon as she finds love, however, it''s torn away when she''s kidnapped by Ms. Toad. Now Thumbelina has to escape Ms. Toad''s grasp and search for Prince Cornelius. Luckily, there''s a whole city of animals willing to help.',NULL,NULL,5.5634,6.5,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2135,204436,'tt1181840',NULL,'Jack and the Cuckoo-Clock Heart','Jack et la mécanique du cœur','movie',2014,'https://image.tmdb.org/t/p/w500/ZSrU2mvlzM5Jr30XtKCU1fziIj.jpg','https://image.tmdb.org/t/p/original/rjXK74vrvmFMN0vuFw3TViZ18Ha.jpg','Jack is born with his heart frozen solid on the coldest day in history. A wise midwife saves him by replacing it with a cuckoo clock. Now Jack must abide by three rules to keep his mechanical heart safe: never touch the clock''s hands, master his anger, and never fall in love. He tries his best, but when he meets a girl named Acacia he falls in love, threatening the delicate balance of his artificial heart.',NULL,NULL,1.8413,7.225,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2136,16306,'tt0070544',NULL,'Fantastic Planet','La Planète sauvage','movie',1973,'https://image.tmdb.org/t/p/w500/prq0j1S0K07UjwLZLF6oMGflRUI.jpg','https://image.tmdb.org/t/p/original/AwrqoanoZVYoc0MRyE0RiHEKm71.jpg','On the planet Ygam, the Draags, extremely technologically and spiritually advanced blue humanoids, consider the tiny Oms, human beings descendants of Terra''s inhabitants, as ignorant animals. Those who live in slavery are treated as simple pets and used to entertain Draag children; those who live hidden in the hostile wilderness of the planet are periodically hunted and ruthlessly slaughtered as if they were vermin.',NULL,NULL,2.3994,7.6,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2137,64022,'tt0091449',NULL,'The Snow Queen','Lumikuningatar','movie',1986,'https://image.tmdb.org/t/p/w500/mSwR8C9UMQ0EkFFirad9ePWDUxq.jpg','https://image.tmdb.org/t/p/original/sXYnCnB33rfBPMxgS7fq4mkflF9.jpg','A Finnish live action adaptation of Hans Christian Andersen''s fairy tale, The Snow Queen. The tale centers on the struggle between good and evil as experienced by a little boy and girl, Kai and Kerttu.',NULL,NULL,1.3611,6.824,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2138,22504,'tt0079820',NULL,'The King and the Mockingbird','Le Roi et l''Oiseau','movie',1980,'https://image.tmdb.org/t/p/w500/yDbfVUrb9b0Dkm1TptWtzkujXBk.jpg','https://image.tmdb.org/t/p/original/pSL75Sg1APD4OHpQs4VyFb8pIFv.jpg','A young shepherdess and a chimneysweep plan to get married and escape the clutches of a tyrannical king in love with her, assisted by the guile of a cheeky mockingbird, the king''s archenemy.',NULL,NULL,1.6115,7.765,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2139,58429,'tt0240419',NULL,'La Ciénaga','La Ciénaga','movie',2001,'https://image.tmdb.org/t/p/w500/fcgRKfCRudyWggyHIT9LOPgU3qW.jpg','https://image.tmdb.org/t/p/original/7IpUXbKHWA1Xt4jCwnP3A2YFPC3.jpg','Amid the sweltering summer heat in northern Argentina, two middle-class families retreat to a crumbling country estate and a modest townhouse, where strained relationships, simmering tensions, and the presence of children and servants quietly expose the fractures of family life. Between idle days, gossip, and unspoken desires, the boundaries of class, tradition, and faith are reflected in their everyday interactions.',NULL,NULL,1.109,6.867,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2140,481432,'tt6752992',NULL,'Happy as Lazzaro','Lazzaro felice','movie',2018,'https://image.tmdb.org/t/p/w500/j4x1O6G0cbchHQwNsEZ0DntOJMJ.jpg','https://image.tmdb.org/t/p/original/zTnpY0BXP6ytvV4ZMsAmsIEDmNM.jpg','Purehearted teen Lazzaro is content living as a sharecropper in rural Italy, but an unlikely friendship with the marquise’s son will change his world.',NULL,NULL,1.3752,7.4,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2141,334394,'tt4935418',NULL,'Baskin','Baskın: Karabasan','movie',2015,'https://image.tmdb.org/t/p/w500/oNiinNDzPUH0I3K4puCwrJa7Hn1.jpg','https://image.tmdb.org/t/p/original/uxrsznMDPgsGDqiZ7UkkFgBEglM.jpg','A squad of unsuspecting cops go through a trapdoor to Hell when they stumble upon a Black Mass in an abandoned building.',NULL,NULL,1.0421,5.867,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2142,123957,'tt2006697',NULL,'Bobby Yeah','Bobby Yeah','movie',2011,'https://image.tmdb.org/t/p/w500/A9gKUDeuVQU1frU465IeCCahHiv.jpg','https://image.tmdb.org/t/p/original/9O8X66iDoEEows2khSnzgDrfuGp.jpg','Bobby Yeah is a petty thug who lightens his miserable existence by brawling and stealing stuff. One day, he steals the favourite pet of some very dangerous individuals, and finds himself in deep trouble. He really should learn, but he just can''t help it.',NULL,NULL,0.4959,7.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2143,9457,'tt0118956',NULL,'Deep Rising','Deep Rising','movie',1998,'https://image.tmdb.org/t/p/w500/A1nOnrAlG3EbOvzgZt2ya11OmjQ.jpg','https://image.tmdb.org/t/p/original/adLEtxJpjwrHuwCHnRmSfkkjJ6Q.jpg','A group of heavily armed hijackers board a luxury ocean liner in the South Pacific Ocean to loot it, only to do battle with a series of large-sized, tentacled, man-eating sea creatures who have taken over the ship first.',NULL,NULL,5.7846,6.181,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2144,444149,'tt5476182',NULL,'Hellraiser: Judgment','Hellraiser: Judgment','movie',2018,'https://image.tmdb.org/t/p/w500/nYlSoysJVSvfKhMMKB6PLbXuWUK.jpg','https://image.tmdb.org/t/p/original/qW4hr2WweKiyztgd4Ql0wlfRYBF.jpg','Three detectives trying to stop a diabolical serial killer are sucked into a maze of otherworldly horror, where hellish denizens including the Auditor, the Assessor, and the Jury await to pass judgment.',NULL,NULL,1.7219,5.1,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2145,11887,'tt0962726',NULL,'High School Musical 3: Senior Year','High School Musical 3: Senior Year','movie',2008,'https://image.tmdb.org/t/p/w500/aq2o1wT0crBOTxof36O6KTyjpgE.jpg','https://image.tmdb.org/t/p/original/spyZFUG0lR6FEbvMn3YBcxT8vdx.jpg','As seniors in high school, Troy and Gabriella struggle with the idea of being separated from one another as college approaches. Along with the rest of the Wildcats, they stage a spring musical to address their experiences, hopes and fears about their future.',NULL,NULL,3.4901,6.541,0,4.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2146,19011,'tt0063427',NULL,'Picnic with Weismann','Picknick mit Weismann','movie',1968,'https://image.tmdb.org/t/p/w500/p6eY1LCUJjOwqymhq2m3D1U4uWJ.jpg','https://image.tmdb.org/t/p/original/9SurKdg5F0SoPtJ0SQAtwhV62ug.jpg','Various objects are having a sunny outing together in the nature.',NULL,NULL,0.2367,6.458,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2147,709926,'tt12409100',NULL,'Routine: The Prohibition','Rutina: La prohibición','movie',2019,'https://image.tmdb.org/t/p/w500/m66Urq7XHxsoccpgAPFGdiCbaT4.jpg','https://image.tmdb.org/t/p/original/w1G1BYqmvVRXGoxAdGrMDzhk4d2.jpg','It''s business as usual for the mutant denizens of a dystopia not entirely unlike our own in this beguiling stop-motion fantasia.',NULL,NULL,0.1446,6.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2148,59357,'tt0092020',NULL,'Street of Crocodiles','Street of Crocodiles','movie',1986,'https://image.tmdb.org/t/p/w500/dbHs6pwSDuuX3n17ARz5Shps3ZU.jpg','https://image.tmdb.org/t/p/original/gioBVeKMT0gyh0x4NOsk19lDJdp.jpg','A puppet, newly released from his strings, explores the sinister room in which he finds himself.',NULL,NULL,0.7484,6.58,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2149,1433,'tt0256009',NULL,'The Devil''s Backbone','El espinazo del diablo','movie',2001,'https://image.tmdb.org/t/p/w500/iP1z1aJzPnkP8FHg77TS7ukqoEZ.jpg','https://image.tmdb.org/t/p/original/iUFylO8khUHGiSJanUZQfzZYyXI.jpg','Spain, 1939. In the last days of the Spanish Civil War, the young Carlos arrives at the Santa Lucía orphanage, where he will make friends and enemies as he follows the quiet footsteps of a mysterious presence eager for revenge.',NULL,NULL,3.422,7.289,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2150,10542,'tt0116791',NULL,'The Killer Condom','Kondom des Grauens','movie',1996,'https://image.tmdb.org/t/p/w500/miOAaZHAxPFyO79BSwndQ38iPyl.jpg','https://image.tmdb.org/t/p/original/ihH2rEO2yljzHDzSLUfVtHoqbmA.jpg','In New York City, detective Luigi Mackeroni investigates a string of mysterious penile mutilations at the Hotel Quickie. After Mackeroni attempts to have a tryst with a gigolo he meets in the lobby, a carniverous condom bites off his right testicle and flees, which sets the detective off on a quest to stop the predatory prophylactic once and for all.',NULL,NULL,1.5356,5.242,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2151,128191,'tt0378611',NULL,'Punk Rock Holocaust','Punk Rock Holocaust','movie',2004,'https://image.tmdb.org/t/p/w500/ojHSYpjwHQTfTBouJWzCfc4LNxx.jpg',NULL,'It is about a serial killer on the loose at the Vans Warped Tour who tries killing off the bands one by one, and features bands such as Me First and the Gimme Gimmes, Less Than Jake, The Used, Big D and the Kids Table, Rancid, The Horrorpops, The Suicide Machines, Dropkick Murphys, The Phenomenauts and many more. It was principally filmed during the summer of 2003 on the Vans Warped Tour, and features live performances from many of the bands.[1][2] The director also appears as the bandana-wrapped killer. With 110 onscreen deaths, it held the record for individual deaths in a horror film.[3] Four of the five members of Simple Plan are individually killed, making them the only band to get such individual treatment. According to the director''s commentary, bassist David Desrosiers did not want to be killed. The Phenomenauts'' actual tour bus, the "Phenomebomber" was blown up specially for the film.',NULL,NULL,0.5929,5.0,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2152,274247,'tt1139617',NULL,'Punk Rock Holocaust 2','Punk Rock Holocaust 2','movie',2008,'https://image.tmdb.org/t/p/w500/azsoce6osCKprYgSzRWL7UXGTJZ.jpg',NULL,'Picking up a year after a homicidal madman turned the Vans Warped Tour into a massacre, this intense sequel finds the decapitated Executioner looking for his missing noggin. While tour production manager Kevin Lyman faces off with a record label bigwig, the Executioner continues the bloodshed, and a nubile newshound sets out to expose the truth about the demonic killings.',NULL,NULL,0.3164,0.0,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2153,613911,'tt10333426',NULL,'Bliss','Bliss','movie',2021,'https://image.tmdb.org/t/p/w500/b7BllsQkD6nTkAdtd28UVCmKqVi.jpg','https://image.tmdb.org/t/p/original/eSl9MRMvWJ0Hm5yePHgsRhFtPTw.jpg','A mind-bending love story following Greg who, after recently being divorced and then fired, meets the mysterious Isabel, a woman living on the streets and convinced that the polluted, broken world around them is just a computer simulation. Doubtful at first, Greg eventually discovers there may be some truth to Isabel’s wild conspiracy.',NULL,NULL,1.6282,5.507,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2154,504,'tt0340855',NULL,'Monster','Monster','movie',2003,'https://image.tmdb.org/t/p/w500/sWPKG1GX0woLNBuvDZkwZC8Q3Ub.jpg','https://image.tmdb.org/t/p/original/nUJk4UjWS9YvBJUepCWziQ1QYSf.jpg','In 1989, prostitute Aileen Wuornos befriends and enters a relationship with a young woman named Selby. Determined to straighten out her life, Aileen''s limited education lands her back on the corner. She''s raped by a trick, who she kills. A string of murder and robbery follows that ultimately leads Aileen to becoming America''s first female serial killer.',NULL,NULL,4.0674,7.208,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2155,59678,'tt1478964',NULL,'Attack the Block','Attack the Block','movie',2011,'https://image.tmdb.org/t/p/w500/wzCMnA6NDruLzgWeqMcLPDrGAdF.jpg','https://image.tmdb.org/t/p/original/ncYrkutA6Yd1Gmh8fLyGieWlqLv.jpg','A South London teen gang must team up with the other residents of their housing estate to protect the neighbourhood from a terrifying alien invasion.',NULL,NULL,2.8893,6.466,0,1.24066666666666662e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2156,396774,'tt4351548',NULL,'Bomb City','Bomb City','movie',2017,'https://image.tmdb.org/t/p/w500/kho48mWJ5xuiLn5bpuIvO6ZP7ep.jpg','https://image.tmdb.org/t/p/original/9tIGBB0VUWLLsiG4JqinSPKVYBE.jpg','An ongoing feud between punk rockers and a more affluent clique in a small Texas town leads to a hate crime.',NULL,NULL,1.0435,7.125,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2157,NULL,NULL,482,'Silent Hill 3','Silent Hill 3','game',2003,'https://images.igdb.com/igdb/image/upload/t_cover_big/co3kol.jpg',NULL,'Silent Hill 3 is the third installment in the Silent Hill series. Like the previous entries, Silent Hill 3 is a survival horror combining action-based combat and puzzle-solving, but is somewhat more combat-oriented than the preceding installments. The main character is able to side-step and block some attacks, but in general shares with the other protagonists of the series their relative ineptitude in combat.','https://www.igdb.com/games/silent-hill-3','["PC (Microsoft Windows)", "PlayStation 2"]',NULL,NULL,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2158,354216,'tt4935372',NULL,'The Devil''s Candy','The Devil''s Candy','movie',2016,'https://image.tmdb.org/t/p/w500/xLw8nDNLuffMdvjYXQLwL6UCXcs.jpg','https://image.tmdb.org/t/p/original/lcix4ZjVsO7YqHohmk0QLcJRRl5.jpg','A struggling painter is possessed by satanic forces after he and his young family move into their dream home in rural Texas.',NULL,NULL,1.4812,6.313,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2159,28054,'tt0086589',NULL,'Suburbia','Suburbia','movie',1984,'https://image.tmdb.org/t/p/w500/vydIE7nizxO04ER9EcDdbdaHh8c.jpg','https://image.tmdb.org/t/p/original/1t0SonlKEQy4XHZcIu0SgQNrdJ5.jpg','When household tensions and a sense of worthlessness overcome Evan, he finds escape when he clings with the orphans of a throw-away society. The runaways hold on to each other like a family until a tragedy tears them apart.',NULL,NULL,1.1472,6.649,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2160,27090,'tt0365960',NULL,'Zero Day','Zero Day','movie',2003,'https://image.tmdb.org/t/p/w500/92aAP2PPAFbue7cgmFYfxGT8WKc.jpg','https://image.tmdb.org/t/p/original/ahXtNFVHtFxvjphZN8QlHRVsu9W.jpg','Two troubled adolescents chronicle the events that ultimately lead up to a terrifying assault on their school.',NULL,NULL,4.3513,7.4,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2161,2061,'tt0117407',NULL,'Pusher','Pusher','movie',1996,'https://image.tmdb.org/t/p/w500/9Myfvq4e2BySE5aosX8UzV9cUME.jpg','https://image.tmdb.org/t/p/original/1ZJlf0fxLRRrAn39guNvJi4e7Im.jpg','A drug pusher grows increasingly desperate after a botched deal leaves him with a large debt to a ruthless drug lord.',NULL,NULL,2.6649,7.0,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2162,1005776,'tt21651560',NULL,'V/H/S/99','V/H/S/99','movie',2022,'https://image.tmdb.org/t/p/w500/1bOMmFtnykBmvhFcx8zdXO6bCAa.jpg','https://image.tmdb.org/t/p/original/zLUeVsiJ4mKlqSI7cB7lnxCzSbb.jpg','A thirsty teenager''s home video leads to a series of horrifying revelations, harkening back to the final punk rock analog days of VHS, while taking one giant leap forward into the hellish new millennium.',NULL,NULL,1.5239,5.887,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2163,624779,'tt9894470',NULL,'VFW','VFW','movie',2019,'https://image.tmdb.org/t/p/w500/AnVD7Gn14uOTQhcc5xYZGQ9DRvS.jpg','https://image.tmdb.org/t/p/original/qhGHcg1RxrAObpabDu03MkxCI1G.jpg','A typical night for veterans at a VFW turns into an all-out battle for survival when a desperate teen runs into the bar with a bag of stolen drugs. When a gang of violent punks come looking for her, the vets use every weapon at their disposal to protect the girl and themselves from an unrelenting attack.',NULL,NULL,0.9783,5.848,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2164,16209,'tt0311361',NULL,'Jesus Christ Vampire Hunter','Jesus Christ Vampire Hunter','movie',2001,'https://image.tmdb.org/t/p/w500/iYAiPgkzaCAlMwQ7hyAr0h3D2uF.jpg','https://image.tmdb.org/t/p/original/chTzuvknyHTc0jqjQjGsEjmg5DG.jpg','The second coming is upon us, and Jesus has returned to earth. But before he can get down to the serious business of judging the living and the dead, he has to contend with an army of vampires that can walk in the daylight.',NULL,NULL,0.5633,4.905,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2165,13553,'tt0079082',NULL,'The Driller Killer','The Driller Killer','movie',1979,'https://image.tmdb.org/t/p/w500/qeFh14wpyxtmEZrpnPX1L4q5AJG.jpg','https://image.tmdb.org/t/p/original/ejNnuzHFwYWKBelYq9vpluLHFih.jpg','An artist slowly goes insane while struggling to pay his bills, work on his paintings, and care for his two female roommates, which leads him taking to the streets of New York after dark and randomly killing derelicts with a power drill.',NULL,NULL,0.7711,5.126,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2166,718558,'tt9102084',NULL,'Fried Barry','Fried Barry','movie',2020,'https://image.tmdb.org/t/p/w500/iQ2TCB6nszgFHnF1QeHJujvBIzn.jpg','https://image.tmdb.org/t/p/original/hYfm6bESA5cahGIOOD4gH0L4pQf.jpg','Barry is a drug-addled, abusive bastard who - after yet another bender - is abducted by aliens. Barry takes a backseat as an alien visitor assumes control of his body and takes it for a joyride through Cape Town. What follows is an onslaught of drugs, sex, and violence as our alien tourist enters the weird and wonderful world of humankind.',NULL,NULL,0.6987,5.074,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2167,9424,'tt0134619',NULL,'Disturbing Behavior','Disturbing Behavior','movie',1998,'https://image.tmdb.org/t/p/w500/uAhvaueOUUQ6ORCRdsJr1WXz1w0.jpg','https://image.tmdb.org/t/p/original/9bMAhzkuvwSXdxUIoFrYuAvkxDU.jpg','Steve Clark is a newcomer in the town of Cradle Bay, and he quickly realizes that there''s something odd about his high school classmates. The clique known as the "Blue Ribbons" are the eerie embodiment of academic excellence and clean living. But, like the rest of the town, they''re a little too perfect. When Steve''s rebellious friend Gavin mysteriously joins their ranks, Steve searches for the truth with fellow misfit Rachel.',NULL,NULL,2.2027,5.815,0,10.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2168,79548,'tt1838544',NULL,'Gone','Gone','movie',2012,'https://image.tmdb.org/t/p/w500/5GcbQhm0Qbbf1qt24spUpqX5tfP.jpg','https://image.tmdb.org/t/p/original/nx0xf9ocWJmKUWWfuWMkUtUyHjh.jpg','Jill Conway is trying to rebuild her life after escaping a terrifying kidnapping. Though she is having a difficult time, she takes small steps toward normalcy by starting a new job and inviting her sister, Molly, to move in with her. Returning home from work one morning, Jill discovers that Molly has vanished, and she is certain that the same man who previously abducted her has returned for revenge.',NULL,NULL,2.3878,6.235,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2169,320,'tt0278504',NULL,'Insomnia','Insomnia','movie',2002,'https://image.tmdb.org/t/p/w500/riVXh3EimGO0y5dgQxEWPRy5Itg.jpg','https://image.tmdb.org/t/p/original/jU8MC5uSgBkZXyZYGtZgMsMsfeN.jpg','Two Los Angeles homicide detectives are dispatched to a northern town where the sun doesn''t set to investigate the methodical murder of a local teen.',NULL,NULL,8.1511,6.961,0,11.59,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2170,10424,'tt0104549',NULL,'Jennifer Eight','Jennifer Eight','movie',1992,'https://image.tmdb.org/t/p/w500/pMlk8spEliRD6hr4ILs5ubHeBGT.jpg','https://image.tmdb.org/t/p/original/dAWlWircXrlnMjsVZSyb7vgMlIo.jpg','John Berlin, a big-city cop from LA moves to a small-town police force and immediately finds himself investigating a murder. Using theories rejected by his colleagues, Berlin meets a young blind woman named Helena, whom he is attracted to. Meanwhile, a serial killer is on the loose—and only John knows it.',NULL,NULL,2.2836,6.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2171,10632,'tt0269347',NULL,'The Hunted','The Hunted','movie',2003,'https://image.tmdb.org/t/p/w500/AvdBPe2XSKm3cGyTKFgbquC2jCo.jpg','https://image.tmdb.org/t/p/original/2T3k09YnrM03CQd1yK3ZQLEHEZH.jpg','In the wilderness of British Columbia, two hunters are tracked and viciously murdered by Aaron Hallam. A former Special Operations instructor is approached and asked to apprehend Hallam—his former student—who has ''gone rogue'' after suffering severe battle stress from his time in Kosovo.',NULL,NULL,3.3254,6.18,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2172,710295,'tt4216984',NULL,'Wolf Man','Wolf Man','movie',2025,'https://image.tmdb.org/t/p/w500/wpSDzTBfF0Eeo5lzu2w9FTujGqd.jpg','https://image.tmdb.org/t/p/original/wwARk7hRIfHfh2n2ubN6N7lvTne.jpg','With his marriage fraying, Blake persuades his wife Charlotte to take a break from the city and visit his remote childhood home in rural Oregon. As they arrive at the farmhouse in the dead of night, they''re attacked by an unseen animal and barricade themselves inside the home as the creature prowls the perimeter. But as the night stretches on, Blake begins to behave strangely, transforming into something unrecognizable.',NULL,NULL,4.3871,6.159,0,4.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2173,127865,'tt10834220',NULL,'The Chestnut Man','Kastanjemanden','tv',2021,'https://image.tmdb.org/t/p/w500/naCYfDx93zfXT6MwmvTwBOkIUy9.jpg','https://image.tmdb.org/t/p/original/fIXTetAsXkPO6UUUw85IU4oactf.jpg','At a grisly murder scene sits a figurine made of chestnuts. From this creepy clue, two detectives hunt a killer linked to a politician''s missing child.',NULL,NULL,13.0483,7.48,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2174,34415,'tt1637727',NULL,'The Killing','The Killing','tv',2011,'https://image.tmdb.org/t/p/w500/3yiwAUNGn1rsPSVmFgVwPVJFtYf.jpg','https://image.tmdb.org/t/p/original/LjXBJaNaBGgAsNHDYfFTwGOUWb.jpg','The Killing is an American crime drama television series based upon the Danish television series Forbrydelsen. Set in Seattle, Washington, the series follows the various murder investigations by homicide detectives Sarah Linden and Stephen Holder.',NULL,NULL,18.2842,7.829,0,10.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2175,9717,'tt0096098',NULL,'Shoot to Kill','Shoot to Kill','movie',1988,'https://image.tmdb.org/t/p/w500/tvp2vmD7qRgrh7rjiL7qI8XYxne.jpg','https://image.tmdb.org/t/p/original/oDXHbnE2XTaGkEmlhRCXSmYlFF9.jpg','When a cunning murderer vanishes into the rugged mountains of the Pacific Northwest, pursuing FBI agent Warren Stantin must exchange familiar city streets for unknown wilderness trails. Completely out of his element, Stantin is forced to enlist the aid of expert tracker Jonathan Knox. It''s a turbulent yet vital relationship they must maintain in order to survive... and one that becomes increasingly desperate when Knox''s girlfriend Sarah becomes the killer''s latest hostage!',NULL,NULL,2.8174,6.613,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2176,901385,'tt15353964',NULL,'Significant Other','Significant Other','movie',2022,'https://image.tmdb.org/t/p/w500/liGvBdUsyOfiTJjNCD55JJfISzb.jpg','https://image.tmdb.org/t/p/original/dR78i8aMsa8wIuBiHGfU8K5gNL7.jpg','Ruth and Harry decide to take a romantic backpacking trip through the Pacific Northwest, but amongst the beautiful scenery, Ruth makes an unexpected discovery that sets her off on a strange, frightening new path. The couple aren''t alone in the woods, and they might not be the same when they come out...if they come out.',NULL,NULL,2.0007,6.088,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2177,228973,'tt2944198',NULL,'Backcountry','Backcountry','movie',2015,'https://image.tmdb.org/t/p/w500/AdIkDCWcBqv1B10ncm71sMiqEEF.jpg','https://image.tmdb.org/t/p/original/fX8OjnkkWnGJdQ7tkpf8z7la4Xu.jpg','A couple on a deep-wilderness hike become hopelessly lost within an aggressive black bear''s territory.',NULL,NULL,3.4818,5.977,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2178,70523,'tt5753856',NULL,'Dark','Dark','tv',2017,'https://image.tmdb.org/t/p/w500/apbrbWs8M9lyOpJYU5WXrpFbk1Z.jpg','https://image.tmdb.org/t/p/original/3jDXL4Xvj3AzDOF6UH1xeyHW8MH.jpg','A missing child sets four families on a frantic hunt for answers as they unearth a mind-bending mystery that spans three generations.',NULL,NULL,39.0914,8.427,0,12.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2179,1586,'tt0363988',NULL,'Secret Window','Secret Window','movie',2004,'https://image.tmdb.org/t/p/w500/hvzw4wufKZkDCTPVeG71Z7pGfZh.jpg','https://image.tmdb.org/t/p/original/dBSYDUZpps3LWru7ofUZAYoFgUj.jpg','Mort Rainey, a writer just emerging from a painful divorce with his ex-wife, is stalked at his remote lake house by a psychotic stranger and would-be scribe who claims Rainey swiped his best story idea. But as Rainey endeavors to prove his innocence, he begins to question his own sanity.',NULL,NULL,4.8525,6.568,0,1.0129999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2180,1622,'tt0460681',NULL,'Supernatural','Supernatural','tv',2005,'https://image.tmdb.org/t/p/w500/8iixmfGx5EIFPdpNvB2JvI3VIqX.jpg','https://image.tmdb.org/t/p/original/ro0tlgnsco4SwbdAgmscLkSlMSL.jpg','When they were boys, Sam and Dean Winchester lost their mother to a mysterious and demonic supernatural force. Subsequently, their father raised them to be soldiers. He taught them about the paranormal evil that lives in the dark corners and on the back roads of America ... and he taught them how to kill it. Now, the Winchester brothers crisscross the country in their ''67 Chevy Impala, battling every kind of supernatural threat they encounter along the way. ',NULL,NULL,200.7453,8.312,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2181,10727,'tt0282209',NULL,'Darkness Falls','Darkness Falls','movie',2003,'https://image.tmdb.org/t/p/w500/qoceKsM15yL5Tmyuhkdl7vM5Vi4.jpg','https://image.tmdb.org/t/p/original/ap5DOvqzyIld9VBZZ5Yuc251RJo.jpg','A vengeful spirit has taken the form of the Tooth Fairy to exact vengeance on the town that lynched her 150 years earlier. Her only opposition is the only child, now grown up, who has survived her before.',NULL,NULL,1.8595,5.6,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2182,NULL,NULL,1062,'Alan Wake','Alan Wake','game',2010,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2dft.jpg',NULL,'Alan Wake is a psychological horror action-adventure game developed by Remedy Entertainment. The narrative centres on Alan Wake, a bestselling thriller novelist experiencing writer''s block. He travels to the small town of Bright Falls with his wife, Alice, seeking a change of environment. Shortly after their arrival, Alice vanishes under mysterious circumstances.

As Alan searches for her, he discovers pages of a thriller novel he does not recall writing. The events described in these pages begin to manifest in reality, and Alan encounters hostile supernatural entities known as the "Taken," who are controlled by darkness. The gameplay involves navigating Bright Falls and using light to combat these dark forces. The storyline explores themes of reality and fiction, along with the influence of the written word.','https://www.igdb.com/games/alan-wake','["PC (Microsoft Windows)", "Xbox 360"]',NULL,NULL,0,1.26599999999999983e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2183,NULL,NULL,185246,'Alan Wake II','Alan Wake II','game',2023,'https://images.igdb.com/igdb/image/upload/t_cover_big/co6jar.jpg',NULL,'Alan Wake 2 marks Remedy Entertainment’s first foray into the survival horror genre. Ritualistic murders in a small town. A writer trapped in a nightmare. An FBI agent looking for answers. Two realities. Two hero characters. One horror story that wants them dead.','https://www.igdb.com/games/alan-wake-ii','["Xbox Series X|S", "PC (Microsoft Windows)", "PlayStation 5"]',NULL,NULL,0,11.545,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2184,NULL,NULL,26192,'The Last of Us Part II','The Last of Us Part II','game',2020,'https://images.igdb.com/igdb/image/upload/t_cover_big/co5ziw.jpg',NULL,'The Last of Us Part II is an action-adventure game set five years after the events of The Last of Us. The player traverses post-apocalyptic environments such as buildings and forests to advance the story. They can use firearms, improvised weapons, and stealth to defend against hostile humans and cannibalistic creatures infected by a mutated strain of the Cordyceps fungus. The game intermittently switches control between Ellie and Abby, and also briefly Joel in the opening sequence. The nimble nature of the player character introduces platforming elements, allowing the player to jump and climb to traverse environments and gain advantages during combat.','https://www.igdb.com/games/the-last-of-us-part-ii','["PlayStation 4", "PlayStation 5"]',NULL,NULL,0,10.11,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2185,509635,'tt7711170',NULL,'Alone','Alone','movie',2020,'https://image.tmdb.org/t/p/w500/n9OzZmPMnVrV0cMQ7amX0DtBkQH.jpg','https://image.tmdb.org/t/p/original/obExOU9qDnMcxvWPumoD14oxup5.jpg','A recently widowed traveler is kidnapped by a cold blooded killer, only to escape into the wilderness where she is forced to battle against the elements as her pursuer closes in on her.',NULL,NULL,3.7657,6.4,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2186,635731,'tt11003218',NULL,'Pig','Pig','movie',2021,'https://image.tmdb.org/t/p/w500/1InMm4Mbjx8wCKvIy5gglo5i3HN.jpg','https://image.tmdb.org/t/p/original/uFvueAhlKsXQacjiKxGBgnBqarf.jpg','A truffle hunter who lives alone in the Oregon wilderness must visit Portland to find the mysterious person who stole his beloved foraging pig.',NULL,NULL,4.4982,6.623,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2187,1029281,'tt22375054',NULL,'Strange Darling','Strange Darling','movie',2024,'https://image.tmdb.org/t/p/w500/kWNCRgt3ocv19bYO0sk7TRuZuFY.jpg','https://image.tmdb.org/t/p/original/I4ofwq3XfmwXAETUs5pjubcMJ0.jpg','Nothing is what it seems when a twisted one-night stand spirals into a serial killer’s vicious murder spree.',NULL,NULL,6.0572,6.9,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2188,70954,'tt1703148',NULL,'The Hunter','The Hunter','movie',2011,'https://image.tmdb.org/t/p/w500/KgFYNh3GE36FrXjo9udZbnV1z6.jpg','https://image.tmdb.org/t/p/original/fAsuiSAYRg0iadijOdEqK9CO6kY.jpg','Martin, a mercenary, is sent from Europe by an anonymous biotech company to the Tasmanian wilderness on a hunt for the last Tasmanian tiger.',NULL,NULL,2.2742,6.6,0,10.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2189,61405,'tt3435532',NULL,'Gracepoint','Gracepoint','tv',2014,'https://image.tmdb.org/t/p/w500/smeC4HKFDWWhgg8R5ub86RpZhBJ.jpg','https://image.tmdb.org/t/p/original/c68h9tYwz1wsZk1vnb9JD3JZnay.jpg','When a young boy is found dead on an idyllic beach, a major police investigation gets underway in the small California seaside town where the tragedy occurred. Soon deemed a homicide, the case sparks a media frenzy, which throws the boy''s family into further turmoil and upends the lives of all of the town''s residents.',NULL,NULL,3.3819,6.626,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2190,95,'tt0118276',NULL,'Buffy the Vampire Slayer','Buffy the Vampire Slayer','tv',1997,'https://image.tmdb.org/t/p/w500/y7fVZkyheCEQHDUEHwNmYENGfT2.jpg','https://image.tmdb.org/t/p/original/lBmlLro9ZfY815ZXE5NKhYNxPRQ.jpg','Into every generation a slayer is born: one girl in all the world, a chosen one. She alone will wield the strength and skill to fight the vampires, demons, and the forces of darkness; to stop the spread of their evil and the swell of their number. She is the Slayer.',NULL,NULL,35.8638,8.106,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2191,840,'tt0075860',NULL,'Close Encounters of the Third Kind','Close Encounters of the Third Kind','movie',1977,'https://image.tmdb.org/t/p/w500/yaPx3cK9zGFX3SbcKwxWM1QIbUh.jpg','https://image.tmdb.org/t/p/original/yBCekmb7vK70xUhtsRQBcTu65sB.jpg','After an encounter with UFOs, an electricity linesman feels undeniably drawn to an isolated area in the wilderness where something spectacular is about to happen.',NULL,NULL,7.8019,7.358,0,12.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2192,1396869,'tt36302733',NULL,'Diés Iraé','ഡീയസ് ഈറെ','movie',2025,'https://image.tmdb.org/t/p/w500/123DlTiiezgLaJruVe7RiSi0RFf.jpg','https://image.tmdb.org/t/p/original/8Fl8B1TRkcjkU9VMp9ex9mV6949.jpg','Rohan''s affluent lifestyle spirals out of control as he becomes convinced there is a supernatural entity in his home. As he starts to uncover the mystery, he is drawn into unexpected worlds and alliances, along with the horrors that lie ahead.',NULL,NULL,3.2775,6.429,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2193,601,'tt0083866',NULL,'E.T. the Extra-Terrestrial','E.T. the Extra-Terrestrial','movie',1982,'https://image.tmdb.org/t/p/w500/an0nD6uq6byfxXCfk6lQBzdL2J1.jpg','https://image.tmdb.org/t/p/original/mXLVA0YL6tcXi6SJSuAh9ONXFj5.jpg','An alien is left behind on Earth and saved by the 10-year-old Elliott who decides to keep him hidden in his home. While a task force hunts for the extra-terrestrial, Elliott, his brother, and his little sister Gertie form an emotional bond with their new friend, and try to help him find his way home.',NULL,NULL,13.3172,7.517,0,1.50783333333333331e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2194,NULL,NULL,2899,'EarthBound','EarthBound','game',1994,'https://images.igdb.com/igdb/image/upload/t_cover_big/co6v07.jpg',NULL,'A turn-based JRPG and sequel to the then-Japan-only Earthbound Beginnings (1989) in which Ness, a young boy living in a land based on the USA, leaves home to go on an adventure through strange locations, get to know quirky characters, and defeat an unknowable alien threat called Giygas while facing up to the realities of growing up and becoming familiar with the real world.','https://www.igdb.com/games/earthbound','["Super Nintendo Entertainment System", "Wii U", "New Nintendo 3DS", "Game Boy Advance", "Super Famicom"]',NULL,NULL,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2195,11495,'tt0087262',NULL,'Firestarter','Firestarter','movie',1984,'https://image.tmdb.org/t/p/w500/2ux5lqNuibd8eOkwwUhzfzAJBqD.jpg','https://image.tmdb.org/t/p/original/tGvV6JZJxOh7yTRfcR5Hvo22aln.jpg','Charlene "Charlie" McGee has the amazing ability to start fires with just a glance. Can her psychic power and the love of her father save her from the threatening government agency which wants to destroy her?',NULL,NULL,1.4978,6.3,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2196,620,'tt0087332',NULL,'Ghostbusters','Ghostbusters','movie',1984,'https://image.tmdb.org/t/p/w500/7E8nLijS9AwwUEPu2oFYOVKhdFA.jpg','https://image.tmdb.org/t/p/original/c6yfABGVKuB5cjoOwdX4AJMlzUz.jpg','After losing their university jobs, three parapsychologists start a ghost-catching business in New York City and uncover a supernatural threat that could destroy the world.',NULL,NULL,8.5272,7.498,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2197,1639,'tt0813715',NULL,'Heroes','Heroes','tv',2006,'https://image.tmdb.org/t/p/w500/lf0TcOkheYUZKpeh7c8lqJHNk5O.jpg','https://image.tmdb.org/t/p/original/zoetbPF7jYY0jjY5js3x6r1QjSW.jpg','Common people discover that they have super powers. Their lives intertwine as a devastating event must be prevented.',NULL,NULL,43.0713,7.445,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2198,8844,'tt0113497',NULL,'Jumanji','Jumanji','movie',1995,'https://image.tmdb.org/t/p/w500/iWV47r6kFneCiApgrMII5HSkfHw.jpg','https://image.tmdb.org/t/p/original/qSxeCfWUUyht9hZgaaYmtPtTkw2.jpg','When siblings Judy and Peter discover an enchanted board game that opens the door to a magical world, they unwittingly invite Alan -- an adult who''s been trapped inside the game for 26 years -- into their living room. Alan''s only hope for freedom is to finish the game, which proves risky as all three find themselves running from giant rhinoceroses, evil monkeys and other terrifying creatures.',NULL,NULL,3.3023,7.249,0,10.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2199,15138,'tt0097758',NULL,'Little Monsters','Little Monsters','movie',1989,'https://image.tmdb.org/t/p/w500/ynQT9NA4SBfoswIRkyrwqHe4aBz.jpg','https://image.tmdb.org/t/p/original/1zE5hF4ZsOzruEaWYq3oZ0qnUW6.jpg','A young boy is scared of the monster under his bed. He asks his 6th grade brother to swap rooms for the night as a bet that the monster really exists. Soon the brother becomes friends with the monster and discovers a whole new world of fun and games under his bed where pulling pranks on kids and other monsters is the main attraction.',NULL,NULL,2.0195,5.839,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2200,245703,'tt2649554',NULL,'Midnight Special','Midnight Special','movie',2016,'https://image.tmdb.org/t/p/w500/hgDRq1l4ATxwufWjILKsYtglbI6.jpg','https://image.tmdb.org/t/p/original/23COMNwqP8q4rWPtLGTBuCD3LnT.jpg','A father and son go on the run after the dad learns his child possesses special powers.',NULL,NULL,2.6325,6.255,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2201,11171,'tt0370986',NULL,'Mysterious Skin','Mysterious Skin','movie',2005,'https://image.tmdb.org/t/p/w500/wgSwDqhl6Rt3cuSCwt5sNpPna3x.jpg','https://image.tmdb.org/t/p/original/plsZ3coRURoFnNkjaWcbPVy72kd.jpg','A teenage hustler and a young man obsessed with alien abductions cross paths, together discovering a horrible, liberating truth.',NULL,NULL,4.1426,7.7,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2202,3040,'tt0403358',NULL,'Night Watch','Ночной дозор','movie',2004,'https://image.tmdb.org/t/p/w500/mWdfItjr9tZtsSgjkqB8YhORF8T.jpg','https://image.tmdb.org/t/p/original/2f6La6ZJDIQTNPcn2WSR6qdXy8Q.jpg','Among normal humans live the "Others" possessing various supernatural powers. They are divided up into the forces of light and the forces of the dark, who signed a truce several centuries ago to end a devastating battle. Ever since, the forces of light govern the day while the night belongs to their dark opponents. In modern day Moscow the dark Others actually roam the night as vampires while a "Night Watch" of light forces, among them Anton, the movie''s protagonist, try to control them and limit their outrage',NULL,NULL,1.9983,6.207,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2203,20481,'tt0100260',NULL,'Nightbreed','Nightbreed','movie',1990,'https://image.tmdb.org/t/p/w500/1ChluYH0BEvJo3gtYoFHnMZI660.jpg','https://image.tmdb.org/t/p/original/vt7ZQ38ZLOpq63DXu7pi3Rf5T24.jpg','A troubled young man is drawn to a mythical place called Midian where a variety of friendly monsters are hiding from humanity. Meanwhile, a sadistic serial killer is looking for a patsy.',NULL,NULL,4.6828,6.366,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2204,1114873,'tt7575046',NULL,'Riddle of Fire','Riddle of Fire','movie',2024,'https://image.tmdb.org/t/p/w500/yjBbl4iLk3Zj5erRq4FjlyyTrWu.jpg','https://image.tmdb.org/t/p/original/jS3u87nfPAgtT1RLYaw7fMWWJoj.jpg','Three mischievous children embark on a woodland odyssey when their mother sends them on an errand.',NULL,NULL,1.0095,7.3,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2205,24808,'tt0086336',NULL,'Something Wicked This Way Comes','Something Wicked This Way Comes','movie',1983,'https://image.tmdb.org/t/p/w500/94dMO6kAawyFUk0sCDGIjAnchED.jpg','https://image.tmdb.org/t/p/original/yCoyqFx0CB6Usa8xom9fU7sc44P.jpg','In a small American town, a diabolical circus arrives, granting wishes for the townsfolk, but twisted as only the esteemed Mr. Dark can make them. Can two young boys overcome the worst the devil himself can deal out?',NULL,NULL,1.1292,6.5,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2206,37686,'tt1650062',NULL,'Super 8','Super 8','movie',2011,'https://image.tmdb.org/t/p/w500/pUWIjaMMYJjeBm5bJyE3mIXdQ62.jpg','https://image.tmdb.org/t/p/original/x6Dr9i6vhWICxs7hnX2BakcMtPd.jpg','In late 1970s Ohio, a group of friends filming a homemade zombie movie witness a devastating train derailment. Soon after, their quiet town is gripped by unexplained disappearances, strange phenomena, and a growing sense of fear, as they uncover that something terrifying has been set loose.',NULL,NULL,5.7224,6.78,0,1.22533333333333338e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2207,1372432,'tt28265205',NULL,'The Elevator Game','The Elevator Game','movie',2023,'https://image.tmdb.org/t/p/w500/6GTCmWnj4DwOJskYgBvK6zEg6cy.jpg',NULL,'Suicide or stuck in another dimension? Two friends delve into the most dangerous urban legend to find answers about their colleague''s odd death.',NULL,NULL,0.2995,6.5,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2208,7980,'tt0380510',NULL,'The Lovely Bones','The Lovely Bones','movie',2009,'https://image.tmdb.org/t/p/w500/sn0iDphRxQ7I6aLd9igIgACITak.jpg','https://image.tmdb.org/t/p/original/5abq386123nxHS8mVZLsFi7c75z.jpg','After being brutally murdered, 14-year-old Susie Salmon watches from heaven over her grief-stricken family -- and her killer. As she observes their daily lives, she must balance her thirst for revenge with her desire for her family to heal.',NULL,NULL,7.073,7.058,0,1.1254999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2209,13509,'tt0093560',NULL,'The Monster Squad','The Monster Squad','movie',1987,'https://image.tmdb.org/t/p/w500/8EVuqCcqFzQvc7X8E3fx3w4B5Td.jpg','https://image.tmdb.org/t/p/original/thYgTJfMO2HG7OJTVIAbbuHCx2D.jpg','Count Dracula returns to the world of humans accompanied by Frankenstein''s Monster, the Wolfman, the Mummy, and the Gillman. The uglies are in search of a powerful amulet that will grant them the ability to rule the world. A group of horror-loving heroes are the only ones daring to stand in their way.',NULL,NULL,2.8604,6.7,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2210,614933,'tt14856980',NULL,'Atlas','Atlas','movie',2024,'https://image.tmdb.org/t/p/w500/bcM2Tl5HlsvPBnL8DKP9Ie6vU4r.jpg','https://image.tmdb.org/t/p/original/3TNSoa0UHGEzEz5ndXGjJVKo8RJ.jpg','A brilliant counterterrorism analyst with a deep distrust of AI discovers it might be her only hope when a mission to capture a renegade robot goes awry.',NULL,NULL,5.4475,6.66,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2211,539885,'tt8784956',NULL,'Ava','Ava','movie',2020,'https://image.tmdb.org/t/p/w500/qzA87Wf4jo1h8JMk9GilyIYvwsA.jpg','https://image.tmdb.org/t/p/original/54yOImQgj8i85u9hxxnaIQBRUuo.jpg','A black ops assassin is forced to fight for her own survival after a job goes dangerously wrong.',NULL,NULL,2.5936,5.825,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2212,66045,'tt0092664',NULL,'Black Magic M-66','ブラックマジックM-66','movie',1987,'https://image.tmdb.org/t/p/w500/osln12VHCtGEhiib7FHnTBZr9FJ.jpg','https://image.tmdb.org/t/p/original/3KdQhE2hrFcvB34hwq63yONM28m.jpg','A top-secret weapon escapes from military custody ready to destroy its pre-programmed target. The nosy freelance reporter who shows up to cover the story lands herself at the center of something even more dangerous than the international scandal she signed up for.',NULL,NULL,0.8635,6.33,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2213,15003,'tt1183252',NULL,'Chocolate','ช็อคโกแลต','movie',2008,'https://image.tmdb.org/t/p/w500/t6G2SGFZArIkMibcpGV9K8ke7rV.jpg','https://image.tmdb.org/t/p/original/umEjgwcWIjWHoxrKTS8QPMMJjDz.jpg','Zen, an autistic teenage girl with powerful martial arts skills, gets money to pay for her sick mother Zin''s treatment by seeking out all the people who owe Zin money and making them pay.',NULL,NULL,3.0017,7.332,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
