INSERT OR IGNORE INTO "recommendations" VALUES(2215,24488,'tt0284034',NULL,'Demonlover','Demonlover','movie',2002,'https://image.tmdb.org/t/p/w500/rxNhFZ7WZ12JGc9gC7PwtLKkAlo.jpg','https://image.tmdb.org/t/p/original/iv5ZHMglzn8I9qn1phdP8xSoHKs.jpg','A French corporation goes head-to-head with an American web media company for the rights to a 3-D manga pornography studio, resulting in a power struggle that culminates in violence and espionage.',NULL,NULL,1.5798,5.81,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2216,9053,'tt0398913',NULL,'DOA: Dead or Alive','DOA: Dead or Alive','movie',2006,'https://image.tmdb.org/t/p/w500/hRcYqTWgbPF3TtpSDfwqRDAJjlv.jpg','https://image.tmdb.org/t/p/original/wa5eEBwjI01yhNMKPwIaqeBiw2d.jpg','Four beautiful rivals at an invitation-only martial-arts tournament join forces against a sinister threat. Princess Kasumi is an aristocratic warrior trained by martial-arts masters. Tina Armstrong is a wrestling superstar. Helena Douglas is an athlete with a tragic past. Christie Allen earns her keep as a thief and an assassin-for-hire.',NULL,NULL,3.6242,5.263,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2217,10347,'tt0118996',NULL,'Dobermann','Dobermann','movie',1997,'https://image.tmdb.org/t/p/w500/3rahpIHJBenGJKI1EfAHlGSfKEY.jpg','https://image.tmdb.org/t/p/original/caaLhZmZm6kQVAnYInjIPiNBIE8.jpg','The charismatic criminal Dobermann, who got his first gun when he was christened, leads a gang of brutal robbers. After a complex and brutal bank robbery, they are being hunted by the Paris police. The hunt is led by the sadistic cop Christini, who only has one goal: to catch Dobermann at any cost.',NULL,NULL,1.8565,6.488,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2218,10577,'tt0219653',NULL,'Dracula 2000','Dracula 2000','movie',2000,'https://image.tmdb.org/t/p/w500/jnAfl6GSZbBMigL98RJGbOSk4V1.jpg','https://image.tmdb.org/t/p/original/bYaSV1JD9f1FBPrCDTQvFl0wcgb.jpg','When a team of techno-savvy thieves break into a high-security vault, they don''t discover priceless works of art... they find a crypt unopened for 100 years.',NULL,NULL,2.856,5.247,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2219,9947,'tt0357277',NULL,'Elektra','Elektra','movie',2005,'https://image.tmdb.org/t/p/w500/gC6s6NKHneSrOKyQZnUMb443RKU.jpg','https://image.tmdb.org/t/p/original/2JMOTj6DFjNcg9KToctmfTV55EW.jpg','Elektra the warrior survives a near-death experience, becomes an assassin-for-hire, and tries to protect her two latest targets, a single father and his young daughter, from a group of supernatural assassins.',NULL,NULL,4.285,5.051,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2220,1097,'tt0791205',NULL,'Ergo Proxy','エルゴプラクシー','tv',2006,'https://image.tmdb.org/t/p/w500/tHcce6PKnhNBneSMbadI4jynHpY.jpg','https://image.tmdb.org/t/p/original/jGAgj9QztYjSsYCnZhDMgBUzQKU.jpg','Thousands of years after Earth’s atmosphere was destroyed, adventure blooms in the strangest of places. The domed city of Romdo is supposed to be perfect, but Re-l Mayer, a young female inspector from the Civilian Intelligence Office, knows better. In this place where humans and robots coexist, she receives a strange message: something is awakening!',NULL,NULL,7.996,7.644,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
