INSERT OR IGNORE INTO "recommendations" VALUES(2222,10016,'tt0228333',NULL,'Ghosts of Mars','Ghosts of Mars','movie',2001,'https://image.tmdb.org/t/p/w500/i2zztssCIbahGES1fdfWFmDXian.jpg','https://image.tmdb.org/t/p/original/1loG5dSesKgwakjOET0Ll27jKgI.jpg','In 2176, a Martian police unit is sent to pick up a highly dangerous criminal at a remote mining post. Upon arrival, the cops find the post deserted and something far more dangerous than any criminal — the original inhabitants of Mars, hellbent on getting their planet back.',NULL,NULL,3.4656,5.163,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2223,574060,'tt8368408',NULL,'Gunpowder Milkshake','Gunpowder Milkshake','movie',2021,'https://image.tmdb.org/t/p/w500/56ofGPMOZCwlTjTao5fB7vnGOoj.jpg','https://image.tmdb.org/t/p/original/7OxkZIH9dkDQlXhwWggyCSrXmwd.jpg','To protect an 8-year-old girl, a dangerous assassin reunites with her mother and her lethal associates to take down a ruthless crime syndicate and its army of henchmen.',NULL,NULL,3.6635,6.27,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2224,70435,'tt1506999',NULL,'Haywire','Haywire','movie',2011,'https://image.tmdb.org/t/p/w500/c9fJ0dYC30NnE9k2p61c0dqlZqW.jpg','https://image.tmdb.org/t/p/original/r5bLJXXwUMp2MO5hkn4KYXIR4eO.jpg','A black ops soldier seeks payback after she is betrayed and left for dead.',NULL,NULL,4.6547,5.702,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2225,324544,'tt4419684',NULL,'In the Lost Lands','In the Lost Lands','movie',2025,'https://image.tmdb.org/t/p/w500/dDlfjR7gllmr8HTeN6rfrYhTdwX.jpg','https://image.tmdb.org/t/p/original/oI5uHu7lrQ0mBBH1c8OHCAkCq4x.jpg','A queen sends the powerful and feared sorceress Gray Alys to the ghostly wilderness of the Lost Lands in search of a magical power, where she and her guide, the drifter Boyce, must outwit and outfight both man and demon.',NULL,NULL,7.0877,6.358,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2226,43341,'tt0107228',NULL,'Iria: Zeiram the Animation','イ・リ・ア ゼイラム the Animation','tv',1994,'https://image.tmdb.org/t/p/w500/j2qNFUKu6CjOnHakPlH4Ffq4UoZ.jpg','https://image.tmdb.org/t/p/original/ho2i3OcCv9Neer9Nyy14FjrHgH4.jpg','Iria is the story of a girl and the Alien being she loves to hate. The series begins with her brother, Gren, taking a job. He is a bounty hunter, and one well known for his incredible skill. Iria, being a skilled apprentice bounty hunter herself, tags along. What is the job, one might ask. It is to find out what has happened to the crew and cargo of a Space Station. Needless to say, nothing is as it seems, and the war between Iria and Zeiram begins in earnest.',NULL,NULL,2.3876,8.091,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2227,2294,'tt0261392',NULL,'Jay and Silent Bob Strike Back','Jay and Silent Bob Strike Back','movie',2001,'https://image.tmdb.org/t/p/w500/aEsAdMAhwKYFgnHHxMOknktQYKK.jpg','https://image.tmdb.org/t/p/original/2K4ZRi6bYrl9Ha53uRi4ZyoYuft.jpg','When Jay and Silent Bob learn that their comic-book alter egos, Bluntman and Chronic, have been sold to Hollywood as part of a big-screen movie that leaves them out of any royalties, the pair travels to Tinseltown to sabotage the production.',NULL,NULL,2.5438,6.439,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2228,9945,'tt0120877',NULL,'Vampires','Vampires','movie',1998,'https://image.tmdb.org/t/p/w500/4JhaFBPwyC5IM1rKaRR07Gzutse.jpg','https://image.tmdb.org/t/p/original/uzlGbsQkpK6C3ZiqRqKw9CwK0Do.jpg','The church enlists a team of vampire-hunters to hunt down and destroy a group of vampires searching for an ancient relic that will allow them to exist in sunlight.',NULL,NULL,3.8408,6.317,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2229,23483,'tt1250777',NULL,'Kick-Ass','Kick-Ass','movie',2010,'https://image.tmdb.org/t/p/w500/iHMbrTHJwocsNvo5murCBw0CwTo.jpg','https://image.tmdb.org/t/p/original/P4bGyJQF0shAcRku3I2perNUQR.jpg','Dave Lizewski is an unnoticed high school student and comic book fan who one day decides to become a super-hero, even though he has no powers, training or meaningful reason to do so.',NULL,NULL,10.9133,7.124,0,12.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2230,10855,'tt0341495',NULL,'Naked Weapon','赤裸特工','movie',2002,'https://image.tmdb.org/t/p/w500/bEkFMDlIosqroIO8yBBIKZWoGRh.jpg','https://image.tmdb.org/t/p/original/82kYHPzaE1Mv2MVnwmCYAqTDJQT.jpg','A mysterious woman, known as Madame M, kidnaps forty pre-teen girls and transports them to a remote island to train them as the most deadly assassins. CIA operative Jack Chen follows the case for 6 years with no leads, but when a series of assassinations begin to occur, Jack suspects that Madame M is back in business.',NULL,NULL,0.9772,6.8,0,9.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2231,458594,'tt6850820',NULL,'Peppermint','Peppermint','movie',2018,'https://image.tmdb.org/t/p/w500/jrzxS0vcbzIIay1sdYm0rgI2QfJ.jpg','https://image.tmdb.org/t/p/original/14HPHJnNUVAdbYKnG46WnBh4OD6.jpg','A grieving mother transforms herself into a vigilante following the murders of her husband and daughter, eluding the authorities to deliver her own personal brand of justice.',NULL,NULL,2.8134,6.739,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2232,38321,'tt0822847',NULL,'Priest','Priest','movie',2011,'https://image.tmdb.org/t/p/w500/fYHiA7LPGl9DG7m3DUs0Td1VMcO.jpg','https://image.tmdb.org/t/p/original/srrzHjAzhYzUulBbllQCNekgnQb.jpg','In an alternate world, humanity and vampires have warred for centuries. After the last Vampire War, the veteran Warrior Priest lives in obscurity with other humans inside one of the Church''s walled cities. When the Priest''s niece is kidnapped by vampires, the Priest breaks his vows to hunt them down. He is accompanied by the niece''s boyfriend, who is a wasteland sheriff, and a former Warrior Priestess.',NULL,NULL,5.6737,5.888,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2233,87421,'tt1411250',NULL,'Riddick','Riddick','movie',2013,'https://image.tmdb.org/t/p/w500/pUul9pGWOKT7X0smkTvsIEIQxcP.jpg','https://image.tmdb.org/t/p/original/naGU49u4BXynQ1o5L755pfs8dom.jpg','Betrayed by his own kind and left for dead on a desolate planet, Riddick fights for survival against alien predators and becomes more powerful and dangerous than ever before. Soon bounty hunters from throughout the galaxy descend on Riddick only to find themselves pawns in his greater scheme for revenge. With his enemies right where he wants them, Riddick unleashes a vicious attack of vengeance before returning to his home planet of Furya to save it from destruction.',NULL,NULL,6.5384,6.345,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2234,27576,'tt0944835',NULL,'Salt','Salt','movie',2010,'https://image.tmdb.org/t/p/w500/ppXyhOe8UCEOrBRSYqE3SkHwrcR.jpg','https://image.tmdb.org/t/p/original/7RwAE11n2nd5pSqI9mCk4tPaEtM.jpg','As a CIA officer, Evelyn Salt swore an oath to duty, honor, and country. Her loyalty will be tested when a Russian defector accuses her of being a Russian sleeper spy. She goes on the run, using all her skills and years of experience as a covert operative to elude capture, protect her husband, and stay one step ahead of her colleagues at the CIA. Her efforts to prove her innocence only serve to cast doubt on her motives, as the hunt to uncover the truth behind her identity continues and the question remains: "Who is Salt?"',NULL,NULL,4.8363,6.419,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2235,15136,'tt0300620',NULL,'So Close','夕陽天使','movie',2002,'https://image.tmdb.org/t/p/w500/zdw5bISsOT9JLS4mB9OPxH91Sg5.jpg','https://image.tmdb.org/t/p/original/DKiebEytdEyrh9E66XQ9kWovcn.jpg','A conflict of interest between two high-kicking assassin sisters is complicated as they''re pursued by the criminals who hired them and an equally high-kicking female cop.',NULL,NULL,2.5908,6.909,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2236,290859,'tt6450804',NULL,'Terminator: Dark Fate','Terminator: Dark Fate','movie',2019,'https://image.tmdb.org/t/p/w500/vqzNJRH4YyquRiWxCCOH0aXggHI.jpg','https://image.tmdb.org/t/p/original/a6cDxdwaQIFjSkXf7uskg78ZyTq.jpg','Decades after Sarah Connor prevented Judgment Day, a lethal new Terminator is sent to eliminate the future leader of the resistance. In a fight to save mankind, battle-hardened Sarah Connor teams up with an unexpected ally and an enhanced super soldier to stop the deadliest Terminator yet.',NULL,NULL,9.0513,6.421,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2237,522016,'tt8356942',NULL,'The 355','The 355','movie',2022,'https://image.tmdb.org/t/p/w500/xef9Ht77B2igqZv754HNdW8qZCk.jpg','https://image.tmdb.org/t/p/original/oSNqhngemquRBzxKSC3ysAmnC5e.jpg','A group of top female agents from American, British, Chinese, Colombian, and German government agencies are drawn together to try and stop an organization from acquiring a deadly weapon to send the world into chaos.',NULL,NULL,4.9181,6.023,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2238,760204,'tt13468602',NULL,'The Lair','The Lair','movie',2022,'https://image.tmdb.org/t/p/w500/ifRFLx83Xk1DcwAS3OScgI6HmWO.jpg','https://image.tmdb.org/t/p/original/cBNLVp6sDn9xoK8gZYBw1ycAjaD.jpg','Royal Air Force pilot Lt. Kate Sinclair is on her final flight mission when her jet is shot down over one of the most dangerous rebel strongholds in Afghanistan. She finds refuge in an abandoned underground bunker where deadly man-made creatures known as Ravagers — half-human, half-alien, and hungry for human flesh — are awakened.',NULL,NULL,1.7047,5.621,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2239,552688,'tt6968614',NULL,'The Mother','The Mother','movie',2023,'https://image.tmdb.org/t/p/w500/vnRthEZz16Q9VWcP5homkHxyHoy.jpg','https://image.tmdb.org/t/p/original/n5NSF8wZeWQHHZtuWgbRAVpqXFR.jpg','A deadly female assassin comes out of hiding to protect the daughter that she gave up years before, while on the run from dangerous men.',NULL,NULL,3.193,6.622,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2240,645788,'tt6079772',NULL,'The Protégé','The Protégé','movie',2021,'https://image.tmdb.org/t/p/w500/iQUj7MptHUlcXpaMLrqRNZRxGA9.jpg','https://image.tmdb.org/t/p/original/fbTxsnJcQwuwzCEu9VEiU9lV75Y.jpg','Rescued as a child by the legendary assassin Moody and trained in the family business, Anna is the world’s most skilled contract killer. When Moody, the man who was like a father to her and taught her everything she needs to know about trust and survival, is brutally killed, Anna vows revenge. As she becomes entangled with an enigmatic killer whose attraction to her goes way beyond cat and mouse, their confrontation turns deadly and the loose ends of a life spent killing will weave themselves ever tighter.',NULL,NULL,3.4859,6.55,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2241,437109,'tt6777338',NULL,'The Villainess','악녀','movie',2017,'https://image.tmdb.org/t/p/w500/tJlOV2SU6qTxR540H9VtoCAOVm.jpg','https://image.tmdb.org/t/p/original/labMpUVoAqNlHTKiu7KsoZT0v9d.jpg','Honed from childhood into a merciless killing machine by a criminal organization, assassin Sook-hee is recruited with the promise of freedom after ten years of service. However, secrets from her past destroy everything she’s worked for and now she embarks on a roaring rampage of revenge.',NULL,NULL,2.2285,6.922,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2242,16061,'tt1183732',NULL,'Tokyo Gore Police','東京残酷警察','movie',2008,'https://image.tmdb.org/t/p/w500/d1LqkFMhFO5lfV3uwEpwyTLxXgR.jpg','https://image.tmdb.org/t/p/original/6NRBZsOi3sRIbjhYIu1I7IKtqub.jpg','In a futuristic Tokyo where police have been privatized and bitter self-mutilation is so casual that advertising is often specially geared to the ''cutter'' demographic, Ruka is on a mission to avenge her father''s assassination. Ruka is a cop from a squad whose goal is to destroy homicidal mutant humans known as ''engineers'', that possess the ability to transform any injury to a weapon in and of itself.',NULL,NULL,1.859,6.009,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2243,338970,'tt1365519',NULL,'Tomb Raider','Tomb Raider','movie',2018,'https://image.tmdb.org/t/p/w500/s4Qn5LF6OwK4rIifmthIDtbqDSs.jpg','https://image.tmdb.org/t/p/original/ohijjhvNqAPKTURQr6VIF7xuAjY.jpg','Lara Croft, the fiercely independent daughter of a missing adventurer, must push herself beyond her limits when she finds herself on the island where her father disappeared.',NULL,NULL,7.4114,6.365,0,11.17,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2244,27302,'tt0103327',NULL,'Zëiram','ゼイラム','movie',1991,'https://image.tmdb.org/t/p/w500/4mIQKfbmKe8E5XIg15Obwmox8ZV.jpg','https://image.tmdb.org/t/p/original/uePLLSyFR4bczdZYA6VCuugqFyX.jpg','Teppei and Kamiya, two average joes working in the electronic services industry, stumble upon the intergalactic bounty-hunter Ilia, and her partner, the artificial intelligence named Bob. Both men are accidentally transported to the Zone, a virtual reality in which Bob has trapped Ilia''s latest prey, a biological weapon named Zeram. The Earth natives must both survive the experience and help Ilia capture Zeram before the Zone disappears around them.',NULL,NULL,0.6578,6.2,0,11.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2245,840889,'tt14852624',NULL,'Stopmotion','Stopmotion','movie',2024,'https://image.tmdb.org/t/p/w500/kWzWZEctPcZ0dATbtcYy6lIJgGj.jpg','https://image.tmdb.org/t/p/original/shS6buEDnEDoHTdLbGzCoDIZ9ur.jpg','Ella Blake, a stop-motion animator struggling to control her demons after the loss of her overbearing mother, embarks upon the creation of a film that becomes the battleground for her sanity. As Ella’s mind starts to fracture, the characters in her project take on a life of their own.',NULL,NULL,0.9546,6.128,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2246,82094,'tt0174834',NULL,'The Pied Piper','Krysař','movie',1986,'https://image.tmdb.org/t/p/w500/tYDRQvqgTUorU37ZzEFULNMvMHf.jpg','https://image.tmdb.org/t/p/original/cY3sSQRZZc7olOMYHVqeYAEGRvd.jpg','A darkly brilliant stop-motion adaptation of The Pied Piper of Hamelin about a plague of rats that punish townsfolk corrupt with greed.  One of the most ambitious Czech animation projects of the 1980s, notable for its unusual dark art direction, innovative animation techniques and use of a fictitious language.',NULL,NULL,1.6336,7.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2247,10502,'tt0107501',NULL,'The Man Without a Face','The Man Without a Face','movie',1993,'https://image.tmdb.org/t/p/w500/9dmH2jc6jwlZo90JQTFOx4XaBWt.jpg','https://image.tmdb.org/t/p/original/eq5mrlYcu142Z8io1bdVPwGxx34.jpg','Justin McLeod is a former teacher who lives as a recluse on the edge of town after his face is disfigured from an automobile accident ten years earlier, in which a boy was incinerated--and for which he was convicted of involuntary manslaughter. Also suspected of being a paedophile, he is befriended by Chuck, causing the town''s suspicions and hostility to be ignited.',NULL,NULL,1.6825,6.556,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2248,64901,'tt0109702',NULL,'Cold Water','L''Eau froide','movie',1994,'https://image.tmdb.org/t/p/w500/7UmbO8A7EVWmv1kpssBzzz9iPrY.jpg','https://image.tmdb.org/t/p/original/wXzqtoBaQONFDgsHkeSZ2TuELoi.jpg','An outer suburb of Paris, 1972. Gilles and Christine, both sixteen, are classmates and lovers who have become frustrated with the aloofness of their families and the general monotony of their lives. When the pair are caught shoplifting, Christine''s father ships her off to a home for emotionally disturbed children, temporarily putting space between her and Gilles. Luckily for them, though, she escapes and the couple contemplate running away together.',NULL,NULL,0.8739,6.3,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2249,70588,'tt1174042',NULL,'The Myth of the American Sleepover','The Myth of the American Sleepover','movie',2011,'https://image.tmdb.org/t/p/w500/6zIu3afpJjz5Js6S7GkDxpCJCYM.jpg','https://image.tmdb.org/t/p/original/g3ssu6APqfJ2z64VEzzZIzK5AY8.jpg','Four young people navigate the suburban wonderland of metro-Detroit looking for love and adventure on the last weekend of summer.',NULL,NULL,0.8912,6.04,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2250,132344,'tt2209418',NULL,'Before Midnight','Before Midnight','movie',2013,'https://image.tmdb.org/t/p/w500/qbGKJmNUroDz75kh5Oafoall89e.jpg','https://image.tmdb.org/t/p/original/crdW75sDNYM0ddjFyrcg6V59qdP.jpg','It has been nine years since we last met Jesse and Celine, the French-American couple who once met on a train in Vienna. They now live in Paris with twin daughters but have spent a summer in Greece at the invitation of an author colleague of Jesse''s. When the vacation is over and Jesse must send his teenage son off to the States, he begins to question his life decisions, and his relationship with Celine is at risk.',NULL,NULL,3.3648,7.493,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2251,597,'tt0120338',NULL,'Titanic','Titanic','movie',1997,'https://image.tmdb.org/t/p/w500/9xjZS2rlVxm8SFx8kPC3aIGCOYQ.jpg','https://image.tmdb.org/t/p/original/xnHVX37XZEp33hhCbYlQFq7ux1J.jpg','101-year-old Rose DeWitt Bukater tells the story of her life aboard the Titanic, 84 years later. A young Rose boards the ship with her mother and fiancé. Meanwhile, Jack Dawson and Fabrizio De Rossi win third-class tickets aboard the ship. Rose tells the whole story from Titanic''s departure through to its death—on its first and last voyage—on April 15, 1912.',NULL,NULL,36.6551,7.903,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2252,1059073,'tt24515124',NULL,'Winter Spring Summer or Fall','Winter Spring Summer or Fall','movie',2024,'https://image.tmdb.org/t/p/w500/mEPi5ISa5RmzpzeDfwkhX0CcNsf.jpg','https://image.tmdb.org/t/p/original/6GGsUgmef5MIfJnnp2fGvkFWRg6.jpg','Remi and Barnes, two very different teenagers, meet by chance in the winter of their senior year, then spend four  days together over the course of a year that will change their lives forever.',NULL,NULL,2.409,7.243,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2253,14553,'tt0117737',NULL,'Stealing Beauty','Stealing Beauty','movie',1996,'https://image.tmdb.org/t/p/w500/5ugxnyVmBK952bwOcE4M0szNimx.jpg','https://image.tmdb.org/t/p/original/bJFapHYlJIhXpfqH8uaNLtUxHwD.jpg','Lucy Harmon, an American teenager is arriving in the lush Tuscan countryside to be sculpted by a family friend who lives in a beautiful villa. Lucy visited there four years earlier and exchanged a kiss with an Italian boy with whom she hopes to become reacquainted.',NULL,NULL,3.0464,6.7,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2254,286565,'tt3622592',NULL,'Paper Towns','Paper Towns','movie',2015,'https://image.tmdb.org/t/p/w500/lVW67w7eWwmBhbBCc4f983pO8m6.jpg','https://image.tmdb.org/t/p/original/mwoIzHsliirmS0IlSrf2DvVouid.jpg','Quentin Jacobsen has spent a lifetime loving the magnificently adventurous Margo Roth Spiegelman from afar. So when she cracks open a window and climbs back into his life dressed like a ninja and summoning him for an ingenious campaign of revenge, he follows. After their all-nighter ends and a new day breaks, Quentin arrives at school to discover that Margo, always an enigma, has now become a mystery. But Quentin soon learns that there are clues, and they''re for him. Urged down a disconnected path, the closer Quentin gets, the less he sees of the girl he thought he knew.',NULL,NULL,2.4543,6.154,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2255,10442,'tt0108174',NULL,'So I Married an Axe Murderer','So I Married an Axe Murderer','movie',1993,'https://image.tmdb.org/t/p/w500/zQlpQDKDADKlgqfMs1E191ofDJU.jpg','https://image.tmdb.org/t/p/original/iVweNwFhEtlJlPxOkaDh8VboE9b.jpg','Just after a bad breakup, Charlie MacKenzie falls for lovely butcher Harriet Michaels and introduces her to his parents. But, as voracious consumers of sensational tabloids, his parents soon come to suspect that Harriet is actually a notorious serial killer -- "Mrs. X" -- wanted in connection with a string of bizarre honeymoon killings. Thinking his parents foolish, Charlie proposes to Harriet. But while on his honeymoon with her, he begins to fear they were right.',NULL,NULL,1.8286,6.11,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2256,14832,'tt0106535',NULL,'The Cement Garden','The Cement Garden','movie',1993,'https://image.tmdb.org/t/p/w500/dnEoE3tHBStCXZx2i9qsUYkwucu.jpg','https://image.tmdb.org/t/p/original/WQdxfSioBfSK6fHZxkE8feciMl.jpg','After the death of her husband, the mother of Julie, Jack, Sue and Tom begins to suffer from a mysterious illness. Aware that she is going to have to go into hospital she opens a bank account for the children, so that they can be financially self-sufficient and will be able to avoid being taken into care by the authorities. Unfortunately she also dies and Julie and Jack (the older, teenage children) decide to hide her body in the basement so that they can have free reign of their household. Soon Tom has taken to dressing as a girl whilst Sue has become increasingly reticent, confiding only to her diary, meanwhile Jack and Julie sense an attraction developing for each other. However Julie''s new beau, Derek, threatens to unearth the many dark secrets within this family as he becomes increasingly suspicious of Jack.',NULL,NULL,2.8927,6.759,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2257,11457,'tt0264796',NULL,'Life as a House','Life as a House','movie',2001,'https://image.tmdb.org/t/p/w500/qNFlcei9vWh5NCRTVrs52qDvUmq.jpg','https://image.tmdb.org/t/p/original/cq0xYG4TIcEPaFPhkgTpDhWLIqo.jpg','When a man is diagnosed with terminal cancer, he takes custody of his misanthropic teenage son, for whom quality time means getting high, engaging in small-time prostitution, and avoiding his father.',NULL,NULL,1.4265,7.1,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2258,55347,'tt1532503',NULL,'Beginners','Beginners','movie',2011,'https://image.tmdb.org/t/p/w500/mAquHAmoBgZ1omUNdNsnGVNX74c.jpg','https://image.tmdb.org/t/p/original/7zEbI6E4dfpDBAEivZYR1tPID5w.jpg','Oliver meets the irreverent and unpredictable Anna only months after his father Hal Fields has passed away. This new love floods Oliver with memories of his father, who, following the death of his wife of 44 years, came out of the closet at age 75 to live a full, energized, and wonderfully tumultuous gay life – which included a younger boyfriend.',NULL,NULL,2.3019,6.838,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2259,900379,'tt26440619',NULL,'Afire','Roter Himmel','movie',2023,'https://image.tmdb.org/t/p/w500/k8NYzD01zAUsdqocjhLXbO9BSS8.jpg','https://image.tmdb.org/t/p/original/wbW4w4HvvzDavQCjUKtLMosyNn5.jpg','Self-important author Leon joins his best friend on a summer holiday near the Baltic Sea to complete his novel. When they arrive, they find their house is already occupied by a carefree woman who challenges Leon to open up. Meanwhile, forest wildfires rage around them and impending disaster looms.',NULL,NULL,1.2373,6.773,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2260,1156110,'tt28494031',NULL,'Gasoline Rainbow','Gasoline Rainbow','movie',2024,'https://image.tmdb.org/t/p/w500/3wZPMKCrL4jwpAMWgQQoV75VaU.jpg','https://image.tmdb.org/t/p/original/xXU9yITHVQUHwkgLBlzenF7Dq7L.jpg','With high school in the rearview, five teenagers from inland Oregon embark on one last adventure. Piling into a van with a busted tail light, their mission takes them to a place they’ve never been—the Pacific coast, five hundred miles away. Their plan, in full: “Fuck it.”',NULL,NULL,0.2409,5.9,0,10.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2261,708260,'tt0172536',NULL,'Happy End','Happy end','movie',1958,'https://image.tmdb.org/t/p/w500/8o9OGSy09xiDTkm7Lc0kbb2vOLg.jpg','https://image.tmdb.org/t/p/original/U1L5ykQybVY00OG9Zu2hn3Umse.jpg','After destruction of the world, life returns slowly and in convulsions. The being finds its home on the exact place where it was before the catastrophe, and this is the happy end.',NULL,NULL,0.1452,9.0,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2262,1555,'tt0283900',NULL,'The Spanish Apartment','L''Auberge espagnole','movie',2002,'https://image.tmdb.org/t/p/w500/baDm4V3Dqx2hNh7WF1NvGrHGgqQ.jpg','https://image.tmdb.org/t/p/original/kiSderXBFLpkSp7dZ5RQkHOD5nh.jpg','A strait-laced French student moves into an apartment in Barcelona with a cast of six other characters from all over Europe. Together, they speak the international language of love and friendship.',NULL,NULL,1.9785,7.12,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2263,376386,'tt5146068',NULL,'All These Sleepless Nights','Wszystkie nieprzespane noce','movie',2016,'https://image.tmdb.org/t/p/w500/fvvJW25w6ooWAnBHdA9QBIm6J35.jpg','https://image.tmdb.org/t/p/original/akZPui8RjkyIaglxLwnywczrOYK.jpg','What does it mean to be awake in a world that seems satisfied to be asleep? Kris and Michal push their experiences of life and love to a breaking point as they restlessly roam the city streets in search of answers, adrift in the euphoria and uncertainty of youth.',NULL,NULL,1.2376,6.3,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2264,1341615,'tt33308220',NULL,'A Bird Hit My Window and Now I''m a Lesbian','A Bird Hit My Window and Now I''m a Lesbian','movie',2024,'https://image.tmdb.org/t/p/w500/2EpACTGWvjQpqioDgJXaIQEF0A6.jpg','https://image.tmdb.org/t/p/original/a8qZpgy0ZhdMSK5Pex6V4oKzr1F.jpg','After a mysterious stranger shows up at Gray''s doorstep holding the corpse of a dead bird, an impromptu funeral changes the way Gray views herself and her lesbian identity.',NULL,NULL,0.4507,8.2,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2265,75233,'tt1736633',NULL,'Oslo, August 31st','Oslo, 31. august','movie',2011,'https://image.tmdb.org/t/p/w500/a9WUrw5Dkl8mumi2YlOlpt2f5Dc.jpg','https://image.tmdb.org/t/p/original/1gLqb2IjIer0xYTT5GhLzi7CtjC.jpg','A recovering drug addict is granted a day’s leave from rehab and returns to Oslo, where he reconnects with friends, faces the weight of his past, and struggles with uncertainty about his future. Over the course of one day, he drifts through encounters that reflect his longing for connection and his deep sense of alienation.',NULL,NULL,1.7552,7.493,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2266,3784,'tt0101912',NULL,'Frankie and Johnny','Frankie and Johnny','movie',1991,'https://image.tmdb.org/t/p/w500/zSOh7hriX4mQNVxhCz1yVY4aykn.jpg','https://image.tmdb.org/t/p/original/mXn2VhwaRKAKahulvqLdM5i3t7D.jpg','When Johnny is released from prison following a forgery charge, he quickly lands a job as a short-order cook at a New York diner. Following a brief fling with waitress Cora, he develops an attraction for Cora''s friend and fellow waitress Frankie. While Frankie resists Johnny''s charms initially, she eventually relents when her best friend, Tim, persuades her to give Johnny a chance.',NULL,NULL,2.4041,6.8,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2267,48650,'tt1263750',NULL,'Room in Rome','Habitación en Roma','movie',2010,'https://image.tmdb.org/t/p/w500/w90ItYf9qagQKVEBr1uFxPomAtf.jpg','https://image.tmdb.org/t/p/original/abQxLSkGxpHyUxRjRXACt8NbiGf.jpg','A hotel room in the center of Rome serves as the setting for Alba and Natasha, two sexy and recently acquainted women, to have a physical adventure that touches their very souls.',NULL,NULL,23.3085,6.41,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2268,75282,'tt1823744',NULL,'Scenes from the Suburbs','Scenes from the Suburbs','movie',2011,'https://image.tmdb.org/t/p/w500/jNuNlM4Pwp5Uc23GJ5hj2JLd3io.jpg','https://image.tmdb.org/t/p/original/n5EzfQt7BJIR0LqtwajzgCcDmAv.jpg','A resident of a suburban dystopia tries to reassemble his fragmented memories of life as a teen.',NULL,NULL,0.4412,6.8,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2269,81661,'tt1516593',NULL,'Tilva Ros','Tilva Roš','movie',2011,'https://image.tmdb.org/t/p/w500/1AJYzDk22n1eil3yyNmfGADDJ8G.jpg','https://image.tmdb.org/t/p/original/79j2EJTZdE92UAUsVu2aTSA65oU.jpg','Bor, in eastern Serbia, was once home to the largest copper mine in Europe. Now it’s just the biggest hole. This astutely observed coming-of-age film captures the pitfalls of the adult world, where idealism no longer seems to have a place, as two teens come to realize they have no choice but to grow up.',NULL,NULL,0.1956,5.8,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2270,18923,'tt0359423',NULL,'A Home at the End of the World','A Home at the End of the World','movie',2004,'https://image.tmdb.org/t/p/w500/o1YC1V30LR0LJzGR6JtbzpDSTYy.jpg','https://image.tmdb.org/t/p/original/qTpL1GZVXClosHDpEmlrZnyBNrG.jpg','Three friends form a bond over the year, Johnathan is gay, Clare is straight and Bobby is neither, instead he loves the people he loves. As their lives go on there is tension and tears which culminate in a strong yet fragile friendship between the three.',NULL,NULL,0.9058,6.4,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2271,330947,'tt2062700',NULL,'Song to Song','Song to Song','movie',2017,'https://image.tmdb.org/t/p/w500/itmaNi14GyWguTOywZ0mMzyScW9.jpg','https://image.tmdb.org/t/p/original/4fj9pWyIA3I2TxXXfXFRfIPbX0a.jpg','In this modern love story set against the Austin, Texas music scene, two entangled couples — struggling songwriters Faye and BV, and music mogul Cook and the waitress whom he ensnares — chase success through a rock ‘n’ roll landscape of seduction and betrayal.',NULL,NULL,2.0029,5.482,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2272,103328,'tt2076220',NULL,'Holy Motors','Holy Motors','movie',2012,'https://image.tmdb.org/t/p/w500/4ZuTrrDQhCS9f6KzIX6HfsjjyMd.jpg','https://image.tmdb.org/t/p/original/dCuwNZp2DLOWr8qV0GDBHINhVZM.jpg','We follow 24 hours in the life of a being moving from life to life like a cold and solitary assassin moving from hit to hit. In each of these interwoven lives, the being possesses an entirely distinct identity: sometimes a man, sometimes a woman, sometimes youthful, sometimes old. By turns murderer, beggar, company chairman, monstrous creature, worker, family man.',NULL,NULL,5.382,7.0,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2273,107985,'tt1213663',NULL,'The World''s End','The World''s End','movie',2013,'https://image.tmdb.org/t/p/w500/kpglnOBYmKn0AkkWDzGxzKHDbds.jpg','https://image.tmdb.org/t/p/original/stAPkorBeBkvEZ6DQs30Ke4cPyr.jpg','Five friends who reunite in an attempt to top their epic pub crawl from 20 years earlier unwittingly become humankind''s only hope for survival.',NULL,NULL,5.764,6.811,0,1.20466666666666668e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2274,80035,'tt1298649',NULL,'The Watch','The Watch','movie',2012,'https://image.tmdb.org/t/p/w500/gwfgYA9wGpV4QLB0LrcexwfwC19.jpg','https://image.tmdb.org/t/p/original/iQkWo6MQ1pDxbZQ0DNxwW5J3Ysk.jpg','Four everyday suburban guys come together as an excuse to escape their humdrum lives one night a week. But when they accidentally discover that their town has become overrun with aliens posing as ordinary suburbanites, they have no choice but to save their neighborhood – and the world – from total extermination.',NULL,NULL,2.5285,5.6,0,9.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2275,567971,'tt8976576',NULL,'Vampires vs. the Bronx','Vampires vs. the Bronx','movie',2020,'https://image.tmdb.org/t/p/w500/rcdBUbbYNccz8q9LOuBEKC1avMA.jpg','https://image.tmdb.org/t/p/original/onpWnO4mJsHSFBXYRBf48t9tipk.jpg','Three gutsy kids from a rapidly gentrifying Bronx neighborhood stumble upon a sinister plot to suck all the life from their beloved community.',NULL,NULL,1.469,5.722,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2276,755,'tt0116367',NULL,'From Dusk Till Dawn','From Dusk Till Dawn','movie',1996,'https://image.tmdb.org/t/p/w500/sV3kIAmvJ9tPz4Lq5fuf9LLMxte.jpg','https://image.tmdb.org/t/p/original/phiRQhfwZZeMMn3osvQUmGYmJbp.jpg','After kidnapping a father and his two kids, the Gecko brothers head south to a seedy Mexican bar to hide out in safety, unaware of its notorious clientele.',NULL,NULL,11.2743,7.044,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2277,77174,'tt1623288',NULL,'ParaNorman','ParaNorman','movie',2012,'https://image.tmdb.org/t/p/w500/9DZPtuYTKYxt6vzHvZ5FLThG4fl.jpg','https://image.tmdb.org/t/p/original/fRhpdmaA1wTAboeiKW2ZHvDezIm.jpg','In the town of Blithe Hollow, Norman Babcock can speak to the dead, but no one other than his eccentric new friend believes his ability is real. One day, Norman''s eccentric uncle tells him of a ritual he must perform to protect the town from a curse cast by a witch centuries ago.',NULL,NULL,6.1478,7.046,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2278,461928,'tt6433880',NULL,'Anna and the Apocalypse','Anna and the Apocalypse','movie',2018,'https://image.tmdb.org/t/p/w500/jVyqqMzDVRjUMeIoaJKSUpRnB9Y.jpg','https://image.tmdb.org/t/p/original/7GR03LqwB7ePPPhaK5BAYNzt3Vm.jpg','A zombie apocalypse threatens the sleepy town of Little Haven—at Christmas—forcing Anna and her friends to fight, slash, and sing their way to survival. In a desperate race to reach their loved ones, they soon learn that no one is safe in this new world, and with civilization falling apart around them, the only people they can truly rely on are each other.',NULL,NULL,1.4111,6.014,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2279,84204,'tt1525366',NULL,'Grabbers','Grabbers','movie',2012,'https://image.tmdb.org/t/p/w500/n1CkFfuDCh4NDZgaXmyna3V0Hxc.jpg','https://image.tmdb.org/t/p/original/5GI1MueBPswWnFs7nqTeMS8tL7V.jpg','Something sinister has come to the shores of Erin Island, unbeknownst to the quaint population of this sleepy fishing village resting somewhere off Ireland’s coast. First, some fishermen go missing. Then there is the rash of whale carcasses suddenly washing up on the beach. When the murders start, it’s up to two mismatched cops – an irresponsible alcoholic and his new partner, a by-the-book woman from the mainland – to protect the townsfolk from the giant, bloodsucking, tentacled aliens that prey upon them. Their only weapon, they discover, is booze. If they want to survive the creatures’ onslaught, everyone will have to get very, very drunk!',NULL,NULL,1.4847,6.092,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2280,21159,'tt0058700',NULL,'The Last Man on Earth','The Last Man on Earth','movie',1964,'https://image.tmdb.org/t/p/w500/m0zIz963wNxAqqxiKYdZS9cRScT.jpg','https://image.tmdb.org/t/p/original/2peNKd9nJkGUofBRhS9LYPTcXnz.jpg','When a disease turns all of humanity into the living dead, the last man on earth becomes a reluctant vampire hunter.',NULL,NULL,1.9917,6.592,0,6.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2281,9362,'tt0100814',NULL,'Tremors','Tremors','movie',1990,'https://image.tmdb.org/t/p/w500/cA4ggkZ3r1d5r9hOAUWC8x5ul2i.jpg','https://image.tmdb.org/t/p/original/ojVlJoGsysPmdmLrIbGW7ljn7JH.jpg','Val McKee and Earl Bassett are in a fight for their lives when they discover that their desolate town has been infested with gigantic, man-eating creatures that live below the ground.',NULL,NULL,5.5538,6.938,0,10.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2282,13954,'tt0996979',NULL,'Alien Raiders','Alien Raiders','movie',2008,'https://image.tmdb.org/t/p/w500/gBz8ueJSWIVwB3LO80BiuUFpiWY.jpg','https://image.tmdb.org/t/p/original/yn8KXHXI6KTyJzTCpqPVei8NF4q.jpg','It''s the end of yet another night at Hastings Supermarket, a grocery store in Buck Lake, Arizona. But just before closing, a group of masked and armed to the teeth militants invades the store and take everyone hostage',NULL,NULL,1.1176,5.391,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2283,6488,'tt0099052',NULL,'Arachnophobia','Arachnophobia','movie',1990,'https://image.tmdb.org/t/p/w500/lHjpwv1Yv2RcGcTQb4Lc1cKw1y9.jpg','https://image.tmdb.org/t/p/original/CTcfWsVAw524RZwIqb1DhokhRU.jpg','A large spider from the jungles of South America is accidentally transported in a crate with a dead body to America where it mates with a local spider. Soon after, the residents of a small California town disappear as the result of spider bites from the deadly spider offspring. It''s up to a couple of doctors with the help of an insect exterminator to annihilate these eight legged freaks.',NULL,NULL,1.6585,6.448,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2284,501929,'tt7979580',NULL,'The Mitchells vs. the Machines','The Mitchells vs. the Machines','movie',2021,'https://image.tmdb.org/t/p/w500/mI2Di7HmskQQ34kz0iau6J1vr70.jpg','https://image.tmdb.org/t/p/original/vsZLf5uog08pAnfsMuDWrsLWUUF.jpg','A quirky, dysfunctional family''s road trip is upended when they find themselves in the middle of the robot apocalypse and suddenly become humanity''s unlikeliest last hope.',NULL,NULL,7.5295,7.835,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2285,3980,'tt0090887',NULL,'Critters','Critters','movie',1986,'https://image.tmdb.org/t/p/w500/dxBy4WePZY06Bk5KvXb4K3UnjCy.jpg','https://image.tmdb.org/t/p/original/omoQkyiQ94FfyR4gUmA66VXQyZ9.jpg','Carnivorous aliens arrive unannounced at a Kansas family farm; two intergalactic bounty hunters soon follow, determined to blow them off the planet.',NULL,NULL,3.8658,6.492,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2286,10127,'tt0094919',NULL,'Critters 2','Critters 2','movie',1988,'https://image.tmdb.org/t/p/w500/5rR3dVJXnXskkBBWKbLg5EDKWtT.jpg','https://image.tmdb.org/t/p/original/vke5tKoDCB117w2mrWWOalUsXRD.jpg','Three bounty hunters from space fly back to the town of Grovers Bend, hoping to save local residents from a new batch of Critter eggs.',NULL,NULL,2.8869,6.3,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2287,10177,'tt0383353',NULL,'Evil Aliens','Evil Aliens','movie',2006,'https://image.tmdb.org/t/p/w500/rSGYrrua4QoyXPhic6GvxgdQFb8.jpg','https://image.tmdb.org/t/p/original/si4hR3wG5RuFsqLANYFVoDpt2lq.jpg','The sensationalist reporter Michelle Fox presents the TV show Weird World, with phony matters about UFOS and aliens. When she hears about Cat, a young woman that claims that have been abducted with her boyfriend and become pregnant by aliens, she convinces her chief to travel with a team to the remote Welsh island of Scalled to interview Cat. She invites the cameraman Ricky Anderson with his sound technician partner; the nerd expert in "ufology" and "ley lines" Gavin Gorman; the actress Candy Vixen and an obscure gay actor to prepare the matter. They get a van and wait for the low tide to reach the island, and when they find evidences that aliens are really landed in the location, the ambitious Michelle decides to film her way to fame and wealth.',NULL,NULL,1.7473,5.061,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2288,8869,'tt0271367',NULL,'Eight Legged Freaks','Eight Legged Freaks','movie',2002,'https://image.tmdb.org/t/p/w500/5blAumPPS6vX6zcUlt9oIhOEheK.jpg','https://image.tmdb.org/t/p/original/hOVtpgal5wWHP8vDczrEzZXkOEV.jpg','The residents of a rural mining town discover that an unfortunate chemical spill has caused hundreds of little spiders to mutate overnight to the size of SUVs. It''s then up to mining engineer Chris McCormack and Sheriff Sam Parker to mobilize an eclectic group of townspeople, including the Sheriff''s young son, Mike, her daughter, Ashley, and paranoid radio announcer Harlan, into battle against the bloodthirsty eight-legged beasts.',NULL,NULL,4.0906,5.807,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2289,49849,'tt0409847',NULL,'Cowboys & Aliens','Cowboys & Aliens','movie',2011,'https://image.tmdb.org/t/p/w500/9uZsGCP4rvOHVGCpMpYq5gNCuNI.jpg','https://image.tmdb.org/t/p/original/sGXCYMzr1sCnGNVuRpB2TOWPWDA.jpg','A stranger stumbles into the desert town of Absolution with no memory of his past and a futuristic shackle around his wrist. With the help of mysterious beauty Ella and the iron-fisted Colonel Dolarhyde, he finds himself leading an unlikely posse of cowboys, outlaws, and Apache warriors against a common enemy from beyond this world in an epic showdown for survival.',NULL,NULL,7.4974,5.69,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2290,24736,'tt0106868',NULL,'A Far Off Place','A Far Off Place','movie',1993,'https://image.tmdb.org/t/p/w500/uVTs2cUYgeGkdiPoszBOjFXqvNd.jpg','https://image.tmdb.org/t/p/original/2eVkfAVFezj31dsfKaJl7sHRRyb.jpg','Thrown together under incredible circumstances, two strangers must discover courage and strength when they begin a journey across the treacherous African desert! Equipped only with their wits and the expertise of a native bushman who befriends them, they are determined to triumph over impossible odds and reach their destination. But along the way, the trio face a primitive desert wilderness.',NULL,NULL,1.0772,6.2,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2291,7364,'tt0318649',NULL,'Sahara','Sahara','movie',2005,'https://image.tmdb.org/t/p/w500/kyY1onYxkKBDlJsheRsVbMaoQEM.jpg','https://image.tmdb.org/t/p/original/CXQ9wYj4n9MBwy2TQ92YaRygWj.jpg','Seasoned adventurer and treasure hunter Dirk Pitt, a former Navy SEAL, sets out for the African desert with his wisecracking buddy Al in search of a confederate ironclad battleship rumored to have vanished long ago, the main draw being the treasure supposedly hidden within the lost vessel. When the daring duo come across Dr. Eva Rojas, a beautiful scientist who is juggling an escape from a warlord and a mission to stop the spread of a powerful plague, their desert expedition begins to heat up.',NULL,NULL,3.6313,5.916,0,10.55,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2292,409,'tt0116209',NULL,'The English Patient','The English Patient','movie',1996,'https://image.tmdb.org/t/p/w500/8eHHqMg8qEYtVw8LQLygsHXSR2q.jpg','https://image.tmdb.org/t/p/original/em5kAUF8QbwThG5BCqVgFomxNT5.jpg','In the 1930s, Count Almásy is a Hungarian map maker employed by the Royal Geographical Society to chart the vast expanses of the Sahara Desert along with several other prominent explorers. As World War II unfolds, Almásy enters into a world of love, betrayal, and politics.',NULL,NULL,4.0165,7.147,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2293,29244,'tt0040064',NULL,'3 Godfathers','3 Godfathers','movie',1948,'https://image.tmdb.org/t/p/w500/dsVrYIpK2Rcgsr5QrfjBQWee5JE.jpg','https://image.tmdb.org/t/p/original/vkDqTAQdBvtABEA43Kt8hAdD5K3.jpg','Three outlaws on the run discover a dying woman and her baby. They swear to bring the infant to safety across the desert, even at the risk of their own lives.',NULL,NULL,3.8934,6.8,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2294,805682,'tt13964404',NULL,'Horror in the High Desert','Horror in the High Desert','movie',2021,'https://image.tmdb.org/t/p/w500/s1D5ZGgbxVgQHw70CDwYZQbvaBT.jpg','https://image.tmdb.org/t/p/original/uBgSDdFwHo3wrWtSTaLK5ehNV34.jpg','In July 2017, an experienced outdoor enthusiast vanished in Northern Nevada while on an outdoor excursion. After an extensive search, he was never located. On the three-year anniversary of his disappearance, friends and loved ones recall the events leading up to his vanishing, and for the first time, speak about the horrifying conclusion of his fate.',NULL,NULL,0.6388,5.812,0,8.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2295,24016,'tt0100594',NULL,'The Sheltering Sky','The Sheltering Sky','movie',1990,'https://image.tmdb.org/t/p/w500/mcaypmWykltQMLjjSuD2vxylZHV.jpg','https://image.tmdb.org/t/p/original/27nvfP0Y7cBP2Bd7ewqv90HZltq.jpg','An American couple drift toward emptiness in postwar North Africa.',NULL,NULL,1.5705,6.5,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2296,437586,'tt5613484',NULL,'mid90s','mid90s','movie',2018,'https://image.tmdb.org/t/p/w500/9Tw0Y3DK5kGIU9X1yw3Q9gCkOlb.jpg','https://image.tmdb.org/t/p/original/BOeORWljjIPGuCwUgLls24ctF3.jpg','In 1990s Los Angeles, a 13-year-old spends his summer navigating between a troubled home life and a crew of new friends he meets at a skate shop.',NULL,NULL,2.5455,7.457,0,13.1025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2297,681355,'tt11165716',NULL,'North Hollywood','North Hollywood','movie',2021,'https://image.tmdb.org/t/p/w500/rLVxpEkiSs8OnOqg8QmLT7Bs09e.jpg','https://image.tmdb.org/t/p/original/yAk1PpHMG6BY6ABlpWAXPyKZDmy.jpg','A kid must decide between choosing the future his father wants and following his dream of becoming a pro skater.',NULL,NULL,1.0433,5.304,0,8.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2298,489985,'tt7476236',NULL,'Minding the Gap','Minding the Gap','movie',2018,'https://image.tmdb.org/t/p/w500/uOu2YgrryHD1UlngykzTodAxGdC.jpg','https://image.tmdb.org/t/p/original/wXsDDQ4JEdvzL19DUsbsKzlPq9f.jpg','Three young men bond together to escape volatile families in their Rust Belt hometown. As they face adult responsibilities, unexpected revelations threaten their decade-long friendship.',NULL,NULL,0.5453,7.703,0,11.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2299,84231,'tt7765404',NULL,'Wayne','Wayne','tv',2019,'https://image.tmdb.org/t/p/w500/z8E1ZKTDhz477wjkT9ttIRmiVOc.jpg','https://image.tmdb.org/t/p/original/5LTKU79rIPu8ivXJhR6rSyj6t8w.jpg','In this gritty and sometimes bloody tale, sixteen year-old Wayne sets out on a dirt bike with his new crush Del to take back the 1978 Pontiac Trans Am that was stolen from his father before he died. It is Wayne and Del against the world.',NULL,NULL,4.5894,8.259,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2300,1282,'tt0275309',NULL,'Dogtown and Z-Boys','Dogtown and Z-Boys','movie',2002,'https://image.tmdb.org/t/p/w500/eb02dpopuAhuThf7nXAAwKtAF88.jpg','https://image.tmdb.org/t/p/original/ex21uMbWeAEju9QUAhkAqtfAgaO.jpg','This award-winning, thrilling story is about a group of discarded kids who revolutionized skateboarding and shaped the attitude and culture of modern day extreme sports. Featuring old skool skating footage, exclusive interviews and a blistering rock soundtrack, DOGTOWN AND Z-BOYS captures the rise of the Zephyr skateboarding team from Venice''s Dogtown, a tough "locals only" beach with a legacy of outlaw surfing.',NULL,NULL,1.3251,7.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2301,42847,'tt0378720',NULL,'Powell Peralta: The Search for Animal Chin','Powell Peralta: The Search for Animal Chin','movie',1987,'https://image.tmdb.org/t/p/w500/vK2fr7P6HwdR0EyiiXzoQs6W58X.jpg','https://image.tmdb.org/t/p/original/1ufl8gZT77omGSiRoRkGBu6yn3i.jpg','Bones Brigade Video III. The Bones Brigade travels around California, Nevada, and Hawaii to different skate spots in search of a wizened old man, Won Ton "Animal" Chin.',NULL,NULL,0.3355,7.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2302,23470,'tt0108258',NULL,'Surf Ninjas','Surf Ninjas','movie',1993,'https://image.tmdb.org/t/p/w500/4Xn0CBDAGADHc62MEGmFYcbhU1E.jpg','https://image.tmdb.org/t/p/original/fUQXMXd6M54dPYjlBzvQ4v6fkcf.jpg','Two Asian-American "surfer-dude" brothers discover they are the long lost princes from a China Sea Island. Part of their inheritance includes magically-induced martial arts prowess and seeing the future. Using their new powers, they act to overthrow the island''s current dictator, a despotic madman with a metal face!',NULL,NULL,1.3807,5.0,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2303,16314,'tt0103596',NULL,'3 Ninjas','3 Ninjas','movie',1992,'https://image.tmdb.org/t/p/w500/kJjhmLG9eJWVZrKimZ6kCrQ0urF.jpg','https://image.tmdb.org/t/p/original/qoSIw7XPwpbo5p3WuQoc5AvKZ4.jpg','Each year, three brothers Samuel, Jeffrey and Michael Douglas visits their Japanese grandfather, Mori Shintaro whom the boys affectionately refer to as Grandpa, for the summer. Mori is a highly skilled in the fields of Martial arts and Ninjutsu, and for years he has trained the boys in his techniques. After an organized crime ring proves to be too much for the FBI, it''s time for the 3 brother NINJAS! To use their martial arts skills, they team up to battle the crime ring and outwit some very persistent kidnappers!',NULL,NULL,3.5391,5.679,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2304,17343,'tt0066380',NULL,'Vampyros Lesbos','Vampyros Lesbos','movie',1971,'https://image.tmdb.org/t/p/w500/qaZc7veACx1vmq6tZtnIT6vLmxM.jpg','https://image.tmdb.org/t/p/original/mQvyxrbSIadB30lHGVjOGrxBJq7.jpg','An erotic horror tale about a vixen vampiress seducing and killing women to appease her insatiable thirst for female blood.',NULL,NULL,2.7067,5.7,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2305,22536,'tt0762073',NULL,'Thirst','박쥐','movie',2009,'https://image.tmdb.org/t/p/w500/sBnFQwOcmL3dAIYfiQ9nLvLSW7B.jpg','https://image.tmdb.org/t/p/original/9IMZqBKbALO7d2bwr6ECKP4igoe.jpg','A respected priest volunteers for an experimental procedure that may lead to a cure for a deadly virus. He gets infected and dies, but a blood transfusion of unknown origin brings him back to life. Now, he’s torn between faith and bloodlust, and has a newfound desire for the wife of a childhood friend.',NULL,NULL,2.6797,7.116,0,11.775,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2306,9463,'tt0090248',NULL,'Vampire Hunter D','バンパイアハンターD','movie',1985,'https://image.tmdb.org/t/p/w500/5Ni9RhIs6cLUrBLwdrqZ2fUFimS.jpg','https://image.tmdb.org/t/p/original/1zs8iKZMKrtIh2MulIwwU6Gs9EK.jpg','In a far-future time ruled by the supernatural, a young girl requests the help of a vampire hunter to kill the vampire who has bitten her and thus prevent her from becoming a vampire herself.',NULL,NULL,2.5593,6.6,0,12.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2307,NULL,NULL,119133,'Elden Ring','Elden Ring','game',2022,'https://images.igdb.com/igdb/image/upload/t_cover_big/co4jni.jpg',NULL,'Elden Ring is an action RPG developed by FromSoftware and published by Bandai Namco Entertainment, released in February 2022. Directed by Hidetaka Miyazaki, with world-building contributions from novelist George R. R. Martin, the game features an expansive open world called the Lands Between. Players assume the role of a customisable character known as the Tarnished, who must explore this world, battle formidable enemies, and seek to restore the Elden Ring to become the Elden Lord.

The game builds on the challenging gameplay mechanics familiar from the Dark Souls series but introduces a more open-ended structure with vast exploration, dynamic weather, and a day-night cycle. It offers deep lore, complex characters, and an interconnected world filled with secrets, dungeons, and powerful bosses.','https://www.igdb.com/games/elden-ring','["Xbox Series X|S", "PlayStation 4", "Nintendo Switch 2", "PC (Microsoft Windows)", "PlayStation 5", "Xbox One"]',NULL,NULL,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2308,94997,'tt11198330',NULL,'House of the Dragon','House of the Dragon','tv',2022,'https://image.tmdb.org/t/p/w500/7V0Ebks0GgpKvQ7QbLAIdX5dos4.jpg','https://image.tmdb.org/t/p/original/577eXC8wFQT0eUrJcgznSiFPRmk.jpg','The Targaryen dynasty is at the absolute apex of its power, with more than 15 dragons under their yoke. Most empires crumble from such heights. In the case of the Targaryens, their slow fall begins when King Viserys breaks with a century of tradition by naming his daughter Rhaenyra heir to the Iron Throne. But when Viserys later fathers a son, the court is shocked when Rhaenyra retains her status as his heir, and seeds of division sow friction across the realm.',NULL,NULL,471.224,8.373,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2309,25904,'tt0063278',NULL,'Marketa Lazarová','Marketa Lazarová','movie',1967,'https://image.tmdb.org/t/p/w500/c16ArEPUqb0RdUyZBH6fnO7ZiLL.jpg','https://image.tmdb.org/t/p/original/1Vbd0TVNZXlzTlyLkYnOMzpq1eH.jpg','Mikolás and his brother Adam end up with a young German hostage of noble blood during a robbery. While their clan prepares for the wrath of the German king, Mikolás is sent to pressure his neighbor Lazar into a defense pact. Persuasion fails and he abducts Lazar''s daughter Marketa on the eve of her initiation as a nun in an act of vengeance.',NULL,NULL,2.0835,7.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2310,28162,'tt0038733',NULL,'A Matter of Life and Death','A Matter of Life and Death','movie',1946,'https://image.tmdb.org/t/p/w500/H74LWKnhOeIFSk9gNjBcPjIov3.jpg','https://image.tmdb.org/t/p/original/bY7DvsYsAODykqUJfkPZA3BHKOd.jpg','A British wartime aviator who cheats death must argue for his life before a celestial court, hoping to prolong his fledgling romance with an American girl.',NULL,NULL,2.0794,7.8,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2311,19542,'tt0040725',NULL,'The Red Shoes','The Red Shoes','movie',1948,'https://image.tmdb.org/t/p/w500/vPvpBWFWDvEXuQBkoYgA6A89GVp.jpg','https://image.tmdb.org/t/p/original/cSbBSHHiy849SUhyTW6FX4Dbj43.jpg','A fledgling ballerina falls in love with a brilliant composer, but the jealous head of the ballet company plots to drive them apart.',NULL,NULL,2.5207,8.0,0,13.6475,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2312,330457,'tt4520988',NULL,'Frozen II','Frozen II','movie',2019,'https://image.tmdb.org/t/p/w500/mINJaa34MtknCYl5AjtNJzWj8cD.jpg','https://image.tmdb.org/t/p/original/AoSZyb37ljMAxw0RdeQEBHKtgcc.jpg','Elsa, Anna, Kristoff and Olaf head far into the forest to learn the truth about an ancient mystery of their kingdom.',NULL,NULL,19.7188,7.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2313,41691,'tt0130414',NULL,'Merlin','Merlin','tv',1998,'https://image.tmdb.org/t/p/w500/ra2F5ufWFV9qDMcZR1VbCfKZO2Z.jpg','https://image.tmdb.org/t/p/original/giHZE0MzQq1gGHCMCKZQtOhWGww.jpg','A retelling of the legend of King Arthur from the perspective of the wizard Merlin. Sam Neill stars in the title role in a story that covers not only the rise and fall of Camelot but also the phase in the legendary history of Britain that precedes it.',NULL,NULL,11.451,6.932,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2314,10882,'tt0053285',NULL,'Sleeping Beauty','Sleeping Beauty','movie',1959,'https://image.tmdb.org/t/p/w500/n3pxoMDDxp10c1smgbDzW4bwlzq.jpg','https://image.tmdb.org/t/p/original/me67dwJnUBt3O9NqZaBdEQ6i4vM.jpg','Cursed to die by the evil fairy Maleficent when she was a baby, Princess Aurora is sent into hiding under protection from three good fairies. As she grows up far away, Maleficent becomes increasingly determined to seal the princess''s fate.',NULL,NULL,8.6265,6.9,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2315,50620,'tt1673434',NULL,'The Twilight Saga: Breaking Dawn - Part 2','The Twilight Saga: Breaking Dawn - Part 2','movie',2012,'https://image.tmdb.org/t/p/w500/7IGdPaKujv0BjI0Zd0m0a4CzEjJ.jpg','https://image.tmdb.org/t/p/original/qkl57wzSFrpi2sRpoc2mZJbMuLP.jpg','After the birth of Renesmee, the Cullens gather other vampire clans in order to protect the child from a false allegation that puts the family in front of the Volturi.',NULL,NULL,10.3429,6.455,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2316,11253,'tt0411477',NULL,'Hellboy II: The Golden Army','Hellboy II: The Golden Army','movie',2008,'https://image.tmdb.org/t/p/w500/zO0Wdrxnhx3KoJEvychSmnY3urC.jpg','https://image.tmdb.org/t/p/original/gqQKxYVIaYv53Qoy72nQqQxdXYF.jpg','Hellboy, his pyrokinetic girlfriend, Liz, and aquatic empath, Abe Sapien, face their biggest battle when an underworld elven prince plans to reclaim Earth for his magical kindred. Tired of living in the shadow of humans, Prince Nuada tries to awaken an ancient force of killing machines, the all-powerful Golden Army, to clear the way for fantasy creatures to roam free. Only Hellboy can stop the dark prince and prevent humanity''s annihilation.',NULL,NULL,5.0493,6.771,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2317,68812,'tt1491044',NULL,'The Iceman','The Iceman','movie',2012,'https://image.tmdb.org/t/p/w500/3edygPSm9XdISHza8zqHUVAQHAD.jpg','https://image.tmdb.org/t/p/original/kqsMRKkwJssTcp9chZzY161KNRO.jpg','The true story of Richard Kuklinski, the notorious contract killer and family man.',NULL,NULL,2.4354,6.553,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2318,39538,'tt1598778',NULL,'Contagion','Contagion','movie',2011,'https://image.tmdb.org/t/p/w500/qL0IooP0bjXy0KXl9KEyPo22ll0.jpg','https://image.tmdb.org/t/p/original/bdmyvEdrmnj7J3RWaKXEOwYggRv.jpg','As an epidemic of a lethal airborne virus - that kills within days - rapidly grows, the worldwide medical community races to find a cure and control the panic that spreads faster than the virus itself.',NULL,NULL,5.3617,6.649,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2319,72190,'tt0816711',NULL,'World War Z','World War Z','movie',2013,'https://image.tmdb.org/t/p/w500/aCnVdvExw6UWSeQfr0tUH3jr4qG.jpg','https://image.tmdb.org/t/p/original/kg2FOT2Oe5PSCgs3L4vLel6B7ck.jpg','Life for former United Nations investigator Gerry Lane and his family seems content. Suddenly, the world is plagued by a mysterious infection turning whole human populations into rampaging mindless zombies. After barely escaping the chaos, Lane is persuaded to go on a mission to investigate this disease. What follows is a perilous trek around the world where Lane must brave horrific dangers and long odds to find answers before human civilization falls.',NULL,NULL,17.8533,6.843,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2320,29911,'tt0119095',NULL,'FairyTale: A True Story','FairyTale: A True Story','movie',1997,'https://image.tmdb.org/t/p/w500/5H86i0qE8zCAbg0vTBKG7S7I2Vi.jpg','https://image.tmdb.org/t/p/original/qUWr7fJRsiccFcOAKvIJV30gZsP.jpg','In 1917, two children take a photograph, which is soon believed by some to be the first scientific evidence of the existence of fairies. Based on the true story of the Cottingley Fairies.',NULL,NULL,1.4901,6.406,0,10.54,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2321,18032,'tt0396707',NULL,'The Secret of Moonacre','The Secret of Moonacre','movie',2009,'https://image.tmdb.org/t/p/w500/1ZdwKhauiCgIxulUme63JjejpTS.jpg','https://image.tmdb.org/t/p/original/wdpebYdOMtUJpfYZsUei07wOfuB.jpg','When 13 year old Maria Merryweather''s father dies, leaving her orphaned and homeless, she is forced to leave her luxurious London life to go and live with Sir Benjamin, an eccentric uncle she didn''t know she had, at the mysterious Moonacre Manor.',NULL,NULL,2.6656,6.587,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2322,399019,'tt5592248',NULL,'The Beguiled','The Beguiled','movie',2017,'https://image.tmdb.org/t/p/w500/x4R9jyiZhJzevASus5n6WyHQTdR.jpg','https://image.tmdb.org/t/p/original/5jq7TjRzmvkJsa8bF3zWqxbPtmw.jpg','During the Civil War, at a Southern girls’ boarding school, young women take in an injured enemy soldier. As they provide refuge and tend to his wounds, the house is taken over with sexual tension and dangerous rivalries, and taboos are broken in an unexpected turn of events.',NULL,NULL,2.4745,5.918,0,8.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2323,51739,'tt1568921',NULL,'The Secret World of Arrietty','借りぐらしのアリエッティ','movie',2010,'https://image.tmdb.org/t/p/w500/3lSRaSjDp2nkXMQkzzjpRi3035O.jpg','https://image.tmdb.org/t/p/original/7Z7WVzJsSReG8B0CaPk0bvWD7tK.jpg','14-year-old Arrietty and the rest of the Clock family live in peaceful anonymity as they make their own home from items "borrowed" from the house''s human inhabitants. However, life changes for the Clocks when a human boy discovers Arrietty.',NULL,NULL,6.0471,7.7,0,1.2129999999999999e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2324,13179,'tt0823671',NULL,'Tinker Bell','Tinker Bell','movie',2008,'https://image.tmdb.org/t/p/w500/3Ma0r1n8kfH7UaQMS7bJ9KsYUjT.jpg','https://image.tmdb.org/t/p/original/maeox8nZYIxAAE4SdyLA0VOXe1x.jpg','Journey into the secret world of Pixie Hollow and hear Tinker Bell speak for the very first time as the astonishing story of Disney''s most famous fairy is finally revealed in the all-new motion picture "Tinker Bell."',NULL,NULL,5.8407,6.933,0,10.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2325,157065,'tt15567174',NULL,'The Fall of the House of Usher','The Fall of the House of Usher','tv',2023,'https://image.tmdb.org/t/p/w500/2rl04pRCaGfz91lwfWdDQmOiGJp.jpg','https://image.tmdb.org/t/p/original/4qDlkEAKFb4pgIUbeJMLyHX2Xym.jpg','Ruthless siblings Roderick and Madeline Usher have built Fortunato Pharmaceuticals into an empire of wealth, privilege and power. But past secrets come to light when the heirs to the Usher dynasty start dying at the hands of a mysterious woman from their youth.',NULL,NULL,6.3357,7.566,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2326,338947,'tt0887261',NULL,'Hellraiser','Hellraiser','movie',2022,'https://image.tmdb.org/t/p/w500/f9ZAIUxTTk23vo1BC9Ur1Rx5c2E.jpg','https://image.tmdb.org/t/p/original/3r3tZgKTw1554hcFoUfydLHE38w.jpg','A young woman struggling with addiction comes into possession of an ancient puzzle box, unaware that its purpose is to summon the Cenobites, a group of sadistic supernatural beings from another dimension.',NULL,NULL,3.1994,6.2,0,1.06200000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2327,44214,'tt0947798',NULL,'Black Swan','Black Swan','movie',2010,'https://image.tmdb.org/t/p/w500/viWheBd44bouiLCHgNMvahLThqx.jpg','https://image.tmdb.org/t/p/original/eDLp4uFdqP1gpy9oMrutwH6Q64I.jpg','A committed dancer struggles to maintain her sanity after winning the lead role in a production of Tchaikovsky''s "Swan Lake."',NULL,NULL,11.4641,7.7,0,1.23666666666666653e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2328,1636,'tt0230030',NULL,'Bedazzled','Bedazzled','movie',2000,'https://image.tmdb.org/t/p/w500/sBV28EVvWsJRosMsEFCbVmpAZEl.jpg','https://image.tmdb.org/t/p/original/uaTVgIzIn02wd1SBTDXouGTpiIG.jpg','Elliot Richards, a socially awkward IT worker, is given seven wishes to get the girl of his dreams when he meets a very seductive Satan. The catch: his soul. Some of his wishes include being a 7 foot basketball star, a wealthy, powerful man, and a sensitive caring guy. But, as could be expected, the Devil puts her own little twist on each of his fantasies.',NULL,NULL,4.306,6.1,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2329,7452,'tt0097108',NULL,'The Cook, the Thief, His Wife & Her Lover','The Cook, the Thief, His Wife & Her Lover','movie',1989,'https://image.tmdb.org/t/p/w500/15xMqAnFsROopAT66zdRyu2Dtek.jpg','https://image.tmdb.org/t/p/original/rzaf3eCT8pVCGvuS7P8g2nPitqC.jpg','When churlish mobster Albert Spica acquires an upscale French restaurant in London, he dines there nightly, effectively scaring off the clientele with his bad manners. His wife, Georgina, is especially disgusted by him, and soon begins an affair with regular guest Michael. Despite their best efforts to keep it secret, Spica learns about their trysts, and he plots a terrible revenge.',NULL,NULL,6.3224,7.328,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2330,1413,'tt1844624',NULL,'American Horror Story','American Horror Story','tv',2011,'https://image.tmdb.org/t/p/w500/x2c3AvZeTyNehRZXabTojAxfDuR.jpg','https://image.tmdb.org/t/p/original/a4doyPOabvQor0RGkWdhVENAR3G.jpg','An anthology horror drama series centering on different characters and locations, including a house with a murderous past, an asylum, a witch coven, a freak show, a hotel, a farmhouse in Roanoke, a cult, the apocalypse and a summer camp.',NULL,NULL,69.7754,8.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2331,28260,'tt0107953',NULL,'Return of the Living Dead III','Return of the Living Dead III','movie',1993,'https://image.tmdb.org/t/p/w500/lu4Eit7pR5I8hGHJmy3K9Re8FPo.jpg','https://image.tmdb.org/t/p/original/3eYQyFx4QQ5j0L0wqjEoC8I1RvF.jpg','Having recently witnessed the horrific results of a top secret project to bring the dead back to life, a distraught teenager performs the operation on his girlfriend after she''s killed in a motorcycle accident.',NULL,NULL,3.0506,6.58,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2332,901410,'tt16233104',NULL,'xxxHOLiC','ホリック xxxHOLiC','movie',2022,'https://image.tmdb.org/t/p/w500/9anVNOiOTBhO1vet1Q31rQR2xtO.jpg','https://image.tmdb.org/t/p/original/wN6aUgXotlGVSgKGOdeYpWeyCnD.jpg','To be free of his dark visions, Kimihiro Watanuki will work for Dimensional Witch Yūko, a mystical woman quick to help those in a bind—for a fee.',NULL,NULL,1.7186,6.565,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2333,1813,'tt0118971',NULL,'The Devil''s Advocate','The Devil''s Advocate','movie',1997,'https://image.tmdb.org/t/p/w500/5ZzBGpxy55OQzHxKVY11IpY6a0o.jpg','https://image.tmdb.org/t/p/original/2Y6Q7eYDXoolcHjYCAyJQlE2CVT.jpg','Aspiring Florida defense lawyer Kevin Lomax accepts a job at a New York law firm. With the stakes getting higher every case, Kevin quickly learns that his boss has something far more evil planned.',NULL,NULL,11.0803,7.479,0,11.515,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2334,9946,'tt0146675',NULL,'End of Days','End of Days','movie',1999,'https://image.tmdb.org/t/p/w500/pY8FbKKl3VD0jRI1iDFrwN6alLa.jpg','https://image.tmdb.org/t/p/original/oVp4NyyOqVPKrv5PBA7Sjwoh09S.jpg','Cynical bodyguard Jericho is hired by a man possessed by Satan, who is in search of his bride. When Jericho realizes what is happening, he must do everything he can to save the woman and the world.',NULL,NULL,4.8173,6.098,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2335,475220,'tt7464188',NULL,'In Fabric','In Fabric','movie',2018,'https://image.tmdb.org/t/p/w500/puGJX5Ko9KUMWM5cGqPZ5nyxa8c.jpg','https://image.tmdb.org/t/p/original/97NFoAp9JdgXqBQG6aoUprF6zbS.jpg','A haunting ghost story set against the backdrop of a busy winter sales period in a department store, following the life of a cursed dress as it passes from person to person, with devastating consequences.',NULL,NULL,1.0395,5.633,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2336,4024,'tt0054632',NULL,'Last Year at Marienbad','L''Année dernière à Marienbad','movie',1961,'https://image.tmdb.org/t/p/w500/syIJCqiSkGRJTlyaBtyI5jqPtE7.jpg','https://image.tmdb.org/t/p/original/h1ov8VcVCiZsnWRu4EjZ74R33GP.jpg','At a weekend gathering, a man tells a woman that they had spent time there together a year prior. But, the woman has no recollection whatsoever and is convinced that he is simply fabricating the encounter. The more he speaks about their activities the previous year however, the more compelling he becomes. The question remains however – did they meet previously or not?',NULL,NULL,2.6596,7.431,0,11.265,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2337,54671,'tt2628232',NULL,'Penny Dreadful','Penny Dreadful','tv',2014,'https://image.tmdb.org/t/p/w500/hQSdrXBYTbLGHYDIseHkBOPXTgL.jpg','https://image.tmdb.org/t/p/original/32iacqVElB91YZKl9Ky3QEEkXtH.jpg','Some of literature''s most terrifying characters, including Dr. Frankenstein, Dorian Gray, and iconic figures from the novel Dracula are lurking in the darkest corners of Victorian London. Penny Dreadful is a frightening psychological thriller that weaves together these classic horror origin stories into a new adult drama.',NULL,NULL,11.533,7.809,0,11.28,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2338,126277,'tt1959332',NULL,'American Mary','American Mary','movie',2013,'https://image.tmdb.org/t/p/w500/oHwyNKHm41Y6WPRCHL0zOzytGvL.jpg','https://image.tmdb.org/t/p/original/ykIWktRVYmZGM2hqYPPGckOyK44.jpg','A young medical student struggling to pay tuition is drawn into the shady world of underground body-modification.',NULL,NULL,2.2912,6.3,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2339,597208,'tt7740496',NULL,'Nightmare Alley','Nightmare Alley','movie',2021,'https://image.tmdb.org/t/p/w500/vfn1feL0V9HNSXuLLpaxAW8O6LO.jpg','https://image.tmdb.org/t/p/original/g0YNGpmlXsgHfhGnJz3c5uyzZ1B.jpg','An ambitious carnival man with a talent for manipulating people with a few well-chosen words hooks up with a female psychologist who is even more dangerous than he is.',NULL,NULL,4.2842,6.949,0,10.14,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2340,4147,'tt0257044',NULL,'Road to Perdition','Road to Perdition','movie',2002,'https://image.tmdb.org/t/p/w500/loSpBeirRfTPJ3cMIqpQArstGhh.jpg','https://image.tmdb.org/t/p/original/cDDyZ2qtBzNAepdTbgxKfFcxREl.jpg','Mike Sullivan works as a hit man for crime boss John Rooney. Sullivan views Rooney as a father figure, however after his son is witness to a killing, Mike Sullivan finds himself on the run in attempt to save the life of his son and at the same time looking for revenge on those who wronged him.',NULL,NULL,5.6175,7.36,0,12.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2341,43231,'tt0050782',NULL,'White Nights','Le notti bianche','movie',1957,'https://image.tmdb.org/t/p/w500/sAFR7LbXnPSjZGpG1ihSAN7vrfR.jpg','https://image.tmdb.org/t/p/original/fWkNhudvl6dtEHWSdQD6nl92GnD.jpg','A middle-aged man meets a young woman who is waiting on a canal bridge for her lover''s return.',NULL,NULL,2.6958,7.451,0,11.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2342,872,'tt0045152',NULL,'Singin'' in the Rain','Singin'' in the Rain','movie',1952,'https://image.tmdb.org/t/p/w500/w03EiJVHP8Un77boQeE7hg9DVdU.jpg','https://image.tmdb.org/t/p/original/6qOyw4yfzbzTp5YsCX26C28Do0S.jpg','In 1927 Hollywood, a silent film star falls for a chorus girl just as he and his paranoid screen partner struggle to make the difficult transition to talking pictures.',NULL,NULL,5.8128,8.1,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2343,1585,'tt0038650',NULL,'It''s a Wonderful Life','It''s a Wonderful Life','movie',1946,'https://image.tmdb.org/t/p/w500/bSqt9rhDZx1Q7UZ86dBPKdNomp2.jpg','https://image.tmdb.org/t/p/original/3q35nBLCIdEbxYfsr7D5ocYQXKz.jpg','George Bailey has spent his entire life giving to the people of Bedford Falls.  All that prevents rich skinflint Mr. Potter from taking over the entire town is George''s modest building and loan company.  But on Christmas Eve the business''s $8,000 is lost and George''s troubles begin.',NULL,NULL,10.76,8.278,0,12.355,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2344,4922,'tt0421715',NULL,'The Curious Case of Benjamin Button','The Curious Case of Benjamin Button','movie',2008,'https://image.tmdb.org/t/p/w500/26wEWZYt6yJkwRVkjcbwJEFh9IS.jpg','https://image.tmdb.org/t/p/original/2fswjyrY3GEzeoVn6mF8pNeNcgf.jpg','Born under unusual circumstances, Benjamin Button springs into being as an elderly man in a New Orleans nursing home and ages in reverse. Twelve years after his birth, he meets Daisy, a child who flits in and out of his life as she grows up to be a dancer. Though he has all sorts of unusual adventures over the course of his life, it is his relationship with Daisy, and the hope that they will come together at the right time, that drives Benjamin forward.',NULL,NULL,11.1325,7.6,0,1.30033333333333338e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2345,13183,'tt0409459',NULL,'Watchmen','Watchmen','movie',2009,'https://image.tmdb.org/t/p/w500/aVURelN3pM56lFM7Dgfs5TixcIf.jpg','https://image.tmdb.org/t/p/original/dH7ia3vtkYCa3CBvDnvVjqm9uiQ.jpg','In a gritty and alternate 1985, the glory days of costumed vigilantes have been brought to a close by a government crackdown. But after one of the masked veterans is brutally murdered, an investigation into the killer is initiated. The reunited heroes set out to prevent their own destruction, but in doing so they uncover a sinister plot that puts all of humanity in grave danger.',NULL,NULL,7.9687,7.356,0,8.98,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2346,20024,'tt0172396',NULL,'The End of the Affair','The End of the Affair','movie',1999,'https://image.tmdb.org/t/p/w500/xTp5cyp6qG0YTdI4AEz4ytjODOQ.jpg','https://image.tmdb.org/t/p/original/hO1UwCPxI5tpz21hzITij3DPwFY.jpg','On a rainy London night in 1946, novelist Maurice Bendrix has a chance meeting with Henry Miles, husband of his ex-mistress Sarah, who abruptly ended their affair two years before. Bendrix''s obsession with Sarah is rekindled; he succumbs to his own jealousy and arranges to have her followed.',NULL,NULL,2.3257,6.609,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2347,15389,'tt0100142',NULL,'Metropolitan','Metropolitan','movie',1990,'https://image.tmdb.org/t/p/w500/852ZwTRj9tRxkGOT0Pu0Ep8yimk.jpg','https://image.tmdb.org/t/p/original/hyHp1MgvUXw40GLjhqfjxwMWD4.jpg','A radical student is adopted by a group of young New Yorkers, serves as a catalyst to alter his and their lives. Gathering in a Manhattan apartment, the group of friends meet to discuss social mobility, Fourier''s socialism and play bridge in their cocoon of upper-class society - until they are joined by a man with a critical view of their way of life.',NULL,NULL,1.058,6.978,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2348,254,'tt0360717',NULL,'King Kong','King Kong','movie',2005,'https://image.tmdb.org/t/p/w500/6a2HY6UmD7XiDD3NokgaBAXEsD2.jpg','https://image.tmdb.org/t/p/original/mRM2NB0i3wv4HqxXvwIjEVi4Qqq.jpg','In 1933 New York, an overly ambitious movie producer coerces his cast and hired ship crew to travel to mysterious Skull Island, where they encounter Kong, a giant ape who is immediately smitten with the leading lady.',NULL,NULL,10.9599,6.894,0,12.085,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2349,284,'tt0053604',NULL,'The Apartment','The Apartment','movie',1960,'https://image.tmdb.org/t/p/w500/hhSRt1KKfRT0yEhEtRW3qp31JFU.jpg','https://image.tmdb.org/t/p/original/2L8U8rUyWeFTb6n1egTNeJsEsvj.jpg','Bud Baxter is a minor clerk in a huge New York insurance company, until he discovers a quick way to climb the corporate ladder. He lends out his apartment to the executives as a place to take their mistresses. Although he often has to deal with the aftermath of their visits, one night he''s left with a major problem to solve.',NULL,NULL,5.7071,8.2,0,12.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2350,2135,'tt0268695',NULL,'The Time Machine','The Time Machine','movie',2002,'https://image.tmdb.org/t/p/w500/iYayQahkghlbAsfOQX8b5eBzGVy.jpg','https://image.tmdb.org/t/p/original/i0eOILDW8HipIkOUSKhB1dvZzNJ.jpg','Hoping to alter the events of the past, a 19th-century inventor instead travels 800,000 years into the future, where he finds mankind divided into two warring races.',NULL,NULL,5.9054,6.332,0,11.025,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2351,772,'tt0104431',NULL,'Home Alone 2: Lost in New York','Home Alone 2: Lost in New York','movie',1992,'https://image.tmdb.org/t/p/w500/uuitWHpJwxD1wruFl2nZHIb4UGN.jpg','https://image.tmdb.org/t/p/original/8fnYJPoXxwAN4valDLgz2whMGTH.jpg','Instead of flying to Florida with his folks, Kevin ends up alone in New York, where he gets a hotel room with his dad''s credit card—despite problems from a clerk and meddling bellboy. But when Kevin runs into his old nemeses, the Wet Bandits, he''s determined to foil their plans to rob a toy store on Christmas Eve.',NULL,NULL,13.9979,6.79,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2352,19490,'tt0039190',NULL,'The Bishop''s Wife','The Bishop''s Wife','movie',1947,'https://image.tmdb.org/t/p/w500/2sMpffmvoJlW7WBcvyHTPR9DEsj.jpg','https://image.tmdb.org/t/p/original/fVEynIdJC8gRpslMfGXyZXrz5ar.jpg','An Episcopal Bishop, Henry Brougham, has been working for months on the plans for an elaborate new cathedral which he hopes will be paid for primarily by a wealthy, stubborn widow. He is losing sight of his family and of why he became a churchman in the first place. Enter Dudley, an angel sent to help him. Dudley does help everyone he meets, but not necessarily in the way they would have preferred. With the exception of Henry, everyone loves him, but Henry begins to believe that Dudley is there to replace him, both at work and in his family''s affections, as Christmas approaches.',NULL,NULL,1.5747,7.1,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2353,1621,'tt0979432',NULL,'Boardwalk Empire','Boardwalk Empire','tv',2010,'https://image.tmdb.org/t/p/w500/zyHLWVmqS8m7bxABJjcDFMYLdF8.jpg','https://image.tmdb.org/t/p/original/7Yj4QbECkH3JavlZxw4NWReoN7B.jpg','Atlantic City at the dawn of Prohibition is a place where the rules don''t apply. And the man who runs things -- legally and otherwise -- is the town''s treasurer, Enoch "Nucky" Thompson, who is equal parts politician and gangster.',NULL,NULL,27.469,8.021,0,12.035,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2354,696,'tt0079522',NULL,'Manhattan','Manhattan','movie',1979,'https://image.tmdb.org/t/p/w500/k4eT3EvfxW1L9Wmt04UqJqCvCR6.jpg','https://image.tmdb.org/t/p/original/adnSTomHU9YyqV2lx38CgM0UxLS.jpg','Manhattan explores how the life of a middle-aged television writer dating a teenage girl is further complicated when he falls in love with his best friend''s mistress.',NULL,NULL,2.5932,7.712,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2355,82682,'tt1321870',NULL,'Gangster Squad','Gangster Squad','movie',2013,'https://image.tmdb.org/t/p/w500/wAuQNTBFBu2yXZsX6yLhUPiwTlW.jpg','https://image.tmdb.org/t/p/original/cdd4S09XxLLvp6IRN4PQamPAXL6.jpg','Los Angeles, 1949. Ruthless, Brooklyn-born mob king Mickey Cohen runs the show in this town, reaping the ill-gotten gains from the drugs, the guns, the prostitutes and — if he has his way — every wire bet placed west of Chicago. And he does it all with the protection of not only his own paid goons, but also the police and the politicians who are under his control. It’s enough to intimidate even the bravest, street-hardened cop… except, perhaps, for the small, secret crew of LAPD outsiders led by Sgt. John O’Mara and Jerry Wooters who come together to try to tear Cohen’s world apart.',NULL,NULL,3.4024,6.381,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2356,9778,'tt0240890',NULL,'Serendipity','Serendipity','movie',2001,'https://image.tmdb.org/t/p/w500/4jS66Qmq2Ru5S2YzHVknGd4xJyT.jpg','https://image.tmdb.org/t/p/original/sBecqcXgrLRiwufYr6apGnYA70k.jpg','Although strangers Sara and Jonathan are both already in relationships, they realize they have genuine chemistry after a chance encounter – but part company soon after. Years later, they each yearn to reunite, despite being destined for the altar. But to give true love a chance, they have to find one another again.',NULL,NULL,7.3582,6.963,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2357,30890,'tt0093818',NULL,'Radio Days','Radio Days','movie',1987,'https://image.tmdb.org/t/p/w500/ljZ3yyYznAiq1vF6nHITdJn6qXB.jpg','https://image.tmdb.org/t/p/original/rn3E4Kd7EUOGOF95Hsd0aOhQqZg.jpg','The Narrator tells us how the radio influenced his childhood in the days before TV. In the New York City of the late 1930s to the New Year''s Eve 1944, this coming-of-age tale mixes the narrator''s experiences with contemporary anecdotes and urban legends of the radio stars.',NULL,NULL,1.9035,7.046,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2358,631,'tt0018455',NULL,'Sunrise: A Song of Two Humans','Sunrise: A Song of Two Humans','movie',1927,'https://image.tmdb.org/t/p/w500/5V9jDm4u2QemGHbqjUyP5HmFmzf.jpg','https://image.tmdb.org/t/p/original/hKrrCigPFmhv1bg5IJl9nzjEaN4.jpg','A married farmer falls under the spell of a slatternly woman from the city, who tries to convince him to drown his wife.',NULL,NULL,2.0652,7.8,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2359,58224,'tt1396218',NULL,'Mr. Popper''s Penguins','Mr. Popper''s Penguins','movie',2011,'https://image.tmdb.org/t/p/w500/jGwZ1QI5DaL7mHQ2ZsMV1p8xvPS.jpg','https://image.tmdb.org/t/p/original/gtkROcxhItcEvGoRr0a12PWBLpf.jpg','Tom Popper is a successful businessman who’s clueless when it comes to the really important things in life...until he inherits six “adorable” penguins, each with its own unique personality. Soon Tom’s rambunctious roommates turn his swank New York apartment into a snowy winter wonderland — and the rest of his world upside-down.',NULL,NULL,3.8801,5.982,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2360,32558,'tt0040705',NULL,'Portrait of Jennie','Portrait of Jennie','movie',1948,'https://image.tmdb.org/t/p/w500/AuZVFoCOxKKwC6eKWol4NkAFpWi.jpg','https://image.tmdb.org/t/p/original/reoP1aJZbtxXNpBDwMFESng80lY.jpg','A mysterious girl inspires a struggling artist.',NULL,NULL,2.1345,7.2,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2361,3782,'tt0044741',NULL,'Ikiru','生きる','movie',1952,'https://image.tmdb.org/t/p/w500/dgNTS4EQDDVfkzJI5msKuHu2Ei3.jpg','https://image.tmdb.org/t/p/original/pQ06lTkmJd1mbotdl847HoV2iaA.jpg','Kanji Watanabe is a middle-aged man who has worked in the same monotonous bureaucratic position for decades. Learning he has cancer, he starts to look for the meaning of his life.',NULL,NULL,6.9056,8.3,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2362,152599,'tt1951181',NULL,'The Immigrant','The Immigrant','movie',2013,'https://image.tmdb.org/t/p/w500/ArWRRQYeXL3nG4jYpMOPoBvgmy9.jpg','https://image.tmdb.org/t/p/original/mqIheOKqtRD7Z9l4kEmic7BDqEZ.jpg','1921 New York. An immigrant woman is tricked into a life of burlesque and vaudeville until a dazzling magician tries to save her and reunite her with her sister who is being held in the confines of Ellis Island.',NULL,NULL,1.4506,6.326,0,9.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2363,3580,'tt0824747',NULL,'Changeling','Changeling','movie',2008,'https://image.tmdb.org/t/p/w500/829VqESzooUXRVgrfM7PtNBGySf.jpg','https://image.tmdb.org/t/p/original/eBmIaAm1CkBuuyIUQYorhQKzTTg.jpg','Los Angeles, 1928. When single mother Christine Collins leaves for work, her son vanishes without a trace. Five months later, the police reunite mother and son. But when Christine suspects that the boy returned to her isn''t her child, her quest for truth exposes a world of corruption.',NULL,NULL,4.6587,7.578,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2364,1491,'tt0443543',NULL,'The Illusionist','The Illusionist','movie',2006,'https://image.tmdb.org/t/p/w500/1O9jUvqkHaGBMVRyOJz1AlkmALW.jpg','https://image.tmdb.org/t/p/original/8ScGUtKTupr5rVLiXRmffjKMRhH.jpg','With his eye on a lovely aristocrat, a gifted illusionist named Eisenheim uses his powers to win her away from her betrothed, a crown prince. But Eisenheim''s scheme creates tumult within the monarchy and ignites the suspicion of a dogged inspector.',NULL,NULL,5.3702,7.298,0,11.635,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2365,921,'tt0352248',NULL,'Cinderella Man','Cinderella Man','movie',2005,'https://image.tmdb.org/t/p/w500/wkeOjIcpuqLMW4GnVowlM9VI0JE.jpg','https://image.tmdb.org/t/p/original/oO5sMDETneOPCneX3jfXMFfPh9E.jpg','The true story of boxer Jim Braddock who, following his retirement in the 1930s, makes a surprise comeback in order to lift his family out of poverty.',NULL,NULL,3.4539,7.581,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2366,504562,'tt0385887',NULL,'Motherless Brooklyn','Motherless Brooklyn','movie',2019,'https://image.tmdb.org/t/p/w500/2wm20cbkH1L8nA54Gtwfgz2hTqo.jpg','https://image.tmdb.org/t/p/original/xMHeU84wLQ9uH9acJ0oPgdii9wO.jpg','New York City, 1957. Lionel Essrog, a private detective living with Tourette syndrome, tries to solve the murder of his mentor and best friend, armed only with vague clues and the strength of his obsessive mind.',NULL,NULL,2.9306,6.69,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2367,829,'tt0071315',NULL,'Chinatown','Chinatown','movie',1974,'https://image.tmdb.org/t/p/w500/kZRSP3FmOcq0xnBulqpUQngJUXY.jpg','https://image.tmdb.org/t/p/original/pyvkujOZ5qvY2NlQVC71flfgVWE.jpg','Private eye Jake Gittes lives off of the murky moral climate of sunbaked, pre-World War II Southern California. Hired by a beautiful socialite to investigate her husband''s extra-marital affair, Gittes is swept into a maelstrom of double dealings and deadly deceits, uncovering a web of personal and political scandals that come crashing together.',NULL,NULL,5.4618,7.907,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2368,2567,'tt0338751',NULL,'The Aviator','The Aviator','movie',2004,'https://image.tmdb.org/t/p/w500/lx4kWcZc3o9PaNxlQpEJZM17XUI.jpg','https://image.tmdb.org/t/p/original/6KLKdhk9wZvJ6OcTzDCoxup0Kmh.jpg','A biopic depicting the life of filmmaker and aviation pioneer Howard Hughes from 1927 to 1947, during which time he became a successful film producer and an aviation magnate, while simultaneously growing more unstable due to severe obsessive-compulsive disorder.',NULL,NULL,6.0385,7.218,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2369,1104,'tt0804503',NULL,'Mad Men','Mad Men','tv',2007,'https://image.tmdb.org/t/p/w500/7v8iCNzKFpdlrCMcqCoJyn74Nsa.jpg','https://image.tmdb.org/t/p/original/A5lVyejMsP5G7rAJBwU9ug3Wzou.jpg','Set in 1960-1970 New York, this sexy, stylized and provocative drama follows the lives of the ruthlessly competitive men and women of Madison Avenue advertising.',NULL,NULL,53.3766,8.124,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2370,71769,'tt4604612',NULL,'The Alienist','The Alienist','tv',2018,'https://image.tmdb.org/t/p/w500/zUd4RPbfHuB1zIG2iNI5bdZcQo3.jpg','https://image.tmdb.org/t/p/original/oDTBlmFiHAslFwj4JU8jkBB6E6V.jpg','New York, 1896. Police commissioner Theodore Roosevelt brings together criminal psychologist Dr. Laszlo Kreizler, newspaper illustrator John Moore and secretary Sara Howard to investigate several murders of male prostitutes.',NULL,NULL,11.3371,7.518,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2371,70796,'tt5788792',NULL,'The Marvelous Mrs. Maisel','The Marvelous Mrs. Maisel','tv',2017,'https://image.tmdb.org/t/p/w500/zS7fQiOZiKCVH2vlYSiIsFWW8hh.jpg','https://image.tmdb.org/t/p/original/vQ77kC1amsZECKIxkUIsMJCtBVp.jpg','It’s 1958 Manhattan and Miriam “Midge” Maisel has everything she’s ever wanted - the perfect husband, kids, and Upper West Side apartment. But when her life suddenly takes a turn and Midge must start over, she discovers a previously unknown talent - one that will take her all the way from the comedy clubs of Greenwich Village to a spot on Johnny Carson’s couch.',NULL,NULL,17.0118,8.066,0,11.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2372,2006,'tt0051406',NULL,'Bell, Book and Candle','Bell, Book and Candle','movie',1958,'https://image.tmdb.org/t/p/w500/z3MLtVFPT2wIkKCBSE2yBgDmeXI.jpg','https://image.tmdb.org/t/p/original/y5e5MTZtbMesmJ7EYgBdlceMcWq.jpg','Gillian Holroyd, a modern-day witch, becomes smitten with her handsome upstairs neighbor, Shep Henderson. Using her magical powers, she casts a love spell on him, only to face unexpected complications when genuine feelings emerge, threatening her supernatural abilities.',NULL,NULL,2.2691,6.559,0,12.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2373,840430,'tt14849194',NULL,'The Holdovers','The Holdovers','movie',2023,'https://image.tmdb.org/t/p/w500/VHSzNBTwxV8vh7wylo7O9CLdac.jpg','https://image.tmdb.org/t/p/original/A99WMiz0ASpH9coOFrxSEuwTWx0.jpg','A curmudgeonly instructor at a New England prep school is forced to remain on campus during Christmas break to babysit the handful of students with nowhere to go. Eventually, he forms an unlikely bond with one of them — a damaged, brainy troublemaker — and with the school’s head cook, who has just lost a son in Vietnam.',NULL,NULL,5.0824,7.644,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2374,17887,'tt0061385',NULL,'Barefoot in the Park','Barefoot in the Park','movie',1967,'https://image.tmdb.org/t/p/w500/qh64tAOmbQNoYMLTETkhmBQgSbu.jpg','https://image.tmdb.org/t/p/original/1hNQtElM8RfieC2xJHvsoUylMZ.jpg','In this film based on a Neil Simon play, newlyweds Corie, a free spirit, and Paul Bratter, an uptight lawyer, share a sixth-floor apartment in Greenwich Village. Soon after their marriage, Corie tries to find a companion for mother, Ethel, who is now alone, and sets up Ethel with neighbor Victor. Inappropriate behavior on a double date causes conflict, and the young couple considers divorce.',NULL,NULL,1.9675,7.133,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2375,11674,'tt0115433',NULL,'101 Dalmatians','101 Dalmatians','movie',1996,'https://image.tmdb.org/t/p/w500/8o2ADoAyG796UwTjwBFjPyBz0yG.jpg','https://image.tmdb.org/t/p/original/yqh3mb9jd3GTTs09ZlnW4mxS95z.jpg','An evil, high-fashion designer plots to steal Dalmatian puppies in order to make an extravagant fur coat, but instead creates an extravagant mess.',NULL,NULL,7.0475,5.946,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2376,9062,'tt0066011',NULL,'Love Story','Love Story','movie',1970,'https://image.tmdb.org/t/p/w500/yCjADq9fwbdPnxMo0DKNeRGZ4YC.jpg','https://image.tmdb.org/t/p/original/jZC1xS5DVTe4T5azqJ4NB2QBpgt.jpg','Harvard Law student Oliver Barrett IV and music student Jennifer Cavilleri share a chemistry they cannot deny - and a love they cannot ignore. Despite their opposite backgrounds, the young couple put their hearts on the line for each other. When they marry, Oliver''s wealthy father threatens to disown him. Jenny tries to reconcile the Barrett men, but to no avail.',NULL,NULL,2.9505,6.826,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2377,42034,'tt0089052',NULL,'Dreamchild','Dreamchild','movie',1985,'https://image.tmdb.org/t/p/w500/vgmONyJ6Io0sPibW9SRiZFHVOO0.jpg','https://image.tmdb.org/t/p/original/6Q5a6x8s4DK94LV4TGsuzqbWlMw.jpg','80-year-old Alice Hargreaves is about to visit Columbia University to attend a reception in honour of author Lewis Carroll. As a child, Alice''s close friendship with the writer was the creative catalyst for Carroll''s most beloved work. However, as Alice reflects on her experiences with the author, she slowly realises the complexity of their bond has had lasting, deeply felt ramifications.',NULL,NULL,2.849,6.6,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2378,9283,'tt0115639',NULL,'Beautiful Girls','Beautiful Girls','movie',1996,'https://image.tmdb.org/t/p/w500/sHcx1fBmrtZYvFmUywU0d5cvIFd.jpg','https://image.tmdb.org/t/p/original/5VfgNZJvJ6FcwF3PPQbpUIzILkQ.jpg','During a snowy winter in the small fictional town of Knight''s Ridge, Massachusetts, a group of lifelong buddies hang out, drink and struggle to connect with the women who affect their decisions, dreams and desires.',NULL,NULL,3.8336,6.657,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2379,18148,'tt0046438',NULL,'Tokyo Story','東京物語','movie',1953,'https://image.tmdb.org/t/p/w500/g2YbTYKpY7N2yDSk7BfXZ18I5QV.jpg','https://image.tmdb.org/t/p/original/jLq0ol1f0ZKXni9R9GsPBcyPrNN.jpg','The elderly Shukishi and his wife, Tomi, take the long journey from their small seaside village to visit their adult children in Tokyo. Their elder son, Koichi, a doctor, and their daughter, Shige, a hairdresser, don''t have much time to spend with their aged parents, and so it falls to Noriko, the widow of their younger son who was killed in the war, to keep her in-laws company.',NULL,NULL,4.3849,8.151,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2380,1421990,'tt35520290',NULL,'The Baltimorons','The Baltimorons','movie',2025,'https://image.tmdb.org/t/p/w500/yZWcrfj3mFf9LGItIFwa7DSkedz.jpg','https://image.tmdb.org/t/p/original/coon7luAq01HIUr4qWvujZ04EDX.jpg','A newly sober man''s Christmas Eve dental emergency leads to an unexpected romance with his older dentist as they explore Baltimore together.',NULL,NULL,1.2415,6.193,0,4.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2381,15919,'tt0048356',NULL,'Marty','Marty','movie',1955,'https://image.tmdb.org/t/p/w500/8tnGO5VoAQII4DbE3hozWKhV4BY.jpg','https://image.tmdb.org/t/p/original/zhZtaNcjtc6VgV8SC4VlokiaeNt.jpg','Marty, a butcher who lives in the Bronx with his mother, is unmarried at 34. Good-natured but socially awkward, he faces constant badgering from family and friends to get married but has reluctantly resigned himself to bachelorhood. He then meets Clara, an unattractive school teacher. Realising their emotional connection, Marty promises to call, but family and friends try to convince him not to.',NULL,NULL,2.3245,7.472,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2382,364,'tt0103776',NULL,'Batman Returns','Batman Returns','movie',1992,'https://image.tmdb.org/t/p/w500/jKBjeXM7iBBV9UkUcOXx3m7FSHY.jpg','https://image.tmdb.org/t/p/original/7x4SNxO5HWArighxxFeet5sn3il.jpg','The monstrous Penguin, who dwells in the sewers beneath Gotham, joins up with corrupt mayoral candidate Max Shreck to topple the Batman once and for all. But when Shreck''s timid assistant Selina Kyle finds out, and Shreck tries to kill her, she''s transformed into the sexy Catwoman. She teams up with the Penguin and Shreck to destroy Batman, but sparks fly unexpectedly when she confronts the caped crusader.',NULL,NULL,8.3362,6.9,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2383,453,'tt0268978',NULL,'A Beautiful Mind','A Beautiful Mind','movie',2001,'https://image.tmdb.org/t/p/w500/rEIg5yJdNOt9fmX4P8gU9LeNoTQ.jpg','https://image.tmdb.org/t/p/original/hCJFWTPghXCwwSpvPpAoIB8318Q.jpg','From the heights of notoriety to the depths of depravity, John Forbes Nash Jr. experiences it all. As a brilliant but socially awkward mathematician, he made a groundbreaking discovery early in his career and stands on the brink of international acclaim. But as the handsome and arrogant Nash accepts secret work in cryptography, he becomes entangled in a mysterious conspiracy. His life takes a nightmarish turn and he soon finds himself on a painful and harrowing journey of self-discovery.',NULL,NULL,11.1775,7.854,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2384,400617,'tt5776858',NULL,'Phantom Thread','Phantom Thread','movie',2017,'https://image.tmdb.org/t/p/w500/hgoWjp9Sh0MI97eAMZCnIoVfgvq.jpg','https://image.tmdb.org/t/p/original/sJZd1H4cl2Nxhj0nutVCK5pMczL.jpg','In 1950s London, a renowned dressmaker''s meticulous lifestyle begins drastically changing as his relationship with his young muse intensifies.',NULL,NULL,4.3807,7.318,0,11.76,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2385,311,'tt0087843',NULL,'Once Upon a Time in America','Once Upon a Time in America','movie',1984,'https://image.tmdb.org/t/p/w500/i0enkzsL5dPeneWnjl1fCWm6L7k.jpg','https://image.tmdb.org/t/p/original/xlDUjb0Q5Dv6jPQRF5VE4IMjIy.jpg','A former Prohibition-era Jewish gangster returns to the Lower East Side of Manhattan over thirty years later, where he once again must confront the ghosts and regrets of his old life.',NULL,NULL,16.2883,8.4,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2386,8271,'tt0486822',NULL,'Disturbia','Disturbia','movie',2007,'https://image.tmdb.org/t/p/w500/3f9KwSrieczuH9nRrwfOsoMoMNd.jpg','https://image.tmdb.org/t/p/original/8Yz0WeWD1EUyJEOKMLZEeuNERyp.jpg','Kale has a life most teenagers would envy. He spends his days endlessly playing video games, surfing the net, eating junk food and watching cable. He has complete free reign of the house, and a beautiful young hottie named Ashley has just moved in next door. There’s only one problem—he’s not allowed to leave the house. Kale’s under court-ordered house arrest for three months, and if he takes one step beyond a 100-foot perimeter of the house, his next confinement will be in a real prison.',NULL,NULL,6.4377,6.689,0,10.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2387,9872,'tt0089114',NULL,'Explorers','Explorers','movie',1985,'https://image.tmdb.org/t/p/w500/oFJosj5ECYjf1jkvpTEjGNzPx2x.jpg','https://image.tmdb.org/t/p/original/ijNmO643l3HYM5k3i1L1ivSdWEb.jpg','Middle schooler Ben spends his free time watching sci-fi films, playing video games and reading comic books. Surprisingly, his affinity for all things fantastical yields a real result – when he has a vivid dream about technology, his prodigy best friend Wolfgang manages to create a working spacecraft. Joined by their buddy Darren, the boys take off into outer space and encounter some very odd extraterrestrial life.',NULL,NULL,2.9733,6.3,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2388,220289,'tt2866360',NULL,'Coherence','Coherence','movie',2014,'https://image.tmdb.org/t/p/w500/ezUtb9m5DeLwL2gxi4gktzNCvQv.jpg','https://image.tmdb.org/t/p/original/cvGE73s935bXEAVt2W0zADPPegG.jpg','Four couples gather for dinner the night a mysterious and powerful comet passes overhead.',NULL,NULL,5.7538,7.215,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2389,22824,'tt1220198',NULL,'The Fourth Kind','The Fourth Kind','movie',2009,'https://image.tmdb.org/t/p/w500/vfnsGUwurUQqlpvArBvUVc9rYXa.jpg','https://image.tmdb.org/t/p/original/4Ue8De8AXVrSWvFQMzmoJQn4Pxe.jpg','Since the 1960s, a disproportionate number of the population in and around Nome, Alaska, have gone missing. Despite FBI investigations, the disappearances remain a mystery. Dr. Abigail Tyler, a psychologist, may be on the verge of blowing the unsolved cases wide open when, during the course of treating her patients, she finds evidence of alien abductions.',NULL,NULL,4.348,6.368,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2390,2267,'tt0768212',NULL,'The Last Mimzy','The Last Mimzy','movie',2007,'https://image.tmdb.org/t/p/w500/jnLXcQFx4hSKDNG1P6RMz4v5jje.jpg','https://image.tmdb.org/t/p/original/zzhXcdGij5MPfrnpNoC6dKhgT8M.jpg','Two siblings begin to develop special talents after they find a mysterious box of toys, and soon their parents and even their teacher are drawn into a strange new world – and find a task ahead of them that is far more important than any of them could imagine.',NULL,NULL,1.8465,6.332,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2391,820609,'tt14509110',NULL,'No One Will Save You','No One Will Save You','movie',2023,'https://image.tmdb.org/t/p/w500/ehGIDAMaYy6Eg0o8ga0oqflDjqW.jpg','https://image.tmdb.org/t/p/original/zYlgqIpqJ1VAbvFhRhktAzIybVs.jpg','A lonely woman battles extraterrestrials who threaten her future while forcing her to face her past.',NULL,NULL,6.4279,6.71,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2392,28774,'tt0097100',NULL,'Communion','Communion','movie',1989,'https://image.tmdb.org/t/p/w500/unDk9honWK30AMUTwSknhplFI5G.jpg','https://image.tmdb.org/t/p/original/vb7hke97pbAsZcCG1C7vhDtAiMk.jpg','A novelist''s wife and son see him changed by an apparent encounter with aliens in the mountains.',NULL,NULL,1.1336,5.365,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2393,10386,'tt0129167',NULL,'The Iron Giant','The Iron Giant','movie',1999,'https://image.tmdb.org/t/p/w500/ct04FCFLPImNG5thcPLRnVsZlmS.jpg','https://image.tmdb.org/t/p/original/gZ78dyRH9hXeH94ASjuvD9Vw4b5.jpg','In the small town of Rockwell, Maine in October 1957, a giant metal machine befriends a nine-year-old boy and ultimately finds its humanity by unselfishly saving people from their own fears and prejudices.',NULL,NULL,8.5256,8.0,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2394,10122,'tt0091059',NULL,'Flight of the Navigator','Flight of the Navigator','movie',1986,'https://image.tmdb.org/t/p/w500/tdRgQWMximj0tL6OWu9kRTtePmI.jpg','https://image.tmdb.org/t/p/original/8esvgUVVX4GGXLGuGvKDYFNqVdt.jpg','12-year-old David is accidentally knocked out in the forest near his home, but when he awakens eight years have passed. His family is overjoyed to have him back, but is just as perplexed as he is that he hasn''t aged. When a NASA scientist discovers a UFO nearby, David gets the chance to unravel the mystery and recover the life he lost.',NULL,NULL,2.5383,6.961,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2395,54007,'tt0120478',NULL,'Star Kid','Star Kid','movie',1997,'https://image.tmdb.org/t/p/w500/srnvpaAg83sfYr82meDe6k1nDd.jpg','https://image.tmdb.org/t/p/original/okPwhy7bkNBAzisjLEEtFKMWTM6.jpg','Shy seventh-grader Spencer Griffith''s life changes when the meteor falls into local junkyard and he finds a Cybersuit - the wise and strong robot from another galaxy. Spencer puts Cybersuit on and becomes a different kind of guy',NULL,NULL,1.0582,6.5,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2396,568,'tt0112384',NULL,'Apollo 13','Apollo 13','movie',1995,'https://image.tmdb.org/t/p/w500/tVeKscCm2fY1xDXZk8PgnZ87h9S.jpg','https://image.tmdb.org/t/p/original/n0FDJI9c0uWiZwm8wgXVjaMBn96.jpg','The true story of technical troubles that scuttle the Apollo 13 lunar mission in 1970, risking the lives of astronaut Jim Lovell and his crew, with the failed journey turning into a thrilling saga of heroism. Drifting more than 200,000 miles from Earth, the astronauts work furiously with the ground crew to avert tragedy.',NULL,NULL,6.3008,7.465,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2397,15613,'tt0106912',NULL,'Fire in the Sky','Fire in the Sky','movie',1993,'https://image.tmdb.org/t/p/w500/rTFrjAp1YV49DSTUGCyKSkaEHC8.jpg','https://image.tmdb.org/t/p/original/rG8rGUrK3Ur6N2DuTVvjrtpV44l.jpg','After clearing brush for the government, a group of men return to town claiming their friend was abducted. Despite no apparent motive or evidence of foul play, no-one believes their story and his disappearance is treated as murder.',NULL,NULL,3.3359,6.665,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2398,20182,'tt0142074',NULL,'Alien Abduction: Incident in Lake County','Alien Abduction: Incident in Lake County','movie',1998,'https://image.tmdb.org/t/p/w500/ix6kUUS6UkbzzTb3gVzHk9QcNxY.jpg','https://image.tmdb.org/t/p/original/gHsz9q4OXw4dBfh3aDvnCkKzsRb.jpg','After a mysterious blackout, a son goes out to investigate and captures footage of actual aliens. When the aliens follow he and his brothers back to their home all hell breaks lose.',NULL,NULL,1.4711,7.336,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2399,204611,'tt0169005',NULL,'UFO Abduction','UFO Abduction','movie',1989,'https://image.tmdb.org/t/p/w500/Ap6zknBoIHaioieVfOLd5qaWd4X.jpg','https://image.tmdb.org/t/p/original/rNTwEIoF85FVnNITLriwxlQE7QW.jpg','On October 8th, 1983, the Van Heese family gathered together to celebrate the 5th birthday of Michelle, the littlest member of their household. Everything was captured on VHS by Michael McPherson and his new camcorder — including the alien invasion.',NULL,NULL,1.0648,5.261,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2400,34028,'tt0090293',NULL,'Warning Sign','Warning Sign','movie',1985,'https://image.tmdb.org/t/p/w500/bcwnXp1fESWS4oMnEgSgT7weEWC.jpg','https://image.tmdb.org/t/p/original/9SSPezaZ3VrilgXmSvYuuTnzF8R.jpg','An accident occurs in an ultra-secret government biological weapons laboratory spreading a sinister bacteria.',NULL,NULL,1.279,5.909,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2401,612515,'tt8269120',NULL,'Dark Encounter','Dark Encounter','movie',2019,'https://image.tmdb.org/t/p/w500/nc18JXQ4yLkClFFJQUYgFahMBhZ.jpg','https://image.tmdb.org/t/p/original/w2URHrf9cjU3iG7IQGjpACLT5a2.jpg','A year after the mysterious disappearance of an 8 year-old girl, we meet her grieving family as they return home from her memorial service in their small town. Later that evening, strange lights appear in the nearby forest and the family is exposed to an inexplicably strange phenomenon that rattles them to the core. The origin of the lights appear to be visitors from another world that seemingly terrorize the family. What they don''t realize is that these ''beings'' will lead the family to the truth behind the little girl''s disturbing disappearance.',NULL,NULL,0.8901,5.302,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2402,446159,'tt2762506',NULL,'Bacurau','Bacurau','movie',2019,'https://image.tmdb.org/t/p/w500/tBa4zMGzZUco26XT3WfZZCwQ76i.jpg','https://image.tmdb.org/t/p/original/nhsC7Q1Zb5n2p4H3UKy422zP5XC.jpg','Bacurau, a small town in the Brazilian sertão, mourns the loss of its matriarch, Carmelita, who lived to be 94. Days later, its inhabitants notice that their community has vanished from most maps.',NULL,NULL,1.4756,7.6,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2403,4104,'tt0106387',NULL,'Benny & Joon','Benny & Joon','movie',1993,'https://image.tmdb.org/t/p/w500/7g7qYdUN9wDXJGIOj6U67RPIBHO.jpg','https://image.tmdb.org/t/p/original/2TkuCpt75P5CyRgW1606dkY4JwM.jpg','A mentally ill young woman finds her love in an eccentric man who models himself after Buster Keaton.',NULL,NULL,2.2141,7.024,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2404,10707,'tt0367089',NULL,'The Squid and the Whale','The Squid and the Whale','movie',2005,'https://image.tmdb.org/t/p/w500/9NbXn1NMdfGM491V3EFjZADR9SX.jpg','https://image.tmdb.org/t/p/original/3ZjxENlw4HXioGGwhqaJrvdEXKo.jpg','Based on the true childhood experiences of Noah Baumbach and his brother, The Squid and the Whale tells the touching story of two young boys dealing with their parents'' divorce in Brooklyn in the 1980s.',NULL,NULL,2.3611,6.956,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2405,101,'tt0110413',NULL,'Léon: The Professional','Léon','movie',1994,'https://image.tmdb.org/t/p/w500/bxB2q91nKYp8JNzqE7t7TWBVupB.jpg','https://image.tmdb.org/t/p/original/fj0hwDJEOOHllRim2BMt5L7tbjf.jpg','Léon, the top hit man in New York, has earned a rep as an effective "cleaner". But when his next-door neighbors are wiped out by a loose-cannon DEA agent, he becomes the unwilling custodian of 12-year-old Mathilda. Before long, Mathilda''s thoughts turn to revenge, and she considers following in Léon''s footsteps.',NULL,NULL,20.1169,8.294,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2406,NULL,NULL,243296,'The Last of Us Part I: Digital Deluxe Edition','The Last of Us Part I: Digital Deluxe Edition','game',2022,'https://images.igdb.com/igdb/image/upload/t_cover_big/coa1gs.jpg',NULL,'Experience the emotional storytelling and unforgettable characters in The Last of Us, winner of over 200 Game of the Year awards.

The Digital Deluxe Edition includes:
- Complete The Last of Us single-player story (PS5).
- Celebrated prequel chapter, Left Behind, which explores the events that changed the lives of Ellie and her best friend Riley forever.

Early unlock of the following in-game items:
- Increased Crafting Speed Skill.
- Increased Healing Speed Skill.
- 9mm Reload Speed Increase Upgrade.
- Rifle Clip Capacity Increase Upgrade.
- Explosive Arrows Gameplay Modifier.
- Dither Punk Filter.
- Speedrun Mode.
- Six Weapon Skins: Black Gold 9mm Pistol, Silver Filigree 9mm Pistol, Rubber Tactical Shotgun, Sculpted Oak Shotgun, Arctic White Bow, Carbon Black Bow.','https://www.igdb.com/games/the-last-of-us-part-i-digital-deluxe-edition','["PC (Microsoft Windows)", "PlayStation 5"]',NULL,NULL,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2407,259694,'tt1292566',NULL,'How to Be Single','How to Be Single','movie',2016,'https://image.tmdb.org/t/p/w500/a4Ce3qHqIyHM3QfGsiVTAu3YADJ.jpg','https://image.tmdb.org/t/p/original/bCakS265nbi6fYB3bwuzVLAsjsv.jpg','New York City is full of lonely hearts seeking the right match, and what Alice, Robin, Lucy, Meg, Tom and David all have in common is the need to learn how to be single in a world filled with ever-evolving definitions of love.',NULL,NULL,4.9739,6.256,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2408,18197,'tt0096018',NULL,'Running on Empty','Running on Empty','movie',1988,'https://image.tmdb.org/t/p/w500/kzhyruFxY4Z5Ert8M9tuM2MV8dd.jpg','https://image.tmdb.org/t/p/original/xZGCJleQaeqi5jFsvcOoqfsMZvT.jpg','The Popes are a family who haven''t been able to use their real identity for years. In the late sixties, the parents set a weapons lab afire in an effort to hinder the government''s Vietnam war campaign. Ever since then, the Popes have been on the run with the authorities never far behind. Their survival is threatened when their eldest son falls in love with a girl, and announces his wish to live his life on his own terms.',NULL,NULL,1.6275,7.452,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2409,5761,'tt0841108',NULL,'Hannah Takes the Stairs','Hannah Takes the Stairs','movie',2007,'https://image.tmdb.org/t/p/w500/hy0wRpAtjed2yV1WE78gWj4BLrJ.jpg','https://image.tmdb.org/t/p/original/gsLIPjKTKA8Hr46Br9Nlc92SsMH.jpg','Hannah is a recent college graduate interning at a Chicago production company. She is crushing on two writers at work, Matt and Paul, who share an office and keep her entertained. Will a relationship with one of them disrupt the delicate balance of their friendship?',NULL,NULL,0.8082,5.245,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2410,33693,'tt0327753',NULL,'Funny Ha Ha','Funny Ha Ha','movie',2003,'https://image.tmdb.org/t/p/w500/4UsciNkAvuOZiM7ZfgLbfNR0WNJ.jpg','https://image.tmdb.org/t/p/original/xdA871I2bdUKyKM4OOiHSLJjpjC.jpg','Unsure of what to do next, 23-year-old Marnie tries her best to navigate life after college. Still partying like there''s no tomorrow, Marnie drags herself out of bed for her miserable temp job and can''t decide whether she''s wasting her time going after best buddy Alex, who doesn''t seem to be interested.',NULL,NULL,1.2552,6.2,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2411,55803,'tt0116121',NULL,'Dogs: The Rise and Fall of an All-Girl Bookie Joint','Dogs: The Rise and Fall of an All-Girl Bookie Joint','movie',1997,'https://image.tmdb.org/t/p/w500/hR8Zk85Y6IapEHlE4YNzfJPwTKu.jpg',NULL,'Four twenty-something women, crammed into a small Manhattan apartment, have dead end jobs (or no job) and overdue rent. They discover cash and self esteem when they set up an illegal bookie joint in their kitchen. Suddenly they can pay their bills; they imagine joining the middle class; they even make corporate donations to charity. The film also explores their relationships with men, most of whom are unfit for anything lasting, and with their mothers, who appear in surreal, imagined conversations with their daughters.',NULL,NULL,0.2741,7.0,0,10.06,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2412,1010639,'tt27546190',NULL,'The Sweet East','The Sweet East','movie',2023,'https://image.tmdb.org/t/p/w500/luWKeAedGQwNu3AdzygaBQN4h8f.jpg','https://image.tmdb.org/t/p/original/5bBrVV70UmJ0f5LmwMOZDHYDMcz.jpg','A picaresque journey through contemporary America, undertaken by a young woman granted access to the strange sects and cults that proliferate in this country by a series of gatekeepers eager to win her over.',NULL,NULL,1.3593,6.51,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2413,2898,'tt0119822',NULL,'As Good as It Gets','As Good as It Gets','movie',1997,'https://image.tmdb.org/t/p/w500/xXxuJPNUDZ0vjsAXca0O5p3leVB.jpg','https://image.tmdb.org/t/p/original/x7y8ezKtU1vRInk0dmbvDoKgJ8u.jpg','A misanthropic author, a single mother and waitress, and a gay artist form an unlikely friendship after the artist is assaulted in a robbery.',NULL,NULL,4.7668,7.402,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2414,1845,'tt0841044',NULL,'2 Days in Paris','2 Days in Paris','movie',2007,'https://image.tmdb.org/t/p/w500/4yf8vcgJtADTTPP0Ltq2KhqLfdE.jpg','https://image.tmdb.org/t/p/original/jyaCqYH5gLEp0Z9oZJ8nQrQM9pA.jpg','Marion and Jack try to rekindle their relationship with a visit to Paris, home of Marion''s parents — and several of her ex-boyfriends.',NULL,NULL,1.8104,6.251,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2415,2269,'tt0409904',NULL,'Day Watch','Дневной Дозор','movie',2006,'https://image.tmdb.org/t/p/w500/c99EkthlyDtdVh0xTaKsk9PRDg1.jpg','https://image.tmdb.org/t/p/original/s0ChBkAuxCm1eNOkPvMccW9PMix.jpg','A man who serves in the war between the forces of Light and Dark comes into possession of a device that can restore life to Moscow, which was nearly destroyed by an apocalyptic event.',NULL,NULL,1.4318,6.105,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2416,275060,'tt3720788',NULL,'The Disappearance of Eleanor Rigby: Her','The Disappearance of Eleanor Rigby: Her','movie',2014,'https://image.tmdb.org/t/p/w500/ynQT7JLYoLwV8P2ropoQEpTH7gG.jpg','https://image.tmdb.org/t/p/original/zWjcyGONx6RayBlOmDMOkXIrsuT.jpg','Told from the woman''s perspective, the story of a couple trying to reclaim the life and love they once knew and pick up the pieces of a past that may be too far gone.',NULL,NULL,1.7907,6.66,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2417,661539,'tt11563598',NULL,'A Complete Unknown','A Complete Unknown','movie',2024,'https://image.tmdb.org/t/p/w500/llWl3GtNoXosbvYboelmoT459NM.jpg','https://image.tmdb.org/t/p/original/otugS74HEHdca4aTCtt8HtXvPYV.jpg','New York, early 1960s. Against the backdrop of a vibrant music scene and tumultuous cultural upheaval, an enigmatic 19-year-old from Minnesota arrives in the West Village with his guitar and revolutionary talent, destined to change the course of American music.',NULL,NULL,6.373,7.068,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2418,17127,'tt0120772',NULL,'The Object of My Affection','The Object of My Affection','movie',1998,'https://image.tmdb.org/t/p/w500/2mA6QEdzhsftNIFV11SGsQLJvJR.jpg','https://image.tmdb.org/t/p/original/9ItSJKC4O77Uk2yULvSYdV6F171.jpg','A pregnant New York social worker begins to develop romantic feelings for her gay best friend, and decides she''d rather raise her child with him, much to the dismay of her overbearing boyfriend.',NULL,NULL,1.7643,5.831,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2419,31304,'tt0065955',NULL,'A Swedish Love Story','En kärlekshistoria','movie',1970,'https://image.tmdb.org/t/p/w500/bSIkQ7Yu8LEcZ8g85GkzSpHJRZ.jpg','https://image.tmdb.org/t/p/original/hdX3esdD6u0gUdU1oSAaNMFlFQk.jpg','The puppy love of two teenagers is set against a backdrop of adults struggling with their own lives. As a couple in love, they don''t care about anything but themselves and seem totally unaware about everything that surrounds them.',NULL,NULL,1.035,7.0,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2420,16372,'tt0055018',NULL,'The Innocents','The Innocents','movie',1961,'https://image.tmdb.org/t/p/w500/idqvLBmlEHUITMnQ0EJ6Yb5TpVw.jpg','https://image.tmdb.org/t/p/original/oog0DJtSuPnWoSTYM7cKmAFbeuU.jpg','In a mid-19th century Essex country house, a young governess for two children becomes convinced that the house and grounds are haunted by ghosts and that the children are being possessed.',NULL,NULL,1.7228,7.493,0,11.285,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2421,72844,'tt6763664',NULL,'The Haunting of Hill House','The Haunting of Hill House','tv',2018,'https://image.tmdb.org/t/p/w500/nWPZb800NCGiDPNGsKCfY0w44Z2.jpg','https://image.tmdb.org/t/p/original/dQF17lG4OZ3pC4QD9iNjaMS96gO.jpg','Flashing between past and present, a fractured family confronts haunting memories of their old home and the terrifying events that drove them from it.',NULL,NULL,10.961,8.105,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2422,340676,'tt4714782',NULL,'Personal Shopper','Personal Shopper','movie',2016,'https://image.tmdb.org/t/p/w500/cdm6qZgmbaIwjKBZnUSGWS4eyM2.jpg','https://image.tmdb.org/t/p/original/2I4Pe9EN5NlVC90X1JDrbYObZY5.jpg','Maureen, mid-20s, is a personal shopper for a media celebrity. The job pays for her stay in Paris, a city she refuses to leave until she makes contact with her twin brother who previously died there. Her life becomes more complicated when a mysterious person contacts her via text message.',NULL,NULL,1.9491,5.929,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2423,207774,'tt2781832',NULL,'The Borderlands','The Borderlands','movie',2014,'https://image.tmdb.org/t/p/w500/dNtkysYSyE3FcUGbdkooDckD16Y.jpg','https://image.tmdb.org/t/p/original/j6xyaXJO4oaE99QJGxggpeLbJ7j.jpg','Vatican investigators are sent to the British West Country to investigate paranormal activity, and they find the events are more disturbing than they first imagined.',NULL,NULL,1.7124,5.532,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2424,1246049,'tt31434030',NULL,'Dracula','Dracula','movie',2025,'https://image.tmdb.org/t/p/w500/dYRqA50yd0nB3qBR7AtWEJJQ8q.jpg','https://image.tmdb.org/t/p/original/be5SIsRGMckO8tU9lrLcIik70Dy.jpg','In late 15th-century Eastern Europe, Prince Vlad II’s bride is brutally murdered. As a result, he renounces God and damns Heaven itself. Cursed with eternal life, Vlad is reborn as Dracula, an immortal warlord who defies fate in a blood-soaked crusade to wrench his lost love back from death.',NULL,NULL,29.8175,7.2,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2425,2895,'tt0118632',NULL,'The Apostle','The Apostle','movie',1997,'https://image.tmdb.org/t/p/w500/9KqCzLhWbFMBPjqRpZ69izRiYgG.jpg','https://image.tmdb.org/t/p/original/iDNA5Bbl9NgcYbyn8dDrpnf2MUt.jpg','After his happy life spins out of control, a preacher from Texas changes his name, goes to Louisiana and starts preaching on the radio.',NULL,NULL,1.2418,6.325,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2426,413998,'tt4411596',NULL,'My Cousin Rachel','My Cousin Rachel','movie',2017,'https://image.tmdb.org/t/p/w500/lLPm7mjg8a8Y5veds4fhSWwvlFS.jpg','https://image.tmdb.org/t/p/original/gD9JOmzP5jGbb273Abp9ZVG2lnt.jpg','A young Englishman plots revenge against his mysterious, beautiful cousin, believing that she murdered his guardian. But his feelings become complicated as he finds himself falling under the beguiling spell of her charms.',NULL,NULL,1.7096,5.7,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2427,407559,'tt5059406',NULL,'I Am the Pretty Thing That Lives in the House','I Am the Pretty Thing That Lives in the House','movie',2016,'https://image.tmdb.org/t/p/w500/lq8ktDO2uqJFgV0jRlMQlPSmNm8.jpg','https://image.tmdb.org/t/p/original/vTfQfWUaj4QUJFvtCUHShIxrIuW.jpg','A young nurse takes care of an elderly author who lives in a haunted house.',NULL,NULL,1.0369,4.607,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2428,395,'tt0370263',NULL,'AVP: Alien vs. Predator','AVP: Alien vs. Predator','movie',2004,'https://image.tmdb.org/t/p/w500/ySWu5bCnnmgV1cVacvFnFIhgOjp.jpg','https://image.tmdb.org/t/p/original/xvq1RLaiwSdHwPHe7WUhqZa1rCA.jpg','When scientists discover something near Antarctica that appears to be a buried Pyramid, they send a research team out to investigate. Little do they know that they are about to step into a hunting ground where Aliens are grown as sport for the Predator race.',NULL,NULL,5.6821,6.0,0,12.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2429,256766,'tt2006753',NULL,'Heavenly Sword','Heavenly Sword','movie',2014,'https://image.tmdb.org/t/p/w500/wZzMbYDomCgj6LUN1b33ha7BiGh.jpg','https://image.tmdb.org/t/p/original/gKcFbx4QsanSNyblcsnycCEgKdq.jpg','The film''s plot follows that of the game closely. Nariko, a member of an ancient tribe who have guarded an ancient magical sword for thousands of years, is charged with bringing the sword to its destined wielder, a deity reincarnated who will bring peace to the land. But on her quest, Nariko must wield the sword herself against the forces of King Bohan, who wishes to possess the weapon himself.',NULL,NULL,1.1819,6.321,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2430,556694,'tt9198364',NULL,'Three Thousand Years of Longing','Three Thousand Years of Longing','movie',2022,'https://image.tmdb.org/t/p/w500/nS7DNl4A7XnDncZX70UJ8ALAihF.jpg','https://image.tmdb.org/t/p/original/90IcDDC47Rck4D2fyZbpZ1rbFZW.jpg','A solitary scholar discovers an ancient bottle while on a trip to Istanbul and unleashes a djinn who offers her three wishes. Filled with reluctance, she is unable to come up with one, so the djinn tries to inspire her with his stories.',NULL,NULL,5.4526,6.877,0,10.56,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2431,15927,'tt0087892',NULL,'A Passage to India','A Passage to India','movie',1984,'https://image.tmdb.org/t/p/w500/rvBWlGRKte2U6qElHV13h6JvmSe.jpg','https://image.tmdb.org/t/p/original/vhexJUk3sTEldSl3cI3eRzt6SZ5.jpg','Cultural mistrust and false accusations doom a friendship in British colonial India between an Indian doctor, an Englishwoman engaged to marry a city magistrate, and an English educator.',NULL,NULL,2.0166,6.839,0,9.53,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2432,1893,'tt0120915',NULL,'Star Wars: Episode I - The Phantom Menace','Star Wars: Episode I - The Phantom Menace','movie',1999,'https://image.tmdb.org/t/p/w500/xQzMnuiv81d0gfUIVstuleNutjA.jpg','https://image.tmdb.org/t/p/original/3TeGmKJfkik1D1rIoqGb1aR4k9c.jpg','Anakin Skywalker, a young slave strong with the Force, is discovered on Tatooine. Meanwhile, the evil Sith have returned, enacting their plot for revenge against the Jedi.',NULL,NULL,10.2442,6.6,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2433,14073,'tt0449994',NULL,'Jodhaa Akbar','जोधा अकबर','movie',2008,'https://image.tmdb.org/t/p/w500/gPjgeywFNTlh9IUuXWy85nn4h8J.jpg','https://image.tmdb.org/t/p/original/dwdH8HykILUADCIupGsqjcq1ygv.jpg','A sixteenth century love story about a marriage of alliance that gave birth to true love between a Mughal emperor and a Rajput princess.',NULL,NULL,1.6343,7.314,0,8.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2434,19026,'tt0439123',NULL,'Azur & Asmar: The Princes'' Quest','Azur et Asmar','movie',2006,'https://image.tmdb.org/t/p/w500/hkjdx0FbNGOt5QDD18jt0ZkPiHQ.jpg','https://image.tmdb.org/t/p/original/fBtaZ5QLYdfUiVgbcnTjzxGq6HD.jpg','Raised on tales of a Djinn fairy princess, Azur, a young Frenchman goes to North Africa in search of the sprite, only to discover that his close childhood friend, Asmar, an Arab youth whose mother raised both boys also seeks the genie.',NULL,NULL,1.4912,7.701,0,9.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2435,85,'tt0082971',NULL,'Raiders of the Lost Ark','Raiders of the Lost Ark','movie',1981,'https://image.tmdb.org/t/p/w500/ceG9VzoRAVGwivFU403Wc3AHRys.jpg','https://image.tmdb.org/t/p/original/zPACwR32amTNvzId9qyapCWXYDJ.jpg','When Dr. Indiana Jones – the tweed-suited professor who just happens to be a celebrated archaeologist – is hired by the government to locate the legendary Ark of the Covenant, he finds himself up against the entire Nazi regime.',NULL,NULL,16.1348,7.925,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2436,82362,'tt0071950',NULL,'Footprints on the Moon','Le orme','movie',1975,'https://image.tmdb.org/t/p/w500/hLEnjCTWzmxTpCgQBjuPhmkAi85.jpg','https://image.tmdb.org/t/p/original/aY5ScEWrBOpQmWiMfqoGtQKDpch.jpg','Alice, a young translator, finds the real world slowly merging with her recurring nightmares as she tries to solve the puzzle of her recent memory loss.  A postcard leads her to the island of Garma where the locals seems to know her.  Is she who she thinks she is?  And what significance does her dream of an astronaut abandoned on the moon have?',NULL,NULL,0.6268,6.269,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2437,692969,'tt11284280',NULL,'Cadaver','Kadaver','movie',2020,'https://image.tmdb.org/t/p/w500/j8pltHMcL3sAFqd6udZ1kMAlbQg.jpg','https://image.tmdb.org/t/p/original/pgBXz60Rf4zUaXleeIfR0ukIDhS.jpg','In the aftermath of a nuclear disaster, a starving family finds hope in a charismatic hotel owner. Lured by the prospect of a free dinner, they discover that the evening''s entertainment blurs the lines between performance and reality. Will they wind up the spectators or the spectacle?',NULL,NULL,0.9902,5.636,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2438,27019,'tt0071381',NULL,'Céline and Julie Go Boating','Céline et Julie vont en bateau','movie',1974,'https://image.tmdb.org/t/p/w500/h62tGTMdVVUThFwl5b4EP18cBhb.jpg','https://image.tmdb.org/t/p/original/oSr9IXgkJtpI6yeUkoDU3gfffBe.jpg','Julie, a daydreaming librarian, meets Céline, an enigmatic magician, and together they become the heroines of a time-warping adventure involving a haunted house, psychotropic candy, and a murder-mystery melodrama.',NULL,NULL,1.3238,6.807,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2439,1574,'tt0299658',NULL,'Chicago','Chicago','movie',2002,'https://image.tmdb.org/t/p/w500/3ED8cWCXY9zkx77Sd0N5qMbsdDP.jpg','https://image.tmdb.org/t/p/original/euxYhuuJjChU755u2YHj0ZPjww3.jpg','Murderesses Velma Kelly and Roxie Hart find themselves on death row together and fight for the fame that will keep them from the gallows in 1920s Chicago.',NULL,NULL,4.0998,7.136,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2440,11673,'tt0099334',NULL,'Cyrano de Bergerac','Cyrano de Bergerac','movie',1990,'https://image.tmdb.org/t/p/w500/80XJ5UkGuYTKDuALeG03BLk1OT1.jpg','https://image.tmdb.org/t/p/original/bvpYJgsC5jcMJd43HRHXUQw7j5O.jpg','Famed swordsman and poet Cyrano de Bergerac is in love with his cousin Roxane. He has never expressed his love for her as he his large nose undermines his self-confidence. Then he finds a way to express his love to her, indirectly.',NULL,NULL,1.7874,7.323,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2441,1407,'tt0450188',NULL,'La Vie en Rose','La Môme','movie',2007,'https://image.tmdb.org/t/p/w500/3b9DAONAsFRhJKu25R33PE3VwDh.jpg','https://image.tmdb.org/t/p/original/mgDv2dDihyetAcENxyf2tpXY245.jpg','From the mean streets of the Belleville district of Paris to the dazzling limelight of New York''s most famous concert halls, Edith Piaf''s life was a constant battle to sing and survive, to live and love. Raised in her grandmother''s brothel, Piaf was discovered in 1935 by nightclub owner Louis Leplee, who persuaded her to sing despite her extreme nervousness. Piaf became one of France''s immortal icons, her voice one of the indelible signatures of the 20th century.',NULL,NULL,2.6131,7.366,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2442,10997,'tt0106332',NULL,'Farewell My Concubine','霸王别姬','movie',1993,'https://image.tmdb.org/t/p/w500/f54hNIiHNINw3JiUJB2XaQl5wCN.jpg','https://image.tmdb.org/t/p/original/bBiZN1epQTu3F8iFLBuMhc4TRzr.jpg','In an epic tale of theater, gender, love and class, two Beijing opera actors navigate political turmoil as their friendship evolves over decades.',NULL,NULL,32.5137,7.91,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2443,28971,'tt0044837',NULL,'Limelight','Limelight','movie',1952,'https://image.tmdb.org/t/p/w500/wNWQS4cPTVtyOPzMZ9HSjmOLZ97.jpg','https://image.tmdb.org/t/p/original/q5vgDhmDS4EoYWrk9f9nqYZGDOw.jpg','A fading music hall comedian tries to help a despondent ballet dancer learn to walk and to again feel confident about life.',NULL,NULL,2.626,7.898,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2444,20115,'tt0093677',NULL,'Opera','Opera','movie',1987,'https://image.tmdb.org/t/p/w500/v5VBvSVu2sWLAmyQhKQwBV5aPJA.jpg','https://image.tmdb.org/t/p/original/jh1TMz3AUe40HbCigQ7weCDEW0d.jpg','A young opera singer is stalked by a deranged fan bent on killing the people associated with her to claim her for himself.',NULL,NULL,3.8722,6.8,0,8.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2445,579047,'tt3272066',NULL,'Reminiscence','Reminiscence','movie',2021,'https://image.tmdb.org/t/p/w500/17siH6wJRQ2jZiqz9BWUhy1UtZ.jpg','https://image.tmdb.org/t/p/original/8yhWlFcJ8zCqjfCvLy3lWFuawR1.jpg','Nicolas Bannister, a rugged and solitary veteran living in a near-future Miami flooded by rising seas, is an expert in a dangerous occupation: he offers clients the chance to relive any memory they desire. His life changes when he meets a mysterious young woman named Mae. What begins as a simple matter of lost and found becomes a passionate love affair. But when a different client''s memories implicate Mae in a series of violent crimes, Bannister must delve through the dark world of the past to uncover the truth about the woman he fell for.',NULL,NULL,2.3602,6.511,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2446,299245,'tt2309260',NULL,'The Gallows','The Gallows','movie',2015,'https://image.tmdb.org/t/p/w500/4oBk2DsYRO0VuloOX52ROmz2QhU.jpg','https://image.tmdb.org/t/p/original/x736Ayub2V1pSldtzigS35owWNN.jpg','20 years after a horrific accident during a small town school play, students at the school resurrect the failed show in a misguided attempt to honor the anniversary of the tragedy - but soon discover that some things are better left alone.',NULL,NULL,1.3516,4.9,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2447,4459,'tt0074028',NULL,'The Muppet Show','The Muppet Show','tv',1976,'https://image.tmdb.org/t/p/w500/x1aZsosXqaCpZTI12lLpNYIj6HX.jpg','https://image.tmdb.org/t/p/original/9UyPl2zR9dckpnmBWP6Xz4E6P3G.jpg','Go behind the curtains as Kermit the Frog and his muppet friends struggle to put on a weekly variety show.',NULL,NULL,7.7798,8.009,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2448,1124,'tt0482571',NULL,'The Prestige','The Prestige','movie',2006,'https://image.tmdb.org/t/p/w500/Ag2B2KHKQPukjH7WutmgnnSNurZ.jpg','https://image.tmdb.org/t/p/original/z3br1ub7spqGMkxgjgJSdM4DC21.jpg','A mysterious story of two magicians whose intense rivalry leads them on a life-long battle for supremacy -- full of obsession, deceit and jealousy with dangerous and deadly consequences.',NULL,NULL,19.2912,8.21,0,1.26099999999999976e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2449,46435,'tt0151568',NULL,'Topsy-Turvy','Topsy-Turvy','movie',1999,'https://image.tmdb.org/t/p/w500/nxHjVAVOFgWbD2RptBBCLVO6SIR.jpg','https://image.tmdb.org/t/p/original/vuB822fEemGIv5CXhd05OVFiroI.jpg','For nearly a decade, Gilbert and Sullivan’s collaborations have delighted the English people. But in 1884, as a London heat wave cuts into the theater trade, their latest work, "Princess Ida", receives lukewarm press. In an effort to reconcile their creative differences and drawing inspiration from Japanese culture, they went on to create the hit opera "The Mikado", one of the duo''s greatest successes.',NULL,NULL,1.5708,6.6,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2450,55787,'tt1067583',NULL,'Water for Elephants','Water for Elephants','movie',2011,'https://image.tmdb.org/t/p/w500/8T7Hvb9trKvCAmbSI8cEIU0Sl2T.jpg','https://image.tmdb.org/t/p/original/12xU204ABgr31iCTM57JT6wGFMg.jpg','In this captivating Depression-era melodrama, impetuous veterinary student Jacob Jankowski joins a celebrated circus as an animal caretaker but faces a wrenching dilemma when he''s transfixed by angelic married performer Marlena.',NULL,NULL,3.0328,6.931,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2451,788929,'tt9812474',NULL,'Lamb','Dýrið','movie',2021,'https://image.tmdb.org/t/p/w500/gP9yviboTGWGolqUZKIB1UkF1C2.jpg','https://image.tmdb.org/t/p/original/96uOMED23ZLBtb0HQQ5Urr3qMRp.jpg','An Icelandic couple live with their herd of sheep on a beautiful but remote farm. When they discover a mysterious newborn on their land, they decide to keep it and raise it as their own. This unexpected development and the prospects of a new family brings them much joy before ultimately destroying them.',NULL,NULL,2.391,6.427,0,1.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2452,976720,'tt20225374',NULL,'Vesper','Vesper','movie',2022,'https://image.tmdb.org/t/p/w500/etvK8ni1adjXU8obDpdUxTTQT6n.jpg','https://image.tmdb.org/t/p/original/uczbEzBD4jJ7EYxySarXeh2liF5.jpg','After the collapse of Earth''s ecosystem, Vesper, a 13-year-old girl struggling to survive with her paralyzed Father, meets a mysterious Woman with a secret that forces Vesper to use her wits, strength and bio-hacking abilities to fight for the possibility of a future.',NULL,NULL,1.635,6.279,0,1.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2453,674324,'tt11813216',NULL,'The Banshees of Inisherin','The Banshees of Inisherin','movie',2022,'https://image.tmdb.org/t/p/w500/4yFG6cSPaCaPhyJ1vtGOtMD1lgh.jpg','https://image.tmdb.org/t/p/original/1vXD5HXqkhvsXFHE7KmCPZGPR1e.jpg','Two lifelong friends find themselves at an impasse when one abruptly ends their relationship, with alarming consequences for both of them.',NULL,NULL,4.7825,7.464,0,1.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2454,330459,'tt3748528',NULL,'Rogue One: A Star Wars Story','Rogue One: A Star Wars Story','movie',2016,'https://image.tmdb.org/t/p/w500/i0yw1mFbB7sNGHCs7EXZPzFkdA1.jpg','https://image.tmdb.org/t/p/original/6t8ES1d12OzWyCGxBeDYLHoaDrT.jpg','A rogue band of resistance fighters unite for a mission to steal the Death Star plans and bring a new hope to the galaxy.',NULL,NULL,9.6222,7.509,0,1.34,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2455,NULL,NULL,2207,'Shadow of the Colossus','Shadow of the Colossus','game',2005,'https://images.igdb.com/igdb/image/upload/t_cover_big/co1ozz.jpg',NULL,'An open-world action/adventure game in which a young wanderer, along with a stolen magical sword and his steed companion, trespasses a cursed land, makes a deal with an ancient being to bring a sacrificial victim back to life, and sets off to fulfill his end of the bargain, which involves tracking down and infiltrating the abodes of sixteen colossi and sacrificing them to achieve his goal.','https://www.igdb.com/games/shadow-of-the-colossus','["PlayStation 2"]',NULL,NULL,0,1.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2456,9922,'tt0119925',NULL,'The Postman','The Postman','movie',1997,'https://image.tmdb.org/t/p/w500/piVzOuKFLHNGLxnjwNtibC26lTy.jpg','https://image.tmdb.org/t/p/original/5mwd1quVNkdwImOF2RGm90hKZ5P.jpg','In 2013, there are no highways, no I-ways, no dreams of a better tomorrow, only scattered survivors across what was once the United States. Into this apocalyptic wasteland comes an enigmatic drifter with a mule, a knack for Shakespeare, and something yet undiscovered: the power to inspire hope.',NULL,NULL,3.4372,6.273,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2457,116745,'tt0359950',NULL,'The Secret Life of Walter Mitty','The Secret Life of Walter Mitty','movie',2013,'https://image.tmdb.org/t/p/w500/iAo1hlzsPV9XpYcLQp6Ud065tGO.jpg','https://image.tmdb.org/t/p/original/pzMrxeP9XkKOtQVUBPTq5yk4ck5.jpg','A timid magazine photo manager who lives life vicariously through daydreams embarks on a true-life adventure when a negative goes missing.',NULL,NULL,16.6798,7.225,0,1.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2458,37724,'tt1074638',NULL,'Skyfall','Skyfall','movie',2012,'https://image.tmdb.org/t/p/w500/d0IVecFQvsGdSbnMAHqiYsNYaJT.jpg','https://image.tmdb.org/t/p/original/wkA622CCN2X0uwpgqYEOnUYEDf5.jpg','When Bond''s latest assignment goes gravely wrong, agents around the world are exposed and MI6 headquarters is attacked. While M faces challenges to her authority and position from Gareth Mallory, the new Chairman of the Intelligence and Security Committee, it''s up to Bond, aided only by field agent Eve, to locate the mastermind behind the attack.',NULL,NULL,9.5571,7.263,0,1.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2459,960206,'tt19623228',NULL,'Godland','Vanskabte land','movie',2022,'https://image.tmdb.org/t/p/w500/s0cWPhzpKJ4kspaleMcOduHBFBw.jpg','https://image.tmdb.org/t/p/original/sKBB1Fh9YMiLMsUUCPvdcbpVTfo.jpg','In the late 19th century, a young Danish priest travels to a remote part of Iceland to build a church and photograph its people. But the deeper he goes into the unforgiving landscape, the more he strays from his purpose, the mission and morality.',NULL,NULL,1.3322,6.77,0,1.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2460,522402,'tt3420504',NULL,'Finch','Finch','movie',2021,'https://image.tmdb.org/t/p/w500/eEJtzD1F05xDipFEDY98CTH5yZn.jpg','https://image.tmdb.org/t/p/original/uoc358GH6Yl7TufbUKHkETPu64B.jpg','On a post-apocalyptic Earth, a robot, built to protect the life of his dying creator''s beloved dog, learns about life, love, friendship, and what it means to be human.',NULL,NULL,5.9934,7.813,0,1.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2461,109958,'tt10970552',NULL,'The Haunting of Bly Manor','The Haunting of Bly Manor','tv',2020,'https://image.tmdb.org/t/p/w500/vIXQ8UymmQ7zJEPrKJP3s3fSbhR.jpg','https://image.tmdb.org/t/p/original/iDYiSNqZlPNvYA4qL6gUs4Okkrh.jpg','After an au pair''s tragic death, Henry Wingrave hires a young American nanny to care for his orphaned niece and nephew who reside at Bly Manor with the estate''s chef Owen, groundskeeper Jamie and housekeeper, Mrs. Grose. But all is not as it seems at the manor, and centuries of dark secrets of love and loss are waiting to be unearthed in this chilling tale.',NULL,NULL,5.3032,7.564,0,11.59,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2462,27116,'tt0068294',NULL,'Bluebeard','Bluebeard','movie',1972,'https://image.tmdb.org/t/p/w500/fuVlMgyg4YnQQCxQ3OFJikvlXmX.jpg','https://image.tmdb.org/t/p/original/HiidlKN4AOLnQBJK3TLjASr6Uv.jpg','Baron von Sepper is an Austrian aristocrat noted for his blue-toned beard, and his appetite for beautiful wives. His latest spouse, an American beauty named Anne, discovers a vault in his castle that''s filled with the frozen bodies of several beautiful women.',NULL,NULL,1.2936,5.409,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2463,58428,'tt1594562',NULL,'The Innkeepers','The Innkeepers','movie',2012,'https://image.tmdb.org/t/p/w500/aC9XHtf0Opw2IJDVjSkL8eO71An.jpg','https://image.tmdb.org/t/p/original/hgP1lEgyxFFhU607nqn0FHmG859.jpg','During the final days at the Yankee Pedlar Inn, two employees determined to reveal the hotel''s haunted past begin to experience disturbing events as old guests check in for a stay.',NULL,NULL,3.3397,5.4,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2464,6591,'tt0068416',NULL,'What Have You Done to Solange?','Cosa avete fatto a Solange?','movie',1972,'https://image.tmdb.org/t/p/w500/eMwcPwaqPckzR0c312v0eCyfQ5U.jpg','https://image.tmdb.org/t/p/original/5J2ijG7v68e1BfoXG5JOQ9dQPgi.jpg','After several Catholic school pupils are murdered, a teacher who is having an affair with one of his students becomes a suspect. When other gruesome murders start occurring shortly thereafter, the teacher suspects that he may be the cause of them.',NULL,NULL,1.1083,6.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2465,1381027,'tt34381258',NULL,'Good Boy','Good Boy','movie',2026,'https://image.tmdb.org/t/p/w500/eWb841fMkSNly5gfL9J1N0xzVYI.jpg','https://image.tmdb.org/t/p/original/zeCuk7kwfhzRZMN2KoYTYODgpU3.jpg','Tommy, a volatile 19-year-old, revels in drugs, parties and violence. After getting separated from his friends on a drunken bender, he is abducted by a shadowy figure. He wakes to find himself imprisoned in the basement of a remote Yorkshire house, inhabited by a very strange family. But what unfolds is not what he could possibly expect.',NULL,NULL,11.8061,7.055,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2466,526051,'tt5834760',NULL,'Look Away','Look Away','movie',2018,'https://image.tmdb.org/t/p/w500/8WTEFOwFBx0mHurnEfv27I0FOe2.jpg','https://image.tmdb.org/t/p/original/x04SgdgxFGeNk2SLUnv9aXEuzQT.jpg','A timid and socially alienated 17-year-old high school student''s life is turned upside down when she switches places with her sinister mirror image.',NULL,NULL,2.6111,6.547,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2467,931,'tt0069995',NULL,'Don''t Look Now','Don''t Look Now','movie',1973,'https://image.tmdb.org/t/p/w500/ivWsU3QtcstImCTOjItsH0SAbNn.jpg','https://image.tmdb.org/t/p/original/8qi3gplNf48uLZnne09iiL4OvFG.jpg','While grieving a terrible loss, a married couple meet two mysterious sisters, one of whom gives them a message sent from the afterlife.',NULL,NULL,7.0851,6.922,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2468,334991,'tt4173478',NULL,'Journey to the Shore','岸辺の旅','movie',2015,'https://image.tmdb.org/t/p/w500/uZ2cQTV8vVxCPXztp4CE2E4gQu.jpg','https://image.tmdb.org/t/p/original/nygRqI0XXp3zCyBMnF1tX5kUN6B.jpg','Mizuki''s husband Yusuke has been missing for three years. He suddenly comes back home as a ghost and asks Mizuki to go on a trip with him. Their trip consists of visiting the people that helped Yusuke on his previous travel.',NULL,NULL,0.9025,6.6,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2469,38684,'tt1229822',NULL,'Jane Eyre','Jane Eyre','movie',2011,'https://image.tmdb.org/t/p/w500/3Cn7D0wEaxnvm8kTta1osNu3QJv.jpg','https://image.tmdb.org/t/p/original/am9WwUTZuUDuinVcyST4OxJ8vFs.jpg','After a bleak childhood, Jane Eyre goes out into the world to become a governess. As she lives happily in her new position at Thornfield Hall, she meets the dark, cold, and abrupt master of the house, Edward Rochester. Jane and her employer grow close in friendship and she soon finds herself falling in love with him. Happiness seems to have found Jane at last, but could Rochester''s terrible secret be about to destroy it forever?',NULL,NULL,8.3851,7.196,0,7.06000000000000049e+00,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2470,242828,'tt3398268',NULL,'When Marnie Was There','思い出のマーニー','movie',2014,'https://image.tmdb.org/t/p/w500/vug1dvDI1tSa60Z8qjCuUE7ntkO.jpg','https://image.tmdb.org/t/p/original/86l1gqKjhPn6Ypd8XSSIGx7ZikB.jpg','Upon being sent to live with relatives in the countryside due to an illness, an emotionally distant adolescent girl becomes obsessed with an abandoned mansion and infatuated with a girl who lives there - a girl who may or may not be real.',NULL,NULL,3.4214,7.934,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2471,19072,'tt0038363',NULL,'Blithe Spirit','Blithe Spirit','movie',1945,'https://image.tmdb.org/t/p/w500/mBKB90yS8Gti4QhcYGuUeJmeOoC.jpg','https://image.tmdb.org/t/p/original/xFqLWRaYqxNC2KfqvUcj5Ln4gmB.jpg','While holding a séance for skeptical novelist Charles Condomine, self-proclaimed ''spiritualist medium'' Madame Arcati inadvertently summons the spirit of his deceased first wife Elvira, leading to an increasingly complex love triangle with Ruth, his current wife of five years.',NULL,NULL,1.4747,6.961,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2472,54344,'tt2699128',NULL,'The Leftovers','The Leftovers','tv',2014,'https://image.tmdb.org/t/p/w500/NKJdryIFHr245Umq6gXsf7oULW.jpg','https://image.tmdb.org/t/p/original/rK9D7R4nzG3YGBktQY7VD5tGdtb.jpg','When 2% of the world''s population abruptly disappears without explanation, the world struggles to understand just what they''re supposed to do about it. This is the story of the people who didn''t make the cut.',NULL,NULL,20.6566,7.671,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2473,675885,'tt2764642',NULL,'Carmilla','Carmilla','movie',1980,'https://image.tmdb.org/t/p/w500/sH30y6HsVQbucm74XpT4jOii9w9.jpg','https://image.tmdb.org/t/p/original/rsGwHWzeX88ug5fRWIa7qAlH0CY.jpg','In 19th-century Styria, isolated Laura''s quiet life is upended by the arrival of mysterious, beautiful Carmilla, a female vampire with whom she develops an intense, homoerotic bond. As Laura''s life slowly drains, themes of forbidden desire, identity, and the supernatural are explored, culminating in Laura''s discovery of Carmilla''s vampiric nature and a confrontation with her ancient lineage.',NULL,NULL,0.6091,6.5,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2474,11787,'tt0042546',NULL,'Harvey','Harvey','movie',1950,'https://image.tmdb.org/t/p/w500/dgd82hYmpiXDM1G867HqNaWe8wj.jpg','https://image.tmdb.org/t/p/original/Ah7uiN6ws2QcBZhLdDfkiSJIX35.jpg','The story of Elwood P. Dowd who makes friends with a spirit taking the form of a human-sized rabbit named Harvey that only he sees (and a few privileged others on occasion also.) After his sister tries to commit him to a mental institution, a comedy of errors ensues. Elwood and Harvey become the catalysts for a family mending its wounds and for romance blossoming in unexpected places.',NULL,NULL,1.8489,7.685,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2475,1700361,'tt15720668',NULL,'Ringu Doorbell','Ringu Doorbell','movie',2021,'https://image.tmdb.org/t/p/w500/rjd9tpdGPS4GsoiS9a6CAS9sDfd.jpg',NULL,'The popular security doorbell meets the popular horror movie of the same name.',NULL,NULL,0.6023,1.0,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2476,749004,'tt13204490',NULL,'Petite Maman','Petite Maman','movie',2021,'https://image.tmdb.org/t/p/w500/fxl2ARZO2vRfUGDfqSz2bostauE.jpg','https://image.tmdb.org/t/p/original/yuXZXuS4RCTnCYScrRWBCNz2ywB.jpg','After the death of her beloved grandmother, eight-year-old Nelly meets a strangely familiar girl her own age in the woods. Instantly forming a connection with this mysterious new friend, Nelly embarks on a fantastical journey of discovery which helps her come to terms with this newfound loss.',NULL,NULL,2.3916,7.089,0,11.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2477,138843,'tt1457767',NULL,'The Conjuring','The Conjuring','movie',2013,'https://image.tmdb.org/t/p/w500/wVYREutTvI2tmxr6ujrHT704wGF.jpg','https://image.tmdb.org/t/p/original/ecKQlAEG95k62SMGhvX83oEqANK.jpg','Paranormal investigators Ed and Lorraine Warren work to help a family terrorized by a dark presence in their farmhouse. Forced to confront a powerful entity, the Warrens find themselves caught in the most terrifying case of their lives.',NULL,NULL,22.7678,7.541,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2478,1115379,'tt27590147',NULL,'Only the River Flows','河边的错误','movie',2023,'https://image.tmdb.org/t/p/w500/qdlcJnXY63t17xKFfROfafTbXsD.jpg','https://image.tmdb.org/t/p/original/jZjzMYXD8H9gnS1GMORTPynrHXI.jpg','Dedicated police detective Ma Zhe is tasked with solving a series of brutal murders in a rural Chinese town. As pressure mounts from his superiors, a hasty arrest is made, but while his colleagues celebrate, several clues push Ma Zhe deeper into a desperate investigation of his own.',NULL,NULL,2.5997,6.397,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2479,6537,'tt0464141',NULL,'The Orphanage','El orfanato','movie',2007,'https://image.tmdb.org/t/p/w500/vIpi1KtHLXUOfSVC2m6MqpjSPgL.jpg','https://image.tmdb.org/t/p/original/g6pNnKmvTkNlEvn0ScwstYvhFE.jpg','A woman brings her family back to her childhood home, which used to be an orphanage, intent on reopening it. Before long, her son starts to communicate with a new invisible friend.',NULL,NULL,3.5728,7.232,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2480,16373,'tt0037415',NULL,'The Uninvited','The Uninvited','movie',1944,'https://image.tmdb.org/t/p/w500/uwp5ahLmWliRyX3mPoLHU7BKhf5.jpg','https://image.tmdb.org/t/p/original/poCmeIQA2xL7GnGq9PMwUcJ4AgI.jpg','A pair of siblings from London [Ray Milland and Ruth Hussey] purchase a surprisingly affordable, lonely cliff-top house in Cornwall, England. Only to discover that it actually carries a ghostly price, and soon they’re caught up in a bizarre romantic triangle from beyond the grave. Rich in atmosphere, The Uninvited, directed by Lewis Allen, was groundbreaking for the seriousness with which it treated the supernatural, haunted house genre, and it remains an elegant and eerie experience, featuring a classic score by Victor Young. A tragic family past, a mysteriously locked room, cold chills, bumps in the night - this gothic Hollywood classic has it all.',NULL,NULL,1.5711,6.924,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2481,828651,NULL,NULL,'I Stopped by Your House Last Night and The Porch Lights Swallowed Me Up','I Stopped by Your House Last Night and The Porch Lights Swallowed Me Up','movie',2020,'https://image.tmdb.org/t/p/w500/aS83iJHCNCxUfthMvk0RXzVNWJc.jpg',NULL,'A mysterious set of circumstances transpire.',NULL,NULL,0.1383,0.0,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2482,428449,'tt6265828',NULL,'A Ghost Story','A Ghost Story','movie',2017,'https://image.tmdb.org/t/p/w500/rp5JPIyZi9sMob15l46zNQLe5cO.jpg','https://image.tmdb.org/t/p/original/2y2aqaScd7jsUee0ddI1iRNgwGq.jpg','Recently deceased, a white-sheeted ghost returns to his suburban home to console his bereft wife, only to find that in his spectral state he has become unstuck in time, forced to watch passively as the life he knew and the woman he loves slowly slip away.',NULL,NULL,3.3415,7.1,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2483,15356,'tt0830558',NULL,'The Girl Next Door','The Girl Next Door','movie',2007,'https://image.tmdb.org/t/p/w500/dXjLp7k7ILyg22T0s9VvpPKc9jn.jpg','https://image.tmdb.org/t/p/original/9M7CfAYjhdXJk7em6khWH2aUjq7.jpg','In a quiet suburban town in the summer of 1958, two recently orphaned sisters are placed in the care of their mentally unstable Aunt Ruth. But Ruth''s depraved sense of discipline will soon lead to unspeakable acts of abuse and torture that involve her young sons, the neighborhood children, and one 12-year-old boy whose life will be changed forever.',NULL,NULL,5.764,6.649,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2484,132232,'tt2023587',NULL,'Mama','Mama','movie',2013,'https://image.tmdb.org/t/p/w500/eo8BhR8Q5STmWE9sMLsEPagxmy6.jpg','https://image.tmdb.org/t/p/original/cu3uaBqPORcfpKQWaIjA1GJbvEg.jpg','Guillermo del Toro presents Mama, a supernatural thriller that tells the haunting tale of two little girls who disappeared into the woods the day that their parents were killed. When they are rescued years later and begin a new life, they find that someone or something still wants to come tuck them in at night.',NULL,NULL,5.379,6.295,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2485,11772,'tt0057129',NULL,'The Haunting','The Haunting','movie',1963,'https://image.tmdb.org/t/p/w500/fmpTnUKTcrpuxLSY23gQMUf9qu7.jpg','https://image.tmdb.org/t/p/original/9CVUzIPyBMnHsDDighQNgkDYsP9.jpg','Dr. John Markway recruits three strangers for a sleep-disorder study at the eerie and isolated Hill House. It soon becomes clear his real interest lies in the mansion itself and its sinister history, as they are forced to confront the nature of its horror…',NULL,NULL,2.1651,7.089,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2486,8358,'tt0162222',NULL,'Cast Away','Cast Away','movie',2000,'https://image.tmdb.org/t/p/w500/7lLJgKnAicAcR5UEuo8xhSMj18w.jpg','https://image.tmdb.org/t/p/original/oCFVYPXI4IfhtF3GapU2jkDicDI.jpg','Chuck Noland, a top international manager for FedEx, and Kelly, a Ph.D. student, are in love and heading towards marriage. Then Chuck''s plane to Malaysia crashes at sea during a terrible storm. He''s the only survivor, and finds himself marooned on a desolate island. With no way to escape, Chuck must find ways to survive in his new home.',NULL,NULL,10.07,7.665,0,1.28966666666666682e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2487,953,'tt0351283',NULL,'Madagascar','Madagascar','movie',2005,'https://image.tmdb.org/t/p/w500/zMpJY5CJKUufG9OTw0In4eAFqPX.jpg','https://image.tmdb.org/t/p/original/tPaurpIUskVji5vwV0dhy9pq4Vs.jpg','Four animal friends get a taste of the wild life when they break out of captivity at the Central Park Zoo and wash ashore on the island of Madagascar.',NULL,NULL,15.5312,6.926,0,12.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2488,87827,'tt0454876',NULL,'Life of Pi','Life of Pi','movie',2012,'https://image.tmdb.org/t/p/w500/iLgRu4hhSr6V1uManX6ukDriiSc.jpg','https://image.tmdb.org/t/p/original/21YsCNMub5455NQCn3jh9SmRFyG.jpg','The story of an Indian boy named Pi, a zookeeper''s son who finds himself in the company of a hyena, zebra, orangutan, and a Bengal tiger after a shipwreck sets them adrift in the Pacific Ocean.',NULL,NULL,10.7353,7.4,0,10.58,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2489,497828,'tt7322224',NULL,'Triangle of Sadness','Triangle of Sadness','movie',2022,'https://image.tmdb.org/t/p/w500/k9eLozCgCed5FGTSdHu0bBElAV8.jpg','https://image.tmdb.org/t/p/original/vNPY4oCSUp7CxbHkKJNRx1fmCl0.jpg','A celebrity model couple are invited on a luxury cruise for the uber-rich, helmed by an unhinged, alcoholic captain. What first appears Instagrammable ends catastrophically, leaving the survivors stranded on a desert island in a struggle of hierarchy.',NULL,NULL,4.91,7.015,0,11.545,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2490,10527,'tt0479952',NULL,'Madagascar: Escape 2 Africa','Madagascar: Escape 2 Africa','movie',2008,'https://image.tmdb.org/t/p/w500/agRbLOHgN46TQO4YdKR462iR7To.jpg','https://image.tmdb.org/t/p/original/3yXLkSTrVhG66MIAr3X6C4gjccw.jpg','Alex, Marty, and other zoo animals find a way to escape from Madagascar when the penguins reassemble a wrecked airplane. The precariously repaired craft stays airborne just long enough to make it to the African continent. There the New Yorkers encounter members of their own species for the first time. Africa proves to be a wild place, but Alex and company wonder if it is better than their Central Park home.',NULL,NULL,10.9618,6.527,0,10.52,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2491,421,'tt0362270',NULL,'The Life Aquatic with Steve Zissou','The Life Aquatic with Steve Zissou','movie',2004,'https://image.tmdb.org/t/p/w500/qZoFLNBC78jzboWeDH6Ha0qavF2.jpg','https://image.tmdb.org/t/p/original/7tWktnLQ81G8pHUkhuTebcTkcB3.jpg','Renowned oceanographer Steve Zissou has sworn vengeance upon the rare shark that devoured a member of his crew. In addition to his regular team, he is joined on his boat by Ned, a man who believes Zissou to be his father, and Jane, a journalist pregnant by a married man. They travel the sea, all too often running into pirates and, perhaps more traumatically, various figures from Zissou''s past, including his estranged wife, Eleanor.',NULL,NULL,3.125,7.075,0,11.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2492,254320,'tt3464902',NULL,'The Lobster','The Lobster','movie',2015,'https://image.tmdb.org/t/p/w500/7Y9ILV1unpW9mLpGcqyGQU72LUy.jpg','https://image.tmdb.org/t/p/original/iH2esZUZvt8qlJgu74WBvibDnfF.jpg','In a dystopian near future, single people, according to the laws of The City, are taken to The Hotel, where they are obliged to find a romantic partner in forty-five days or are transformed into animals and sent off into The Woods.',NULL,NULL,5.0987,7.024,0,10.51,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2493,116149,'tt1109624',NULL,'Paddington','Paddington','movie',2014,'https://image.tmdb.org/t/p/w500/wpchRGhRhvhtU083PfX2yixXtiw.jpg','https://image.tmdb.org/t/p/original/kfofK4GzJsJZhCShqZY438c8Y4Y.jpg','A young Peruvian bear travels to London in search of a home. Finding himself lost and alone at Paddington Station, he meets the kindly Brown family, who offer him a temporary haven.',NULL,NULL,5.0086,7.122,0,10.66,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2494,346648,'tt4468740',NULL,'Paddington 2','Paddington 2','movie',2017,'https://image.tmdb.org/t/p/w500/1OJ9vkD5xPt3skC6KguyXAgagRZ.jpg','https://image.tmdb.org/t/p/original/kRVUMsXFzhuXjr20JcCGc6TapxA.jpg','Paddington, now happily settled with the Browns, picks up a series of odd jobs to buy the perfect present for his Aunt Lucy, but it is stolen.',NULL,NULL,6.7944,7.479,0,11.15,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2495,10437,'tt0104940',NULL,'The Muppet Christmas Carol','The Muppet Christmas Carol','movie',1992,'https://image.tmdb.org/t/p/w500/ssrV29QSVVJuemBHho0Qx7pFYak.jpg','https://image.tmdb.org/t/p/original/kLVWvnUdqQ07WjbAYGpmiD2ZFQa.jpg','A retelling of the classic Dickens tale of Ebenezer Scrooge, miser extraordinaire. He is held accountable for his dastardly ways during night-time visitations by the Ghosts of Christmas Past, Present and Future.',NULL,NULL,3.0107,7.444,0,10.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2496,58876,NULL,NULL,'The Enchanted World of Brambly Hedge','The Enchanted World of Brambly Hedge','tv',1996,'https://image.tmdb.org/t/p/w500/vqn0Hhw76xGtQb6FOnvSXi1qRue.jpg','https://image.tmdb.org/t/p/original/5Lb6W2cw4sdlMqdb7wB4pcVk2uP.jpg','The Enchanted World of Brambly Hedge is a stop-motion animated series based on the Brambly Hedge books by Jill Barklem. The show was produced by Reader''s Digest Video and Hit Entertainment; in the United States, episodes began airing on the Starz premium channel in 1997.',NULL,NULL,0.7473,7.0,0,11.215,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2497,20334,'tt0033045',NULL,'The Shop Around the Corner','The Shop Around the Corner','movie',1940,'https://image.tmdb.org/t/p/w500/dZ1aEzGYRiqJwPfjS6VL7wUkHmF.jpg','https://image.tmdb.org/t/p/original/wqgZSvgoctaadgwUdPYVsksivxn.jpg','Two employees at a gift shop can barely stand one another, without realising that they are falling in love through the post as each other''s anonymous pen pal.',NULL,NULL,2.7644,8.062,0,10.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2498,381719,'tt5117670',NULL,'Peter Rabbit','Peter Rabbit','movie',2018,'https://image.tmdb.org/t/p/w500/lugOvdaNpbVGQK9TyMRDiUbLtY6.jpg','https://image.tmdb.org/t/p/original/1wj8H9gdtkb98Tl3zu0hrHfW0qw.jpg','Peter Rabbit''s feud with Mr. McGregor escalates to greater heights than ever before as they rival for the affections of the warm-hearted animal lover who lives next door.',NULL,NULL,8.4028,6.702,0,11.135,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2499,47825,'tt0264081',NULL,'The Tale of Beatrix Potter','The Tale of Beatrix Potter','tv',1982,'https://image.tmdb.org/t/p/w500/d4WUJbHyuYxxqTywW3yaecr6PSt.jpg',NULL,'',NULL,NULL,0.9274,8.0,0,10.26,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2500,47509,'tt0067570',NULL,'Tales of Beatrix Potter','Tales of Beatrix Potter','movie',1971,'https://image.tmdb.org/t/p/w500/xinf6K25syd6NxcMGnkpwRm6fFq.jpg','https://image.tmdb.org/t/p/original/hAfO79tvqaPO5K70WLLSGyfV98M.jpg','The Royal Ballet Company brings Squirrel Nutkin, Tom Thumb, Hunca Munca, Jemima Puddle-Duck, Jeremy Fisher, Pigling Bland, and Pigwig to the screen doing pirouettes and pas de deux in this filmed ballet production directed by Reginald Mills. The film more properly belongs, however, to choreographer Frederick Ashmore, composer John Lanchbery, and costume designer Rostislav Douboujinsky. This literal adaptation concerns the shy Beatrix Potter and how, when all of the toy animals in her room come to life, she emerges from her shell and begins to enjoy life. Sequences include a rowdy dance with Tom Thumb and Hunca Munca destroying a collection of plaster food, a midnight pas de deux between Pigling Bland and Pigwig, and a corps de ballet of dancing mice.',NULL,NULL,0.6558,6.179,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2501,251790,NULL,NULL,'Sylvanian Families','シルバニアファミリ','tv',2007,'https://image.tmdb.org/t/p/w500/lj9Mm43Ml8gWEtcySnnKh5FgPF3.jpg',NULL,'A 3-episode 3DCGI Original Video Animation in 2007 based on the Franchise of the same name.',NULL,NULL,0.9178,0.0,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2502,30060,'tt0084509',NULL,'The Plague Dogs','The Plague Dogs','movie',1982,'https://image.tmdb.org/t/p/w500/gLKf3C4O1ZlkWrz0awUfgRneumL.jpg','https://image.tmdb.org/t/p/original/FwV9a72BGBtaRpAEwvPaYfCMon.jpg','Two dogs, Rowf and Snitter, struggle to survive in the countryside after escaping from an animal research laboratory. They''re pursued by search parties and then the military after rumours spread that they could be carrying the bubonic plague.',NULL,NULL,2.0152,7.831,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2503,2849,'tt0283721',NULL,'The World of David the Gnome','David el gnomo','tv',1985,'https://image.tmdb.org/t/p/w500/9jvDfTtMVLbcNV0gyt69ROZa6Yb.jpg','https://image.tmdb.org/t/p/original/zRMZKPSz9ZboQkp5okd6vK7fmui.jpg','A Spanish animated television series based on the children''s book The Secret Book of Gnomes, by the Dutch author Wil Huygen and illustrator Rien Poortvliet.',NULL,NULL,2.6113,7.255,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2504,448491,'tt6083230',NULL,'Little Forest','리틀 포레스트','movie',2018,'https://image.tmdb.org/t/p/w500/gKmPuyjmALswSQUF94PWXoAvkKM.jpg','https://image.tmdb.org/t/p/original/vTw1MjLJfCFzFdq5iElKpjI0LIV.jpg','A young woman leaves the city to return to her hometown in the countryside. Seeking to escape the hustle and bustle of the city, she becomes self-sufficient in a bid to reconnect with nature.',NULL,NULL,1.6385,7.613,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2505,1362,'tt0077687',NULL,'The Hobbit','The Hobbit','movie',1977,'https://image.tmdb.org/t/p/w500/2ohvyMPhvjftLrM6S6Ljr6QrL0u.jpg','https://image.tmdb.org/t/p/original/qNVf39jp9fZSLd1bWMYjOrrEkI2.jpg','The story follows the adventures of Bilbo Baggins, a diminutive creative who resides in a place called Middle-Earth before he is compelled to go on a quest to find a treasure buried deep in the heart of the Lonely Mountain.',NULL,NULL,1.9577,6.6,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2506,250480,'tt0076363',NULL,'The Many Adventures of Winnie the Pooh','The Many Adventures of Winnie the Pooh','movie',1977,'https://image.tmdb.org/t/p/w500/nefc61WQGahSWoNRrndoqinrZQu.jpg','https://image.tmdb.org/t/p/original/19lyrve8NcorainRPLXELTDVnA2.jpg','Whether we’re young or forever young at heart, the Hundred Acre Wood calls to that place in each of us that still believes in magic. Join pals Pooh, Piglet, Kanga, Roo, Owl, Rabbit, Tigger and Christopher Robin as they enjoy their days together and sing their way through adventures.',NULL,NULL,3.107,7.2,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2507,242291,'tt26518389',NULL,'Quentin Blake''s Box of Treasures','Quentin Blake''s Box of Treasures','tv',2023,'https://image.tmdb.org/t/p/w500/rmjfzMO6Bk19o9vkzSyWkNGMyEg.jpg','https://image.tmdb.org/t/p/original/ro5vAaT305hXhXy4Idm1SbBlu0s.jpg','A unique collection of six animated stories from the world-famous illustrator and master storyteller.',NULL,NULL,1.4585,8.0,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2508,110416,'tt1865505',NULL,'Song of the Sea','Song of the Sea','movie',2014,'https://image.tmdb.org/t/p/w500/16LQC6zpqB0l74mVWb93a2oMFnX.jpg','https://image.tmdb.org/t/p/original/mVLZvSe1Aa8CFKx0cInTamVZJrW.jpg','The story of the last Seal Child’s journey home. After their mother’s disappearance, Ben and Saoirse are sent to live with Granny in the city. When they resolve to return to their home by the sea, their journey becomes a race against time as they are drawn into a world Ben knows only from his mother’s folktales. But this is no bedtime story; these fairy folk have been in our world far too long. It soon becomes clear to Ben that Saoirse is the key to their survival.',NULL,NULL,4.0452,7.991,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2509,929204,'tt17163970',NULL,'Wallace & Gromit: Vengeance Most Fowl','Wallace & Gromit: Vengeance Most Fowl','movie',2024,'https://image.tmdb.org/t/p/w500/jUWFSBxTOiCinPdTOh3IDUXVemZ.jpg','https://image.tmdb.org/t/p/original/XNVdWNgiAHu8y4BsJv5ndUHXxN.jpg','Gromit’s concern that Wallace is becoming too dependent on his inventions proves justified, when Wallace invents a “smart” gnome that seems to develop a mind of its own. When it emerges that a vengeful figure from the past might be masterminding things, it falls to Gromit to battle sinister forces and save his master… or Wallace may never be able to invent again!',NULL,NULL,3.8018,7.451,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2510,13396,'tt0084701',NULL,'The Snowman','The Snowman','movie',1982,'https://image.tmdb.org/t/p/w500/b3CMolkeXrPaVvd5vTsssMKfZZo.jpg','https://image.tmdb.org/t/p/original/aNCGvBqqrc9L6JKgujYkc2EKbXH.jpg','A young boy makes a snowman one Christmas Eve, which comes to life at midnight and takes him on a magical adventure to the North Pole to meet Santa Claus.',NULL,NULL,1.9461,7.575,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2511,644120,'tt8010354',NULL,'The Tiger Who Came to Tea','The Tiger Who Came to Tea','movie',2022,'https://image.tmdb.org/t/p/w500/56tm3E4FVosdTpdcnJrNqxIsKME.jpg','https://image.tmdb.org/t/p/original/8vNsKKl6NTVpfE6v93u4IR4jTyk.jpg','On a rainy day, a mother and daughter forego a trip to the park to bake pastries and partake in a two-person tea party when an unexpected guest menacingly invites himself into the house and ransacks the food and drink in the house.',NULL,NULL,0.461,6.4,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2512,1130737,'tt27836891',NULL,'Mog''s Christmas','Mog''s Christmas','movie',2023,'https://image.tmdb.org/t/p/w500/qbyQpVLnQNC89vfQyZDpV2INPz3.jpg','https://image.tmdb.org/t/p/original/ddD80YBC9h7Y1DQEYuxnP3ZeFzN.jpg','Mog feels a little ignored during the Thomas family''s Christmas preparations. When she spots the huge Christmas tree, she freaks out and climbs to the roof, where she refuses to move no matter how hard the family tries.',NULL,NULL,0.6959,7.3,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2513,272418,'tt33484460',NULL,'Robin Hood','Robin Hood','tv',2025,'https://image.tmdb.org/t/p/w500/3teWChNzKJdbfen46IdeKTygdZa.jpg','https://image.tmdb.org/t/p/original/uoIOfRNmu47P2fET2KnrYHt3TH.jpg','A modern reimagining of the classic tale. After the Norman invasion of England, Rob, a Saxon forester’s son, and Marian, a Norman lord’s daughter, fall in love and unite to fight for justice, challenge corruption, and restore peace to the land.',NULL,NULL,9.0868,7.5,0,10.18,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2514,508965,'tt4729430',NULL,'Klaus','Klaus','movie',2019,'https://image.tmdb.org/t/p/w500/q125RHUDgR4gjwh1QkfYuJLYkL.jpg','https://image.tmdb.org/t/p/original/cYQvXNPZLow73lhspVQ7CYlT3Mi.jpg','A selfish postman and a reclusive toymaker form an unlikely friendship, delivering joy to a cold, dark town that desperately needs it.',NULL,NULL,4.9614,8.222,0,13.0175,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2515,74534,'tt1412386',NULL,'The Best Exotic Marigold Hotel','The Best Exotic Marigold Hotel','movie',2012,'https://image.tmdb.org/t/p/w500/gNWiOKTWDvPTpr7QfPWk18gLftz.jpg','https://image.tmdb.org/t/p/original/zp5bc23EPflpLhkCObsFFOL3psw.jpg','British retirees travel to India to take up residence in what they believe is a newly restored hotel. Less luxurious than its advertisements, the Marigold Hotel nevertheless slowly begins to charm in unexpected ways as the residents find new purpose in their old age.',NULL,NULL,2.0922,6.952,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2516,754609,'tt5151570',NULL,'Mrs. Harris Goes to Paris','Mrs. Harris Goes to Paris','movie',2022,'https://image.tmdb.org/t/p/w500/eUg0HDLhTEDcXGBU2iK6QRBILv4.jpg','https://image.tmdb.org/t/p/original/AhkirfgU32n0D1uxpaGYJEKy2Hu.jpg','A 1950s London cleaning lady falls in love with an haute couture dress by Christian Dior and decides to gamble everything for the sake of this folly.',NULL,NULL,2.4704,7.308,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2517,76922,'tt7259746',NULL,'Queer Eye','Queer Eye','tv',2018,'https://image.tmdb.org/t/p/w500/zyuQwYNTkiPpyqiA9XAZuToZRhN.jpg','https://image.tmdb.org/t/p/original/7pCQzxyOOB4lyUuffvVzWOAqlYJ.jpg','An all-new “Fab Five” advise men on fashion, grooming, food, culture and design in this modern reboot of the Emmy Award-winning reality series.',NULL,NULL,11.3928,7.429,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2518,66134,'tt5014882',NULL,'The Durrells','The Durrells','tv',2016,'https://image.tmdb.org/t/p/w500/sgZiuQ9PMeyHU7xMaIctwRu4SLa.jpg','https://image.tmdb.org/t/p/original/lkb3NBvByVWBvr63wE4weHVFz4i.jpg','In 1935, financially strapped widow Louisa Durrell, whose life has fallen apart, decides to move from England, with her four children (three sons, one daughter), to the island of Corfu, Greece. Once there, the family moves into a dilapidated old house that has no electricity and that is crumbling apart. But life on Corfu is cheap, it''s an earthly paradise, and the Durrells proceed to forge their new existence, with all its challenges, adventures, and forming relationships.',NULL,NULL,7.0846,7.402,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2519,136311,'tt15677150',NULL,'Shrinking','Shrinking','tv',2023,'https://image.tmdb.org/t/p/w500/zEFKMNPBKq6JG7uuDkzTQ9WwErn.jpg','https://image.tmdb.org/t/p/original/hI9z1UuNhBthvkm3iJ8m3zv43Pf.jpg','Jimmy is struggling to grieve the loss of his wife while being a dad, friend, and therapist. He decides to try a new approach with everyone in his path: unfiltered, brutal honesty. Will it make things better—or unleash uproarious chaos?',NULL,NULL,25.4807,7.833,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2520,97546,'tt10986410',NULL,'Ted Lasso','Ted Lasso','tv',2020,'https://image.tmdb.org/t/p/w500/5fhZdwP1DVJ0FyVH6vrFdHwpXIn.jpg','https://image.tmdb.org/t/p/original/gEQkOMmnJcoh9Hh1vk7fpVYnksR.jpg','Ted Lasso, an American football coach, moves to England when he''s hired to manage a soccer team—despite having no experience. With cynical players and a doubtful town, will he get them to see the Ted Lasso Way?',NULL,NULL,40.1027,8.3,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2521,141,'tt0083399',NULL,'Cheers','Cheers','tv',1982,'https://image.tmdb.org/t/p/w500/nD1ZQBKbgKSmKcrAkWTofohsScj.jpg','https://image.tmdb.org/t/p/original/5U7NIuRK836GutAlo7TLPfmVtGW.jpg','The story about a blue-collar Boston bar run by former sports star Sam Malone and the quirky and wonderful people who worked and drank there.',NULL,NULL,41.7314,7.56,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2522,122906,'tt2194499',NULL,'About Time','About Time','movie',2013,'https://image.tmdb.org/t/p/w500/ls6zswrOZVhCXQBh96DlbnLBajM.jpg','https://image.tmdb.org/t/p/original/einbto9qLXFx9QXxEHylaxDbKPx.jpg','The night after another unsatisfactory New Year''s party, Tim''s father reveals to him that the men in their family have the ability to travel through time. They can''t change history, but they can change what happens and has happened in their own lives. Thus begins the start of a lesson in learning to appreciate life itself as it is, as it comes, and most importantly, the people living alongside us.',NULL,NULL,14.0701,7.907,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2523,245312,'tt26670955',NULL,'A Man on the Inside','A Man on the Inside','tv',2024,'https://image.tmdb.org/t/p/w500/c09XdTLpLku2tqHt158NZBgC4hi.jpg','https://image.tmdb.org/t/p/original/6EObfIe4akZGvCLXwXLJw3kPitQ.jpg','A retired professor with a knack for snooping gets a new lease on life when a private investigator recruits him to go undercover and crack a case.',NULL,NULL,9.1511,7.41,0,10.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2524,40075,'tt1865718',NULL,'Gravity Falls','Gravity Falls','tv',2012,'https://image.tmdb.org/t/p/w500/qwi3p6PzKfQZ4YXBzv3CP5pO2dE.jpg','https://image.tmdb.org/t/p/original/lhg7eA6CTOCL10QNVdKiyxkgPsL.jpg','Twin brother and sister Dipper and Mabel Pines are in for an unexpected adventure when they spend the summer helping their great uncle Stan run a tourist trap in the mysterious town of Gravity Falls, Oregon.',NULL,NULL,36.2704,8.618,0,6.1,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2525,15655,'tt0220099',NULL,'The Tigger Movie','The Tigger Movie','movie',2000,'https://image.tmdb.org/t/p/w500/9OdZKUdGfaBAUwRLbtWpFWKbILO.jpg','https://image.tmdb.org/t/p/original/60JMvMGuLHSlVjoUpi86UiB5Lmq.jpg','Winnie the Pooh, Piglet, Owl, Kanga, Roo, and Rabbit are preparing a suitable winter home for Eeyore, the perennially dejected donkey, but Tigger''s continual bouncing interrupts their efforts. Rabbit suggests that Tigger go find others of his kind to bounce with, but Tigger thinks "the most wonderful thing about tiggers is" he''s "the only one!" Just in case though, the joyously jouncy feline sets out to see if he can find relatives.',NULL,NULL,2.6683,6.675,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2526,453191,'tt5851904',NULL,'The Big Bad Fox and Other Tales','Le Grand Méchant Renard et autres contes...','movie',2017,'https://image.tmdb.org/t/p/w500/3Nib5a3p2O7yPFSTTNwChp0cnsh.jpg','https://image.tmdb.org/t/p/original/xte6dUGLvFss0ZJIau9avtrfTQR.jpg','The countryside isn''t always as calm and peaceful as it''s made out to be, and the animals on this farm are particularly agitated: a fox who mothers a family of chicks, a rabbit who plays the stork, and a duck who wants to be Santa Claus.',NULL,NULL,0.9808,7.717,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2527,38782,'tt0086590',NULL,'The Wind in the Willows','The Wind in the Willows','movie',1983,'https://image.tmdb.org/t/p/w500/Dgg7N0bukwmVJU2c1UtgxpdpDB.jpg','https://image.tmdb.org/t/p/original/hhnzRodAKHCkIYoaOcN6GXQBM3g.jpg','One spring, Mole decides that he can ignore the spring cleaning for a little longer, and begins a series of adventures with his new friend Rat. They go for a picnic on the riverbank, on a caravan expedition with Toad, until Toad switches allegiance to his new car and his reckless driving makes Mole and Rat search out Badger for help in curbing Toad''s profligate habits. But Toad gets away from them and gets a 20-year sentence from the magistrate for theft, reckless driving, and Gross Impertinence. While Toad works his wiles on the jailer''s daughter and escapes jail dressed as a washer woman, Badger tries to guard Toad Hall from the machinations of the Weasels and is badly beaten. And it requires a plan of attack and all four comrades to regain Toad Hall.',NULL,NULL,0.7549,6.955,0,10.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2528,59179,'tt0286309',NULL,'The Willows in Winter','The Willows in Winter','movie',1996,'https://image.tmdb.org/t/p/w500/ApcDl7gBpUjDfc0rolP0sHPwSxo.jpg','https://image.tmdb.org/t/p/original/npNlWTsI31FdlxrdvkMAeQjXkjN.jpg','Hailed as the "rightful heir" to "The Wind in the Willows", William Horwood''s critically acclaimed sequel comes to magical life in this beautifully animated feature-length classic. Join four of the best-loved characters in children''s literature for their heart-warming and hilarious new adventure along the Riverbank, narrated by Academy Award-winner Vanessa Redgrave.',NULL,NULL,0.8094,6.667,0,10.08,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2529,1020969,'tt21054736',NULL,'Teddy''s Christmas','Teddybjørnens Jul','movie',2022,'https://image.tmdb.org/t/p/w500/jEf96axaZhZQEu9ORVtEujBTG9p.jpg','https://image.tmdb.org/t/p/original/8FWC4tDWB1p006vwiubhai4a8iS.jpg','While visiting a Christmas market in her Norwegian town, eight year old Mariann spots a talking teddy bear at a carnival game booth. However, when someone else wins it, she embarks on a quest to find the adorable bear that captured her heart.',NULL,NULL,4.3852,6.991,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2530,21394,'tt0090610',NULL,'The Children of Noisy Village','Alla vi barn i Bullerbyn','movie',1986,'https://image.tmdb.org/t/p/w500/3J8XDd1MmwfWlUFktdw313otVbR.jpg','https://image.tmdb.org/t/p/original/hZ7oCK4pWbsnHwX6OXhw0VgjSSl.jpg','The story of the children who live in Bullerbyn, Sweden, through the spring and summer months.',NULL,NULL,1.092,6.3,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2531,20785,'tt0075988',NULL,'Emmet Otter''s Jug-Band Christmas','Emmet Otter''s Jug-Band Christmas','movie',1977,'https://image.tmdb.org/t/p/w500/jng1wnVzIBdtllpUWQdzkODIB4Z.jpg','https://image.tmdb.org/t/p/original/gkrF4A7MiKIU2ZvuP3XZ7MsyUlm.jpg','A poor otter family risks everything for the chance to win the cash prize of a talent contest for Christmas.',NULL,NULL,0.5815,6.9,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2532,9834,'tt0245637',NULL,'Little Bear','Little Bear','tv',1995,'https://image.tmdb.org/t/p/w500/bLm7pkUAoi2AGsnPXrPnZ3ErlKs.jpg','https://image.tmdb.org/t/p/original/aSvHDKF7qk367U4CmqoRthQ9T4t.jpg','Follows a young bear as he goes on exciting adventures in the forest, gets into trouble and learns new things with his friends, including Emily, Duck, Hen, Cat, and Owl. His parents are Mother Bear, who is always there when he needs her, and Father Bear, a fisherman who is often at sea. Based on books by Else Holmelund Minarik.',NULL,NULL,9.4691,6.983,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2533,13792,'tt0486172',NULL,'The Moomins','Opowiadania Muminków','tv',1978,'https://image.tmdb.org/t/p/w500/4lMukCV39lBFwzbkjMBzD0wyQDw.jpg','https://image.tmdb.org/t/p/original/rdGan3JnMvDmyuyVKAYR5yccEhc.jpg','The series is based on the famous series of novels by Finnish author Tove Jansson. It follows the adventures of strange creatures called Moomins and their equally strange friends. The series features a continuous narrative within individual installments, which do not always align with the 13-episode division. The series is realized using the semi-flat puppet technique, with commentary.',NULL,NULL,13.6643,7.4,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2534,420814,'tt4575576',NULL,'Christopher Robin','Christopher Robin','movie',2018,'https://image.tmdb.org/t/p/w500/i6Ytex4d3CdfIKJFxB5v5vh24vb.jpg','https://image.tmdb.org/t/p/original/hnh4oqnGPlVFEMUuw41nYxKRYf0.jpg','Christopher Robin, the boy who had countless adventures in the Hundred Acre Wood, has grown up and lost his way. Now it’s up to his spirited and loveable stuffed animals, Winnie The Pooh, Tigger, Piglet, and the rest of the gang, to rekindle their friendship and remind him of endless days of childlike wonder and make-believe, when doing nothing was the very best something.',NULL,NULL,3.8168,7.295,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2535,10817,'tt0296886',NULL,'The World of Peter Rabbit and Friends','The World of Peter Rabbit and Friends','tv',1992,'https://image.tmdb.org/t/p/w500/tji54kBnBhcaraT0sVr2wwRP11Y.jpg','https://image.tmdb.org/t/p/original/7eTyWVh6xYBAXUvbS38JONT6fUK.jpg','Nine animated stories based on the original Peter Rabbit books by Beatrix Potter.',NULL,NULL,1.9192,6.375,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2536,29904,'tt0200369',NULL,'Redwall','Redwall','tv',1999,'https://image.tmdb.org/t/p/w500/vLXvgV2bpqPuva4k0jCSJ4kidRZ.jpg','https://image.tmdb.org/t/p/original/iunTZGVT3HMhsM331YRYtOWcgtW.jpg','To save his besieged Abbey, a young mouse novice must learn of his destiny to be the successor to a great warrior.',NULL,NULL,1.82,7.375,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2537,11076,'tt0116329',NULL,'Fly Away Home','Fly Away Home','movie',1996,'https://image.tmdb.org/t/p/w500/obcQJkZB2OsRxd5GWIcQ5Qjv4YW.jpg','https://image.tmdb.org/t/p/original/gJeF1Pn9nsSsexqaQpS0G840nI2.jpg','Amy is only 13 years old when her mother is killed. She goes to Canada to live with her father, an eccentric inventor whom she barely knows. Amy is miserable in her new life... until she discovers a nest of goose eggs that were abandoned when a local forest was torn down. The eggs hatch and Amy becomes "Mama Goose". When winter comes, Amy and her dad must find a way to lead the birds South.',NULL,NULL,3.2918,6.961,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2538,83417,'tt6732214',NULL,'Tilda Appleseed','Tilda Apfelkern','tv',2016,'https://image.tmdb.org/t/p/w500/9fGPuHDwcHccVl28O7tfWoqbfmS.jpg','https://image.tmdb.org/t/p/original/ismaWjrzLk3M2Y2HDlrWtxLKpon.jpg','Tilda Appleseed is a small white church mouse. She loves her friends, delicious food, and picnics. Every day is a wonderful day in Tilda''s charming little village, where greater and smaller adventures await its inhabitants.',NULL,NULL,0.4711,0.0,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2539,1186957,'tt9900816',NULL,'The Velveteen Rabbit','The Velveteen Rabbit','movie',2023,'https://image.tmdb.org/t/p/w500/aM0ViG6LVkN1PQGe9Bon1gQXpc7.jpg','https://image.tmdb.org/t/p/original/pTIny6C5BQYuvHJXmmxuociYcMw.jpg','When seven-year-old William receives a new favorite toy for Christmas, he discovers a lifelong friend and unlocks a world of magic.',NULL,NULL,1.5304,6.882,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2540,NULL,NULL,262538,'Thank Goodness You''re Here!','Thank Goodness You''re Here!','game',2024,'https://images.igdb.com/igdb/image/upload/t_cover_big/co6yyq.jpg',NULL,'Thank Goodness You''re Here! is an absurd comedy slapformer set in the bizarre Northern English town of Barnsworth. As a traveling salesman, take the time to see the sights and meet the locals, who are very eager to give you a series of increasingly odd jobs…','https://www.igdb.com/games/thank-goodness-youre-here','["Xbox Series X|S", "PlayStation 4", "PC (Microsoft Windows)", "PlayStation 5", "Mac", "Nintendo Switch"]',NULL,NULL,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2541,126319,'tt1816518',NULL,'Ernest & Celestine','Ernest et Célestine','movie',2012,'https://image.tmdb.org/t/p/w500/iJPbRASktYW0I009Ktc2zUE6Fvg.jpg','https://image.tmdb.org/t/p/original/1yQpY4UCaGEirYq9EqTrDvZ24KQ.jpg','Celestine is a little mouse trying to avoid a dental career while Ernest is a big bear craving an artistic outlet. When Celestine meets Ernest, they overcome their natural enmity by forging a life of crime together.',NULL,NULL,3.389,7.7,0,10.23,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2542,458741,'tt6915596',NULL,'Mayaanadhi','മായാനദി','movie',2017,'https://image.tmdb.org/t/p/w500/mNxAgWdHPWOAUVcI4kEuXvpo97j.jpg','https://image.tmdb.org/t/p/original/cWmknHr6VVNInXw6BmauPaldMnP.jpg','A shady money deal goes wrong and in the aftermath Mathan  ends up killing a police officer. Meanwhile in Kochi, his old flame Aparna  an aspiring actress is struggling to prop up her career. Mathan meets up with Aparna and tries to rekindle the past, even as the police hunt for him gets intense.',NULL,NULL,0.6399,7.556,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2543,77016,'tt1855199',NULL,'End of Watch','End of Watch','movie',2012,'https://image.tmdb.org/t/p/w500/pDeVKQICkcdwwjHxGj0MeS14YJ6.jpg','https://image.tmdb.org/t/p/original/fYet7pf0ZlmKrOfmHqRNGRhtZNp.jpg','Two young officers are marked for death after confiscating a small cache of money and firearms from the members of a notorious cartel during a routine traffic stop.',NULL,NULL,3.6536,7.356,0,10.0,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2544,59961,'tt1599348',NULL,'Safe House','Safe House','movie',2012,'https://image.tmdb.org/t/p/w500/7CBhSjQa07LYt0RGejYjWugGmdV.jpg','https://image.tmdb.org/t/p/original/kXRskNzFiTxi5xwsM6hDmOTGae7.jpg','A dangerous CIA renegade resurfaces after a decade on the run. When the safe house he''s remanded to is attacked by mercenaries, a rookie operative escapes with him. Now, the unlikely allies must stay alive long enough to uncover who wants them dead.',NULL,NULL,4.0491,6.492,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2545,74777,'tt1610996',NULL,'Absentia','Absentia','movie',2011,'https://image.tmdb.org/t/p/w500/imUIPWoe0Yma5UhZVl6bqX5lF.jpg','https://image.tmdb.org/t/p/original/hY0BJllNWKQP9BvJu6gCVbUEXVf.jpg','Tricia''s husband has been missing for seven years. Her younger sister Callie comes to live with her as the pressure mounts to finally declare him ''dead in absentia''. Tricia is reluctant, always holding out hope, but Callie is practical and wants her to move on. As Tricia sifts through the wreckage and tries to move on with her life, Callie finds herself drawn to an ominous tunnel near the house.',NULL,NULL,2.6934,5.8,0,11.015,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2546,325302,'tt4105970',NULL,'They Look Like People','They Look Like People','movie',2016,'https://image.tmdb.org/t/p/w500/srfpn9OxEOpTpsKAhkbA43RsWqj.jpg','https://image.tmdb.org/t/p/original/ywGCXYAfFYImYI5fWt1WwrWLHxq.jpg','Suspecting that people are transforming into malevolent shape-shifters, Wyatt flees to New York City to seek out his estranged childhood friend Christian.',NULL,NULL,0.8793,6.227,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2547,1438,'tt0306414',NULL,'The Wire','The Wire','tv',2002,'https://image.tmdb.org/t/p/w500/4lbclFySvugI51fwsyxBTOm4DqK.jpg','https://image.tmdb.org/t/p/original/layPSOJGckJv3PXZDIVluMq69mn.jpg','Told from the points of view of both the Baltimore homicide and narcotics detectives and their targets, the series captures a universe in which the national war on drugs has become a permanent, self-sustaining bureaucracy, and distinctions between good and evil are routinely obliterated.',NULL,NULL,39.1714,8.632,0,10.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2548,49797,'tt1588170',NULL,'I Saw the Devil','악마를 보았다','movie',2010,'https://image.tmdb.org/t/p/w500/zp5NrmYp80axIGiEiYPmm1CW6uH.jpg','https://image.tmdb.org/t/p/original/dXDFWWxiEb6tg4ojMWQJrSI0Tun.jpg','Kyung-chul is a dangerous psychopath who kills for pleasure. Soo-hyeon, a top-secret agent, decides to track down the murderer himself. He promises himself that he will do everything in his power to take vengeance against the killer, even if it means that he must become a monster himself.',NULL,NULL,7.0091,7.805,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2549,283350,'tt0443465',NULL,'Before We Go','Before We Go','movie',2014,'https://image.tmdb.org/t/p/w500/qBnkNKjbJV0E8GvEPidBS1nIRWD.jpg','https://image.tmdb.org/t/p/original/xlGQ44jpBneZu13VAnvU01dWA0y.jpg','A chance encounter between two strangers in Grand Central Terminal sparks a life-changing, nighttime sojourn through New York City. They grow into each other''s most trusted confidants when an evening of unexpected adventure forces them to confront their fears and take control of their lives.',NULL,NULL,2.1455,6.7,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2550,272,'tt0372784',NULL,'Batman Begins','Batman Begins','movie',2005,'https://image.tmdb.org/t/p/w500/sPX89Td70IDDjVr85jdSBb4rWGr.jpg','https://image.tmdb.org/t/p/original/9IIBboV7MCT0bTxzXHmWK1Hq558.jpg','Driven by tragedy, billionaire Bruce Wayne dedicates his life to uncovering and defeating the corruption that plagues his home, Gotham City.  Unable to work within the system, he instead creates a new identity, a symbol of fear for the criminal underworld - The Batman.',NULL,NULL,23.5418,7.728,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2551,322,'tt0327056',NULL,'Mystic River','Mystic River','movie',2003,'https://image.tmdb.org/t/p/w500/hCHVDbo6XJGj3r2i4hVjKhE0GKF.jpg','https://image.tmdb.org/t/p/original/4ycpMe25LYpzGW42U9amyW9gM53.jpg','The lives of three men who were childhood friends are shattered when one of them suffers a family tragedy.',NULL,NULL,8.3851,7.746,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2552,265010,'tt2517658',NULL,'The Canal','The Canal','movie',2014,'https://image.tmdb.org/t/p/w500/5c4FFLSUx4ZBqcS2rq5CLVJdY9E.jpg','https://image.tmdb.org/t/p/original/8OfuPvpLLd9FhVxV7B6bC51JD84.jpg','A man who suspects his wife is cheating on him begins having nightmarish visions of an evil presence that he believes inhabits his house.',NULL,NULL,1.365,5.776,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2553,2009,'tt1032846',NULL,'4 Months, 3 Weeks and 2 Days','4 luni, 3 săptămâni și 2 zile','movie',2007,'https://image.tmdb.org/t/p/w500/acEtvzFPeOQwbzRWncjRLenhnKV.jpg','https://image.tmdb.org/t/p/original/phYwx0HKSdcQyOuK5bMMO8woETT.jpg','Two college roommates have 24 hours to make the ultimate choice as they finalize arrangements for a black market abortion.',NULL,NULL,3.1716,7.5,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2554,591222,'tt14032696',NULL,'Limbo','智齒','movie',2021,'https://image.tmdb.org/t/p/w500/7Hh2w1ei26DTJ3JWmW8qcGQUI1n.jpg','https://image.tmdb.org/t/p/original/cPq0qrpFFbhYPGXBuVGH0DFk9sb.jpg','Veteran detective Cham works with rookie cop Will to hunt down the city''s serial killer. The investigation leads them to a lair littered with dismembered female limbs, and an ex-con who killed Cham''s wife and child years ago...',NULL,NULL,0.7576,7.222,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2555,19457,'tt0138946',NULL,'The Yards','The Yards','movie',2000,'https://image.tmdb.org/t/p/w500/AtwXtU8CDWvVADgOwRkOSRZFPWI.jpg','https://image.tmdb.org/t/p/original/y8cbKwg2VYtG7IdZUu8TE0AajsO.jpg','In the rail yards of Queens, contractors repair and rebuild the city''s subway cars. These contracts are lucrative, so graft and corruption are rife. When Leo Handler gets out of prison, he finds his aunt married to Frank Olchin, one of the big contractors; he''s battling with a minority-owned firm for contracts.',NULL,NULL,2.4759,6.232,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2556,169917,'tt0365907',NULL,'A Walk Among the Tombstones','A Walk Among the Tombstones','movie',2014,'https://image.tmdb.org/t/p/w500/euPgyPsiNFp6gOBB7nUFxvN5ZaY.jpg','https://image.tmdb.org/t/p/original/k23FPWl97XKpJ1oTaDyADzxWxs6.jpg','Private investigator Matthew Scudder is hired by a drug kingpin to find out who kidnapped and murdered his wife.',NULL,NULL,3.5729,6.334,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2557,4553,'tt0361862',NULL,'The Machinist','The Machinist','movie',2004,'https://image.tmdb.org/t/p/w500/diAYqR4xdF9Hnj7qun6DEQhRrT2.jpg','https://image.tmdb.org/t/p/original/hi3lxLd93iKwCmVAfhMV9m1k2jr.jpg','Trevor, an insomniac lathe operator, experiences unusual occurrences at work and home. A strange man follows him everywhere, but no one else seems to notice him.',NULL,NULL,6.1962,7.5,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2558,13855,'tt1190539',NULL,'The Chaser','추격자','movie',2008,'https://image.tmdb.org/t/p/w500/hy49xJiKN1nakkN1ZmKuOf6vQYR.jpg','https://image.tmdb.org/t/p/original/urBBFQrrVxy7T8uytrn7dOoHqZn.jpg','Joong-ho is a dirty detective turned pimp, who''s in financial trouble as several of his girls have recently disappeared without clearing their debts. While trying to track them down, he finds a clue that the vanished girls were all called up by the same client, whom one of his girls is meeting with right now.',NULL,NULL,4.4587,7.763,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2559,NULL,NULL,730,'Grand Theft Auto III','Grand Theft Auto III','game',2001,'https://images.igdb.com/igdb/image/upload/t_cover_big/co2lb8.jpg',NULL,'Featuring a fully 3-D living city, a combination of narrative driven and non-linear gameplay and a completely open environment, Grand Theft Auto III represents a huge leap forward in interactive entertainment. For the first time, players are put at the heart of their very own gangster movie, and let loose in a fully-realised 3 dimensional city, in which anything can happen and probably will.

With a cast of hundreds, 50 plus vehicles, ranging from sports cars to ice cream trucks and from boats to buses, 3 hours of music, including opera, reggae, house, drum and bass, pop and disco, a huge array of street ready weapons and some of the seediest characters in video game history, Grand Theft Auto 3 is a sprawling epic which will show you that sometimes, crime can pay and sometimes it can pay you back. Available now for PlayStation2, Xbox, PC and Macintosh.','https://www.igdb.com/games/grand-theft-auto-iii','["Xbox", "PlayStation 4", "Android", "PC (Microsoft Windows)", "iOS", "Mac", "PlayStation 2"]',NULL,NULL,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2560,64689,'tt1764234',NULL,'Killing Them Softly','Killing Them Softly','movie',2012,'https://image.tmdb.org/t/p/w500/heaz45kpFa4Oa7iLis0OBas68ls.jpg','https://image.tmdb.org/t/p/original/4xGuNyCX46pwEpdQISRYiaBXEN7.jpg','Jackie Cogan is an enforcer hired to restore order after three dumb guys rob a Mob protected card game, causing the local criminal economy to collapse.',NULL,NULL,3.1503,6.029,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2561,10669,'tt0068473',NULL,'Deliverance','Deliverance','movie',1972,'https://image.tmdb.org/t/p/w500/2TrAzNJlHyNYYSkQf6asg3rs2Xr.jpg','https://image.tmdb.org/t/p/original/aaqbyTRo1bZB34ZdjeWyqnL0qz0.jpg','Intent on seeing the Cahulawassee River before it''s turned into one huge lake, outdoor fanatic Lewis Medlock takes his friends on a river-rafting trip they''ll never forget into the dangerous American back-country.',NULL,NULL,3.2709,7.3,0,12.135,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2562,1233413,'tt31193180',NULL,'Sinners','Sinners','movie',2025,'https://image.tmdb.org/t/p/w500/fWPgbnt2LSqkQ6cdQc0SZN9CpLm.jpg','https://image.tmdb.org/t/p/original/nAxGnGHOsfzufThz20zgmRwKur3.jpg','Trying to leave their troubled lives behind, twin brothers return to their hometown to start again, only to discover that an even greater evil is waiting to welcome them back.',NULL,NULL,28.776,7.497,0,12.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2563,13466,'tt0132477',NULL,'October Sky','October Sky','movie',1999,'https://image.tmdb.org/t/p/w500/umWrXCIWdcYPf764ruvMRCpG3cA.jpg','https://image.tmdb.org/t/p/original/c6uIPrMgvDzhEGSKuZc8aw6NfC.jpg','The true story of Homer Hickam, a coal miner''s son who was inspired by the first Sputnik launch to take up rocketry against his father''s wishes.',NULL,NULL,3.8586,7.676,0,12.15,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2564,87523,'tt3673480',NULL,'The Good Lord Bird','The Good Lord Bird','tv',2020,'https://image.tmdb.org/t/p/w500/bNFcWrxlnFXvrjJezId6bAoePzT.jpg','https://image.tmdb.org/t/p/original/8WwsIKZEGXhxhKpa4LwstfqgYxJ.jpg','Henry ''Little Onion'' Shackleford, a newly freed teenager joins abolitionist John Brown on a holy crusade to end slavery. Onion encounters Frederick Douglass and Harriet Tubman, and he finds himself as a part of the famous 1859 raid at Harpers Ferry.',NULL,NULL,5.7577,6.639,0,11.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2565,417466,'tt6062774',NULL,'Monos','Monos','movie',2019,'https://image.tmdb.org/t/p/w500/sMcvyEqzwWyaUhuUaJtiZuc7Ku5.jpg','https://image.tmdb.org/t/p/original/iqd7U0nrQw9zKUKyG05dtWpBVJT.jpg','On a faraway mountaintop, eight kids with guns watch over a hostage and a conscripted milk cow.',NULL,NULL,2.4797,6.6,0,9.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2566,86320,'tt0134402',NULL,'Twenty Years Later','Cabra Marcado Para Morrer','movie',1984,'https://image.tmdb.org/t/p/w500/gqLIvOGAUQOIQh6PEbkL6yz00Ch.jpg','https://image.tmdb.org/t/p/original/f8zh7tSRsp4h3tGaD6ZRRWANXSX.jpg','Eduardo Coutinho was filming a movie with the same name in the Northeast of Brazil, in 1964, when there came the military coup. He had to interrupt the project, and came back to it in 1981, looking for the same places and people, showing what had ocurred since then, and trying to gather a family whose patriarch, a political leader fighting for rights of country people, had been murdered.',NULL,NULL,0.4077,8.4,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2567,80039,'tt6704972',NULL,'The Underground Railroad','The Underground Railroad','tv',2021,'https://image.tmdb.org/t/p/w500/CrrTqw7LHafnbdH9UcK60aOZSm.jpg','https://image.tmdb.org/t/p/original/pZcS7g2wsGWqWvleu3f9JS288QT.jpg','Follow young Cora’s journey as she makes a desperate bid for freedom in the antebellum South. After escaping her Georgia plantation for the rumored Underground Railroad, Cora discovers no mere metaphor, but an actual railroad full of engineers and conductors, and a secret network of tracks and tunnels beneath the Southern soil.',NULL,NULL,3.4144,7.232,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2568,62677,'tt0210299',NULL,'Songcatcher','Songcatcher','movie',2001,'https://image.tmdb.org/t/p/w500/qpUSLY5BPi42rqO097tNF8e53Qm.jpg','https://image.tmdb.org/t/p/original/1ExirZYN7X0Vowg57XW71JQHtxo.jpg','After being denied a promotion at the university where she teaches, Doctor Lily Penleric, a brilliant musicologist, impulsively visits her sister, who runs a struggling rural school in Appalachia. There she stumbles upon the discovery of her life - a treasure trove of ancient Scots-Irish ballads, songs that have been handed down from generation to generation, preserved intact by the seclusion of the mountains. With the goal of securing her promotion, Lily ventures into the most isolated areas of the mountains to collect the songs and finds herself increasingly enchanted.',NULL,NULL,0.7425,6.205,0,10.05,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2569,82633,'tt1212450',NULL,'Lawless','Lawless','movie',2012,'https://image.tmdb.org/t/p/w500/Ahtzwts22ayviD3LEVslfL4nRWB.jpg','https://image.tmdb.org/t/p/original/6zTqEmFWlmmPPY907qwvv9WQBUm.jpg','In 1931, the Bondurant brothers of Franklin County, Virginia, run a multipurpose backwoods establishment that hides their true business — bootlegging. Middle brother Forrest is the brain of the operation; older Howard is the brawn, and younger Jack, the lookout. Though the local police have taken bribes and left the brothers alone, a violent war erupts when a sadistic lawman from Chicago arrives and tries to shut down the Bondurants operation.',NULL,NULL,4.8589,7.071,0,15.052,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2570,1087822,'tt26757462',NULL,'Hellboy: The Crooked Man','Hellboy: The Crooked Man','movie',2024,'https://image.tmdb.org/t/p/w500/iz2GabtToVB05gLTVSH7ZvFtsMM.jpg','https://image.tmdb.org/t/p/original/78CquSA0GN0m7NIYnNECx91KFkJ.jpg','Hellboy and a rookie BPRD agent get stranded in 1950s rural Appalachia. There, they discover a small community haunted by witches, led by a local devil with a troubling connection to Hellboy''s past: the Crooked Man.',NULL,NULL,3.7971,5.154,0,12.085,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2571,64437,'tt4816626',NULL,'Outsiders','Outsiders','tv',2016,'https://image.tmdb.org/t/p/w500/vPKJwmLmcTLwvJhpeKUhWIHlDp3.jpg','https://image.tmdb.org/t/p/original/uwF07UWJgHOkumVPWs9O2eBNddm.jpg','A struggle for power and control set in the rugged and mysterious hills of Appalachia, "Outsiders" tells the story of the Farrell clan, a family of outsiders who''ve been in these parts since before anyone can remember. Living off the grid and above the law on their mountaintop homestead, they''ll protect their world and defend their way of life using any means necessary.',NULL,NULL,6.6085,6.486,0,10.16,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2572,27418,'tt0097967',NULL,'Next of Kin','Next of Kin','movie',1989,'https://image.tmdb.org/t/p/w500/ieM9upg9O4agtodEvlZIiuNKZsN.jpg','https://image.tmdb.org/t/p/original/gYtBxbJIeJTOFEIdCzYITSHIB4d.jpg','Truman Gates, a Chicago cop, sets out to find his brother''s killer. Meanwhile, another of his brothers, Briar (a hillbilly) decides to find the killer himself.',NULL,NULL,2.0272,5.9,0,10.095,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2573,359940,'tt5027774',NULL,'Three Billboards Outside Ebbing, Missouri','Three Billboards Outside Ebbing, Missouri','movie',2017,'https://image.tmdb.org/t/p/w500/bRYLt8fV82tdVoDppSFTZIcJiLN.jpg','https://image.tmdb.org/t/p/original/oQHF0Y4gCw6VdPmapjsbZoxY2ht.jpg','After seven months have passed without a culprit in her daughter''s murder case, Mildred Hayes makes a bold move, painting three signs leading into her town with a controversial message directed at Bill Willoughby, the town''s revered chief of police. When his second-in-command Officer Jason Dixon, an immature mother''s boy with a penchant for violence, gets involved, the battle between Mildred and Ebbing''s law enforcement is only exacerbated.',NULL,NULL,6.3918,8.054,0,9.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2574,11152,'tt0963794',NULL,'The Ruins','The Ruins','movie',2008,'https://image.tmdb.org/t/p/w500/6HpicbiT7xmlMjQXOSCeNoLZGpf.jpg','https://image.tmdb.org/t/p/original/rYqjPTWtgswEh7gTMbponxsy0tR.jpg','Americans Amy, Stacy, Jeff and Eric look for fun during a sunny holiday in Mexico, but they get much more than that after visiting an archaeological dig in the jungle.',NULL,NULL,3.4408,5.938,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2575,49637,'tt1396227',NULL,'The Wild and Wonderful Whites of West Virginia','The Wild and Wonderful Whites of West Virginia','movie',2009,'https://image.tmdb.org/t/p/w500/7EQQsuK1Hk1zcoBlNBKfU41aS39.jpg','https://image.tmdb.org/t/p/original/2S0Kk3cMPE2CX0vEJ6Fp5OjPZgI.jpg','Produced by Johnny Knoxville and Jeff Tremaine for MTV and Dickhouse Productions, The Wild and Wonderful Whites of West Virginia is a documentary about the renowned West Virginia outlaw Jesco White and his eccentric backwoods family. In addition to getting in trouble with the law, the Whites, who live deep within Appalachia, uphold a time-honored dancing style, even as they contend with poverty, drugs and other issues. Alternately humorous and sad, the movie is an unflinching look at life on the criminal margins of rural mountain culture.',NULL,NULL,0.6098,6.74,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2576,45153,'tt0119080',NULL,'Eve''s Bayou','Eve''s Bayou','movie',1997,'https://image.tmdb.org/t/p/w500/33yTPcGSv7eo3FVlb7XKACHl1M8.jpg','https://image.tmdb.org/t/p/original/dzoLlCiMhraAfCjQuudyVLcl8Le.jpg','Summer heats up in rural Louisiana beside Eve’s Bayou, 1962, as the Batiste family tries to survive the secrets they’ve kept and the betrayals they’ve endured.',NULL,NULL,2.113,6.409,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2577,748853,'tt13429362',NULL,'In the Earth','In the Earth','movie',2021,'https://image.tmdb.org/t/p/w500/a2e9GLb14xX1DFv80nsioci5Zld.jpg','https://image.tmdb.org/t/p/original/fjRlDPqo2qqMBoUItMtTDZe9kvZ.jpg','As a deadly virus ravages the world, Dr. Martin Lowery embarks on a mission to reach test site ATU327A, a research hub deep in the Arboreal Forest. The arduous journey, guided by park scout Alma, is set back by a nighttime attack that leaves the two bruised and shoeless. When they run into Zach, a man living off the grid, they gratefully accept his help. Zach’s intentions aren’t exactly what they seem, however, and a path out of the forest and into safety quickly fades as the line between myth and science blurs.',NULL,NULL,0.9191,5.597,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2578,24276,'tt0093509',NULL,'Matewan','Matewan','movie',1987,'https://image.tmdb.org/t/p/w500/jMYqoM60clzYIQriM1wYXXBjU3O.jpg','https://image.tmdb.org/t/p/original/7Z2448JzjPf2THI0oJ0dsfSz56y.jpg','Filmed in the coal country of West Virginia, "Matewan" celebrates labor organizing in the context of a 1920s work stoppage. Union organizer, Joe Kenehan, a scab named "Few Clothes" Johnson and a sympathetic mayor and police chief heroically fight the power represented by a coal company and Matewan''s vested interests so that justice and workers'' rights need not take a back seat to squalid working conditions, exploitation and the bottom line.',NULL,NULL,2.3846,7.384,0,14.045,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2579,164457,'tt1206543',NULL,'Out of the Furnace','Out of the Furnace','movie',2013,'https://image.tmdb.org/t/p/w500/cOuQQ4eRpSBxb0G9OXzWE1pHPeq.jpg','https://image.tmdb.org/t/p/original/joXz5iPvhDvrHUejlviswMCZaEz.jpg','Two brothers live in the economically-depressed Rust Belt, when a cruel twist of fate lands one in prison. His brother is then lured into one of the most violent crime rings in the Northeast.',NULL,NULL,3.0358,6.566,0,1.11200000000000009e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2580,154400,'tt1600196',NULL,'The Drop','The Drop','movie',2014,'https://image.tmdb.org/t/p/w500/olQInYvVCW2wycMSU1ogo9Jshml.jpg','https://image.tmdb.org/t/p/original/kydclLUnhGMuoCxl6VRfSSwdRRO.jpg','Bob Saginowski finds himself at the center of a robbery gone awry and entwined in an investigation that digs deep into the neighborhood''s past where friends, families, and foes all work together to make a living - no matter the cost.',NULL,NULL,3.847,6.827,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2581,637620,'tt7631568',NULL,'The Devil to Pay','The Devil to Pay','movie',2020,'https://image.tmdb.org/t/p/w500/3VaJuPGaqxJ0Un8pbw5jL7uvWfS.jpg','https://image.tmdb.org/t/p/original/wCEGBFfF6rbsWMx0CsUU0wrVsLA.jpg','After the disappearance of her husband, a struggling farmer in an isolated Appalachian community fights to save her son when the cold-hearted matriarch of the oldest family on the mountain demands payment of a debt that could destroy a decades-old truce.',NULL,NULL,0.6636,6.37,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2582,121606,'tt1977895',NULL,'Resolution','Resolution','movie',2013,'https://image.tmdb.org/t/p/w500/gTZTCMmU7N0qTWJrSUOVBI70ZlA.jpg','https://image.tmdb.org/t/p/original/fF5XLTGoZEsP84wcDF3HtGNp5zm.jpg','A man imprisons his estranged junkie friend in an isolated cabin in the boonies of San Diego to force him through a week of sobriety, but the events of that week are being mysteriously manipulated.',NULL,NULL,1.1384,6.352,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2583,499932,'tt7395114',NULL,'The Devil All the Time','The Devil All the Time','movie',2020,'https://image.tmdb.org/t/p/w500/bVL7LGq528h3KzeNI90HOVbV5uW.jpg','https://image.tmdb.org/t/p/original/gWPz2ucZxzbnbTQCJHADDCcGi9o.jpg','In Knockemstiff, Ohio and its neighboring backwoods, sinister characters converge around young Arvin Russell as he fights the evil forces that threaten him and his family.',NULL,NULL,3.5843,7.178,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2584,297,'tt0119643',NULL,'Meet Joe Black','Meet Joe Black','movie',1998,'https://image.tmdb.org/t/p/w500/fDPAjvfPMomkKF7cMRmL5Anak61.jpg','https://image.tmdb.org/t/p/original/uMBByiSDpgFwWVegAtwwnuzvogJ.jpg','Bill Parrish has it all - success, wealth and power. Days before his 65th birthday, he receives a visit from a mysterious stranger, Joe Black, who soon reveals himself as Death. In exchange for extra time, Bill agrees to serve as Joe''s earthly guide. But will he regret his choice when Joe unexpectedly falls in love with Bill''s beautiful daughter Susan?',NULL,NULL,8.4698,7.367,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2585,9902,'tt0295700',NULL,'Wrong Turn','Wrong Turn','movie',2003,'https://image.tmdb.org/t/p/w500/12G5V0dTmljnv7RFMT144dJ2chh.jpg','https://image.tmdb.org/t/p/original/wT9GbyGHmJExhBsJuVQ9Lfga533.jpg','Chris crashes into a carload of other young people, and the group of stranded motorists is soon lost in the woods of West Virginia, where they''re hunted by three cannibalistic mountain men who are grossly disfigured by generations of inbreeding.',NULL,NULL,8.8934,6.403,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2586,31146,'tt0115738',NULL,'Box of Moonlight','Box of Moonlight','movie',1996,'https://image.tmdb.org/t/p/w500/ibDb9U1JsPXJYycSgq6ssSOz1W4.jpg','https://image.tmdb.org/t/p/original/ypaWcRK1K4gvBaOIFmxfwY31tzZ.jpg','Al Fountain, a middle-aged electrical engineer, is on the verge of a mid-life crisis, when he decides to take his time coming home from a business trip, rents a car, and heads out looking for a lake he remembers from his childhood. But his wandering takes him into the life of Kid, a free-spirited young man who helps Al escape from the routine of everyday life and find freedom to enjoy himself.',NULL,NULL,0.9618,6.8,0,9.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2587,244260,'tt3125220',NULL,'Little Accidents','Little Accidents','movie',2014,'https://image.tmdb.org/t/p/w500/8nGltRVl58E5GEwCqCtk9HOifV5.jpg','https://image.tmdb.org/t/p/original/z4al5eMKT3Vjyy80GGU4gw14izC.jpg','In a small American coal town living in the shadow of a recent mining accident, the disappearance of a teenage boy draws three people together—a surviving miner, the lonely wife of a mine executive, and a local boy—in a web of secrets.',NULL,NULL,1.0548,5.4,0,10.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2588,110695,'tt9174558',NULL,'Dopesick','Dopesick','tv',2021,'https://image.tmdb.org/t/p/w500/qW8Gpddy29faTcD7VuyKjwLXbKU.jpg','https://image.tmdb.org/t/p/original/uJxG5mIb6gUuFt9OGUUCVikserY.jpg','The story of how one company triggered the worst drug epidemic in American history. Look into the epicenter of America''s struggle with opioid addiction, from a distressed Virginia mining community, to the hallways of the DEA, and to the opulence of "one percenter" Big Pharma Manhattan.',NULL,NULL,5.3319,8.015,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2589,33324,'tt0074605',NULL,'Harlan County U.S.A.','Harlan County U.S.A.','movie',1977,'https://image.tmdb.org/t/p/w500/p0cyMNsoP5ap0omfhakhImBWTRw.jpg','https://image.tmdb.org/t/p/original/pVspyFNl8uE8jAoY3C973XkjTgB.jpg','This film documents the coal miners'' strike against the Brookside Mine of the Eastover Mining Company in Harlan County, Kentucky in June, 1973. Eastover''s refusal to sign a contract (when the miners joined with the United Mine Workers of America) led to the strike, which lasted more than a year and included violent battles between gun-toting company thugs/scabs and the picketing miners and their supportive women-folk. Director Barbara Kopple puts the strike into perspective by giving us some background on the historical plight of the miners and some history of the UMWA.  Preserved by the Academy Film Archive in partnership with New York Women in Film & Television in 2004.',NULL,NULL,0.746,7.504,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2590,1387101,'tt30789011',NULL,'Appalachian Dog','Appalachian Dog','movie',2025,'https://image.tmdb.org/t/p/w500/pHYLL5T8IUCNiddNZaYBtukfPDN.jpg','https://image.tmdb.org/t/p/original/O4AfSdYqoDHxWYOLUwo85bvCOF.jpg','Appalachia, 1946: a seamstress welcomes home her tailor husband to find they are not the team they were. Trying to stitch their old life back together, time and again it threatens to fall apart - with each of them pulling at the thread.',NULL,NULL,0.3669,0.0,0,8.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2591,38557,'tt0088007',NULL,'The River','The River','movie',1984,'https://image.tmdb.org/t/p/w500/bXIlE2QVIarVug9wpyPIz2xiWxf.jpg','https://image.tmdb.org/t/p/original/tEodwsC1kRFFbI4CJCZJopdX0D.jpg','Tom and Mae Garvey are a Tennessee farming couple battling violent floods to save their land. In addition to natural disasters, the Garveys fight to stop a selfish land developer and a local corporation from foreclosing on their farm. While Mae stays at home to care for their children and tend to the crops, Tom finds work as a scab at a steel mill to preserve his family''s property.',NULL,NULL,1.3469,6.4,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2592,873,'tt0088939',NULL,'The Color Purple','The Color Purple','movie',1985,'https://image.tmdb.org/t/p/w500/6bvxkcTAXyqxGRwo38mxw92D6Xr.jpg','https://image.tmdb.org/t/p/original/lh6MbyxwCribn3hdAo81xLdPGoV.jpg','An epic tale spanning forty years in the life of Celie, an African-American woman living in the South who survives incredible abuse and bigotry. After Celie''s abusive father marries her off to the equally debasing ''Mister'' Albert Johnson, things go from bad to worse, leaving Celie to find companionship anywhere she can. She perseveres, holding on to her dream of one day being reunited with her sister in Africa.',NULL,NULL,6.0402,7.723,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2593,7446,'tt0942385',NULL,'Tropic Thunder','Tropic Thunder','movie',2008,'https://image.tmdb.org/t/p/w500/zAurB9mNxfYRoVrVjAJJwGV3sPg.jpg','https://image.tmdb.org/t/p/original/4pLi4QMm0MZ9TSoF3l8qQmY9HNO.jpg','A group of self-absorbed actors set out to make the most expensive war film ever. After ballooning costs force the studio to cancel the movie, the frustrated director refuses to stop shooting, leading his cast into the jungles of Southeast Asia, where they encounter real bad guys.',NULL,NULL,10.3795,6.72,0,7.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2594,399170,'tt5439796',NULL,'Logan Lucky','Logan Lucky','movie',2017,'https://image.tmdb.org/t/p/w500/mQrhrBaaHvRfBQq0Px3HtVbH9iE.jpg','https://image.tmdb.org/t/p/original/eszmHIWJHAKdnJcE3KcvVzOb6Jd.jpg','Trying to reverse a family curse, brothers Jimmy and Clyde Logan set out to execute an elaborate robbery during the legendary Coca-Cola 600 race at the Charlotte Motor Speedway.',NULL,NULL,4.3062,6.738,0,9.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2595,9361,'tt0104691',NULL,'The Last of the Mohicans','The Last of the Mohicans','movie',1992,'https://image.tmdb.org/t/p/w500/qzJMPWRtZveBkxXOv3ucWhoJuyj.jpg','https://image.tmdb.org/t/p/original/mhpDSuNyHPMsccI7zISEaskTgOQ.jpg','In war-torn colonial America, in the midst of a bloody battle between British, the French and Native American allies, the aristocratic daughter of a British Colonel and her party are captured by a group of Huron warriors. Fortunately, a group of three Mohican trappers comes to their rescue.',NULL,NULL,6.3015,7.387,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2596,1436,'tt1489428',NULL,'Justified','Justified','tv',2010,'https://image.tmdb.org/t/p/w500/ie1quhMk09lDtvtAyQAHTu09R9Z.jpg','https://image.tmdb.org/t/p/original/cyieN1P9Xo5SvLasSUT7SaAAzfy.jpg','A character drama based on the 2001 Elmore Leonard short story "Fire in the Hole." Leonard''s tale centers around U.S. Marshal Raylan Givens of Kentucky, a quiet but strong-willed official of the law. The tale covers his high-stakes job, as well as his strained relationships with his ex-wife and father.',NULL,NULL,24.4395,7.976,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2597,1241983,'tt29768334',NULL,'Train Dreams','Train Dreams','movie',2025,'https://image.tmdb.org/t/p/w500/l3zS4YnpOi4usyEXGJMtxSqDDyb.jpg','https://image.tmdb.org/t/p/original/u5NWHVhZ6HWc1fXnqn82cMar5St.jpg','A logger leads a life of quiet grace as he experiences love and loss during an era of monumental change in early 20th-century America.',NULL,NULL,5.5835,7.314,0,8.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2598,53186,'tt0124012',NULL,'Morgiana','Morgiana','movie',1972,'https://image.tmdb.org/t/p/w500/bX8ZGlqREc3qwsO7blOPWX52HyG.jpg','https://image.tmdb.org/t/p/original/3sB8Vg4BZmb7vir5L3F4aYowkwN.jpg','Jealous of her vapidly "good" sister''s popularity, poisonous Viktoria doses pretty Klara''s tea with a slow-acting fatal substance. As the latter grows hysterically weak, the former finds success increasingly compromised by guilt, blackmail, and the pesky need to kill others lest she be exposed.',NULL,NULL,2.1018,7.2,0,10.09,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2599,660715,'tt10243676',NULL,'After Blue (Dirty Paradise)','After Blue (Paradis sale)','movie',2022,'https://image.tmdb.org/t/p/w500/uzlk8JZbialeyduUjgtbsqwH3yX.jpg','https://image.tmdb.org/t/p/original/croBEXnr8sbqyjLmFrMRpDfnSbv.jpg','In a faraway future, on a wild and untamed female inhabited planet called After Blue, a lonely teenager named Roxy unknowingly releases a mystical, dangerous, and sensual assassin from her prison.',NULL,NULL,0.5457,5.4,0,10.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2600,10994,'tt0283139',NULL,'White Oleander','White Oleander','movie',2002,'https://image.tmdb.org/t/p/w500/pOdmhUaqvg4twAHqrhL5Onjgalb.jpg','https://image.tmdb.org/t/p/original/qOlJT9P2yC7xLBo5r2ZCrkvFuf6.jpg','A teenager journeys through a series of foster homes after her mother goes to prison for committing a crime of passion.',NULL,NULL,2.1756,7.026,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2601,20770,'tt0179116',NULL,'But I''m a Cheerleader','But I''m a Cheerleader','movie',2000,'https://image.tmdb.org/t/p/w500/dGEwlAuzTZoZjvsqgT2MRKHnGi8.jpg','https://image.tmdb.org/t/p/original/f4ZgIaMpOWd6rewhCfoIIMqWquh.jpg','Megan is an all-American girl. A cheerleader. She has a boyfriend. But Megan doesn''t like kissing her boyfriend very much. And she''s pretty touchy with her cheerleader friends. Her conservative parents worry that she must be a lesbian and send her off to "sexual redirection" school, where she must, with other lesbians and gays learn how to be straight.',NULL,NULL,4.9023,7.072,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2602,1024,'tt0110005',NULL,'Heavenly Creatures','Heavenly Creatures','movie',1994,'https://image.tmdb.org/t/p/w500/uvb86wVCIqD3Rlbr0GTNgWDF7Zo.jpg','https://image.tmdb.org/t/p/original/jHjOY9vgE7maH2HRk2fd9lOPg8.jpg','Precocious teenager Juliet moves to New Zealand with her family and soon befriends the quiet, brooding Pauline through their shared love of fantasy and literature. This friendship gradually develops into an intense and obsessive bond.',NULL,NULL,3.2576,7.0,0,10.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2603,19079,'tt1034325',NULL,'Phoebe in Wonderland','Phoebe in Wonderland','movie',2008,'https://image.tmdb.org/t/p/w500/iiLMczPwwJE9sKjkg4Khdh3oFFn.jpg','https://image.tmdb.org/t/p/original/stRc4geXiW3F2wZGxNt6EkasqfH.jpg','The fantastical tale of a little girl who won''t - or can''t - follow the rules. Confounded by her clashes with the rule-obsessed world around her, Phoebe seeks enlightenment from her unconventional drama teacher, even as her brilliant but anguished mother looks to Phoebe herself for inspiration.',NULL,NULL,1.4398,7.199,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2604,28902,'tt0120710',NULL,'In Dreams','In Dreams','movie',1999,'https://image.tmdb.org/t/p/w500/q3Q00fCgeZGjAYaiwbfTMuIrUb0.jpg','https://image.tmdb.org/t/p/original/opESjJxA10pGES8hod8YK2Gi4ug.jpg','A suburban housewife learns that she has psychic connections to a serial killer, and can predict this person''s motives through her dreams.',NULL,NULL,1.4595,5.49,0,10.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2605,6073,'tt0236493',NULL,'The Mexican','The Mexican','movie',2001,'https://image.tmdb.org/t/p/w500/5GqF6rVjUW6CVTuj7w1A2JE49AF.jpg','https://image.tmdb.org/t/p/original/nfG7okcUaUknI8HsDg25eQpQu3L.jpg','Jerry Welbach, a reluctant bagman, has been given two ultimatums: The first is from his mob boss to travel to Mexico and retrieve a priceless antique pistol, known as "the Mexican"... or suffer the consequences. The second is from his girlfriend Samantha to end his association with the mob. Jerry figures alive and in trouble with Samantha is better than the more permanent alternative, so he heads south of the border.',NULL,NULL,2.7813,5.951,0,11.03,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2606,5071,'tt0122082',NULL,'The Crazy Stranger','Gadjo Dilo','movie',1998,'https://image.tmdb.org/t/p/w500/eM8RuoymwDaMRhR33wWTR1wXijf.jpg','https://image.tmdb.org/t/p/original/14KWvA1ZAiEEQyLVux5uKFxqtMV.jpg','A man is looking for a singer he had heard on cassette. He finds much more.',NULL,NULL,2.9872,7.398,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2607,23620,'tt0047443',NULL,'Salt of the Earth','Salt of the Earth','movie',1954,'https://image.tmdb.org/t/p/w500/vYOH8TLzXq15alUDM5DDZXMb1LN.jpg','https://image.tmdb.org/t/p/original/uqh2tPWQzY2Bzi8Xg6keXv7XMTo.jpg','At New Mexico''s Empire Zinc mine, Mexican-American workers protest the unsafe work conditions and unequal wages compared to their Anglo counterparts. Ramon Quintero helps organize the strike, but he is shown to be a hypocrite by treating his pregnant wife, Esperanza, with a similar unfairness. When an injunction stops the men from protesting, however, the gender roles are reversed, and women find themselves on the picket lines while the men stay at home.',NULL,NULL,1.0806,7.0,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2608,25188,'tt0067328',NULL,'The Last Picture Show','The Last Picture Show','movie',1971,'https://image.tmdb.org/t/p/w500/7NYePZc0lZrRomtmQsjOJMePTEb.jpg','https://image.tmdb.org/t/p/original/fhzwleXGmiqBuQdWxmEwpkydhm4.jpg','High school seniors and best friends, Sonny and Duane, live in a dying Texas town. The handsome Duane is dating a local beauty, while Sonny is having an affair with the coach''s wife. As graduation nears and both boys contemplate their futures, Duane eyes the army and Sonny takes over a local business. Each struggles to figure out if he can escape this dead-end town and build a better life somewhere else.',NULL,NULL,2.9243,7.616,0,12.02,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2609,20122,'tt0095475',NULL,'Damnation','Kárhozat','movie',1988,'https://image.tmdb.org/t/p/w500/iW1WHmZEk9QTeY4qp7gjaDcCPDS.jpg','https://image.tmdb.org/t/p/original/m6sHDQ7Hsc2q3Tn5hMbWkTMIXup.jpg','Karrer plods his way through life in quiet desperation. His environment is drab and rainy and muddy. Eaten up with solitude, his hopelessness would be incurable but for the existence of the Titanik Bar and its beautiful, haunting singer. But the lady is married and Karrer is determined to keep her husband away...',NULL,NULL,1.4761,7.634,0,11.04,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2610,129670,'tt1821549',NULL,'Nebraska','Nebraska','movie',2013,'https://image.tmdb.org/t/p/w500/o1t2Mw18EEBnl8v4Nby3PFjxnM1.jpg','https://image.tmdb.org/t/p/original/yePsFcldyZ6VnxaBr8ZbVEaOt4W.jpg','An aging, booze-addled father takes a trip from Montana to Nebraska with his estranged son in order to claim what he believes to be a million-dollar sweepstakes prize.',NULL,NULL,4.3765,7.453,0,1.30333333333333332e+01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2611,220,'tt0048028',NULL,'East of Eden','East of Eden','movie',1955,'https://image.tmdb.org/t/p/w500/xv1MZVIop0SQqwLUymgE5eb2LFl.jpg','https://image.tmdb.org/t/p/original/u7i1XtbOubq0xwRy2Zbgmox6g9W.jpg','In the Salinas Valley in and around World War I, Cal Trask feels he must compete against overwhelming odds with his brother for the love of their father. Cal is frustrated at every turn, from his reaction to the war, how to get ahead in business and in life, and how to relate to his estranged mother.',NULL,NULL,2.6471,7.5,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2612,122,'tt0167260',NULL,'The Lord of the Rings: The Return of the King','The Lord of the Rings: The Return of the King','movie',2003,'https://image.tmdb.org/t/p/w500/rCzpDGLbOoPwLjy3OAm5NUPOTrC.jpg','https://image.tmdb.org/t/p/original/2u7zbn8EudG6kLlBzUYqP8RyFU4.jpg','As armies mass for a final battle that will decide the fate of the world--and powerful, ancient forces of Light and Dark compete to determine the outcome--one member of the Fellowship of the Ring is revealed as the noble heir to the throne of the Kings of Men. Yet, the sole hope for triumph over evil lies with a brave hobbit, Frodo, who, accompanied by his loyal friend Sam and the hideous, wretched Gollum, ventures deep into the very dark heart of Mordor on his seemingly impossible quest to destroy the Ring of Power.​',NULL,NULL,38.5236,8.501,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2613,1554,'tt0090967',NULL,'Down by Law','Down by Law','movie',1986,'https://image.tmdb.org/t/p/w500/4IyxoUQ7BB5kcSd7gASe2dTyWu7.jpg','https://image.tmdb.org/t/p/original/8kVPLOzuZ1G9EBYxcOrzaHbxCeC.jpg','A disc jockey, a pimp and an Italian tourist escape from jail in New Orleans.',NULL,NULL,1.8109,7.3,0,12.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2614,15392,'tt0090888',NULL,'Crossroads','Crossroads','movie',1986,'https://image.tmdb.org/t/p/w500/2sMo7gwZ8L7KttiW210T0ueJ2eX.jpg','https://image.tmdb.org/t/p/original/k8TtcMVQFBfEEiVNYMBB5v1Ez7v.jpg','A wanna-be blues guitar virtuoso seeks a long-lost song by legendary musician, Robert Johnson.',NULL,NULL,2.9104,7.345,0,11.07,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2615,872585,'tt15398776',NULL,'Oppenheimer','Oppenheimer','movie',2023,'https://image.tmdb.org/t/p/w500/8Gxv8gSFCU0XGDykEGv7zR1n2ua.jpg','https://image.tmdb.org/t/p/original/neeNHeXjMF5fXoCJRsOmkNGC7q.jpg','The story of J. Robert Oppenheimer''s role in the development of the atomic bomb during World War II.',NULL,NULL,28.3616,8.024,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2616,29425,'tt0069895',NULL,'The Crazies','The Crazies','movie',1973,'https://image.tmdb.org/t/p/w500/xSNgBJL9WKMHwl42gZXeRsQXFa1.jpg','https://image.tmdb.org/t/p/original/iCdtK81PavU2Tcm5nuuPipG0gHt.jpg','The military attempts to contain a manmade virus causing death and permanent insanity in those infected, as it overtakes a small Pennsylvania town.',NULL,NULL,3.7471,6.1,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2617,67748,'tt1680114',NULL,'Snowtown','Snowtown','movie',2011,'https://image.tmdb.org/t/p/w500/5LW1vPLa8ueVwdOgR8w5xYkSQGv.jpg','https://image.tmdb.org/t/p/original/1KlJVF0xXLeFq2KTIjzA2LvWHH9.jpg','Based on true events, 16 year-old Jamie falls in with his mother''s new boyfriend and his crowd of self-appointed neighborhood watchmen, a relationship that leads to a spree of torture and murder.',NULL,NULL,5.0589,6.307,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2618,588064,'tt7293920',NULL,'The Fare','The Fare','movie',2018,'https://image.tmdb.org/t/p/w500/mLqhPBNyHkTkJGb93DwqlisIJ6Y.jpg','https://image.tmdb.org/t/p/original/783I7YwlyxaaOCHwO2JAbDblDNE.jpg','Harris and Penny, a cab driver and his fare, engage in flirtatious banter during their brief ride on a desolate road…until Penny abruptly vanishes from the back seat, leaving Harris mystified.',NULL,NULL,0.8342,6.457,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2619,664,'tt0117998',NULL,'Twister','Twister','movie',1996,'https://image.tmdb.org/t/p/w500/d4ie3f6QTvNw40V770Uzo87SDZn.jpg','https://image.tmdb.org/t/p/original/5oCAo7LFj2x0yByfi5JYirGnK8I.jpg','An unprecedented series of violent tornadoes is sweeping across Oklahoma. Tornado chasers, headed by Dr. Jo Harding, attempt to release a groundbreaking device that will allow them to track them and create a more advanced warning system. They are joined by Jo''s soon to be ex-husband Bill, a former tornado chaser himself, and his girlfriend Melissa.',NULL,NULL,7.4741,6.567,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2620,10427,'tt0105226',NULL,'Red Rock West','Red Rock West','movie',1993,'https://image.tmdb.org/t/p/w500/ewofUEqU3Gpr7WSgSz3TEVPIfBg.jpg','https://image.tmdb.org/t/p/original/3JbHPpUJ53I52w66jydAhIp8Ibe.jpg','When a promised job for Texan Michael fails to materialize in Wyoming, Mike is mistaken by Wayne to be the hitman he hired to kill his unfaithful wife, Suzanne. Mike takes full advantage of the situation, collects the money, and runs. During his getaway, things go wrong, and soon get worse when he runs into the real hitman, Lyle.',NULL,NULL,1.117,6.778,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
INSERT OR IGNORE INTO "recommendations" VALUES(2621,1047020,'tt11674730',NULL,'The Last Stop in Yuma County','The Last Stop in Yuma County','movie',2024,'https://image.tmdb.org/t/p/w500/u6ae2MMh8PpSamO3cIttLM5B18v.jpg','https://image.tmdb.org/t/p/original/2s4KvAxS9igmXZkhrxqzztAykGB.jpg','While awaiting the next fuel truck at a middle-of-nowhere Arizona rest stop, a traveling young knife salesman is thrust into a high-stakes hostage situation by the arrival of two similarly stranded bank robbers with no qualms about using cruelty—or cold, hard steel—to protect their bloodstained, ill-gotten fortune.',NULL,NULL,2.1784,6.921,0,11.01,'2026-07-15 12:01:52','2026-07-15 12:01:52');
